#endif
        if (IsAutomationCommandLine())
        {
            autoSaveEnabled = false;
            Application.runInBackground = true;
        }
        BuildAudio();
        ApplyAudioSettings();
        ApplyDisplaySettings();
        ApplyPerformanceSettings();
        BuildCases();
        BuildInterface();
        ShowMainMenu();
        if (!IsAutomationCommandLine() && PlayerPrefs.GetInt(FirstRunNoticeAcceptedPrefsKey, 0) != 1)
