    private void LoadSettings()
    {
        largeTextMode = PlayerPrefs.GetInt(LargeTextPrefsKey, 0) == 1;
        highContrastMode = PlayerPrefs.GetInt(HighContrastPrefsKey, 0) == 1;
        autoSaveEnabled = PlayerPrefs.GetInt(AutoSavePrefsKey, 1) == 1;
        activeSaveSlot = Mathf.Clamp(PlayerPrefs.GetInt(SaveSlotPrefsKey, 1), 1, MaxSaveSlots);
        volumeLevel = Mathf.Clamp(PlayerPrefs.GetInt(VolumePrefsKey, 80), 0, 100);
        fullscreenEnabled = PlayerPrefs.GetInt(FullscreenPrefsKey, 0) == 1;
        resolutionIndex = Mathf.Clamp(PlayerPrefs.GetInt(ResolutionPrefsKey, 1), 0, ResolutionOptions.Length - 1);
        lowSpecMode = PlayerPrefs.GetInt(LowSpecModePrefsKey, 0) == 1;
        frameRateIndex = Mathf.Clamp(PlayerPrefs.GetInt(FrameRatePrefsKey, 1), 0, FrameRateOptions.Length - 1);
        campaignMandate = ClampCampaignMandate(PlayerPrefs.GetInt(CampaignMandatePrefsKey, (int)CampaignMandate.Standard));
        appealRemedyGraphTriageCandidateIndex = LoadAppealRemedyGraphTriageCandidateIndexForSlot(activeSaveSlot);
    }

    private void BuildAudio()
    {
        if (FindFirstObjectByType<AudioListener>() == null)
        {
            gameObject.AddComponent<AudioListener>();
        }

        sfxSource = gameObject.AddComponent<AudioSource>();
        sfxSource.playOnAwake = false;
        sfxSource.loop = false;
        sfxSource.spatialBlend = 0f;

        musicSource = gameObject.AddComponent<AudioSource>();
        musicSource.playOnAwake = false;
        musicSource.loop = true;
        musicSource.spatialBlend = 0f;
        musicSource.volume = 0.18f;

        LoadAudioResources();

        buttonClickClip = GetSfxClip("ui_click") ?? CreateToneClip("ui_click", 0.055f, t => 0.16f * Mathf.Sin(2f * Mathf.PI * 980f * t) + 0.08f * Mathf.Sin(2f * Mathf.PI * 1480f * t));
        uiBackClip = GetSfxClip("ui_back") ?? CreateToneClip("ui_back", 0.09f, t => 0.10f * Mathf.Sin(2f * Mathf.PI * 620f * t) + 0.05f * Mathf.Sin(2f * Mathf.PI * 360f * t));
        approveClip = GetSfxClip("stamp_approve") ?? CreateToneClip("stamp_approve", 0.16f, t => 0.22f * Mathf.Sin(2f * Mathf.PI * 135f * t) + 0.08f * Mathf.Sin(2f * Mathf.PI * 270f * t));
        conditionalClip = GetSfxClip("stamp_conditional") ?? CreateToneClip("stamp_conditional", 0.18f, t => 0.16f * Mathf.Sin(2f * Mathf.PI * 180f * t) + 0.10f * Mathf.Sin(2f * Mathf.PI * 360f * t));
        holdClip = GetSfxClip("stamp_hold") ?? CreateToneClip("stamp_hold", 0.14f, t => 0.12f * Mathf.Sin(2f * Mathf.PI * 120f * t));
        investigateClip = GetSfxClip("stamp_investigate") ?? CreateToneClip("stamp_investigate", 0.20f, t => 0.13f * Mathf.Sin(2f * Mathf.PI * (240f + 220f * t) * t));
        rejectClip = GetSfxClip("stamp_reject") ?? CreateToneClip("stamp_reject", 0.18f, t => 0.20f * Mathf.Sin(2f * Mathf.PI * 95f * t) + 0.05f * Mathf.Sin(2f * Mathf.PI * 55f * t));
        pageTurnClip = GetSfxClip("page_turn") ?? CreateNoiseClip("page_turn", 0.18f, 0.10f, 13);
        paperSlideClip = GetSfxClip("paper_slide") ?? CreateNoiseClip("paper_slide", 0.26f, 0.075f, 29);
        policyBookOpenClip = GetSfxClip("policy_book_open") ?? CreateNoiseClip("policy_book_open", 0.34f, 0.085f, 41);
        decisionFeedbackClip = GetSfxClip("decision_feedback") ?? CreateToneClip("decision_feedback", 0.26f, t => 0.08f * Mathf.Sin(2f * Mathf.PI * 196f * t) + 0.05f * Mathf.Sin(2f * Mathf.PI * 262f * t));
        alertClip = GetSfxClip("briefing_alert") ?? CreateToneClip("briefing_alert", 0.36f, t => 0.11f * Mathf.Sin(2f * Mathf.PI * 392f * t) + 0.10f * Mathf.Sin(2f * Mathf.PI * 523f * t));
        incidentMinorClip = GetSfxClip("incident_minor") ?? CreateToneClip("incident_minor", 0.34f, t => 0.09f * Mathf.Sin(2f * Mathf.PI * 330f * t) + 0.05f * Mathf.Sin(2f * Mathf.PI * 660f * t));
        incidentMajorClip = GetSfxClip("incident_major") ?? CreateToneClip("incident_major", 0.48f, t => 0.12f * Mathf.Sin(2f * Mathf.PI * (420f - 110f * t) * t) + 0.08f * Mathf.Sin(2f * Mathf.PI * 210f * t));
        incidentCriticalClip = GetSfxClip("incident_critical") ?? CreateToneClip("incident_critical", 0.62f, t => 0.13f * Mathf.Sin(2f * Mathf.PI * (520f + 90f * Mathf.Sin(2f * Mathf.PI * 5f * t)) * t) + 0.06f * Mathf.Sin(2f * Mathf.PI * 92f * t));
        reportClip = GetSfxClip("report_ready") ?? CreateToneClip("report_ready", 0.42f, t => 0.10f * Mathf.Sin(2f * Mathf.PI * 262f * t) + 0.12f * Mathf.Sin(2f * Mathf.PI * 330f * t) + 0.10f * Mathf.Sin(2f * Mathf.PI * 392f * t));
        saveClip = GetSfxClip("save_confirm") ?? CreateToneClip("save_confirm", 0.18f, t => 0.12f * Mathf.Sin(2f * Mathf.PI * 660f * t) + 0.09f * Mathf.Sin(2f * Mathf.PI * 880f * t));
        analysisClip = GetSfxClip("analysis_open") ?? CreateToneClip("analysis_open", 0.32f, t => 0.11f * Mathf.Sin(2f * Mathf.PI * (220f + 520f * t) * t));
