    private void LoadAudioResources()
    {
        bgmClips.Clear();
        for (int i = 0; i < RequiredBgmKeys.Length; i++)
        {
            string key = RequiredBgmKeys[i];
            AudioClip clip = Resources.Load<AudioClip>(AudioBgmResourcePrefix + key);
            if (clip != null)
            {
                bgmClips[key] = clip;
            }
        }

        sfxClips.Clear();
        for (int i = 0; i < RequiredSfxKeys.Length; i++)
        {
            string key = RequiredSfxKeys[i];
            AudioClip clip = Resources.Load<AudioClip>(AudioSfxResourcePrefix + key);
            if (clip != null)
            {
                sfxClips[key] = clip;
            }
        }
    }

    private AudioClip GetSfxClip(string key)
    {
        return sfxClips.TryGetValue(key, out AudioClip clip) ? clip : null;
    }

    private AudioClip GetBgmClip(string key)
    {
        return bgmClips.TryGetValue(key, out AudioClip clip) ? clip : fallbackMusicClip;
    }

    private void PlayBgm(string key)
    {
        if (musicSource == null)
        {
            return;
        }

        AudioClip clip = GetBgmClip(key);
        if (clip == null)
        {
            return;
        }

        if (currentBgmKey == key && musicSource.clip == clip)
        {
            if (!Application.isBatchMode && volumeLevel > 0 && !musicSource.isPlaying)
            {
                musicSource.Play();
            }
            return;
        }

        currentBgmKey = key;
        musicSource.clip = clip;
        if (!Application.isBatchMode && volumeLevel > 0)
        {
            musicSource.Play();
        }
    }

    private void BuildCases()
    {
        cases.Clear();

        for (int day = 1; day <= 7; day++)
        {
            bool loaded = LoadCaseDatabaseResource($"Data/cases_day{day}");
            if (!loaded && day > 1)
            {
                break;
            }

            if (!loaded && day == 1)
            {
                break;
            }
        }

        if (cases.Count == 0)
        {
            AddEmbeddedPrototypeCases();
        }

        AddSupplementalArchiveCases();
    }

    private bool LoadCaseDatabaseResource(string resourcePath)
    {
        TextAsset databaseAsset = Resources.Load<TextAsset>(resourcePath);
        if (databaseAsset == null)
        {
            return false;
        }

        try
        {
            CaseDatabase database = JsonUtility.FromJson<CaseDatabase>(databaseAsset.text);
            if (database?.cases == null || database.cases.Count == 0)
            {
                return false;
            }

            cases.AddRange(database.cases);
            return true;
        }
        catch (Exception exception)
        {
            Debug.LogWarning("Failed to load case database " + resourcePath + ". " + exception.Message);
            return false;
        }
    }

    private void AddEmbeddedPrototypeCases()
    {
        cases.Add(new CareCase(
            "A-014", "김서연 가족", "한부모 초등 자녀 가정", "방과후 돌봄 바우처 + 긴급 상담 연계",
            "월 소득은 기준 이내이나 야간 근무가 잦고, 최근 아이의 지각과 결석이 늘었다. 신청자는 증빙서류를 대부분 갖췄지만 직장 근무표는 누락되어 있다.",
            "신청서: 완비\n소득증명: 완비\n학교 의견서: 결석 증가, 피로 누적\n근무표: 미제출",
            "서류는 거의 충분함. 야간 노동과 돌봄 공백이 동시에 나타나는 전형적인 긴급 사례.",
            280, 78, 72, 62, "조건부 승인"));
        cases.Add(new CareCase(
            "B-022", "박정호 가족", "조손가정", "학습지원 + 이동 동행 서비스",
            "조부모가 손녀를 돌보고 있다. 소득 기준은 충족하지만 병원 기록상 조모의 만성질환이 있어 돌봄 지속 가능성이 낮다.",
            "신청서: 완비\n소득증명: 완비\n의료기록: 조모 만성질환\n학교 의견서: 보호자 면담 요청",
            "현재 위기는 크지 않아 보이지만 돌봄 제공자의 건강 악화가 구조적 위험이다.",
