    private void BuildEndingGalleryInterface()
    {
        CreatePanel("Ending Gallery Dim", endingGalleryRoot, Vector2.zero, new Vector2(1920, 1080), new Color32(10, 12, 14, 184));
        CreatePanel("Ending Gallery Paper", endingGalleryRoot, Vector2.zero, new Vector2(1340, 760), new Color32(246, 231, 198, 232));
        CreatePanel("Ending Gallery Header Strip", endingGalleryRoot, new Vector2(0, 322), new Vector2(1180, 72), new Color32(33, 45, 46, 212));

        Text title = CreateText(endingGalleryRoot, "Ending Gallery Title", "엔딩 기록", 38, TextAnchor.MiddleCenter, new Color32(246, 232, 202, 255), FontStyle.Bold);
        SetRect(title.rectTransform, new Vector2(0, 322), new Vector2(720, 58));

        endingGalleryStatusText = CreateText(
            endingGalleryRoot,
            "Ending Gallery Status",
            "",
            17,
            TextAnchor.MiddleCenter,
            new Color32(38, 31, 25, 255),
            FontStyle.Bold);
        SetRect(endingGalleryStatusText.rectTransform, new Vector2(0, 266), new Vector2(1160, 36));

        EndingOutcome[] endings = BuildEndingCatalog();
        endingGalleryCardTexts = new Text[endings.Length];
        endingGalleryRecordButtonTexts = new Text[endings.Length];
        endingGalleryImages = new Image[endings.Length];
        endingGalleryRecordButtons = new Button[endings.Length];
        for (int i = 0; i < endings.Length; i++)
        {
            int col = i % 2;
            int row = i / 2;
            Vector2 cardCenter = new Vector2(-330 + col * 660, 86 - row * 286);
            CreatePanel("Ending Gallery Card " + endings[i].id, endingGalleryRoot, cardCenter, new Vector2(594, 242), new Color32(32, 38, 38, 190));

            endingGalleryImages[i] = CreateImage(
                "Ending Gallery Image " + endings[i].id,
                endingGalleryRoot,
                EndingSprite(endings[i].visualIndex),
                cardCenter + new Vector2(-172, 32),
                new Vector2(238, 142),
                Color.white);
            endingGalleryImages[i].preserveAspect = true;

            endingGalleryCardTexts[i] = CreateTextBox(
                endingGalleryRoot,
                "Ending Gallery Text " + endings[i].id,
                cardCenter + new Vector2(132, 10),
                new Vector2(320, 168),
                new Color32(246, 231, 198, 78),
                12,
                "",
                13,
                TextAnchor.UpperLeft,
                new Color32(244, 232, 205, 255),
                FontStyle.Bold);

            string endingId = endings[i].id;
            endingGalleryRecordButtons[i] = CreateTextButton(
                endingGalleryRoot,
                "관련 기록",
                cardCenter + new Vector2(-172, -86),
                new Vector2(160, 36),
                new Color32(65, 82, 104, 238),
                () => OpenEndingGalleryCareerRecord(endingId));
            endingGalleryRecordButtonTexts[i] = endingGalleryRecordButtons[i].GetComponentInChildren<Text>(true);
            endingGalleryRecordButtons[i].gameObject.SetActive(false);
        }

        CreateTextButton(endingGalleryRoot, "기준 전환", new Vector2(-420, -332), new Vector2(210, 58), new Color32(92, 76, 112, 238), CycleEndingGalleryMandate);
        Button followUpFilterButton = CreateTextButton(endingGalleryRoot, "후속 보기", new Vector2(-140, -332), new Vector2(210, 58), new Color32(65, 82, 104, 238), ToggleEndingGalleryFollowUpFilter);
        endingGalleryFollowUpFilterButtonText = followUpFilterButton.GetComponentInChildren<Text>();
        CreateTextButton(endingGalleryRoot, "새 캠페인", new Vector2(140, -332), new Vector2(210, 58), new Color32(96, 129, 67, 238), StartNewCampaign);
        CreateTextButton(endingGalleryRoot, "메인 메뉴", new Vector2(420, -332), new Vector2(210, 58), new Color32(116, 82, 50, 238), ShowMainMenu);
    }

