        achievementDecisionPracticeRecordButtonText = achievementDecisionPracticeRecordButton.GetComponentInChildren<Text>(true);
        Button achievementEndingRecordButton = CreateTextButton(achievementRoot, "엔딩 기록", new Vector2(240, -354), new Vector2(128, 58), new Color32(82, 76, 112, 238), ShowEndingGallery);
        Button achievementNewCampaignButton = CreateTextButton(achievementRoot, "새 캠페인", new Vector2(400, -354), new Vector2(128, 58), new Color32(96, 129, 67, 238), StartNewCampaign);
        Button achievementMainMenuButton = CreateTextButton(achievementRoot, "메인 메뉴", new Vector2(560, -354), new Vector2(128, 58), new Color32(116, 82, 50, 238), ShowMainMenu);
        ConfigureAchievementLongLoopNavigation(achievementEndingRecordButton, achievementNewCampaignButton, achievementMainMenuButton);
    }

    private void ConfigureAchievementLongLoopNavigation(Button endingRecordButton, Button newCampaignButton, Button mainMenuButton)
    {
        ConfigureExplicitNavigation(
            achievementAppealRemedyTriageCandidateButton,
            null,
            achievementNextGoalButton,
            null,
            achievementAppealRemedyRecordButton);
        ConfigureExplicitNavigation(
            achievementNextGoalButton,
            achievementAppealRemedyTriageCandidateButton,
            null,
            null,
            achievementReplayRecordButton);

        ConfigureExplicitNavigation(achievementReplayRecordButton, null, achievementGrowthRecordButton, achievementReplayTierRecordButtons[0], null);
        ConfigureExplicitNavigation(achievementGrowthRecordButton, achievementReplayRecordButton, achievementGrowthFollowUpRecordButton, achievementReplayTierRecordButtons[1], null);
        ConfigureExplicitNavigation(achievementGrowthFollowUpRecordButton, achievementGrowthRecordButton, achievementAppealRemedyRecordButton, achievementReplayTierRecordButtons[2], null);
        ConfigureExplicitNavigation(achievementAppealRemedyRecordButton, achievementGrowthFollowUpRecordButton, achievementDecisionPracticeRecordButton, achievementAppealRemedyTriageCandidateButton, null);
        ConfigureExplicitNavigation(achievementDecisionPracticeRecordButton, achievementAppealRemedyRecordButton, endingRecordButton, achievementDecisionPracticeTierRecordButtons[0], null);
        ConfigureExplicitNavigation(endingRecordButton, achievementDecisionPracticeRecordButton, newCampaignButton, null, null);
        ConfigureExplicitNavigation(newCampaignButton, endingRecordButton, mainMenuButton, null, null);
        ConfigureExplicitNavigation(mainMenuButton, newCampaignButton, null, null, null);

        for (int i = 0; i < achievementReplayTierRecordButtons.Length; i++)
        {
            Button left = i > 0 ? achievementReplayTierRecordButtons[i - 1] : null;
            Button right = i + 1 < achievementReplayTierRecordButtons.Length ? achievementReplayTierRecordButtons[i + 1] : null;
            Button down = i == 0 ? achievementReplayRecordButton : i == 1 ? achievementGrowthRecordButton : achievementGrowthFollowUpRecordButton;
            ConfigureExplicitNavigation(achievementReplayTierRecordButtons[i], left, right, null, down);
        }

        for (int i = 0; i < achievementDecisionPracticeTierRecordButtons.Length; i++)
        {
            Button left = i > 0 ? achievementDecisionPracticeTierRecordButtons[i - 1] : null;
            Button right = i + 1 < achievementDecisionPracticeTierRecordButtons.Length ? achievementDecisionPracticeTierRecordButtons[i + 1] : null;
            ConfigureExplicitNavigation(achievementDecisionPracticeTierRecordButtons[i], left, right, achievementReplayTierRecordButtons[i], achievementDecisionPracticeRecordButton);
        }
    }

