    private void OpenCareerRecordAppealTriageCandidateQueue(CareerRecord record)
    {
        if (record == null || string.IsNullOrWhiteSpace(record.appealRemedyObjectiveCaseId))
        {
            UpdateCareerRecordContent();
            return;
        }

        string caseId = record.appealRemedyObjectiveCaseId;
        ShowCaseArchiveForCase(caseId);
        int filterIndex = CaseArchiveFilterIndexForTriageLabel(record.appealRemedyObjectiveTriageLabel);
        caseArchiveFilterIndex = filterIndex;
        caseArchiveFocusedCaseId = caseId;
        List<CareCase> archiveCases = BuildCaseArchiveFilteredCases();
        int index = FindCaseArchiveIndex(archiveCases, caseId);
        if (index < 0)
        {
            caseArchiveFilterIndex = 0;
            archiveCases = BuildCaseArchiveFilteredCases();
            index = FindCaseArchiveIndex(archiveCases, caseId);
        }

        caseArchivePage = index >= 0 ? index / CaseArchivePageSize : 0;
        caseArchiveCareerRecordFocusCaseId = caseId;
        caseArchiveCareerRecordTimelineText = CareerRecordCaseTimelineText(record, caseId);
        SetCaseArchiveCareerRecordReturnFocus(record, "보정 추천", CareerRecordAppealTriageFilterId);
        UpdateCaseArchiveContent();
        if (caseArchiveStatusText != null)
        {
            string summary = string.IsNullOrWhiteSpace(record.appealRemedyObjectiveTriageSummary)
                ? record.appealRemedyObjectiveTriageLabel
                : Shorten(record.appealRemedyObjectiveTriageSummary, 72);
            caseArchiveStatusText.text =
                $"캠페인 기록 포커스: 보정 추천 큐 {record.appealRemedyObjectiveTriageLabel} {caseId} · {summary}\n" +
                caseArchiveStatusText.text;
        }
    }

