    private CareCase RecommendedCaseObjectiveArchiveCase()
    {
        if (!string.IsNullOrWhiteSpace(latestAgentDisagreementCaseId))
        {
            CareCase agentCase = FindCaseById(latestAgentDisagreementCaseId);
            if (agentCase != null)
            {
                return agentCase;
            }
        }

        CareCase best = null;
        int bestScore = int.MinValue;
        CareerRecordDatabase recordDatabase = LoadCareerRecordDatabase();
        CareerRecord recentRecord = recordDatabase.records.Count > 0 ? recordDatabase.records[0] : null;
        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            int score = RecommendedCaseObjectiveBaseScore(careCase) +
                RecentCareerDecisionTendencyScore(careCase, recentRecord) +
                CumulativeCareerDecisionTendencyScore(careCase, recordDatabase.records);
            if (score > bestScore)
            {
                best = careCase;
                bestScore = score;
            }
        }

        return best;
    }

    private static int RecommendedCaseObjectiveBaseScore(CareCase careCase)
    {
        int pressure = CasePressureScore(careCase);
        int score = pressure * 2 + careCase.day * 3;
            if (careCase.recommendedDecision == "추가조사")
            {
                score += 18;
            }
            if (careCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(careCase.missingDocuments))
            {
                score += 14;
            }
            if (!careCase.incomeEligible)
            {
                score += 10;
            }
            if (GetDecisionCost(DecisionKind.Approve, careCase, CampaignMandate.Standard) >= 300)
            {
                score += 8;
            }

        return score;
    }

    private string RecommendedCaseObjectiveMenuLine()
