    private string RecommendedCaseObjectiveButtonLabel(CareCase targetCase)
    {
        string prefix = IsAchievementUnlocked("case_objective_replay") ? "추천" : "목표";
        return targetCase == null ? $"{prefix} 사례" : $"{prefix} {targetCase.id}";
    }

    private string RecommendedCaseObjectiveReason(CareCase targetCase)
    {
        if (targetCase == null)
        {
            return "표시할 사례가 없습니다";
        }

        if (!string.IsNullOrWhiteSpace(latestAgentDisagreementCaseId) &&
            string.Equals(targetCase.id, latestAgentDisagreementCaseId, StringComparison.OrdinalIgnoreCase))
        {
            return "판단 비교 사례";
        }

        List<string> reasons = new();
        string cumulativeTendency = CumulativeCareerDecisionTendencyReason(targetCase);
        if (!string.IsNullOrWhiteSpace(cumulativeTendency))
        {
            reasons.Add(cumulativeTendency);
        }
        string recentTendency = RecentCareerDecisionTendencyReason(targetCase);
        if (!string.IsNullOrWhiteSpace(recentTendency))
        {
            reasons.Add(recentTendency);
        }
        if (CasePressureScore(targetCase) >= 78)
        {
            reasons.Add("고압력");
        }
        if (targetCase.recommendedDecision == "추가조사")
        {
            reasons.Add("추가조사 권장");
        }
        if (targetCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(targetCase.missingDocuments))
        {
            reasons.Add("서류 취약");
        }
        if (!targetCase.incomeEligible)
        {
            reasons.Add("소득 예외");
        }
        if (GetDecisionCost(DecisionKind.Approve, targetCase, CampaignMandate.Standard) >= 300)
        {
            reasons.Add("고비용");
        }

        if (reasons.Count == 0)
        {
            reasons.Add("대표 재심사 추천");
        }

        return string.Join("/", reasons);
    }

    private static int CumulativeCareerDecisionTendencyScore(CareCase careCase, List<CareerRecord> records)
    {
        if (careCase == null || records == null || records.Count == 0)
        {
            return 0;
        }

        BuildCumulativeCareerTendency(records, out int support, out int investigation, out int delay, out int total, out float averageMatch);
        if (total <= 0)
        {
            return 0;
        }

        float supportRate = support / (float)total;
        float investigationRate = investigation / (float)total;
        float delayRate = delay / (float)total;
        int score = 0;
        if (supportRate >= 0.45f)
        {
            if (CasePressureScore(careCase) >= 74) score += 14;
            if (careCase.recommendedDecision == "추가조사") score += 10;
            if (careCase.documentStrength < 62 || !string.IsNullOrWhiteSpace(careCase.missingDocuments)) score += 8;
        }
        if (investigationRate >= 0.30f)
        {
            if (careCase.recommendedDecision != "추가조사") score += 12;
            if (careCase.documentStrength >= 70 && string.IsNullOrWhiteSpace(careCase.missingDocuments)) score += 7;
        }
        if (delayRate >= 0.38f)
        {
            if (careCase.incomeEligible && careCase.equityNeed >= 70) score += 12;
            if (careCase.recommendedDecision == "승인" || careCase.recommendedDecision == "조건부") score += 7;
        }
        if (averageMatch > 0f && averageMatch < 72f)
        {
            score += CasePressureScore(careCase) >= 70 ? 7 : 3;
        }

        return score;
    }

    private static string CumulativeCareerDecisionTendencyReason(CareCase careCase)
    {
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        if (careCase == null || database.records.Count == 0 || CumulativeCareerDecisionTendencyScore(careCase, database.records) <= 0)
        {
            return "";
        }

        BuildCumulativeCareerTendency(database.records, out int support, out int investigation, out int delay, out int total, out float averageMatch);
        if (total <= 0)
        {
            return "";
        }

        float supportRate = support / (float)total;
        float investigationRate = investigation / (float)total;
        float delayRate = delay / (float)total;
        if (supportRate >= 0.45f) return "누적 지원 성향";
        if (investigationRate >= 0.30f) return "누적 조사 성향";
        if (delayRate >= 0.38f) return "누적 지연/거절 성향";
        if (averageMatch > 0f && averageMatch < 72f) return "누적 권장 불일치";
        return "";
    }

    private static string BuildCumulativeCareerTendencyGraphLine()
    {
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        return BuildCumulativeCareerTendencyGraphLine(database.records);
    }

    private static string BuildCumulativeCareerTendencyGraphLine(List<CareerRecord> records)
    {
        if (records == null || records.Count == 0)
        {
            return "누적 성향: 기록 없음";
        }

        BuildCumulativeCareerTendency(records, out int support, out int investigation, out int delay, out int total, out float averageMatch);
        if (total <= 0)
        {
            return "누적 성향: 판단 기록 없음";
        }

        string supportBar = RatioBar(support / (float)total, 5);
        string investigationBar = RatioBar(investigation / (float)total, 5);
        string delayBar = RatioBar(delay / (float)total, 5);
        return $"누적 성향: 지{supportBar} 조{investigationBar} 지연{delayBar} · 권장 {averageMatch:0}%";
    }

    private static void BuildCumulativeCareerTendency(List<CareerRecord> records, out int support, out int investigation, out int delay, out int total, out float averageMatch)
    {
        support = 0;
        investigation = 0;
        delay = 0;
        total = 0;
        float matchTotal = 0f;
        int matchCount = 0;
        int limit = Mathf.Min(records != null ? records.Count : 0, 6);
        for (int i = 0; i < limit; i++)
        {
            CareerRecord record = records[i];
            if (record == null)
            {
                continue;
            }

            support += record.supportCount;
            investigation += record.investigationCount;
            delay += record.holdCount + record.rejectCount;
            total += record.supportCount + record.investigationCount + record.holdCount + record.rejectCount;
            if (record.recommendedMatchRatePercent > 0f)
            {
                matchTotal += record.recommendedMatchRatePercent;
                matchCount++;
            }
        }

        averageMatch = matchCount > 0 ? matchTotal / matchCount : 0f;
    }

    private static string RatioBar(float ratio, int width)
    {
        int filled = Mathf.Clamp(Mathf.RoundToInt(ratio * width), 0, width);
        return new string('■', filled) + new string('□', width - filled);
    }

    private static CareerRecord LatestCareerRecordForRecommendation()
    {
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        return database.records.Count > 0 ? database.records[0] : null;
    }

    private static int RecentCareerDecisionTendencyScore(CareCase careCase, CareerRecord record)
    {
        if (careCase == null || record == null)
        {
            return 0;
        }

        int score = 0;
        int total = Mathf.Max(1, record.supportCount + record.investigationCount + record.holdCount + record.rejectCount);
        float supportRate = record.supportCount / (float)total;
        float investigationRate = record.investigationCount / (float)total;
        float delayRate = (record.holdCount + record.rejectCount) / (float)total;

        if (supportRate >= 0.48f)
        {
            if (CasePressureScore(careCase) >= 76) score += 22;
            if (careCase.recommendedDecision == "추가조사") score += 16;
            if (careCase.documentStrength < 62 || !string.IsNullOrWhiteSpace(careCase.missingDocuments)) score += 12;
        }
        if (investigationRate >= 0.34f)
        {
            if (careCase.recommendedDecision != "추가조사") score += 18;
            if (careCase.documentStrength >= 70 && string.IsNullOrWhiteSpace(careCase.missingDocuments)) score += 8;
            if (careCase.recommendedDecision == "추가조사") score -= 6;
        }
        if (delayRate >= 0.42f)
        {
            if (careCase.incomeEligible && careCase.equityNeed >= 70) score += 18;
            if (careCase.recommendedDecision == "승인" || careCase.recommendedDecision == "조건부") score += 10;
        }
        if (record.recommendedMatchRatePercent > 0f && record.recommendedMatchRatePercent < 70f)
        {
            score += CasePressureScore(careCase) >= 70 ? 8 : 3;
            if (!string.IsNullOrWhiteSpace(careCase.recommendedDecision)) score += 4;
        }

        return score;
    }

    private static string RecentCareerDecisionTendencyReason(CareCase careCase)
    {
        CareerRecord record = LatestCareerRecordForRecommendation();
        if (careCase == null || record == null || RecentCareerDecisionTendencyScore(careCase, record) <= 0)
        {
            return "";
        }

        int total = Mathf.Max(1, record.supportCount + record.investigationCount + record.holdCount + record.rejectCount);
        float supportRate = record.supportCount / (float)total;
        float investigationRate = record.investigationCount / (float)total;
        float delayRate = (record.holdCount + record.rejectCount) / (float)total;

        if (supportRate >= 0.48f)
        {
            return "직전 지원 성향 보정";
        }
        if (investigationRate >= 0.34f)
        {
            return "직전 조사 성향 보정";
        }
        if (delayRate >= 0.42f)
        {
            return "직전 지연/거절 보정";
        }
        if (record.recommendedMatchRatePercent > 0f && record.recommendedMatchRatePercent < 70f)
        {
            return "직전 권장 불일치 보정";
        }

        return "";
    }

    private CareCase FindCaseById(string caseId)
    {
        if (string.IsNullOrWhiteSpace(caseId))
        {
            return null;
        }

        for (int i = 0; i < cases.Count; i++)
        {
            if (string.Equals(cases[i].id, caseId, StringComparison.OrdinalIgnoreCase))
            {
                return cases[i];
            }
        }

        return null;
    }

    private void OpenLatestAgentDisagreementCase()
    {
        if (string.IsNullOrWhiteSpace(latestAgentDisagreementCaseId))
        {
            RunAgentSimulation();
        }

        ShowCaseArchiveForCase(latestAgentDisagreementCaseId);
    }

    private void ApplyLatestAgentReplayObjective()
    {
        if (!latestAgentReplayObjectiveReady)
        {
            RunAgentSimulation();
        }

        if (!latestAgentReplayObjectiveReady)
        {
            if (agentDashboardPathText != null)
            {
                agentDashboardPathText.text = "다음 회차 추천을 만들 심사 기록이 아직 부족합니다.";
            }
            return;
        }

        pendingNextCampaignObjective = latestAgentReplayObjective;
        hasPendingNextCampaignObjective = true;
        UpdateRecommendedCampaignButton();

        if (agentDashboardPathText != null)
        {
            agentDashboardPathText.text =
                $"다음 회차 추천 적용: {latestAgentReplayPersonaName} → {CampaignMandateLabel(latestAgentReplayObjective.mandate)}\n" +
                $"{Shorten(latestAgentReplayObjective.challenge, 46)}";
        }
    }

    private void StartCaseArchiveObjectiveCampaign()
    {
        if (!ApplyCaseArchiveObjective())
        {
            return;
        }

        StartRecommendedCampaign();
    }

    private void StartCaseArchiveDecisionPracticeCampaign()
    {
        if (!ApplyCaseArchiveDecisionPracticeObjective())
        {
            return;
        }

        StartRecommendedCampaign();
    }

    private bool ApplyCaseArchiveObjective()
    {
        CareCase careCase = CurrentCaseArchiveObjectiveCase();
        if (careCase == null)
        {
            if (caseArchiveStatusText != null)
            {
                caseArchiveStatusText.text = "목표 심사를 만들 대표 사례가 없습니다.";
            }
            return false;
        }

        pendingNextCampaignObjective = BuildCaseReplayObjective(careCase);
        hasPendingNextCampaignObjective = true;
        pendingCaseReplayObjectiveReady = true;
        pendingCaseReplayObjectiveCaseId = careCase.id;
        pendingCaseReplayObjectiveChallenge = pendingNextCampaignObjective.challenge;
        UpdateRecommendedCampaignButton();
        if (caseArchiveStatusText != null)
        {
            caseArchiveStatusText.text =
                $"목표 심사 적용: {careCase.id} → {CampaignMandateLabel(pendingNextCampaignObjective.mandate)} · " +
                Shorten(pendingNextCampaignObjective.challenge, 52);
        }
        return true;
    }

    private bool ApplyCaseArchiveDecisionPracticeObjective()
    {
        CareCase careCase = CurrentCaseArchiveObjectiveCase();
        if (careCase == null)
        {
            if (caseArchiveStatusText != null)
            {
                caseArchiveStatusText.text = "비교 연습을 만들 대표 사례가 없습니다.";
            }
            return false;
        }

        DecisionKind targetDecision = DecisionKindFromLabel(careCase.recommendedDecision);
        DecisionPreview preview = BuildDecisionPreview(careCase, targetDecision, campaignMandate, budget, stability, equity, missedRisk, complaints);
        int riskDelta = preview.missedRiskDelta + preview.complaintsDelta;
        CampaignMandate mandate = DecisionPracticeMandateFor(targetDecision);
        pendingNextCampaignObjective = new NextCampaignObjective(
            mandate,
            $"판단 비교 연습: {careCase.id} {preview.decisionLabel} 기준으로 40건 재심사",
            $"사례 자료실 판단 비교표 · 예산 {SignedNumber(preview.budgetDelta)}만 · 안정 {SignedNumber(preview.stabilityDelta)} · 형평 {SignedNumber(preview.equityDelta)} · 위험 {SignedNumber(riskDelta)} · 후폭풍 {preview.consequence.title}");
        hasPendingNextCampaignObjective = true;
        pendingCaseReplayObjectiveReady = true;
        pendingCaseReplayObjectiveCaseId = careCase.id;
        pendingCaseReplayObjectiveChallenge = pendingNextCampaignObjective.challenge;
        UpdateRecommendedCampaignButton();
        if (caseArchiveStatusText != null)
        {
            caseArchiveStatusText.text =
                $"비교 연습 적용: {careCase.id} {preview.decisionLabel} → {CampaignMandateLabel(mandate)} · " +
                Shorten(preview.consequence.title, 34);
        }
        return true;
    }

    private static CampaignMandate DecisionPracticeMandateFor(DecisionKind targetDecision)
    {
        return targetDecision switch
        {
            DecisionKind.Approve => CampaignMandate.SupportExpanded,
            DecisionKind.Conditional => CampaignMandate.SupportExpanded,
            DecisionKind.Investigate => CampaignMandate.SupportExpanded,
            DecisionKind.Reject => CampaignMandate.AusterityAudit,
            _ => CampaignMandate.Standard
        };
    }

    private void NextCaseArchivePage()
    {
        int pageCount = CaseArchivePageCount();
        if (pageCount <= 0)
        {
            return;
        }

        caseArchiveFocusedCaseId = "";
        caseArchivePage = (caseArchivePage + 1) % pageCount;
        UpdateCaseArchiveContent();
    }

    private void PreviousCaseArchivePage()
    {
        int pageCount = CaseArchivePageCount();
        if (pageCount <= 0)
        {
            return;
        }

        caseArchiveFocusedCaseId = "";
        caseArchivePage = (caseArchivePage - 1 + pageCount) % pageCount;
        UpdateCaseArchiveContent();
    }

    private void CycleCaseArchiveFilter()
    {
        caseArchiveFilterIndex = (caseArchiveFilterIndex + 1) % CaseArchiveFilterLabels.Length;
        caseArchiveFocusedCaseId = "";
        caseArchivePage = 0;
        TryFocusAppealRemedyGraphTriageCaseForCurrentFilter();
        UpdateCaseArchiveContent();
    }

    private static int FindCaseArchiveIndex(List<CareCase> archiveCases, string caseId)
    {
        if (archiveCases == null || string.IsNullOrWhiteSpace(caseId))
        {
            return -1;
        }

        for (int i = 0; i < archiveCases.Count; i++)
        {
            if (string.Equals(archiveCases[i].id, caseId, StringComparison.OrdinalIgnoreCase))
            {
                return i;
            }
        }

        return -1;
    }

    private int CaseArchivePageCount()
    {
        return CaseArchivePageCount(BuildCaseArchiveFilteredCases());
    }

    private static int CaseArchivePageCount(List<CareCase> archiveCases)
    {
        return Mathf.Max(1, Mathf.CeilToInt(archiveCases.Count / (float)CaseArchivePageSize));
    }

    private string CaseArchiveFilterLabel()
    {
        int index = Mathf.Clamp(caseArchiveFilterIndex, 0, CaseArchiveFilterLabels.Length - 1);
        return CaseArchiveFilterLabels[index];
    }

    private List<CareCase> BuildCaseArchiveFilteredCases()
    {
        List<CareCase> filteredCases = new();
        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            if (MatchesCaseArchiveFilter(careCase))
            {
                filteredCases.Add(careCase);
            }
        }

        return filteredCases;
    }

    private bool MatchesCaseArchiveFilter(CareCase careCase)
    {
        switch (caseArchiveFilterIndex)
        {
            case 1:
                return CasePressureScore(careCase) >= 72 || careCase.urgency >= 82;
            case 2:
                return careCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(careCase.missingDocuments);
            case 3:
                return !careCase.incomeEligible;
            case 4:
                return GetDecisionCost(DecisionKind.Approve, careCase) >= 360;
            case 5:
                return careCase.recommendedDecision == "추가조사";
            case 6:
                return HasAppealReviewForCase(careCase.id);
            default:
                return true;
        }
    }

    private bool HasAppealReviewForCase(string caseId)
    {
        return HighestAppealReviewLogForCase(caseId, out int score) != null && score >= 35;
    }

    private void UpdateCaseArchiveContent()
    {
        if (caseArchiveStatusText == null || caseArchiveListText == null || caseArchiveDetailText == null)
        {
            return;
        }

        List<CareCase> archiveCases = BuildCaseArchiveFilteredCases();
        int pageCount = CaseArchivePageCount(archiveCases);
        caseArchivePage = Mathf.Clamp(caseArchivePage, 0, pageCount - 1);
        int start = caseArchivePage * CaseArchivePageSize;
        int end = Mathf.Min(archiveCases.Count, start + CaseArchivePageSize);
        if (caseArchiveFilterButtonText != null)
        {
            caseArchiveFilterButtonText.text = "필터: " + CaseArchiveFilterLabel();
        }
        UpdateCaseArchiveDecisionPracticeButton(archiveCases, start);
        UpdateCaseArchiveCareerRecordButton();
        UpdateCaseArchiveDecisionAuditCoachingButton();
        UpdateCaseArchiveTriageCandidateButtons();

        caseArchiveStatusText.text = BuildCaseArchiveSummaryText(archiveCases, start, end, pageCount);
        caseArchiveListText.text = BuildCaseArchiveListText(archiveCases, start, end);
        caseArchiveDetailText.text = BuildCaseArchiveDetailText(archiveCases, start);
    }

