                ? $"복기 {Shorten(sourceCaseId, 8)}"
                : label;
            caseArchiveDecisionAuditCoachingButtonText.fontSize = 14;
        }
    }

    private bool TryGetDecisionAuditCoachingArchiveCase(out CareerRecord record, out CareCase careCase, out string sourceCaseId)
    {
        record = null;
        careCase = null;
        sourceCaseId = "";

        CareerRecordDatabase database = LoadCareerRecordDatabase();
        if (database.records == null)
        {
            return false;
        }

        for (int i = 0; i < database.records.Count; i++)
        {
            CareerRecord candidate = database.records[i];
            if (candidate == null)
            {
                continue;
            }

            string caseId = candidate.decisionAuditCoachingAppealCaseId;
            if (string.IsNullOrWhiteSpace(caseId))
            {
                continue;
            }

            CareCase found = cases.Find(c => string.Equals(c.id, caseId, StringComparison.OrdinalIgnoreCase));
            if (found == null)
            {
                continue;
            }

            record = candidate;
            careCase = found;
            sourceCaseId = caseId;
            return true;
        }

        for (int i = 0; i < database.records.Count; i++)
        {
            CareerRecord candidate = database.records[i];
            if (candidate == null || string.IsNullOrWhiteSpace(candidate.decisionAuditCoachingSummaryLine))
            {
                continue;
            }

            string caseId = candidate.representativeCaseId;
            if (string.IsNullOrWhiteSpace(caseId))
            {
                continue;
            }

            CareCase found = cases.Find(c => string.Equals(c.id, caseId, StringComparison.OrdinalIgnoreCase));
            if (found == null)
            {
                continue;
            }

            record = candidate;
            careCase = found;
            sourceCaseId = caseId;
            return true;
        }

        return false;
    }

