    private string BuildCaseArchiveSummaryText(List<CareCase> archiveCases, int start, int end, int pageCount)
    {
        int highUrgencyCount = 0;
        int documentWeakCount = 0;
        int incomeExceptionCount = 0;
        int investigationRecommendedCount = 0;
        int appealReviewCount = 0;
        int highestDay = 0;
        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            highestDay = Mathf.Max(highestDay, careCase.day);
            if (careCase.urgency >= 80)
            {
                highUrgencyCount++;
            }
            if (careCase.documentStrength < 60)
            {
                documentWeakCount++;
            }
            if (!careCase.incomeEligible)
            {
                incomeExceptionCount++;
            }
            if (careCase.recommendedDecision == "추가조사")
            {
                investigationRecommendedCount++;
            }
            if (HasAppealReviewForCase(careCase.id))
            {
                appealReviewCount++;
            }
        }

        string rangeLabel = archiveCases.Count > 0
            ? $"{start + 1}-{end}번 / {archiveCases.Count}"
            : "0건 / 0";
        string focusLabel = !string.IsNullOrWhiteSpace(caseArchiveFocusedCaseId)
            ? $" · 포커스 {caseArchiveFocusedCaseId}"
            : "";
        string triageLine = BuildCaseArchiveAppealRemedyGraphTriageRecommendationLine();
        return
            $"필터: {CaseArchiveFilterLabel()} · 전체 {cases.Count}개 합성 사례 중 {archiveCases.Count}개 표시 · {highestDay}일차 캠페인 · {rangeLabel} · {caseArchivePage + 1}/{pageCount}쪽{focusLabel}\n" +
            $"고긴급 {highUrgencyCount}건 · 서류 보강 {documentWeakCount}건 · 소득 예외 {incomeExceptionCount}건 · 추가조사 권장 {investigationRecommendedCount}건 · 이의제기 {appealReviewCount}건" +
            triageLine;
    }

    private string BuildCaseArchiveAppealRemedyGraphTriageRecommendationLine()
    {
        if (!TryGetTopAppealRemedyGraphTriageRecommendation(out AppealRemedyGraphTriageItem item, out CareCase careCase, out int filterIndex))
        {
            return "";
        }

        string filterLabel = CaseArchiveFilterLabels[Mathf.Clamp(filterIndex, 0, CaseArchiveFilterLabels.Length - 1)];
        bool focused =
            string.Equals(caseArchiveFocusedCaseId, careCase.id, StringComparison.OrdinalIgnoreCase) &&
            caseArchiveFilterIndex == filterIndex;
        string action = focused
            ? "R 목표 심사로 보정 추천 재심사 시작"
            : $"F로 {filterLabel} 필터 이동 시 {careCase.id} 자동 포커스";
        return
            "\n보정 추천: " +
            BuildAppealRemedyGraphTriageRecommendationSummary(item, careCase, true) +
            " · " + action;
    }

    private string BuildAppealRemedyGraphTriageRecommendationSummary(AppealRemedyGraphTriageItem item, CareCase careCase, bool includeGraph)
    {
        if (item == null || careCase == null)
        {
            return "보정 추천: 대기";
        }

        string graph = includeGraph && !string.IsNullOrWhiteSpace(item.topBeforeAfterGraph)
            ? " · " + Shorten(item.topBeforeAfterGraph, 44)
            : "";
        return $"보정 추천: {item.label} · {careCase.id} · {item.caseCount}건/{item.sessionCount}세션{graph}{BuildAppealRemedyGraphTriageCandidateListSummary()}";
    }

    private string BuildAppealRemedyGraphTriageCandidateListSummary()
    {
        if (!TryGetAppealRemedyGraphTriageCandidates(out List<AppealRemedyGraphTriageItem> triage) ||
            triage.Count <= 1)
        {
            return "";
        }

        List<string> labels = new();
        for (int i = 0; i < triage.Count && labels.Count < 3; i++)
        {
            AppealRemedyGraphTriageItem candidate = triage[i];
            if (candidate == null || string.IsNullOrWhiteSpace(candidate.label) || string.IsNullOrWhiteSpace(candidate.topCaseId))
            {
                continue;
            }

            CareCase candidateCase = FindCaseById(candidate.topCaseId);
            labels.Add($"{candidate.label} {candidateCase.id}");
        }

        return labels.Count > 1
            ? $" · 추천 {labels.Count}개: {string.Join(", ", labels)}"
            : "";
    }

    private bool TryFocusAppealRemedyGraphTriageCaseForCurrentFilter()
    {
        if (!TryGetTopAppealRemedyGraphTriageRecommendation(out _, out CareCase careCase, out int filterIndex) ||
            filterIndex != caseArchiveFilterIndex)
        {
            return false;
        }

        List<CareCase> archiveCases = BuildCaseArchiveFilteredCases();
        int index = FindCaseArchiveIndex(archiveCases, careCase.id);
        if (index < 0)
        {
            return false;
        }

        caseArchiveFocusedCaseId = careCase.id;
        caseArchivePage = index / CaseArchivePageSize;
        return true;
    }

    private void OpenNextAppealRemedyGraphTriageCandidate()
    {
        if (!TryGetAppealRemedyGraphTriageCandidates(out List<AppealRemedyGraphTriageItem> candidates) ||
            candidates.Count == 0)
        {
            if (caseArchiveStatusText != null)
            {
                caseArchiveStatusText.text = "보정 추천이 아직 없습니다.";
            }
            return;
        }

        appealRemedyGraphTriageCandidateIndex = Mathf.Clamp(appealRemedyGraphTriageCandidateIndex, 0, candidates.Count - 1);
        int nextIndex = (appealRemedyGraphTriageCandidateIndex + 1) % candidates.Count;
        for (int i = 0; i < candidates.Count; i++)
        {
            if (string.Equals(caseArchiveFocusedCaseId, candidates[i].topCaseId, StringComparison.OrdinalIgnoreCase))
            {
                nextIndex = (i + 1) % candidates.Count;
                break;
            }
        }

        FocusAppealRemedyGraphTriageCandidate(candidates[nextIndex], "보정 추천 열기");
    }

    private void StartFocusedAppealRemedyGraphTriageCandidate()
    {
        if (!TryGetAppealRemedyGraphTriageCandidates(out List<AppealRemedyGraphTriageItem> candidates) ||
            candidates.Count == 0)
        {
            return;
        }

        AppealRemedyGraphTriageItem selected = candidates[0];
        for (int i = 0; i < candidates.Count; i++)
        {
            if (string.Equals(caseArchiveFocusedCaseId, candidates[i].topCaseId, StringComparison.OrdinalIgnoreCase))
            {
                selected = candidates[i];
                break;
            }
        }

        if (!FocusAppealRemedyGraphTriageCandidate(selected, "보정 추천 시작") || !ApplyCaseArchiveObjective())
        {
            return;
        }

        StartRecommendedCampaign();
    }

    private bool FocusAppealRemedyGraphTriageCandidate(AppealRemedyGraphTriageItem item, string prefix)
    {
        if (item == null || string.IsNullOrWhiteSpace(item.topCaseId))
        {
            return false;
        }

        CareCase careCase = FindCaseById(item.topCaseId);
        if (careCase == null)
        {
            return false;
        }

        SetAppealRemedyGraphTriageCandidateIndex(item);
        caseArchiveFilterIndex = CaseArchiveFilterIndexForTriageLabel(item.label);
        caseArchiveFocusedCaseId = careCase.id;
        List<CareCase> archiveCases = BuildCaseArchiveFilteredCases();
        int index = FindCaseArchiveIndex(archiveCases, careCase.id);
        if (index < 0)
        {
            caseArchiveFilterIndex = 0;
            archiveCases = BuildCaseArchiveFilteredCases();
            index = FindCaseArchiveIndex(archiveCases, careCase.id);
        }

        caseArchivePage = index >= 0 ? index / CaseArchivePageSize : 0;
        UpdateCaseArchiveContent();
        if (caseArchiveStatusText != null)
        {
            caseArchiveStatusText.text =
                $"{prefix}: {item.label} · {careCase.id} · {item.caseCount}건/{item.sessionCount}세션 · 목표 심사로 바로 시작 가능\n" +
                caseArchiveStatusText.text;
        }

        return true;
    }

    private void SetAppealRemedyGraphTriageCandidateIndex(AppealRemedyGraphTriageItem selectedItem)
    {
        if (selectedItem == null ||
            !TryGetAppealRemedyGraphTriageCandidates(out List<AppealRemedyGraphTriageItem> candidates) ||
            candidates.Count == 0)
        {
            appealRemedyGraphTriageCandidateIndex = 0;
            PersistAppealRemedyGraphTriageCandidateIndex();
            return;
        }

        for (int i = 0; i < candidates.Count; i++)
        {
            AppealRemedyGraphTriageItem candidate = candidates[i];
            if (candidate == null)
            {
                continue;
            }

            bool sameCase = string.Equals(candidate.topCaseId, selectedItem.topCaseId, StringComparison.OrdinalIgnoreCase);
            bool sameLabel = string.Equals(candidate.label, selectedItem.label, StringComparison.OrdinalIgnoreCase);
            if (sameCase && sameLabel)
            {
                appealRemedyGraphTriageCandidateIndex = i;
                PersistAppealRemedyGraphTriageCandidateIndex();
                return;
            }
        }

        appealRemedyGraphTriageCandidateIndex = Mathf.Clamp(appealRemedyGraphTriageCandidateIndex, 0, candidates.Count - 1);
        PersistAppealRemedyGraphTriageCandidateIndex();
    }

    private bool TryGetTopAppealRemedyGraphTriageRecommendation(out AppealRemedyGraphTriageItem item, out CareCase careCase, out int filterIndex)
    {
        item = null;
        careCase = null;
        filterIndex = 0;

        if (!TryGetAppealRemedyGraphTriageCandidates(out List<AppealRemedyGraphTriageItem> triage) ||
            triage.Count == 0)
        {
            return false;
        }

        item = triage[0];
        careCase = FindCaseById(item.topCaseId);
        filterIndex = CaseArchiveFilterIndexForTriageLabel(item.label);
        return careCase != null;
    }

    private bool TryGetSelectedAppealRemedyGraphTriageRecommendation(out AppealRemedyGraphTriageItem item, out CareCase careCase, out int filterIndex)
    {
        item = null;
        careCase = null;
        filterIndex = 0;

        if (!TryGetAppealRemedyGraphTriageCandidates(out List<AppealRemedyGraphTriageItem> triage) ||
            triage.Count == 0)
        {
            appealRemedyGraphTriageCandidateIndex = 0;
            PersistAppealRemedyGraphTriageCandidateIndex();
            return false;
        }

        appealRemedyGraphTriageCandidateIndex = Mathf.Clamp(appealRemedyGraphTriageCandidateIndex, 0, triage.Count - 1);
        PersistAppealRemedyGraphTriageCandidateIndex();
        item = triage[appealRemedyGraphTriageCandidateIndex];
        careCase = FindCaseById(item.topCaseId);
        filterIndex = CaseArchiveFilterIndexForTriageLabel(item.label);
        return careCase != null;
    }

    private bool CycleAppealRemedyGraphTriageCandidate(out AppealRemedyGraphTriageItem item, out CareCase careCase)
    {
        item = null;
        careCase = null;
        if (!TryGetAppealRemedyGraphTriageCandidates(out List<AppealRemedyGraphTriageItem> candidates) ||
            candidates.Count <= 1)
        {
            return false;
        }

        appealRemedyGraphTriageCandidateIndex = (Mathf.Clamp(appealRemedyGraphTriageCandidateIndex, 0, candidates.Count - 1) + 1) % candidates.Count;
        PersistAppealRemedyGraphTriageCandidateIndex();
        item = candidates[appealRemedyGraphTriageCandidateIndex];
        careCase = FindCaseById(item.topCaseId);
        return careCase != null;
    }

    private void CycleAppealRemedyGraphTriageCandidateFromMenu()
    {
        if (!CycleAppealRemedyGraphTriageCandidate(out AppealRemedyGraphTriageItem item, out CareCase careCase))
        {
            UpdateMenuStatus("보정 추천이 2개 이상일 때 추천 전환을 사용할 수 있습니다.");
            UpdateMenuAppealRemedyTriageCandidateButton(false);
            return;
        }

        ShowMainMenu();
        UpdateMenuStatus("보정 추천 전환: " + BuildAppealRemedyGraphTriageRecommendationSummary(item, careCase, false));
    }

    private void CycleAppealRemedyGraphTriageCandidateFromAchievement()
    {
        if (!CycleAppealRemedyGraphTriageCandidate(out AppealRemedyGraphTriageItem item, out CareCase careCase))
        {
            if (achievementStatusText != null)
            {
                achievementStatusText.text = "보정 추천이 2개 이상일 때 추천 전환을 사용할 수 있습니다.\n" + achievementStatusText.text;
            }
            UpdateAchievementAppealRemedyTriageCandidateButton(false);
            return;
        }

        ShowAchievements();
        if (achievementStatusText != null)
        {
            achievementStatusText.text =
                "보정 추천 전환: " + BuildAppealRemedyGraphTriageRecommendationSummary(item, careCase, false) + "\n" +
                achievementStatusText.text;
        }
    }

    private bool TryGetAppealRemedyGraphTriageCandidates(out List<AppealRemedyGraphTriageItem> candidates)
    {
        candidates = new List<AppealRemedyGraphTriageItem>();
        if (!TryLoadAppealRemedyGraphTriage(out List<AppealRemedyGraphTriageItem> triage) ||
            triage == null ||
            triage.Count == 0)
        {
            return false;
        }

        for (int i = 0; i < triage.Count; i++)
        {
            AppealRemedyGraphTriageItem candidate = triage[i];
            if (candidate == null || string.IsNullOrWhiteSpace(candidate.topCaseId) || FindCaseById(candidate.topCaseId) == null)
            {
                continue;
            }

            candidates.Add(candidate);
        }

        return candidates.Count > 0;
    }

    private bool TryFindAppealRemedyGraphTriageForCase(string caseId, out AppealRemedyGraphTriageItem item)
    {
        item = null;
        if (string.IsNullOrWhiteSpace(caseId) ||
            !TryLoadAppealRemedyGraphTriage(out List<AppealRemedyGraphTriageItem> triage) ||
            triage == null)
        {
            return false;
        }

        for (int i = 0; i < triage.Count; i++)
        {
            AppealRemedyGraphTriageItem candidate = triage[i];
            if (candidate != null && string.Equals(candidate.topCaseId, caseId, StringComparison.OrdinalIgnoreCase))
            {
                item = candidate;
                return true;
            }
        }

        return false;
    }

    private static int CaseArchiveFilterIndexForTriageLabel(string label)
    {
        if (string.IsNullOrWhiteSpace(label))
        {
            return 6;
        }

        if (label.Contains("고위험"))
        {
            return 1;
        }
        if (label.Contains("서류"))
        {
            return 2;
        }
        if (label.Contains("소득"))
        {
            return 3;
        }
        if (label.Contains("고비용"))
        {
            return 4;
        }
        if (label.Contains("조사"))
        {
            return 5;
        }

        return 6;
    }

    private static bool TryLoadAppealRemedyGraphTriage(out List<AppealRemedyGraphTriageItem> triage)
    {
        triage = null;
#if !CARE_REVIEW_QA_TOOLS
        return false;
#else
        if (!TryReadProjectQaText(Path.Combine("playtest_packet", "care_review_playtest_aggregate.json"), out string json) ||
            string.IsNullOrWhiteSpace(json))
        {
            return false;
        }

        try
        {
            PlaytestAggregateExport aggregate = JsonUtility.FromJson<PlaytestAggregateExport>(json);
            if (aggregate == null || aggregate.appealRemedyGraphTriage == null || aggregate.appealRemedyGraphTriage.Count == 0)
            {
                return false;
            }

            triage = aggregate.appealRemedyGraphTriage;
            return true;
        }
        catch (Exception exception)
        {
            Debug.LogWarning("Appeal-remedy graph triage load failed: " + exception.Message);
            return false;
        }
    }

    private static bool TryReadProjectQaText(string relativePath, out string content)
    {
        content = "";
        try
        {
            string root = Directory.GetCurrentDirectory();
            for (int i = 0; i < 6 && !string.IsNullOrWhiteSpace(root); i++)
            {
                if (File.Exists(Path.Combine(root, "ProjectSettings", "ProjectVersion.txt")))
                {
                    string path = Path.Combine(root, "Builds", "QA", "v0.3.0", relativePath);
                    if (File.Exists(path))
                    {
                        content = File.ReadAllText(path, Encoding.UTF8);
                        return true;
                    }
                }

                DirectoryInfo parent = Directory.GetParent(root);
                root = parent != null ? parent.FullName : "";
            }
        }
        catch (Exception exception)
        {
            Debug.LogWarning("Project QA read failed: " + relativePath + " " + exception.Message);
        }

        return false;
#endif
    }

    private string BuildCaseArchiveListText(List<CareCase> archiveCases, int start, int end)
    {
        if (cases.Count == 0)
        {
            return "불러온 사례가 없습니다. Data/cases_day*.json 또는 내장 프로토타입 사례를 확인하세요.";
        }
        if (archiveCases.Count == 0)
        {
            return $"'{CaseArchiveFilterLabel()}' 필터에 해당하는 사례가 없습니다.\nF 키나 필터 버튼으로 다른 검토 큐를 선택하세요.";
        }

        StringBuilder builder = new();
        builder.AppendLine("일차  사례              유형        권장       압박        비용");
        builder.AppendLine("────────────────────────────────────────");
        for (int i = start; i < end; i++)
        {
            CareCase careCase = archiveCases[i];
            int pressure = CasePressureScore(careCase);
            string marker = string.Equals(careCase.id, caseArchiveFocusedCaseId, StringComparison.OrdinalIgnoreCase) ? "▶" : " ";
            builder.AppendLine(
                $"{marker}D{careCase.day}  {Shorten(careCase.id + " " + careCase.name, 14),-14}  " +
                $"{Shorten(careCase.type, 8),-8}  " +
                $"{Shorten(careCase.recommendedDecision, 6),-6}  " +
                $"{pressure,3}/{CasePressureLabel(pressure),-4}  " +
                $"{GetDecisionCost(DecisionKind.Approve, careCase),4}만");
        }

        builder.AppendLine();
        builder.AppendLine("압박은 긴급도, 형평 필요, 서류 취약도를 합친 빠른 검토 지표입니다. F로 큐를 바꿉니다.");
        return builder.ToString();
    }

    private string BuildCaseArchiveDetailText(List<CareCase> archiveCases, int start)
    {
        if (cases.Count == 0)
        {
            return "사례 세부 정보를 표시할 수 없습니다.";
        }
        if (archiveCases.Count == 0)
        {
            return "현재 필터에는 대표 사례가 없습니다.\n다른 필터를 선택하면 해당 큐의 첫 사례를 요약합니다.";
        }

        int focusedIndex = FindCaseArchiveIndex(archiveCases, caseArchiveFocusedCaseId);
        bool hasFocusedCaseOnPage = focusedIndex >= start && focusedIndex < Mathf.Min(archiveCases.Count, start + CaseArchivePageSize);
        CareCase careCase = archiveCases[hasFocusedCaseOnPage ? focusedIndex : Mathf.Clamp(start, 0, archiveCases.Count - 1)];
        string titlePrefix = hasFocusedCaseOnPage ? "포커스 사례" : "쪽 대표 사례";
        string incomeLabel = careCase.incomeEligible ? "소득 기준 적합" : "소득 기준 예외 검토";
        string missingLabel = string.IsNullOrWhiteSpace(careCase.missingDocuments)
            ? "주요 누락 없음"
            : careCase.missingDocuments;
        int approveCost = GetDecisionCost(DecisionKind.Approve, careCase);
        int conditionalCost = GetDecisionCost(DecisionKind.Conditional, careCase);
        int pressure = CasePressureScore(careCase);

        return
            $"{titlePrefix}: {careCase.id} {careCase.name}\n" +
            $"유형: {careCase.type} · D{careCase.day} · {incomeLabel}\n" +
            $"권장 판단: {careCase.recommendedDecision} · 압박 {pressure}/100({CasePressureLabel(pressure)})\n" +
            $"비용: 승인 {approveCost}만원 · 조건부 {conditionalCost}만원\n\n" +
            BuildCaseArchiveAppealRemedyHistoryText(careCase.id) +
            BuildCaseArchiveDecisionComparisonText(careCase) +
            $"신청 요약\n{careCase.summary}\n\n" +
            $"요청\n{careCase.request}\n\n" +
            $"핵심 위험 신호\n{careCase.signal}\n\n" +
            $"서류\n{careCase.documents}\n누락/보강: {missingLabel}\n\n" +
            $"후속 메모\n{(!string.IsNullOrWhiteSpace(careCase.followUp) ? careCase.followUp : "후속 메모 없음")}" +
            BuildCaseReplayObjectiveText(careCase) +
            BuildUnlockedInvestigationText(careCase.id) +
            BuildAppealReviewText(careCase.id) +
            BuildCareerRecordCaseTimelineText(careCase.id) +
            BuildAgentCaseDebateText(careCase.id);
    }

    private string BuildCaseArchiveDecisionComparisonText(CareCase careCase)
    {
        if (careCase == null)
        {
            return "";
        }

        StringBuilder builder = new();
        builder.AppendLine("판단 비교");
        for (int i = 0; i < PolicyDecisionOrder.Length; i++)
        {
            DecisionKind kind = PolicyDecisionOrder[i];
            DecisionPreview preview = BuildDecisionPreview(careCase, kind, campaignMandate, budget, stability, equity, missedRisk, complaints);
            int riskDelta = preview.missedRiskDelta + preview.complaintsDelta;
            string marker = MatchesRecommended(preview.decisionLabel, careCase.recommendedDecision) ? "[권장] " : "";
            builder.AppendLine(
                $"{marker}{preview.decisionLabel}: 예산 {SignedNumber(preview.budgetDelta)}만 · " +
                $"안정 {SignedNumber(preview.stabilityDelta)} · 형평 {SignedNumber(preview.equityDelta)} · " +
                $"위험 {SignedNumber(riskDelta)} · 후폭풍 {Shorten(preview.consequence.title, 18)}");
        }

        builder.AppendLine();
        return builder.ToString();
    }

    private static string BuildCaseArchiveAppealRemedyHistoryText(string caseId)
    {
        if (string.IsNullOrWhiteSpace(caseId))
        {
            return "";
        }

        CareerRecordDatabase database = LoadCareerRecordDatabase();
        if (database.records == null || database.records.Count == 0)
        {
            return "";
        }

        int remedyCount = 0;
        int successCount = 0;
        CareerRecord latest = null;
        for (int i = 0; i < database.records.Count; i++)
        {
            CareerRecord record = database.records[i];
            if (record == null ||
                !record.appealRemedyObjectiveCompleted ||
                !string.Equals(record.appealRemedyObjectiveCaseId, caseId, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            remedyCount++;
            if (record.appealRemedyObjectiveSucceeded)
            {
                successCount++;
            }

            latest ??= record;
        }

        if (remedyCount == 0 || latest == null)
        {
            return "";
        }

        int successRate = Mathf.RoundToInt(successCount * 100f / remedyCount);
        string latestState = latest.appealRemedyObjectiveSucceeded ? "성공" : "미달";
        string progress = FallbackText(latest.appealRemedyObjectiveProgress, latest.appealRemedyObjectiveChallenge);
        string next = IsAppealRemedyObjective(new NextCampaignObjective(
            CampaignMandateFromId(latest.nextCampaignMandateId),
            latest.nextCampaignChallenge,
            latest.nextCampaignReason))
                ? latest.nextCampaignChallenge
                : FallbackText(latest.appealRemedyObjectiveChallenge, "보정 목표 대기");

      return
          "보정 이력\n" +
          $"완료 {remedyCount}회 · 성공률 {successRate}%({successCount}/{remedyCount}) · 최근 {latestState}\n" +
          $"최근 진행: {Shorten(progress, 78)}\n" +
          $"다음 보정: {Shorten(next, 78)}\n\n";
    }

    private string BuildAppealReviewText(string caseId)
    {
        DecisionLog selected = HighestAppealReviewLogForCase(caseId, out int selectedScore);
        if (selected == null || selectedScore < 35)
        {
            return "";
        }

        return
            "\n\n이의제기 검토\n" +
            $"상태: {AppealReviewStatus(selected)} · 점수 {selectedScore}\n" +
            $"근거: {DecisionReviewReason(selected)}\n" +
            $"보정 조치: {AppealReviewRemedy(selected)}";
    }

    private DecisionLog HighestAppealReviewLogForCase(string caseId, out int selectedScore)
    {
        selectedScore = 0;
        if (string.IsNullOrWhiteSpace(caseId) || logs.Count == 0)
        {
            return null;
        }

        DecisionLog selected = null;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (!string.Equals(log.caseId, caseId, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            int score = AppealReviewScore(log);
            if (score > selectedScore)
            {
                selectedScore = score;
                selected = log;
            }
        }

        return selected;
    }

    private string BuildCareerRecordCaseTimelineText(string caseId)
    {
        if (string.IsNullOrWhiteSpace(caseId) ||
            string.IsNullOrWhiteSpace(caseArchiveCareerRecordFocusCaseId) ||
            string.IsNullOrWhiteSpace(caseArchiveCareerRecordTimelineText) ||
            !string.Equals(caseId, caseArchiveCareerRecordFocusCaseId, StringComparison.OrdinalIgnoreCase))
        {
            return "";
        }

        return "\n\n캠페인 기록 타임라인\n" + caseArchiveCareerRecordTimelineText;
    }

    private CareCase CurrentCaseArchiveObjectiveCase()
    {
        List<CareCase> archiveCases = BuildCaseArchiveFilteredCases();
        if (archiveCases.Count == 0)
        {
            return null;
        }

        int pageCount = CaseArchivePageCount(archiveCases);
        int page = Mathf.Clamp(caseArchivePage, 0, pageCount - 1);
        int start = page * CaseArchivePageSize;
        int focusedIndex = FindCaseArchiveIndex(archiveCases, caseArchiveFocusedCaseId);
        bool hasFocusedCaseOnPage = focusedIndex >= start && focusedIndex < Mathf.Min(archiveCases.Count, start + CaseArchivePageSize);
        return archiveCases[hasFocusedCaseOnPage ? focusedIndex : Mathf.Clamp(start, 0, archiveCases.Count - 1)];
    }

    private string BuildCaseReplayObjectiveText(CareCase careCase)
    {
        NextCampaignObjective objective = BuildCaseReplayObjective(careCase);
        return
            "\n\n반복 목표 제안\n" +
            $"목표 심사: {CampaignMandateLabel(objective.mandate)} · {objective.challenge}\n" +
            $"근거: {objective.reason}";
    }

    private NextCampaignObjective BuildCaseReplayObjective(CareCase careCase)
    {
        int pressure = CasePressureScore(careCase);
        bool highRisk = careCase.urgency >= 84 || pressure >= 80;
        bool documentWeak = careCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(careCase.missingDocuments);
        bool highCost = GetDecisionCost(DecisionKind.Approve, careCase, CampaignMandate.Standard) >= 300;
        bool incomeException = !careCase.incomeEligible;
        bool investigationRecommended = careCase.recommendedDecision == "추가조사";
        DecisionLog appealLog = HighestAppealReviewLogForCase(careCase.id, out int appealScore);

        if (TryFindAppealRemedyGraphTriageForCase(careCase.id, out AppealRemedyGraphTriageItem triageItem))
        {
            CampaignMandate mandate = CaseArchiveFilterIndexForTriageLabel(triageItem.label) == 2
                ? CampaignMandate.Standard
                : CampaignMandate.SupportExpanded;
            return new NextCampaignObjective(
                mandate,
                $"D{careCase.day} {careCase.id}형 이의제기 보정 추천 재심사",
                $"보정 추천 분류: {triageItem.label} {triageItem.caseCount}건/{triageItem.sessionCount}세션 · {Shorten(triageItem.topBeforeAfterGraph, 54)}");
        }

        if (appealLog != null && appealScore >= 35)
        {
            return new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                $"D{careCase.day} {careCase.id}형 이의제기 보정 재심사",
                $"{AppealReviewStatus(appealLog)} {appealScore}점 · {Shorten(AppealReviewRemedy(appealLog), 32)}");
        }

        if (highRisk && !highCost)
        {
            return new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                $"D{careCase.day} {careCase.id}형 고위험 사례 지연 없이 처리",
                $"압박 {pressure}/100 · 긴급 {careCase.urgency}");
        }

        if (highCost || incomeException)
        {
            return new NextCampaignObjective(
                CampaignMandate.AusterityAudit,
                $"D{careCase.day} {careCase.id}형 고비용/예외 사례 조건부 우선",
                $"승인 비용 {GetDecisionCost(DecisionKind.Approve, careCase, CampaignMandate.Standard)}만 · 소득예외 {BoolLabel(incomeException)}");
        }

        if (documentWeak || investigationRecommended)
        {
            return new NextCampaignObjective(
                CampaignMandate.Standard,
                $"D{careCase.day} {careCase.id}형 서류보강 사례 조사 메모 확보",
                $"서류 {careCase.documentStrength}/100 · 보강 {Shorten(careCase.missingDocuments, 24)}");
        }

        return new NextCampaignObjective(
            CampaignMandate.Standard,
            $"D{careCase.day} {careCase.id}형 대표 사례 권장 판단 유지",
            $"권장 {careCase.recommendedDecision} · 압박 {pressure}/100");
    }

    private string BuildUnlockedInvestigationText(string caseId)
    {
        if (string.IsNullOrWhiteSpace(caseId) || logs.Count == 0)
        {
            return "";
        }

        StringBuilder builder = new();
        int count = 0;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (!string.Equals(log.caseId, caseId, StringComparison.OrdinalIgnoreCase) ||
                string.IsNullOrWhiteSpace(log.investigationFinding))
            {
                continue;
            }

            if (count == 0)
            {
                builder.AppendLine();
                builder.AppendLine();
                builder.AppendLine("해금된 추가조사 메모");
            }

            builder.AppendLine($"- #{log.decisionIndex:00} {Shorten(log.investigationFinding, 76)}");
            count++;
            if (count >= 3)
            {
                break;
            }
        }

        return count > 0 ? builder.ToString().TrimEnd() : "";
    }

    private string BuildAgentCaseDebateText(string caseId)
    {
        if (string.IsNullOrWhiteSpace(caseId))
        {
            return "";
        }

        if (latestAgentDecisionLogs.Count == 0)
        {
            return "\n\n판단 비교\n아직 판단 비교를 실행하지 않았습니다.";
        }

        List<AgentDecisionLog> caseLogs = new();
        Dictionary<string, int> decisionCounts = new(StringComparer.OrdinalIgnoreCase);
        for (int i = 0; i < latestAgentDecisionLogs.Count; i++)
        {
            AgentDecisionLog log = latestAgentDecisionLogs[i];
            if (!string.Equals(log.caseId, caseId, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            caseLogs.Add(log);
            string decision = string.IsNullOrWhiteSpace(log.decision) ? "미정" : log.decision;
            if (!decisionCounts.ContainsKey(decision))
            {
                decisionCounts[decision] = 0;
            }
            decisionCounts[decision]++;
        }

        if (caseLogs.Count == 0)
        {
            return "\n\n판단 비교\n해당 사례의 비교 판단 기록이 없습니다.";
        }

        caseLogs.Sort((left, right) =>
        {
            int compare = string.Compare(left.decision, right.decision, StringComparison.Ordinal);
            return compare != 0 ? compare : string.Compare(left.personaName, right.personaName, StringComparison.Ordinal);
        });

        StringBuilder builder = new();
        builder.AppendLine();
        builder.AppendLine();
        builder.AppendLine("판단 비교");
        builder.AppendLine($"분포: {BuildDecisionCountBrief(decisionCounts)} · 권장 {caseLogs[0].recommendedDecision}");

        int rows = Mathf.Min(4, caseLogs.Count);
        for (int i = 0; i < rows; i++)
        {
            AgentDecisionLog log = caseLogs[i];
            string recommendedMatch = log.matchedRecommended ? "권장 일치" : "권장 불일치";
            string playerMatch = log.matchedPlayerDecision ? "내 판단 일치" : "내 판단 다름";
            builder.AppendLine($"- {log.personaName}: {log.decision} · {recommendedMatch} · {playerMatch}");
            builder.AppendLine($"  판단 이유: {Shorten(log.decisionReason, 54)}");
        }

        if (caseLogs.Count > rows)
        {
            builder.AppendLine($"  외 {caseLogs.Count - rows}개 성향은 판단 비교 기록에 포함됨");
        }

        return builder.ToString().TrimEnd();
    }

    private static int CasePressureScore(CareCase careCase)
    {
        return Mathf.Clamp(Mathf.RoundToInt(careCase.urgency * 0.45f + careCase.equityNeed * 0.35f + (100 - careCase.documentStrength) * 0.20f), 0, 100);
    }

    private static string CasePressureLabel(int score)
    {
        if (score >= 84)
        {
            return "매우 높음";
        }
        if (score >= 72)
        {
            return "높음";
        }
        if (score >= 58)
        {
            return "보통";
        }

        return "낮음";
    }

