    private void UpdatePolicyHandbookContent()
    {
        if (policyHandbookSummaryText == null || policyHandbookCaseText == null || policyHandbookDecisionText == null || policyHandbookSimulationText == null)
        {
            return;
        }

        if (currentIndex < 0 || currentIndex >= cases.Count)
        {
            policyHandbookSummaryText.text = "현재 검토 중인 신청서가 없습니다. 최종 리포트에서 캠페인 전체 판단을 확인하세요.";
            policyHandbookCaseText.text = "캠페인이 종료되었습니다.";
            policyHandbookDecisionText.text = "새 캠페인을 시작하면 현재 사례 기준표가 다시 표시됩니다.";
            policyHandbookSimulationText.text = "기준 비교\n\n새 캠페인 중 심사 화면에서 40건 전체 예측을 확인할 수 있습니다.";
            UpdatePolicySimulationVisuals(null);
            return;
        }

        CareCase currentCase = cases[currentIndex];
        policyHandbookSummaryText.text = BuildPolicyHandbookSummaryText(currentCase);
        policyHandbookCaseText.text = BuildPolicyHandbookCaseText(currentCase);
        policyHandbookDecisionText.text = BuildPolicyHandbookDecisionText(currentCase);
        policyHandbookSimulationText.text = BuildPolicySimulationText(currentCase);
        UpdatePolicySimulationVisuals(currentCase);
    }

    private string BuildPolicyHandbookSummaryText(CareCase careCase)
    {
        int pressure = Mathf.Max(careCase.urgency, careCase.equityNeed, 100 - careCase.documentStrength);
        string pressureLabel = pressure >= 90 ? "매우 높음" : (pressure >= 78 ? "높음" : "보통");
        int approveCost = GetDecisionCost(DecisionKind.Approve, careCase);
        string conclusion = pressure >= 82
            ? "위험 지연을 먼저 줄이세요"
            : (careCase.documentStrength < 55 ? "서류 공백을 먼저 확인하세요" : "예산과 형평을 같이 보세요");
        return
            $"결론: {careCase.recommendedDecision} 기준 · {conclusion} · 압박 {pressureLabel}\n" +
            $"운영 기준: {CampaignMandateLabel(campaignMandate)} · {CampaignMandateBrief(campaignMandate)} · 남은 예산 {budget}만원\n" +
            $"현재 사례: {careCase.id} {careCase.name} · 요청비용 {approveCost}만원 · 압박 {pressure}/100 · 권장 판단 {careCase.recommendedDecision}";
    }

    private static string BuildPolicyHandbookCaseText(CareCase careCase)
    {
        string incomeLabel = careCase.incomeEligible ? "소득 기준 적합" : "소득 기준 예외 검토";
        string missingLabel = string.IsNullOrWhiteSpace(careCase.missingDocuments)
            ? "주요 누락 없음"
            : careCase.missingDocuments;
        string documentLabel = careCase.documentStrength >= 70
            ? "서류 근거 강함"
            : (careCase.documentStrength >= 50 ? "보강 필요" : "근거 취약");
        string riskLabel = careCase.urgency >= 82
            ? "즉시 지연 위험"
            : (careCase.urgency >= 68 ? "단기 악화 가능" : "관찰 가능");
        string equityLabel = careCase.equityNeed >= 82
            ? "배제 가능성 큼"
            : (careCase.equityNeed >= 65 ? "접근성 장벽 있음" : "일반 기준 우선");

        return
            "사례 근거\n\n" +
            $"- 가족 유형: {careCase.type}\n" +
            $"- 요청: {Shorten(careCase.request, 46)}\n" +
            $"- 소득/서류: {incomeLabel} · {documentLabel}\n" +
            $"- 보강 서류: {Shorten(missingLabel, 48)}\n" +
            $"- 위험 판단: {riskLabel} · 형평 판단: {equityLabel}\n\n" +
            "핵심 위험 신호\n" +
            Shorten(careCase.signal, 150);
    }

    private string BuildPolicyHandbookDecisionText(CareCase careCase)
    {
        StringBuilder builder = new();
        builder.AppendLine("도장별 예상 변화");
        builder.AppendLine("예산 · 안정 · 형평 · 위험");

        for (int i = 0; i < PolicyDecisionOrder.Length; i++)
        {
            DecisionKind kind = PolicyDecisionOrder[i];
            DecisionPreview preview = BuildDecisionPreview(careCase, kind, campaignMandate, budget, stability, equity, missedRisk, complaints);
            bool recommended = MatchesRecommended(preview.decisionLabel, careCase.recommendedDecision);
            int riskDelta = preview.missedRiskDelta + preview.complaintsDelta;
            string marker = recommended ? " [권장]" : "";
            builder.AppendLine(
                $"{preview.decisionLabel}{marker}: " +
                $"예 {SignedNumber(preview.budgetDelta)}만 | " +
                $"안 {SignedNumber(preview.stabilityDelta)} | " +
                $"형 {SignedNumber(preview.equityDelta)} | " +
                $"위 {SignedNumber(riskDelta)} → {Shorten(preview.consequence.title, 8)}");
        }

        return builder.ToString();
    }

    private void UpdatePolicySimulationVisuals(CareCase currentCase)
    {
        if (policySimulationRowTexts == null ||
            policySimulationSupportFills == null ||
            policySimulationInvestigationFills == null ||
            policySimulationDelayFills == null ||
            policySimulationMatchFills == null)
        {
            return;
        }

        List<PolicySimulationResult> results = currentCase != null
            ? BuildPolicySimulationResults(currentCase)
            : new List<PolicySimulationResult>();

        for (int i = 0; i < policySimulationRowTexts.Length; i++)
        {
            if (i >= results.Count)
            {
                policySimulationRowTexts[i].text = "";
                SetPolicySimulationDistributionBar(i, 0, 0, 0, 1);
                SetPolicySimulationMatchBar(i, 0f);
                continue;
            }

            PolicySimulationResult result = results[i];
            int pressure = result.finalMissedRisk + result.finalComplaints;
            policySimulationRowTexts[i].text =
                $"{result.preset.label} -> {DecisionLabel(result.currentCaseDecision)}\n" +
                $"예산 {result.finalBudget}만 · 위험 {pressure}";
            SetPolicySimulationDistributionBar(i, result.supportCount, result.investigateCount, result.delayCount, result.caseCount);
            SetPolicySimulationMatchBar(i, result.matchedCount / (float)Mathf.Max(1, result.caseCount));
        }

        if (policySimulationRecommendationTexts == null || policySimulationRecommendationTexts.Length < 3)
        {
            return;
        }

        if (results.Count == 0)
        {
            policySimulationRecommendationTexts[0].text = "위험 최소\n캠페인 중\n표시";
            policySimulationRecommendationTexts[1].text = "예산 안정\n캠페인 중\n표시";
            policySimulationRecommendationTexts[2].text = "권장 일치\n캠페인 중\n표시";
            return;
        }

        PolicySimulationResult safest = BestRiskPolicy(results);
        PolicySimulationResult budgetSafe = BestBudgetPolicy(results);
        PolicySimulationResult closest = BestMatchPolicy(results);
        policySimulationRecommendationTexts[0].text = $"위험 최소\n{safest.preset.label}\n{safest.finalMissedRisk + safest.finalComplaints}";
        policySimulationRecommendationTexts[1].text = $"예산 안정\n{budgetSafe.preset.label}\n{budgetSafe.finalBudget}만";
        policySimulationRecommendationTexts[2].text = $"권장 일치\n{closest.preset.label}\n{closest.matchedCount}/{closest.caseCount}";
    }

    private void SetPolicySimulationDistributionBar(int index, int supportCount, int investigationCount, int delayCount, int caseCount)
    {
        const float fullWidth = 150f;
        float y = 84f - index * 46f + 8f;
        float startX = 536f - fullWidth * 0.5f;
        int total = Mathf.Max(1, caseCount);
        float supportWidth = Mathf.Clamp01(supportCount / (float)total) * fullWidth;
        float investigationWidth = Mathf.Clamp01(investigationCount / (float)total) * fullWidth;
        float delayWidth = Mathf.Max(0f, fullWidth - supportWidth - investigationWidth);

        SetSegmentBar(policySimulationSupportFills[index], startX, y, supportWidth, 12f);
        SetSegmentBar(policySimulationInvestigationFills[index], startX + supportWidth, y, investigationWidth, 12f);
        SetSegmentBar(policySimulationDelayFills[index], startX + supportWidth + investigationWidth, y, delayWidth, 12f);
    }

    private void SetPolicySimulationMatchBar(int index, float ratio)
    {
        const float fullWidth = 76f;
        float y = 84f - index * 46f - 10f;
        float width = Mathf.Clamp01(ratio) * fullWidth;
        RectTransform fillRect = policySimulationMatchFills[index].rectTransform;
        fillRect.sizeDelta = new Vector2(Mathf.Max(1f, width), 10f);
        fillRect.anchoredPosition = new Vector2(662f - ((fullWidth - width) * 0.5f), y);
    }

    private static void SetSegmentBar(Image image, float leftX, float centerY, float width, float height)
    {
        RectTransform rect = image.rectTransform;
        float visibleWidth = Mathf.Max(1f, width);
        rect.sizeDelta = new Vector2(visibleWidth, height);
        rect.anchoredPosition = new Vector2(leftX + visibleWidth * 0.5f, centerY);
    }

    private string BuildPolicySimulationText(CareCase currentCase)
    {
        List<PolicySimulationResult> results = BuildPolicySimulationResults(currentCase);
        PolicySimulationResult safest = BestRiskPolicy(results);
        PolicySimulationResult budgetSafe = BestBudgetPolicy(results);
        PolicySimulationResult closest = BestMatchPolicy(results);
        StringBuilder builder = new();
        builder.AppendLine("기준 비교 결론");
        builder.AppendLine("40건 전체 기준 비교 · 운영 기준을 바꾸면 현재 판단의 전체 여파가 달라집니다.");
        builder.AppendLine($"위험 최소: {safest.preset.label} · 예산 안정: {budgetSafe.preset.label} · 권장 일치: {closest.preset.label}");
        builder.Append("검증값: ");

        foreach (PolicySimulationResult result in results)
        {
            builder.Append($"{result.preset.label} 현재 {DecisionLabel(result.currentCaseDecision)} 지원 {result.supportCount} 조사 {result.investigateCount} 보류 {result.delayCount} 일치 {result.matchedCount}/{result.caseCount} 예산 {result.finalBudget} 위험 {result.finalMissedRisk} 민원 {result.finalComplaints}; ");
        }

        return builder.ToString();
    }

    private List<PolicySimulationResult> BuildPolicySimulationResults(CareCase currentCase)
    {
        List<PolicySimulationPreset> presets = BuildPolicySimulationPresets();
        List<PolicySimulationResult> results = new();
        for (int i = 0; i < presets.Count; i++)
        {
            results.Add(BuildPolicySimulationResult(presets[i], currentCase));
        }

        return results;
    }

    private static List<PolicySimulationPreset> BuildPolicySimulationPresets()
    {
        return new List<PolicySimulationPreset>
        {
            new("balanced", "균형 기준", CampaignMandate.Standard, 1.00f, 1.00f, 1.00f, 0.90f, 0.00f),
            new("support_expanded", "지원 확대", CampaignMandate.SupportExpanded, 1.24f, 1.18f, 0.82f, 0.55f, 14.00f),
            new("austerity_audit", "긴축 감사", CampaignMandate.AusterityAudit, 0.78f, 0.76f, 1.18f, 1.35f, -16.00f),
            new("risk_first", "위험 우선", CampaignMandate.SupportExpanded, 1.42f, 1.24f, 0.72f, 0.70f, 10.00f),
            new("budget_guard", "예산 방어", CampaignMandate.AusterityAudit, 0.70f, 0.62f, 1.10f, 1.55f, -22.00f)
        };
    }

    private PolicySimulationResult BuildPolicySimulationResult(PolicySimulationPreset preset, CareCase currentCase)
    {
        int simulatedBudget = StartingBudgetForMandate(preset.mandate);
        int simulatedStability = 50;
        int simulatedEquity = 50;
        int simulatedMissedRisk = 0;
        int simulatedComplaints = 0;
        int supportCount = 0;
        int investigateCount = 0;
        int delayCount = 0;
        int matchedCount = 0;
        DecisionKind currentCaseDecision = DecisionKind.Hold;

        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            DecisionKind decision = ChoosePolicySimulationDecision(preset, careCase, simulatedBudget);
            if (currentCase != null && string.Equals(careCase.id, currentCase.id, StringComparison.OrdinalIgnoreCase))
            {
                currentCaseDecision = decision;
            }

            DecisionPreview preview = BuildDecisionPreview(
                careCase,
                decision,
                preset.mandate,
                simulatedBudget,
                simulatedStability,
                simulatedEquity,
                simulatedMissedRisk,
                simulatedComplaints);

            simulatedBudget = preview.budgetAfter + preview.consequence.budgetDelta;
            simulatedStability = Mathf.Clamp(preview.stabilityAfter + preview.consequence.stabilityDelta, 0, 100);
            simulatedEquity = Mathf.Clamp(preview.equityAfter + preview.consequence.equityDelta, 0, 100);
            simulatedMissedRisk = Mathf.Clamp(preview.missedRiskAfter + preview.consequence.missedRiskDelta, 0, 100);
            simulatedComplaints = Mathf.Clamp(preview.complaintsAfter + preview.consequence.complaintsDelta, 0, 100);

            if (decision == DecisionKind.Approve || decision == DecisionKind.Conditional)
            {
                supportCount++;
            }
            else if (decision == DecisionKind.Investigate)
            {
                investigateCount++;
            }
            else
            {
                delayCount++;
            }

            if (MatchesRecommended(DecisionLabel(decision), careCase.recommendedDecision))
            {
                matchedCount++;
            }
        }

        return new PolicySimulationResult(
            preset,
            cases.Count,
            supportCount,
            investigateCount,
            delayCount,
            matchedCount,
            simulatedBudget,
            simulatedMissedRisk,
            simulatedComplaints,
            currentCaseDecision);
    }

    private static DecisionKind ChoosePolicySimulationDecision(PolicySimulationPreset preset, CareCase careCase, int remainingBudget)
    {
        float budgetPressure = Mathf.Clamp01((StartingBudgetForMandate(preset.mandate) - remainingBudget) / Mathf.Max(1f, StartingBudgetForMandate(preset.mandate)));
        float urgency = careCase.urgency * preset.urgencyWeight;
        float equityScore = careCase.equityNeed * preset.equityWeight;
        float documentScore = (100 - careCase.documentStrength) * preset.documentDoubtWeight;
        float budgetScore = ((careCase.cost / 8f) + budgetPressure * 48f) * preset.budgetWeight;
        float supportScore = urgency + equityScore + preset.supportBias - budgetScore;
        float investigationScore = documentScore + urgency * 0.35f + budgetPressure * 18f;

        if (remainingBudget <= 0 && preset.budgetWeight >= 1.0f)
        {
            return careCase.documentStrength < 64 ? DecisionKind.Investigate : DecisionKind.Hold;
        }

        if (supportScore >= 166f && remainingBudget >= careCase.cost * 0.55f)
        {
            return DecisionKind.Approve;
        }

        if (supportScore >= 120f && remainingBudget >= careCase.cost * 0.34f)
        {
            return DecisionKind.Conditional;
        }

        if (investigationScore >= 82f || (careCase.urgency >= 82 && supportScore >= 92f))
        {
            return DecisionKind.Investigate;
        }

        if (budgetScore >= 76f && careCase.urgency < 76)
        {
            return DecisionKind.Reject;
        }

        return DecisionKind.Hold;
    }

    private static PolicySimulationResult BestRiskPolicy(List<PolicySimulationResult> results)
    {
        PolicySimulationResult best = results[0];
        for (int i = 1; i < results.Count; i++)
        {
            if (results[i].finalMissedRisk + results[i].finalComplaints < best.finalMissedRisk + best.finalComplaints)
            {
                best = results[i];
            }
        }

        return best;
    }

    private static PolicySimulationResult BestBudgetPolicy(List<PolicySimulationResult> results)
    {
        PolicySimulationResult best = results[0];
        for (int i = 1; i < results.Count; i++)
        {
            if (results[i].finalBudget > best.finalBudget)
            {
                best = results[i];
            }
        }

        return best;
    }

    private static PolicySimulationResult BestMatchPolicy(List<PolicySimulationResult> results)
    {
        PolicySimulationResult best = results[0];
        for (int i = 1; i < results.Count; i++)
        {
            if (results[i].matchedCount > best.matchedCount)
            {
                best = results[i];
            }
        }

        return best;
    }

    private void UpdateDecisionHistoryContent()
    {
        if (decisionHistorySummaryText == null || decisionHistoryBodyText == null)
        {
            return;
        }

        decisionHistorySummaryText.text = BuildDecisionHistorySummaryText();
        decisionHistoryBodyText.text = BuildDecisionHistoryBodyText();
    }

    private string BuildDecisionHistorySummaryText()
    {
        int supportCount = 0;
        int investigationCount = 0;
        int delayCount = 0;
        int mismatchCount = 0;
        int totalSpent = 0;
        int totalRiskDelta = 0;

        foreach (DecisionLog log in logs)
        {
            if (IsSupportDecision(log.decision))
            {
                supportCount++;
            }
            if (log.decision == "추가조사")
            {
                investigationCount++;
            }
            if (IsDelayDecision(log.decision))
            {
                delayCount++;
            }
            if (!log.matchedRecommended)
            {
                mismatchCount++;
            }

            totalSpent += log.spentBudget;
            totalRiskDelta += Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore) + Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
        }

        string currentCase = currentIndex < cases.Count
            ? $"현재 사례: {cases[currentIndex].id} {Shorten(cases[currentIndex].name, 12)}"
            : "현재 사례: 최종 리포트";

        return
            $"운영 기준: {CampaignMandateLabel(campaignMandate)} · 진행 {Mathf.Min(currentIndex + 1, cases.Count)}/{cases.Count} · 판단 {logs.Count}건 · {currentCase}\n" +
            $"지원 {supportCount} · 추가조사 {investigationCount} · 지연/거절 {delayCount} · 권장 불일치 {mismatchCount} · 누적 지출 {totalSpent}만원 · 위험 증가 {totalRiskDelta}";
    }

    private string BuildDecisionHistoryBodyText()
    {
        if (logs.Count == 0)
        {
            CareCase currentCase = currentIndex < cases.Count ? cases[currentIndex] : null;
            if (currentCase == null)
            {
                return "아직 기록된 판단이 없습니다.";
            }

            return
                "아직 기록된 판단이 없습니다.\n\n" +
                $"현재 검토 중: {currentCase.id} {currentCase.name}\n" +
                $"가족 유형: {currentCase.type} · 긴급 {currentCase.urgency} · 서류 {currentCase.documentStrength} · 형평 {currentCase.equityNeed}\n" +
                $"권장 판단: {currentCase.recommendedDecision}\n\n" +
                "첫 판단 뒤에는 이 화면에서 판단/권장 판단, 예산 변화, 위험 증가, 감사 플래그를 바로 확인할 수 있습니다.";
        }

        StringBuilder builder = new();
        int skipped = Mathf.Max(0, logs.Count - ReportPreviewLineLimit);
        if (skipped > 0)
        {
            builder.AppendLine($"이전 {skipped}건은 생략되었습니다. 전체 흐름은 심사 기록과 최종 리포트에서 확인할 수 있습니다.");
        }

        int start = Mathf.Max(0, logs.Count - ReportPreviewLineLimit);
        for (int i = start; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            string mark = log.matchedRecommended ? "일치" : "불일치";
            int riskDelta = Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore) + Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
            builder.AppendLine($"{log.decisionIndex:00}. {log.caseId} D{log.day} {Shorten(log.caseName, 7)} · {ShortDecision(log.decision)}/{ShortDecision(log.recommendedDecision)} {mark} · 근거 {Shorten(DecisionRationaleLabelForLog(log), 7)} · 예산 {log.budgetBefore}->{log.budgetAfter} · 위험 +{riskDelta} · {Shorten(DecisionAuditFlags(log), 20)}");
        }

        if (currentIndex < cases.Count)
        {
            CareCase currentCase = cases[currentIndex];
            builder.AppendLine();
            builder.AppendLine(awaitingNext
                ? "현재 판단의 후폭풍을 확인한 뒤 다음 사례로 넘어갈 수 있습니다."
                : $"다음 검토: {currentCase.id} {Shorten(currentCase.name, 14)} · 긴급 {currentCase.urgency} · 서류 {currentCase.documentStrength} · 권장 {currentCase.recommendedDecision}");
        }

        return builder.ToString();
    }

    private void UpdateFollowUpInboxContent()
    {
        if (followUpInboxSummaryText == null || followUpInboxBodyText == null)
        {
            return;
        }

        followUpInboxSummaryText.text = BuildFollowUpInboxSummaryText();
        followUpInboxBodyText.text = BuildFollowUpInboxBodyText();
    }

    private string BuildFollowUpInboxSummaryText()
    {
        if (logs.Count == 0)
        {
            string currentCase = currentIndex < cases.Count
                ? $"{cases[currentIndex].id} {Shorten(cases[currentIndex].name, 12)}"
                : "최종 리포트";
            return
                $"후속 연락 0건 · 운영 기준: {CampaignMandateLabel(campaignMandate)} · 현재 검토: {currentCase}\n" +
                "첫 판단을 내리면 가족 연락, 민원, 감사 요청, 안전 확인 메모가 이곳에 쌓입니다.";
        }

        int currentDay = currentIndex < cases.Count ? cases[currentIndex].day : logs[logs.Count - 1].day;
        int todayCount = 0;
        int escalationCount = 0;
        int complaintCount = 0;
        int auditCount = 0;
        int mismatchCount = 0;
        int investigationMemoCount = 0;
        int appealReviewCount = 0;
        foreach (DecisionLog log in logs)
        {
            if (log.day == currentDay)
            {
                todayCount++;
            }
            if (IsEscalatedFollowUp(log))
            {
                escalationCount++;
            }
            if (log.consequenceComplaintsDelta > 0)
            {
                complaintCount++;
            }
            if (log.consequenceType == "audit_request" || log.consequenceType == "review_backlog")
            {
                auditCount++;
            }
            if (!log.matchedRecommended)
            {
                mismatchCount++;
            }
            if (!string.IsNullOrWhiteSpace(log.investigationFinding))
            {
                investigationMemoCount++;
            }
            if (AppealReviewScore(log) >= 35)
            {
                appealReviewCount++;
            }
        }

        DecisionLog latest = logs[logs.Count - 1];
        return
            $"후속 연락 {logs.Count}건 · 현재 일차 D{currentDay} 접수 {todayCount}건 · 고압력 {escalationCount} · 민원 증가 {complaintCount} · 감사/대기열 {auditCount} · 조사 메모 {investigationMemoCount} · 이의제기 검토 {appealReviewCount}\n" +
            $"최근: {latest.caseId} {Shorten(latest.caseName, 12)} · {latest.decision} → {latest.consequenceTitle} · 권장 불일치 {mismatchCount}건";
    }

    private string BuildFollowUpInboxBodyText()
    {
        if (logs.Count == 0)
        {
            CareCase currentCase = currentIndex < cases.Count ? cases[currentIndex] : null;
            if (currentCase == null)
            {
                return "아직 접수된 후속 연락이 없습니다.";
            }

            return
                "아직 접수된 후속 연락이 없습니다.\n\n" +
                $"현재 검토 중: {currentCase.id} {currentCase.name}\n" +
                $"권장 판단: {currentCase.recommendedDecision} · 긴급 {currentCase.urgency} · 서류 {currentCase.documentStrength} · 형평 {currentCase.equityNeed}\n\n" +
                "판단을 내리면 이곳에 가족의 후속 연락, 담당자 메모, 민원/감사 위험, 안전 확인 큐가 누적됩니다.";
        }

        StringBuilder builder = new();
        int skipped = Mathf.Max(0, logs.Count - 10);
        if (skipped > 0)
        {
            builder.AppendLine($"이전 {skipped}건은 생략되었습니다. 전체 흐름은 최종 리포트와 캠페인 기록에서 확인할 수 있습니다.");
        }

        builder.AppendLine("최근 후속 연락");
        int start = Mathf.Max(0, logs.Count - 10);
        for (int i = start; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            string mark = log.matchedRecommended ? "권장 O" : "권장 X";
            string pressure = IsEscalatedFollowUp(log) ? "주의" : "기록";
            string contact = !string.IsNullOrWhiteSpace(log.followUp) ? log.followUp : log.consequenceText;
            builder.AppendLine($"{log.decisionIndex:00}. D{log.day} {log.caseId} {Shorten(log.caseName, 9)} · {log.decision} → {log.consequenceTitle} · {mark} · 근거 {Shorten(DecisionRationaleLabelForLog(log), 8)} · {pressure}");
            builder.AppendLine($"    연락: {Shorten(contact, 66)}");
            if (!string.IsNullOrWhiteSpace(log.investigationFinding))
            {
                builder.AppendLine($"    조사 메모: {Shorten(log.investigationFinding, 72)}");
            }
            int appealScore = AppealReviewScore(log);
            if (appealScore >= 35)
            {
                builder.AppendLine($"    이의제기 검토: {AppealReviewStatus(log)} · 점수 {appealScore} · {AppealReviewRemedy(log)}");
            }
            builder.AppendLine($"    영향: 예산 {SignedNumber(log.consequenceBudgetDelta)}만 · 안정 {SignedNumber(log.consequenceStabilityDelta)} · 형평 {SignedNumber(log.consequenceEquityDelta)} · 누락 {SignedNumber(log.consequenceMissedRiskDelta)} · 민원 {SignedNumber(log.consequenceComplaintsDelta)}");
        }

        DecisionLog focus = HighestPressureFollowUpLog();
        if (focus != null)
        {
            builder.AppendLine();
            builder.AppendLine("우선 확인");
            builder.AppendLine($"{focus.caseId} {Shorten(focus.caseName, 12)} · {focus.consequenceTitle} · {Shorten(focus.consequenceText, 70)}");
            int appealScore = AppealReviewScore(focus);
            if (appealScore >= 35)
            {
                builder.AppendLine($"이의제기 보정: {AppealReviewStatus(focus)} · {AppealReviewRemedy(focus)}");
            }
        }

        return builder.ToString();
    }

    private DecisionLog HighestPressureFollowUpLog()
    {
        DecisionLog selected = null;
        int selectedScore = int.MinValue;
        foreach (DecisionLog log in logs)
        {
            int score =
                Mathf.Max(0, log.consequenceMissedRiskDelta) * 3 +
                Mathf.Max(0, log.consequenceComplaintsDelta) * 2 +
                Mathf.Max(0, -log.consequenceStabilityDelta) * 2 +
                (log.matchedRecommended ? 0 : 5) +
                (log.urgency >= 82 ? 4 : 0);
            if (score > selectedScore)
            {
                selectedScore = score;
                selected = log;
            }
        }

        return selected;
    }

    private static bool IsEscalatedFollowUp(DecisionLog log)
    {
        if (log == null)
        {
            return false;
        }

        return log.consequenceMissedRiskDelta + log.consequenceComplaintsDelta >= 5 ||
            log.consequenceStabilityDelta < 0 ||
            (!log.matchedRecommended && log.urgency >= 78);
    }

    private static int AppealReviewScore(DecisionLog log)
    {
        if (log == null)
        {
            return 0;
        }

        int score = 0;
        if (!log.matchedRecommended)
        {
            score += 28;
        }
        if (IsDelayDecision(log.decision) && log.urgency >= 75)
        {
            score += 24;
        }
        if (log.consequenceComplaintsDelta > 0)
        {
            score += log.consequenceComplaintsDelta * 5;
        }
        if (log.consequenceMissedRiskDelta > 0)
        {
            score += log.consequenceMissedRiskDelta * 4;
        }
        if (log.documentStrength < 60 || !string.IsNullOrWhiteSpace(log.missingDocuments))
        {
            score += 8;
        }
        if (!log.incomeEligible)
        {
            score += 6;
        }
        if (!string.IsNullOrWhiteSpace(log.investigationFinding))
        {
            score -= 12;
        }

        return Mathf.Max(0, score);
    }

    private static string AppealReviewStatus(DecisionLog log)
    {
        int score = AppealReviewScore(log);
        if (score >= 65)
        {
            return "즉시 재검토";
        }
        if (score >= 45)
        {
            return "가족 이의제기 가능";
        }
        if (score >= 35)
        {
            return "담당자 확인";
        }

        return "기록 보관";
    }

    private static string AppealReviewRemedy(DecisionLog log)
    {
        if (log == null)
        {
            return "후속 연락 원문 확인";
        }
        if (IsDelayDecision(log.decision) && log.urgency >= 75)
        {
            return "24시간 안전 확인 또는 조건부 승인 보정 비교";
        }
        if (!log.matchedRecommended)
        {
            return $"권장 판단 '{log.recommendedDecision}' 기준으로 예산·위험 차이 재계산";
        }
        if (!string.IsNullOrWhiteSpace(log.missingDocuments) || log.documentStrength < 60)
        {
            return "대체 증빙 요청과 보류 기간 단축 검토";
        }
        if (log.consequenceComplaintsDelta > 0)
        {
            return "민원 응대 메모와 결정 근거 설명 보강";
        }

        return "후속 연락 원문과 판단 근거 대조";
    }

    private AppealReviewCampaignSummary BuildAppealReviewCampaignSummary()
    {
        int count = 0;
        int maxScore = 0;
        DecisionLog selected = null;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            int score = AppealReviewScore(log);
            if (score < 35)
            {
                continue;
            }

            count++;
            if (score > maxScore)
            {
                maxScore = score;
                selected = log;
            }
        }

        if (selected == null)
        {
            return new AppealReviewCampaignSummary(count, maxScore, "", "", "");
        }

        return new AppealReviewCampaignSummary(
            count,
            maxScore,
            selected.caseId,
            AppealReviewStatus(selected),
            AppealReviewRemedy(selected));
    }

    private static string BuildAppealReviewReportSummaryLine(AppealReviewCampaignSummary summary)
    {
        if (summary.count <= 0)
        {
            return "";
        }

        return $"\n이의제기 검토 {summary.count}건 · 보정 {summary.status} {summary.maxScore}점 · {summary.caseId}";
    }

    private static string BuildAppealReviewReportInsight(AppealReviewCampaignSummary summary)
    {
        if (summary.count <= 0)
        {
            return "이의제기 검토: 고위험 불일치 판단이 없어 보정 검토 큐는 비어 있습니다.";
        }

        return $"이의제기 검토: {summary.caseId} {summary.status} · {summary.remedy}";
    }

    private static string BuildAppealReviewLogPathLine(AppealReviewCampaignSummary summary)
    {
        if (summary.count <= 0)
        {
            return "";
        }

        return $"이의제기 보정: {summary.caseId} · {summary.status} {summary.maxScore}점\n";
    }

    private string BuildCompactReportLogPathText(
        NextCampaignObjective nextObjective,
        CampaignChallengeResult challenge,
        int matchedRecommendedCount,
        GrowthObjectiveResult growthResult,
        AppealRemedyObjectiveResult appealRemedyResult,
        AppealReviewCampaignSummary appealSummary)
    {
        StringBuilder builder = new();
        builder.AppendLine($"다음 목표: {CampaignMandateLabel(nextObjective.mandate)} · {CompactNextObjectiveChallenge(nextObjective)}");
        builder.AppendLine($"근거: {CompactNextObjectiveReason(nextObjective)}");
        builder.AppendLine($"챌린지: {challenge.title} · {challenge.progress}");

        string objectiveResult = BuildCompactReportObjectiveResultLine(matchedRecommendedCount, growthResult, appealRemedyResult, appealSummary);
        if (!string.IsNullOrWhiteSpace(objectiveResult))
        {
            builder.AppendLine(objectiveResult);
        }

        string appealRemedyCta = BuildCompactAppealRemedyNextObjectiveCtaLine(appealRemedyResult, nextObjective);
        if (!string.IsNullOrWhiteSpace(appealRemedyCta))
        {
            builder.AppendLine(appealRemedyCta);
        }
        else
        {
            builder.AppendLine("추천 심사 버튼으로 시작");
        }

        int replayObjectiveCount = CountReplayObjectiveRecords(LoadCareerRecordDatabase().records);
        if (replayObjectiveCount >= 2)
        {
            builder.AppendLine(BuildAdvancedReplayChallengeReportLine());
        }

        return builder.ToString().TrimEnd('\r', '\n');
    }

    private static string CompactNextObjectiveChallenge(NextCampaignObjective nextObjective)
    {
        if (IsAppealRemedyObjective(nextObjective))
        {
            if (nextObjective.challenge.Contains("재도전"))
            {
                return "이의제기 보정 재도전";
            }

            if (nextObjective.challenge.Contains("후속"))
            {
                return "이의제기 보정 후속";
            }

            return "이의제기 보정 목표";
        }

        if (IsGrowthFollowUpObjective(nextObjective))
        {
            if (nextObjective.challenge.Contains("성장 보정"))
            {
                return Shorten(nextObjective.challenge, 26);
            }

            return nextObjective.challenge.Contains("성장 후속")
                ? Shorten(nextObjective.challenge, 26)
                : "성장 후속 목표";
        }

        if (IsAchievementObjective(nextObjective))
        {
            return Shorten("성과 목표: " + AchievementObjectiveTitle(nextObjective), 30);
        }

        if (IsDecisionAuditCoachingObjective(nextObjective))
        {
            return "복기 목표: " + DecisionAuditCoachingButtonPattern(nextObjective);
        }

        if (IsDecisionPracticeObjective(nextObjective))
        {
            return "판단 비교 연습";
        }

        return Shorten(nextObjective.challenge, 34);
    }

    private static string CompactNextObjectiveReason(NextCampaignObjective nextObjective)
    {
        if (IsAchievementObjective(nextObjective))
        {
            return Shorten("미해금 성과: " + AchievementObjectiveTitle(nextObjective), 46);
        }

        if (IsAppealRemedyObjective(nextObjective))
        {
            if (nextObjective.reason.Contains("보정 목표 미달"))
            {
                return "보정 목표 미달 · 고위험 지연 재점검";
            }

            if (nextObjective.reason.Contains("보정 목표 성공"))
            {
                return "보정 목표 성공 · 품질 유지";
            }
        }

        if (IsGrowthFollowUpObjective(nextObjective))
        {
            if (nextObjective.reason.Contains("성장 목표 성공"))
            {
                return "성장 목표 성공 · 후속 실험";
            }

            if (nextObjective.reason.Contains("성장 목표 미달"))
            {
                return "성장 목표 미달 · 보정 실험";
            }
        }

        if (IsDecisionAuditCoachingObjective(nextObjective))
        {
            return "판단 복기: " + DecisionAuditCoachingButtonPattern(nextObjective);
        }

        return Shorten(nextObjective.reason, 46);
    }

    private string BuildCompactReportObjectiveResultLine(
        int matchedRecommendedCount,
        GrowthObjectiveResult growthResult,
        AppealRemedyObjectiveResult appealRemedyResult,
        AppealReviewCampaignSummary appealSummary)
    {
        if (currentCampaignStartedFromDecisionPracticeObjective)
        {
            float matchRate = logs.Count > 0 ? matchedRecommendedCount * 100f / logs.Count : 0f;
            return $"비교 연습 완료: {currentCampaignCaseObjectiveId} · 권장 {matchRate:0}%";
        }

        if (growthResult.active)
        {
            return $"성장 목표 판정: {GrowthObjectiveStateLabel(growthResult)} · {Shorten(growthResult.progress, 40)}";
        }

        if (appealRemedyResult.active)
        {
            return $"보정 목표 판정: {AppealRemedyObjectiveStateLabel(appealRemedyResult)} · {Shorten(appealRemedyResult.progress, 40)}";
        }

        if (appealSummary.count > 0)
        {
            return $"이의제기 보정: {appealSummary.caseId} · {appealSummary.status} {appealSummary.maxScore}점";
        }

        return "";
    }

    private static string BuildCompactAppealRemedyNextObjectiveCtaLine(AppealRemedyObjectiveResult result, NextCampaignObjective nextObjective)
    {
        if (!result.active || !IsAppealRemedyObjective(nextObjective))
        {
            return "";
        }

        string cta = result.succeeded ? "보정 후속 안내" : "보정 재도전 안내";
        string action = result.succeeded ? "유지 목표" : "재도전 목표";
        return $"{cta}: 추천 심사 버튼 · {action}";
    }

    private void ShowTutorial(bool launchesCampaign)
    {
        tutorialLaunchesCampaign = launchesCampaign;
        tutorialStepIndex = 0;
        if (launchesCampaign)
        {
            menuRoot.gameObject.SetActive(false);
            settingsRoot.gameObject.SetActive(false);
            endingGalleryRoot.gameObject.SetActive(false);
            achievementRoot.gameObject.SetActive(false);
            careerRecordRoot.gameObject.SetActive(false);
            creditsRoot.gameObject.SetActive(false);
            caseArchiveRoot.gameObject.SetActive(false);
            dayTransitionRoot.gameObject.SetActive(false);
            reportRoot.gameObject.SetActive(false);
            reviewRoot.gameObject.SetActive(false);
        }

