    private void TutorialBack()
    {
        if (tutorialStepIndex > 0)
        {
            tutorialStepIndex--;
            UpdateTutorialContent();
            PlaySfx(uiBackClip, 0.45f);
            return;
        }

        if (tutorialLaunchesCampaign)
        {
            BeginCampaignReview();
            return;
        }

        tutorialRoot.gameObject.SetActive(false);
        PlaySfx(uiBackClip, 0.45f);
    }

    private void TutorialNext()
    {
        if (tutorialStepIndex < TutorialStepCount() - 1)
        {
            tutorialStepIndex++;
            UpdateTutorialContent();
            return;
        }

        if (tutorialLaunchesCampaign)
        {
            BeginCampaignReview();
            return;
        }

        tutorialRoot.gameObject.SetActive(false);
        PlaySfx(uiBackClip, 0.45f);
    }

    private void UpdateTutorialContent()
    {
        int stepCount = TutorialStepCount();
        tutorialStepIndex = Mathf.Clamp(tutorialStepIndex, 0, stepCount - 1);
        tutorialTitleText.text = TutorialTitleForStep(tutorialStepIndex);
        tutorialBodyText.text = TutorialBodyForStep(tutorialStepIndex) + $"\n\n({tutorialStepIndex + 1} / {stepCount})";
        if (tutorialChecklistText != null)
        {
            tutorialChecklistText.text = TutorialChecklistForStep(tutorialStepIndex);
        }
        tutorialBackButtonText.text = tutorialStepIndex == 0
            ? (tutorialLaunchesCampaign ? "건너뛰기" : "닫기")
            : "이전";
        tutorialNextButtonText.text = tutorialStepIndex == stepCount - 1
            ? (tutorialLaunchesCampaign ? "심사 시작" : "닫기")
            : "다음";
        UpdateTutorialCaseArchiveButton();
    }

    private void UpdateTutorialCaseArchiveButton()
    {
        if (tutorialCaseArchiveButton == null)
        {
            return;
        }

        bool canOpenCase =
            tutorialLaunchesCampaign &&
            tutorialStepIndex == 0 &&
            CurrentCampaignIsAppealRemedyObjective() &&
            !string.IsNullOrWhiteSpace(currentCampaignCaseObjectiveId);
        tutorialCaseArchiveButton.gameObject.SetActive(canOpenCase);
        tutorialCaseArchiveButton.interactable = canOpenCase;
        if (tutorialCaseArchiveButtonText != null)
        {
            tutorialCaseArchiveButtonText.text = canOpenCase ? "원 사례" : "원 사례";
            tutorialCaseArchiveButtonText.fontSize = 18;
        }
    }

    private void OpenTutorialCaseObjectiveArchive()
    {
        if (!CurrentCampaignIsAppealRemedyObjective() || string.IsNullOrWhiteSpace(currentCampaignCaseObjectiveId))
        {
            PlaySfx(errorDeniedClip, 0.55f);
            return;
        }

        string caseId = currentCampaignCaseObjectiveId;
        ShowCaseArchiveForCase(caseId);
