    private int TutorialStepCount()
    {
        return TutorialTitles.Length;
    }

    private string TutorialTitleForStep(int stepIndex)
    {
        return TutorialTitles[Mathf.Clamp(stepIndex, 0, TutorialTitles.Length - 1)];
    }

    private string TutorialBodyForStep(int stepIndex)
    {
        if (tutorialLaunchesCampaign)
        {
            return BuildFirstStartTutorialBody(stepIndex);
        }

        return TutorialBodies[Mathf.Clamp(stepIndex, 0, TutorialBodies.Length - 1)];
    }

    private string TutorialChecklistForStep(int stepIndex)
    {
        if (tutorialLaunchesCampaign)
        {
            return BuildFirstStartTutorialChecklist(stepIndex);
        }

        switch (Mathf.Clamp(stepIndex, 0, TutorialTitles.Length - 1))
        {
            case 0:
                return "오늘 할 일\n- 1일차 접수 규모 확인\n- 시작 예산과 운영 기준 확인\n- 첫 신청서까지 바로 진입";
            case 1:
                return "읽는 위치\n- 중앙 신청서: 유형/요청/위험 신호\n- 아래 서류: 누락/증빙 강도\n- 오른쪽 지표: 예산/위험 압박";
            case 2:
                return "도장 선택 전\n- [권장]은 기준표와 가장 맞는 선택\n- [대체]는 가능하지만 더 비싸거나 위험함\n- Q/근거 버튼으로 판단 이유를 남김";
            default:
                return "첫 사례 시작\n- 5단계 하이라이트 가이드 확인\n- 미리보기 비교\n- 도장으로 첫 판단 기록";
        }
    }

    private string BuildFirstStartTutorialBody(int stepIndex)
    {
        switch (Mathf.Clamp(stepIndex, 0, TutorialTitles.Length - 1))
        {
            case 0:
                return BuildTodayMissionTutorialBody();
            case 1:
                return TutorialBodies[1];
            case 2:
                return TutorialBodies[2];
            default:
                return TutorialBodies[3];
        }
    }

    private string BuildFirstStartTutorialChecklist(int stepIndex)
    {
        switch (Mathf.Clamp(stepIndex, 0, TutorialTitles.Length - 1))
        {
            case 0:
                string checklist =
                    "오늘 할 일\n" +
                    $"- 오늘 접수 {CountCasesForDay(1)}건 중 첫 신청서부터 처리\n" +
                    $"- 전체 {cases.Count}건 캠페인 완주\n" +
                    $"- 시작 예산 {StartingBudgetForMandate(campaignMandate)}만원 관리\n" +
                    $"- 캠페인 챌린지: {CampaignChallengeTitle(campaignMandate)}";
                if (currentCampaignStartedFromGrowthObjective)
                {
                    checklist += "\n- 성장 목표와 직전 회차 대비 개선 기준";
                }
                if (currentCampaignStartedFromGrowthFollowUpObjective)
                {
                    checklist += "\n- 성장 후속 목표와 다음 운영 기준 실험";
                }
                if (CurrentCampaignIsAppealRemedyObjective())
                {
                    checklist += "\n- 이의제기 원 사례와 보정 조치";
                    checklist += "\n- 고위험 지연 기준 확인";
                }
                if (currentCampaignStartedFromDecisionAuditCoachingObjective)
                {
                    checklist += "\n- 판단 복기 목표와 압박 패턴 추적";
                }
                return checklist;
            case 1:
                return "읽는 순서\n1. 중앙 신청서\n2. 아래 서류\n3. 오른쪽 지표/기준표\n4. 도장 위 미리보기";
            case 2:
                return "판단 기준\n- 승인: 안정 상승, 예산 소모\n- 조건부: 비용 절감, 확인 업무 발생\n- 추가조사/보류/거절: 예산 보전, 지연 위험";
            default:
                return "첫 사례 시작\n- 다음 버튼은 심사 화면으로 이동\n- 첫 사례 가이드는 5단계 유지\n- 마지막에는 도장으로 첫 판단";
        }
    }

    private string BuildTodayMissionTutorialBody()
    {
        string body =
            $"오늘 할 일: 오늘 접수 {CountCasesForDay(1)}건을 처리하고, 전체 {cases.Count}건 캠페인의 기준을 잡습니다.\n\n" +
            $"운영 기준: {CampaignMandateLabel(campaignMandate)} · 시작 예산 {StartingBudgetForMandate(campaignMandate)}만원 · {CampaignMandateBrief(campaignMandate)}\n" +
            $"캠페인 챌린지: {CampaignChallengeTitle(campaignMandate)} · {CampaignChallengeObjective(campaignMandate)}";
        if (currentCampaignStartedFromGrowthObjective)
        {
            body += $"\n\n성장 목표: {currentCampaignGrowthObjectiveChallenge}\n근거: {currentCampaignGrowthObjectiveReason}";
        }
        else if (currentCampaignStartedFromGrowthFollowUpObjective)
        {
            body += $"\n\n성장 후속 목표: {currentCampaignGrowthFollowUpChallenge}\n근거: {currentCampaignGrowthFollowUpReason}";
        }
        else if (CurrentCampaignIsAppealRemedyObjective())
        {
            body += $"\n\n이의제기 보정 목표: {currentCampaignCaseObjectiveChallenge}\n원 사례: {currentCampaignCaseObjectiveId}";
            if (!string.IsNullOrWhiteSpace(currentCampaignCaseObjectiveReason))
            {
                body += $"\n보정 조치/근거: {Shorten(currentCampaignCaseObjectiveReason, 86)}";
            }
        }
        else if (currentCampaignStartedFromDecisionPracticeObjective)
        {
            body +=
                $"\n\n판단 비교 연습: {currentCampaignCaseObjectiveChallenge}\n" +
                $"기준 사례: {currentCampaignCaseObjectiveId}\n" +
                (!string.IsNullOrWhiteSpace(currentCampaignCaseObjectiveReason) ? $"근거: {currentCampaignCaseObjectiveReason}" : "");
        }
        else if (currentCampaignStartedFromDecisionAuditCoachingObjective)
        {
            body +=
                $"\n\n판단 복기 목표: {currentCampaignDecisionAuditCoachingChallenge}\n" +
                $"패턴: {currentCampaignDecisionAuditCoachingPattern}\n" +
                $"근거: {currentCampaignDecisionAuditCoachingReason}";
        }

        return body;
    }

    private int CountCasesForDay(int day)
    {
        int count = 0;
        for (int i = 0; i < cases.Count; i++)
        {
            if (cases[i].day == day)
            {
                count++;
            }
        }

        return count;
    }

