    private void UpdateFirstCaseGuideContent()
    {
        firstCaseGuideStepIndex = Mathf.Clamp(firstCaseGuideStepIndex, 0, FirstCaseGuideTitles.Length - 1);
        firstCaseGuideTitleText.text = $"{firstCaseGuideStepIndex + 1}. {FirstCaseGuideTitles[firstCaseGuideStepIndex]}";
        firstCaseGuideBodyText.text = FirstCaseGuideBodies[firstCaseGuideStepIndex];
        firstCaseGuideButtonText.text = firstCaseGuideStepIndex == FirstCaseGuideTitles.Length - 1 ? "이해함" : "다음";
        SetRect(firstCaseHighlightImage.rectTransform, FirstCaseGuideHighlightPositions[firstCaseGuideStepIndex], FirstCaseGuideHighlightSizes[firstCaseGuideStepIndex]);
        UpdateFirstCaseGuideSpotlightMask(FirstCaseGuideHighlightPositions[firstCaseGuideStepIndex], FirstCaseGuideHighlightSizes[firstCaseGuideStepIndex]);
    }

    private void UpdateFirstCaseGuideSpotlightMask(Vector2 highlightPosition, Vector2 highlightSize)
    {
        if (firstCaseGuideMaskImages == null || firstCaseGuideMaskImages.Length < 4)
        {
            return;
        }

        const float minX = -960f;
        const float maxX = 960f;
        const float minY = -540f;
        const float maxY = 540f;
        float x1 = Mathf.Clamp(highlightPosition.x - highlightSize.x * 0.5f - 10f, minX, maxX);
        float x2 = Mathf.Clamp(highlightPosition.x + highlightSize.x * 0.5f + 10f, minX, maxX);
        float y1 = Mathf.Clamp(highlightPosition.y - highlightSize.y * 0.5f - 10f, minY, maxY);
        float y2 = Mathf.Clamp(highlightPosition.y + highlightSize.y * 0.5f + 10f, minY, maxY);

        SetMaskRect(firstCaseGuideMaskImages[0], minX, x1, minY, maxY);
        SetMaskRect(firstCaseGuideMaskImages[1], x2, maxX, minY, maxY);
        SetMaskRect(firstCaseGuideMaskImages[2], x1, x2, y2, maxY);
        SetMaskRect(firstCaseGuideMaskImages[3], x1, x2, minY, y1);
    }

    private void SetMaskRect(Image mask, float xMin, float xMax, float yMin, float yMax)
    {
        if (mask == null)
        {
            return;
        }

        float width = Mathf.Max(0f, xMax - xMin);
        float height = Mathf.Max(0f, yMax - yMin);
        mask.enabled = width > 1f && height > 1f;
        SetRect(mask.rectTransform, new Vector2((xMin + xMax) * 0.5f, (yMin + yMax) * 0.5f), new Vector2(width, height));
    }

    private void ContinueCampaign()
    {
        pendingDeleteSlot = -1;
        if (!LoadSession())
        {
            PlaySfx(errorDeniedClip, 0.60f);
            UpdateMenuStatus("저장된 세션을 불러오지 못했습니다. 새 캠페인을 시작해 주세요.");
        }
    }

