    private void ManualSave()
    {
        SaveSession(false);
        feedbackText.text = $"현재 심사 진행 상황을 슬롯 {activeSaveSlot}에 저장했습니다.";
        PlaySfx(saveClip, 0.85f);
    }

    private void SelectSaveSlot(int slot)
    {
        activeSaveSlot = Mathf.Clamp(slot, 1, MaxSaveSlots);
        appealRemedyGraphTriageCandidateIndex = LoadAppealRemedyGraphTriageCandidateIndexForSlot(activeSaveSlot);
        pendingDeleteSlot = -1;
        PlayerPrefs.SetInt(SaveSlotPrefsKey, activeSaveSlot);
        PlayerPrefs.Save();
        UpdateMenuStatus();
    }

    private void RequestDeleteSaveSlot()
    {
        bool saveExists = File.Exists(SavePath);
        string backupPath = SaveBackupPathForSlot(activeSaveSlot);
        bool backupExists = File.Exists(backupPath);
        if (!saveExists && !backupExists)
        {
            pendingDeleteSlot = -1;
            PlaySfx(errorDeniedClip, 0.55f);
            UpdateMenuStatus($"선택 슬롯 {activeSaveSlot}에는 삭제할 저장이 없습니다.");
            return;
        }

        if (pendingDeleteSlot != activeSaveSlot)
        {
            pendingDeleteSlot = activeSaveSlot;
            PlaySfx(errorDeniedClip, 0.42f);
            UpdateMenuStatus($"슬롯 {activeSaveSlot} 저장을 삭제하려면 삭제 확인을 한 번 더 누르세요.");
            return;
        }

        string deletedFileName = Path.GetFileName(SavePath);
        try
        {
            if (saveExists)
            {
                File.Delete(SavePath);
            }
            if (backupExists)
            {
                File.Delete(backupPath);
            }
            ResetCampaignState();
            pendingDeleteSlot = -1;
            UpdateMenuStatus($"슬롯 {activeSaveSlot} 저장 파일을 삭제했습니다: {deletedFileName}");
        }
        catch (Exception exception)
        {
            pendingDeleteSlot = -1;
            PlaySfx(errorDeniedClip, 0.60f);
            UpdateMenuStatus("저장 파일 삭제에 실패했습니다: " + exception.Message);
        }
    }

    private void RequestClearLocalData()
    {
        if (!pendingClearLocalData)
        {
            pendingClearLocalData = true;
            UpdateClearLocalDataButton();
            PlaySfx(errorDeniedClip, 0.42f);
            UpdateSettingsStatus("로컬 데이터 삭제를 다시 누르면 저장 슬롯, 플레이 기록, 성과/엔딩/캠페인 기록을 지웁니다. 실행 파일과 설치 파일은 지우지 않습니다.");
            return;
        }

        try
        {
            LocalDataCleanupResult result = ClearLocalDataAtPath(LogDirectory, true);
            pendingClearLocalData = false;
            pendingDeleteSlot = -1;
            activeSaveSlot = 1;
            ResetCampaignState();
            UpdateClearLocalDataButton();

            if (result.completed)
            {
                UpdateSettingsStatus(
                    "로컬 데이터 삭제 완료\n" +
                    $"파일 {result.filesDeleted}개 · 폴더 {result.directoriesDeleted}개 · 진행 기록 {result.playerPrefsDeleted}개 삭제\n" +
                    "설정값, 실행 파일, 설치 파일은 유지했습니다.");
            }
            else
            {
                UpdateSettingsStatus(
                    "로컬 데이터 삭제 중 확인이 필요합니다.\n" +
                    $"안전 경로: {(result.rootPathSafe ? "통과" : "차단")} · 실패 {result.deleteFailureCount}건\n" +
                    "게임 데이터 폴더 밖의 파일은 건드리지 않았습니다.");
            }
        }
        catch (Exception exception)
        {
            pendingClearLocalData = false;
            UpdateClearLocalDataButton();
            PlaySfx(errorDeniedClip, 0.60f);
            UpdateSettingsStatus("로컬 데이터 삭제 실패: " + exception.Message);
        }
    }

    private LocalDataCleanupResult ClearLocalDataAtPath(string rootPath, bool clearProgressPrefs)
    {
        LocalDataCleanupResult result = new();
        if (!IsSafeLocalDataRoot(rootPath))
        {
            result.rootPathSafe = false;
            result.completed = false;
            return result;
        }

        result.rootPathSafe = true;
        try
        {
            Directory.CreateDirectory(rootPath);
        }
        catch
        {
            result.deleteFailureCount++;
            result.completed = false;
            return result;
        }

        string[] files = Array.Empty<string>();
        try
        {
            files = Directory.GetFiles(rootPath);
        }
        catch
        {
            result.deleteFailureCount++;
        }

        for (int i = 0; i < files.Length; i++)
        {
            string fileName = Path.GetFileName(files[i]);
            if (IsManagedLocalDataFile(fileName))
            {
                TryDeleteManagedFile(files[i], result);
            }
        }

        string[] managedDirectories =
        {
#if CARE_REVIEW_QA_TOOLS
            "playtest_sessions",
            "support_bundles",
            "low_resolution_ui_v030",
            "incident_cards_v030",
            "store_screenshots_v030",
            "trailer_frames_v030",
            "local_data_delete_smoke_v030"
#endif
        };

        for (int i = 0; i < managedDirectories.Length; i++)
        {
            TryDeleteManagedDirectory(Path.Combine(rootPath, managedDirectories[i]), result);
        }

        if (clearProgressPrefs)
        {
            result.playerPrefsDeleted += ClearProgressPlayerPrefs();
        }

        result.completed = result.rootPathSafe && result.deleteFailureCount == 0;
        return result;
    }

    private bool IsSafeLocalDataRoot(string rootPath)
    {
        if (string.IsNullOrWhiteSpace(rootPath))
        {
            return false;
        }

        try
        {
            string fullRoot = NormalizeFullPath(rootPath);
            string fullLogRoot = NormalizeFullPath(LogDirectory);
            return IsSameOrChildPath(fullRoot, fullLogRoot);
        }
        catch
        {
            return false;
        }
    }

    private static string NormalizeFullPath(string path)
    {
        return Path.GetFullPath(path).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
    }

    private static bool IsSameOrChildPath(string candidatePath, string parentPath)
    {
        if (string.Equals(candidatePath, parentPath, StringComparison.OrdinalIgnoreCase))
        {
            return true;
        }

        string parentWithSeparator = parentPath + Path.DirectorySeparatorChar;
        return candidatePath.StartsWith(parentWithSeparator, StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsManagedLocalDataFile(string fileName)
    {
        for (int slot = 1; slot <= MaxSaveSlots; slot++)
        {
            if (string.Equals(fileName, SaveFileNameForSlot(slot), StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }
        }

        return fileName.StartsWith("care_review_", StringComparison.OrdinalIgnoreCase) &&
            fileName.IndexOf('.') >= 0;
    }

    private static void TryDeleteManagedFile(string filePath, LocalDataCleanupResult result)
    {
        try
        {
            if (File.Exists(filePath))
            {
                File.Delete(filePath);
                result.filesDeleted++;
            }
        }
        catch
        {
            result.deleteFailureCount++;
        }
    }

    private static void TryDeleteManagedDirectory(string directoryPath, LocalDataCleanupResult result)
    {
        try
        {
            if (Directory.Exists(directoryPath))
            {
                Directory.Delete(directoryPath, true);
                result.directoriesDeleted++;
            }
        }
        catch
        {
            result.deleteFailureCount++;
        }
    }

    private int ClearProgressPlayerPrefs()
    {
        int deleted = 0;
        EndingOutcome[] endings = BuildEndingCatalog();
        for (int i = 0; i < endings.Length; i++)
        {
            deleted += DeletePlayerPrefIfExists(EndingSeenPrefsPrefix + endings[i].id);
            for (int mandateIndex = 0; mandateIndex < CampaignMandateCatalog.Length; mandateIndex++)
            {
                deleted += DeletePlayerPrefIfExists(EndingSeenForMandateKey(CampaignMandateCatalog[mandateIndex], endings[i].id));
            }
        }

        deleted += DeletePlayerPrefIfExists(LastEndingPrefsKey);
        for (int i = 0; i < CampaignMandateCatalog.Length; i++)
        {
            deleted += DeletePlayerPrefIfExists(LastEndingForMandateKey(CampaignMandateCatalog[i]));
        }

        AchievementDefinition[] achievements = BuildAchievementCatalog();
        for (int i = 0; i < achievements.Length; i++)
        {
            deleted += DeletePlayerPrefIfExists(AchievementUnlockedPrefsPrefix + achievements[i].id);
            deleted += DeletePlayerPrefIfExists(AchievementUnlockedAtPrefsPrefix + achievements[i].id);
        }

        deleted += DeletePlayerPrefIfExists(CareerRecordPrefsKey);
        for (int slot = 1; slot <= MaxSaveSlots; slot++)
        {
            deleted += DeletePlayerPrefIfExists(AppealRemedyTriageCandidatePrefsKeyForSlot(slot));
        }

        if (PlayerPrefs.GetInt(SaveSlotPrefsKey, 1) != 1)
        {
            deleted++;
        }

        activeSaveSlot = 1;
        PlayerPrefs.SetInt(SaveSlotPrefsKey, activeSaveSlot);
        PlayerPrefs.Save();
        return deleted;
    }

    private static int DeletePlayerPrefIfExists(string key)
    {
        if (!PlayerPrefs.HasKey(key))
        {
            return 0;
        }

        PlayerPrefs.DeleteKey(key);
        return 1;
    }

