    private void StartSystemDiagnosticExport()
    {
        if (systemDiagnosticRunning)
        {
            UpdateSettingsStatus("환경 진단을 이미 실행 중입니다.");
            return;
        }

        StartCoroutine(RunSystemDiagnosticExportRoutine());
    }

    private IEnumerator RunSystemDiagnosticExportRoutine()
    {
        systemDiagnosticRunning = true;
        UpdateSettingsStatus("환경 진단을 실행 중입니다. CPU/GPU/RAM, 화면 설정, FPS 샘플을 로컬 파일로 저장합니다.");

        List<PerformanceScreenSample> samples = new();
        yield return MeasureCurrentDiagnosticScreen("settings", samples);
        PerformanceScreenSample sample = samples.Count > 0 ? samples[0] : BuildEmptyPerformanceSample("settings");

        try
        {
            string sessionId = EnsureSessionId();
            string sessionDirectoryPath = SessionDirectory(sessionId);
            Directory.CreateDirectory(sessionDirectoryPath);
            string jsonPath = Path.Combine(sessionDirectoryPath, "care_review_system_diagnostic.json");
            string markdownPath = Path.Combine(sessionDirectoryPath, "care_review_system_diagnostic.md");

            SystemDiagnosticExport diagnostic = BuildSystemDiagnosticExport(sessionId, sample, jsonPath, markdownPath);
            File.WriteAllText(jsonPath, JsonUtility.ToJson(diagnostic, true), Encoding.UTF8);
            File.WriteAllText(markdownPath, BuildSystemDiagnosticMarkdown(diagnostic), Encoding.UTF8);
            WriteLatestPlaytestPacketCopies(jsonPath, markdownPath);

            systemDiagnosticRunning = false;
            string notice =
                $"환경 진단 저장 완료: {sample.p95FrameMs:0.0}ms p95 · {(sample.passesFrameBudget ? "통과" : "확인 필요")}\n" +
                $"세션 폴더: {SessionRelativeDirectory(sessionId)}\n" +
                $"파일: {Path.GetFileName(jsonPath)} / {Path.GetFileName(markdownPath)}\n" +
                "로컬 저장 전용이며 서버로 자동 업로드하지 않습니다.";
            UpdateSettingsStatus(notice);
            Debug.Log("CARE_REVIEW_SYSTEM_DIAGNOSTIC path=" + jsonPath + " markdown=" + markdownPath + " completed=True");
        }
        catch (Exception exception)
        {
            systemDiagnosticRunning = false;
            UpdateSettingsStatus("환경 진단 저장 실패: " + exception.Message);
            Debug.LogError("CARE_REVIEW_SYSTEM_DIAGNOSTIC completed=False error=" + exception);
        }
    }

