    private SupportBundleExport ExportSupportBundleFiles()
    {
        Directory.CreateDirectory(LogDirectory);
        WriteRuntimeIssueLogFiles();
        string sessionId = EnsureSessionId();
        string bundleName = "care_review_support_bundle_" + DateTime.UtcNow.ToString("yyyyMMddHHmmss") + "_" + SafePathSegment(sessionId);
        string bundleDirectoryPath = Path.Combine(LogDirectory, "support_bundles", bundleName);
        Directory.CreateDirectory(bundleDirectoryPath);

        SupportBundleExport bundle = new()
        {
            generatedAt = DateTime.Now.ToString("s"),
            sessionId = sessionId,
            buildVersion = BuildVersionLabel,
            bundleName = bundleName,
            bundleDirectoryPath = bundleDirectoryPath,
            files = new List<string>()
        };

        string[] latestFileNames =
        {
            "care_review_play_log.json",
            "care_review_play_log.csv",
            "care_review_incident_log.csv",
            "care_review_playtest_summary.json",
            "care_review_playtest_feedback.md",
            "care_review_analytics_dashboard.html",
            "care_review_in_game_feedback.json",
            "care_review_in_game_feedback.md",
            "care_review_system_diagnostic.json",
            "care_review_system_diagnostic.md",
            RuntimeIssuesJsonFileName,
            RuntimeIssuesMarkdownFileName,
            "care_review_playtest_sessions_index.csv",
            "care_review_playtest_aggregate.json",
            "care_review_playtest_aggregate.md"
        };

        foreach (string fileName in latestFileNames)
        {
            if (CopyFileIntoSupportBundle(Path.Combine(LogDirectory, fileName), bundleDirectoryPath, fileName, bundle.files))
            {
                bundle.latestFileCount++;
            }
        }

        string saveDirectoryPath = Path.Combine(bundleDirectoryPath, "saves");
        foreach (string savePath in Directory.GetFiles(LogDirectory, "care_review_save*.json*", SearchOption.TopDirectoryOnly))
        {
            string saveFileName = Path.GetFileName(savePath);
            if (saveFileName.EndsWith(".tmp", StringComparison.OrdinalIgnoreCase) ||
                saveFileName.IndexOf("_backup", StringComparison.OrdinalIgnoreCase) >= 0 ||
                saveFileName.IndexOf("_original", StringComparison.OrdinalIgnoreCase) >= 0)
            {
                continue;
            }

            if (CopyFileIntoSupportBundle(savePath, saveDirectoryPath, "saves/" + Path.GetFileName(savePath), bundle.files))
            {
                bundle.saveFileCount++;
            }
        }

        string sessionDirectoryPath = SessionDirectory(sessionId);
        if (Directory.Exists(sessionDirectoryPath))
        {
            string relativeSessionDirectory = "playtest_sessions/" + SafePathSegment(sessionId);
            string targetSessionDirectory = Path.Combine(bundleDirectoryPath, "playtest_sessions", SafePathSegment(sessionId));
            bundle.sessionFileCount = CopyDirectoryIntoSupportBundle(sessionDirectoryPath, targetSessionDirectory, relativeSessionDirectory, bundle.files);
        }

        bundle.fileCount = bundle.files.Count;
        bundle.hasPlayLog = SupportBundleContains(bundle, "care_review_play_log.json");
        bundle.hasSummary = SupportBundleContains(bundle, "care_review_playtest_summary.json");
        bundle.hasDashboard = SupportBundleContains(bundle, "care_review_analytics_dashboard.html");
        bundle.hasDiagnostic = SupportBundleContains(bundle, "care_review_system_diagnostic.json") && SupportBundleContains(bundle, "care_review_system_diagnostic.md");
        bundle.hasSurvey = SupportBundleContains(bundle, "care_review_in_game_feedback.json") && SupportBundleContains(bundle, "care_review_in_game_feedback.md");
        bundle.hasRuntimeIssues = SupportBundleContains(bundle, RuntimeIssuesJsonFileName) && SupportBundleContains(bundle, RuntimeIssuesMarkdownFileName);
        bundle.triageActionsCsvReferencePath = NormalizeShareablePath(ExternalHandoffActionsCsvReferencePath);
        bundle.triageActionsCsvReferenceAvailable = File.Exists(ExternalHandoffActionsCsvReferencePath);
        bundle.externalHandoffZipReferencePath = NormalizeShareablePath(ExternalHandoffZipReferencePath);
        bundle.externalHandoffHashReferencePath = NormalizeShareablePath(ExternalHandoffHashReferencePath);
        bundle.externalHandoffHashReferenceAvailable = File.Exists(ExternalHandoffHashReferencePath);
        bundle.externalHandoffZipSha256 = bundle.externalHandoffHashReferenceAvailable
            ? File.ReadAllText(ExternalHandoffHashReferencePath, Encoding.UTF8).Trim()
            : "";

        string manifestJsonPath = Path.Combine(bundleDirectoryPath, "care_review_support_bundle_manifest.json");
        string manifestMarkdownPath = Path.Combine(bundleDirectoryPath, "care_review_support_bundle_manifest.md");
        File.WriteAllText(manifestJsonPath, BuildSupportBundleManifestJson(bundle), Encoding.UTF8);
        File.WriteAllText(manifestMarkdownPath, BuildSupportBundleManifestMarkdown(bundle), Encoding.UTF8);
        bundle.files.Add("care_review_support_bundle_manifest.json");
        bundle.files.Add("care_review_support_bundle_manifest.md");
        bundle.fileCount = bundle.files.Count;
        bundle.filesHaveNoLocalAbsolutePath = SupportBundleFilesHaveNoLocalAbsolutePath(bundleDirectoryPath);

        File.WriteAllText(manifestJsonPath, BuildSupportBundleManifestJson(bundle), Encoding.UTF8);
        File.WriteAllText(manifestMarkdownPath, BuildSupportBundleManifestMarkdown(bundle), Encoding.UTF8);
        return bundle;
    }

    private static bool CopyFileIntoSupportBundle(string sourcePath, string targetDirectoryPath, string relativePath, List<string> copiedFiles)
    {
        if (string.IsNullOrEmpty(sourcePath) || !File.Exists(sourcePath))
        {
            return false;
        }

        Directory.CreateDirectory(targetDirectoryPath);
        string targetPath = Path.Combine(targetDirectoryPath, Path.GetFileName(sourcePath));
        File.Copy(sourcePath, targetPath, true);
        copiedFiles.Add(NormalizeShareablePath(relativePath));
        return true;
    }

    private static int CopyDirectoryIntoSupportBundle(string sourceDirectoryPath, string targetDirectoryPath, string relativeDirectoryPath, List<string> copiedFiles)
    {
        int count = 0;
        Directory.CreateDirectory(targetDirectoryPath);
        foreach (string sourcePath in Directory.GetFiles(sourceDirectoryPath, "*", SearchOption.AllDirectories))
        {
            string relativeFilePath = sourcePath.Substring(sourceDirectoryPath.Length).TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
            string targetPath = Path.Combine(targetDirectoryPath, relativeFilePath);
            string targetParent = Path.GetDirectoryName(targetPath);
            if (!string.IsNullOrEmpty(targetParent))
            {
                Directory.CreateDirectory(targetParent);
            }

            File.Copy(sourcePath, targetPath, true);
            copiedFiles.Add(NormalizeShareablePath(relativeDirectoryPath + "/" + relativeFilePath.Replace("\\", "/")));
            count++;
        }

        return count;
    }

    private static bool SupportBundleContains(SupportBundleExport bundle, string fileName)
    {
        for (int i = 0; i < bundle.files.Count; i++)
        {
            if (bundle.files[i].EndsWith(fileName, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }
        }

        return false;
    }

    private static bool SupportBundleFilesHaveNoLocalAbsolutePath(string bundleDirectoryPath)
    {
        foreach (string filePath in Directory.GetFiles(bundleDirectoryPath, "*", SearchOption.AllDirectories))
        {
            string extension = Path.GetExtension(filePath).ToLowerInvariant();
            if (extension != ".json" && extension != ".csv" && extension != ".md" && extension != ".html" && extension != ".txt")
            {
                continue;
            }

            string text = File.ReadAllText(filePath, Encoding.UTF8);
            if (ContainsLocalAbsolutePath(text))
            {
                return false;
            }
        }

        return true;
    }

    private static string BuildSupportBundleManifestJson(SupportBundleExport bundle)
    {
        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine($"  \"generatedAt\": \"{EscapeJson(bundle.generatedAt)}\",");
        builder.AppendLine($"  \"sessionId\": \"{EscapeJson(bundle.sessionId)}\",");
        builder.AppendLine($"  \"buildVersion\": \"{EscapeJson(bundle.buildVersion)}\",");
        builder.AppendLine($"  \"bundleName\": \"{EscapeJson(bundle.bundleName)}\",");
        builder.AppendLine($"  \"fileCount\": {bundle.fileCount},");
        builder.AppendLine($"  \"latestFileCount\": {bundle.latestFileCount},");
        builder.AppendLine($"  \"sessionFileCount\": {bundle.sessionFileCount},");
        builder.AppendLine($"  \"saveFileCount\": {bundle.saveFileCount},");
        builder.AppendLine($"  \"hasPlayLog\": {(bundle.hasPlayLog ? "true" : "false")},");
        builder.AppendLine($"  \"hasSummary\": {(bundle.hasSummary ? "true" : "false")},");
        builder.AppendLine($"  \"hasDashboard\": {(bundle.hasDashboard ? "true" : "false")},");
        builder.AppendLine($"  \"hasDiagnostic\": {(bundle.hasDiagnostic ? "true" : "false")},");
        builder.AppendLine($"  \"hasSurvey\": {(bundle.hasSurvey ? "true" : "false")},");
        builder.AppendLine($"  \"hasRuntimeIssues\": {(bundle.hasRuntimeIssues ? "true" : "false")},");
        builder.AppendLine($"  \"triageActionsCsvReferencePath\": \"{EscapeJson(bundle.triageActionsCsvReferencePath)}\",");
        builder.AppendLine($"  \"triageActionsCsvReferenceAvailable\": {(bundle.triageActionsCsvReferenceAvailable ? "true" : "false")},");
        builder.AppendLine($"  \"externalHandoffZipReferencePath\": \"{EscapeJson(bundle.externalHandoffZipReferencePath)}\",");
        builder.AppendLine($"  \"externalHandoffHashReferencePath\": \"{EscapeJson(bundle.externalHandoffHashReferencePath)}\",");
        builder.AppendLine($"  \"externalHandoffHashReferenceAvailable\": {(bundle.externalHandoffHashReferenceAvailable ? "true" : "false")},");
        builder.AppendLine($"  \"externalHandoffZipSha256\": \"{EscapeJson(bundle.externalHandoffZipSha256)}\",");
        builder.AppendLine($"  \"filesHaveNoLocalAbsolutePath\": {(bundle.filesHaveNoLocalAbsolutePath ? "true" : "false")},");
        builder.AppendLine("  \"files\": [");
        for (int i = 0; i < bundle.files.Count; i++)
        {
            string suffix = i == bundle.files.Count - 1 ? "" : ",";
            builder.AppendLine($"    \"{EscapeJson(bundle.files[i])}\"{suffix}");
        }
        builder.AppendLine("  ]");
        builder.AppendLine("}");
        return builder.ToString();
    }

