        builder.AppendLine($"- 파일 수: {bundle.fileCount}");
        builder.AppendLine($"- 최신 사본: {bundle.latestFileCount}");
        builder.AppendLine($"- 세션 원본: {bundle.sessionFileCount}");
        builder.AppendLine($"- 저장 파일: {bundle.saveFileCount}");
        builder.AppendLine($"- 로그 포함: {BoolLabel(bundle.hasPlayLog)}");
        builder.AppendLine($"- 요약 포함: {BoolLabel(bundle.hasSummary)}");
        builder.AppendLine($"- HTML 대시보드 포함: {BoolLabel(bundle.hasDashboard)}");
        builder.AppendLine($"- 환경 진단 포함: {BoolLabel(bundle.hasDiagnostic)}");
        builder.AppendLine($"- 설문 포함: {BoolLabel(bundle.hasSurvey)}");
        builder.AppendLine($"- 런타임 이슈 로그 포함: {BoolLabel(bundle.hasRuntimeIssues)}");
        builder.AppendLine($"- 분류 조치 CSV 참조: `{bundle.triageActionsCsvReferencePath}` ({BoolLabel(bundle.triageActionsCsvReferenceAvailable)})");
        builder.AppendLine($"- 외부 인계 zip 참조: `{bundle.externalHandoffZipReferencePath}`");
        builder.AppendLine($"- 외부 인계 해시 참조: `{bundle.externalHandoffHashReferencePath}` ({BoolLabel(bundle.externalHandoffHashReferenceAvailable)})");
        builder.AppendLine($"- 외부 인계 zip SHA256: `{bundle.externalHandoffZipSha256}`");
        builder.AppendLine($"- 로컬 사용자 절대경로 미포함: {BoolLabel(bundle.filesHaveNoLocalAbsolutePath)}");
        builder.AppendLine();
        builder.AppendLine("## 포함 파일");
        builder.AppendLine();
        foreach (string file in bundle.files)
        {
            builder.AppendLine("- `" + file + "`");
        }

        return builder.ToString();
    }

    private void HandleRuntimeLogMessage(string condition, string stackTrace, LogType type)
    {
        if (writingRuntimeIssueLog || !ShouldCaptureRuntimeIssue(type))
        {
            return;
        }

        CaptureRuntimeIssue(type, condition, stackTrace);
    }

    private static bool ShouldCaptureRuntimeIssue(LogType type)
    {
        return type == LogType.Warning ||
            type == LogType.Error ||
            type == LogType.Exception ||
            type == LogType.Assert;
    }

    private void CaptureRuntimeIssue(LogType type, string condition, string stackTrace)
    {
        RuntimeIssueLogEntry entry = new()
        {
            capturedAt = DateTime.Now.ToString("s"),
            type = type.ToString(),
            message = SanitizeRuntimeIssueText(condition, MaxRuntimeIssueMessageCharacters),
            stackSummary = BuildRuntimeIssueStackSummary(stackTrace),
            screen = RuntimeIssueScreenName(),
            caseIndex = Mathf.Clamp(currentIndex, 0, cases.Count),
            decisionCount = logs.Count
        };

        runtimeIssueEntries.Add(entry);
        while (runtimeIssueEntries.Count > MaxRuntimeIssueEntries)
        {
            runtimeIssueEntries.RemoveAt(0);
        }

        if (type == LogType.Warning)
        {
            runtimeWarningCount++;
        }
        else if (type == LogType.Exception)
        {
            runtimeExceptionCount++;
        }
        else
        {
            runtimeErrorCount++;
        }

        WriteRuntimeIssueLogFiles();
    }

    private void ResetRuntimeIssueLog()
    {
        runtimeIssueEntries.Clear();
        runtimeWarningCount = 0;
        runtimeErrorCount = 0;
        runtimeExceptionCount = 0;
        DeleteFileIfExists(Path.Combine(LogDirectory, RuntimeIssuesJsonFileName));
        DeleteFileIfExists(Path.Combine(LogDirectory, RuntimeIssuesMarkdownFileName));
    }

    private void WriteRuntimeIssueLogFiles()
    {
        if (writingRuntimeIssueLog || runtimeIssueEntries.Count == 0)
        {
            return;
        }

        writingRuntimeIssueLog = true;
        try
        {
            Directory.CreateDirectory(LogDirectory);
            string jsonPath = Path.Combine(LogDirectory, RuntimeIssuesJsonFileName);
            string markdownPath = Path.Combine(LogDirectory, RuntimeIssuesMarkdownFileName);
            File.WriteAllText(jsonPath, BuildRuntimeIssueLogJson(), Encoding.UTF8);
            File.WriteAllText(markdownPath, BuildRuntimeIssueLogMarkdown(), Encoding.UTF8);
        }
        catch
        {
        }
        finally
        {
            writingRuntimeIssueLog = false;
        }
    }

    private string BuildRuntimeIssueLogJson()
    {
        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine($"  \"generatedAt\": \"{EscapeJson(DateTime.Now.ToString("s"))}\",");
        builder.AppendLine($"  \"buildVersion\": \"{EscapeJson(BuildVersionLabel)}\",");
        builder.AppendLine($"  \"sessionId\": \"{EscapeJson(EnsureSessionId())}\",");
        builder.AppendLine($"  \"warningCount\": {runtimeWarningCount},");
        builder.AppendLine($"  \"errorCount\": {runtimeErrorCount},");
        builder.AppendLine($"  \"exceptionCount\": {runtimeExceptionCount},");
        builder.AppendLine($"  \"entryCount\": {runtimeIssueEntries.Count},");
        builder.AppendLine($"  \"maxEntries\": {MaxRuntimeIssueEntries},");
        builder.AppendLine("  \"filesHaveNoLocalAbsolutePath\": true,");
        builder.AppendLine("  \"entries\": [");
        for (int i = 0; i < runtimeIssueEntries.Count; i++)
        {
            RuntimeIssueLogEntry entry = runtimeIssueEntries[i];
            string suffix = i == runtimeIssueEntries.Count - 1 ? "" : ",";
            builder.AppendLine("    {");
            builder.AppendLine($"      \"capturedAt\": \"{EscapeJson(entry.capturedAt)}\",");
            builder.AppendLine($"      \"type\": \"{EscapeJson(entry.type)}\",");
            builder.AppendLine($"      \"message\": \"{EscapeJson(entry.message)}\",");
            builder.AppendLine($"      \"stackSummary\": \"{EscapeJson(entry.stackSummary)}\",");
            builder.AppendLine($"      \"screen\": \"{EscapeJson(entry.screen)}\",");
            builder.AppendLine($"      \"caseIndex\": {entry.caseIndex},");
            builder.AppendLine($"      \"decisionCount\": {entry.decisionCount}");
            builder.AppendLine("    }" + suffix);
        }
        builder.AppendLine("  ]");
        builder.AppendLine("}");
        return builder.ToString();
    }

    private string BuildRuntimeIssueLogMarkdown()
    {
        StringBuilder builder = new();
        builder.AppendLine("# 돌봄지원 심사소 런타임 이슈 로그");
        builder.AppendLine();
        builder.AppendLine("- 생성 시각: " + DateTime.Now.ToString("s"));
        builder.AppendLine("- 빌드: " + BuildVersionLabel);
        builder.AppendLine("- 세션 ID: " + EnsureSessionId());
        builder.AppendLine("- Warning: " + runtimeWarningCount);
        builder.AppendLine("- Error: " + runtimeErrorCount);
        builder.AppendLine("- Exception: " + runtimeExceptionCount);
        builder.AppendLine("- 로컬 사용자 절대경로 미포함: yes");
        builder.AppendLine();
        builder.AppendLine("## 최근 항목");
        builder.AppendLine();
        foreach (RuntimeIssueLogEntry entry in runtimeIssueEntries)
        {
            builder.AppendLine("### " + entry.type + " / " + entry.capturedAt);
            builder.AppendLine();
            builder.AppendLine("- 화면: " + entry.screen);
            builder.AppendLine("- 진행: 사례 " + entry.caseIndex + " / 판단 " + entry.decisionCount);
            builder.AppendLine("- 메시지: `" + entry.message + "`");
            if (!string.IsNullOrEmpty(entry.stackSummary))
            {
                builder.AppendLine("- 스택 요약: `" + entry.stackSummary + "`");
            }
            builder.AppendLine();
        }

        return builder.ToString();
    }

    private string BuildRuntimeIssueStackSummary(string stackTrace)
    {
        string sanitized = SanitizeRuntimeIssueText(stackTrace, MaxRuntimeIssueStackCharacters);
        if (string.IsNullOrEmpty(sanitized))
        {
            return "";
        }

        string[] lines = sanitized.Split('\n');
        StringBuilder builder = new();
        int included = 0;
        for (int i = 0; i < lines.Length && included < 8; i++)
        {
            string line = lines[i].Trim();
            if (line.Length == 0)
            {
                continue;
            }

            if (builder.Length > 0)
            {
                builder.Append(" | ");
            }
            builder.Append(line);
            included++;
        }

        return Shorten(builder.ToString(), MaxRuntimeIssueStackCharacters);
    }

    private string SanitizeRuntimeIssueText(string value, int maxCharacters)
    {
        if (string.IsNullOrEmpty(value))
        {
            return "";
        }

        string sanitized = value.Replace("\\", "/");
        string persistentPath = Application.persistentDataPath.Replace("\\", "/");
        string userProfile = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile).Replace("\\", "/");
        if (!string.IsNullOrEmpty(persistentPath))
        {
            sanitized = sanitized.Replace(persistentPath, "[local-data]");
        }
        if (!string.IsNullOrEmpty(userProfile))
        {
            sanitized = sanitized.Replace(userProfile, "[user-home]");
        }

        sanitized = sanitized
            .Replace("C:/Users", "[user-root]")
            .Replace("/AppData/", "/[app-data]/")
            .Replace("AppData", "[app-data]")
            .Replace("LocalLow", "[local-low]");

        return Shorten(sanitized, maxCharacters);
    }

    private string RuntimeIssueScreenName()
    {
        if (reportRoot != null && reportRoot.gameObject.activeSelf) return "report";
        if (reviewRoot != null && reviewRoot.gameObject.activeSelf) return "review";
        if (settingsRoot != null && settingsRoot.gameObject.activeSelf) return "settings";
        if (menuRoot != null && menuRoot.gameObject.activeSelf) return "menu";
        if (tutorialRoot != null && tutorialRoot.gameObject.activeSelf) return "tutorial";
        if (creditsRoot != null && creditsRoot.gameObject.activeSelf) return "credits";
        if (dayTransitionRoot != null && dayTransitionRoot.gameObject.activeSelf) return "day_transition";
        return "unknown";
    }

