    private void ApplyAudioSettings()
    {
        AudioListener.volume = volumeLevel / 100f;
        if (sfxSource != null)
        {
            sfxSource.volume = 0.82f;
        }

        if (musicSource != null)
        {
            musicSource.volume = volumeLevel > 0 ? 0.18f : 0f;
            if (!Application.isBatchMode && volumeLevel > 0 && !musicSource.isPlaying)
            {
                musicSource.Play();
            }
        }
    }

    private void ApplyDisplaySettings()
    {
        Vector2Int resolution = ResolutionOptions[Mathf.Clamp(resolutionIndex, 0, ResolutionOptions.Length - 1)];
        Screen.SetResolution(resolution.x, resolution.y, fullscreenEnabled ? FullScreenMode.FullScreenWindow : FullScreenMode.Windowed);
    }

    private void ApplyPerformanceSettings()
    {
        QualitySettings.vSyncCount = 0;
        if (lowSpecMode)
        {
            QualitySettings.antiAliasing = 0;
            QualitySettings.shadowDistance = 0f;
            Application.targetFrameRate = 30;
            return;
        }

        QualitySettings.antiAliasing = 2;
        QualitySettings.shadowDistance = 50f;
        Application.targetFrameRate = FrameRateOptions[Mathf.Clamp(frameRateIndex, 0, FrameRateOptions.Length - 1)];
    }

    private string ResolutionLabel()
    {
        Vector2Int resolution = ResolutionOptions[Mathf.Clamp(resolutionIndex, 0, ResolutionOptions.Length - 1)];
        return $"{resolution.x} x {resolution.y}";
    }

    private string FrameRateLabel()
    {
        if (lowSpecMode)
        {
            return "30 FPS";
        }

        int frameRate = FrameRateOptions[Mathf.Clamp(frameRateIndex, 0, FrameRateOptions.Length - 1)];
        return frameRate > 0 ? $"{frameRate} FPS" : "제한 없음";
    }

