    private void HandleKeyboardShortcuts()
    {
        if (firstRunNoticeRoot != null && firstRunNoticeRoot.gameObject.activeSelf)
        {
            if (Input.GetKeyDown(KeyCode.Return) || Input.GetKeyDown(KeyCode.KeypadEnter) || Input.GetKeyDown(KeyCode.Space))
            {
                AcceptFirstRunNotice();
            }
            return;
        }

        if (firstCaseGuideRoot != null && firstCaseGuideRoot.gameObject.activeSelf)
        {
            if (Input.GetKeyDown(KeyCode.Return) || Input.GetKeyDown(KeyCode.KeypadEnter) || Input.GetKeyDown(KeyCode.Space) || Input.GetKeyDown(KeyCode.RightArrow))
            {
                AdvanceFirstCaseGuide();
            }
            else if (Input.GetKeyDown(KeyCode.Escape))
            {
                DismissFirstCaseGuide();
            }
            return;
        }

        if (tutorialRoot != null && tutorialRoot.gameObject.activeSelf)
        {
            if (Input.GetKeyDown(KeyCode.Return) || Input.GetKeyDown(KeyCode.KeypadEnter) || Input.GetKeyDown(KeyCode.Space) || Input.GetKeyDown(KeyCode.RightArrow))
            {
                TutorialNext();
            }
            else if (Input.GetKeyDown(KeyCode.LeftArrow) || Input.GetKeyDown(KeyCode.Backspace))
            {
                TutorialBack();
            }
            else if (Input.GetKeyDown(KeyCode.Escape))
            {
                ShowMainMenu();
            }
            return;
        }

        if (creditsRoot != null && creditsRoot.gameObject.activeSelf)
        {
            if (Input.GetKeyDown(KeyCode.Escape) || Input.GetKeyDown(KeyCode.M))
            {
                ShowMainMenu();
            }
            else if (Input.GetKeyDown(KeyCode.S))
            {
                ShowSettings();
            }
            return;
        }

        if (settingsRoot != null && settingsRoot.gameObject.activeSelf)
        {
            if (Input.GetKeyDown(KeyCode.Escape) || Input.GetKeyDown(KeyCode.M))
            {
                ShowMainMenu();
            }
            else if (Input.GetKeyDown(KeyCode.T))
            {
                ToggleLargeText();
            }
            else if (Input.GetKeyDown(KeyCode.C))
            {
                ToggleHighContrast();
            }
            else if (Input.GetKeyDown(KeyCode.A))
            {
                ToggleAutoSave();
            }
            else if (Input.GetKeyDown(KeyCode.D))
            {
                CycleCampaignMandate();
            }
            else if (Input.GetKeyDown(KeyCode.I))
            {
                ShowCreditsNotice();
            }
            else if (Input.GetKeyDown(KeyCode.P))
            {
                ToggleLowSpecMode();
            }
            else if (Input.GetKeyDown(KeyCode.O))
            {
                RequestClearLocalData();
            }
            else if (Input.GetKeyDown(KeyCode.Minus) || Input.GetKeyDown(KeyCode.KeypadMinus))
            {
                DecreaseVolume();
            }
            else if (Input.GetKeyDown(KeyCode.Equals) || Input.GetKeyDown(KeyCode.KeypadPlus))
            {
                IncreaseVolume();
            }
            return;
        }

        if (dayTransitionRoot != null && dayTransitionRoot.gameObject.activeSelf)
        {
            if (Input.GetKeyDown(KeyCode.Return) || Input.GetKeyDown(KeyCode.KeypadEnter) || Input.GetKeyDown(KeyCode.Space) || Input.GetKeyDown(KeyCode.N))
            {
                ContinueAfterDayTransition();
            }
            else if (Input.GetKeyDown(KeyCode.Escape) || Input.GetKeyDown(KeyCode.M))
