    private void HandleControllerShortcuts()
    {
        if (firstRunNoticeRoot != null && firstRunNoticeRoot.gameObject.activeSelf)
        {
            if (ControllerSubmitPressed())
            {
                AcceptFirstRunNotice();
            }
            return;
        }

        if (firstCaseGuideRoot != null && firstCaseGuideRoot.gameObject.activeSelf)
        {
            if (ControllerSubmitPressed() || ControllerRightShoulderPressed())
            {
                AdvanceFirstCaseGuide();
            }
            else if (ControllerCancelPressed())
            {
                DismissFirstCaseGuide();
            }
            return;
        }

        if (tutorialRoot != null && tutorialRoot.gameObject.activeSelf)
        {
            if (ControllerSubmitPressed() || ControllerRightShoulderPressed())
            {
                TutorialNext();
            }
            else if (ControllerCancelPressed() || ControllerLeftShoulderPressed())
            {
                TutorialBack();
            }
            else if (ControllerMenuPressed())
            {
                ShowMainMenu();
            }
            return;
        }

        if (settingsRoot != null && settingsRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed())
            {
                ShowMainMenu();
            }
            else if (ControllerSubmitPressed())
            {
                ToggleAutoSave();
            }
            else if (ControllerWestPressed())
            {
                ToggleHighContrast();
            }
            else if (ControllerNorthPressed())
            {
                ToggleLargeText();
            }
            else if (ControllerRightShoulderPressed())
            {
                CycleCampaignMandate();
            }
            return;
        }

        if (creditsRoot != null && creditsRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed())
            {
                ShowMainMenu();
            }
            else if (ControllerWestPressed())
            {
                ShowSettings();
            }
            return;
        }

        if (dayTransitionRoot != null && dayTransitionRoot.gameObject.activeSelf)
        {
            if (ControllerSubmitPressed() || ControllerMenuPressed())
            {
                ContinueAfterDayTransition();
            }
            else if (ControllerCancelPressed())
            {
                ReturnToMenu();
            }
            return;
        }

        if (decisionHistoryRoot != null && decisionHistoryRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed() || ControllerViewPressed())
            {
                HideDecisionHistory();
            }
            return;
        }

        if (followUpInboxRoot != null && followUpInboxRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed() || ControllerNorthPressed())
            {
                HideFollowUpInbox();
            }
            else if (ControllerViewPressed())
            {
                ShowDecisionHistory();
            }
            return;
        }

        if (policyHandbookRoot != null && policyHandbookRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed() || ControllerLeftShoulderPressed())
            {
                HidePolicyHandbook();
            }
            return;
        }

        if (reviewRoot != null && reviewRoot.gameObject.activeSelf)
        {
            if (ControllerRightShoulderPressed())
            {
                CycleDecisionRationale();
            }
            else if (ControllerViewPressed())
            {
                ShowDecisionHistory();
            }
            else if (ControllerMenuPressed())
            {
                ManualSave();
            }
            else if (awaitingNext && ControllerSubmitPressed())
            {
                AdvanceToNextCase();
            }
            else if (awaitingNext && ControllerCancelPressed())
            {
                ReturnToMenu();
            }
            else if (!awaitingNext)
            {
                if (ControllerSubmitPressed())
                {
                    Decide(DecisionKind.Approve);
                }
                else if (ControllerWestPressed())
                {
                    Decide(DecisionKind.Conditional);
                }
                else if (ControllerNorthPressed())
                {
                    Decide(DecisionKind.Hold);
                }
                else if (ControllerLeftShoulderPressed())
                {
                    Decide(DecisionKind.Investigate);
                }
                else if (ControllerCancelPressed())
                {
                    Decide(DecisionKind.Reject);
                }
            }
            return;
        }

        if (reportRoot != null && reportRoot.gameObject.activeSelf)
        {
#if CARE_REVIEW_QA_TOOLS
            if (playtestSurveyRoot != null && playtestSurveyRoot.gameObject.activeSelf)
            {
                if (ControllerCancelPressed() || ControllerNorthPressed())
                {
                    ClosePlaytestSurvey();
                }
                else if (ControllerSubmitPressed() || ControllerWestPressed())
                {
                    SavePlaytestSurvey();
                }
                return;
            }
#endif

            if (ControllerCancelPressed())
            {
                ReturnToMenu();
            }
            else if (ControllerViewPressed())
            {
                RunAgentSimulation();
            }
            else if (ControllerSubmitPressed())
            {
                Restart();
            }
            return;
        }

        if (endingGalleryRoot != null && endingGalleryRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed())
            {
                ShowMainMenu();
            }
            else if (ControllerSubmitPressed())
            {
                StartNewCampaign();
            }
            else if (ControllerRightShoulderPressed() || ControllerLeftShoulderPressed())
            {
                CycleEndingGalleryMandate();
            }
            else if (ControllerWestPressed())
            {
                ToggleEndingGalleryFollowUpFilter();
            }
            return;
        }

        if (achievementRoot != null && achievementRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed())
            {
                ShowMainMenu();
            }
            else if (ControllerSubmitPressed())
            {
                StartNewCampaign();
            }
            else if (ControllerRightShoulderPressed())
            {
                ShowEndingGallery();
            }
            else if (ControllerLeftShoulderPressed())
            {
                ShowCareerRecords();
            }
            return;
        }

        if (careerRecordRoot != null && careerRecordRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed())
            {
                ShowMainMenu();
            }
            else if (ControllerSubmitPressed())
            {
                StartNewCampaign();
            }
            else if (ControllerWestPressed())
            {
                ShowAchievements();
            }
            else if (ControllerRightShoulderPressed())
            {
                ShowEndingGallery();
            }
            return;
        }

        if (caseArchiveRoot != null && caseArchiveRoot.gameObject.activeSelf)
        {
            if (ControllerCancelPressed())
            {
                ShowMainMenu();
            }
            else if (ControllerSubmitPressed())
            {
                StartCaseArchiveObjectiveCampaign();
            }
            else if (ControllerRightShoulderPressed())
            {
                NextCaseArchivePage();
            }
            else if (ControllerLeftShoulderPressed())
            {
                PreviousCaseArchivePage();
            }
            else if (ControllerWestPressed())
            {
                CycleCaseArchiveFilter();
            }
            return;
        }

        if (menuRoot != null && menuRoot.gameObject.activeSelf)
        {
            if (ControllerSubmitPressed())
            {
                StartNewCampaign();
            }
            else if (ControllerWestPressed() && continueButton != null && continueButton.interactable)
            {
                ContinueCampaign();
            }
            else if (ControllerNorthPressed())
            {
                ShowSettings();
            }
            else if (ControllerCancelPressed())
            {
                ShowCreditsNotice();
            }
            else if (ControllerRightShoulderPressed() || ControllerLeftShoulderPressed())
            {
                CycleCampaignMandate();
            }
            else if (ControllerViewPressed())
            {
                ShowCareerRecords();
            }
        }
    }

