    private IEnumerator RunAppealReviewSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        bool hadCaseObjectiveAchievement = IsAchievementUnlocked("case_objective_replay");
        string previousCaseObjectiveAt = AchievementUnlockedAt("case_objective_replay");
        bool hadAppealRemedyAchievement = IsAchievementUnlocked("appeal_remedy_objective");
        string previousAppealRemedyAt = AchievementUnlockedAt("appeal_remedy_objective");
        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.Save();

        ResetCampaignState();
        appealRemedyGraphTriageCandidateIndex = 0;
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        caseArchiveRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);

        int appealIndex = 0;
        for (int i = 0; i < cases.Count; i++)
        {
            if (cases[i].urgency >= 80 && cases[i].recommendedDecision != "거절")
            {
                appealIndex = i;
                break;
            }
        }

        currentIndex = 0;
        ShowCase(currentIndex);
        int guard = cases.Count * 4 + 20;
        while (currentIndex < appealIndex && guard > 0)
        {
            if (dayTransitionRoot.gameObject.activeSelf)
            {
                ContinueAfterDayTransition();
                yield return null;
                guard--;
                continue;
            }

            if (!awaitingNext)
            {
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }

        CareCase appealCase = cases[currentIndex];
        Decide(DecisionKind.Reject);
        yield return null;

        DecisionLog log = logs.Count > 0 ? logs[logs.Count - 1] : null;
        int appealScore = AppealReviewScore(log);
        bool logCreatesAppeal = log != null && appealScore >= 35 && AppealReviewStatus(log) != "기록 보관";

        ShowFollowUpInbox();
        yield return null;
        string inboxSummary = followUpInboxSummaryText != null ? followUpInboxSummaryText.text : "";
        string inboxBody = followUpInboxBodyText != null ? followUpInboxBodyText.text : "";
        bool inboxMentionsAppeal = inboxSummary.Contains("이의제기 검토") &&
            inboxBody.Contains("이의제기 검토") &&
            inboxBody.Contains("보정") &&
            inboxBody.Contains(appealCase.id);

        ShowCaseArchiveForCase(appealCase.id);
        yield return null;
        string archiveDetail = caseArchiveDetailText != null ? caseArchiveDetailText.text : "";
        bool archiveMentionsAppeal = archiveDetail.Contains("이의제기 검토") &&
            archiveDetail.Contains("보정 조치") &&
            archiveDetail.Contains(appealCase.id);

        string csv = BuildPlayLogCsv(logs, campaignMandate, "appeal-review-smoke");
        bool csvHasAppealColumns = csv.Contains("appeal_review_score") &&
            csv.Contains("appeal_review_status") &&
            csv.Contains("appeal_review_remedy");
        bool csvHasAppealStatus = csv.Contains(AppealReviewStatus(log));

        caseArchiveRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        if (awaitingNext)
        {
            AdvanceToNextCase();
            yield return null;
        }
        yield return PlayRecommendedUntilReport();
        yield return new WaitForEndOfFrame();

        string reportSummary = reportSummaryText != null ? reportSummaryText.text : "";
        string reportInsight = reportInsightText != null ? reportInsightText.text : "";
        bool reportMentionsAppeal =
            reportSummary.Contains("이의제기 검토") &&
            reportSummary.Contains(appealCase.id) &&
            reportInsight.Contains("보정");

        CareerRecordDatabase careerDatabase = LoadCareerRecordDatabase();
        CareerRecord careerRecord = careerDatabase.records.Count > 0 ? careerDatabase.records[0] : null;
        ShowCareerRecords();
        yield return new WaitForEndOfFrame();
        string careerBody = careerRecordBodyText != null ? careerRecordBodyText.text : "";
        string careerDetail = careerRecordDetailText != null ? careerRecordDetailText.text : "";
        bool careerRecordStoresAppeal =
            careerRecord != null &&
            careerRecord.appealReviewCount > 0 &&
            careerRecord.appealReviewMaxScore >= appealScore &&
            careerRecord.appealReviewCaseId == appealCase.id;
        bool careerRecordMentionsAppeal =
            careerBody.Contains("이의제기 누적") &&
            careerBody.Contains(appealCase.id) &&
            careerDetail.Contains("이의제기 검토") &&
            careerDetail.Contains("보정 조치");

        bool completed =
            appealCase != null &&
            logCreatesAppeal &&
            inboxMentionsAppeal &&
            archiveMentionsAppeal &&
            csvHasAppealColumns &&
            csvHasAppealStatus &&
            reportMentionsAppeal &&
            careerRecordStoresAppeal &&
            careerRecordMentionsAppeal;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_appeal_review_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"caseId\": \"{EscapeJson(appealCase != null ? appealCase.id : "")}\",\n" +
            $"  \"appealScore\": {appealScore},\n" +
            $"  \"appealStatus\": \"{EscapeJson(AppealReviewStatus(log))}\",\n" +
            $"  \"logCreatesAppeal\": {(logCreatesAppeal ? "true" : "false")},\n" +
            $"  \"inboxMentionsAppeal\": {(inboxMentionsAppeal ? "true" : "false")},\n" +
            $"  \"archiveMentionsAppeal\": {(archiveMentionsAppeal ? "true" : "false")},\n" +
            $"  \"csvHasAppealColumns\": {(csvHasAppealColumns ? "true" : "false")},\n" +
            $"  \"csvHasAppealStatus\": {(csvHasAppealStatus ? "true" : "false")},\n" +
            $"  \"reportMentionsAppeal\": {(reportMentionsAppeal ? "true" : "false")},\n" +
            $"  \"careerRecordStoresAppeal\": {(careerRecordStoresAppeal ? "true" : "false")},\n" +
            $"  \"careerRecordMentionsAppeal\": {(careerRecordMentionsAppeal ? "true" : "false")},\n" +
            $"  \"careerAppealCount\": {(careerRecord != null ? careerRecord.appealReviewCount : 0)},\n" +
            $"  \"careerAppealMaxScore\": {(careerRecord != null ? careerRecord.appealReviewMaxScore : 0)}\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_APPEAL_REVIEW_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " score=" + appealScore);
        if (hadPreviousRecords)
        {
            PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
        }
        else
        {
            PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        }
        RestoreAchievementPref("case_objective_replay", hadCaseObjectiveAchievement, previousCaseObjectiveAt);
        RestoreAchievementPref("appeal_remedy_objective", hadAppealRemedyAchievement, previousAppealRemedyAt);
        PlayerPrefs.Save();
        Application.Quit();
    }

