    private IEnumerator RunInvestigationFollowUpSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);

        int investigationIndex = 0;
        for (int i = 0; i < cases.Count; i++)
        {
            if (cases[i].day == 1 && cases[i].recommendedDecision == "추가조사")
            {
                investigationIndex = i;
                break;
            }
        }

        currentIndex = investigationIndex;
        ShowCase(currentIndex);
        yield return null;

        CareCase investigatedCase = cases[currentIndex];
        Decide(DecisionKind.Investigate);
        yield return null;

        bool findingUnlocked = logs.Count > 0 && !string.IsNullOrWhiteSpace(logs[logs.Count - 1].investigationFinding);
        ShowFollowUpInbox();
        yield return null;
        string inboxSummary = followUpInboxSummaryText != null ? followUpInboxSummaryText.text : "";
        bool inboxSummaryMentionsMemo = inboxSummary.Contains("조사 메모 1");
        HideFollowUpInbox();

        int expectedBudget = 0;
        int expectedStability = 0;
        int expectedEquity = 0;
        int expectedMissedRisk = 0;
        int expectedComplaints = 0;
        InvestigationFollowUpImpact expectedImpact = new(0, 0, 0, 0, 0, 0, "");

        int guard = cases.Count * 3;
        while (!dayTransitionRoot.gameObject.activeSelf && currentIndex < cases.Count && guard > 0)
        {
            if (!awaitingNext)
            {
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                bool crossingToNextDay = currentIndex + 1 < cases.Count && ShouldShowDayTransition(currentIndex, currentIndex + 1);
                if (crossingToNextDay)
                {
                    int completedDay = cases[currentIndex].day;
                    expectedImpact = BuildInvestigationFollowUpImpact(completedDay);
                    SumDayConsequenceDeltas(
                        completedDay,
                        out int consequenceBudgetDelta,
                        out int consequenceStabilityDelta,
                        out int consequenceEquityDelta,
                        out int consequenceMissedRiskDelta,
                        out int consequenceComplaintsDelta);
                    expectedBudget = budget + consequenceBudgetDelta + expectedImpact.budgetDelta + CalculateDailyBudgetReallocation(completedDay + 1);
                    expectedStability = Mathf.Clamp(stability + consequenceStabilityDelta + expectedImpact.stabilityDelta, 0, 100);
                    expectedEquity = Mathf.Clamp(equity + consequenceEquityDelta + expectedImpact.equityDelta, 0, 100);
                    expectedMissedRisk = Mathf.Clamp(missedRisk + consequenceMissedRiskDelta + expectedImpact.missedRiskDelta, 0, 100);
                    expectedComplaints = Mathf.Clamp(complaints + consequenceComplaintsDelta + expectedImpact.complaintsDelta, 0, 100);
                }

                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }

        string body = dayTransitionBodyText != null ? dayTransitionBodyText.text : "";
        bool transitionActive = dayTransitionRoot != null && dayTransitionRoot.gameObject.activeSelf;
        bool briefingMentionsFollowUp =
            body.Contains("조사 후속") &&
            body.Contains("해금 메모") &&
            body.Contains("누락 " + SignedNumber(expectedImpact.missedRiskDelta)) &&
            body.Contains("민원 " + SignedNumber(expectedImpact.complaintsDelta));
        bool metricsReflectFollowUp =
            transitionActive &&
            expectedImpact.count > 0 &&
            budget == expectedBudget &&
            stability == expectedStability &&
            equity == expectedEquity &&
            missedRisk == expectedMissedRisk &&
            complaints == expectedComplaints;

        bool completed =
            guard > 0 &&
            findingUnlocked &&
            inboxSummaryMentionsMemo &&
            transitionActive &&
            expectedImpact.count > 0 &&
            briefingMentionsFollowUp &&
            metricsReflectFollowUp;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_investigation_follow_up_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"findingUnlocked\": {(findingUnlocked ? "true" : "false")},\n" +
            $"  \"inboxSummaryMentionsMemo\": {(inboxSummaryMentionsMemo ? "true" : "false")},\n" +
            $"  \"transitionActive\": {(transitionActive ? "true" : "false")},\n" +
            $"  \"briefingMentionsFollowUp\": {(briefingMentionsFollowUp ? "true" : "false")},\n" +
            $"  \"metricsReflectFollowUp\": {(metricsReflectFollowUp ? "true" : "false")},\n" +
            $"  \"investigationFollowUpCount\": {expectedImpact.count},\n" +
            $"  \"investigatedCaseId\": \"{EscapeJson(investigatedCase.id)}\",\n" +
            $"  \"expectedBudget\": {expectedBudget},\n" +
            $"  \"actualBudget\": {budget},\n" +
            $"  \"expectedMissedRisk\": {expectedMissedRisk},\n" +
            $"  \"actualMissedRisk\": {missedRisk},\n" +
            $"  \"expectedComplaints\": {expectedComplaints},\n" +
            $"  \"actualComplaints\": {complaints},\n" +
            $"  \"briefingText\": \"{EscapeJson(body)}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_INVESTIGATION_FOLLOW_UP_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " case=" + investigatedCase.id);
        Application.Quit();
    }

