    private IEnumerator RunDecisionRationaleSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        string initialRationaleId = CurrentDecisionRationaleId();
        CycleDecisionRationale();
        yield return null;

        string selectedRationaleId = CurrentDecisionRationaleId();
        string selectedRationaleName = CurrentDecisionRationaleName();
        string selectedRationaleLabel = CurrentDecisionRationaleLabel();
        string selectedRationaleDescription = CurrentDecisionRationaleDescription();
        string buttonText = rationaleButtonText != null ? rationaleButtonText.text : "";
        string metricText = metricDeltaText != null ? metricDeltaText.text : "";
        bool changedRationale = !string.Equals(initialRationaleId, selectedRationaleId, StringComparison.OrdinalIgnoreCase);
        bool buttonUpdated = buttonText.Contains(selectedRationaleLabel);
        bool metricMentionsRationale = metricText.Contains(selectedRationaleName) || metricText.Contains(selectedRationaleLabel);

        Decide(DecisionKindFromLabel(cases[0].recommendedDecision));
        yield return null;

        DecisionLog log = logs.Count > 0 ? logs[0] : null;
        bool logHasRationale = log != null &&
            string.Equals(log.decisionRationaleId, selectedRationaleId, StringComparison.OrdinalIgnoreCase) &&
            string.Equals(log.decisionRationaleLabel, selectedRationaleName, StringComparison.Ordinal) &&
            string.Equals(log.decisionRationaleDescription, selectedRationaleDescription, StringComparison.Ordinal);

        string csv = BuildPlayLogCsv(logs, campaignMandate, "smoke-session");
        bool csvHasRationaleColumns = csv.Contains("decision_rationale_id,decision_rationale_label,decision_rationale_description");
        bool csvHasRationaleValue = csv.Contains(selectedRationaleId) &&
            csv.Contains(selectedRationaleName) &&
            csv.Contains(selectedRationaleDescription);

        ShowDecisionHistory();
        yield return null;
        string historyBody = decisionHistoryBodyText != null ? decisionHistoryBodyText.text : "";
        bool historyMentionsRationale = historyBody.Contains("근거") && historyBody.Contains(selectedRationaleLabel);
        HideDecisionHistory();

        ShowFollowUpInbox();
        yield return null;
        string inboxBody = followUpInboxBodyText != null ? followUpInboxBodyText.text : "";
        bool inboxMentionsRationale = inboxBody.Contains("근거") && inboxBody.Contains(selectedRationaleLabel);
        HideFollowUpInbox();

        bool completed = changedRationale &&
            buttonUpdated &&
            metricMentionsRationale &&
            logHasRationale &&
            csvHasRationaleColumns &&
            csvHasRationaleValue &&
            historyMentionsRationale &&
            inboxMentionsRationale;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_decision_rationale_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"changedRationale\": {(changedRationale ? "true" : "false")},\n" +
            $"  \"buttonUpdated\": {(buttonUpdated ? "true" : "false")},\n" +
            $"  \"metricMentionsRationale\": {(metricMentionsRationale ? "true" : "false")},\n" +
            $"  \"logHasRationale\": {(logHasRationale ? "true" : "false")},\n" +
            $"  \"csvHasRationaleColumns\": {(csvHasRationaleColumns ? "true" : "false")},\n" +
            $"  \"csvHasRationaleValue\": {(csvHasRationaleValue ? "true" : "false")},\n" +
            $"  \"historyMentionsRationale\": {(historyMentionsRationale ? "true" : "false")},\n" +
            $"  \"inboxMentionsRationale\": {(inboxMentionsRationale ? "true" : "false")},\n" +
            $"  \"selectedRationaleId\": \"{EscapeJson(selectedRationaleId)}\",\n" +
            $"  \"selectedRationaleName\": \"{EscapeJson(selectedRationaleName)}\",\n" +
            $"  \"logCount\": {logs.Count}\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_DECISION_RATIONALE_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " rationale=" + selectedRationaleId);
        Application.Quit();
    }

    private IEnumerator RunDecisionRationaleAnalyticsSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        int guard = cases.Count * 4 + 20;
        while (currentIndex < cases.Count && guard > 0)
        {
            if (dayTransitionRoot.gameObject.activeSelf)
            {
                ContinueAfterDayTransition();
                yield return null;
            }

            if (currentIndex < cases.Count && !awaitingNext)
            {
                selectedDecisionRationaleIndex = ClampDecisionRationaleIndex(currentIndex);
                UpdateDecisionRationaleButton();
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }

        bool reportActive = reportRoot != null && reportRoot.gameObject.activeSelf;
        string reportInsight = reportInsightText != null ? reportInsightText.text : "";
        bool reportMentionsRationale = reportInsight.Contains("판단 근거 분포") && reportInsight.Contains("위험 신호 우선");
        List<DecisionRationaleSummaryExport> summaries = BuildDecisionRationaleSummaries();
        bool summariesHaveAllRationales = summaries.Count == DecisionRationaleIds.Length;
        bool summariesHaveCounts = true;
        int totalSummaryCount = 0;
        for (int i = 0; i < summaries.Count; i++)
        {
            totalSummaryCount += summaries[i].count;
            if (summaries[i].count <= 0)
            {
                summariesHaveCounts = false;
            }
        }

        ExportLog();
        yield return null;

        string summaryPath = Path.Combine(LogDirectory, "care_review_playtest_summary.json");
        string dashboardPath = Path.Combine(LogDirectory, "care_review_analytics_dashboard.html");
        string summaryText = File.Exists(summaryPath) ? File.ReadAllText(summaryPath, Encoding.UTF8) : "";
        string dashboardText = File.Exists(dashboardPath) ? File.ReadAllText(dashboardPath, Encoding.UTF8) : "";
        bool summaryHasRationaleAnalytics = summaryText.Contains("\"decisionRationaleSummaries\"") &&
            summaryText.Contains("\"topDecisionRationaleName\"") &&
            summaryText.Contains("위험 신호 우선");
        bool dashboardHasRationaleAnalytics = dashboardText.Contains("판단 근거 분포") &&
            dashboardText.Contains("위험 신호 우선") &&
            dashboardText.Contains("decision_rationale");

        bool completed = guard > 0 &&
            reportActive &&
            logs.Count == cases.Count &&
            reportMentionsRationale &&
            summariesHaveAllRationales &&
            summariesHaveCounts &&
            totalSummaryCount == logs.Count &&
            summaryHasRationaleAnalytics &&
            dashboardHasRationaleAnalytics;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_decision_rationale_analytics_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"reportActive\": {(reportActive ? "true" : "false")},\n" +
            $"  \"reportMentionsRationale\": {(reportMentionsRationale ? "true" : "false")},\n" +
            $"  \"summariesHaveAllRationales\": {(summariesHaveAllRationales ? "true" : "false")},\n" +
            $"  \"summariesHaveCounts\": {(summariesHaveCounts ? "true" : "false")},\n" +
            $"  \"summaryHasRationaleAnalytics\": {(summaryHasRationaleAnalytics ? "true" : "false")},\n" +
            $"  \"dashboardHasRationaleAnalytics\": {(dashboardHasRationaleAnalytics ? "true" : "false")},\n" +
            $"  \"summaryCount\": {totalSummaryCount},\n" +
            $"  \"logCount\": {logs.Count},\n" +
            $"  \"caseCount\": {cases.Count}\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_DECISION_RATIONALE_ANALYTICS_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " summaries=" + summaries.Count);
        Application.Quit();
    }

