    private IEnumerator RunDecisionPreviewSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        CareCase careCase = cases.Count > 0 ? cases[0] : null;
        string combinedPreview = "";
        int previewCount = 0;
        bool allPreviewTextsPresent = decisionPreviewTexts != null && decisionPreviewTexts.Length == PolicyDecisionOrder.Length;
        bool everyPreviewMentionsBudget = allPreviewTextsPresent;
        bool everyPreviewMentionsRisk = allPreviewTextsPresent;
        bool recommendedHighlighted = false;
        bool allPreviewBackersPresent = allPreviewTextsPresent;

        if (decisionPreviewTexts != null)
        {
            for (int i = 0; i < decisionPreviewTexts.Length; i++)
            {
                Text previewText = decisionPreviewTexts[i];
                if (previewText == null)
                {
                    allPreviewTextsPresent = false;
                    everyPreviewMentionsBudget = false;
                    everyPreviewMentionsRisk = false;
                    allPreviewBackersPresent = false;
                    continue;
                }

                previewCount++;
                string preview = previewText.text ?? "";
                combinedPreview += preview + "\n";
                everyPreviewMentionsBudget &= preview.Contains("예산") && preview.Contains("만");
                everyPreviewMentionsRisk &= preview.Contains("위험");
                recommendedHighlighted |= preview.Contains("권장") && careCase != null && preview.Contains(careCase.recommendedDecision);
                allPreviewBackersPresent &= previewText.transform.parent != null && previewText.transform.parent.GetComponent<Image>() != null;
            }
        }

        bool completed = careCase != null &&
            allPreviewTextsPresent &&
            previewCount == PolicyDecisionOrder.Length &&
            everyPreviewMentionsBudget &&
            everyPreviewMentionsRisk &&
            recommendedHighlighted &&
            allPreviewBackersPresent;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_decision_preview_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"previewCount\": {previewCount},\n" +
            $"  \"expectedPreviewCount\": {PolicyDecisionOrder.Length},\n" +
            $"  \"allPreviewTextsPresent\": {(allPreviewTextsPresent ? "true" : "false")},\n" +
            $"  \"everyPreviewMentionsBudget\": {(everyPreviewMentionsBudget ? "true" : "false")},\n" +
            $"  \"everyPreviewMentionsRisk\": {(everyPreviewMentionsRisk ? "true" : "false")},\n" +
            $"  \"recommendedHighlighted\": {(recommendedHighlighted ? "true" : "false")},\n" +
            $"  \"allPreviewBackersPresent\": {(allPreviewBackersPresent ? "true" : "false")},\n" +
            $"  \"recommendedDecision\": \"{EscapeJson(careCase != null ? careCase.recommendedDecision : "")}\",\n" +
            $"  \"previewSample\": \"{EscapeJson(Shorten(combinedPreview.Trim(), 260))}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_DECISION_PREVIEW_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        Application.Quit();
    }

