    private IEnumerator RunPolicySimulatorSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        ShowPolicyHandbook();
        yield return new WaitForEndOfFrame();

        string screenshotPath = Path.Combine(Application.persistentDataPath, "care_review_policy_simulator.png");
        if (File.Exists(screenshotPath))
        {
            File.Delete(screenshotPath);
        }
        ScreenCapture.CaptureScreenshot(screenshotPath);
        yield return new WaitForSeconds(0.5f);
        if (!IsScreenshotFileVisuallyValid(screenshotPath))
        {
            TryCaptureCanvasCameraScreenshot(screenshotPath);
        }

        string simulationText = policyHandbookSimulationText != null ? policyHandbookSimulationText.text : "";
        List<PolicySimulationResult> results = currentIndex >= 0 && currentIndex < cases.Count
            ? BuildPolicySimulationResults(cases[currentIndex])
            : new List<PolicySimulationResult>();
        bool simulatorRootActive = policyHandbookRoot != null && policyHandbookRoot.gameObject.activeSelf;
        bool hasFivePresets = results.Count == 5 &&
            simulationText.Contains("균형 기준") &&
            simulationText.Contains("지원 확대") &&
            simulationText.Contains("긴축 감사") &&
            simulationText.Contains("위험 우선") &&
            simulationText.Contains("예산 방어");
        bool everyPresetCoversAllCases = results.Count == 5;
        bool everyPresetHasMetrics = results.Count == 5;
        bool currentCasePreviewReady = simulationText.Contains("현재 ") && simulationText.Contains(DecisionLabel(results.Count > 0 ? results[0].currentCaseDecision : DecisionKind.Hold));
        for (int i = 0; i < results.Count; i++)
        {
            everyPresetCoversAllCases &= results[i].caseCount == cases.Count;
            everyPresetHasMetrics &=
                results[i].supportCount + results[i].investigateCount + results[i].delayCount == results[i].caseCount &&
                results[i].matchedCount >= 0 &&
                simulationText.Contains(results[i].finalBudget.ToString()) &&
                simulationText.Contains(results[i].finalMissedRisk.ToString()) &&
                simulationText.Contains(results[i].finalComplaints.ToString());
            currentCasePreviewReady &= simulationText.Contains(DecisionLabel(results[i].currentCaseDecision));
        }

        bool summaryMentionsBigDataLoop = simulationText.Contains("40건 전체 기준 비교") &&
            simulationText.Contains("위험 최소") &&
            simulationText.Contains("예산 안정") &&
            simulationText.Contains("권장 일치") &&
            simulationText.Contains("운영 기준을 바꾸면");
        bool visualRowsReady = policySimulationRowTexts != null &&
            policySimulationSupportFills != null &&
            policySimulationInvestigationFills != null &&
            policySimulationDelayFills != null &&
            policySimulationMatchFills != null &&
            policySimulationRowTexts.Length == 5 &&
            policySimulationSupportFills.Length == 5 &&
            policySimulationInvestigationFills.Length == 5 &&
            policySimulationDelayFills.Length == 5 &&
            policySimulationMatchFills.Length == 5;
        int visualRowsWithText = 0;
        int visualRowsWithBars = 0;
        if (visualRowsReady)
        {
            for (int i = 0; i < policySimulationRowTexts.Length; i++)
            {
                if (policySimulationRowTexts[i] != null &&
                    policySimulationRowTexts[i].text.Contains("예산") &&
                    policySimulationRowTexts[i].text.Contains("위험"))
                {
                    visualRowsWithText++;
                }
                if (policySimulationSupportFills[i] != null &&
                    policySimulationInvestigationFills[i] != null &&
                    policySimulationDelayFills[i] != null &&
                    policySimulationMatchFills[i] != null &&
                    policySimulationSupportFills[i].rectTransform.sizeDelta.x > 0f &&
                    policySimulationInvestigationFills[i].rectTransform.sizeDelta.x > 0f &&
                    policySimulationDelayFills[i].rectTransform.sizeDelta.x > 0f &&
                    policySimulationMatchFills[i].rectTransform.sizeDelta.x > 0f)
                {
                    visualRowsWithBars++;
                }
            }
        }
        bool recommendationCardsReady = policySimulationRecommendationTexts != null &&
            policySimulationRecommendationTexts.Length == 3 &&
            policySimulationRecommendationTexts[0] != null &&
            policySimulationRecommendationTexts[0].text.Contains("위험 최소") &&
            policySimulationRecommendationTexts[1] != null &&
            policySimulationRecommendationTexts[1].text.Contains("예산 안정") &&
            policySimulationRecommendationTexts[2] != null &&
            policySimulationRecommendationTexts[2].text.Contains("권장 일치");
        bool completed = simulatorRootActive &&
            hasFivePresets &&
            everyPresetCoversAllCases &&
            everyPresetHasMetrics &&
            currentCasePreviewReady &&
            visualRowsReady &&
            visualRowsWithText == 5 &&
            visualRowsWithBars == 5 &&
            recommendationCardsReady &&
            summaryMentionsBigDataLoop;
        bool screenshotCaptured = File.Exists(screenshotPath);
        string screenshotFile = Path.GetFileName(screenshotPath);

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_policy_simulator_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"simulatorRootActive\": {(simulatorRootActive ? "true" : "false")},\n" +
            $"  \"presetCount\": {results.Count},\n" +
            $"  \"expectedPresetCount\": 5,\n" +
            $"  \"caseCount\": {cases.Count},\n" +
            $"  \"hasFivePresets\": {(hasFivePresets ? "true" : "false")},\n" +
            $"  \"everyPresetCoversAllCases\": {(everyPresetCoversAllCases ? "true" : "false")},\n" +
            $"  \"everyPresetHasMetrics\": {(everyPresetHasMetrics ? "true" : "false")},\n" +
            $"  \"currentCasePreviewReady\": {(currentCasePreviewReady ? "true" : "false")},\n" +
            $"  \"summaryMentionsBigDataLoop\": {(summaryMentionsBigDataLoop ? "true" : "false")},\n" +
            $"  \"visualRowsReady\": {(visualRowsReady ? "true" : "false")},\n" +
            $"  \"visualRowsWithText\": {visualRowsWithText},\n" +
            $"  \"visualRowsWithBars\": {visualRowsWithBars},\n" +
            $"  \"recommendationCardsReady\": {(recommendationCardsReady ? "true" : "false")},\n" +
            $"  \"screenshotCaptured\": {(screenshotCaptured ? "true" : "false")},\n" +
            $"  \"screenshotFile\": \"{EscapeJson(screenshotFile)}\",\n" +
            $"  \"simulationSample\": \"{EscapeJson(Shorten(simulationText, 360))}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        TryWriteProjectQaSmokeResult("care_review_policy_simulator_smoke_result.json", resultJson);
        Debug.Log("CARE_REVIEW_POLICY_SIMULATOR_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        Application.Quit();
    }

    private IEnumerator RunCampaignGradeSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        yield return PlayRecommendedUntilReport();
        yield return null;

        CampaignGradeResult grade = BuildCampaignGrade(CountMatchedRecommendedLogs());
        string gradeText = reportGradeText != null ? reportGradeText.text : "";
        string summaryText = reportSummaryText != null ? reportSummaryText.text : "";
        bool reportActive = reportRoot != null && reportRoot.gameObject.activeSelf;
        bool gradeVisible = gradeText.Contains("운영 등급") && gradeText.Contains("점") && gradeText.Contains(grade.grade);
        bool summaryMentionsGrade = summaryText.Contains("등급") && summaryText.Contains(grade.grade) && summaryText.Contains(grade.score.ToString());
        bool gradeHasBadge = !string.IsNullOrWhiteSpace(grade.badge) && gradeText.Contains(grade.badge);
        bool gradeHasReason = !string.IsNullOrWhiteSpace(grade.reason);
        bool scoreInRange = grade.score >= 0 && grade.score <= 100;
        bool completed = reportActive && gradeVisible && summaryMentionsGrade && gradeHasBadge && gradeHasReason && scoreInRange;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_campaign_grade_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"reportActive\": {(reportActive ? "true" : "false")},\n" +
            $"  \"gradeVisible\": {(gradeVisible ? "true" : "false")},\n" +
            $"  \"summaryMentionsGrade\": {(summaryMentionsGrade ? "true" : "false")},\n" +
            $"  \"gradeHasBadge\": {(gradeHasBadge ? "true" : "false")},\n" +
            $"  \"gradeHasReason\": {(gradeHasReason ? "true" : "false")},\n" +
            $"  \"scoreInRange\": {(scoreInRange ? "true" : "false")},\n" +
            $"  \"score\": {grade.score},\n" +
            $"  \"grade\": \"{EscapeJson(grade.grade)}\",\n" +
            $"  \"badge\": \"{EscapeJson(grade.badge)}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_CAMPAIGN_GRADE_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " grade=" + grade.grade + " score=" + grade.score);
        Application.Quit();
    }

    private IEnumerator RunCampaignChallengeSmokeTest()
    {
        yield return null;

        campaignMandate = CampaignMandate.Standard;
        ResetCampaignState();
        firstCaseGuideDismissed = true;
        ShowMainMenu();
        yield return null;

        string menuCard = menuMandateText != null ? menuMandateText.text : "";
        bool menuMentionsChallenge = menuCard.Contains("챌린지") && menuCard.Contains(CampaignChallengeTitle(campaignMandate));

        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        yield return PlayRecommendedUntilReport();
        yield return null;

        CampaignChallengeResult challenge = BuildCampaignChallengeResult();
        string summaryText = reportSummaryText != null ? reportSummaryText.text : "";
        string insightText = reportInsightText != null ? reportInsightText.text : "";
        string logPathText = reportLogPathText != null ? reportLogPathText.text : "";
        bool reportActive = reportRoot != null && reportRoot.gameObject.activeSelf;
        bool reportMentionsChallenge = summaryText.Contains("챌린지") &&
            insightText.Contains("캠페인 챌린지") &&
            logPathText.Contains(challenge.title) &&
            logPathText.Contains(challenge.progress);
        bool challengeSucceeded = challenge.succeeded && challenge.score >= 80;

        ExportLog();
        yield return null;

        string playLogJsonPath = Path.Combine(Application.persistentDataPath, "care_review_play_log.json");
        string feedbackPath = Path.Combine(Application.persistentDataPath, "care_review_playtest_feedback.md");
        string summaryPath = Path.Combine(Application.persistentDataPath, "care_review_playtest_summary.json");
        string dashboardPath = Path.Combine(Application.persistentDataPath, "care_review_analytics_dashboard.html");
        string playLogJsonText = File.Exists(playLogJsonPath) ? File.ReadAllText(playLogJsonPath, Encoding.UTF8) : "";
        string feedbackText = File.Exists(feedbackPath) ? File.ReadAllText(feedbackPath, Encoding.UTF8) : "";
        string summaryJsonText = File.Exists(summaryPath) ? File.ReadAllText(summaryPath, Encoding.UTF8) : "";
        string dashboardText = File.Exists(dashboardPath) ? File.ReadAllText(dashboardPath, Encoding.UTF8) : "";
        bool logHasChallenge = playLogJsonText.Contains("\"campaignChallengeId\"") && playLogJsonText.Contains("\"campaignChallengeSucceeded\"");
        bool summaryHasChallenge = summaryJsonText.Contains("\"campaignChallengeId\"") && summaryJsonText.Contains("\"campaignChallengeProgress\"");
        bool feedbackMentionsChallenge = feedbackText.Contains("캠페인 챌린지") && feedbackText.Contains("챌린지 진행");
        bool dashboardMentionsChallenge = dashboardText.Contains("캠페인 챌린지") && dashboardText.Contains(challenge.title);

        bool completed = menuMentionsChallenge &&
            reportActive &&
            reportMentionsChallenge &&
            challengeSucceeded &&
            File.Exists(playLogJsonPath) &&
            File.Exists(summaryPath) &&
            File.Exists(feedbackPath) &&
            File.Exists(dashboardPath) &&
            logHasChallenge &&
            summaryHasChallenge &&
            feedbackMentionsChallenge &&
            dashboardMentionsChallenge;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_campaign_challenge_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"menuMentionsChallenge\": {(menuMentionsChallenge ? "true" : "false")},\n" +
            $"  \"reportActive\": {(reportActive ? "true" : "false")},\n" +
            $"  \"reportMentionsChallenge\": {(reportMentionsChallenge ? "true" : "false")},\n" +
            $"  \"challengeSucceeded\": {(challengeSucceeded ? "true" : "false")},\n" +
            $"  \"logHasChallenge\": {(logHasChallenge ? "true" : "false")},\n" +
            $"  \"summaryHasChallenge\": {(summaryHasChallenge ? "true" : "false")},\n" +
            $"  \"feedbackMentionsChallenge\": {(feedbackMentionsChallenge ? "true" : "false")},\n" +
            $"  \"dashboardMentionsChallenge\": {(dashboardMentionsChallenge ? "true" : "false")},\n" +
            $"  \"challengeId\": \"{EscapeJson(challenge.id)}\",\n" +
            $"  \"challengeTitle\": \"{EscapeJson(challenge.title)}\",\n" +
            $"  \"challengeProgress\": \"{EscapeJson(challenge.progress)}\",\n" +
            $"  \"challengeScore\": {challenge.score},\n" +
            $"  \"caseCount\": {cases.Count},\n" +
            $"  \"logCount\": {logs.Count}\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_CAMPAIGN_CHALLENGE_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " challenge=" + challenge.id);
        Application.Quit();
    }

    private IEnumerator RunCaseArchiveSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        string previousTriageCandidateKey = AppealRemedyTriageCandidatePrefsKeyForSlot(activeSaveSlot);
        bool hadPreviousTriageCandidatePreference = PlayerPrefs.HasKey(previousTriageCandidateKey);
        int previousTriageCandidatePreference = PlayerPrefs.GetInt(previousTriageCandidateKey, 0);
        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.Save();

        ResetCampaignState();
        appealRemedyGraphTriageCandidateIndex = 0;
        PersistAppealRemedyGraphTriageCandidateIndex();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        caseArchiveRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);

        int appealIndex = 0;
        for (int i = 0; i < cases.Count; i++)
        {
            if (cases[i].urgency >= 80 && cases[i].recommendedDecision != "거절")
            {
                appealIndex = i;
                break;
            }
        }

        currentIndex = 0;
        ShowCase(currentIndex);
        int guard = cases.Count * 4 + 20;
        while (currentIndex < appealIndex && guard > 0)
        {
            if (dayTransitionRoot.gameObject.activeSelf)
            {
                ContinueAfterDayTransition();
                yield return null;
                guard--;
                continue;
            }

            if (!awaitingNext)
            {
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }

        string appealCaseId = currentIndex >= 0 && currentIndex < cases.Count ? cases[currentIndex].id : "";
        if (currentIndex < cases.Count)
        {
            Decide(DecisionKind.Reject);
            yield return null;
        }

        ShowCaseArchive();
        yield return null;

        string initialStatus = caseArchiveStatusText != null ? caseArchiveStatusText.text : "";
        string initialList = caseArchiveListText != null ? caseArchiveListText.text : "";
        string initialDetail = caseArchiveDetailText != null ? caseArchiveDetailText.text : "";
        bool archiveActive = caseArchiveRoot != null && caseArchiveRoot.gameObject.activeSelf;
        bool summaryMentionsCaseCount = initialStatus.Contains($"전체 {cases.Count}개") && initialStatus.Contains("합성 사례");
        bool listMentionsFirstCase = cases.Count > 0 && initialList.Contains(cases[0].id) && initialList.Contains("권장");
        bool detailMentionsRisk = initialDetail.Contains("핵심 위험 신호") && initialDetail.Contains("권장 판단");
        bool caseArchiveMentionsDecisionComparison =
            initialDetail.Contains("판단 비교") &&
            initialDetail.Contains("[권장]") &&
            initialDetail.Contains("예산") &&
            initialDetail.Contains("위험") &&
            initialDetail.Contains("후폭풍");
        string initialDecisionPracticeButtonText = caseArchiveDecisionPracticeButtonText != null ? caseArchiveDecisionPracticeButtonText.text : "";
        bool caseArchiveDecisionPracticeButtonReady =
            initialDecisionPracticeButtonText.Contains("연습");
        bool caseArchiveDecisionPracticeApplied = ApplyCaseArchiveDecisionPracticeObjective();
        yield return null;
        string decisionPracticeStatus = caseArchiveStatusText != null ? caseArchiveStatusText.text : "";
        bool caseArchiveDecisionPracticeCreatesObjective =
            caseArchiveDecisionPracticeApplied &&
            hasPendingNextCampaignObjective &&
            pendingCaseReplayObjectiveReady &&
            pendingNextCampaignObjective.challenge.Contains("판단 비교 연습") &&
            pendingNextCampaignObjective.reason.Contains("판단 비교표") &&
            pendingNextCampaignObjective.reason.Contains("후폭풍") &&
            decisionPracticeStatus.Contains("비교 연습 적용");

        NextCaseArchivePage();
        yield return null;
        string nextList = caseArchiveListText != null ? caseArchiveListText.text : "";
        bool nextPageChanged = cases.Count > CaseArchivePageSize && nextList.Contains(cases[CaseArchivePageSize].id);

        PreviousCaseArchivePage();
        yield return null;
        bool previousPageRestored = caseArchiveListText != null && cases.Count > 0 && caseArchiveListText.text.Contains(cases[0].id);

        CycleCaseArchiveFilter();
        yield return null;
        List<CareCase> filteredCases = BuildCaseArchiveFilteredCases();
        string filteredStatus = caseArchiveStatusText != null ? caseArchiveStatusText.text : "";
        string filteredList = caseArchiveListText != null ? caseArchiveListText.text : "";
        string filteredDetail = caseArchiveDetailText != null ? caseArchiveDetailText.text : "";
