        bool filterPageReset = caseArchivePage == 0 && filteredStatus.Contains($"중 {filteredCases.Count}개 표시");
        bool filteredListMentionsQueue = filteredCases.Count > 0 && filteredList.Contains(filteredCases[0].id);
        bool filteredDetailMentionsQueue = filteredCases.Count > 0 && filteredDetail.Contains(filteredCases[0].id) && filteredDetail.Contains("권장 판단");

        bool appealRemedyGraphTriageRecommendationAvailable =
