    private IEnumerator RunDailyProgressSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        firstRunNoticeRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);
        yield return null;

        string initialRegulation = regulationText != null ? regulationText.text : "";
        bool initialProgressVisible =
            initialRegulation.Contains("오늘 진행 0/8") &&
            initialRegulation.Contains("남은 고위험") &&
            initialRegulation.Contains("조사 메모 0");

        Decide(DecisionKindFromLabel(cases[0].recommendedDecision));
        yield return null;

        string afterDecisionRegulation = regulationText != null ? regulationText.text : "";
        bool afterDecisionProgressUpdated =
            afterDecisionRegulation.Contains("오늘 진행 1/8") &&
            afterDecisionRegulation.Contains("남은 7");

        if (awaitingNext)
        {
            AdvanceToNextCase();
            yield return null;
        }

        string nextCaseRegulation = regulationText != null ? regulationText.text : "";
        bool nextCaseProgressPersists =
            currentIndex == 1 &&
            nextCaseRegulation.Contains("오늘 진행 1/8") &&
            nextCaseRegulation.Contains("남은 7");

        yield return PlayRecommendedUntilDayTransition();
        bool transitionActive = dayTransitionRoot != null && dayTransitionRoot.gameObject.activeSelf;
        ContinueAfterDayTransition();
        yield return null;

        string nextDayRegulation = regulationText != null ? regulationText.text : "";
        bool nextDayProgressReset =
            currentIndex == 8 &&
            nextDayRegulation.Contains("오늘 진행 0/8") &&
            nextDayRegulation.Contains("조사 메모 0");

        bool completed =
            initialProgressVisible &&
            afterDecisionProgressUpdated &&
            nextCaseProgressPersists &&
            transitionActive &&
            nextDayProgressReset;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_daily_progress_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"initialProgressVisible\": {(initialProgressVisible ? "true" : "false")},\n" +
            $"  \"afterDecisionProgressUpdated\": {(afterDecisionProgressUpdated ? "true" : "false")},\n" +
            $"  \"nextCaseProgressPersists\": {(nextCaseProgressPersists ? "true" : "false")},\n" +
            $"  \"transitionActive\": {(transitionActive ? "true" : "false")},\n" +
            $"  \"nextDayProgressReset\": {(nextDayProgressReset ? "true" : "false")},\n" +
            $"  \"currentIndex\": {currentIndex},\n" +
            $"  \"initialRegulation\": \"{EscapeJson(initialRegulation)}\",\n" +
            $"  \"afterDecisionRegulation\": \"{EscapeJson(afterDecisionRegulation)}\",\n" +
            $"  \"nextCaseRegulation\": \"{EscapeJson(nextCaseRegulation)}\",\n" +
            $"  \"nextDayRegulation\": \"{EscapeJson(nextDayRegulation)}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_DAILY_PROGRESS_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        Application.Quit();
    }

    private IEnumerator RunUiCleanupSmokeTest()
    {
        yield return null;

        ShowTutorial(true);
        yield return null;
        bool briefingHasFourStepCounter = tutorialBodyText != null && tutorialBodyText.text.Contains("(1 / 4)");
        TutorialNext();
        yield return null;

        string tutorialBody = tutorialBodyText != null ? tutorialBodyText.text : "";
        string tutorialChecklist = tutorialChecklistText != null ? tutorialChecklistText.text : "";
        bool tutorialMentionsScreenOrder =
            tutorialBody.Contains("중앙 신청서") &&
            tutorialChecklist.Contains("중앙 신청서") &&
            tutorialChecklist.Contains("오른쪽 지표") &&
            tutorialChecklist.Contains("미리보기");
        bool tutorialButtonsHumanReadable =
            tutorialBackButtonText != null &&
            tutorialNextButtonText != null &&
            !tutorialBackButtonText.text.Contains("Tutorial") &&
            !tutorialNextButtonText.text.Contains("Tutorial");

        ResetCampaignState();
        ResetFirstCaseGuide();
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        tutorialRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);
        yield return null;

        bool firstGuideActive = firstCaseGuideRoot != null && firstCaseGuideRoot.gameObject.activeSelf;
        Image blocker = firstCaseGuideRoot != null
            ? firstCaseGuideRoot.Find("First Case Guide Input Blocker")?.GetComponent<Image>()
            : null;
        bool guideBlocksUnderlyingInput = blocker != null && blocker.raycastTarget;
        bool firstGuideHasFiveSteps = FirstCaseGuideTitles.Length == 5 && FirstCaseGuideBodies.Length == 5;
        bool firstGuideMentionsPreview = false;
        for (int i = 0; i < FirstCaseGuideBodies.Length; i++)
        {
            firstCaseGuideStepIndex = i;
            UpdateFirstCaseGuideContent();
            if ((firstCaseGuideTitleText != null && firstCaseGuideTitleText.text.Contains("미리보기")) ||
                (firstCaseGuideBodyText != null && firstCaseGuideBodyText.text.Contains("미리보기") && firstCaseGuideBodyText.text.Contains("[권장]")))
            {
                firstGuideMentionsPreview = true;
            }
        }
        bool firstGuideButtonsHumanReadable =
            firstCaseGuideRoot != null &&
            !AnyButtonLabelContains(firstCaseGuideRoot, "First Case") &&
            !AnyButtonLabelContains(firstCaseGuideRoot, "Guide");
        int firstGuideSpotlightMaskCount = CountNamedChildren(firstCaseGuideRoot, "First Case Guide Spotlight Mask");
        bool firstGuideUsesSpotlightMask = firstGuideSpotlightMaskCount == 4;

        int primaryRecommendationCount = 0;
        int alternativeRecommendationCount = 0;
        bool everyPreviewMentionsBudgetRisk = decisionPreviewTexts != null && decisionPreviewTexts.Length > 0;
        if (decisionPreviewTexts != null)
        {
            foreach (Text previewText in decisionPreviewTexts)
            {
                string text = previewText != null ? previewText.text : "";
                if (text.Contains("권장"))
                {
                    primaryRecommendationCount++;
                }
                if (text.Contains("대체"))
                {
                    alternativeRecommendationCount++;
                }
                everyPreviewMentionsBudgetRisk &= text.Contains("예산") && text.Contains("위험");
            }
        }

        bool exactlyOnePrimaryRecommendation = primaryRecommendationCount == 1;
        int menuPrimaryCount = CountButtonsForRole(menuRoot, TextButtonRole.Primary);
        int reportPrimaryCount = CountDirectButtonsForRole(reportRoot, TextButtonRole.Primary);
        int utilityAccentCount =
            CountButtonsWithRoleAndAccent(menuRoot, TextButtonRole.Utility) +
            CountButtonsWithRoleAndAccent(reviewRoot, TextButtonRole.Utility) +
            CountButtonsWithRoleAndAccent(reportRoot, TextButtonRole.Utility);
        int primaryAccentCount =
            CountButtonsWithRoleAndAccent(menuRoot, TextButtonRole.Primary) +
            CountButtonsWithRoleAndAccent(reviewRoot, TextButtonRole.Primary) +
            CountButtonsWithRoleAndAccent(reportRoot, TextButtonRole.Primary);
        int generatedButtonChromeCount =
            CountButtonsWithGeneratedUi(menuRoot) +
            CountButtonsWithGeneratedUi(reviewRoot) +
            CountButtonsWithGeneratedUi(reportRoot);
        int generatedPanelChromeCount =
            CountGeneratedPanelChrome(menuRoot) +
            CountGeneratedPanelChrome(reviewRoot) +
            CountGeneratedPanelChrome(reportRoot);
        int generatedTextBoxChromeCount =
            CountGeneratedTextBoxChrome(menuRoot) +
            CountGeneratedTextBoxChrome(reviewRoot) +
            CountGeneratedTextBoxChrome(reportRoot);
        bool buttonRoleHierarchyApplied =
            menuPrimaryCount >= 1 &&
            reportPrimaryCount == 1 &&
            primaryAccentCount >= 2 &&
            utilityAccentCount == 0;
        bool generatedUiChromeApplied =
            generatedButtonChromeCount >= 24 &&
            generatedPanelChromeCount >= 5 &&
            generatedTextBoxChromeCount >= 18;
        List<Text> denseReportTexts = new()
        {
            reportCaseLogText,
            reportFollowUpText,
            reportLogPathText,
            agentDashboardPathText,
            agentDashboardDisagreementText,
            decisionAuditQueueText
        };
        if (playerFamilyRowTexts != null)
        {
            denseReportTexts.AddRange(playerFamilyRowTexts);
        }
        if (agentRowTexts != null)
        {
            denseReportTexts.AddRange(agentRowTexts);
        }
        if (decisionAuditRowTexts != null)
        {
            denseReportTexts.AddRange(decisionAuditRowTexts);
        }
        int reportDenseTextMinimumFontSize = MinimumFontSize(denseReportTexts);
        bool reportDenseTextReadable = reportDenseTextMinimumFontSize >= 14;
        string activeFontName = koreanFont != null ? koreanFont.name : "";
        bool paperlogyFontApplied = activeFontName.IndexOf("Paperlogy", StringComparison.OrdinalIgnoreCase) >= 0;
        List<RectTransform> fontAuditRoots = new()
        {
            menuRoot,
            reviewRoot,
            dayTransitionRoot,
            reportRoot,
            reportDashboardRoot,
            agentDashboardRoot,
            decisionAuditRoot,
            decisionHistoryRoot,
            followUpInboxRoot,
            policyHandbookRoot,
            settingsRoot,
            endingGalleryRoot,
            achievementRoot,
            careerRecordRoot,
            achievementToastRoot,
            creditsRoot,
            caseArchiveRoot,
#if CARE_REVIEW_QA_TOOLS
            playtestSurveyRoot,
#endif
            tutorialRoot,
            firstCaseGuideRoot,
            firstRunNoticeRoot
        };
        int paperlogyTextComponentCount = CountTextComponents(fontAuditRoots);
        int paperlogyTextMismatchCount = CountTextComponentsWithoutFontName(fontAuditRoots, "Paperlogy");
        bool paperlogyTextFontCoverageApplied = paperlogyTextComponentCount >= 120 && paperlogyTextMismatchCount == 0;

        bool completed =
            briefingHasFourStepCounter &&
            tutorialMentionsScreenOrder &&
            tutorialButtonsHumanReadable &&
            firstGuideActive &&
            guideBlocksUnderlyingInput &&
            firstGuideHasFiveSteps &&
            firstGuideMentionsPreview &&
            firstGuideButtonsHumanReadable &&
            firstGuideUsesSpotlightMask &&
            everyPreviewMentionsBudgetRisk &&
            exactlyOnePrimaryRecommendation &&
            buttonRoleHierarchyApplied &&
            generatedUiChromeApplied &&
            reportDenseTextReadable &&
            paperlogyFontApplied &&
            paperlogyTextFontCoverageApplied;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_ui_cleanup_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"briefingHasFourStepCounter\": {(briefingHasFourStepCounter ? "true" : "false")},\n" +
            $"  \"tutorialMentionsScreenOrder\": {(tutorialMentionsScreenOrder ? "true" : "false")},\n" +
            $"  \"tutorialButtonsHumanReadable\": {(tutorialButtonsHumanReadable ? "true" : "false")},\n" +
            $"  \"firstGuideActive\": {(firstGuideActive ? "true" : "false")},\n" +
            $"  \"guideBlocksUnderlyingInput\": {(guideBlocksUnderlyingInput ? "true" : "false")},\n" +
            $"  \"firstGuideHasFiveSteps\": {(firstGuideHasFiveSteps ? "true" : "false")},\n" +
            $"  \"firstGuideMentionsPreview\": {(firstGuideMentionsPreview ? "true" : "false")},\n" +
            $"  \"firstGuideButtonsHumanReadable\": {(firstGuideButtonsHumanReadable ? "true" : "false")},\n" +
            $"  \"firstGuideUsesSpotlightMask\": {(firstGuideUsesSpotlightMask ? "true" : "false")},\n" +
            $"  \"firstGuideSpotlightMaskCount\": {firstGuideSpotlightMaskCount},\n" +
            $"  \"everyPreviewMentionsBudgetRisk\": {(everyPreviewMentionsBudgetRisk ? "true" : "false")},\n" +
            $"  \"primaryRecommendationCount\": {primaryRecommendationCount},\n" +
            $"  \"alternativeRecommendationCount\": {alternativeRecommendationCount},\n" +
            $"  \"buttonRoleHierarchyApplied\": {(buttonRoleHierarchyApplied ? "true" : "false")},\n" +
            $"  \"generatedUiChromeApplied\": {(generatedUiChromeApplied ? "true" : "false")},\n" +
            $"  \"menuPrimaryCount\": {menuPrimaryCount},\n" +
            $"  \"reportPrimaryCount\": {reportPrimaryCount},\n" +
            $"  \"primaryAccentCount\": {primaryAccentCount},\n" +
            $"  \"utilityAccentCount\": {utilityAccentCount},\n" +
            $"  \"generatedButtonChromeCount\": {generatedButtonChromeCount},\n" +
            $"  \"generatedPanelChromeCount\": {generatedPanelChromeCount},\n" +
            $"  \"generatedTextBoxChromeCount\": {generatedTextBoxChromeCount},\n" +
            $"  \"reportDenseTextReadable\": {(reportDenseTextReadable ? "true" : "false")},\n" +
            $"  \"reportDenseTextMinimumFontSize\": {reportDenseTextMinimumFontSize},\n" +
            $"  \"paperlogyFontApplied\": {(paperlogyFontApplied ? "true" : "false")},\n" +
            $"  \"paperlogyTextFontCoverageApplied\": {(paperlogyTextFontCoverageApplied ? "true" : "false")},\n" +
            $"  \"paperlogyTextComponentCount\": {paperlogyTextComponentCount},\n" +
            $"  \"paperlogyTextMismatchCount\": {paperlogyTextMismatchCount},\n" +
            $"  \"activeFontName\": \"{EscapeJson(activeFontName)}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_UI_CLEANUP_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " primaryRecommendationCount=" + primaryRecommendationCount);
        Application.Quit();
    }

    private static bool AnyButtonLabelContains(RectTransform root, string token)
    {
        if (root == null)
        {
            return false;
        }

        Button[] buttons = root.GetComponentsInChildren<Button>(true);
        foreach (Button button in buttons)
        {
            Text label = button.GetComponentInChildren<Text>(true);
            if (label != null && label.text.Contains(token))
            {
                return true;
            }
        }

        return false;
    }

    private static int CountButtonsForRole(RectTransform root, TextButtonRole role)
    {
        if (root == null)
        {
            return 0;
        }

        int count = 0;
        Button[] buttons = root.GetComponentsInChildren<Button>(true);
        foreach (Button button in buttons)
        {
            if (button.transform.Find("Button Role " + role) != null)
            {
                count++;
            }
        }

        return count;
    }

    private static int CountDirectButtonsForRole(RectTransform root, TextButtonRole role)
    {
        if (root == null)
        {
            return 0;
        }

        int count = 0;
        Button[] buttons = root.GetComponentsInChildren<Button>(true);
        foreach (Button button in buttons)
        {
            if (button.transform.parent == root && button.transform.Find("Button Role " + role) != null)
            {
                count++;
            }
        }

        return count;
    }

    private static int CountButtonsWithRoleAndAccent(RectTransform root, TextButtonRole role)
    {
        if (root == null)
        {
            return 0;
        }

        int count = 0;
        Button[] buttons = root.GetComponentsInChildren<Button>(true);
        foreach (Button button in buttons)
        {
            if (button.transform.Find("Button Role " + role) != null &&
                button.transform.Find("Button Accent") != null)
            {
                count++;
            }
        }

        return count;
    }

    private static int CountButtonsWithGeneratedUi(RectTransform root)
    {
        if (root == null)
        {
            return 0;
        }

        int count = 0;
        Button[] buttons = root.GetComponentsInChildren<Button>(true);
        foreach (Button button in buttons)
        {
            Image image = button.GetComponent<Image>();
            if (image != null &&
                image.sprite != null &&
                button.transform.Find("Button Generated UI") != null)
            {
                count++;
            }
        }

        return count;
    }

    private static int CountGeneratedPanelChrome(RectTransform root)
    {
        if (root == null)
        {
            return 0;
        }

        int count = 0;
        Transform[] transforms = root.GetComponentsInChildren<Transform>(true);
        foreach (Transform child in transforms)
        {
            if (child.name == "Generated UI Chrome")
            {
                count++;
            }
        }

        return count;
    }

    private static int CountGeneratedTextBoxChrome(RectTransform root)
    {
        if (root == null)
        {
            return 0;
        }

        return CountNamedChildren(root, "Generated Text Box Chrome");
    }

    private static int MinimumFontSize(List<Text> texts)
    {
        int minimum = int.MaxValue;
        foreach (Text text in texts)
        {
            if (text != null)
            {
                minimum = Mathf.Min(minimum, text.fontSize);
            }
        }

        return minimum == int.MaxValue ? 0 : minimum;
    }

    private static int CountTextComponents(List<RectTransform> roots)
    {
        int count = 0;
        foreach (RectTransform root in roots)
        {
            if (root != null)
            {
                count += root.GetComponentsInChildren<Text>(true).Length;
            }
        }

        return count;
    }

    private static int CountTextComponentsWithoutFontName(List<RectTransform> roots, string expectedFontToken)
    {
        int count = 0;
        foreach (RectTransform root in roots)
        {
            if (root == null)
            {
                continue;
            }

            Text[] texts = root.GetComponentsInChildren<Text>(true);
            foreach (Text text in texts)
            {
                string fontName = text != null && text.font != null ? text.font.name : "";
                if (fontName.IndexOf(expectedFontToken, StringComparison.OrdinalIgnoreCase) < 0)
                {
                    count++;
                }
            }
        }

        return count;
    }

    private static int CountNamedChildren(RectTransform root, string namePrefix)
    {
        if (root == null)
        {
            return 0;
        }

        int count = 0;
        Transform[] transforms = root.GetComponentsInChildren<Transform>(true);
        foreach (Transform child in transforms)
        {
            if (child.name.StartsWith(namePrefix, StringComparison.Ordinal))
            {
                count++;
            }
        }

        return count;
    }

    private IEnumerator RunEndingGallerySmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        endingGalleryRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        yield return PlayRecommendedUntilReport();

        EndingOutcome ending = BuildEndingOutcome();
        ShowEndingGallery();
        yield return new WaitForEndOfFrame();

        string screenshotPath = Path.Combine(Application.persistentDataPath, "care_review_ending_gallery.png");
        if (File.Exists(screenshotPath))
        {
            File.Delete(screenshotPath);
        }
        ScreenCapture.CaptureScreenshot(screenshotPath);
        Debug.Log("CARE_REVIEW_ENDING_GALLERY_SCREENSHOT path=" + screenshotPath);
        yield return new WaitForSeconds(0.5f);

        EndingOutcome[] endings = BuildEndingCatalog();
        int discoveredCount = CountDiscoveredEndings(endings);
        int mandateDiscoveredCount = CountDiscoveredEndingsForMandate(campaignMandate, endings);
        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_ending_gallery_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"galleryActive\": {(endingGalleryRoot.gameObject.activeSelf ? "true" : "false")},\n" +
            $"  \"discoveredCount\": {discoveredCount},\n" +
            $"  \"mandateDiscoveredCount\": {mandateDiscoveredCount},\n" +
            $"  \"endingCatalogCount\": {endings.Length},\n" +
            $"  \"campaignMandateId\": \"{EscapeJson(CampaignMandateId(campaignMandate))}\",\n" +
            $"  \"campaignMandateName\": \"{EscapeJson(CampaignMandateLabel(campaignMandate))}\",\n" +
            $"  \"recommendedEndingId\": \"{EscapeJson(ending.id)}\",\n" +
            $"  \"recommendedEndingTitle\": \"{EscapeJson(ending.title)}\",\n" +
            $"  \"recommendedEndingDiscovered\": {(IsEndingDiscovered(ending.id) ? "true" : "false")},\n" +
            $"  \"recommendedEndingDiscoveredForCurrentMandate\": {(IsEndingDiscoveredForMandate(campaignMandate, ending.id) ? "true" : "false")},\n" +
            $"  \"statusText\": \"{EscapeJson(endingGalleryStatusText.text)}\",\n" +
            $"  \"screenshot\": \"{screenshotPath.Replace("\\", "/")}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_ENDING_GALLERY_SMOKE_RESULT path=" + resultPath);
        Application.Quit();
    }

    private IEnumerator RunEndingInvestigationFilterSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        CampaignMandate originalMandate = campaignMandate;

        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.Save();

        try
        {
            campaignMandate = CampaignMandate.Standard;
            PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
            PlayerPrefs.Save();

            ResetCampaignState();
            firstCaseGuideDismissed = true;
            menuRoot.gameObject.SetActive(false);
            settingsRoot.gameObject.SetActive(false);
            endingGalleryRoot.gameObject.SetActive(false);
            achievementRoot.gameObject.SetActive(false);
            careerRecordRoot.gameObject.SetActive(false);
            dayTransitionRoot.gameObject.SetActive(false);
            reportRoot.gameObject.SetActive(false);
            reviewRoot.gameObject.SetActive(true);
            ShowCase(0);
            yield return null;

            yield return PlayRecommendedUntilReport();
            yield return null;

            CareerRecordDatabase database = LoadCareerRecordDatabase();
            CareerRecord record = database.records.Count > 0 ? database.records[0] : null;

            endingGalleryFollowUpFilterActive = false;
            ShowEndingGallery();
            yield return null;

            EndingOutcome[] endings = BuildEndingCatalog();
            EndingInvestigationHighlight[] highlights = BuildEndingInvestigationHighlights(endings, database.records);
            int highlightedEndingCount = CountEndingInvestigationHighlights(highlights);
            string statusBeforeFilter = endingGalleryStatusText != null ? endingGalleryStatusText.text : "";
            string cardsBeforeFilter = CombinedText(endingGalleryCardTexts);
            bool statusMentionsFollowUpFilter =
                statusBeforeFilter.Contains("후속 필터") &&
                statusBeforeFilter.Contains("후속 많은 엔딩");
            bool cardMentionsFollowUpBadge =
                cardsBeforeFilter.Contains("조사 후속 배지") &&
                cardsBeforeFilter.Contains("건");

            ToggleEndingGalleryFollowUpFilter();
            yield return null;

            string statusAfterFilter = endingGalleryStatusText != null ? endingGalleryStatusText.text : "";
            string cardsAfterFilter = CombinedText(endingGalleryCardTexts);
            bool filterActive = endingGalleryFollowUpFilterActive;
            bool buttonMentionsWholeView =
                endingGalleryFollowUpFilterButtonText != null &&
                endingGalleryFollowUpFilterButtonText.text.Contains("전체 보기");
            bool filteredStatusMentionsActive =
                statusAfterFilter.Contains("후속 필터: 켜짐") &&
                statusAfterFilter.Contains("후속 많은 엔딩");
            bool filteredCardsKeepBadge = cardsAfterFilter.Contains("조사 후속 배지");
            bool filteredCardsMarkEmptySlots = cardsAfterFilter.Contains("후속 많은 회차 없음");

            bool completed =
                record != null &&
                record.investigationFollowUpCount >= EndingInvestigationHighlightThreshold &&
                highlightedEndingCount >= 1 &&
                statusMentionsFollowUpFilter &&
                cardMentionsFollowUpBadge &&
                filterActive &&
                buttonMentionsWholeView &&
                filteredStatusMentionsActive &&
                filteredCardsKeepBadge &&
                filteredCardsMarkEmptySlots;

            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_ending_investigation_filter_smoke_result.json");
            string resultJson =
                "{\n" +
                $"  \"completed\": {(completed ? "true" : "false")},\n" +
                $"  \"recordInvestigationFollowUpCount\": {(record != null ? record.investigationFollowUpCount : 0)},\n" +
                $"  \"highlightedEndingCount\": {highlightedEndingCount},\n" +
                $"  \"threshold\": {EndingInvestigationHighlightThreshold},\n" +
                $"  \"statusMentionsFollowUpFilter\": {(statusMentionsFollowUpFilter ? "true" : "false")},\n" +
                $"  \"cardMentionsFollowUpBadge\": {(cardMentionsFollowUpBadge ? "true" : "false")},\n" +
                $"  \"filterActive\": {(filterActive ? "true" : "false")},\n" +
                $"  \"buttonMentionsWholeView\": {(buttonMentionsWholeView ? "true" : "false")},\n" +
                $"  \"filteredStatusMentionsActive\": {(filteredStatusMentionsActive ? "true" : "false")},\n" +
                $"  \"filteredCardsKeepBadge\": {(filteredCardsKeepBadge ? "true" : "false")},\n" +
                $"  \"filteredCardsMarkEmptySlots\": {(filteredCardsMarkEmptySlots ? "true" : "false")},\n" +
                $"  \"endingId\": \"{EscapeJson(record != null ? record.endingId : "")}\",\n" +
                $"  \"endingTitle\": \"{EscapeJson(record != null ? record.endingTitle : "")}\",\n" +
                $"  \"statusBeforeFilter\": \"{EscapeJson(statusBeforeFilter)}\",\n" +
                $"  \"statusAfterFilter\": \"{EscapeJson(statusAfterFilter)}\"\n" +
                "}\n";
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            Debug.Log("CARE_REVIEW_ENDING_INVESTIGATION_FILTER_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        }
        finally
        {
            if (hadPreviousRecords)
            {
                PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
            }
            else
            {
                PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
            }

            campaignMandate = originalMandate;
            PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
            endingGalleryFollowUpFilterActive = false;
            PlayerPrefs.Save();
        }

        Application.Quit();
    }

    private IEnumerator RunEndingCareerLinkSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        CampaignMandate originalMandate = campaignMandate;
        bool originalFilterState = endingGalleryFollowUpFilterActive;

        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.Save();

        try
        {
            campaignMandate = CampaignMandate.Standard;
            PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
            PlayerPrefs.Save();

            ResetCampaignState();
            firstCaseGuideDismissed = true;
            menuRoot.gameObject.SetActive(false);
            settingsRoot.gameObject.SetActive(false);
            endingGalleryRoot.gameObject.SetActive(false);
            achievementRoot.gameObject.SetActive(false);
            careerRecordRoot.gameObject.SetActive(false);
            dayTransitionRoot.gameObject.SetActive(false);
            reportRoot.gameObject.SetActive(false);
            reviewRoot.gameObject.SetActive(true);
            ShowCase(0);
            yield return null;

            yield return PlayRecommendedUntilReport();
            yield return null;

            CareerRecordDatabase database = LoadCareerRecordDatabase();
            CareerRecord record = database.records.Count > 0 ? database.records[0] : null;
            CareerRecord linkedRecord = null;
            string linkType = "";
            bool linkedRecordFound = record != null &&
                TryFindLinkedEndingCareerRecord(record.endingId, database.records, false, out linkedRecord, out linkType);

            endingGalleryFollowUpFilterActive = false;
            ShowEndingGallery();
            yield return null;

            EndingOutcome[] endings = BuildEndingCatalog();
            int endingIndex = -1;
            if (record != null)
            {
                for (int i = 0; i < endings.Length; i++)
                {
                    if (string.Equals(endings[i].id, record.endingId, StringComparison.OrdinalIgnoreCase))
                    {
                        endingIndex = i;
                        break;
                    }
                }
            }

            bool buttonActive = endingIndex >= 0 &&
                endingGalleryRecordButtons != null &&
                endingIndex < endingGalleryRecordButtons.Length &&
                endingGalleryRecordButtons[endingIndex] != null &&
                endingGalleryRecordButtons[endingIndex].gameObject.activeSelf;
            string buttonText = endingIndex >= 0 &&
                endingGalleryRecordButtonTexts != null &&
                endingIndex < endingGalleryRecordButtonTexts.Length &&
                endingGalleryRecordButtonTexts[endingIndex] != null
                    ? endingGalleryRecordButtonTexts[endingIndex].text
                    : "";
            string galleryCards = CombinedText(endingGalleryCardTexts);
            bool galleryMentionsLinkableBadge = galleryCards.Contains("조사 후속 배지") || galleryCards.Contains("반복 장식");
            bool buttonMentionsRecord = buttonText.Contains("기록") || buttonText.Contains("장식");

            if (record != null)
            {
                OpenEndingGalleryCareerRecord(record.endingId);
            }
            yield return null;

            string careerBody = careerRecordBodyText != null ? careerRecordBodyText.text : "";
            string careerDetail = careerRecordDetailText != null ? careerRecordDetailText.text : "";
            bool careerRecordActive = careerRecordRoot != null && careerRecordRoot.gameObject.activeSelf;
            bool careerShowsFocusedRecord =
                careerBody.Contains("관련 엔딩 기록 포커스") &&
                careerBody.Contains("선택 회차 세부") &&
                record != null &&
                careerBody.Contains(record.endingTitle) &&
                careerBody.Contains(record.sessionId);
            bool careerDetailShowsRepresentativeCase =
                careerDetail.Contains("선택 회차 상세") &&
                careerDetail.Contains("대표 사례") &&
                record != null &&
                careerDetail.Contains(record.representativeCaseId);
            bool careerDetailShowsInvestigationMemo =
                careerDetail.Contains("조사 메모") &&
                record != null &&
                (string.IsNullOrWhiteSpace(record.investigationMemoCaseId) || careerDetail.Contains(record.investigationMemoCaseId));
            bool careerShowsFollowUpDetail =
                record != null &&
                careerBody.Contains("조사 후속") &&
                careerBody.Contains(record.investigationFollowUpCount + "건");
            bool tableMarksFocusedRecord = careerBody.Contains("▶");

            bool completed =
                record != null &&
                record.investigationFollowUpCount >= EndingInvestigationHighlightThreshold &&
                linkedRecordFound &&
                linkedRecord != null &&
                IsSameCareerRecord(record, linkedRecord) &&
                buttonActive &&
                buttonMentionsRecord &&
                galleryMentionsLinkableBadge &&
                careerRecordActive &&
                careerShowsFocusedRecord &&
                careerDetailShowsRepresentativeCase &&
                careerDetailShowsInvestigationMemo &&
                careerShowsFollowUpDetail &&
                tableMarksFocusedRecord;

            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_ending_career_link_smoke_result.json");
            string resultJson =
                "{\n" +
                $"  \"completed\": {(completed ? "true" : "false")},\n" +
                $"  \"linkedRecordFound\": {(linkedRecordFound ? "true" : "false")},\n" +
                $"  \"buttonActive\": {(buttonActive ? "true" : "false")},\n" +
                $"  \"buttonMentionsRecord\": {(buttonMentionsRecord ? "true" : "false")},\n" +
                $"  \"galleryMentionsLinkableBadge\": {(galleryMentionsLinkableBadge ? "true" : "false")},\n" +
                $"  \"careerRecordActive\": {(careerRecordActive ? "true" : "false")},\n" +
                $"  \"careerShowsFocusedRecord\": {(careerShowsFocusedRecord ? "true" : "false")},\n" +
                $"  \"careerDetailShowsRepresentativeCase\": {(careerDetailShowsRepresentativeCase ? "true" : "false")},\n" +
                $"  \"careerDetailShowsInvestigationMemo\": {(careerDetailShowsInvestigationMemo ? "true" : "false")},\n" +
                $"  \"careerShowsFollowUpDetail\": {(careerShowsFollowUpDetail ? "true" : "false")},\n" +
                $"  \"tableMarksFocusedRecord\": {(tableMarksFocusedRecord ? "true" : "false")},\n" +
                $"  \"recordInvestigationFollowUpCount\": {(record != null ? record.investigationFollowUpCount : 0)},\n" +
                $"  \"endingId\": \"{EscapeJson(record != null ? record.endingId : "")}\",\n" +
                $"  \"endingTitle\": \"{EscapeJson(record != null ? record.endingTitle : "")}\",\n" +
                $"  \"linkType\": \"{EscapeJson(linkType)}\",\n" +
                $"  \"buttonText\": \"{EscapeJson(buttonText)}\"\n" +
                "}\n";
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            Debug.Log("CARE_REVIEW_ENDING_CAREER_LINK_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        }
        finally
        {
            if (hadPreviousRecords)
            {
                PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
            }
            else
            {
                PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
            }

            campaignMandate = originalMandate;
            PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
            endingGalleryFollowUpFilterActive = originalFilterState;
            focusedCareerRecordSessionId = "";
            focusedCareerRecordStartedAt = "";
            focusedCareerRecordSourceLabel = "";
            PlayerPrefs.Save();
        }

        Application.Quit();
    }

