    private IEnumerator RunLongTermProgressionSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        bool hadCaseObjectiveAchievement = IsAchievementUnlocked("case_objective_replay");
        string previousCaseObjectiveAt = AchievementUnlockedAt("case_objective_replay");
        bool hadInvestigationFollowUpAchievement = IsAchievementUnlocked("investigation_follow_up");
        string previousInvestigationFollowUpAt = AchievementUnlockedAt("investigation_follow_up");

        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.DeleteKey(AchievementUnlockedPrefsPrefix + "case_objective_replay");
        PlayerPrefs.DeleteKey(AchievementUnlockedAtPrefsPrefix + "case_objective_replay");
        PlayerPrefs.DeleteKey(AchievementUnlockedPrefsPrefix + "investigation_follow_up");
        PlayerPrefs.DeleteKey(AchievementUnlockedAtPrefsPrefix + "investigation_follow_up");
        PlayerPrefs.Save();

        try
        {
            ResetCampaignState();
            firstCaseGuideDismissed = true;

            RunAgentSimulation();
            yield return null;

            string focusedCaseId = latestAgentDisagreementCaseId;
            ShowCaseArchiveForCase(focusedCaseId);
            yield return null;

            bool applied = ApplyCaseArchiveObjective();
            string appliedChallenge = pendingCaseReplayObjectiveChallenge;
            StartRecommendedCampaign();
            BeginCampaignReview();
            yield return null;

            yield return PlayRecommendedUntilReport();
            yield return null;

            ShowCareerRecords();
            yield return null;
            CareerRecordDatabase database = LoadCareerRecordDatabase();
            CareerRecord record = database.records.Count > 0 ? database.records[0] : null;
            string careerBody = careerRecordBodyText != null ? careerRecordBodyText.text : "";
            bool recordHasCaseObjective =
                record != null &&
                record.startedFromCaseObjective &&
                string.Equals(record.caseObjectiveSourceId, focusedCaseId, StringComparison.OrdinalIgnoreCase) &&
                !string.IsNullOrWhiteSpace(record.caseObjectiveChallenge);
            bool recordHasInvestigationFollowUp = record != null && record.investigationFollowUpCount > 0;
            bool bodyMentionsLongTermRewards =
                careerBody.Contains("사례 목표") &&
                careerBody.Contains("조사 후속");

            ShowAchievements();
            yield return null;
            string achievementStatus = achievementStatusText != null ? achievementStatusText.text : "";
            bool caseObjectiveAchievementUnlocked = IsAchievementUnlocked("case_objective_replay");
            bool investigationFollowUpAchievementUnlocked = IsAchievementUnlocked("investigation_follow_up");
            bool achievementCatalogExpanded = BuildAchievementCatalog().Length == 14 && achievementStatus.Contains("/ 14");

            bool completed =
                applied &&
                !string.IsNullOrWhiteSpace(focusedCaseId) &&
                caseObjectiveAchievementUnlocked &&
                investigationFollowUpAchievementUnlocked &&
                recordHasCaseObjective &&
                recordHasInvestigationFollowUp &&
                bodyMentionsLongTermRewards &&
                achievementCatalogExpanded;

            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_long_term_progression_smoke_result.json");
            string resultJson =
                "{\n" +
                $"  \"completed\": {(completed ? "true" : "false")},\n" +
                $"  \"objectiveApplied\": {(applied ? "true" : "false")},\n" +
                $"  \"focusedCaseId\": \"{EscapeJson(focusedCaseId)}\",\n" +
                $"  \"appliedChallenge\": \"{EscapeJson(appliedChallenge)}\",\n" +
                $"  \"caseObjectiveAchievementUnlocked\": {(caseObjectiveAchievementUnlocked ? "true" : "false")},\n" +
                $"  \"investigationFollowUpAchievementUnlocked\": {(investigationFollowUpAchievementUnlocked ? "true" : "false")},\n" +
                $"  \"recordHasCaseObjective\": {(recordHasCaseObjective ? "true" : "false")},\n" +
                $"  \"recordHasInvestigationFollowUp\": {(recordHasInvestigationFollowUp ? "true" : "false")},\n" +
                $"  \"bodyMentionsLongTermRewards\": {(bodyMentionsLongTermRewards ? "true" : "false")},\n" +
                $"  \"achievementCatalogExpanded\": {(achievementCatalogExpanded ? "true" : "false")},\n" +
                $"  \"achievementCatalogCount\": {BuildAchievementCatalog().Length},\n" +
                $"  \"recordInvestigationFollowUpCount\": {(record != null ? record.investigationFollowUpCount : 0)},\n" +
                $"  \"recordCaseObjectiveSourceId\": \"{EscapeJson(record != null ? record.caseObjectiveSourceId : "")}\",\n" +
                $"  \"achievementStatus\": \"{EscapeJson(achievementStatus)}\"\n" +
                "}\n";
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            Debug.Log("CARE_REVIEW_LONG_TERM_PROGRESSION_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        }
        finally
        {
            if (hadPreviousRecords)
            {
                PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
            }
            else
            {
                PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
            }

            RestoreAchievementPref("case_objective_replay", hadCaseObjectiveAchievement, previousCaseObjectiveAt);
            RestoreAchievementPref("investigation_follow_up", hadInvestigationFollowUpAchievement, previousInvestigationFollowUpAt);
            PlayerPrefs.Save();
        }

        Application.Quit();
    }

    private IEnumerator RunPersonalizedRecommendationSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        bool hadBudgetAchievement = IsAchievementUnlocked("budget_explained");
        string previousBudgetAchievementAt = AchievementUnlockedAt("budget_explained");
        CampaignMandate originalMandate = campaignMandate;

        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.DeleteKey(AchievementUnlockedPrefsPrefix + "budget_explained");
        PlayerPrefs.DeleteKey(AchievementUnlockedAtPrefsPrefix + "budget_explained");
        PlayerPrefs.Save();

        try
        {
            campaignMandate = CampaignMandate.AusterityAudit;
            PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
            PlayerPrefs.Save();
            ResetCampaignState();
            firstCaseGuideDismissed = true;
            menuRoot.gameObject.SetActive(false);
            settingsRoot.gameObject.SetActive(false);
            dayTransitionRoot.gameObject.SetActive(false);
            reportRoot.gameObject.SetActive(false);
            reviewRoot.gameObject.SetActive(true);
            ShowCase(0);
            yield return null;

            yield return PlayRecommendedUntilReport();
            yield return null;

        string reportNextText = reportLogPathText != null ? reportLogPathText.text : "";
        bool reportMentionsPersonalizedReason =
            reportNextText.Contains("미해금 성과") &&
            reportNextText.Contains("예산 설명 완료");
            bool objectiveTargetsBudgetAchievement =
                hasPendingNextCampaignObjective &&
                pendingNextCampaignObjective.mandate == CampaignMandate.AusterityAudit &&
                pendingNextCampaignObjective.reason.Contains("미해금 성과") &&
                pendingNextCampaignObjective.reason.Contains("예산 설명 완료");

            ShowCareerRecords();
            yield return null;
            string careerBody = careerRecordBodyText != null ? careerRecordBodyText.text : "";
            bool careerMentionsPersonalizedRecommendation =
                careerBody.Contains("개인화 추천") &&
                careerBody.Contains("예산 설명 완료");

            ShowMainMenu();
            yield return null;
            string menuStatus = menuStatusText != null ? menuStatusText.text : "";
            bool menuMentionsLongTermRecommendation =
                menuStatus.Contains("장기 추천") &&
                menuStatus.Contains("예산 설명 완료");

            CareerRecordDatabase database = LoadCareerRecordDatabase();
            CareerRecord record = database.records.Count > 0 ? database.records[0] : null;
            bool recordHasPersonalizedReason =
                record != null &&
                !string.IsNullOrWhiteSpace(record.nextCampaignReason) &&
                record.nextCampaignReason.Contains("미해금 성과") &&
                record.nextCampaignReason.Contains("예산 설명 완료");

            bool completed =
                objectiveTargetsBudgetAchievement &&
                reportMentionsPersonalizedReason &&
                careerMentionsPersonalizedRecommendation &&
                menuMentionsLongTermRecommendation &&
                recordHasPersonalizedReason;

            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_personalized_recommendation_smoke_result.json");
            string resultJson =
                "{\n" +
                $"  \"completed\": {(completed ? "true" : "false")},\n" +
                $"  \"objectiveTargetsBudgetAchievement\": {(objectiveTargetsBudgetAchievement ? "true" : "false")},\n" +
                $"  \"reportMentionsPersonalizedReason\": {(reportMentionsPersonalizedReason ? "true" : "false")},\n" +
                $"  \"careerMentionsPersonalizedRecommendation\": {(careerMentionsPersonalizedRecommendation ? "true" : "false")},\n" +
                $"  \"menuMentionsLongTermRecommendation\": {(menuMentionsLongTermRecommendation ? "true" : "false")},\n" +
                $"  \"recordHasPersonalizedReason\": {(recordHasPersonalizedReason ? "true" : "false")},\n" +
                $"  \"nextCampaignMandate\": \"{EscapeJson(hasPendingNextCampaignObjective ? CampaignMandateLabel(pendingNextCampaignObjective.mandate) : "")}\",\n" +
                $"  \"nextCampaignChallenge\": \"{EscapeJson(hasPendingNextCampaignObjective ? pendingNextCampaignObjective.challenge : "")}\",\n" +
                $"  \"nextCampaignReason\": \"{EscapeJson(hasPendingNextCampaignObjective ? pendingNextCampaignObjective.reason : "")}\",\n" +
                $"  \"menuStatus\": \"{EscapeJson(menuStatus)}\"\n" +
                "}\n";
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            Debug.Log("CARE_REVIEW_PERSONALIZED_RECOMMENDATION_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        }
        finally
        {
            if (hadPreviousRecords)
            {
                PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
            }
            else
            {
                PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
            }

            RestoreAchievementPref("budget_explained", hadBudgetAchievement, previousBudgetAchievementAt);
            campaignMandate = originalMandate;
            PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
            PlayerPrefs.Save();
        }

        Application.Quit();
    }

