    private IEnumerator RunAdvancedReplayTierSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.Save();

        try
        {
            string lastFocusedCaseId = "";
            bool allApplied = true;
            for (int run = 0; run < 6; run++)
            {
                ResetCampaignState();
                firstCaseGuideDismissed = true;
                RunAgentSimulation();
                yield return null;

                lastFocusedCaseId = latestAgentDisagreementCaseId;
                ShowCaseArchiveForCase(lastFocusedCaseId);
                yield return null;

                bool applied = ApplyCaseArchiveObjective();
                allApplied &= applied;
                StartRecommendedCampaign();
                BeginCampaignReview();
                yield return null;

                yield return PlayRecommendedUntilReport();
                yield return null;
            }

            string reportNextText = reportLogPathText != null ? reportLogPathText.text : "";
            bool reportMentionsTier =
                reportNextText.Contains("상위 챌린지") &&
                reportNextText.Contains("반복 목표 설계자") &&
                reportNextText.Contains("최고 단계");

            ShowCareerRecords();
            yield return null;
            CareerRecordDatabase database = LoadCareerRecordDatabase();
            CareerRecord record = database.records.Count > 0 ? database.records[0] : null;
            string careerBody = careerRecordBodyText != null ? careerRecordBodyText.text : "";
            bool recordHasTier =
                record != null &&
                record.replayObjectiveCompletionCount >= 6 &&
                record.advancedReplayChallengeBadge.Contains("반복 목표 설계자") &&
                record.advancedReplayChallengeProgress.Contains("최고 단계") &&
                record.advancedReplayChallengeTier.Contains("상위 단계 3") &&
                record.advancedReplayChallengeDecoration.Contains("금색");
            bool careerMentionsTier =
                careerBody.Contains("챌린지 카드") &&
                careerBody.Contains("상위 단계 3") &&
                careerBody.Contains("금색 엔딩 장식");

            ShowEndingGallery();
            yield return null;
            string endingGalleryStatus = endingGalleryStatusText != null ? endingGalleryStatusText.text : "";
            string endingGalleryCards = CombinedText(endingGalleryCardTexts);
            bool endingGalleryMentionsDecoration =
                endingGalleryStatus.Contains("상위 장식") &&
                endingGalleryCards.Contains("반복 장식") &&
                endingGalleryCards.Contains("금색 엔딩 장식");
            int decoratedEndingIndex = -1;
            EndingOutcome[] endings = BuildEndingCatalog();
            if (record != null)
            {
                for (int i = 0; i < endings.Length; i++)
                {
                    if (string.Equals(endings[i].id, record.endingId, StringComparison.OrdinalIgnoreCase))
                    {
                        decoratedEndingIndex = i;
                        break;
                    }
                }
            }
            bool endingGalleryDecorationLinkAvailable =
                decoratedEndingIndex >= 0 &&
                endingGalleryRecordButtons != null &&
                decoratedEndingIndex < endingGalleryRecordButtons.Length &&
                endingGalleryRecordButtons[decoratedEndingIndex] != null &&
                endingGalleryRecordButtons[decoratedEndingIndex].gameObject.activeSelf &&
                endingGalleryRecordButtonTexts != null &&
                decoratedEndingIndex < endingGalleryRecordButtonTexts.Length &&
                endingGalleryRecordButtonTexts[decoratedEndingIndex] != null &&
                endingGalleryRecordButtonTexts[decoratedEndingIndex].text.Contains("장식");

            ShowAchievements();
            yield return null;
            string achievementCards = CombinedText(achievementCardTexts);
            bool achievementCardMentionsAdvancedReplayDecoration =
                achievementCards.Contains("사례 재심사 목표") &&
                achievementCards.Contains("상위 단계 3") &&
                achievementCards.Contains("금색 엔딩 장식");
            bool achievementReplayRecordButtonActive =
                achievementReplayRecordButton != null &&
                achievementReplayRecordButton.interactable &&
                achievementReplayRecordButtonText != null &&
                achievementReplayRecordButtonText.text.Contains("반복 6회");
            string achievementReplayRewardPanel = achievementReplayRewardText != null ? achievementReplayRewardText.text : "";
            bool achievementReplayRewardPanelMentionsGoldHistory =
                achievementReplayRewardPanel.Contains("반복 보상 이력") &&
                achievementReplayRewardPanel.Contains("현재 6회") &&
                achievementReplayRewardPanel.Contains("2회 동색") &&
                achievementReplayRewardPanel.Contains("4회 은색") &&
                achievementReplayRewardPanel.Contains("6회 금색") &&
                achievementReplayRewardPanel.Contains("최고 단계");
            bool achievementReplayTierRecordButtonsActive =
                achievementReplayTierRecordButtons != null &&
                achievementReplayTierRecordButtons.Length >= 3 &&
                achievementReplayTierRecordButtons[0] != null &&
                achievementReplayTierRecordButtons[1] != null &&
                achievementReplayTierRecordButtons[2] != null &&
                achievementReplayTierRecordButtons[0].interactable &&
                achievementReplayTierRecordButtons[1].interactable &&
                achievementReplayTierRecordButtons[2].interactable;
            bool achievementCatalogMentionsAdvancedReplayTiers = false;
            AchievementDefinition[] achievements = BuildAchievementCatalog();
            for (int i = 0; i < achievements.Length; i++)
            {
                if (achievements[i].id == "case_objective_replay")
                {
                    achievementCatalogMentionsAdvancedReplayTiers =
                        achievements[i].description.Contains("2/4/6회") &&
                        achievements[i].description.Contains("금색 엔딩 장식");
                    break;
                }
            }
            OpenAchievementReplayTierRecord(6);
            yield return null;
            string tierFocusedCareerBody = careerRecordBodyText != null ? careerRecordBodyText.text : "";
            bool achievementReplayTierRecordButtonOpensCareer =
                careerRecordRoot != null &&
                careerRecordRoot.gameObject.activeSelf &&
                tierFocusedCareerBody.Contains("성과 반복 보상 6회") &&
                tierFocusedCareerBody.Contains("금색 엔딩 장식") &&
                tierFocusedCareerBody.Contains("▶");
            OpenAchievementReplayRecord();
            yield return null;
            string focusedCareerBody = careerRecordBodyText != null ? careerRecordBodyText.text : "";
            bool achievementReplayRecordOpensCareer =
                careerRecordRoot != null &&
                careerRecordRoot.gameObject.activeSelf &&
                focusedCareerBody.Contains("성과 반복 기록") &&
                focusedCareerBody.Contains("▶") &&
                focusedCareerBody.Contains("상위 단계 3") &&
                focusedCareerBody.Contains("금색 엔딩 장식");

            bool completed =
                allApplied &&
                database.records.Count >= 6 &&
                recordHasTier &&
                reportMentionsTier &&
                careerMentionsTier &&
                endingGalleryMentionsDecoration &&
                endingGalleryDecorationLinkAvailable &&
                achievementCardMentionsAdvancedReplayDecoration &&
                achievementCatalogMentionsAdvancedReplayTiers &&
                achievementReplayRecordButtonActive &&
                achievementReplayRewardPanelMentionsGoldHistory &&
                achievementReplayTierRecordButtonsActive &&
                achievementReplayTierRecordButtonOpensCareer &&
                achievementReplayRecordOpensCareer;

            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_advanced_replay_tier_smoke_result.json");
            string resultJson =
                "{\n" +
                $"  \"completed\": {(completed ? "true" : "false")},\n" +
                $"  \"allObjectivesApplied\": {(allApplied ? "true" : "false")},\n" +
                $"  \"recordCount\": {database.records.Count},\n" +
                $"  \"recordHasTier\": {(recordHasTier ? "true" : "false")},\n" +
                $"  \"reportMentionsTier\": {(reportMentionsTier ? "true" : "false")},\n" +
                $"  \"careerMentionsTier\": {(careerMentionsTier ? "true" : "false")},\n" +
                $"  \"endingGalleryMentionsDecoration\": {(endingGalleryMentionsDecoration ? "true" : "false")},\n" +
                $"  \"endingGalleryDecorationLinkAvailable\": {(endingGalleryDecorationLinkAvailable ? "true" : "false")},\n" +
                $"  \"achievementCardMentionsAdvancedReplayDecoration\": {(achievementCardMentionsAdvancedReplayDecoration ? "true" : "false")},\n" +
                $"  \"achievementCatalogMentionsAdvancedReplayTiers\": {(achievementCatalogMentionsAdvancedReplayTiers ? "true" : "false")},\n" +
                $"  \"achievementReplayRecordButtonActive\": {(achievementReplayRecordButtonActive ? "true" : "false")},\n" +
                $"  \"achievementReplayRewardPanelMentionsGoldHistory\": {(achievementReplayRewardPanelMentionsGoldHistory ? "true" : "false")},\n" +
                $"  \"achievementReplayRewardPanel\": \"{EscapeJson(achievementReplayRewardPanel)}\",\n" +
                $"  \"achievementReplayTierRecordButtonsActive\": {(achievementReplayTierRecordButtonsActive ? "true" : "false")},\n" +
                $"  \"achievementReplayTierRecordButtonOpensCareer\": {(achievementReplayTierRecordButtonOpensCareer ? "true" : "false")},\n" +
                $"  \"achievementReplayRecordOpensCareer\": {(achievementReplayRecordOpensCareer ? "true" : "false")},\n" +
                $"  \"replayObjectiveCompletionCount\": {(record != null ? record.replayObjectiveCompletionCount : 0)},\n" +
                $"  \"advancedReplayChallengeBadge\": \"{EscapeJson(record != null ? record.advancedReplayChallengeBadge : "")}\",\n" +
                $"  \"advancedReplayChallengeTier\": \"{EscapeJson(record != null ? record.advancedReplayChallengeTier : "")}\",\n" +
                $"  \"advancedReplayChallengeDecoration\": \"{EscapeJson(record != null ? record.advancedReplayChallengeDecoration : "")}\",\n" +
                $"  \"lastFocusedCaseId\": \"{EscapeJson(lastFocusedCaseId)}\",\n" +
                $"  \"endingGalleryStatus\": \"{EscapeJson(endingGalleryStatus)}\"\n" +
                "}\n";
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            Debug.Log("CARE_REVIEW_ADVANCED_REPLAY_TIER_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        }
        finally
        {
            if (hadPreviousRecords)
            {
                PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
            }
            else
            {
                PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
            }

            PlayerPrefs.Save();
        }

        Application.Quit();
    }

