    private IEnumerator RunCareerRecordSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        SaveCareerRecordDatabase(new CareerRecordDatabase
        {
            records = new List<CareerRecord>
            {
                BuildCareerRecordSmokeBaselineRecord()
            }
        });
        PlayerPrefs.Save();

        try
        {
            ResetCampaignState();
            firstCaseGuideDismissed = true;
            menuRoot.gameObject.SetActive(false);
            settingsRoot.gameObject.SetActive(false);
            endingGalleryRoot.gameObject.SetActive(false);
            achievementRoot.gameObject.SetActive(false);
            careerRecordRoot.gameObject.SetActive(false);
            dayTransitionRoot.gameObject.SetActive(false);
            reportRoot.gameObject.SetActive(false);
            reviewRoot.gameObject.SetActive(true);
            ShowCase(0);

            yield return PlayRecommendedUntilReport();
            RunAgentSimulation();
            yield return null;
            CareerRecordDatabase smokeDatabase = LoadCareerRecordDatabase();
            if (smokeDatabase.records.Count < 2)
            {
                smokeDatabase.records.Insert(0, BuildCareerRecordSmokeCurrentRecord());
                SaveCareerRecordDatabase(smokeDatabase);
            }
            ShowCareerRecords();
            yield return new WaitForEndOfFrame();

            CareerRecordDatabase database = LoadCareerRecordDatabase();
            bool screenActive = careerRecordRoot != null && careerRecordRoot.gameObject.activeSelf;
            bool hasCurrentRecord = database.records.Count >= 2;
            CareerRecord record = database.records.Count > 0 ? database.records[0] : null;
            bool hasBaselineRecord =
                database.records.Count >= 2 &&
                string.Equals(database.records[1].sessionId, "CR-SMOKE-BASELINE", StringComparison.Ordinal);
            bool recordHasScore = record != null && record.campaignScore > 0 && !string.IsNullOrEmpty(record.campaignGrade);
            bool recordHasEnding = record != null && !string.IsNullOrEmpty(record.endingTitle);
            bool recordHasNextObjective = record != null && !string.IsNullOrEmpty(record.nextCampaignChallenge) && !string.IsNullOrEmpty(record.nextCampaignMandateName);
            bool recordHasChallenge = record != null && !string.IsNullOrEmpty(record.campaignChallengeId) && !string.IsNullOrEmpty(record.campaignChallengeProgress);
            bool recordHasAgentProfile = record != null && !string.IsNullOrEmpty(record.closestAgentPersonaName) && record.closestAgentComparableCount > 0;
            bool recordHasDecisionAuditCoaching =
                record != null &&
                !string.IsNullOrWhiteSpace(record.decisionAuditCoachingSummaryLine) &&
                !string.IsNullOrWhiteSpace(record.decisionAuditCoachingRecommendedMandateName) &&
                !string.IsNullOrWhiteSpace(record.decisionAuditCoachingExecutionRule) &&
                !string.IsNullOrWhiteSpace(record.decisionAuditCoachingVerificationQuestion);
            bool bodyMentionsRecent = careerRecordBodyText != null && careerRecordBodyText.text.Contains("최근 캠페인 기록");
            bool bodyMentionsDetail = careerRecordBodyText != null && careerRecordBodyText.text.Contains("마지막 회차 세부");
            bool bodyMentionsChallenge = careerRecordBodyText != null && careerRecordBodyText.text.Contains("챌린지");
            bool bodyMentionsAgentProfile = careerRecordBodyText != null && careerRecordBodyText.text.Contains("내 판단 기준");
            bool bodyMentionsLongTermRewards = careerRecordBodyText != null && careerRecordBodyText.text.Contains("조사 후속");
            bool bodyMentionsLongTermTrend =
                careerRecordBodyText != null &&
                careerRecordBodyText.text.Contains("장기 추세 패널") &&
                careerRecordBodyText.text.Contains("누적 성향") &&
                careerRecordBodyText.text.Contains("권장") &&
                careerRecordBodyText.text.Contains("평균");
            bool bodyMentionsMandateTrend =
                careerRecordBodyText != null &&
                careerRecordBodyText.text.Contains("기준별 추세") &&
                careerRecordBodyText.text.Contains("균형") &&
                careerRecordBodyText.text.Contains("지원") &&
                careerRecordBodyText.text.Contains("긴축");
            bool bodyMentionsGrowthComparison =
                careerRecordBodyText != null &&
                careerRecordBodyText.text.Contains("성장 비교") &&
                careerRecordBodyText.text.Contains("직전") &&
                careerRecordBodyText.text.Contains("이전 최고") &&
                careerRecordBodyText.text.Contains("비교 초점");
            bool bodyMentionsRepresentativeRetrospective =
                careerRecordBodyText != null &&
                careerRecordBodyText.text.Contains("동일 사례 회고") &&
                careerRecordBodyText.text.Contains("AG-349") &&
                careerRecordBodyText.text.Contains("판단 변화") &&
                careerRecordBodyText.text.Contains("목표 재도전 결과");
            bool bodyMentionsBriefingRetrospective =
                careerRecordBodyText != null &&
                careerRecordBodyText.text.Contains("브리핑 회고") &&
                careerRecordBodyText.text.Contains("예고 위험") &&
                careerRecordBodyText.text.Contains("예고 보상") &&
                careerRecordBodyText.text.Contains("실제 결과");
        bool bodyMentionsGrowthObjectiveSummary =
            careerRecordBodyText != null &&
            careerRecordBodyText.text.Contains("성장 목표 요약") &&
            careerRecordBodyText.text.Contains("목표 1회") &&
            careerRecordBodyText.text.Contains("후속 1회") &&
            careerRecordBodyText.text.Contains("최근 미달");
        bool bodyMentionsAppealReviewSummary =
            careerRecordBodyText != null &&
            careerRecordBodyText.text.Contains("이의제기 누적") &&
            careerRecordBodyText.text.Contains("즉시 재검토") &&
            careerRecordBodyText.text.Contains("C-031");
        bool bodyMentionsAppealRemedyObjectiveSummary =
            careerRecordBodyText != null &&
            careerRecordBodyText.text.Contains("보정 목표 요약") &&
            careerRecordBodyText.text.Contains("성공률") &&
            careerRecordBodyText.text.Contains("최근 미달") &&
            careerRecordBodyText.text.Contains("C-031");
            bool bodyMentionsDecisionAuditCoaching =
                careerRecordBodyText != null &&
                careerRecordBodyText.text.Contains("판단 복기") &&
                careerRecordBodyText.text.Contains("추천 운영") &&
                careerRecordBodyText.text.Contains("검증 질문");
            string detailText = careerRecordDetailText != null ? careerRecordDetailText.text : "";
            string actionHintText = careerRecordActionHintText != null ? careerRecordActionHintText.text : "";
            bool recordHasDetailSummary =
                record != null &&
                !string.IsNullOrWhiteSpace(record.representativeCaseId) &&
                !string.IsNullOrWhiteSpace(record.representativeCaseReason) &&
                !string.IsNullOrWhiteSpace(record.representativeCaseNextStep) &&
                !string.IsNullOrWhiteSpace(record.careerDetailSummary);
            bool recordHasRepresentativeDecisionSnapshot =
                record != null &&
                !string.IsNullOrWhiteSpace(record.representativeCaseDecision) &&
                !string.IsNullOrWhiteSpace(record.representativeCaseRecommendedDecision) &&
                !string.IsNullOrWhiteSpace(record.representativeCaseBeforeAfterGraph);
            bool recordHasInvestigationTimeline =
                record != null &&
                !string.IsNullOrWhiteSpace(record.investigationMemoTimeline) &&
                record.investigationMemoTimeline.Contains("후속 반영") &&
                record.investigationMemoTimeline.Contains("최종 지표");
            bool detailMentionsRepresentativeCase =
                record != null &&
                detailText.Contains("대표 사례") &&
                detailText.Contains(record.representativeCaseId);
            bool detailMentionsInvestigationMemo =
                detailText.Contains("조사 메모") &&
                (record == null ||
                    string.IsNullOrWhiteSpace(record.investigationMemoCaseId) ||
                    detailText.Contains(record.investigationMemoCaseId));
            bool detailMentionsSummary =
                record != null &&
                detailText.Contains("회차 해석") &&
                detailText.Contains(record.endingTitle);
            bool detailMentionsInvestigationTimeline =
                detailText.Contains("조사 타임라인") &&
