    private IEnumerator RunAgentCareerProfileSmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.Save();

        try
        {
            ResetCampaignState();
            firstCaseGuideDismissed = true;
            menuRoot.gameObject.SetActive(false);
            settingsRoot.gameObject.SetActive(false);
            endingGalleryRoot.gameObject.SetActive(false);
            achievementRoot.gameObject.SetActive(false);
            careerRecordRoot.gameObject.SetActive(false);
            dayTransitionRoot.gameObject.SetActive(false);
            reportRoot.gameObject.SetActive(false);
            reviewRoot.gameObject.SetActive(true);
            ShowCase(0);

            yield return PlayRecommendedUntilReport();
            RunAgentSimulation();
            yield return null;
            ShowCareerRecords();
            yield return new WaitForEndOfFrame();

            CareerRecordDatabase database = LoadCareerRecordDatabase();
            CareerRecord record = database.records.Count > 0 ? database.records[0] : null;
            string careerBody = careerRecordBodyText != null ? careerRecordBodyText.text : "";
            string agentPath = agentDashboardPathText != null ? agentDashboardPathText.text : "";
            bool recordHasAgentProfile = record != null &&
                !string.IsNullOrWhiteSpace(record.closestAgentPersonaName) &&
                record.closestAgentComparableCount == logs.Count &&
                record.closestAgentMatchRatePercent > 0f;
            bool bodyMentionsAgentProfile = careerBody.Contains("내 판단 기준") &&
                record != null &&
                careerBody.Contains(record.closestAgentPersonaName);
            bool dashboardMentionsCareerProfile = agentPath.Contains("가까운 기준");
            bool completed = recordHasAgentProfile &&
                bodyMentionsAgentProfile &&
                dashboardMentionsCareerProfile &&
                careerRecordRoot != null &&
                careerRecordRoot.gameObject.activeSelf;

            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_agent_career_profile_smoke_result.json");
            string resultJson =
                "{\n" +
                $"  \"completed\": {(completed ? "true" : "false")},\n" +
                $"  \"recordHasAgentProfile\": {(recordHasAgentProfile ? "true" : "false")},\n" +
                $"  \"bodyMentionsAgentProfile\": {(bodyMentionsAgentProfile ? "true" : "false")},\n" +
                $"  \"dashboardMentionsCareerProfile\": {(dashboardMentionsCareerProfile ? "true" : "false")},\n" +
                $"  \"careerRecordActive\": {(careerRecordRoot != null && careerRecordRoot.gameObject.activeSelf ? "true" : "false")},\n" +
                $"  \"closestAgentPersonaId\": \"{EscapeJson(record != null ? record.closestAgentPersonaId : "")}\",\n" +
                $"  \"closestAgentPersonaName\": \"{EscapeJson(record != null ? record.closestAgentPersonaName : "")}\",\n" +
                $"  \"closestAgentMatchCount\": {(record != null ? record.closestAgentMatchCount : 0)},\n" +
                $"  \"closestAgentComparableCount\": {(record != null ? record.closestAgentComparableCount : 0)},\n" +
                $"  \"closestAgentMatchRatePercent\": {(record != null ? record.closestAgentMatchRatePercent : 0f):0.0},\n" +
                $"  \"logCount\": {logs.Count}\n" +
                "}\n";
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            Debug.Log("CARE_REVIEW_AGENT_CAREER_PROFILE_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        }
        finally
        {
            if (hadPreviousRecords)
            {
                PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
            }
            else
            {
                PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
            }
            PlayerPrefs.Save();
        }

        Application.Quit();
    }

    private IEnumerator RunAgentReplayObjectiveSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        endingGalleryRoot.gameObject.SetActive(false);
        achievementRoot.gameObject.SetActive(false);
        careerRecordRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        yield return PlayRecommendedUntilReport();
        RunAgentSimulation();
        yield return null;

        bool objectiveReadyBeforeApply = latestAgentReplayObjectiveReady;
        string objectivePersona = latestAgentReplayPersonaName;
        CampaignMandate expectedMandate = latestAgentReplayObjectiveReady ? latestAgentReplayObjective.mandate : campaignMandate;
        string expectedChallenge = latestAgentReplayObjectiveReady ? latestAgentReplayObjective.challenge : "";
        string beforePath = agentDashboardPathText != null ? agentDashboardPathText.text : "";
        bool dashboardMentionsObjective = beforePath.Contains("다음 회차 추천") && beforePath.Contains(CampaignMandateLabel(expectedMandate));

        ApplyLatestAgentReplayObjective();
        yield return null;

        string afterPath = agentDashboardPathText != null ? agentDashboardPathText.text : "";
        string recommendationButtonLabel = recommendedCampaignButtonText != null ? recommendedCampaignButtonText.text : "";
        bool pendingObjectiveApplied = hasPendingNextCampaignObjective &&
            pendingNextCampaignObjective.mandate == expectedMandate &&
            pendingNextCampaignObjective.challenge == expectedChallenge;
        bool buttonMentionsAgentMandate = recommendationButtonLabel.Contains("추천 심사 시작") &&
            recommendationButtonLabel.Contains(CampaignMandateLabel(expectedMandate));
        bool dashboardMentionsApplied = afterPath.Contains("다음 회차 추천 적용") &&
            afterPath.Contains(CampaignMandateLabel(expectedMandate));

        StartRecommendedCampaign();
        yield return null;
        bool startUsesAgentMandate = campaignMandate == expectedMandate &&
            currentIndex == 0 &&
            logs.Count == 0 &&
            reviewRoot.gameObject.activeSelf == false &&
            tutorialRoot.gameObject.activeSelf;

        bool completed = objectiveReadyBeforeApply &&
            dashboardMentionsObjective &&
            pendingObjectiveApplied &&
            buttonMentionsAgentMandate &&
            dashboardMentionsApplied &&
            startUsesAgentMandate;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_agent_replay_objective_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"objectiveReadyBeforeApply\": {(objectiveReadyBeforeApply ? "true" : "false")},\n" +
            $"  \"dashboardMentionsObjective\": {(dashboardMentionsObjective ? "true" : "false")},\n" +
            $"  \"pendingObjectiveApplied\": {(pendingObjectiveApplied ? "true" : "false")},\n" +
            $"  \"buttonMentionsAgentMandate\": {(buttonMentionsAgentMandate ? "true" : "false")},\n" +
            $"  \"dashboardMentionsApplied\": {(dashboardMentionsApplied ? "true" : "false")},\n" +
            $"  \"startUsesAgentMandate\": {(startUsesAgentMandate ? "true" : "false")},\n" +
            $"  \"objectivePersona\": \"{EscapeJson(objectivePersona)}\",\n" +
            $"  \"expectedMandateId\": \"{EscapeJson(CampaignMandateId(expectedMandate))}\",\n" +
            $"  \"expectedMandateName\": \"{EscapeJson(CampaignMandateLabel(expectedMandate))}\",\n" +
            $"  \"expectedChallenge\": \"{EscapeJson(expectedChallenge)}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_AGENT_REPLAY_OBJECTIVE_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        Application.Quit();
    }

    private IEnumerator RunCreditsNoticeSmokeTest()
    {
        yield return null;

        ShowCreditsNotice();
        yield return new WaitForEndOfFrame();

        string screenshotPath = Path.Combine(Application.persistentDataPath, "care_review_credits_notice.png");
        if (File.Exists(screenshotPath))
        {
            File.Delete(screenshotPath);
        }
        ScreenCapture.CaptureScreenshot(screenshotPath);
        Debug.Log("CARE_REVIEW_CREDITS_SCREENSHOT path=" + screenshotPath);
        yield return new WaitForSeconds(0.5f);

        string body = creditsBodyText != null ? creditsBodyText.text : "";
        bool creditsActive = creditsRoot.gameObject.activeSelf;
        bool mentionsSyntheticProfiles = body.Contains("합성 프로필");
        bool mentionsNoPersonalData = body.Contains("실제 개인정보");
        bool mentionsLocalLogs = body.Contains("로컬 저장");
        bool mentionsNoAutomaticUpload = body.Contains("자동 업로드");
        bool omitsSystemDiagnosticData = !body.Contains("환경 진단") && !body.Contains("FPS 샘플");
        bool omitsSupportBundleData = !body.Contains("지원 번들");
        bool mentionsAiUse = body.Contains("생성형 AI");
        bool mentionsNotAdvice = body.Contains("실제 복지 행정");
        string screenshotFile = Path.GetFileName(screenshotPath);
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(screenshotFile);
        bool completed = creditsActive &&
            mentionsSyntheticProfiles &&
            mentionsNoPersonalData &&
            mentionsLocalLogs &&
            mentionsNoAutomaticUpload &&
            omitsSystemDiagnosticData &&
            omitsSupportBundleData &&
            mentionsAiUse &&
            mentionsNotAdvice &&
            filesHaveNoLocalAbsolutePath;
        bool screenshotCaptured = File.Exists(screenshotPath);
        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_credits_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"creditsActive\": {(creditsActive ? "true" : "false")},\n" +
            $"  \"mentionsSyntheticProfiles\": {(mentionsSyntheticProfiles ? "true" : "false")},\n" +
            $"  \"mentionsNoPersonalData\": {(mentionsNoPersonalData ? "true" : "false")},\n" +
            $"  \"mentionsLocalLogs\": {(mentionsLocalLogs ? "true" : "false")},\n" +
            $"  \"mentionsNoAutomaticUpload\": {(mentionsNoAutomaticUpload ? "true" : "false")},\n" +
            $"  \"omitsSystemDiagnosticData\": {(omitsSystemDiagnosticData ? "true" : "false")},\n" +
            $"  \"omitsSupportBundleData\": {(omitsSupportBundleData ? "true" : "false")},\n" +
            $"  \"mentionsAiUse\": {(mentionsAiUse ? "true" : "false")},\n" +
            $"  \"mentionsNotAdvice\": {(mentionsNotAdvice ? "true" : "false")},\n" +
            $"  \"filesHaveNoLocalAbsolutePath\": {(filesHaveNoLocalAbsolutePath ? "true" : "false")},\n" +
            $"  \"bodyLength\": {body.Length},\n" +
            $"  \"screenshotCaptured\": {(screenshotCaptured ? "true" : "false")},\n" +
            $"  \"screenshotFile\": \"{EscapeJson(screenshotFile)}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_CREDITS_SMOKE_RESULT path=" + resultPath);
        Application.Quit();
    }

    private IEnumerator RunFirstRunNoticeSmokeTest()
    {
        yield return null;

        bool hadPreviousAcceptedValue = PlayerPrefs.HasKey(FirstRunNoticeAcceptedPrefsKey);
        int previousAcceptedValue = PlayerPrefs.GetInt(FirstRunNoticeAcceptedPrefsKey, 0);

        try
        {
            PlayerPrefs.DeleteKey(FirstRunNoticeAcceptedPrefsKey);
            PlayerPrefs.Save();

            ShowMainMenu();
            ShowFirstRunNotice();
            yield return new WaitForEndOfFrame();

            string body = firstRunNoticeBodyText != null ? firstRunNoticeBodyText.text : "";
            bool noticeActiveBeforeAccept = firstRunNoticeRoot != null && firstRunNoticeRoot.gameObject.activeSelf;
            Image dim = firstRunNoticeRoot != null
                ? firstRunNoticeRoot.Find("First Run Notice Dim")?.GetComponent<Image>()
                : null;
            bool noticeBlocksUnderlyingInput = dim != null && dim.raycastTarget;
            bool mentionsSyntheticCases = body.Contains("합성 사례");
            bool mentionsNoPersonalData = body.Contains("실제 이름") && body.Contains("식별번호");
            bool mentionsLocalStorage = body.Contains("로컬 저장소");
            bool mentionsNoAutomaticUpload = body.Contains("자동 업로드");
            bool omitsSupportBundle = !body.Contains("지원 번들");
            bool mentionsLocalDataDelete = body.Contains("로컬 데이터 삭제");
            bool mentionsNotAdvice = body.Contains("실제 복지") && body.Contains("대체하지 않습니다");
            bool mentionsFirstWorkStart = body.Contains("첫 근무 시작") && body.Contains("4장 안내");

            AcceptFirstRunNotice();
            yield return null;

            bool preferenceSaved = PlayerPrefs.GetInt(FirstRunNoticeAcceptedPrefsKey, 0) == 1;
            bool noticeHiddenAfterAccept = firstRunNoticeRoot != null && !firstRunNoticeRoot.gameObject.activeSelf;
            bool menuVisibleAfterAccept = menuRoot != null && menuRoot.gameObject.activeSelf;

            string resultBody =
                "{\n" +
                $"  \"completed\": {(noticeActiveBeforeAccept && noticeBlocksUnderlyingInput && preferenceSaved && noticeHiddenAfterAccept && menuVisibleAfterAccept && mentionsSyntheticCases && mentionsNoPersonalData && mentionsLocalStorage && mentionsNoAutomaticUpload && omitsSupportBundle && mentionsLocalDataDelete && mentionsNotAdvice && mentionsFirstWorkStart ? "true" : "false")},\n" +
                $"  \"noticeActiveBeforeAccept\": {(noticeActiveBeforeAccept ? "true" : "false")},\n" +
                $"  \"noticeBlocksUnderlyingInput\": {(noticeBlocksUnderlyingInput ? "true" : "false")},\n" +
                $"  \"preferenceSaved\": {(preferenceSaved ? "true" : "false")},\n" +
                $"  \"noticeHiddenAfterAccept\": {(noticeHiddenAfterAccept ? "true" : "false")},\n" +
                $"  \"menuVisibleAfterAccept\": {(menuVisibleAfterAccept ? "true" : "false")},\n" +
                $"  \"mentionsSyntheticCases\": {(mentionsSyntheticCases ? "true" : "false")},\n" +
                $"  \"mentionsNoPersonalData\": {(mentionsNoPersonalData ? "true" : "false")},\n" +
                $"  \"mentionsLocalStorage\": {(mentionsLocalStorage ? "true" : "false")},\n" +
                $"  \"mentionsNoAutomaticUpload\": {(mentionsNoAutomaticUpload ? "true" : "false")},\n" +
                $"  \"omitsSupportBundle\": {(omitsSupportBundle ? "true" : "false")},\n" +
                $"  \"mentionsLocalDataDelete\": {(mentionsLocalDataDelete ? "true" : "false")},\n" +
                $"  \"mentionsNotAdvice\": {(mentionsNotAdvice ? "true" : "false")},\n" +
                $"  \"mentionsFirstWorkStart\": {(mentionsFirstWorkStart ? "true" : "false")},\n" +
                $"  \"bodyLength\": {body.Length},\n";
            bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(resultBody);
            string resultJson = resultBody +
                $"  \"filesHaveNoLocalAbsolutePath\": {(filesHaveNoLocalAbsolutePath ? "true" : "false")}\n" +
                "}\n";
            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_first_run_notice_smoke_result.json");
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            Debug.Log("CARE_REVIEW_FIRST_RUN_NOTICE_SMOKE_RESULT path=" + resultPath + " completed=" + (noticeActiveBeforeAccept && noticeBlocksUnderlyingInput && preferenceSaved && noticeHiddenAfterAccept && menuVisibleAfterAccept));
        }
        finally
        {
            if (hadPreviousAcceptedValue)
            {
                PlayerPrefs.SetInt(FirstRunNoticeAcceptedPrefsKey, previousAcceptedValue);
            }
            else
            {
                PlayerPrefs.DeleteKey(FirstRunNoticeAcceptedPrefsKey);
            }
            PlayerPrefs.Save();
        }

        Application.Quit();
    }

    private IEnumerator RunFirstStartOnboardingSmokeTest()
    {
        yield return null;

        bool hadPreviousAcceptedValue = PlayerPrefs.HasKey(FirstRunNoticeAcceptedPrefsKey);
        int previousAcceptedValue = PlayerPrefs.GetInt(FirstRunNoticeAcceptedPrefsKey, 0);
        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        string[] savePaths = new string[MaxSaveSlots + 1];
        string[] backupPaths = new string[MaxSaveSlots + 1];
        string[] saveContents = new string[MaxSaveSlots + 1];
        string[] backupContents = new string[MaxSaveSlots + 1];
        bool[] saveExists = new bool[MaxSaveSlots + 1];
        bool[] backupExists = new bool[MaxSaveSlots + 1];

        for (int slot = 1; slot <= MaxSaveSlots; slot++)
        {
            savePaths[slot] = SavePathForSlot(slot);
            backupPaths[slot] = SaveBackupPathForSlot(slot);
            saveExists[slot] = File.Exists(savePaths[slot]);
            backupExists[slot] = File.Exists(backupPaths[slot]);
            saveContents[slot] = saveExists[slot] ? File.ReadAllText(savePaths[slot], Encoding.UTF8) : "";
            backupContents[slot] = backupExists[slot] ? File.ReadAllText(backupPaths[slot], Encoding.UTF8) : "";
        }

        try
        {
            PlayerPrefs.DeleteKey(FirstRunNoticeAcceptedPrefsKey);
            PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
            PlayerPrefs.Save();
            for (int slot = 1; slot <= MaxSaveSlots; slot++)
            {
                if (File.Exists(savePaths[slot]))
                {
                    File.Delete(savePaths[slot]);
                }
                if (File.Exists(backupPaths[slot]))
                {
                    File.Delete(backupPaths[slot]);
                }
            }

            ShowMainMenu();
            ShowFirstRunNotice();
            yield return null;

            string noticeBody = firstRunNoticeBodyText != null ? firstRunNoticeBodyText.text : "";
            bool noticeMentionsFirstWork = noticeBody.Contains("첫 근무 시작") && noticeBody.Contains("4장 안내");

            AcceptFirstRunNotice();
            yield return null;

            string newCampaignLabel = newCampaignButton != null && newCampaignButton.GetComponentInChildren<Text>(true) != null
                ? newCampaignButton.GetComponentInChildren<Text>(true).text
                : "";
            string menuStatus = menuStatusText != null ? menuStatusText.text : "";
            bool freshStartStateReady = IsFreshStartState();
            bool firstWorkButtonReady = newCampaignLabel.Contains("첫 근무 시작");
            bool menuGuidesFirstAction = menuStatus.Contains("처음이면") &&
                menuStatus.Contains("첫 근무 시작") &&
                menuStatus.Contains("4장 안내") &&
                menuStatus.Contains("첫 신청서");
            bool menuShowsTodayOrder = menuStatus.Contains("오늘 순서") &&
                menuStatus.Contains("문서 읽기") &&
                menuStatus.Contains("기준 확인") &&
                menuStatus.Contains("도장 선택");

            StartNewCampaign();
            yield return null;

            int stepCount = TutorialStepCount();
            string firstTitle = tutorialTitleText != null ? tutorialTitleText.text : "";
            string firstBody = tutorialBodyText != null ? tutorialBodyText.text : "";
            string firstChecklist = tutorialChecklistText != null ? tutorialChecklistText.text : "";
            bool tutorialHasFourSteps = stepCount == 4 && firstBody.Contains("(1 / 4)");
            bool firstStepMentionsTodayMission = firstTitle.Contains("오늘 할 일") &&
                firstBody.Contains("오늘 할 일") &&
                firstBody.Contains("오늘 접수") &&
                firstBody.Contains("전체 40건") &&
                firstBody.Contains("시작 예산") &&
                firstBody.Contains("캠페인 챌린지") &&
                firstChecklist.Contains("오늘 접수") &&
                firstChecklist.Contains("전체 40건");

            List<string> tutorialTitles = new();
            tutorialTitles.Add(firstTitle);
            for (int i = 1; i < stepCount; i++)
            {
                TutorialNext();
                yield return null;
                tutorialTitles.Add(tutorialTitleText != null ? tutorialTitleText.text : "");
            }

            bool tutorialSequenceReady =
                tutorialTitles.Count == 4 &&
                tutorialTitles[0].Contains("오늘 할 일") &&
                tutorialTitles[1].Contains("읽는 순서") &&
                tutorialTitles[2].Contains("판단 기준") &&
                tutorialTitles[3].Contains("첫 사례 시작") &&
                tutorialNextButtonText != null &&
                tutorialNextButtonText.text.Contains("심사 시작");

            TutorialNext();
            yield return null;

            bool reviewStarted = reviewRoot != null && reviewRoot.gameObject.activeSelf && currentIndex == 0;
            bool firstGuideActive = firstCaseGuideRoot != null && firstCaseGuideRoot.gameObject.activeSelf;
            bool firstGuideStillFiveSteps = FirstCaseGuideTitles.Length == 5 && FirstCaseGuideBodies.Length == 5;

            bool completed = noticeMentionsFirstWork &&
                freshStartStateReady &&
                firstWorkButtonReady &&
                menuGuidesFirstAction &&
                menuShowsTodayOrder &&
                tutorialHasFourSteps &&
                firstStepMentionsTodayMission &&
                tutorialSequenceReady &&
                reviewStarted &&
                firstGuideActive &&
                firstGuideStillFiveSteps;

            string resultJson =
                "{\n" +
                $"  \"completed\": {(completed ? "true" : "false")},\n" +
                $"  \"noticeMentionsFirstWork\": {(noticeMentionsFirstWork ? "true" : "false")},\n" +
                $"  \"freshStartStateReady\": {(freshStartStateReady ? "true" : "false")},\n" +
                $"  \"firstWorkButtonReady\": {(firstWorkButtonReady ? "true" : "false")},\n" +
                $"  \"menuGuidesFirstAction\": {(menuGuidesFirstAction ? "true" : "false")},\n" +
                $"  \"menuShowsTodayOrder\": {(menuShowsTodayOrder ? "true" : "false")},\n" +
                $"  \"tutorialHasFourSteps\": {(tutorialHasFourSteps ? "true" : "false")},\n" +
                $"  \"firstStepMentionsTodayMission\": {(firstStepMentionsTodayMission ? "true" : "false")},\n" +
                $"  \"tutorialSequenceReady\": {(tutorialSequenceReady ? "true" : "false")},\n" +
                $"  \"reviewStarted\": {(reviewStarted ? "true" : "false")},\n" +
                $"  \"firstGuideActive\": {(firstGuideActive ? "true" : "false")},\n" +
                $"  \"firstGuideStillFiveSteps\": {(firstGuideStillFiveSteps ? "true" : "false")},\n" +
                $"  \"tutorialStepCount\": {stepCount},\n" +
                $"  \"firstStartButtonLabel\": \"{EscapeJson(newCampaignLabel)}\",\n" +
                $"  \"firstTutorialTitle\": \"{EscapeJson(firstTitle)}\"\n" +
                "}\n";
            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_first_start_onboarding_smoke_result.json");
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            TryWriteProjectQaSmokeResult("care_review_first_start_onboarding_smoke_result.json", resultJson);
            Debug.Log("CARE_REVIEW_FIRST_START_ONBOARDING_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        }
        finally
        {
            if (hadPreviousAcceptedValue)
            {
                PlayerPrefs.SetInt(FirstRunNoticeAcceptedPrefsKey, previousAcceptedValue);
            }
            else
            {
                PlayerPrefs.DeleteKey(FirstRunNoticeAcceptedPrefsKey);
            }
            if (hadPreviousRecords)
            {
                PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
            }
            else
            {
                PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
            }
            PlayerPrefs.Save();

            for (int slot = 1; slot <= MaxSaveSlots; slot++)
            {
                if (saveExists[slot])
                {
                    File.WriteAllText(savePaths[slot], saveContents[slot], Encoding.UTF8);
                }
                else if (File.Exists(savePaths[slot]))
                {
                    File.Delete(savePaths[slot]);
                }

                if (backupExists[slot])
                {
                    File.WriteAllText(backupPaths[slot], backupContents[slot], Encoding.UTF8);
                }
                else if (File.Exists(backupPaths[slot]))
                {
                    File.Delete(backupPaths[slot]);
                }
            }
        }

        Application.Quit();
    }

    private IEnumerator RunLowResolutionUiSmokeTest()
    {
        yield return null;

        string screenshotDirectory = Path.Combine(Application.persistentDataPath, "low_resolution_ui_v030");
        Directory.CreateDirectory(screenshotDirectory);
        foreach (string oldScreenshotPath in Directory.GetFiles(screenshotDirectory, "*.png"))
        {
            File.Delete(oldScreenshotPath);
        }

        StringBuilder screensJson = new();
        bool firstEntry = true;
        int screenshotCount = 0;
        lowResolutionInvalidScreenshotCount = 0;
        lowResolutionButtonTextOverflowCount = 0;
        lowResolutionEvidenceLabelOverflowCount = 0;
        lowResolutionOffscreenButtonCount = 0;
        bool mainMenuGuidesFirstActionReadable = true;
        float mainMenuGuidesFirstActionMaxDisplayLineWidth = 0f;
        string mainMenuGuidesFirstActionLineSample = "";
        bool mainMenuAchievementBadgeReadable = true;
        float mainMenuAchievementBadgeMaxDisplayLineWidth = 0f;
        string mainMenuAchievementBadgeLineSample = "";
        bool mainMenuAchievementHintReadable = true;
        float mainMenuAchievementHintMaxDisplayLineWidth = 0f;
        string mainMenuAchievementHintSample = "";
        bool mainMenuBriefingWeaknessFocusReadable = true;
        float mainMenuBriefingWeaknessFocusMaxDisplayLineWidth = 0f;
        string mainMenuBriefingWeaknessFocusSample = "";
        bool careerRecordActionHintReadable = true;
        float careerRecordActionHintMaxDisplayLineWidth = 0f;
        bool achievementRecordLinkHintReadable = true;
        bool achievementRecordLinkHintMentionsMenuEntry = true;
        bool achievementRecordLinkHintMentionsCoachingFirstUse = true;
        float achievementRecordLinkHintMaxDisplayLineWidth = 0f;
        bool lowResolutionReleaseCopyAlignmentReadable = true;
        string lowResolutionReleaseCopyAlignmentSample = "";

        for (int i = 0; i < ResolutionOptions.Length; i++)
        {
            Vector2Int resolution = ResolutionOptions[i];
            yield return PrepareCaptureResolution(resolution.x, resolution.y);

            ResetCampaignState();
            firstCaseGuideDismissed = true;
            ShowMainMenu();
            string menuStatus = menuStatusText != null ? menuStatusText.text : "";
            string menuAchievementHint = menuAchievementHintText != null ? menuAchievementHintText.text : "";
            string menuBriefing = menuCampaignBriefingText != null ? menuCampaignBriefingText.text : "";
            string menuFirstActionLine = FirstLineContaining(menuStatus, "처음이면");
            string menuAchievementBadgeLine = FirstLineContaining(menuStatus, "성과 배지");
            string menuBriefingWeaknessFocusLine = FirstLineContaining(menuBriefing, "보정 초점");
            float menuFirstActionWidth = MaxDisplayLineWidth(menuFirstActionLine);
            float menuAchievementBadgeWidth = MaxDisplayLineWidth(menuAchievementBadgeLine);
            float menuAchievementHintWidth = MaxDisplayLineWidth(menuAchievementHint);
            float menuBriefingWeaknessFocusWidth = MaxDisplayLineWidth(menuBriefingWeaknessFocusLine);
            mainMenuGuidesFirstActionMaxDisplayLineWidth = Mathf.Max(mainMenuGuidesFirstActionMaxDisplayLineWidth, menuFirstActionWidth);
            mainMenuAchievementBadgeMaxDisplayLineWidth = Mathf.Max(mainMenuAchievementBadgeMaxDisplayLineWidth, menuAchievementBadgeWidth);
            mainMenuAchievementHintMaxDisplayLineWidth = Mathf.Max(mainMenuAchievementHintMaxDisplayLineWidth, menuAchievementHintWidth);
            mainMenuBriefingWeaknessFocusMaxDisplayLineWidth = Mathf.Max(mainMenuBriefingWeaknessFocusMaxDisplayLineWidth, menuBriefingWeaknessFocusWidth);
            if (string.IsNullOrWhiteSpace(mainMenuGuidesFirstActionLineSample))
            {
                mainMenuGuidesFirstActionLineSample = menuFirstActionLine;
            }
            if (string.IsNullOrWhiteSpace(mainMenuAchievementBadgeLineSample))
            {
                mainMenuAchievementBadgeLineSample = menuAchievementBadgeLine;
            }
            if (string.IsNullOrWhiteSpace(mainMenuAchievementHintSample))
            {
                mainMenuAchievementHintSample = menuAchievementHint;
            }
            if (string.IsNullOrWhiteSpace(mainMenuBriefingWeaknessFocusSample))
            {
                mainMenuBriefingWeaknessFocusSample = menuBriefingWeaknessFocusLine;
            }
            mainMenuGuidesFirstActionReadable &=
                menuRoot != null &&
                menuRoot.gameObject.activeSelf &&
                menuFirstActionLine.Contains("처음이면") &&
                menuFirstActionLine.Contains("새 캠페인") &&
                menuFirstActionLine.Contains("이어하기") &&
                menuFirstActionLine.Contains("기준") &&
                menuFirstActionWidth <= 54f;
            mainMenuAchievementBadgeReadable &=
                menuRoot != null &&
                menuRoot.gameObject.activeSelf &&
                menuAchievementBadgeLine.Contains("성과 배지") &&
                menuAchievementBadgeLine.Contains("다음 성과") &&
                menuAchievementBadgeLine.Contains("반복") &&
                menuAchievementBadgeLine.Contains("A/성과 보기") &&
                menuAchievementBadgeWidth <= 76f;
            mainMenuAchievementHintReadable &=
                menuRoot != null &&
                menuRoot.gameObject.activeSelf &&
                menuAchievementHint.Contains("성과 보기 목표") &&
                menuAchievementHint.Contains(" · ") &&
                (menuAchievementHint.Contains("목표") || menuAchievementHint.Contains("사례") || menuAchievementHint.Contains("기록")) &&
                menuAchievementHintWidth <= 42f;
            mainMenuBriefingWeaknessFocusReadable &=
                menuRoot != null &&
                menuRoot.gameObject.activeSelf &&
                menuBriefingWeaknessFocusLine.Contains("보정 초점") &&
                menuBriefingWeaknessFocusWidth <= 72f;
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "01_menu"), "main_menu");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "main_menu", LowResolutionFileName(resolution, "01_menu"));
            screenshotCount++;

            ShowFirstRunNotice();
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "01b_first_run_notice"), "first_run_notice");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "first_run_notice", LowResolutionFileName(resolution, "01b_first_run_notice"));
            if (firstRunNoticeRoot != null)
            {
                firstRunNoticeRoot.gameObject.SetActive(false);
            }
            screenshotCount++;

            menuRoot.gameObject.SetActive(false);
            settingsRoot.gameObject.SetActive(false);
            dayTransitionRoot.gameObject.SetActive(false);
            reportRoot.gameObject.SetActive(false);
            tutorialRoot.gameObject.SetActive(false);
            reviewRoot.gameObject.SetActive(true);
            ResetFirstCaseGuide();
            ShowCase(0);
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "02a_first_case_guide"), "first_case_guide");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "first_case_guide", LowResolutionFileName(resolution, "02a_first_case_guide"));
            DismissFirstCaseGuide();
            screenshotCount++;

            ShowCase(0);
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "02_review"), "case_review");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "case_review", LowResolutionFileName(resolution, "02_review"));
            screenshotCount++;

            Decide(DecisionKindFromLabel(cases[0].recommendedDecision));
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "03_feedback"), "decision_feedback");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "decision_feedback", LowResolutionFileName(resolution, "03_feedback"));
            screenshotCount++;

            ShowDecisionHistory();
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "04_history"), "decision_history");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "decision_history", LowResolutionFileName(resolution, "04_history"));
            HideDecisionHistory();
            screenshotCount++;

            yield return PlayRecommendedUntilIncidentDayTransition();
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "05_incident"), "incident_briefing");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "incident_briefing", LowResolutionFileName(resolution, "05_incident"));
            screenshotCount++;

            yield return PlayRecommendedUntilReport();
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "06_report"), "final_report");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "final_report", LowResolutionFileName(resolution, "06_report"));
            screenshotCount++;

            ShowEndingGallery();
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "07_endings"), "ending_gallery");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "ending_gallery", LowResolutionFileName(resolution, "07_endings"));
            screenshotCount++;

            ShowReport();
            RunAgentSimulation();
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "08_agent"), "agent_analysis");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "agent_analysis", LowResolutionFileName(resolution, "08_agent"));
            screenshotCount++;

            ShowReport();
            ShowDecisionAudit();
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "09_audit"), "decision_audit");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "decision_audit", LowResolutionFileName(resolution, "09_audit"));
            screenshotCount++;

            ShowCareerRecords();
            yield return null;
            string careerActionHint = careerRecordActionHintText != null ? careerRecordActionHintText.text : "";
            float actionHintWidth = MaxDisplayLineWidth(careerActionHint);
            careerRecordActionHintMaxDisplayLineWidth = Mathf.Max(careerRecordActionHintMaxDisplayLineWidth, actionHintWidth);
            careerRecordActionHintReadable &=
                careerRecordRoot != null &&
                careerRecordRoot.gameObject.activeSelf &&
                careerActionHint.Contains("액션 안내") &&
                careerActionHint.Contains("대표") &&
                careerActionHint.Contains("조사") &&
                careerActionHint.Contains("다음 목표") &&
                actionHintWidth <= 74f;
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "10_career_record"), "career_record");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "career_record", LowResolutionFileName(resolution, "10_career_record"));
            screenshotCount++;

            SeedMarketingReplayDecorationRecords();
            ShowAchievements();
            yield return null;
            string achievementRecordLinkHint = achievementRecordLinkHintText != null ? achievementRecordLinkHintText.text : "";
            float achievementHintWidth = MaxDisplayLineWidth(achievementRecordLinkHint);
            achievementRecordLinkHintMaxDisplayLineWidth = Mathf.Max(achievementRecordLinkHintMaxDisplayLineWidth, achievementHintWidth);
            achievementRecordLinkHintReadable &=
                achievementRoot != null &&
                achievementRoot.gameObject.activeSelf &&
                achievementRecordLinkHint.Contains("기록 이동") &&
                achievementRecordLinkHint.Contains("메뉴 성과") &&
                achievementRecordLinkHint.Contains("하단 기록/2·4·6회") &&
                achievementRecordLinkHint.Contains("캠페인 기록 필터") &&
                achievementHintWidth <= 72f;
            achievementRecordLinkHintMentionsMenuEntry &=
                achievementRecordLinkHint.Contains("메뉴 성과") &&
                achievementRecordLinkHint.Contains("하단 기록/2·4·6회");
            achievementRecordLinkHintMentionsCoachingFirstUse &=
                achievementRecordLinkHint.Contains("복기") &&
                achievementRecordLinkHint.Contains("W-207") &&
                achievementRecordLinkHint.Contains("기록 복귀");
            lowResolutionReleaseCopyAlignmentReadable &=
                menuAchievementHint.Contains("성과 보기 목표") &&
                careerActionHint.Contains("다음 목표") &&
                achievementRecordLinkHint.Contains("기록 이동") &&
                achievementRecordLinkHint.Contains("캠페인 기록 필터") &&
                menuAchievementHintWidth <= 42f &&
                actionHintWidth <= 74f &&
                achievementHintWidth <= 72f;
            if (string.IsNullOrWhiteSpace(lowResolutionReleaseCopyAlignmentSample))
            {
                lowResolutionReleaseCopyAlignmentSample = menuAchievementHint + " | " + careerActionHint + " | " + achievementRecordLinkHint;
            }
            yield return CaptureLowResolutionUiScreenshot(screenshotDirectory, LowResolutionFileName(resolution, "11_achievements"), "achievements");
            AppendLowResolutionScreenJson(screensJson, ref firstEntry, resolution, "achievements", LowResolutionFileName(resolution, "11_achievements"));
            screenshotCount++;
        }

        int expectedScreenshotCount = ResolutionOptions.Length * 13;
        bool completed =
            screenshotCount == expectedScreenshotCount &&
            lowResolutionInvalidScreenshotCount == 0 &&
            lowResolutionButtonTextOverflowCount == 0 &&
            lowResolutionEvidenceLabelOverflowCount == 0 &&
            lowResolutionOffscreenButtonCount == 0 &&
            mainMenuGuidesFirstActionReadable &&
            mainMenuAchievementBadgeReadable &&
            mainMenuAchievementHintReadable &&
            mainMenuBriefingWeaknessFocusReadable &&
            careerRecordActionHintReadable &&
            achievementRecordLinkHintReadable &&
            achievementRecordLinkHintMentionsMenuEntry &&
            achievementRecordLinkHintMentionsCoachingFirstUse &&
            lowResolutionReleaseCopyAlignmentReadable;
        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_low_resolution_ui_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"resolutionCount\": {ResolutionOptions.Length},\n" +
            $"  \"screenshotCount\": {screenshotCount},\n" +
            $"  \"expectedScreenshotCount\": {expectedScreenshotCount},\n" +
            $"  \"invalidScreenshotCount\": {lowResolutionInvalidScreenshotCount},\n" +
            $"  \"buttonTextOverflowCount\": {lowResolutionButtonTextOverflowCount},\n" +
            $"  \"evidenceLabelOverflowCount\": {lowResolutionEvidenceLabelOverflowCount},\n" +
            $"  \"offscreenButtonCount\": {lowResolutionOffscreenButtonCount},\n" +
            $"  \"mainMenuGuidesFirstActionReadable\": {(mainMenuGuidesFirstActionReadable ? "true" : "false")},\n" +
            $"  \"mainMenuGuidesFirstActionMaxDisplayLineWidth\": {mainMenuGuidesFirstActionMaxDisplayLineWidth:0.0},\n" +
            $"  \"mainMenuGuidesFirstActionLineSample\": \"{EscapeJson(mainMenuGuidesFirstActionLineSample)}\",\n" +
