        string screenshotDirectory = Path.Combine(Application.persistentDataPath, "incident_cards_v030");
        Directory.CreateDirectory(screenshotDirectory);
        foreach (string oldScreenshotPath in Directory.GetFiles(screenshotDirectory, "*.png"))
