            StopDayTransitionIncidentReveal();
            ConfigureDayTransitionIncidentVisual(incident);
            dayTransitionIncidentImage.sprite = IncidentSprite(incident.type);
            dayTransitionIncidentImage.color = Color.white;
            dayTransitionIncidentTitleText.text = $"{incident.title} · {IncidentSeverityLabel(incident)}";
            dayTransitionIncidentImpactText.text = IncidentImpactLine(incident) + "\n" + IncidentBrief(incident);
            dayTransitionTitleText.text = "특별 사건 카드 QA";
            dayTransitionBodyText.text =
