            itemsJson.Append("    {\n");
            itemsJson.Append($"      \"type\": \"{EscapeJson(incident.type)}\",\n");
            itemsJson.Append($"      \"title\": \"{EscapeJson(incident.title)}\",\n");
            itemsJson.Append($"      \"severity\": \"{EscapeJson(IncidentSeverityLabel(incident))}\",\n");
            itemsJson.Append($"      \"screenshot\": \"{EscapeJson(fileName)}\"\n");
            itemsJson.Append("    }");
