            $"  \"usesExpandedIncidentSheet\": {(usesExpandedIncidentSheet ? "true" : "false")},\n" +
            $"  \"incidentTypeCount\": {incidentTypes.Length},\n" +
            $"  \"sheetWidth\": {(incidentCardsSheet != null ? incidentCardsSheet.width : 0)},\n" +
            $"  \"sheetHeight\": {(incidentCardsSheet != null ? incidentCardsSheet.height : 0)},\n" +
            $"  \"screenshotDirectory\": \"{EscapeJson(screenshotDirectory.Replace("\\", "/"))}\",\n" +
            "  \"items\": [\n" +
            itemsJson +
