    private IEnumerator RunVisualVarietySmokeTest()
    {
        yield return null;

        bool[] portraitUsed = new bool[Mathf.Max(1, PortraitSheetColumns() * PortraitSheetRows(PortraitSheetColumns()))];
        bool[] evidenceUsed = new bool[EvidenceCardLabels.Length];
        StringBuilder caseItemsJson = new();

        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            int portraitIndex = careCase.portraitIndex >= 0 ? careCase.portraitIndex : i;
            int portraitSlot = ((portraitIndex % portraitUsed.Length) + portraitUsed.Length) % portraitUsed.Length;
            portraitUsed[portraitSlot] = true;

            int[] evidenceIndices = EvidenceIndicesForCase(careCase, i);
            for (int evidenceSlot = 0; evidenceSlot < evidenceIndices.Length; evidenceSlot++)
            {
                int evidenceIndex = Mathf.Clamp(evidenceIndices[evidenceSlot], 0, evidenceUsed.Length - 1);
                evidenceUsed[evidenceIndex] = true;
            }

            if (i > 0)
            {
                caseItemsJson.Append(",\n");
            }

            caseItemsJson.Append("    {\n");
            caseItemsJson.Append($"      \"caseId\": \"{EscapeJson(careCase.id)}\",\n");
            caseItemsJson.Append($"      \"portraitIndex\": {portraitSlot},\n");
            caseItemsJson.Append($"      \"evidenceIndices\": [{string.Join(",", evidenceIndices)}]\n");
            caseItemsJson.Append("    }");
        }

        int uniquePortraits = CountTrue(portraitUsed);
        int uniqueEvidenceCards = CountTrue(evidenceUsed);
        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_visual_variety_smoke_result.json");
        string resultJson =
            "{\n" +
            "  \"completed\": true,\n" +
            $"  \"caseCount\": {cases.Count},\n" +
            $"  \"portraitSheetWidth\": {(familyPortraitsSheet != null ? familyPortraitsSheet.width : 0)},\n" +
            $"  \"portraitSheetHeight\": {(familyPortraitsSheet != null ? familyPortraitsSheet.height : 0)},\n" +
            $"  \"portraitSlotCount\": {portraitUsed.Length},\n" +
            $"  \"uniquePortraits\": {uniquePortraits},\n" +
            $"  \"evidenceSlotCount\": {evidenceUsed.Length},\n" +
            $"  \"uniqueEvidenceCards\": {uniqueEvidenceCards},\n" +
            $"  \"passesVarietyGate\": {(uniquePortraits >= Mathf.Min(8, portraitUsed.Length) && uniqueEvidenceCards >= EvidenceCardLabels.Length ? "true" : "false")},\n" +
            "  \"cases\": [\n" +
            caseItemsJson +
            "\n  ]\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_VISUAL_VARIETY_SMOKE_RESULT path=" + resultPath + " portraits=" + uniquePortraits + " evidence=" + uniqueEvidenceCards);
        Application.Quit();
    }

