    private DataSourceAuditExport BuildDataSourceAuditExport(string generatedAt)
    {
        const int expectedCaseFileCount = 5;
        DataSourceAuditExport audit = new()
        {
            generatedAt = generatedAt,
            buildVersion = BuildVersionLabel,
            expectedCaseFileCount = expectedCaseFileCount,
            runtimeCaseCount = cases.Count,
            caseFiles = new List<DataSourceFileSummary>(),
            agentPersonas = new DataSourcePersonaSummary { resourcePath = "Data/agent_personas" },
            issues = new List<string>()
        };

        HashSet<string> ids = new(StringComparer.OrdinalIgnoreCase);
        HashSet<int> days = new();

        for (int day = 1; day <= expectedCaseFileCount; day++)
        {
            string resourcePath = $"Data/cases_day{day}";
            TextAsset asset = Resources.Load<TextAsset>(resourcePath);
            DataSourceFileSummary summary = new()
            {
                resourcePath = resourcePath,
                expectedDay = day,
                exists = asset != null
            };

            if (asset == null)
            {
                audit.missingCaseFileCount++;
                audit.issues.Add(resourcePath + ": missing_case_file");
                audit.caseFiles.Add(summary);
                continue;
            }

            audit.caseFileCount++;
            summary.byteLength = Encoding.UTF8.GetByteCount(asset.text);

            CaseDatabase database = null;
            try
            {
                database = JsonUtility.FromJson<CaseDatabase>(asset.text);
            }
            catch (Exception exception)
            {
                summary.parseError = true;
                audit.parseErrorCount++;
                audit.issues.Add(resourcePath + ": parse_error " + exception.Message);
                audit.caseFiles.Add(summary);
                continue;
            }

            if (database?.cases == null || database.cases.Count == 0)
            {
                summary.parseError = true;
                audit.parseErrorCount++;
                audit.issues.Add(resourcePath + ": empty_case_database");
                audit.caseFiles.Add(summary);
                continue;
            }

            summary.caseCount = database.cases.Count;
            for (int i = 0; i < database.cases.Count; i++)
            {
                CareCase careCase = database.cases[i];
                audit.externalCaseCount++;
                days.Add(careCase.day);

                if (careCase.day != day)
                {
                    summary.dayMismatchCount++;
                    audit.dayMismatchCount++;
                }

                if (string.IsNullOrWhiteSpace(careCase.id) || !ids.Add(careCase.id))
                {
                    summary.duplicateIdCount++;
                    audit.duplicateIdCount++;
                }

                if (IsMissingCriticalCaseField(careCase))
                {
                    summary.missingCriticalFieldCount++;
                    audit.missingCriticalFieldCount++;
                }

                if (!IsValidRecommendedDecision(careCase.recommendedDecision))
                {
                    summary.invalidRecommendedDecisionCount++;
                    audit.invalidRecommendedDecisionCount++;
                }

                if (!IsPercentMetric(careCase.urgency) ||
                    !IsPercentMetric(careCase.equityNeed) ||
                    !IsPercentMetric(careCase.documentStrength))
                {
                    summary.outOfRangeMetricCount++;
                    audit.outOfRangeMetricCount++;
                }

                if (careCase.cost < 100 || careCase.cost > 800)
                {
                    summary.invalidCostCount++;
                    audit.invalidCostCount++;
                }
            }

            summary.passed = summary.caseCount >= 8 &&
                summary.dayMismatchCount == 0 &&
                summary.duplicateIdCount == 0 &&
                summary.missingCriticalFieldCount == 0 &&
                summary.invalidRecommendedDecisionCount == 0 &&
                summary.outOfRangeMetricCount == 0 &&
                summary.invalidCostCount == 0;
            if (summary.caseCount >= 8)
            {
                audit.daysWithEightCases++;
            }

            if (!summary.passed)
            {
                audit.issues.Add(resourcePath + ": file_gate_failed");
            }

            audit.caseFiles.Add(summary);
        }

        audit.dayCount = days.Count;
        audit.embeddedFallbackUsed = audit.externalCaseCount == 0 && cases.Count > 0;
        audit.casesLoadedFromExternalJson = audit.externalCaseCount == cases.Count && audit.externalCaseCount >= 40;

        TextAsset personaAsset = Resources.Load<TextAsset>("Data/agent_personas");
        audit.agentPersonas.exists = personaAsset != null;
        if (personaAsset == null)
        {
            audit.issues.Add("Data/agent_personas: missing_persona_file");
        }
        else
        {
            audit.agentPersonas.byteLength = Encoding.UTF8.GetByteCount(personaAsset.text);
            try
            {
                AgentPersonaDatabase database = JsonUtility.FromJson<AgentPersonaDatabase>(personaAsset.text);
                if (database?.personas != null)
                {
                    audit.personaCount = database.personas.Count;
                    audit.agentPersonas.personaCount = database.personas.Count;
                    for (int i = 0; i < database.personas.Count; i++)
                    {
                        AgentPersona persona = database.personas[i];
                        if (string.IsNullOrWhiteSpace(persona.id) ||
                            string.IsNullOrWhiteSpace(persona.name) ||
                            persona.urgencyWeight <= 0f ||
                            persona.equityWeight <= 0f ||
                            persona.documentWeight <= 0f ||
                            persona.budgetWeight <= 0f ||
                            persona.documentDoubtWeight <= 0f)
                        {
                            audit.invalidPersonaCount++;
                            audit.agentPersonas.invalidPersonaCount++;
                        }
                    }
                }
            }
            catch (Exception exception)
            {
                audit.parseErrorCount++;
                audit.agentPersonas.parseError = true;
                audit.issues.Add("Data/agent_personas: parse_error " + exception.Message);
            }
        }

        audit.agentPersonas.passed = audit.agentPersonas.exists &&
            !audit.agentPersonas.parseError &&
            audit.agentPersonas.personaCount >= 5 &&
            audit.agentPersonas.invalidPersonaCount == 0;
        if (!audit.agentPersonas.passed)
        {
            audit.issues.Add("Data/agent_personas: persona_gate_failed");
        }

        audit.issueCount = audit.missingCaseFileCount +
            audit.parseErrorCount +
            audit.duplicateIdCount +
            audit.missingCriticalFieldCount +
            audit.invalidRecommendedDecisionCount +
            audit.outOfRangeMetricCount +
            audit.invalidCostCount +
            audit.dayMismatchCount +
            audit.invalidPersonaCount;
        audit.passesDataSourceGate = audit.caseFileCount == expectedCaseFileCount &&
            audit.missingCaseFileCount == 0 &&
            audit.externalCaseCount >= 40 &&
            audit.runtimeCaseCount == audit.externalCaseCount &&
            audit.dayCount >= 5 &&
            audit.daysWithEightCases >= 5 &&
            audit.casesLoadedFromExternalJson &&
            !audit.embeddedFallbackUsed &&
            audit.personaCount >= 5 &&
            audit.issueCount == 0 &&
            audit.agentPersonas.passed;
        return audit;
    }

    private static string BuildDataSourceAuditMarkdown(DataSourceAuditExport audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("# 데이터 소스 무결성 감사");
        builder.AppendLine();
        builder.AppendLine($"- 생성 시각: {audit.generatedAt}");
        builder.AppendLine($"- 빌드: {audit.buildVersion}");
        builder.AppendLine($"- 판정: {(audit.passesDataSourceGate ? "통과" : "보강 필요")}");
        builder.AppendLine($"- 외부 JSON 사례: {audit.externalCaseCount}건 / 런타임 사례: {audit.runtimeCaseCount}건");
        builder.AppendLine($"- 일차 수: {audit.dayCount}, 8건 이상 일차: {audit.daysWithEightCases}");
        builder.AppendLine($"- 가상 플레이어 페르소나: {audit.personaCount}개");
        builder.AppendLine($"- 내장 대체 사용: {BoolLabel(audit.embeddedFallbackUsed)}");
        builder.AppendLine();
        builder.AppendLine("## 사례 JSON 파일");
        builder.AppendLine();
        builder.AppendLine("| Resource | Exists | Cases | Expected Day | Day Mismatch | Issues | Pass |");
        builder.AppendLine("| --- | --- | ---: | ---: | ---: | --- | --- |");
        foreach (DataSourceFileSummary summary in audit.caseFiles)
        {
            int issueCount = summary.duplicateIdCount +
                summary.missingCriticalFieldCount +
                summary.invalidRecommendedDecisionCount +
                summary.outOfRangeMetricCount +
                summary.invalidCostCount +
                summary.dayMismatchCount +
                (summary.parseError ? 1 : 0);
            builder.AppendLine($"| {summary.resourcePath} | {BoolLabel(summary.exists)} | {summary.caseCount} | {summary.expectedDay} | {summary.dayMismatchCount} | {issueCount} | {BoolLabel(summary.passed)} |");
        }

        builder.AppendLine();
        builder.AppendLine("## 에이전트 페르소나 JSON");
        builder.AppendLine();
        builder.AppendLine($"- 파일: {audit.agentPersonas.resourcePath}");
        builder.AppendLine($"- 존재: {BoolLabel(audit.agentPersonas.exists)}");
        builder.AppendLine($"- 페르소나 수: {audit.agentPersonas.personaCount}");
        builder.AppendLine($"- 무효 페르소나: {audit.agentPersonas.invalidPersonaCount}");
        builder.AppendLine($"- 통과: {BoolLabel(audit.agentPersonas.passed)}");
        builder.AppendLine();
        builder.AppendLine("## 점검 항목");
        builder.AppendLine();
        builder.AppendLine($"- 누락 사례 파일: {audit.missingCaseFileCount}");
        builder.AppendLine($"- 파싱 오류: {audit.parseErrorCount}");
        builder.AppendLine($"- 중복/누락 ID: {audit.duplicateIdCount}");
        builder.AppendLine($"- 핵심 필드 누락: {audit.missingCriticalFieldCount}");
        builder.AppendLine($"- 권장 판단 오류: {audit.invalidRecommendedDecisionCount}");
        builder.AppendLine($"- 지표 범위 오류: {audit.outOfRangeMetricCount}");
        builder.AppendLine($"- 비용 범위 오류: {audit.invalidCostCount}");
        builder.AppendLine($"- 파일 일차 불일치: {audit.dayMismatchCount}");
        if (audit.issues != null && audit.issues.Count > 0)
        {
            builder.AppendLine();
            builder.AppendLine("## 이슈");
            foreach (string issue in audit.issues)
            {
                builder.AppendLine("- " + issue);
            }
        }

        return builder.ToString();
    }

    private ContentAuditExport BuildContentAuditExport(string generatedAt)
    {
        ContentAuditExport audit = new()
        {
            generatedAt = generatedAt,
            buildVersion = BuildVersionLabel,
            caseCount = cases.Count,
            daySummaries = new List<ContentAuditDaySummary>(),
            decisionSummaries = new List<ContentAuditDecisionSummary>(),
            cases = new List<ContentAuditCaseRow>(),
            issues = new List<string>()
        };

        HashSet<string> ids = new(StringComparer.OrdinalIgnoreCase);
        HashSet<int> days = new();
        HashSet<string> familyTypes = new(StringComparer.OrdinalIgnoreCase);
        Dictionary<int, ContentAuditDaySummary> daySummaries = new();
        Dictionary<string, ContentAuditDecisionSummary> decisionSummaries = new(StringComparer.OrdinalIgnoreCase);
        int minCost = int.MaxValue;
        int maxCost = int.MinValue;
        int minUrgency = int.MaxValue;
        int maxUrgency = int.MinValue;
        int minDocumentStrength = int.MaxValue;
        int maxDocumentStrength = int.MinValue;
        int minEquityNeed = int.MaxValue;
        int maxEquityNeed = int.MinValue;

        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            List<string> rowIssues = new();
            bool duplicateId = !string.IsNullOrWhiteSpace(careCase.id) && !ids.Add(careCase.id);
            if (duplicateId)
            {
                audit.duplicateIdCount++;
                rowIssues.Add("duplicate_id");
            }

            bool missingCritical = IsMissingCriticalCaseField(careCase);
            if (missingCritical)
            {
                audit.missingCriticalFieldCount++;
                rowIssues.Add("missing_critical_field");
            }

            bool invalidRecommended = !IsValidRecommendedDecision(careCase.recommendedDecision);
            if (invalidRecommended)
            {
                audit.invalidRecommendedDecisionCount++;
                rowIssues.Add("invalid_recommended_decision");
            }

            bool outOfRangeMetric = !IsPercentMetric(careCase.urgency) ||
                !IsPercentMetric(careCase.equityNeed) ||
                !IsPercentMetric(careCase.documentStrength) ||
                careCase.day < 1;
            if (outOfRangeMetric)
            {
                audit.outOfRangeMetricCount++;
                rowIssues.Add("out_of_range_metric");
            }

            bool invalidCost = careCase.cost < 100 || careCase.cost > 800;
            if (invalidCost)
            {
                audit.invalidCostCount++;
                rowIssues.Add("invalid_cost");
            }

            if (careCase.urgency >= 80)
            {
                audit.highRiskCaseCount++;
            }

            if (careCase.documentStrength < 60)
            {
                audit.documentWeakCaseCount++;
            }

            if (!careCase.incomeEligible)
            {
                audit.incomeExceptionCaseCount++;
            }

            if (careCase.cost >= 360)
            {
                audit.highCostCaseCount++;
            }

            if (!string.IsNullOrWhiteSpace(careCase.followUp))
            {
                audit.followUpCompleteCount++;
            }

            if (!string.IsNullOrWhiteSpace(careCase.endingTag))
            {
                audit.endingTagCompleteCount++;
            }

            days.Add(careCase.day);
            audit.highestDay = Mathf.Max(audit.highestDay, careCase.day);
            familyTypes.Add(careCase.type ?? string.Empty);
            minCost = Mathf.Min(minCost, careCase.cost);
            maxCost = Mathf.Max(maxCost, careCase.cost);
            minUrgency = Mathf.Min(minUrgency, careCase.urgency);
            maxUrgency = Mathf.Max(maxUrgency, careCase.urgency);
            minDocumentStrength = Mathf.Min(minDocumentStrength, careCase.documentStrength);
            maxDocumentStrength = Mathf.Max(maxDocumentStrength, careCase.documentStrength);
            minEquityNeed = Mathf.Min(minEquityNeed, careCase.equityNeed);
            maxEquityNeed = Mathf.Max(maxEquityNeed, careCase.equityNeed);

            if (!daySummaries.TryGetValue(careCase.day, out ContentAuditDaySummary daySummary))
            {
                daySummary = new ContentAuditDaySummary { day = careCase.day };
                daySummaries.Add(careCase.day, daySummary);
            }

            daySummary.caseCount++;
            daySummary.totalCost += careCase.cost;
            if (careCase.urgency >= 80)
            {
                daySummary.highRiskCount++;
            }

            if (careCase.documentStrength < 60)
            {
                daySummary.documentWeakCount++;
            }

            if (!careCase.incomeEligible)
            {
                daySummary.incomeExceptionCount++;
            }

            if (!string.IsNullOrWhiteSpace(careCase.recommendedDecision))
            {
                if (!decisionSummaries.TryGetValue(careCase.recommendedDecision, out ContentAuditDecisionSummary decisionSummary))
                {
                    decisionSummary = new ContentAuditDecisionSummary { decision = careCase.recommendedDecision };
                    decisionSummaries.Add(careCase.recommendedDecision, decisionSummary);
                }

                decisionSummary.caseCount++;
            }

            int pressure = CasePressureScore(careCase);
            audit.cases.Add(new ContentAuditCaseRow
            {
                caseId = careCase.id,
                familyType = careCase.type,
                day = careCase.day,
                cost = careCase.cost,
                urgency = careCase.urgency,
                equityNeed = careCase.equityNeed,
                documentStrength = careCase.documentStrength,
                incomeEligible = careCase.incomeEligible,
                recommendedDecision = careCase.recommendedDecision,
                pressureScore = pressure,
                missingDocuments = careCase.missingDocuments,
                hasFollowUp = !string.IsNullOrWhiteSpace(careCase.followUp),
                hasEndingTag = !string.IsNullOrWhiteSpace(careCase.endingTag),
                issueFlags = rowIssues.Count == 0 ? "ok" : string.Join(";", rowIssues)
            });

            if (rowIssues.Count > 0)
            {
                audit.issues.Add($"{careCase.id}: {string.Join(", ", rowIssues)}");
            }
        }

        audit.dayCount = days.Count;
        audit.familyTypeCount = familyTypes.Count;
        audit.recommendedDecisionTypeCount = decisionSummaries.Count;
        audit.minCost = minCost == int.MaxValue ? 0 : minCost;
        audit.maxCost = maxCost == int.MinValue ? 0 : maxCost;
        audit.minUrgency = minUrgency == int.MaxValue ? 0 : minUrgency;
        audit.maxUrgency = maxUrgency == int.MinValue ? 0 : maxUrgency;
        audit.minDocumentStrength = minDocumentStrength == int.MaxValue ? 0 : minDocumentStrength;
        audit.maxDocumentStrength = maxDocumentStrength == int.MinValue ? 0 : maxDocumentStrength;
        audit.minEquityNeed = minEquityNeed == int.MaxValue ? 0 : minEquityNeed;
        audit.maxEquityNeed = maxEquityNeed == int.MinValue ? 0 : maxEquityNeed;

        foreach (ContentAuditDaySummary daySummary in daySummaries.Values)
        {
            daySummary.averageCost = daySummary.caseCount > 0 ? Mathf.RoundToInt(daySummary.totalCost / (float)daySummary.caseCount) : 0;
            if (daySummary.caseCount >= 8)
            {
                audit.daysWithEightCases++;
            }
            audit.daySummaries.Add(daySummary);
        }

        audit.daySummaries.Sort((left, right) => left.day.CompareTo(right.day));
        audit.decisionSummaries.AddRange(decisionSummaries.Values);
        audit.decisionSummaries.Sort((left, right) => string.Compare(left.decision, right.decision, StringComparison.Ordinal));
        audit.issueCount = audit.duplicateIdCount +
            audit.invalidRecommendedDecisionCount +
            audit.missingCriticalFieldCount +
            audit.outOfRangeMetricCount +
            audit.invalidCostCount;
        audit.passesCommercialContentGate = audit.caseCount >= 40 &&
            audit.highestDay >= 5 &&
            audit.dayCount >= 5 &&
            audit.daysWithEightCases >= 5 &&
            audit.familyTypeCount >= 20 &&
            audit.recommendedDecisionTypeCount >= 5 &&
            audit.highRiskCaseCount >= 12 &&
            audit.documentWeakCaseCount >= 12 &&
            audit.incomeExceptionCaseCount >= 8 &&
            audit.highCostCaseCount >= 12 &&
            audit.followUpCompleteCount == audit.caseCount &&
            audit.endingTagCompleteCount == audit.caseCount &&
            audit.issueCount == 0;

        if (audit.issues.Count == 0)
        {
            audit.issues.Add("none");
        }

        return audit;
    }

    private static bool IsMissingCriticalCaseField(CareCase careCase)
    {
        return string.IsNullOrWhiteSpace(careCase.id) ||
            string.IsNullOrWhiteSpace(careCase.name) ||
            string.IsNullOrWhiteSpace(careCase.type) ||
            string.IsNullOrWhiteSpace(careCase.request) ||
            string.IsNullOrWhiteSpace(careCase.summary) ||
            string.IsNullOrWhiteSpace(careCase.documents) ||
            string.IsNullOrWhiteSpace(careCase.signal) ||
            string.IsNullOrWhiteSpace(careCase.missingDocuments) ||
            string.IsNullOrWhiteSpace(careCase.recommendedDecision) ||
            string.IsNullOrWhiteSpace(careCase.followUp) ||
            string.IsNullOrWhiteSpace(careCase.endingTag);
    }

    private static bool IsPercentMetric(int value)
    {
        return value >= 0 && value <= 100;
    }

    private static bool IsValidRecommendedDecision(string decision)
    {
        return decision == "승인" ||
            decision == "조건부 승인" ||
            decision == "보류" ||
            decision == "추가조사" ||
            decision == "거절";
    }

    private static string BuildContentAuditCsv(ContentAuditExport audit)
    {
        StringBuilder csv = new();
        csv.AppendLine("case_id,family_type,day,cost,urgency,equity_need,document_strength,income_eligible,recommended_decision,pressure_score,has_follow_up,has_ending_tag,missing_documents,issue_flags");
        for (int i = 0; i < audit.cases.Count; i++)
        {
            ContentAuditCaseRow row = audit.cases[i];
            csv.Append(EscapeCsv(row.caseId)).Append(',');
            csv.Append(EscapeCsv(row.familyType)).Append(',');
            csv.Append(row.day).Append(',');
            csv.Append(row.cost).Append(',');
            csv.Append(row.urgency).Append(',');
            csv.Append(row.equityNeed).Append(',');
            csv.Append(row.documentStrength).Append(',');
            csv.Append(row.incomeEligible ? "true" : "false").Append(',');
            csv.Append(EscapeCsv(row.recommendedDecision)).Append(',');
            csv.Append(row.pressureScore).Append(',');
            csv.Append(row.hasFollowUp ? "true" : "false").Append(',');
            csv.Append(row.hasEndingTag ? "true" : "false").Append(',');
            csv.Append(EscapeCsv(row.missingDocuments)).Append(',');
            csv.AppendLine(EscapeCsv(row.issueFlags));
        }

        return csv.ToString();
    }

    private static string BuildContentAuditMarkdown(ContentAuditExport audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("# 돌봄지원 심사소 상용 콘텐츠 감사");
        builder.AppendLine();
        builder.AppendLine($"생성 시각: {audit.generatedAt}");
        builder.AppendLine($"빌드: {audit.buildVersion}");
        builder.AppendLine($"상용 콘텐츠 게이트: {(audit.passesCommercialContentGate ? "통과" : "보강 필요")}");
        builder.AppendLine();
        builder.AppendLine("## 요약");
        builder.AppendLine();
        builder.AppendLine($"- 사례 수: {audit.caseCount}");
        builder.AppendLine($"- 일차: {audit.dayCount}개 / 최고 {audit.highestDay}일차 / 8건 이상 일차 {audit.daysWithEightCases}개");
        builder.AppendLine($"- 가족 유형: {audit.familyTypeCount}개");
        builder.AppendLine($"- 권장 판단 종류: {audit.recommendedDecisionTypeCount}개");
        builder.AppendLine($"- 고긴급 사례: {audit.highRiskCaseCount}개");
        builder.AppendLine($"- 서류 취약 사례: {audit.documentWeakCaseCount}개");
        builder.AppendLine($"- 소득 예외 사례: {audit.incomeExceptionCaseCount}개");
        builder.AppendLine($"- 고비용 사례: {audit.highCostCaseCount}개");
        builder.AppendLine($"- 후속 메모 완비: {audit.followUpCompleteCount}/{audit.caseCount}");
        builder.AppendLine($"- 엔딩 태그 완비: {audit.endingTagCompleteCount}/{audit.caseCount}");
        builder.AppendLine($"- 검수 이슈: {audit.issueCount}개");
        builder.AppendLine();
        builder.AppendLine("## 일차별 구성");
        builder.AppendLine();
        builder.AppendLine("| 일차 | 사례 | 평균 비용 | 고긴급 | 서류 취약 | 소득 예외 |");
        builder.AppendLine("|---:|---:|---:|---:|---:|---:|");
        for (int i = 0; i < audit.daySummaries.Count; i++)
        {
            ContentAuditDaySummary day = audit.daySummaries[i];
            builder.AppendLine($"| {day.day} | {day.caseCount} | {day.averageCost} | {day.highRiskCount} | {day.documentWeakCount} | {day.incomeExceptionCount} |");
        }

        builder.AppendLine();
        builder.AppendLine("## 권장 판단 분포");
        builder.AppendLine();
        builder.AppendLine("| 권장 판단 | 사례 |");
        builder.AppendLine("|---|---:|");
        for (int i = 0; i < audit.decisionSummaries.Count; i++)
        {
            ContentAuditDecisionSummary decision = audit.decisionSummaries[i];
            builder.AppendLine($"| {decision.decision} | {decision.caseCount} |");
        }

        builder.AppendLine();
        builder.AppendLine("## 이슈");
        builder.AppendLine();
        for (int i = 0; i < audit.issues.Count; i++)
        {
            builder.AppendLine($"- {audit.issues[i]}");
        }

        return builder.ToString();
    }

    private static int CountTrue(bool[] values)
    {
        int count = 0;
        for (int i = 0; i < values.Length; i++)
        {
            if (values[i])
            {
                count++;
            }
        }

        return count;
    }

    private IEnumerator RunPerformanceSmokeTest()
    {
        yield return null;

        bool previousLowSpecMode = lowSpecMode;
        int previousFrameRateIndex = frameRateIndex;
        int previousResolutionIndex = resolutionIndex;
        bool previousFullscreenEnabled = fullscreenEnabled;

        lowSpecMode = true;
        frameRateIndex = 0;
        resolutionIndex = 0;
        fullscreenEnabled = false;
        ApplyDisplaySettings();
        ApplyPerformanceSettings();
        yield return PrepareCaptureResolution(1280, 720);

        List<PerformanceScreenSample> samples = new();

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        ShowMainMenu();
        yield return MeasurePerformanceScreen("main_menu", samples);

        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        tutorialRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);
        yield return MeasurePerformanceScreen("case_review", samples);

        Decide(DecisionKindFromLabel(cases[0].recommendedDecision));
        yield return MeasurePerformanceScreen("decision_feedback", samples);

        yield return PlayRecommendedUntilIncidentDayTransition();
        yield return MeasurePerformanceScreen("incident_briefing", samples);

        yield return PlayRecommendedUntilReport();
        yield return MeasurePerformanceScreen("final_report", samples);

        ShowEndingGallery();
        yield return MeasurePerformanceScreen("ending_gallery", samples);

        bool passesFrameBudget = true;
        for (int i = 0; i < samples.Count; i++)
        {
            if (!samples[i].passesFrameBudget)
            {
                passesFrameBudget = false;
                break;
            }
        }

        PerformanceSmokeResult result = new()
        {
            completed = samples.Count == 6,
            generatedAt = DateTime.Now.ToString("s"),
            lowSpecMode = lowSpecMode,
            targetFrameRate = Application.targetFrameRate,
            frameBudgetMs = 50f,
            passesFrameBudget = passesFrameBudget,
            screenCount = samples.Count,
            targetWidth = 1280,
            targetHeight = 720,
            actualWidth = Screen.width,
            actualHeight = Screen.height,
            graphicsDeviceName = SystemInfo.graphicsDeviceName,
            graphicsDeviceType = SystemInfo.graphicsDeviceType.ToString(),
            graphicsMemorySizeMb = SystemInfo.graphicsMemorySize,
            processorType = SystemInfo.processorType,
            processorCount = SystemInfo.processorCount,
            systemMemorySizeMb = SystemInfo.systemMemorySize,
            managedMemoryBytes = GC.GetTotalMemory(false),
            screens = samples
        };

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_performance_smoke_result.json");
        File.WriteAllText(resultPath, JsonUtility.ToJson(result, true), Encoding.UTF8);
        Debug.Log("CARE_REVIEW_PERFORMANCE_SMOKE_RESULT path=" + resultPath + " screens=" + samples.Count + " passesFrameBudget=" + passesFrameBudget);

        lowSpecMode = previousLowSpecMode;
        frameRateIndex = previousFrameRateIndex;
        resolutionIndex = previousResolutionIndex;
        fullscreenEnabled = previousFullscreenEnabled;
        ApplyDisplaySettings();
        ApplyPerformanceSettings();
        yield return new WaitForSeconds(0.25f);
        Application.Quit();
    }

    private IEnumerator RunSystemDiagnosticSmokeTest()
    {
        yield return null;

        ShowSettings();
        yield return RunSystemDiagnosticExportRoutine();
        yield return null;

        string jsonPath = Path.Combine(LogDirectory, "care_review_system_diagnostic.json");
        string markdownPath = Path.Combine(LogDirectory, "care_review_system_diagnostic.md");
        string jsonText = File.Exists(jsonPath) ? File.ReadAllText(jsonPath, Encoding.UTF8) : "";
        string markdownText = File.Exists(markdownPath) ? File.ReadAllText(markdownPath, Encoding.UTF8) : "";
        bool hasJson = File.Exists(jsonPath);
        bool hasMarkdown = File.Exists(markdownPath);
        bool jsonHasSystem = jsonText.Contains("\"processorType\"") && jsonText.Contains("\"graphicsDeviceName\"") && jsonText.Contains("\"systemMemorySizeMb\"");
        bool jsonHasSettings = jsonText.Contains("\"lowSpecMode\"") && jsonText.Contains("\"targetFrameRate\"") && jsonText.Contains("\"resolutionLabel\"");
        bool jsonHasFrameSample = jsonText.Contains("\"sampleFrameCount\"") && jsonText.Contains("\"p95FrameMs\"") && jsonText.Contains("\"passesFrameBudget\"");
        bool markdownHasSummary = markdownText.Contains("환경 진단") && markdownText.Contains("p95") && markdownText.Contains("그래픽");
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(jsonText) && !ContainsLocalAbsolutePath(markdownText);
        bool statusMentionsSaved = settingsStatusText != null && settingsStatusText.text.Contains("환경 진단 저장 완료");
        bool completed = hasJson &&
            hasMarkdown &&
            jsonHasSystem &&
            jsonHasSettings &&
            jsonHasFrameSample &&
            markdownHasSummary &&
            filesHaveNoLocalAbsolutePath &&
            statusMentionsSaved;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_system_diagnostic_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"hasJson\": {(hasJson ? "true" : "false")},\n" +
            $"  \"hasMarkdown\": {(hasMarkdown ? "true" : "false")},\n" +
            $"  \"jsonHasSystem\": {(jsonHasSystem ? "true" : "false")},\n" +
            $"  \"jsonHasSettings\": {(jsonHasSettings ? "true" : "false")},\n" +
            $"  \"jsonHasFrameSample\": {(jsonHasFrameSample ? "true" : "false")},\n" +
            $"  \"markdownHasSummary\": {(markdownHasSummary ? "true" : "false")},\n" +
            $"  \"filesHaveNoLocalAbsolutePath\": {(filesHaveNoLocalAbsolutePath ? "true" : "false")},\n" +
            $"  \"statusMentionsSaved\": {(statusMentionsSaved ? "true" : "false")},\n" +
            $"  \"diagnosticJsonFile\": \"{EscapeJson(Path.GetFileName(jsonPath))}\",\n" +
            $"  \"diagnosticMarkdownFile\": \"{EscapeJson(Path.GetFileName(markdownPath))}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_SYSTEM_DIAGNOSTIC_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        Application.Quit();
    }

