    private IEnumerator RunPlaytestSurveySmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        yield return PlayRecommendedUntilReport();
        ShowPlaytestSurvey();
        yield return null;

        SetPlaytestSurveyRating(0, 4);
        SetPlaytestSurveyRating(1, 5);
        SetPlaytestSurveyRating(2, 4);
        SetPlaytestSurveyRating(3, 5);
        SetPlaytestSurveyRating(4, 4);
        SetPlaytestSurveyRating(5, 5);
        SetPlaytestSurveyFlag(1, true);
        SetPlaytestSurveyFlag(3, true);
        PlaytestSurveyExport survey = SavePlaytestSurveyFiles();
        yield return null;

        string jsonPath = Path.Combine(Application.persistentDataPath, "care_review_in_game_feedback.json");
        string markdownPath = Path.Combine(Application.persistentDataPath, "care_review_in_game_feedback.md");
        string jsonText = File.Exists(jsonPath) ? File.ReadAllText(jsonPath, Encoding.UTF8) : "";
        string markdownText = File.Exists(markdownPath) ? File.ReadAllText(markdownPath, Encoding.UTF8) : "";
        bool surveyActive = playtestSurveyRoot != null && playtestSurveyRoot.gameObject.activeSelf;
        bool summaryMentionsSession = playtestSurveySummaryText != null && playtestSurveySummaryText.text.Contains("세션 ID") && playtestSurveySummaryText.text.Contains(survey.sessionId);
        bool statusMentionsSaved = playtestSurveyStatusText != null && playtestSurveyStatusText.text.Contains("인게임 설문 저장 완료");
        bool jsonHasRatings = jsonText.Contains("\"difficultyRating\": 4") && jsonText.Contains("\"decisionClarityRating\": 5") && jsonText.Contains("\"priceValueRating\": 4");
        bool jsonHasReplayRewardValueRating = jsonText.Contains("\"replayRewardValueRating\": 5");
        bool jsonHasFlags = jsonText.Contains("\"uiNeedsWork\": true") && jsonText.Contains("\"replayIntent\": true");
        bool markdownHasSurvey = markdownText.Contains("인게임 구조화 설문") && markdownText.Contains("10달러 가치감") && markdownText.Contains("다시 플레이 의향");
        bool markdownMentionsReplayRewardValue =
            markdownText.Contains("반복 보상/장기 기록 가치감") &&
            markdownText.Contains("성과 반복 보상") &&
            markdownText.Contains("캠페인 기록 장기 추세");
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(jsonText) && !ContainsLocalAbsolutePath(markdownText);

        ClosePlaytestSurvey();
        yield return null;
        bool closeReturnsReport = reportRoot.gameObject.activeSelf && playtestSurveyRoot != null && !playtestSurveyRoot.gameObject.activeSelf;
        bool completed = surveyActive &&
            summaryMentionsSession &&
            statusMentionsSaved &&
            File.Exists(jsonPath) &&
            File.Exists(markdownPath) &&
            jsonHasRatings &&
            jsonHasReplayRewardValueRating &&
            jsonHasFlags &&
            markdownHasSurvey &&
            markdownMentionsReplayRewardValue &&
            filesHaveNoLocalAbsolutePath &&
            closeReturnsReport;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_playtest_survey_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"surveyActive\": {(surveyActive ? "true" : "false")},\n" +
            $"  \"summaryMentionsSession\": {(summaryMentionsSession ? "true" : "false")},\n" +
            $"  \"statusMentionsSaved\": {(statusMentionsSaved ? "true" : "false")},\n" +
            $"  \"hasJson\": {(File.Exists(jsonPath) ? "true" : "false")},\n" +
            $"  \"hasMarkdown\": {(File.Exists(markdownPath) ? "true" : "false")},\n" +
            $"  \"jsonHasRatings\": {(jsonHasRatings ? "true" : "false")},\n" +
            $"  \"jsonHasReplayRewardValueRating\": {(jsonHasReplayRewardValueRating ? "true" : "false")},\n" +
            $"  \"jsonHasFlags\": {(jsonHasFlags ? "true" : "false")},\n" +
            $"  \"markdownHasSurvey\": {(markdownHasSurvey ? "true" : "false")},\n" +
            $"  \"markdownMentionsReplayRewardValue\": {(markdownMentionsReplayRewardValue ? "true" : "false")},\n" +
            $"  \"filesHaveNoLocalAbsolutePath\": {(filesHaveNoLocalAbsolutePath ? "true" : "false")},\n" +
            $"  \"closeReturnsReport\": {(closeReturnsReport ? "true" : "false")},\n" +
            $"  \"surveyJsonFile\": \"{EscapeJson(Path.GetFileName(jsonPath))}\",\n" +
            $"  \"surveyMarkdownFile\": \"{EscapeJson(Path.GetFileName(markdownPath))}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_PLAYTEST_SURVEY_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        Application.Quit();
    }

    private IEnumerator RunPlaytestReadinessSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        tutorialRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        yield return PlayRecommendedUntilReport();
        ShowPlaytestSurvey();
        yield return null;

        PlaytestCollectionReadiness before = BuildPlaytestCollectionReadiness();
        string beforeSummary = playtestSurveySummaryText != null ? playtestSurveySummaryText.text : "";
        string beforeStatus = playtestSurveyStatusText != null ? playtestSurveyStatusText.text : "";
        string beforeCommercialChecklist = playtestSurveyCommercialTriageText != null ? playtestSurveyCommercialTriageText.text : "";
        bool beforeMentionsReadiness = beforeSummary.Contains("회수 준비") && beforeStatus.Contains("회수 준비");
        bool commercialChecklistMentionsSurfaceActions =
            beforeCommercialChecklist.Contains("상용화 보강 체크") &&
            beforeCommercialChecklist.Contains("성과 기록") &&
            beforeCommercialChecklist.Contains("다음 목표") &&
            beforeCommercialChecklist.Contains("2·4·6 보상") &&
            beforeCommercialChecklist.Contains("캠페인 기록") &&
            beforeCommercialChecklist.Contains("장기 추세") &&
            beforeCommercialChecklist.Contains("상점 후보") &&
            beforeCommercialChecklist.Contains("다시 할 이유");
        float commercialChecklistMaxDisplayLineWidth = MaxDisplayLineWidth(beforeCommercialChecklist);
        bool commercialChecklistReadable = commercialChecklistMentionsSurfaceActions && commercialChecklistMaxDisplayLineWidth <= 34f;
        bool beforeShowsMissingFiles = !before.readyForCollection &&
            before.hasMinimumDecisionCount &&
            !before.hasSurveyFiles &&
            !before.hasPlaytestPacketFiles &&
            !before.hasDiagnosticFiles;

        PlaytestSurveyExport survey = SavePlaytestSurveyFiles();
        yield return null;
        ExportLog();
        yield return null;
        WritePlaytestReadinessDiagnosticSample(survey.sessionId);
        UpdatePlaytestSurveyContent();
        yield return null;

        PlaytestCollectionReadiness after = BuildPlaytestCollectionReadiness();
        string afterSummary = playtestSurveySummaryText != null ? playtestSurveySummaryText.text : "";
        string afterStatus = playtestSurveyStatusText != null ? playtestSurveyStatusText.text : "";
        bool summaryMentionsReadiness = afterSummary.Contains("회수 준비") && afterSummary.Contains("회수 완료");
        bool statusMentionsReadiness = afterStatus.Contains("회수 준비") && afterStatus.Contains("회수 완료");
        bool completed = beforeMentionsReadiness &&
            beforeShowsMissingFiles &&
            after.readyForCollection &&
            after.hasMinimumDecisionCount &&
            after.hasSurveyFiles &&
            after.hasPlaytestPacketFiles &&
            after.hasDiagnosticFiles &&
