    private IEnumerator RunRecommendedReplaySmokeTest()
    {
        yield return null;

        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        campaignMandate = CampaignMandate.Standard;
        PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
        PlayerPrefs.Save();
        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        CampaignMandate originalMandate = campaignMandate;
        yield return PlayRecommendedUntilReport();
        yield return null;

        bool reportActive = reportRoot != null && reportRoot.gameObject.activeSelf;
        bool recommendationReady = hasPendingNextCampaignObjective;
        CampaignMandate expectedMandate = recommendationReady ? pendingNextCampaignObjective.mandate : campaignMandate;
        string expectedMandateName = CampaignMandateLabel(expectedMandate);
        string recommendationButtonLabel = recommendedCampaignButtonText != null ? recommendedCampaignButtonText.text : "";
        bool recommendationUsesDecisionAuditCoachingLabel =
            recommendationReady &&
            IsDecisionAuditCoachingObjective(pendingNextCampaignObjective) &&
            recommendationButtonLabel.Contains("복기") &&
            recommendationButtonLabel.Contains(DecisionAuditCoachingButtonPattern(pendingNextCampaignObjective)) &&
            pendingNextCampaignObjective.challenge.Contains("복기 목표") &&
            pendingNextCampaignObjective.reason.Contains("판단 복기");
        bool buttonMentionsExpectedMandate =
            recommendationButtonLabel.Contains(expectedMandateName) &&
            (recommendationButtonLabel.Contains("추천 심사") || recommendationUsesDecisionAuditCoachingLabel);
        bool recommendationDiffersFromCurrent = expectedMandate != originalMandate;

        StartRecommendedCampaign();
        yield return null;

        bool mandateApplied = campaignMandate == expectedMandate;
        bool budgetResetForMandate = budget == StartingBudgetForMandate(expectedMandate);
        bool campaignReset = currentIndex == 0 && logs.Count == 0 && incidentLogs.Count == 0 && !awaitingNext;
        bool tutorialVisible = tutorialRoot != null && tutorialRoot.gameObject.activeSelf && !reviewRoot.gameObject.activeSelf && !reportRoot.gameObject.activeSelf;
        bool preferenceSaved = PlayerPrefs.GetInt(CampaignMandatePrefsKey, -1) == (int)expectedMandate;
        bool completed = reportActive &&
            recommendationReady &&
            buttonMentionsExpectedMandate &&
            recommendationUsesDecisionAuditCoachingLabel &&
            recommendationDiffersFromCurrent &&
            mandateApplied &&
            budgetResetForMandate &&
            campaignReset &&
            tutorialVisible &&
            preferenceSaved;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_recommended_replay_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"reportActiveBeforeRestart\": {(reportActive ? "true" : "false")},\n" +
            $"  \"recommendationReady\": {(recommendationReady ? "true" : "false")},\n" +
            $"  \"buttonMentionsExpectedMandate\": {(buttonMentionsExpectedMandate ? "true" : "false")},\n" +
            $"  \"recommendationUsesDecisionAuditCoachingLabel\": {(recommendationUsesDecisionAuditCoachingLabel ? "true" : "false")},\n" +
            $"  \"recommendationDiffersFromCurrent\": {(recommendationDiffersFromCurrent ? "true" : "false")},\n" +
            $"  \"mandateApplied\": {(mandateApplied ? "true" : "false")},\n" +
            $"  \"budgetResetForMandate\": {(budgetResetForMandate ? "true" : "false")},\n" +
            $"  \"campaignReset\": {(campaignReset ? "true" : "false")},\n" +
            $"  \"tutorialVisible\": {(tutorialVisible ? "true" : "false")},\n" +
            $"  \"preferenceSaved\": {(preferenceSaved ? "true" : "false")},\n" +
            $"  \"originalMandateId\": \"{EscapeJson(CampaignMandateId(originalMandate))}\",\n" +
            $"  \"recommendedMandateId\": \"{EscapeJson(CampaignMandateId(expectedMandate))}\",\n" +
            $"  \"recommendedMandateName\": \"{EscapeJson(expectedMandateName)}\",\n" +
            $"  \"nextObjectiveChallenge\": \"{EscapeJson(recommendationReady ? pendingNextCampaignObjective.challenge : "")}\",\n" +
            $"  \"nextObjectiveReason\": \"{EscapeJson(recommendationReady ? pendingNextCampaignObjective.reason : "")}\",\n" +
            $"  \"startingBudget\": {StartingBudgetForMandate(expectedMandate)},\n" +
            $"  \"buttonLabel\": \"{EscapeJson(recommendationButtonLabel)}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        TryWriteProjectQaSmokeResult("care_review_recommended_replay_smoke_result.json", resultJson);
        campaignMandate = originalMandate;
        PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
        if (hadPreviousRecords)
        {
            PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
        }
        else
        {
            PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        }
        PlayerPrefs.Save();
        Debug.Log("CARE_REVIEW_RECOMMENDED_REPLAY_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " mandate=" + CampaignMandateId(expectedMandate));
        Application.Quit();
    }

    private IEnumerator RunDecisionAuditCoachingHudSmokeTest()
    {
        yield return null;

        CampaignMandate originalMandate = campaignMandate;
        bool hadPreviousRecords = PlayerPrefs.HasKey(CareerRecordPrefsKey);
        string previousRecords = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)CampaignMandate.Standard);
        PlayerPrefs.Save();
        campaignMandate = CampaignMandate.Standard;
        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);

        yield return PlayRecommendedUntilReport();
        yield return null;

        bool recommendationReady =
            hasPendingNextCampaignObjective &&
            IsDecisionAuditCoachingObjective(pendingNextCampaignObjective);
        string expectedChallenge = recommendationReady ? pendingNextCampaignObjective.challenge : "";
        string expectedPattern = recommendationReady ? DecisionAuditCoachingButtonPattern(pendingNextCampaignObjective) : "";
        string expectedReason = recommendationReady ? pendingNextCampaignObjective.reason : "";

        StartRecommendedCampaign();
        yield return null;

        string briefingText = tutorialBodyText != null ? tutorialBodyText.text : "";
        bool coachingStateApplied =
            currentCampaignStartedFromDecisionAuditCoachingObjective &&
            currentCampaignDecisionAuditCoachingChallenge.Contains("복기 목표") &&
            currentCampaignDecisionAuditCoachingPattern == expectedPattern &&
            currentCampaignDecisionAuditCoachingReason.Contains("판단 복기");
        bool briefingMentionsCoachingObjective =
            briefingText.Contains("판단 복기 목표") &&
            briefingText.Contains("패턴") &&
            briefingText.Contains("목표") &&
            briefingText.Contains(expectedPattern);

        BeginCampaignReview();
        yield return null;

        string initialHudText = regulationText != null ? regulationText.text : "";
        bool reviewHudMentionsCoachingObjective =
            initialHudText.Contains("판단 복기 진행") &&
            initialHudText.Contains(expectedPattern) &&
            initialHudText.Contains("처리 0/") &&
            initialHudText.Contains("복기 목표");

        Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
        yield return null;

        string afterDecisionHudText = regulationText != null ? regulationText.text : "";
        bool reviewHudUpdatesAfterDecision =
            afterDecisionHudText.Contains("판단 복기 진행") &&
            afterDecisionHudText.Contains("처리 1/") &&
            (afterDecisionHudText.Contains("고비용 지원") ||
                afterDecisionHudText.Contains("고위험 지연") ||
                afterDecisionHudText.Contains("권장 불일치") ||
                afterDecisionHudText.Contains("보정 재심사"));

        bool completed =
            recommendationReady &&
            coachingStateApplied &&
            briefingMentionsCoachingObjective &&
            reviewHudMentionsCoachingObjective &&
            reviewHudUpdatesAfterDecision;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_decision_audit_coaching_hud_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"recommendationReady\": {(recommendationReady ? "true" : "false")},\n" +
            $"  \"coachingStateApplied\": {(coachingStateApplied ? "true" : "false")},\n" +
            $"  \"briefingMentionsCoachingObjective\": {(briefingMentionsCoachingObjective ? "true" : "false")},\n" +
            $"  \"reviewHudMentionsCoachingObjective\": {(reviewHudMentionsCoachingObjective ? "true" : "false")},\n" +
            $"  \"reviewHudUpdatesAfterDecision\": {(reviewHudUpdatesAfterDecision ? "true" : "false")},\n" +
            $"  \"expectedPattern\": \"{EscapeJson(expectedPattern)}\",\n" +
            $"  \"expectedChallenge\": \"{EscapeJson(expectedChallenge)}\",\n" +
            $"  \"expectedReason\": \"{EscapeJson(expectedReason)}\",\n" +
            $"  \"initialHudPreview\": \"{EscapeJson(Shorten(initialHudText.Replace("\n", " / "), 260))}\",\n" +
            $"  \"afterDecisionHudPreview\": \"{EscapeJson(Shorten(afterDecisionHudText.Replace("\n", " / "), 260))}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        TryWriteProjectQaSmokeResult("care_review_decision_audit_coaching_hud_smoke_result.json", resultJson);
        campaignMandate = originalMandate;
        PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
        if (hadPreviousRecords)
        {
            PlayerPrefs.SetString(CareerRecordPrefsKey, previousRecords);
        }
        else
        {
            PlayerPrefs.DeleteKey(CareerRecordPrefsKey);
        }
        PlayerPrefs.Save();
        Debug.Log("CARE_REVIEW_DECISION_AUDIT_COACHING_HUD_SMOKE_RESULT path=" + resultPath + " completed=" + completed + " pattern=" + expectedPattern);
        Application.Quit();
    }

    private IEnumerator RunDecisionAuditSmokeTest()
    {
        yield return null;

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        int appealIndex = 0;
        for (int i = 0; i < cases.Count; i++)
        {
            if (cases[i].urgency >= 80 && cases[i].recommendedDecision != "거절")
            {
                appealIndex = i;
                break;
            }
        }

        ShowCase(0);
        int guard = cases.Count * 4 + 20;
        while (currentIndex < appealIndex && guard > 0)
        {
            if (dayTransitionRoot.gameObject.activeSelf)
            {
                ContinueAfterDayTransition();
                yield return null;
                guard--;
                continue;
            }

            if (!awaitingNext)
            {
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }

        string appealCaseId = currentIndex >= 0 && currentIndex < cases.Count ? cases[currentIndex].id : "";
        if (currentIndex < cases.Count)
        {
            Decide(DecisionKind.Reject);
            yield return null;
            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }
        }

        yield return PlayRecommendedUntilReport();
        ShowDecisionAudit();
        yield return null;

        string summaryText = decisionAuditSummaryText != null ? decisionAuditSummaryText.text : "";
        string queueText = decisionAuditQueueText != null ? decisionAuditQueueText.text : "";
        string coachingText = decisionAuditCoachingText != null ? decisionAuditCoachingText.text : "";
        bool hasDayRows = decisionAuditRowTexts != null && decisionAuditRowTexts.Length >= 5 &&
            decisionAuditRowTexts[0] != null &&
            decisionAuditRowTexts[0].text.Contains("1일차") &&
            decisionAuditRowTexts[4] != null &&
            decisionAuditRowTexts[4].text.Contains("5일차");
        bool hasBars = decisionAuditSpendFills != null && decisionAuditRiskFills != null && decisionAuditMatchFills != null &&
            decisionAuditSpendFills.Length >= 5 &&
            decisionAuditRiskFills.Length >= 5 &&
            decisionAuditMatchFills.Length >= 5;
        bool queueMentionsAppealPriority =
            queueText.Contains("이의제기 우선순위") &&
            queueText.Contains(appealCaseId) &&
            queueText.Contains("보정");
        bool queueMentionsAppealBeforeAfterGraph =
            queueText.Contains("보정 전/후 그래프") &&
            queueText.Contains("예산") &&
            queueText.Contains("위험") &&
            queueText.Contains("안정") &&
            queueText.Contains(appealCaseId);
        bool coachingMentionsNextRunStrategy =
            coachingText.Contains("다음 회차 복기") &&
            coachingText.Contains("핵심 패턴") &&
            coachingText.Contains("추천 운영") &&
            coachingText.Contains("실행 규칙") &&
            coachingText.Contains("검증 질문") &&
            coachingText.Contains("권장 일치율");
        bool coachingMentionsPatternSpecificNextObjective =
            coachingText.Contains("다음 목표: 복기 목표") &&
            coachingText.Contains("버튼 라벨: 복기") &&
            coachingText.Contains("시작:") &&
            coachingText.Contains("추천 운영");
        RectTransform coachingBoxRect = decisionAuditCoachingText != null && decisionAuditCoachingText.transform.parent != null
            ? decisionAuditCoachingText.transform.parent.GetComponent<RectTransform>()
            : null;
        bool coachingCardInsideReportPaper =
            coachingBoxRect != null &&
            coachingBoxRect.anchoredPosition.x > -20f &&
            coachingBoxRect.anchoredPosition.x < 360f &&
            coachingBoxRect.anchoredPosition.y < -150f &&
            coachingBoxRect.sizeDelta.x <= 360f;
        bool completed = decisionAuditRoot != null &&
            decisionAuditRoot.gameObject.activeSelf &&
            logs.Count == cases.Count &&
            summaryText.Contains("판단 복기") &&
            summaryText.Contains("권장 일치") &&
            queueText.Contains("고압력 결정") &&
            queueText.Contains("대표 복기 사례") &&
            queueMentionsAppealPriority &&
            queueMentionsAppealBeforeAfterGraph &&
            coachingMentionsNextRunStrategy &&
            coachingMentionsPatternSpecificNextObjective &&
            coachingCardInsideReportPaper &&
            hasDayRows &&
            hasBars;

        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_decision_audit_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"caseCount\": {cases.Count},\n" +
            $"  \"logCount\": {logs.Count},\n" +
            $"  \"auditRootActive\": {(decisionAuditRoot != null && decisionAuditRoot.gameObject.activeSelf ? "true" : "false")},\n" +
            $"  \"summaryMentionsAudit\": {(summaryText.Contains("판단 복기") ? "true" : "false")},\n" +
            $"  \"queueMentionsPressure\": {(queueText.Contains("고압력 결정") ? "true" : "false")},\n" +
            $"  \"queueMentionsAppealPriority\": {(queueMentionsAppealPriority ? "true" : "false")},\n" +
            $"  \"queueMentionsAppealBeforeAfterGraph\": {(queueMentionsAppealBeforeAfterGraph ? "true" : "false")},\n" +
            $"  \"coachingMentionsNextRunStrategy\": {(coachingMentionsNextRunStrategy ? "true" : "false")},\n" +
            $"  \"coachingMentionsPatternSpecificNextObjective\": {(coachingMentionsPatternSpecificNextObjective ? "true" : "false")},\n" +
            $"  \"coachingCardInsideReportPaper\": {(coachingCardInsideReportPaper ? "true" : "false")},\n" +
            $"  \"appealCaseId\": \"{EscapeJson(appealCaseId)}\",\n" +
            $"  \"queuePreview\": \"{EscapeJson(Shorten(queueText.Replace("\n", " / "), 320))}\",\n" +
            $"  \"coachingPreview\": \"{EscapeJson(Shorten(coachingText.Replace("\n", " / "), 320))}\",\n" +
            $"  \"hasDayRows\": {(hasDayRows ? "true" : "false")},\n" +
            $"  \"hasBars\": {(hasBars ? "true" : "false")}\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        TryWriteProjectQaSmokeResult("care_review_decision_audit_smoke_result.json", resultJson);
        Debug.Log("CARE_REVIEW_DECISION_AUDIT_SMOKE_RESULT path=" + resultPath + " completed=" + completed);
        Application.Quit();
    }

#if CARE_REVIEW_QA_TOOLS
    private IEnumerator CreateAutomatedPlaytestSession(CampaignMandate mandate)
    {
        campaignMandate = mandate;
        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
