        playtestSurveyRatings[3] = 4;
        playtestSurveyRatings[4] = mandate == CampaignMandate.SupportExpanded ? 5 : 4;
        playtestSurveyRatings[5] = 4;
        Array.Clear(playtestSurveyFlags, 0, playtestSurveyFlags.Length);
        playtestSurveyFlags[3] = true;
        SavePlaytestSurveyFiles();
        ExportLog();
        yield return null;
    }
