    private IEnumerator RunAudioSmokeTest()
    {
        yield return null;

        bool clickPlayed = PlaySfx(buttonClickClip, 0.6f);
        bool approvePlayed = PlaySfx(approveClip, 0.4f);

        ShowMainMenu();
        string menuBgmKey = currentBgmKey;
        if (cases.Count > 0)
        {
            ShowCase(0);
        }
        string reviewBgmKey = currentBgmKey;
        ShowPolicyHandbook();
        string policyBgmKey = currentBgmKey;
        ShowReportDashboard();
        string reportBgmKey = currentBgmKey;
        ShowEndingGallery();
        string endingBgmKey = currentBgmKey;

        int previousVolumeLevel = volumeLevel;
        volumeLevel = 0;
        ApplyAudioSettings();
        bool zeroVolumeSfxPlayed = PlaySfx(buttonClickClip, 0.6f);
        bool zeroVolumeMusicMuted = musicSource == null || Mathf.Approximately(musicSource.volume, 0f);
        volumeLevel = previousVolumeLevel;
        ApplyAudioSettings();

        string bgmSamplesJson = BuildAudioResourceSamplesJson(AudioBgmResourcePrefix, RequiredBgmKeys, out int loadedBgmCount, out bool allBgmHaveSamples);
        string sfxSamplesJson = BuildAudioResourceSamplesJson(AudioSfxResourcePrefix, RequiredSfxKeys, out int loadedSfxCount, out bool allSfxHaveSamples);
        bool screenBgmKeysExpected =
            menuBgmKey == MenuBgmKey &&
            reviewBgmKey == ReviewBgmKey &&
            policyBgmKey == PolicyBgmKey &&
            reportBgmKey == ReportBgmKey &&
            endingBgmKey == EndingBgmKey;
        bool completed =
            FindFirstObjectByType<AudioListener>() != null &&
            sfxSource != null &&
            musicSource != null &&
            loadedBgmCount == RequiredBgmKeys.Length &&
            loadedSfxCount == RequiredSfxKeys.Length &&
            allBgmHaveSamples &&
            allSfxHaveSamples &&
            screenBgmKeysExpected &&
            !zeroVolumeSfxPlayed &&
            zeroVolumeMusicMuted;
        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_audio_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"hasListener\": {(FindFirstObjectByType<AudioListener>() != null ? "true" : "false")},\n" +
            $"  \"hasSfxSource\": {(sfxSource != null ? "true" : "false")},\n" +
            $"  \"hasMusicSource\": {(musicSource != null ? "true" : "false")},\n" +
            $"  \"loadedBgmCount\": {loadedBgmCount},\n" +
            $"  \"requiredBgmCount\": {RequiredBgmKeys.Length},\n" +
            $"  \"loadedSfxCount\": {loadedSfxCount},\n" +
            $"  \"requiredSfxCount\": {RequiredSfxKeys.Length},\n" +
            $"  \"allBgmHaveSamples\": {(allBgmHaveSamples ? "true" : "false")},\n" +
            $"  \"allSfxHaveSamples\": {(allSfxHaveSamples ? "true" : "false")},\n" +
            $"  \"buttonSamples\": {ClipSamples(buttonClickClip)},\n" +
            $"  \"approveSamples\": {ClipSamples(approveClip)},\n" +
            $"  \"rejectSamples\": {ClipSamples(rejectClip)},\n" +
            $"  \"incidentMinorSamples\": {ClipSamples(incidentMinorClip)},\n" +
            $"  \"incidentMajorSamples\": {ClipSamples(incidentMajorClip)},\n" +
            $"  \"incidentCriticalSamples\": {ClipSamples(incidentCriticalClip)},\n" +
            $"  \"fallbackMusicSamples\": {ClipSamples(fallbackMusicClip)},\n" +
            $"  \"initialClickPlayed\": {(clickPlayed ? "true" : "false")},\n" +
            $"  \"initialApprovePlayed\": {(approvePlayed ? "true" : "false")},\n" +
            $"  \"zeroVolumeSfxPlayed\": {(zeroVolumeSfxPlayed ? "true" : "false")},\n" +
            $"  \"zeroVolumeMusicMuted\": {(zeroVolumeMusicMuted ? "true" : "false")},\n" +
            $"  \"screenBgmKeysExpected\": {(screenBgmKeysExpected ? "true" : "false")},\n" +
            $"  \"menuBgmKey\": \"{EscapeJson(menuBgmKey)}\",\n" +
            $"  \"reviewBgmKey\": \"{EscapeJson(reviewBgmKey)}\",\n" +
            $"  \"policyBgmKey\": \"{EscapeJson(policyBgmKey)}\",\n" +
            $"  \"reportBgmKey\": \"{EscapeJson(reportBgmKey)}\",\n" +
            $"  \"endingBgmKey\": \"{EscapeJson(endingBgmKey)}\",\n" +
