    private static string CurrentSelectedObjectName()
    {
        EventSystem current = EventSystem.current;
        GameObject selected = current != null ? current.currentSelectedGameObject : null;
        if (selected == null)
        {
            return "";
        }

        Text label = selected.GetComponentInChildren<Text>(true);
        return label != null && !string.IsNullOrWhiteSpace(label.text)
            ? label.text
            : selected.name;
    }

    private static bool FocusButtonAndVerify(RectTransform root, Button button)
    {
        EventSystem current = EventSystem.current;
        if (root == null ||
            current == null ||
            button == null ||
            !button.interactable ||
            !button.gameObject.activeInHierarchy)
        {
            return false;
        }

        current.SetSelectedGameObject(button.gameObject);
        return ActiveRootContainsSelection(root) && CurrentSelectionHasFocusHighlight();
    }

    private static bool FocusActiveButtonsAndVerify(RectTransform root, Button[] buttons, out int focusedCount)
    {
        focusedCount = 0;
        if (buttons == null)
        {
            return false;
        }

        bool allFocused = true;
        for (int i = 0; i < buttons.Length; i++)
        {
            Button button = buttons[i];
            if (button == null || !button.interactable || !button.gameObject.activeInHierarchy)
            {
                continue;
            }

            focusedCount++;
            allFocused &= FocusButtonAndVerify(root, button);
        }

        return focusedCount > 0 && allFocused;
    }

    private static bool SelectionIsOneOf(Button[] buttons)
    {
        EventSystem current = EventSystem.current;
        GameObject selected = current != null ? current.currentSelectedGameObject : null;
        if (selected == null || buttons == null)
        {
            return false;
        }

        for (int i = 0; i < buttons.Length; i++)
        {
            if (buttons[i] != null && buttons[i].gameObject == selected)
            {
                return true;
            }
        }

        return false;
    }

    private enum NavigationDirection
    {
        Left,
        Right,
        Up,
        Down
    }

    private static bool NavigationRightChainMatches(Button[] buttons)
    {
        if (buttons == null || buttons.Length < 2)
        {
            return false;
        }

        for (int i = 0; i + 1 < buttons.Length; i++)
        {
            if (!NavigationTargetIs(buttons[i], NavigationDirection.Right, buttons[i + 1]) ||
                !NavigationTargetIs(buttons[i + 1], NavigationDirection.Left, buttons[i]))
            {
                return false;
            }
        }

        return true;
    }

    private static bool NavigationTargetIs(Button source, NavigationDirection direction, Selectable expected)
    {
        if (source == null || expected == null)
        {
            return false;
        }

        Navigation navigation = source.navigation;
        if (navigation.mode != Navigation.Mode.Explicit)
        {
            return false;
        }

        Selectable actual = direction switch
        {
            NavigationDirection.Left => navigation.selectOnLeft,
            NavigationDirection.Right => navigation.selectOnRight,
            NavigationDirection.Up => navigation.selectOnUp,
            NavigationDirection.Down => navigation.selectOnDown,
            _ => null
        };

        return actual == expected;
    }

    private static bool RectHasPositiveSize(RectTransform rect)
    {
        return rect != null && rect.rect.width > 1f && rect.rect.height > 1f;
    }

    private static string RectSnapshot(RectTransform rect)
    {
        if (rect == null)
        {
            return "";
        }

        Vector2 center = rect.anchoredPosition;
        Vector2 size = rect.rect.size;
        return $"center=({center.x:0.0},{center.y:0.0}) size=({size.x:0.0},{size.y:0.0})";
    }

    private static int ClipSamples(AudioClip clip)
    {
        return clip != null ? clip.samples : 0;
    }

    private static string BuildAudioResourceSamplesJson(string resourcePrefix, string[] keys, out int loadedCount, out bool allHaveSamples)
    {
        StringBuilder builder = new();
        builder.Append("[");
        loadedCount = 0;
        allHaveSamples = true;
        for (int i = 0; i < keys.Length; i++)
        {
            string key = keys[i];
            AudioClip clip = Resources.Load<AudioClip>(resourcePrefix + key);
            int samples = ClipSamples(clip);
            bool loaded = clip != null;
            loadedCount += loaded ? 1 : 0;
            allHaveSamples &= loaded && samples > 0;
            if (i > 0)
            {
                builder.Append(",");
            }

            builder.Append("{");
            builder.Append($"\"key\":\"{EscapeJson(key)}\",");
            builder.Append($"\"loaded\":{(loaded ? "true" : "false")},");
            builder.Append($"\"samples\":{samples},");
            builder.Append($"\"channels\":{(clip != null ? clip.channels : 0)},");
            builder.Append($"\"frequency\":{(clip != null ? clip.frequency : 0)}");
            builder.Append("}");
        }

        builder.Append("]");
        return builder.ToString();
    }

    private static DecisionKind DecisionKindFromLabel(string decision)
    {
        return decision switch
        {
            "승인" => DecisionKind.Approve,
            "조건부 승인" => DecisionKind.Conditional,
            "추가조사" => DecisionKind.Investigate,
            "거절" => DecisionKind.Reject,
            _ => DecisionKind.Hold
        };
    }

    private void WriteSmokeTestResult(bool completedWithinGuard)
    {
        int highestDay = 0;
        for (int i = 0; i < cases.Count; i++)
        {
            highestDay = Mathf.Max(highestDay, cases[i].day);
        }

        EndingOutcome ending = BuildEndingOutcome();
        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_smoke_result.json");
        string resultJson =
            "{\n" +
            $"  \"completed\": {(completedWithinGuard && currentIndex >= cases.Count ? "true" : "false")},\n" +
            $"  \"caseCount\": {cases.Count},\n" +
            $"  \"logCount\": {logs.Count},\n" +
            $"  \"highestDay\": {highestDay},\n" +
            $"  \"campaignMandateId\": \"{EscapeJson(CampaignMandateId(campaignMandate))}\",\n" +
            $"  \"campaignMandateName\": \"{EscapeJson(CampaignMandateLabel(campaignMandate))}\",\n" +
            $"  \"currentIndex\": {currentIndex},\n" +
            $"  \"budget\": {budget},\n" +
            $"  \"stability\": {stability},\n" +
            $"  \"equity\": {equity},\n" +
            $"  \"missedRisk\": {missedRisk},\n" +
            $"  \"complaints\": {complaints},\n" +
            $"  \"incidentCount\": {incidentLogs.Count},\n" +
            $"  \"endingId\": \"{EscapeJson(ending.id)}\",\n" +
            $"  \"endingTitle\": \"{EscapeJson(ending.title)}\"\n" +
            "}\n";
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log($"CARE_REVIEW_SMOKE_RESULT path={resultPath} cases={cases.Count} logs={logs.Count} highestDay={highestDay}");
    }

    private IEnumerator RunSaveSlotDeleteSmokeTest()
    {
        yield return null;

        int previousSlot = activeSaveSlot;
        int testSlot = MaxSaveSlots;
        string testPath = SavePathForSlot(testSlot);
        string saveBackupPath = SaveBackupPathForSlot(testSlot);
        string originalSaveBackupPath = testPath + ".delete_smoke_backup";
        string originalBakBackupPath = saveBackupPath + ".delete_smoke_backup";
        bool hadExistingSave = File.Exists(testPath);
        bool hadExistingBackup = File.Exists(saveBackupPath);
        bool backupCreated = false;
        bool saveBackupCreated = false;
        bool saveCreated = false;
        bool saveBackupGenerated = false;
        bool continueBeforeDelete = false;
        bool confirmationArmed = false;
        bool saveDeleted = false;
        bool saveBackupDeleted = false;
        bool continueAfterDelete = false;
        string labelAfterFirstClick = "";
        string labelAfterSecondClick = "";
        string statusAfterDelete = "";

        try
        {
            if (File.Exists(originalSaveBackupPath))
            {
                File.Delete(originalSaveBackupPath);
            }

            if (File.Exists(originalBakBackupPath))
            {
                File.Delete(originalBakBackupPath);
            }

            if (hadExistingSave)
            {
                File.Copy(testPath, originalSaveBackupPath, true);
                backupCreated = File.Exists(originalSaveBackupPath);
            }

            if (hadExistingBackup)
            {
                File.Copy(saveBackupPath, originalBakBackupPath, true);
                saveBackupCreated = File.Exists(originalBakBackupPath);
            }

            activeSaveSlot = testSlot;
            PlayerPrefs.SetInt(SaveSlotPrefsKey, activeSaveSlot);
            PlayerPrefs.Save();

            if (File.Exists(testPath))
            {
                File.Delete(testPath);
            }
            if (File.Exists(saveBackupPath))
            {
                File.Delete(saveBackupPath);
            }

            ResetCampaignState();
            SaveSession(false);
            budget -= 10;
            SaveSession(false);
            ShowMainMenu();
            saveCreated = File.Exists(testPath);
            saveBackupGenerated = File.Exists(saveBackupPath);
            continueBeforeDelete = continueButton != null && continueButton.interactable;

            RequestDeleteSaveSlot();
            labelAfterFirstClick = deleteSaveSlotButtonText != null ? deleteSaveSlotButtonText.text : "";
            confirmationArmed = pendingDeleteSlot == testSlot && File.Exists(testPath) && File.Exists(saveBackupPath);

            RequestDeleteSaveSlot();
            labelAfterSecondClick = deleteSaveSlotButtonText != null ? deleteSaveSlotButtonText.text : "";
            statusAfterDelete = menuStatusText != null ? menuStatusText.text : "";
            saveDeleted = !File.Exists(testPath);
            saveBackupDeleted = !File.Exists(saveBackupPath);
            continueAfterDelete = continueButton != null && !continueButton.interactable;

            string resultPath = Path.Combine(Application.persistentDataPath, "care_review_save_slot_delete_smoke_result.json");
            string resultJson =
                "{\n" +
                $"  \"testSlot\": {testSlot},\n" +
                $"  \"hadExistingSave\": {(hadExistingSave ? "true" : "false")},\n" +
                $"  \"hadExistingBackup\": {(hadExistingBackup ? "true" : "false")},\n" +
                $"  \"backupCreated\": {(backupCreated ? "true" : "false")},\n" +
                $"  \"saveBackupCreated\": {(saveBackupCreated ? "true" : "false")},\n" +
                $"  \"saveCreated\": {(saveCreated ? "true" : "false")},\n" +
                $"  \"saveBackupGenerated\": {(saveBackupGenerated ? "true" : "false")},\n" +
                $"  \"continueBeforeDelete\": {(continueBeforeDelete ? "true" : "false")},\n" +
                $"  \"confirmationArmed\": {(confirmationArmed ? "true" : "false")},\n" +
                $"  \"saveDeleted\": {(saveDeleted ? "true" : "false")},\n" +
                $"  \"saveBackupDeleted\": {(saveBackupDeleted ? "true" : "false")},\n" +
                $"  \"continueAfterDelete\": {(continueAfterDelete ? "true" : "false")},\n" +
                $"  \"labelAfterFirstClick\": \"{EscapeJson(labelAfterFirstClick)}\",\n" +
                $"  \"labelAfterSecondClick\": \"{EscapeJson(labelAfterSecondClick)}\",\n" +
                $"  \"statusAfterDelete\": \"{EscapeJson(statusAfterDelete)}\"\n" +
                "}\n";
            File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
            Debug.Log("CARE_REVIEW_SAVE_SLOT_DELETE_SMOKE_RESULT path=" + resultPath + " deleted=" + saveDeleted + " restored=" + hadExistingSave);
        }
        finally
        {
            if (hadExistingSave && File.Exists(originalSaveBackupPath))
            {
                File.Copy(originalSaveBackupPath, testPath, true);
            }
            else if (!hadExistingSave && File.Exists(testPath))
            {
                File.Delete(testPath);
            }

            if (hadExistingBackup && File.Exists(originalBakBackupPath))
            {
                File.Copy(originalBakBackupPath, saveBackupPath, true);
            }
            else if (!hadExistingBackup && File.Exists(saveBackupPath))
            {
                File.Delete(saveBackupPath);
            }

            if (File.Exists(originalSaveBackupPath))
            {
                File.Delete(originalSaveBackupPath);
            }

            if (File.Exists(originalBakBackupPath))
            {
                File.Delete(originalBakBackupPath);
            }

            activeSaveSlot = Mathf.Clamp(previousSlot, 1, MaxSaveSlots);
            pendingDeleteSlot = -1;
            PlayerPrefs.SetInt(SaveSlotPrefsKey, activeSaveSlot);
            PlayerPrefs.Save();
            UpdateMenuStatus();
        }

        Application.Quit();
    }

    private IEnumerator RunSaveRecoverySmokeTest()
    {
        yield return null;

        int previousSlot = activeSaveSlot;
        int testSlot = Mathf.Max(1, MaxSaveSlots - 1);
        string primaryPath = SavePathForSlot(testSlot);
        string backupPath = SaveBackupPathForSlot(testSlot);
        string tempPath = SaveTempPathForSlot(testSlot);
        string originalPrimaryPath = primaryPath + ".save_recovery_original";
        string originalBackupPath = backupPath + ".save_recovery_original";
        string testSlotCandidatePrefsKey = AppealRemedyTriageCandidatePrefsKeyForSlot(testSlot);
        bool hadExistingPrimary = File.Exists(primaryPath);
        bool hadExistingBackup = File.Exists(backupPath);
        bool hadCandidatePreference = PlayerPrefs.HasKey(testSlotCandidatePrefsKey);
        int previousCandidatePreference = PlayerPrefs.GetInt(testSlotCandidatePrefsKey, 0);
        bool originalPrimaryBackedUp = false;
        bool originalBackupBackedUp = false;
        bool firstSaveWritten = false;
        bool backupCreated = false;
        bool secondSaveWritten = false;
        bool corruptedPrimaryRejected = false;
        bool recoveredFromBackup = false;
        bool primaryRestored = false;
        bool backupPreserved = false;
        bool versionCurrent = false;
        bool firstSaveStoresAppealTriageCandidate = false;
        bool secondSaveStoresAppealTriageCandidate = false;
        bool restoredAppealTriageCandidate = false;
        bool slotPreferenceRestoredAppealTriageCandidate = false;
        int restoredAppealTriageCandidateIndex = -1;
        string error = "";

        try
        {
            DeleteFileIfExists(originalPrimaryPath);
            DeleteFileIfExists(originalBackupPath);
            DeleteFileIfExists(tempPath);

            if (hadExistingPrimary)
            {
                File.Copy(primaryPath, originalPrimaryPath, true);
                originalPrimaryBackedUp = File.Exists(originalPrimaryPath);
            }

            if (hadExistingBackup)
            {
                File.Copy(backupPath, originalBackupPath, true);
                originalBackupBackedUp = File.Exists(originalBackupPath);
            }

            DeleteFileIfExists(primaryPath);
            DeleteFileIfExists(backupPath);

            activeSaveSlot = testSlot;
            PlayerPrefs.SetInt(SaveSlotPrefsKey, activeSaveSlot);
            PlayerPrefs.Save();

            campaignMandate = CampaignMandate.Standard;
            ResetCampaignState();
            int expectedRecoveredBudget = budget;
            int expectedRecoveredTriageCandidateIndex = 1;
            appealRemedyGraphTriageCandidateIndex = expectedRecoveredTriageCandidateIndex;
            PersistAppealRemedyGraphTriageCandidateIndex();
            SaveSession(false);
            firstSaveWritten = TryReadSaveDataFile(primaryPath, out SaveData firstSave, out error) &&
                firstSave.version == SaveDataVersion &&
                firstSave.budget == expectedRecoveredBudget;
            firstSaveStoresAppealTriageCandidate =
                firstSaveWritten &&
                firstSave.appealRemedyGraphTriageCandidateIndex == expectedRecoveredTriageCandidateIndex;

            budget = expectedRecoveredBudget - 77;
            stability += 4;
            appealRemedyGraphTriageCandidateIndex = 0;
            PersistAppealRemedyGraphTriageCandidateIndex();
            SaveSession(false);
            backupCreated = TryReadSaveDataFile(backupPath, out SaveData backupSave, out error) &&
                backupSave.version == SaveDataVersion &&
                backupSave.budget == expectedRecoveredBudget;
            secondSaveWritten = TryReadSaveDataFile(primaryPath, out SaveData secondSave, out error) &&
                secondSave.version == SaveDataVersion &&
                secondSave.budget == expectedRecoveredBudget - 77;
            secondSaveStoresAppealTriageCandidate =
                secondSaveWritten &&
                secondSave.appealRemedyGraphTriageCandidateIndex == 0 &&
                backupSave.appealRemedyGraphTriageCandidateIndex == expectedRecoveredTriageCandidateIndex;

            File.WriteAllText(primaryPath, "{ broken save", Encoding.UTF8);
            corruptedPrimaryRejected = !TryReadSaveDataFile(primaryPath, out _, out _);
            recoveredFromBackup = LoadSession() && budget == expectedRecoveredBudget;
            restoredAppealTriageCandidateIndex = appealRemedyGraphTriageCandidateIndex;
            restoredAppealTriageCandidate = recoveredFromBackup &&
                restoredAppealTriageCandidateIndex == expectedRecoveredTriageCandidateIndex;
            slotPreferenceRestoredAppealTriageCandidate =
                PlayerPrefs.GetInt(testSlotCandidatePrefsKey, -1) == expectedRecoveredTriageCandidateIndex;
            primaryRestored = TryReadSaveDataFile(primaryPath, out SaveData restoredSave, out error) &&
                restoredSave.version == SaveDataVersion &&
                restoredSave.budget == expectedRecoveredBudget &&
                restoredSave.appealRemedyGraphTriageCandidateIndex == expectedRecoveredTriageCandidateIndex;
            backupPreserved = TryReadSaveDataFile(backupPath, out SaveData preservedBackup, out error) &&
                preservedBackup.version == SaveDataVersion &&
                preservedBackup.budget == expectedRecoveredBudget &&
                preservedBackup.appealRemedyGraphTriageCandidateIndex == expectedRecoveredTriageCandidateIndex;
            versionCurrent = primaryRestored && restoredSave.version == SaveDataVersion;
        }
        catch (Exception exception)
        {
            error = exception.GetType().Name + ": " + exception.Message;
        }
        finally
        {
            if (hadExistingPrimary && File.Exists(originalPrimaryPath))
            {
                File.Copy(originalPrimaryPath, primaryPath, true);
            }
            else if (!hadExistingPrimary)
            {
                DeleteFileIfExists(primaryPath);
            }

            if (hadExistingBackup && File.Exists(originalBackupPath))
            {
                File.Copy(originalBackupPath, backupPath, true);
            }
            else if (!hadExistingBackup)
            {
                DeleteFileIfExists(backupPath);
            }

            DeleteFileIfExists(tempPath);
            DeleteFileIfExists(originalPrimaryPath);
            DeleteFileIfExists(originalBackupPath);

            activeSaveSlot = Mathf.Clamp(previousSlot, 1, MaxSaveSlots);
            if (hadCandidatePreference)
            {
                PlayerPrefs.SetInt(testSlotCandidatePrefsKey, previousCandidatePreference);
            }
            else
            {
                PlayerPrefs.DeleteKey(testSlotCandidatePrefsKey);
            }

            PlayerPrefs.SetInt(SaveSlotPrefsKey, activeSaveSlot);
            PlayerPrefs.Save();
            appealRemedyGraphTriageCandidateIndex = LoadAppealRemedyGraphTriageCandidateIndexForSlot(activeSaveSlot);
            ResetCampaignState();
            UpdateMenuStatus();
        }

        string resultBody =
            "{\n" +
            $"  \"completed\": {(firstSaveWritten && backupCreated && secondSaveWritten && corruptedPrimaryRejected && recoveredFromBackup && primaryRestored && backupPreserved && versionCurrent && firstSaveStoresAppealTriageCandidate && secondSaveStoresAppealTriageCandidate && restoredAppealTriageCandidate && slotPreferenceRestoredAppealTriageCandidate ? "true" : "false")},\n" +
            $"  \"testSlot\": {testSlot},\n" +
            $"  \"saveDataVersion\": {SaveDataVersion},\n" +
            $"  \"hadExistingPrimary\": {(hadExistingPrimary ? "true" : "false")},\n" +
            $"  \"hadExistingBackup\": {(hadExistingBackup ? "true" : "false")},\n" +
            $"  \"originalPrimaryBackedUp\": {(originalPrimaryBackedUp ? "true" : "false")},\n" +
            $"  \"originalBackupBackedUp\": {(originalBackupBackedUp ? "true" : "false")},\n" +
            $"  \"firstSaveWritten\": {(firstSaveWritten ? "true" : "false")},\n" +
            $"  \"backupCreated\": {(backupCreated ? "true" : "false")},\n" +
            $"  \"secondSaveWritten\": {(secondSaveWritten ? "true" : "false")},\n" +
            $"  \"corruptedPrimaryRejected\": {(corruptedPrimaryRejected ? "true" : "false")},\n" +
            $"  \"recoveredFromBackup\": {(recoveredFromBackup ? "true" : "false")},\n" +
            $"  \"primaryRestored\": {(primaryRestored ? "true" : "false")},\n" +
            $"  \"backupPreserved\": {(backupPreserved ? "true" : "false")},\n" +
            $"  \"versionCurrent\": {(versionCurrent ? "true" : "false")},\n" +
            $"  \"firstSaveStoresAppealTriageCandidate\": {(firstSaveStoresAppealTriageCandidate ? "true" : "false")},\n" +
            $"  \"secondSaveStoresAppealTriageCandidate\": {(secondSaveStoresAppealTriageCandidate ? "true" : "false")},\n" +
            $"  \"restoredAppealTriageCandidate\": {(restoredAppealTriageCandidate ? "true" : "false")},\n" +
            $"  \"slotPreferenceRestoredAppealTriageCandidate\": {(slotPreferenceRestoredAppealTriageCandidate ? "true" : "false")},\n" +
            $"  \"restoredAppealTriageCandidateIndex\": {restoredAppealTriageCandidateIndex},\n" +
            $"  \"primaryFile\": \"{EscapeJson(Path.GetFileName(primaryPath))}\",\n" +
            $"  \"backupFile\": \"{EscapeJson(Path.GetFileName(backupPath))}\",\n" +
            $"  \"error\": \"{EscapeJson(error)}\",\n";
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(resultBody);
        string resultJson = resultBody +
            $"  \"filesHaveNoLocalAbsolutePath\": {(filesHaveNoLocalAbsolutePath ? "true" : "false")}\n" +
            "}\n";
        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_save_recovery_smoke_result.json");
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        TryWriteProjectQaSmokeResult("care_review_save_recovery_smoke_result.json", resultJson);
        Debug.Log("CARE_REVIEW_SAVE_RECOVERY_SMOKE_RESULT path=" + resultPath + " recovered=" + recoveredFromBackup + " primaryRestored=" + primaryRestored);

        Application.Quit();
    }

    private IEnumerator RunLocalDataDeleteSmokeTest()
    {
        yield return null;

        string tempRoot = Path.Combine(LogDirectory, "local_data_delete_smoke_v030");
        string savePath = Path.Combine(tempRoot, SaveFileNameForSlot(1));
        string saveBackupPath = Path.Combine(tempRoot, SaveBackupFileNameForSlot(1));
        string playLogPath = Path.Combine(tempRoot, "care_review_play_log.json");
        string dashboardPath = Path.Combine(tempRoot, "care_review_analytics_dashboard.html");
        string unrelatedPath = Path.Combine(tempRoot, "keep_me.txt");
        string sessionDirectory = Path.Combine(tempRoot, "playtest_sessions", "session_smoke");
        string bundleDirectory = Path.Combine(tempRoot, "support_bundles", "bundle_smoke");
        string lowResolutionDirectory = Path.Combine(tempRoot, "low_resolution_ui_v030");

        bool confirmationArmed = false;
        string labelAfterFirstClick = "";
        string statusAfterFirstClick = "";
        LocalDataCleanupResult result = new();
        bool managedFilesDeleted = false;
        bool managedDirectoriesDeleted = false;
        bool unrelatedFilePreserved = false;

        try
        {
            if (Directory.Exists(tempRoot))
            {
                Directory.Delete(tempRoot, true);
            }

            Directory.CreateDirectory(tempRoot);
            Directory.CreateDirectory(sessionDirectory);
            Directory.CreateDirectory(bundleDirectory);
            Directory.CreateDirectory(lowResolutionDirectory);
            File.WriteAllText(savePath, "{}", Encoding.UTF8);
            File.WriteAllText(saveBackupPath, "{}", Encoding.UTF8);
            File.WriteAllText(playLogPath, "{}", Encoding.UTF8);
            File.WriteAllText(dashboardPath, "<html></html>", Encoding.UTF8);
            File.WriteAllText(Path.Combine(sessionDirectory, "care_review_play_log.json"), "{}", Encoding.UTF8);
            File.WriteAllText(Path.Combine(bundleDirectory, "manifest.json"), "{}", Encoding.UTF8);
            File.WriteAllText(Path.Combine(lowResolutionDirectory, "settings.png"), "png", Encoding.UTF8);
            File.WriteAllText(unrelatedPath, "preserve", Encoding.UTF8);

            ShowSettings();
            RequestClearLocalData();
            labelAfterFirstClick = clearLocalDataButtonText != null ? clearLocalDataButtonText.text : "";
            statusAfterFirstClick = settingsStatusText != null ? settingsStatusText.text : "";
            confirmationArmed = pendingClearLocalData &&
                labelAfterFirstClick.Contains("확인") &&
                statusAfterFirstClick.Contains("다시 누르면");
            pendingClearLocalData = false;
            UpdateClearLocalDataButton();

            result = ClearLocalDataAtPath(tempRoot, false);
            managedFilesDeleted = !File.Exists(savePath) && !File.Exists(saveBackupPath) && !File.Exists(playLogPath) && !File.Exists(dashboardPath);
            managedDirectoriesDeleted = !Directory.Exists(Path.Combine(tempRoot, "playtest_sessions")) &&
                !Directory.Exists(Path.Combine(tempRoot, "support_bundles")) &&
                !Directory.Exists(lowResolutionDirectory);
            unrelatedFilePreserved = File.Exists(unrelatedPath);
        }
        finally
        {
            if (Directory.Exists(tempRoot))
            {
                Directory.Delete(tempRoot, true);
            }
        }

        string resultBody =
            "{\n" +
            $"  \"completed\": {(result.completed && confirmationArmed && managedFilesDeleted && managedDirectoriesDeleted && unrelatedFilePreserved ? "true" : "false")},\n" +
            $"  \"confirmationArmed\": {(confirmationArmed ? "true" : "false")},\n" +
            $"  \"rootPathSafe\": {(result.rootPathSafe ? "true" : "false")},\n" +
            $"  \"managedFilesDeleted\": {(managedFilesDeleted ? "true" : "false")},\n" +
            $"  \"managedDirectoriesDeleted\": {(managedDirectoriesDeleted ? "true" : "false")},\n" +
            $"  \"unrelatedFilePreserved\": {(unrelatedFilePreserved ? "true" : "false")},\n" +
            $"  \"deleteFailureCount\": {result.deleteFailureCount},\n" +
            $"  \"filesDeleted\": {result.filesDeleted},\n" +
            $"  \"directoriesDeleted\": {result.directoriesDeleted},\n" +
            $"  \"playerPrefsDeleted\": {result.playerPrefsDeleted},\n" +
            $"  \"labelAfterFirstClick\": \"{EscapeJson(labelAfterFirstClick)}\",\n" +
            $"  \"relativeSmokeRoot\": \"local_data_delete_smoke_v030\",\n";
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(resultBody);
        string resultJson = resultBody +
            $"  \"filesHaveNoLocalAbsolutePath\": {(filesHaveNoLocalAbsolutePath ? "true" : "false")}\n" +
            "}\n";
        string resultPath = Path.Combine(Application.persistentDataPath, "care_review_local_data_delete_smoke_result.json");
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_LOCAL_DATA_DELETE_SMOKE_RESULT path=" + resultPath + " completed=" + (result.completed && confirmationArmed && managedFilesDeleted && managedDirectoriesDeleted && unrelatedFilePreserved));

        Application.Quit();
    }

    private IEnumerator RunRuntimeIssueSmokeTest()
    {
        yield return null;

        ResetRuntimeIssueLog();
        CaptureRuntimeIssue(
            LogType.Error,
            "CARE_REVIEW_SYNTHETIC_RUNTIME_ISSUE C:/Users/test/AppData/LocalLow/user-visible-path",
            "at C:/Users/test/AppData/LocalLow/FakeStack.cs:12\nat CareReviewGame.RuntimeIssueSmoke()");

        string jsonPath = Path.Combine(LogDirectory, RuntimeIssuesJsonFileName);
        string markdownPath = Path.Combine(LogDirectory, RuntimeIssuesMarkdownFileName);
        string jsonText = File.Exists(jsonPath) ? File.ReadAllText(jsonPath, Encoding.UTF8) : "";
        string markdownText = File.Exists(markdownPath) ? File.ReadAllText(markdownPath, Encoding.UTF8) : "";
        bool hasJson = File.Exists(jsonPath);
        bool hasMarkdown = File.Exists(markdownPath);
        bool jsonHasIssue = jsonText.Contains("CARE_REVIEW_SYNTHETIC_RUNTIME_ISSUE") && jsonText.Contains("\"errorCount\": 1");
        bool markdownHasIssue = markdownText.Contains("CARE_REVIEW_SYNTHETIC_RUNTIME_ISSUE") && markdownText.Contains("Error");
        bool messageSanitized = !jsonText.Contains("C:/Users") && !jsonText.Contains("AppData") && !jsonText.Contains("LocalLow");
        bool stackSanitized = !markdownText.Contains("C:/Users") && !markdownText.Contains("AppData") && !markdownText.Contains("LocalLow");

        SupportBundleExport bundle = ExportSupportBundleFiles();
        string manifestJsonPath = Path.Combine(bundle.bundleDirectoryPath, "care_review_support_bundle_manifest.json");
        string manifestJson = File.Exists(manifestJsonPath) ? File.ReadAllText(manifestJsonPath, Encoding.UTF8) : "";
        bool supportBundleHasRuntimeIssues = bundle.hasRuntimeIssues;
        bool manifestMentionsRuntimeIssues = manifestJson.Contains("\"hasRuntimeIssues\": true");
        bool completed = hasJson &&
            hasMarkdown &&
            jsonHasIssue &&
            markdownHasIssue &&
            messageSanitized &&
            stackSanitized &&
            supportBundleHasRuntimeIssues &&
            manifestMentionsRuntimeIssues &&
            bundle.filesHaveNoLocalAbsolutePath;

        string resultBody =
            "{\n" +
            $"  \"completed\": {(completed ? "true" : "false")},\n" +
            $"  \"hasJson\": {(hasJson ? "true" : "false")},\n" +
            $"  \"hasMarkdown\": {(hasMarkdown ? "true" : "false")},\n" +
            $"  \"jsonHasIssue\": {(jsonHasIssue ? "true" : "false")},\n" +
            $"  \"markdownHasIssue\": {(markdownHasIssue ? "true" : "false")},\n" +
            $"  \"messageSanitized\": {(messageSanitized ? "true" : "false")},\n" +
            $"  \"stackSanitized\": {(stackSanitized ? "true" : "false")},\n" +
            $"  \"supportBundleHasRuntimeIssues\": {(supportBundleHasRuntimeIssues ? "true" : "false")},\n" +
            $"  \"manifestMentionsRuntimeIssues\": {(manifestMentionsRuntimeIssues ? "true" : "false")},\n" +
            $"  \"bundleFilesHaveNoLocalAbsolutePath\": {(bundle.filesHaveNoLocalAbsolutePath ? "true" : "false")},\n" +
            $"  \"runtimeIssueJsonFile\": \"{RuntimeIssuesJsonFileName}\",\n" +
            $"  \"runtimeIssueMarkdownFile\": \"{RuntimeIssuesMarkdownFileName}\",\n" +
            $"  \"bundleName\": \"{EscapeJson(bundle.bundleName)}\",\n";
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(resultBody) && !ContainsLocalAbsolutePath(jsonText) && !ContainsLocalAbsolutePath(markdownText);
        string resultJson = resultBody +
            $"  \"filesHaveNoLocalAbsolutePath\": {(filesHaveNoLocalAbsolutePath ? "true" : "false")}\n" +
            "}\n";
        string resultPath = Path.Combine(LogDirectory, "care_review_runtime_issue_smoke_result.json");
        File.WriteAllText(resultPath, resultJson, Encoding.UTF8);
        Debug.Log("CARE_REVIEW_RUNTIME_ISSUE_SMOKE_RESULT path=" + resultPath + " completed=" + completed);

        Application.Quit();
    }

    private IEnumerator RunBalanceQa()
    {
        yield return null;

        List<BalanceRunSummary> summaries = new();
        foreach (CampaignMandate mandate in CampaignMandateCatalog)
        {
            foreach (BalancePolicyProfile profile in BuildBalancePolicyProfiles())
            {
                summaries.Add(SimulateBalanceRun(profile, mandate));
            }
        }

        int highestDay = 0;
        foreach (CareCase careCase in cases)
        {
            highestDay = Mathf.Max(highestDay, careCase.day);
        }

        string generatedAt = DateTime.Now.ToString("s");
        BalanceQaExport export = new(generatedAt, cases.Count, highestDay, summaries);
        BalanceTuningReportExport tuningReport = BuildBalanceTuningReport(generatedAt, cases.Count, highestDay, summaries);
        string jsonPath = Path.Combine(Application.persistentDataPath, "care_review_balance_qa.json");
        string csvPath = Path.Combine(Application.persistentDataPath, "care_review_balance_qa.csv");
        string tuningJsonPath = Path.Combine(Application.persistentDataPath, "care_review_balance_tuning_report.json");
        string tuningMarkdownPath = Path.Combine(Application.persistentDataPath, "care_review_balance_tuning_report.md");
        string tuningHtmlPath = Path.Combine(Application.persistentDataPath, "care_review_balance_tuning_report.html");
        string tuningSmokePath = Path.Combine(Application.persistentDataPath, "care_review_balance_tuning_smoke_result.json");
        File.WriteAllText(jsonPath, JsonUtility.ToJson(export, true), Encoding.UTF8);
        File.WriteAllText(csvPath, BuildBalanceQaCsv(summaries), Encoding.UTF8);
        File.WriteAllText(tuningJsonPath, JsonUtility.ToJson(tuningReport, true), Encoding.UTF8);
        File.WriteAllText(tuningMarkdownPath, BuildBalanceTuningMarkdown(tuningReport), Encoding.UTF8);
        File.WriteAllText(tuningHtmlPath, BuildBalanceTuningHtml(tuningReport), Encoding.UTF8);

        string tuningMarkdown = File.ReadAllText(tuningMarkdownPath, Encoding.UTF8);
        string tuningHtml = File.ReadAllText(tuningHtmlPath, Encoding.UTF8);
        bool hasMandateRecommendations = tuningReport.mandates != null && tuningReport.mandates.Count == CampaignMandateCatalog.Length;
        bool hasCommercialReadiness = !string.IsNullOrWhiteSpace(tuningReport.commercialReadiness);
        bool hasReadableExports = tuningMarkdown.Contains("운영 기준별 권고") &&
            tuningMarkdown.Contains("조정 우선순위") &&
            tuningHtml.Contains("운영 기준별 권고") &&
            tuningHtml.Contains("조정 우선순위");
        bool tuningCompleted = summaries.Count == CampaignMandateCatalog.Length * BuildBalancePolicyProfiles().Count &&
            hasMandateRecommendations &&
            hasCommercialReadiness &&
            hasReadableExports;
        string tuningSmokeJson =
            "{\n" +
            $"  \"completed\": {(tuningCompleted ? "true" : "false")},\n" +
            $"  \"runCount\": {summaries.Count},\n" +
            $"  \"mandateRecommendationCount\": {(tuningReport.mandates != null ? tuningReport.mandates.Count : 0)},\n" +
            $"  \"issueCount\": {(tuningReport.issues != null ? tuningReport.issues.Count : 0)},\n" +
            $"  \"hasMandateRecommendations\": {(hasMandateRecommendations ? "true" : "false")},\n" +
            $"  \"hasCommercialReadiness\": {(hasCommercialReadiness ? "true" : "false")},\n" +
            $"  \"hasReadableExports\": {(hasReadableExports ? "true" : "false")},\n" +
            $"  \"markdownPath\": \"{EscapeJson(tuningMarkdownPath.Replace("\\", "/"))}\",\n" +
            $"  \"htmlPath\": \"{EscapeJson(tuningHtmlPath.Replace("\\", "/"))}\"\n" +
            "}\n";
        File.WriteAllText(tuningSmokePath, tuningSmokeJson, Encoding.UTF8);

        BalanceRunSummary recommended = summaries.Count > 0 ? summaries[0] : null;
        Debug.Log(
            "CARE_REVIEW_BALANCE_QA_RESULT path=" + jsonPath +
            " csv=" + csvPath +
            " tuning=" + tuningMarkdownPath +
            " runs=" + summaries.Count +
            (recommended != null
                ? $" recommendedBudget={recommended.finalBudget} recommendedComplaints={recommended.complaints} recommendedMissedRisk={recommended.missedRisk} recommendedFlag={recommended.riskFlag}"
                : string.Empty));
        Application.Quit();
    }

    private static BalanceTuningReportExport BuildBalanceTuningReport(string generatedAt, int caseCount, int highestDay, List<BalanceRunSummary> summaries)
    {
        BalanceTuningReportExport report = new()
        {
            generatedAt = generatedAt,
            caseCount = caseCount,
            highestDay = highestDay,
            runCount = summaries.Count,
            stableRunCount = CountBalanceRunsByFlag(summaries, "stable"),
            strainedRunCount = CountBalanceRunsByFlag(summaries, "strained"),
            highPressureRunCount = CountBalanceRunsByFlag(summaries, "high_pressure"),
            mandates = new List<BalanceMandateTuningExport>(),
            issues = new List<BalanceTuningIssueExport>()
        };

        foreach (CampaignMandate mandate in CampaignMandateCatalog)
        {
            List<BalanceRunSummary> mandateRuns = FilterBalanceRuns(summaries, CampaignMandateId(mandate));
            BalanceRunSummary recommended = FindBalanceRun(mandateRuns, "recommended");
            BalanceRunSummary pressureRun = FindHighestPressureRun(mandateRuns);
            int stableCount = CountBalanceRunsByFlag(mandateRuns, "stable");
            int strainedCount = CountBalanceRunsByFlag(mandateRuns, "strained");
            int highPressureCount = CountBalanceRunsByFlag(mandateRuns, "high_pressure");
            float averageBudget = AverageBalanceMetric(mandateRuns, BalanceMetric.FinalBudget);
            float averageMissedRisk = AverageBalanceMetric(mandateRuns, BalanceMetric.MissedRisk);
            float averageComplaints = AverageBalanceMetric(mandateRuns, BalanceMetric.Complaints);
            string recommendation = BuildBalanceMandateRecommendation(mandate, mandateRuns, recommended, stableCount, strainedCount, highPressureCount, averageBudget, averageMissedRisk, averageComplaints);

            report.mandates.Add(new BalanceMandateTuningExport
            {
                campaignMandateId = CampaignMandateId(mandate),
                campaignMandateName = CampaignMandateLabel(mandate),
                runCount = mandateRuns.Count,
                stableRunCount = stableCount,
                strainedRunCount = strainedCount,
                highPressureRunCount = highPressureCount,
                averageFinalBudget = Mathf.RoundToInt(averageBudget),
                averageMissedRisk = Mathf.RoundToInt(averageMissedRisk),
                averageComplaints = Mathf.RoundToInt(averageComplaints),
                recommendedProfileFlag = recommended != null ? recommended.riskFlag : "missing",
                recommendedFinalBudget = recommended != null ? recommended.finalBudget : 0,
                recommendedMissedRisk = recommended != null ? recommended.missedRisk : 0,
                recommendedComplaints = recommended != null ? recommended.complaints : 0,
                highestPressureProfileId = pressureRun != null ? pressureRun.profileId : "",
                highestPressureProfileName = pressureRun != null ? pressureRun.profileName : "",
                highestPressureScore = pressureRun != null ? BalancePressureScore(pressureRun) : 0,
                recommendation = recommendation
            });

            AppendBalanceTuningIssues(report.issues, mandate, mandateRuns, recommended, pressureRun, stableCount, highPressureCount);
        }

        report.commercialReadiness = BuildBalanceCommercialReadiness(report);
        return report;
    }

