        builder.AppendLine("- 자동 QA에서 stable인 경로는 시작 밸런스로 보고, strained/high_pressure 경로는 상점 설명, 브리핑, 챌린지 목표, 비용 계수 조정 후보로 본다.");
        builder.AppendLine("- 실제 테스터 5명 이상 회수 후에는 플레이테스트 집계의 가격 가치감, 난이도, 결과 납득도와 함께 다시 판단한다.");
        return builder.ToString();
    }

