    private static List<BalanceRunSummary> FilterBalanceRuns(List<BalanceRunSummary> summaries, string mandateId)
    {
        List<BalanceRunSummary> runs = new();
        foreach (BalanceRunSummary summary in summaries)
        {
            if (summary.campaignMandateId == mandateId)
            {
                runs.Add(summary);
            }
        }
        return runs;
    }

    private static BalanceRunSummary FindBalanceRun(List<BalanceRunSummary> summaries, string profileId)
    {
        foreach (BalanceRunSummary summary in summaries)
        {
            if (summary.profileId == profileId)
            {
                return summary;
            }
        }
        return null;
    }

    private static BalanceRunSummary FindHighestPressureRun(List<BalanceRunSummary> summaries)
    {
        BalanceRunSummary selected = null;
        int selectedScore = int.MinValue;
        foreach (BalanceRunSummary summary in summaries)
        {
            int score = BalancePressureScore(summary);
            if (selected == null || score > selectedScore)
            {
                selected = summary;
                selectedScore = score;
            }
        }
        return selected;
    }

#endif

    private static int CountBalanceRunsByFlag(List<BalanceRunSummary> summaries, string flag)
    {
        int count = 0;
        foreach (BalanceRunSummary summary in summaries)
        {
            if (summary.riskFlag == flag)
            {
                count++;
            }
        }
        return count;
    }

    private enum BalanceMetric
    {
        FinalBudget,
        MissedRisk,
        Complaints
    }

    private static float AverageBalanceMetric(List<BalanceRunSummary> summaries, BalanceMetric metric)
    {
        if (summaries.Count == 0)
        {
            return 0f;
        }

        int total = 0;
        foreach (BalanceRunSummary summary in summaries)
        {
            total += metric switch
            {
                BalanceMetric.FinalBudget => summary.finalBudget,
                BalanceMetric.MissedRisk => summary.missedRisk,
                _ => summary.complaints
            };
        }
        return total / (float)summaries.Count;
    }

    private static int BalancePressureScore(BalanceRunSummary summary)
    {
        if (summary == null)
        {
            return 0;
        }

        int score = 0;
        if (summary.finalBudget < 0)
        {
            score += Mathf.RoundToInt(-summary.finalBudget / 40f);
        }
        score += summary.complaints;
        score += summary.missedRisk;
        score += Mathf.Max(0, 60 - summary.stability);
        score += Mathf.Max(0, 60 - summary.equity);
        if (summary.riskFlag == "strained")
        {
            score += 25;
        }
        else if (summary.riskFlag == "high_pressure")
        {
            score += 60;
        }
        return score;
    }

    private static string BuildBalanceMandateRecommendation(CampaignMandate mandate, List<BalanceRunSummary> mandateRuns, BalanceRunSummary recommended, int stableCount, int strainedCount, int highPressureCount, float averageBudget, float averageMissedRisk, float averageComplaints)
    {
        if (recommended == null)
        {
            return "권장 경로 산출이 없어 자동 QA 구성을 먼저 확인한다.";
        }

        if (mandate == CampaignMandate.SupportExpanded)
        {
            if (recommended.riskFlag == "stable" && recommended.finalBudget > 900 && recommended.complaints < 75)
            {
                return "초보/스토리 확인용 기준으로 기능한다. 실제 테스터가 너무 쉽다고 느끼면 챌린지 목표만 강화한다.";
            }
            return "지원 확대 기준이 예상보다 압박적이다. 시작 예산이나 민원 완화 계수를 소폭 올리는 후보로 본다.";
        }

        if (mandate == CampaignMandate.AusterityAudit)
        {
            BalanceRunSummary riskFirst = FindBalanceRun(mandateRuns, "risk_first");
            if (recommended.riskFlag == "high_pressure" && riskFirst != null && riskFirst.riskFlag == "stable")
            {
                return "고난도 반복 플레이 의도가 선명하다. 브리핑에서 권장 경로만 따르면 예산 압박이 온다는 설명을 유지한다.";
            }
            if (recommended.riskFlag != "stable")
            {
                return "고난도 기준은 유지하되 실제 플레이에서 불공정하다는 반응이 나오면 비용 계수와 일일 재배정을 완화한다.";
            }
            return "긴축 감사가 예상보다 안정적이다. 상용 반복 모드로 쓰려면 감사 비용/민원 계수를 올리는 후보로 본다.";
        }

        if (recommended.riskFlag == "stable" && recommended.finalBudget > -900 && recommended.complaints < 85 && recommended.missedRisk < 45)
        {
            return "표준 기준은 시작 밸런스로 유지한다. 민원과 예산 압박은 후속 연락함/재검토 큐로 안내한다.";
        }

        if (recommended.riskFlag == "strained")
        {
            return "표준 권장 경로가 약간 빡빡하다. 실제 테스터가 1회차에서 좌절하면 일일 예산 재배정이나 조건부 승인 비용을 완화한다.";
        }

        return highPressureCount >= stableCount
            ? "표준 기준의 고압력 비율이 높다. 1회차 완주율을 위해 비용/민원 계수를 낮추는 후보로 본다."
            : "자동 QA 기준으로 큰 조정 없이 실제 사람 플레이 반응을 확인한다.";
    }

    private static void AppendBalanceTuningIssues(List<BalanceTuningIssueExport> issues, CampaignMandate mandate, List<BalanceRunSummary> mandateRuns, BalanceRunSummary recommended, BalanceRunSummary pressureRun, int stableCount, int highPressureCount)
    {
        if (recommended != null && mandate != CampaignMandate.AusterityAudit && recommended.riskFlag == "high_pressure")
        {
            issues.Add(new BalanceTuningIssueExport
            {
                priority = "high",
                campaignMandateId = CampaignMandateId(mandate),
                campaignMandateName = CampaignMandateLabel(mandate),
                profileId = recommended.profileId,
                profileName = recommended.profileName,
                metric = "권장 경로 고압력",
                evidence = $"예산 {recommended.finalBudget}, 누락 위험 {recommended.missedRisk}, 민원 {recommended.complaints}",
                recommendation = "표준/지원 확대 권장 경로는 첫 회차 기준이므로 비용 또는 민원 계수를 완화한다."
            });
        }

        if (mandate == CampaignMandate.SupportExpanded && recommended != null && recommended.riskFlag == "stable" && recommended.finalBudget > 1800)
        {
            issues.Add(new BalanceTuningIssueExport
            {
                priority = "low",
                campaignMandateId = CampaignMandateId(mandate),
                campaignMandateName = CampaignMandateLabel(mandate),
                profileId = recommended.profileId,
                profileName = recommended.profileName,
                metric = "지원 확대 여유 예산",
                evidence = $"권장 경로 최종 예산 {recommended.finalBudget}",
                recommendation = "너무 쉽다는 피드백이 2명 이상 나오면 캠페인 챌린지 점수 기준을 올린다."
            });
        }

        if (mandate == CampaignMandate.AusterityAudit && pressureRun != null && pressureRun.riskFlag == "high_pressure")
        {
            issues.Add(new BalanceTuningIssueExport
            {
                priority = "medium",
                campaignMandateId = CampaignMandateId(mandate),
                campaignMandateName = CampaignMandateLabel(mandate),
                profileId = pressureRun.profileId,
                profileName = pressureRun.profileName,
                metric = "고난도 압박 상한",
                evidence = $"최고 압박 점수 {BalancePressureScore(pressureRun)}, 예산 {pressureRun.finalBudget}, 민원 {pressureRun.complaints}",
                recommendation = "고압력은 의도된 스트레스 테스트다. 실제 플레이에서 불공정 피드백이 반복될 때만 긴축 비용 계수를 낮춘다."
            });
        }

        if (stableCount == 0 && highPressureCount > 0)
        {
            issues.Add(new BalanceTuningIssueExport
            {
                priority = "high",
                campaignMandateId = CampaignMandateId(mandate),
                campaignMandateName = CampaignMandateLabel(mandate),
                profileId = pressureRun != null ? pressureRun.profileId : "",
                profileName = pressureRun != null ? pressureRun.profileName : "",
                metric = "안정 경로 없음",
                evidence = $"stable 0회, high_pressure {highPressureCount}회",
                recommendation = "적어도 한 가지 읽을 수 있는 안정 경로가 나오도록 운영 기준 브리핑과 비용 계수를 재검토한다."
            });
        }
    }

    private static string BuildBalanceCommercialReadiness(BalanceTuningReportExport report)
    {
        bool standardOk = false;
        bool supportOk = false;
        bool austerityOk = false;
        foreach (BalanceMandateTuningExport mandate in report.mandates)
        {
            if (mandate.campaignMandateId == "standard")
            {
                standardOk = mandate.recommendedProfileFlag == "stable" || mandate.recommendedProfileFlag == "strained";
            }
            else if (mandate.campaignMandateId == "support_expanded")
            {
                supportOk = mandate.recommendedProfileFlag == "stable";
            }
            else if (mandate.campaignMandateId == "austerity_audit")
            {
                austerityOk = mandate.stableRunCount >= 1 && mandate.highPressureRunCount >= 1;
            }
        }

        return standardOk && supportOk && austerityOk
            ? "자동 밸런스 기준 판매 후보 구조 통과. 실제 사람 플레이테스트로 체감 난이도와 가격 가치감을 확인해야 한다."
            : "자동 밸런스 기준에서 추가 수치 조정 후보가 있다. 실제 사람 플레이테스트 전 최소 1회 재검토가 필요하다.";
    }

