    private BalanceRunSummary SimulateBalanceRun(BalancePolicyProfile profile, CampaignMandate mandate)
    {
        int simulatedBudget = StartingBudgetForMandate(mandate);
        int simulatedStability = 50;
        int simulatedEquity = 50;
        int simulatedMissedRisk = 0;
        int simulatedComplaints = 0;
        int simulatedInvestigations = 0;
        int supportCount = 0;
        int holdCount = 0;
        int rejectCount = 0;
        int matchedCount = 0;
        int transitionDaysApplied = 0;
        int minBudget = simulatedBudget;
        int maxComplaints = simulatedComplaints;
        int maxMissedRisk = simulatedMissedRisk;
        int pendingBudgetDelta = 0;
        int pendingStabilityDelta = 0;
        int pendingEquityDelta = 0;
        int pendingMissedRiskDelta = 0;
        int pendingComplaintsDelta = 0;
        int pendingFinalBudgetDelta = 0;
        int pendingFinalMissedRiskDelta = 0;
        int pendingFinalComplaintsDelta = 0;
        int currentDay = cases.Count > 0 ? cases[0].day : 1;
        List<IncidentLog> simulatedIncidents = new();

        foreach (CareCase careCase in cases)
        {
            if (careCase.day != currentDay)
            {
                ApplyBalanceDayEffects(
                    currentDay,
                    ref simulatedBudget,
                    ref simulatedStability,
                    ref simulatedEquity,
                    ref simulatedMissedRisk,
                    ref simulatedComplaints,
                    pendingBudgetDelta,
                    pendingStabilityDelta,
                    pendingEquityDelta,
                    pendingMissedRiskDelta,
                    pendingComplaintsDelta,
                    simulatedIncidents);
                simulatedBudget += CalculateDailyBudgetReallocation(careCase.day, mandate);
                transitionDaysApplied++;
                minBudget = Mathf.Min(minBudget, simulatedBudget);
                maxComplaints = Mathf.Max(maxComplaints, simulatedComplaints);
                maxMissedRisk = Mathf.Max(maxMissedRisk, simulatedMissedRisk);
                pendingBudgetDelta = 0;
                pendingStabilityDelta = 0;
                pendingEquityDelta = 0;
                pendingMissedRiskDelta = 0;
                pendingComplaintsDelta = 0;
                currentDay = careCase.day;
            }

            DecisionKind decision = ChooseBalanceDecision(profile.policy, careCase, simulatedBudget);
            string decisionLabel = DecisionLabel(decision);
            int cost = GetDecisionCost(decision, careCase, mandate);
            ApplyDirectDecisionDeltas(
                decision,
                careCase,
                cost,
                mandate,
                ref simulatedBudget,
                ref simulatedStability,
                ref simulatedEquity,
                ref simulatedMissedRisk,
                ref simulatedComplaints,
                ref simulatedInvestigations);

            if (decision == DecisionKind.Approve || decision == DecisionKind.Conditional)
            {
                supportCount++;
            }
            else if (decision == DecisionKind.Hold)
            {
                holdCount++;
            }
            else if (decision == DecisionKind.Reject)
            {
                rejectCount++;
            }

            bool matched = decisionLabel == careCase.recommendedDecision ||
                (careCase.recommendedDecision == "조건부 승인" && decisionLabel == "승인");
            if (matched)
            {
                matchedCount++;
            }

            Consequence consequence = AdjustConsequenceForMandate(mandate, BuildConsequence(careCase, decisionLabel, matched, simulatedBudget));
            pendingBudgetDelta += consequence.budgetDelta;
            pendingStabilityDelta += consequence.stabilityDelta;
            pendingEquityDelta += consequence.equityDelta;
            pendingMissedRiskDelta += consequence.missedRiskDelta;
            pendingComplaintsDelta += consequence.complaintsDelta;
            pendingFinalBudgetDelta = pendingBudgetDelta;
            pendingFinalMissedRiskDelta = pendingMissedRiskDelta;
            pendingFinalComplaintsDelta = pendingComplaintsDelta;

            minBudget = Mathf.Min(minBudget, simulatedBudget);
            maxComplaints = Mathf.Max(maxComplaints, simulatedComplaints);
            maxMissedRisk = Mathf.Max(maxMissedRisk, simulatedMissedRisk);
        }

        if (cases.Count > 0)
        {
            ApplyBalanceDayEffects(
                currentDay,
                ref simulatedBudget,
                ref simulatedStability,
                ref simulatedEquity,
                ref simulatedMissedRisk,
                ref simulatedComplaints,
                pendingBudgetDelta,
                pendingStabilityDelta,
                pendingEquityDelta,
                pendingMissedRiskDelta,
                pendingComplaintsDelta,
                simulatedIncidents);
            minBudget = Mathf.Min(minBudget, simulatedBudget);
            maxComplaints = Mathf.Max(maxComplaints, simulatedComplaints);
            maxMissedRisk = Mathf.Max(maxMissedRisk, simulatedMissedRisk);
        }

        int investigationCount = simulatedInvestigations;
        string riskFlag = BuildBalanceRiskFlag(simulatedBudget, simulatedStability, simulatedEquity, simulatedMissedRisk, simulatedComplaints);
        return new BalanceRunSummary(
            CampaignMandateId(mandate),
            CampaignMandateLabel(mandate),
            profile.id,
            profile.name,
            cases.Count,
            supportCount,
            investigationCount,
            holdCount,
            rejectCount,
            matchedCount,
            transitionDaysApplied,
            simulatedIncidents.Count,
            simulatedBudget,
            simulatedStability,
            simulatedEquity,
            simulatedMissedRisk,
            simulatedComplaints,
            minBudget,
            maxComplaints,
            maxMissedRisk,
            pendingFinalBudgetDelta,
            pendingFinalMissedRiskDelta,
            pendingFinalComplaintsDelta,
            riskFlag);
    }

    private static void ApplyDirectDecisionDeltas(DecisionKind decision, CareCase careCase, int cost, CampaignMandate mandate, ref int budgetValue, ref int stabilityValue, ref int equityValue, ref int missedRiskValue, ref int complaintsValue, ref int investigationValue)
    {
        int stabilityDelta = 0;
        int equityDelta = 0;
        int missedDelta = 0;
        int complaintDelta = 0;

        switch (decision)
        {
            case DecisionKind.Approve:
                stabilityDelta = Mathf.RoundToInt(careCase.urgency * 0.20f);
                equityDelta = Mathf.RoundToInt(careCase.equityNeed * 0.12f);
                missedDelta = -Mathf.RoundToInt(careCase.urgency * 0.18f);
                complaintDelta = careCase.documentStrength < 60 ? 2 : 0;
                break;
            case DecisionKind.Conditional:
                stabilityDelta = Mathf.RoundToInt(careCase.urgency * 0.12f);
                equityDelta = Mathf.RoundToInt(careCase.equityNeed * 0.10f);
                missedDelta = -Mathf.RoundToInt(careCase.urgency * 0.10f);
                complaintDelta = 1;
                break;
            case DecisionKind.Hold:
                stabilityDelta = -Mathf.RoundToInt(careCase.urgency * 0.06f);
                equityDelta = -2;
                missedDelta = Mathf.RoundToInt(careCase.urgency * 0.10f);
                complaintDelta = 3;
                break;
            case DecisionKind.Investigate:
                investigationValue++;
                stabilityDelta = careCase.urgency > 78 ? -2 : 0;
                equityDelta = 3;
                missedDelta = careCase.urgency > 80 ? 5 : 1;
                complaintDelta = 1;
                break;
            default:
                stabilityDelta = -Mathf.RoundToInt(careCase.urgency * 0.15f);
                equityDelta = -Mathf.RoundToInt(careCase.equityNeed * 0.09f);
                missedDelta = Mathf.RoundToInt(careCase.urgency * 0.18f);
                complaintDelta = careCase.urgency > 75 ? 5 : 2;
                break;
        }

        missedDelta = AdjustMissedRiskDeltaForMandate(mandate, missedDelta);
        complaintDelta = AdjustComplaintDeltaForMandate(mandate, complaintDelta);

        budgetValue -= cost;
        stabilityValue = Mathf.Clamp(stabilityValue + stabilityDelta, 0, 100);
        equityValue = Mathf.Clamp(equityValue + equityDelta, 0, 100);
        missedRiskValue = Mathf.Clamp(missedRiskValue + missedDelta, 0, 100);
        complaintsValue = Mathf.Clamp(complaintsValue + complaintDelta, 0, 100);
    }

    private static void ApplyBalanceDayEffects(int completedDay, ref int budgetValue, ref int stabilityValue, ref int equityValue, ref int missedRiskValue, ref int complaintsValue, int budgetDelta, int stabilityDelta, int equityDelta, int missedRiskDelta, int complaintsDelta, List<IncidentLog> incidents)
    {
        budgetValue += budgetDelta;
        stabilityValue = Mathf.Clamp(stabilityValue + stabilityDelta, 0, 100);
        equityValue = Mathf.Clamp(equityValue + equityDelta, 0, 100);
        missedRiskValue = Mathf.Clamp(missedRiskValue + missedRiskDelta, 0, 100);
        complaintsValue = Mathf.Clamp(complaintsValue + complaintsDelta, 0, 100);
        TriggerBalanceIncidents(completedDay, ref budgetValue, ref stabilityValue, ref equityValue, ref missedRiskValue, ref complaintsValue, incidents);
    }

    private static void TriggerBalanceIncidents(int completedDay, ref int budgetValue, ref int stabilityValue, ref int equityValue, ref int missedRiskValue, ref int complaintsValue, List<IncidentLog> incidents)
    {
        if (budgetValue <= -1500 && !HasBalanceIncident(incidents, completedDay, "budget_audit"))
        {
            AddBalanceIncident(incidents, new IncidentLog(completedDay, "budget_audit", "예산 감사 착수", string.Empty, -80, -1, -2, 0, 3), ref budgetValue, ref stabilityValue, ref equityValue, ref missedRiskValue, ref complaintsValue);
        }

        if (complaintsValue >= 55 && !HasBalanceIncident(incidents, completedDay, "complaint_surge"))
        {
            AddBalanceIncident(incidents, new IncidentLog(completedDay, "complaint_surge", "민원 공동 대응 회의", string.Empty, -60, -1, 1, 0, 3), ref budgetValue, ref stabilityValue, ref equityValue, ref missedRiskValue, ref complaintsValue);
        }

        if (missedRiskValue >= 25 && !HasBalanceIncident(incidents, completedDay, "safety_check"))
        {
            AddBalanceIncident(incidents, new IncidentLog(completedDay, "safety_check", "긴급 안전점검", string.Empty, -90, 2, 2, -8, 2), ref budgetValue, ref stabilityValue, ref equityValue, ref missedRiskValue, ref complaintsValue);
        }

        if (equityValue <= 30 && !HasBalanceIncident(incidents, completedDay, "equity_objection"))
        {
            AddBalanceIncident(incidents, new IncidentLog(completedDay, "equity_objection", "형평성 이의제기", string.Empty, -40, -1, -4, 1, 3), ref budgetValue, ref stabilityValue, ref equityValue, ref missedRiskValue, ref complaintsValue);
        }

        if (stabilityValue <= 35 && !HasBalanceIncident(incidents, completedDay, "staff_burnout"))
        {
            AddBalanceIncident(incidents, new IncidentLog(completedDay, "staff_burnout", "심사 인력 과부하", string.Empty, -50, -5, 0, 1, 2), ref budgetValue, ref stabilityValue, ref equityValue, ref missedRiskValue, ref complaintsValue);
        }

        if (complaintsValue >= 42 && missedRiskValue >= 16 && !HasBalanceIncident(incidents, completedDay, "review_backlog"))
        {
            AddBalanceIncident(incidents, new IncidentLog(completedDay, "review_backlog", "사례 적체 경보", string.Empty, -70, -2, -1, 3, 2), ref budgetValue, ref stabilityValue, ref equityValue, ref missedRiskValue, ref complaintsValue);
        }
    }

    private static bool HasBalanceIncident(List<IncidentLog> incidents, int day, string type)
    {
        foreach (IncidentLog incident in incidents)
        {
            if (incident.day == day && incident.type == type)
            {
                return true;
            }
        }

        return false;
    }

    private static void AddBalanceIncident(List<IncidentLog> incidents, IncidentLog incident, ref int budgetValue, ref int stabilityValue, ref int equityValue, ref int missedRiskValue, ref int complaintsValue)
    {
        incidents.Add(incident);
        budgetValue += incident.budgetDelta;
        stabilityValue = Mathf.Clamp(stabilityValue + incident.stabilityDelta, 0, 100);
        equityValue = Mathf.Clamp(equityValue + incident.equityDelta, 0, 100);
        missedRiskValue = Mathf.Clamp(missedRiskValue + incident.missedRiskDelta, 0, 100);
        complaintsValue = Mathf.Clamp(complaintsValue + incident.complaintsDelta, 0, 100);
    }

    private static DecisionKind ChooseBalanceDecision(BalancePolicy policy, CareCase careCase, int remainingBudget)
    {
        switch (policy)
        {
            case BalancePolicy.ApproveAll:
                return DecisionKind.Approve;
            case BalancePolicy.RejectAll:
                return DecisionKind.Reject;
            case BalancePolicy.RiskFirst:
                if (careCase.documentStrength < 48 && careCase.urgency < 88)
                {
                    return DecisionKind.Investigate;
                }
                if (careCase.urgency >= 88 && remainingBudget >= careCase.cost * 0.50f)
                {
                    return careCase.documentStrength >= 62 ? DecisionKind.Approve : DecisionKind.Conditional;
                }
                if (careCase.urgency >= 76 && remainingBudget >= careCase.cost * 0.40f)
                {
                    return DecisionKind.Conditional;
                }
                return careCase.urgency >= 68 ? DecisionKind.Investigate : DecisionKind.Hold;
            case BalancePolicy.BudgetGuarded:
                if (remainingBudget < 0)
                {
                    return careCase.urgency >= 88 ? DecisionKind.Hold : DecisionKind.Reject;
                }
                if (careCase.urgency >= 90 && careCase.documentStrength >= 55 && remainingBudget >= careCase.cost * 0.45f)
                {
                    return DecisionKind.Conditional;
                }
                if (careCase.cost > remainingBudget * 0.32f)
                {
                    return careCase.urgency >= 78 ? DecisionKind.Hold : DecisionKind.Reject;
                }
                return DecisionKindFromLabel(careCase.recommendedDecision);
            case BalancePolicy.DocumentStrict:
                if (careCase.documentStrength < 58)
                {
                    return careCase.urgency >= 88 ? DecisionKind.Investigate : DecisionKind.Hold;
                }
                if (!careCase.incomeEligible && careCase.urgency < 82)
                {
                    return DecisionKind.Reject;
                }
                return DecisionKindFromLabel(careCase.recommendedDecision);
            case BalancePolicy.InvestigationHeavy:
                if (careCase.documentStrength < 72 || !careCase.incomeEligible)
                {
                    return DecisionKind.Investigate;
                }
                if (careCase.urgency >= 88 && remainingBudget >= careCase.cost * 0.45f)
                {
                    return DecisionKind.Conditional;
                }
                return careCase.urgency < 66 ? DecisionKind.Hold : DecisionKindFromLabel(careCase.recommendedDecision);
            default:
                return DecisionKindFromLabel(careCase.recommendedDecision);
        }
    }

    private static string BuildBalanceRiskFlag(int budgetValue, int stabilityValue, int equityValue, int missedRiskValue, int complaintsValue)
    {
        if (budgetValue < -3000 || stabilityValue <= 20 || equityValue <= 20 || missedRiskValue >= 80 || complaintsValue >= 90)
        {
            return "high_pressure";
        }

        if (budgetValue < -1000 || stabilityValue <= 35 || equityValue <= 35 || missedRiskValue >= 50 || complaintsValue >= 85)
        {
            return "strained";
        }

        return "stable";
    }

