    private IEnumerator CaptureStoreScreenshot(string directoryPath, string fileName)
    {
        yield return new WaitForEndOfFrame();

        string screenshotPath = Path.Combine(directoryPath, fileName);
        if (File.Exists(screenshotPath))
        {
            File.Delete(screenshotPath);
        }

        ScreenCapture.CaptureScreenshot(screenshotPath);
        yield return new WaitForSeconds(0.45f);
        if (!IsScreenshotFileVisuallyValid(screenshotPath))
        {
            TryCaptureCanvasCameraScreenshot(screenshotPath);
        }
        Debug.Log("CARE_REVIEW_STORE_SCREENSHOT path=" + screenshotPath);
        yield return new WaitForSeconds(0.20f);
    }

    private static void SeedMarketingReplayDecorationRecords()
    {
        CareerRecordDatabase database = new()
        {
            records = new List<CareerRecord>()
        };

        for (int i = 0; i < 6; i++)
        {
            int count = i + 1;
            database.records.Add(new CareerRecord
            {
                sessionId = "marketing_replay_decoration_" + count,
                campaignStartedAt = DateTime.Now.AddDays(-8 + count).ToString("s"),
                completedAt = DateTime.Now.AddDays(-7 + count).ToString("s"),
                campaignMandateId = CampaignMandateId(CampaignMandate.AusterityAudit),
                campaignMandateName = CampaignMandateLabel(CampaignMandate.AusterityAudit),
                endingId = "paperwork_night",
                endingTitle = "서류의 밤",
                campaignGrade = count >= 6 ? "A" : "B",
                campaignScore = 72 + count * 3,
                caseCount = 40,
                logCount = 40,
                supportCount = 12 + count,
                investigationCount = 8 + count,
                holdCount = 5,
                rejectCount = 15 - count,
                matchedRecommendedCount = 30 + count,
                recommendedMatchRatePercent = 75f + count,
                finalBudget = -2200 - count * 50,
                finalStability = 82 + count,
                finalEquity = 84 + count,
                finalMissedRisk = Mathf.Max(12, 30 - count),
                finalComplaints = Mathf.Max(18, 54 - count * 3),
                campaignChallengeId = "budget_guard",
                campaignChallengeTitle = "예산 방어 계약",
                campaignChallengeSucceeded = count >= 4,
                campaignChallengeScore = 60 + count * 5,
                campaignChallengeProgress = count >= 4 ? "예산 방어 목표 달성" : "예산 방어 목표 진행 중",
                campaignBadge = count >= 6 ? "금색 반복 설계" : "반복 심사 기록",
                nextCampaignMandateId = CampaignMandateId(CampaignMandate.SupportExpanded),
