    private IEnumerator CaptureTrailerFrames()
    {
        yield return PrepareMarketingCaptureResolution();

        string frameDirectory = Path.Combine(Application.persistentDataPath, "trailer_frames_v030");
        Directory.CreateDirectory(frameDirectory);
        foreach (string oldFramePath in Directory.GetFiles(frameDirectory, "trailer_*.png"))
        {
            File.Delete(oldFramePath);
        }

        ResetCampaignState();
        ResetFirstCaseGuide();
        ShowMainMenu();
        yield return CaptureTrailerFrame(frameDirectory, "trailer_001_main_menu.png", "0-4s: title and offer");

        tutorialRoot.gameObject.SetActive(true);
        tutorialRoot.SetAsLastSibling();
        tutorialStepIndex = 0;
        tutorialLaunchesCampaign = false;
        UpdateTutorialContent();
        yield return CaptureTrailerFrame(frameDirectory, "trailer_002_tutorial_goal.png", "4-8s: rules and premise");

        tutorialRoot.gameObject.SetActive(false);
        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);
        yield return CaptureTrailerFrame(frameDirectory, "trailer_003_case_review_day1.png", "8-12s: first case review");

        Decide(DecisionKind.Approve);
        yield return CaptureTrailerFrame(frameDirectory, "trailer_004_decision_stamp.png", "12-16s: decision stamp and metrics");

        yield return MoveToCaseAtIndex(6);
        yield return CaptureTrailerFrame(frameDirectory, "trailer_005_case_variety.png", "16-20s: varied family cases");

        Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
        yield return CaptureTrailerFrame(frameDirectory, "trailer_006_followup_pressure.png", "20-24s: feedback pressure");

        yield return PlayRecommendedUntilIncidentDayTransition();
        yield return CaptureTrailerFrame(frameDirectory, "trailer_007_incident_briefing.png", "24-28s: visual incident briefing");

        ResetCampaignState();
        firstCaseGuideDismissed = true;
        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        ShowCase(0);
        yield return MoveToCaseAtIndex(16);
        yield return CaptureTrailerFrame(frameDirectory, "trailer_008_late_campaign_case.png", "28-31s: later campaign pressure");

        yield return MoveToCaseAtIndex(32);
        yield return CaptureTrailerFrame(frameDirectory, "trailer_009_final_day_case.png", "31-34s: final day dilemma");

        Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
        yield return CaptureTrailerFrame(frameDirectory, "trailer_010_final_day_feedback.png", "34-37s: final day result");

        yield return PlayRecommendedUntilReport();
        yield return CaptureTrailerFrame(frameDirectory, "trailer_011_final_report.png", "37-41s: final report");

        SeedMarketingReplayDecorationRecords();
        ShowAchievements();
        yield return CaptureTrailerFrame(frameDirectory, "trailer_012_agent_analysis.png", "41-45s: achievement replay decoration and replay value");
        ShowCareerRecords();
        SetCareerRecordMandateFilter(CareerRecordAppealTriageFilterId);
        yield return CaptureTrailerFrame(frameDirectory, "trailer_013_career_record_filter.png", "45-49s: career record appeal triage candidate filter, candidate play record, long-term trend, growth comparison, representative retrospective, and growth follow-up");

        File.WriteAllText(
            Path.Combine(frameDirectory, "trailer_frames_manifest.txt"),
            "Care Review Office v0.3.0 trailer frame sequence\n" +
            "Intended runtime: 49 seconds\n" +
            "Frame size: use 1920x1080 capture for Steam trailer draft\n" +
            "01 0-4s title and offer\n" +
            "02 4-8s rules and premise\n" +
            "03 8-12s first case review\n" +
            "04 12-16s decision stamp and metrics\n" +
            "05 16-20s varied family cases\n" +
            "06 20-24s feedback pressure\n" +
            "07 24-28s visual incident briefing\n" +
            "08 28-31s later campaign pressure\n" +
            "09 31-34s final day dilemma\n" +
            "10 34-37s final day result\n" +
            "11 37-41s final report\n" +
            "12 41-45s achievement replay decoration and replay value\n" +
            "13 45-49s career record appeal triage candidate filter, candidate play record, long-term trend, growth comparison, representative retrospective, and growth follow-up objective\n",
            Encoding.UTF8);
        Debug.Log("CARE_REVIEW_TRAILER_FRAMES_DONE path=" + frameDirectory);
        yield return new WaitForSeconds(0.5f);
        Application.Quit();
    }

    private IEnumerator CaptureTrailerFrame(string directoryPath, string fileName, string description)
    {
        yield return new WaitForEndOfFrame();

        string screenshotPath = Path.Combine(directoryPath, fileName);
        if (File.Exists(screenshotPath))
        {
            File.Delete(screenshotPath);
        }

        ScreenCapture.CaptureScreenshot(screenshotPath);
        Debug.Log("CARE_REVIEW_TRAILER_FRAME path=" + screenshotPath + " description=" + description);
        yield return new WaitForSeconds(0.5f);
    }

    private IEnumerator PrepareMarketingCaptureResolution()
    {
        yield return PrepareCaptureResolution(1920, 1080);
    }

    private IEnumerator PrepareCaptureResolution(int width, int height)
    {
        fullscreenEnabled = false;
        Screen.SetResolution(width, height, FullScreenMode.Windowed);
        yield return null;
        yield return new WaitForSeconds(0.75f);
    }

    private static string LowResolutionFileName(Vector2Int resolution, string screenId)
    {
        return $"{resolution.x}x{resolution.y}_{screenId}.png";
    }

    private static void AppendLowResolutionScreenJson(StringBuilder json, ref bool firstEntry, Vector2Int targetResolution, string screenName, string fileName)
    {
        if (!firstEntry)
        {
            json.Append(",\n");
        }

        firstEntry = false;
        json.Append("    {\n");
        json.Append($"      \"screen\": \"{EscapeJson(screenName)}\",\n");
        json.Append($"      \"targetWidth\": {targetResolution.x},\n");
        json.Append($"      \"targetHeight\": {targetResolution.y},\n");
        json.Append($"      \"actualWidth\": {Screen.width},\n");
        json.Append($"      \"actualHeight\": {Screen.height},\n");
        json.Append($"      \"file\": \"{EscapeJson(fileName)}\"\n");
        json.Append("    }");
    }

    private IEnumerator MoveToCaseAtIndex(int targetIndex)
    {
        targetIndex = Mathf.Clamp(targetIndex, 0, cases.Count - 1);
        int guard = cases.Count * 4 + 20;
        while (currentIndex < targetIndex && guard > 0)
        {
            if (dayTransitionRoot.gameObject.activeSelf)
            {
                ContinueAfterDayTransition();
                yield return null;
            }

            if (!awaitingNext)
            {
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }

        if (dayTransitionRoot.gameObject.activeSelf && currentIndex == targetIndex)
        {
            ContinueAfterDayTransition();
            yield return null;
        }
    }

    private IEnumerator PlayRecommendedUntilDayTransition()
    {
        int guard = cases.Count * 3;
        while (!dayTransitionRoot.gameObject.activeSelf && currentIndex < cases.Count && guard > 0)
        {
            if (!awaitingNext)
            {
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }
    }

    private IEnumerator PlayRecommendedUntilIncidentDayTransition()
    {
        int guard = cases.Count * 5 + 20;
        while (currentIndex < cases.Count && guard > 0)
        {
            if (dayTransitionRoot.gameObject.activeSelf)
            {
                int completedDay = currentIndex < cases.Count ? cases[currentIndex].day - 1 : 0;
                if (LatestIncidentForDay(completedDay) != null)
                {
                    yield break;
                }

                ContinueAfterDayTransition();
                yield return null;
            }

            if (currentIndex < cases.Count && !awaitingNext)
            {
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }
    }

    private IEnumerator PlayRecommendedUntilReport()
    {
        int guard = cases.Count * 4 + 20;
        while (currentIndex < cases.Count && guard > 0)
        {
            if (dayTransitionRoot.gameObject.activeSelf)
            {
                ContinueAfterDayTransition();
                yield return null;
            }

            if (currentIndex < cases.Count && !awaitingNext)
            {
                Decide(DecisionKindFromLabel(cases[currentIndex].recommendedDecision));
                yield return null;
            }

            if (awaitingNext)
            {
                AdvanceToNextCase();
                yield return null;
            }

            guard--;
        }
    }

