    private static bool IsFreshStartState()
    {
        for (int slot = 1; slot <= MaxSaveSlots; slot++)
        {
            if (File.Exists(SavePathForSlot(slot)) || File.Exists(SaveBackupPathForSlot(slot)))
            {
                return false;
            }
        }

        CareerRecordDatabase database = LoadCareerRecordDatabase();
        return database.records == null || database.records.Count == 0;
    }

    private string BuildMainMenuAchievementBadgeLine()
    {
        AchievementDefinition[] achievements = BuildAchievementCatalog();
        int unlocked = UnlockedAchievementCount(achievements);
        string next = TryGetNextLockedAchievement(achievements, out AchievementDefinition achievement)
            ? achievement.title
            : "전체 완료";
        int replayCount = CountReplayObjectiveRecords(LoadCareerRecordDatabase().records);
        if (replayCount >= 2)
        {
            return $"성과 배지: {unlocked}/{achievements.Length} · 다음 성과 · {AdvancedReplayChallengeBadge(replayCount)} · 반복 {replayCount}/6 · A/성과 보기";
        }

        return $"성과 배지: {unlocked}/{achievements.Length} · 다음 성과 {Shorten(next, 16)} · 반복 {replayCount}/6 · A/성과 보기";
    }

