        string risk = BuildMenuCampaignBriefingRiskLine(targetMandate);
        string weakness = BuildMenuCampaignBriefingWeaknessLine();
        return
            "다음 근무 초점\n" +
            $"목표: {Shorten(objective, 44)}\n" +
            $"주의: {risk}\n" +
            $"보상: {reward}\n" +
            $"보정 초점: {Shorten(weakness, 46)}\n" +
            $"근거: {Shorten(reason, 48)}";
    }

    private static string BuildMenuCampaignBriefingWeaknessLine()
    {
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        if (database.records == null || database.records.Count == 0 || database.records[0] == null)
        {
            return "이전 기록 없음 · 첫 회차는 균형 기준선 확보";
        }

        CareerRecord latest = database.records[0];
        string coachingWeakness = BuildMenuCampaignBriefingCoachingWeaknessLine(latest);
        if (!string.IsNullOrWhiteSpace(coachingWeakness))
        {
            return coachingWeakness;
        }

        int matchScore = Mathf.RoundToInt(latest.recommendedMatchRatePercent);
        int budgetScore = Mathf.Clamp(latest.finalBudget * 100 / Mathf.Max(1, StartingBudgetForMandate(CampaignMandateFromId(latest.campaignMandateId))), -100, 100);
        int stabilityScore = Mathf.Clamp(latest.finalStability, 0, 100);
        int equityScore = Mathf.Clamp(latest.finalEquity, 0, 100);
        int safetyScore = Mathf.Clamp(100 - latest.finalMissedRisk, 0, 100);
        int complaintScore = Mathf.Clamp(100 - latest.finalComplaints, 0, 100);

        string label = "권장 일치";
        int weakestScore = matchScore;
        string note = $"권장 일치 {matchScore}% · 기준표와 선택 근거 재확인";

        ConsiderMenuBriefingWeakness("예산", budgetScore, $"예산 {latest.finalBudget}만원 · 고비용 지원 우선순위 점검", ref label, ref weakestScore, ref note);
        ConsiderMenuBriefingWeakness("안정", stabilityScore, $"안정 {latest.finalStability}점 · 조사/조건부 판단으로 급락 완충", ref label, ref weakestScore, ref note);
        ConsiderMenuBriefingWeakness("형평", equityScore, $"형평 {latest.finalEquity}점 · 소외 가구 후속 판단 확인", ref label, ref weakestScore, ref note);
        ConsiderMenuBriefingWeakness("누락 위험", safetyScore, $"누락 위험 {latest.finalMissedRisk} · 고위험 보류/거절 재검토", ref label, ref weakestScore, ref note);
        ConsiderMenuBriefingWeakness("민원", complaintScore, $"민원 {latest.finalComplaints} · 거절 근거와 안내 문구 보강", ref label, ref weakestScore, ref note);

        if (!latest.campaignChallengeSucceeded && latest.campaignChallengeScore < weakestScore)
        {
            label = "챌린지";
            weakestScore = latest.campaignChallengeScore;
            note = $"챌린지 미달 {latest.campaignChallengeScore}점 · {latest.campaignChallengeTitle}";
        }

        return string.IsNullOrWhiteSpace(label) || weakestScore >= 70
            ? "직전 회차 안정권 · 새 목표 보상 극대화"
            : note;
    }

    private static string BuildMenuCampaignBriefingCoachingWeaknessLine(CareerRecord latest)
    {
        if (latest == null || string.IsNullOrWhiteSpace(latest.decisionAuditCoachingPattern))
        {
            return "";
        }

        string recommended = FallbackText(latest.decisionAuditCoachingRecommendedMandateName, "없음");
        string verification = FallbackText(latest.decisionAuditCoachingVerificationQuestion, latest.decisionAuditCoachingExecutionRule);
        string verificationFocus = verification.Contains("위험 증가")
            ? "위험 증가"
            : Shorten(verification, 14);
        return
            $"복기 패턴 {latest.decisionAuditCoachingPattern} · " +
            $"추천 운영 {recommended} · " +
            $"검증 질문 {verificationFocus}";
    }

    private static void ConsiderMenuBriefingWeakness(string label, int score, string note, ref string weakestLabel, ref int weakestScore, ref string weakestNote)
    {
        if (score >= weakestScore)
        {
            return;
        }

        weakestLabel = label;
        weakestScore = score;
        weakestNote = note;
    }

