    private static string BuildCompactCareerGrowthPromptLine()
    {
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        if (database.records == null || database.records.Count < 2)
        {
            return "최근 성장: 완료 기록 2회부터 직전 대비 개선 초점 표시";
        }

        CareerRecord latest = database.records[0];
        CareerRecord previous = FindPreviousCareerRecord(database.records, latest);
        if (latest == null || previous == null)
        {
            return "최근 성장: 이전 기록 대기";
        }

        int scoreDelta = latest.campaignScore - previous.campaignScore;
        int matchDelta = Mathf.RoundToInt(latest.recommendedMatchRatePercent - previous.recommendedMatchRatePercent);
        int riskDelta = CareerRecordRiskScore(latest) - CareerRecordRiskScore(previous);
        string focus = BuildCareerRecordGrowthFocus(latest, previous).Replace("비교 초점: ", "");
        return $"최근 성장: 직전 대비 점수 {SignedNumber(scoreDelta)}점 · 권장 {SignedNumber(matchDelta)}p · 위험 {SignedNumber(riskDelta)}p · {focus}";
    }

    private static string BuildCompactCareerGrowthObjectiveSummaryLine()
    {
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        string summary = BuildCareerRecordGrowthObjectiveSummaryLine(database.records);
        return summary.Replace("성장 목표 요약:", "성장 누적:");
    }

