    {
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        string summary = BuildCareerRecordAppealRemedyObjectiveSummaryLine(database.records);
        return summary.Replace("보정 목표 요약:", "보정 누적:");
    }

