    private static string MenuFollowUpObjectiveButtonLabel(NextCampaignObjective objective)
    {
        if (IsAppealRemedyObjective(objective))
        {
            return "보정 심사";
        }

        return objective.challenge.Contains("성장 보정") ? "보정 심사" : "후속 심사";
    }

    private static string FollowUpMenuFocus(NextCampaignObjective objective)
    {
        if (IsAppealRemedyObjective(objective))
        {
            return AppealRemedyMenuFocus(objective);
        }

        return GrowthFollowUpMenuFocus(objective);
    }

    private static string AppealRemedyMenuFocus(NextCampaignObjective objective)
    {
        if (objective.challenge.Contains("재도전"))
        {
            return "재도전 · 고위험 지연";
        }

        if (objective.challenge.Contains("후속"))
        {
            return "후속 · 보정 품질 유지";
        }

        return "이의제기 보정";
    }

    private static string GrowthFollowUpMenuFocus(NextCampaignObjective objective)
    {
        if (!string.IsNullOrWhiteSpace(objective.challenge))
        {
            if (objective.challenge.Contains("권장"))
            {
                return "권장 유지";
            }

            if (objective.challenge.Contains("위험"))
            {
                return "위험 안정";
            }

            if (objective.challenge.Contains("예산"))
            {
                return "예산 회복";
            }

            if (objective.challenge.Contains("지원"))
            {
                return "지원 폭 확장";
            }
        }

        return "후속 검증";
    }

    private void StartGrowthObjectiveCampaign()
    {
        if (!TryBuildCareerGrowthObjective(out NextCampaignObjective objective, out _))
        {
            UpdateMenuStatus("성장 목표는 완료 기록이 2회 이상일 때 생성됩니다.");
            UpdateMenuGrowthObjectiveButton();
            return;
        }

        pendingNextCampaignObjective = objective;
        hasPendingNextCampaignObjective = true;
        pendingCaseReplayObjectiveReady = false;
        pendingCaseReplayObjectiveCaseId = "";
        pendingCaseReplayObjectiveChallenge = "";
        StartRecommendedCampaign();
    }

    private void StartGrowthFollowUpObjectiveCampaign()
    {
        if (!hasPendingNextCampaignObjective ||
            (!IsGrowthFollowUpObjective(pendingNextCampaignObjective) && !IsAppealRemedyObjective(pendingNextCampaignObjective)))
        {
            if (TryBuildAppealRemedyGraphTriageMenuObjective(out NextCampaignObjective triageObjective, out CareCase triageCase, out _))
            {
                pendingNextCampaignObjective = triageObjective;
                hasPendingNextCampaignObjective = true;
                pendingCaseReplayObjectiveReady = true;
                pendingCaseReplayObjectiveCaseId = triageCase.id;
                pendingCaseReplayObjectiveChallenge = triageObjective.challenge;
                StartRecommendedCampaign();
                return;
            }

            UpdateMenuStatus("후속/보정 목표는 직전 목표 완료 후 추천 대기 상태에서 시작됩니다.");
            UpdateMenuGrowthFollowUpObjectiveButton();
            return;
        }

        StartRecommendedCampaign();
    }

    private bool TryBuildAppealRemedyGraphTriageMenuObjective(out NextCampaignObjective objective, out CareCase careCase, out AppealRemedyGraphTriageItem item)
    {
        objective = new NextCampaignObjective(CampaignMandate.Standard, "", "");
        careCase = null;
        item = null;
        if (!TryGetSelectedAppealRemedyGraphTriageRecommendation(out item, out careCase, out _) || careCase == null)
        {
            return false;
        }

        objective = BuildCaseReplayObjective(careCase);
        return IsAppealRemedyObjective(objective) &&
            (objective.challenge.Contains("보정 추천") || objective.challenge.Contains("보정 분류"));
    }

    private void StartCareerRecordNextObjective()
    {
        CareerRecord record = CurrentCareerRecordDetailRecord();
        if (record == null || string.IsNullOrWhiteSpace(record.nextCampaignChallenge))
        {
            if (careerRecordStatusText != null)
            {
                careerRecordStatusText.text = "선택 회차에 다시 시작할 다음 목표가 없습니다.";
            }
            UpdateCareerRecordNextObjectiveButton(record);
            return;
        }

        pendingNextCampaignObjective = new NextCampaignObjective(
            CampaignMandateFromId(record.nextCampaignMandateId),
            record.nextCampaignChallenge,
            record.nextCampaignReason);
        hasPendingNextCampaignObjective = true;
        bool appealRemedyNextObjective = IsAppealRemedyObjective(pendingNextCampaignObjective);
        pendingCaseReplayObjectiveReady = appealRemedyNextObjective;
        pendingCaseReplayObjectiveCaseId = appealRemedyNextObjective
            ? FallbackText(record.appealRemedyObjectiveCaseId, record.caseObjectiveSourceId)
            : "";
        pendingCaseReplayObjectiveChallenge = appealRemedyNextObjective ? record.nextCampaignChallenge : "";
        StartRecommendedCampaign();
    }

    private static bool TryBuildCareerGrowthObjective(out NextCampaignObjective objective, out string focusLabel)
    {
        objective = new NextCampaignObjective(CampaignMandate.Standard, "", "");
        focusLabel = "";
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        if (database.records == null || database.records.Count < 2)
        {
            return false;
        }

        CareerRecord latest = database.records[0];
        CareerRecord previous = FindPreviousCareerRecord(database.records, latest);
        if (latest == null || previous == null)
        {
            return false;
        }

        int scoreDelta = latest.campaignScore - previous.campaignScore;
        int matchDelta = Mathf.RoundToInt(latest.recommendedMatchRatePercent - previous.recommendedMatchRatePercent);
        int riskDelta = CareerRecordRiskScore(latest) - CareerRecordRiskScore(previous);
        int budgetDelta = latest.finalBudget - previous.finalBudget;
        int riskScore = CareerRecordRiskScore(latest);
        string reason =
            $"최근 성장 기반: 직전 대비 점수 {SignedNumber(scoreDelta)}점, 권장 {SignedNumber(matchDelta)}p, 위험 {SignedNumber(riskDelta)}p, 예산 {SignedNumber(budgetDelta)}만";

        if (riskDelta > 0 || riskScore >= 70)
        {
            focusLabel = "위험 회복";
            objective = new NextCampaignObjective(
                CampaignMandate.AusterityAudit,
                $"성장 목표: 위험 지표 {Mathf.Max(8, Mathf.Abs(riskDelta) + 4)}p 낮추기",
                reason + " · 위험 증가를 먼저 되돌리는 긴축 감사 회차");
            return true;
        }

        if (matchDelta < 0 || latest.recommendedMatchRatePercent < 60f)
        {
            focusLabel = "권장 회복";
            objective = new NextCampaignObjective(
                CampaignMandate.Standard,
                $"성장 목표: 권장 판단 일치율 {Mathf.Clamp(Mathf.RoundToInt(latest.recommendedMatchRatePercent) + 10, 60, 90)}% 달성",
                reason + " · 권장 판단 일치율을 회복하는 균형 심사 회차");
            return true;
        }

        if (budgetDelta < 0 || latest.finalBudget < 0)
        {
            focusLabel = "예산 회복";
            objective = new NextCampaignObjective(
                CampaignMandate.AusterityAudit,
                $"성장 목표: 예산 손실 {Mathf.Max(120, Mathf.Abs(budgetDelta))}만원 줄이기",
                reason + " · 예산 손실을 줄이는 긴축 감사 회차");
            return true;
        }

        focusLabel = "상승 유지";
        objective = new NextCampaignObjective(
            CampaignMandate.SupportExpanded,
            "성장 목표: 판단 품질 유지하며 고위험 지원/조사 균형",
            reason + " · 상승세를 유지하며 고위험 사례 대응 폭을 넓히는 지원 확대 회차");
        return true;
    }

    private static bool IsGrowthObjective(NextCampaignObjective objective)
    {
        return !string.IsNullOrWhiteSpace(objective.reason) && objective.reason.Contains("최근 성장 기반");
    }

    private static bool IsGrowthFollowUpObjective(NextCampaignObjective objective)
    {
        return (!string.IsNullOrWhiteSpace(objective.challenge) &&
                (objective.challenge.Contains("성장 후속") || objective.challenge.Contains("성장 보정"))) ||
            (!string.IsNullOrWhiteSpace(objective.reason) &&
                (objective.reason.Contains("성장 목표 성공") || objective.reason.Contains("성장 목표 미달")));
    }

