    private void UpdateSaveSlotButtons()
    {
        if (saveSlotButtons == null)
        {
            return;
        }

        for (int i = 0; i < saveSlotButtons.Length; i++)
        {
            int slot = i + 1;
            bool selected = slot == activeSaveSlot;
            bool exists = File.Exists(SavePathForSlot(slot));
            Image image = saveSlotButtons[i].GetComponent<Image>();
            if (selected)
            {
                image.color = new Color32(96, 129, 67, 238);
            }
            else if (exists)
            {
                image.color = new Color32(65, 82, 104, 210);
            }
            else
            {
                image.color = new Color32(60, 62, 62, 170);
            }
        }

        UpdateDeleteSaveSlotButton();
    }

    private void UpdateDeleteSaveSlotButton()
    {
        if (deleteSaveSlotButton == null)
        {
            return;
        }

        bool exists = File.Exists(SavePath);
        bool confirming = exists && pendingDeleteSlot == activeSaveSlot;
        deleteSaveSlotButton.interactable = exists;

        Image image = deleteSaveSlotButton.GetComponent<Image>();
        if (image != null)
        {
            image.color = !exists
                ? new Color32(60, 62, 62, 150)
                : (confirming ? new Color32(150, 62, 47, 238) : new Color32(116, 82, 50, 220));
