    private void UpdateEndingGalleryContent()
    {
        EndingOutcome[] endings = BuildEndingCatalog();
        CareerRecordDatabase careerDatabase = LoadCareerRecordDatabase();
        EndingInvestigationHighlight[] followUpHighlights = BuildEndingInvestigationHighlights(endings, careerDatabase.records);
        EndingReplayDecoration[] replayDecorations = BuildEndingReplayDecorations(endings, careerDatabase.records);
        int discoveredCount = CountDiscoveredEndings(endings);
        int mandateDiscoveredCount = CountDiscoveredEndingsForMandate(campaignMandate, endings);
        int followUpHighlightCount = CountEndingInvestigationHighlights(followUpHighlights);
        int replayDecorationCount = CountEndingReplayDecorations(replayDecorations);
        string lastEndingId = PlayerPrefs.GetString(LastEndingForMandateKey(campaignMandate), "");
        if (string.IsNullOrEmpty(lastEndingId))
        {
            lastEndingId = PlayerPrefs.GetString(LastEndingPrefsKey, "");
        }
        string lastEndingTitle = "";
        foreach (EndingOutcome ending in endings)
        {
            if (ending.id == lastEndingId)
            {
                lastEndingTitle = ending.title;
                break;
            }
        }

        endingGalleryStatusText.text =
            $"운영 기준: {CampaignMandateLabel(campaignMandate)} · 기준별 발견: {mandateDiscoveredCount} / {endings.Length} · 전체 발견: {discoveredCount} / {endings.Length}" +
            $" · 후속 필터: {(endingGalleryFollowUpFilterActive ? "켜짐" : "꺼짐")} · 후속 많은 엔딩: {followUpHighlightCount}" +
            $" · 상위 장식: {replayDecorationCount}" +
            (string.IsNullOrEmpty(lastEndingTitle) ? "" : $" · 마지막 엔딩: {lastEndingTitle}");

        if (endingGalleryFollowUpFilterButtonText != null)
        {
            endingGalleryFollowUpFilterButtonText.text = endingGalleryFollowUpFilterActive ? "전체 보기" : "후속 보기";
        }

        for (int i = 0; i < endings.Length; i++)
        {
            bool discovered = IsEndingDiscovered(endings[i].id);
            bool mandateDiscovered = IsEndingDiscoveredForMandate(campaignMandate, endings[i].id);
            EndingInvestigationHighlight highlight = i < followUpHighlights.Length ? followUpHighlights[i] : null;
            EndingReplayDecoration decoration = i < replayDecorations.Length ? replayDecorations[i] : null;
            bool hasFollowUpHighlight = highlight != null && highlight.hasHighlight;
            bool hasLinkedRecord = TryFindLinkedEndingCareerRecord(endings[i].id, careerDatabase.records, endingGalleryFollowUpFilterActive, out _, out string linkType);
            if (endingGalleryFollowUpFilterActive)
            {
                endingGalleryImages[i].color = hasFollowUpHighlight
                    ? Color.white
                    : new Color(0.2f, 0.2f, 0.2f, 0.42f);
            }
            else
            {
                endingGalleryImages[i].color = mandateDiscovered
                    ? Color.white
                    : (discovered ? new Color(0.72f, 0.72f, 0.72f, 0.72f) : new Color(0.25f, 0.25f, 0.25f, 0.52f));
            }
            endingGalleryCardTexts[i].text = EndingGalleryCardText(endings[i], discovered, mandateDiscovered, highlight, decoration, endingGalleryFollowUpFilterActive);
            if (endingGalleryRecordButtons != null && i < endingGalleryRecordButtons.Length && endingGalleryRecordButtons[i] != null)
            {
                endingGalleryRecordButtons[i].gameObject.SetActive(hasLinkedRecord);
                if (endingGalleryRecordButtonTexts != null && i < endingGalleryRecordButtonTexts.Length && endingGalleryRecordButtonTexts[i] != null)
                {
                    endingGalleryRecordButtonTexts[i].text = linkType;
                    endingGalleryRecordButtonTexts[i].fontSize = linkType.Length > 5 ? 14 : 15;
                }
            }
        }
    }

    private string EndingGalleryCardText(EndingOutcome ending, bool discovered, bool mandateDiscovered, EndingInvestigationHighlight followUpHighlight, EndingReplayDecoration replayDecoration, bool followUpFilterActive)
    {
        bool hasFollowUpHighlight = followUpHighlight != null && followUpHighlight.hasHighlight;
        if (followUpFilterActive && !hasFollowUpHighlight)
        {
            return
                $"{ending.title}\n후속 많은 회차 없음\n" +
                $"조사 후속 {EndingInvestigationHighlightThreshold}건 이상 완료 기록이 없습니다.\n\n" +
                "추가조사 근거를 다음 날 처리한 회차가 이 카드에 배지로 남습니다.";
        }

        string followUpBadge = hasFollowUpHighlight ? "\n" + EndingInvestigationBadgeText(followUpHighlight) : "";
        string replayBadge = replayDecoration != null && replayDecoration.hasDecoration ? "\n" + EndingReplayDecorationText(replayDecoration) : "";
        if (mandateDiscovered)
        {
            return $"{ending.title}\n현재 운영 기준에서 발견{followUpBadge}{replayBadge}\n{ending.summary}\n\n후속: {Shorten(ending.epilogue, 48)}";
        }

        if (discovered)
        {
            return $"{ending.title}\n다른 운영 기준에서 발견{followUpBadge}{replayBadge}\n{ending.summary}\n\n이 기준으로 다시 완료하면 기록이 채워집니다.";
        }

        if (hasFollowUpHighlight)
        {
            return $"{ending.title}\n커리어 기록에서 발견{followUpBadge}{replayBadge}\n{ending.summary}\n\n기록 데이터 기준으로 후속 회차를 복원했습니다.";
        }

        if (replayDecoration != null && replayDecoration.hasDecoration)
        {
            return $"{ending.title}\n반복 목표 기록에서 발견{replayBadge}\n{ending.summary}\n\n상위 반복 챌린지 기록으로 장식을 복원했습니다.";
        }

        return "미발견 엔딩\n다른 판단 성향으로 5일차 캠페인을 완료하면 이 기록이 열립니다.\n\n예산, 민원, 누락 위험 중 어떤 압력이 커지는지 실험해 보세요.";
    }

    private static EndingInvestigationHighlight[] BuildEndingInvestigationHighlights(EndingOutcome[] endings, List<CareerRecord> records)
    {
        EndingInvestigationHighlight[] highlights = new EndingInvestigationHighlight[endings.Length];
        if (records == null || records.Count == 0)
        {
            return highlights;
        }

        for (int recordIndex = 0; recordIndex < records.Count; recordIndex++)
        {
            CareerRecord record = records[recordIndex];
            if (record == null || record.investigationFollowUpCount < EndingInvestigationHighlightThreshold || string.IsNullOrWhiteSpace(record.endingId))
            {
                continue;
            }

            for (int endingIndex = 0; endingIndex < endings.Length; endingIndex++)
            {
                if (!string.Equals(record.endingId, endings[endingIndex].id, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                EndingInvestigationHighlight highlight = highlights[endingIndex];
                if (highlight == null)
                {
                    highlight = new EndingInvestigationHighlight();
                    highlights[endingIndex] = highlight;
                }

                highlight.runCount++;
                bool betterRecord =
                    !highlight.hasHighlight ||
                    record.investigationFollowUpCount > highlight.maxFollowUpCount ||
                    (record.investigationFollowUpCount == highlight.maxFollowUpCount &&
                        string.Compare(record.completedAt, highlight.completedAt, StringComparison.Ordinal) > 0);
                if (betterRecord)
                {
                    highlight.hasHighlight = true;
                    highlight.maxFollowUpCount = record.investigationFollowUpCount;
                    highlight.completedAt = record.completedAt;
                    highlight.campaignMandateName = record.campaignMandateName;
                    highlight.campaignGrade = record.campaignGrade;
                    highlight.campaignScore = record.campaignScore;
                }
                break;
            }
        }

        return highlights;
    }

    private static int CountEndingInvestigationHighlights(EndingInvestigationHighlight[] highlights)
    {
        int count = 0;
        if (highlights == null)
        {
            return count;
        }

        for (int i = 0; i < highlights.Length; i++)
        {
            if (highlights[i] != null && highlights[i].hasHighlight)
            {
                count++;
            }
        }

        return count;
    }

    private static string EndingInvestigationBadgeText(EndingInvestigationHighlight highlight)
    {
        if (highlight == null || !highlight.hasHighlight)
        {
            return "";
        }

        string completed = string.IsNullOrWhiteSpace(highlight.completedAt) ? "" : " · " + Shorten(highlight.completedAt, 10);
        return $"조사 후속 배지: {highlight.maxFollowUpCount}건 · {Shorten(highlight.campaignMandateName, 6)} · {highlight.campaignGrade}{highlight.campaignScore}점{completed}";
    }

    private static EndingReplayDecoration[] BuildEndingReplayDecorations(EndingOutcome[] endings, List<CareerRecord> records)
    {
        EndingReplayDecoration[] decorations = new EndingReplayDecoration[endings.Length];
        if (records == null || records.Count == 0)
        {
            return decorations;
        }

        for (int recordIndex = 0; recordIndex < records.Count; recordIndex++)
        {
            CareerRecord record = records[recordIndex];
            if (record == null ||
                record.replayObjectiveCompletionCount < AdvancedReplayDecorationThreshold ||
                string.IsNullOrWhiteSpace(record.endingId))
            {
                continue;
            }

            for (int endingIndex = 0; endingIndex < endings.Length; endingIndex++)
            {
                if (!string.Equals(record.endingId, endings[endingIndex].id, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                EndingReplayDecoration decoration = decorations[endingIndex];
                if (decoration == null)
                {
                    decoration = new EndingReplayDecoration();
                    decorations[endingIndex] = decoration;
                }

                bool betterRecord =
                    !decoration.hasDecoration ||
                    record.replayObjectiveCompletionCount > decoration.replayObjectiveCompletionCount ||
                    (record.replayObjectiveCompletionCount == decoration.replayObjectiveCompletionCount &&
                        string.Compare(record.completedAt, decoration.completedAt, StringComparison.Ordinal) > 0);
                if (betterRecord)
                {
                    decoration.hasDecoration = true;
                    decoration.replayObjectiveCompletionCount = record.replayObjectiveCompletionCount;
                    decoration.tier = AdvancedReplayChallengeTier(record.replayObjectiveCompletionCount);
                    decoration.badge = AdvancedReplayChallengeBadge(record.replayObjectiveCompletionCount);
                    decoration.decoration = AdvancedReplayChallengeDecoration(record.replayObjectiveCompletionCount);
                    decoration.completedAt = record.completedAt;
                    decoration.campaignMandateName = record.campaignMandateName;
                    decoration.campaignGrade = record.campaignGrade;
                    decoration.campaignScore = record.campaignScore;
                }
                break;
            }
        }

        return decorations;
    }

    private static int CountEndingReplayDecorations(EndingReplayDecoration[] decorations)
    {
        int count = 0;
        if (decorations == null)
        {
            return count;
        }

        for (int i = 0; i < decorations.Length; i++)
        {
            if (decorations[i] != null && decorations[i].hasDecoration)
            {
                count++;
            }
        }

        return count;
    }

    private static string EndingReplayDecorationText(EndingReplayDecoration decoration)
    {
        if (decoration == null || !decoration.hasDecoration)
        {
            return "";
        }

        string completed = string.IsNullOrWhiteSpace(decoration.completedAt) ? "" : " · " + Shorten(decoration.completedAt, 10);
        return $"반복 장식: {decoration.decoration} · {decoration.replayObjectiveCompletionCount}회 · {Shorten(decoration.campaignMandateName, 6)} · {decoration.campaignGrade}{decoration.campaignScore}점{completed}";
    }

    private static bool TryFindLinkedEndingCareerRecord(string endingId, List<CareerRecord> records, bool requireFollowUpHighlight, out CareerRecord linkedRecord, out string linkType)
    {
        linkedRecord = null;
        linkType = "관련 기록";
        if (string.IsNullOrWhiteSpace(endingId) || records == null || records.Count == 0)
        {
            return false;
        }

        int bestScore = int.MinValue;
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null || !string.Equals(record.endingId, endingId, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            bool hasFollowUp = record.investigationFollowUpCount >= EndingInvestigationHighlightThreshold;
            bool hasReplayDecoration = record.replayObjectiveCompletionCount >= AdvancedReplayDecorationThreshold;
            if (requireFollowUpHighlight && !hasFollowUp)
            {
                continue;
            }
            if (!hasFollowUp && !hasReplayDecoration)
            {
                continue;
            }

            int score =
                (hasFollowUp ? 100000 + record.investigationFollowUpCount * 1000 : 0) +
                (hasReplayDecoration ? 50000 + record.replayObjectiveCompletionCount * 500 : 0) +
                Mathf.Clamp(record.campaignScore, 0, 999);
            if (linkedRecord == null ||
                score > bestScore ||
                (score == bestScore && string.Compare(record.completedAt, linkedRecord.completedAt, StringComparison.Ordinal) > 0))
            {
                bestScore = score;
                linkedRecord = record;
            }
        }

        if (linkedRecord == null)
        {
            return false;
        }

        bool linkedFollowUp = linkedRecord.investigationFollowUpCount >= EndingInvestigationHighlightThreshold;
        bool linkedReplay = linkedRecord.replayObjectiveCompletionCount >= AdvancedReplayDecorationThreshold;
        linkType = linkedFollowUp
            ? (linkedReplay ? "후속+장식" : "후속 기록")
            : "장식 기록";
        return true;
    }

