                linkedRecord = record;
            }
        }

        return linkedRecord != null;
    }

    private static bool TryFindReplayObjectiveCareerRecordForTier(List<CareerRecord> records, int threshold, out CareerRecord linkedRecord)
    {
        linkedRecord = null;
        if (records == null || records.Count == 0)
        {
            return false;
        }

        int bestScore = int.MinValue;
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (!IsReplayObjectiveRecord(record) || record.replayObjectiveCompletionCount < threshold)
            {
                continue;
            }

            int distancePenalty = Mathf.Abs(record.replayObjectiveCompletionCount - threshold) * 1000;
            int score =
                100000 -
                distancePenalty +
                Mathf.Clamp(record.campaignScore, 0, 999);
            if (linkedRecord == null ||
                score > bestScore ||
                (score == bestScore && string.Compare(record.completedAt, linkedRecord.completedAt, StringComparison.Ordinal) > 0))
            {
                bestScore = score;
                linkedRecord = record;
            }
        }

        return linkedRecord != null;
    }

