    private static bool TryFindDecisionPracticeCareerRecordForTier(List<CareerRecord> records, int threshold, out CareerRecord linkedRecord)
    {
        linkedRecord = null;
        if (records == null || records.Count == 0 || threshold <= 0)
        {
            return false;
        }

        List<CareerRecord> practiceRecords = new();
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record != null && record.decisionPracticeObjectiveCompleted)
            {
                practiceRecords.Add(record);
            }
        }

        practiceRecords.Sort(CompareCareerRecordsChronological);
        for (int i = 0; i < practiceRecords.Count; i++)
        {
            if (i + 1 >= threshold)
            {
                linkedRecord = practiceRecords[i];
                return true;
            }
        }

        return false;
    }

    private static int CompareCareerRecordsChronological(CareerRecord left, CareerRecord right)
    {
        string leftKey = left == null ? "" : (!string.IsNullOrWhiteSpace(left.completedAt) ? left.completedAt : left.campaignStartedAt);
        string rightKey = right == null ? "" : (!string.IsNullOrWhiteSpace(right.completedAt) ? right.completedAt : right.campaignStartedAt);
        int dateCompare = string.Compare(leftKey, rightKey, StringComparison.Ordinal);
        if (dateCompare != 0)
        {
            return dateCompare;
        }

        string leftId = left == null ? "" : left.sessionId;
        string rightId = right == null ? "" : right.sessionId;
        return string.Compare(leftId, rightId, StringComparison.Ordinal);
    }

    private static CareerRecord FindCareerRecordByIdentity(List<CareerRecord> records, string sessionId, string startedAt)
    {
        if (records == null || records.Count == 0)
        {
            return null;
        }

        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null)
            {
                continue;
            }

            if (!string.IsNullOrEmpty(sessionId) && record.sessionId == sessionId)
            {
                return record;
            }
            if (!string.IsNullOrEmpty(startedAt) && record.campaignStartedAt == startedAt)
            {
                return record;
            }
        }

        return null;
    }

    private static bool IsSameCareerRecord(CareerRecord left, CareerRecord right)
    {
        if (left == null || right == null)
        {
            return false;
        }

        if (!string.IsNullOrEmpty(left.sessionId) && left.sessionId == right.sessionId)
        {
            return true;
        }

        return !string.IsNullOrEmpty(left.campaignStartedAt) && left.campaignStartedAt == right.campaignStartedAt;
    }

