        UpdateAchievementReplayRecordButton();
        UpdateAchievementGrowthRecordButtons();
        UpdateAchievementAppealRemedyRecordButton();
        UpdateAchievementDecisionPracticeRecordButton();
        UpdateAchievementDecisionPracticeTierRecordButtons(decisionPracticeObjectiveCount);
        UpdateAchievementNextGoalButton(achievements);
        UpdateAchievementAppealRemedyTriageCandidateButton(false);
    }

