    private void OpenAchievementNextGoalAction()
    {
        AchievementDefinition[] achievements = BuildAchievementCatalog();
        if (!TryGetNextLockedAchievement(achievements, out AchievementDefinition achievement))
        {
            ShowCareerRecords();
            return;
        }

        switch (achievement.id)
        {
            case "analytics_export":
                ShowReport();
                ShowDecisionAudit();
                return;
            case "agent_lab":
                ShowReport();
                RunAgentSimulation();
                return;
            case "case_objective_replay":
                ShowRecommendedCaseObjectiveArchive();
                return;
            case "appeal_remedy_objective":
                if (TryBuildAppealRemedyGraphTriageMenuObjective(out _, out CareCase triageCase, out AppealRemedyGraphTriageItem triageItem))
                {
                    ShowCaseArchiveForCase(triageCase.id);
                    if (caseArchiveStatusText != null)
                    {
                        caseArchiveStatusText.text =
                            "성과 보정 추천: " +
                            BuildAppealRemedyGraphTriageRecommendationSummary(triageItem, triageCase, false) +
                            " · 목표 심사로 바로 시작 가능\n" +
                            caseArchiveStatusText.text;
                    }
                    return;
                }

                ShowCaseArchive();
                if (caseArchiveStatusText != null)
                {
                    caseArchiveStatusText.text = "보정 사례 목표: 이의제기 필터 큐에서 보정 목표 심사를 시작하세요.\n" + caseArchiveStatusText.text;
                }
                return;
            case "decision_practice_objective":
                ShowCaseArchive();
                if (caseArchiveStatusText != null)
                {
                    caseArchiveStatusText.text = "판단 비교 연습 목표: 사례 상세의 비교 연습 버튼으로 권장 판단 기준 회차를 시작하세요.\n" + caseArchiveStatusText.text;
                }
                return;
            case "growth_objective_success":
                if (TryBuildCareerGrowthObjective(out _, out _))
                {
                    StartGrowthObjectiveCampaign();
                }
                else
                {
                    ShowCareerRecords();
                }
                return;
            case "growth_follow_up_complete":
                if (hasPendingNextCampaignObjective && IsGrowthFollowUpObjective(pendingNextCampaignObjective))
                {
                    StartRecommendedCampaign();
                }
                else
                {
                    ShowMainMenu();
                }
                return;
            default:
                StartNewCampaign();
                return;
        }
    }

