        if (database.records.Count == 0)
        {
            careerRecordStatusText.text = "완료한 캠페인 기록이 없습니다.";
            careerRecordBodyText.text =
                "5일차 최종 리포트를 열면 이 화면에 캠페인 기록이 저장됩니다.\n\n" +
                "기록에는 운영 기준, 엔딩, 운영 등급, 캠페인 챌린지, 권장 판단 일치율, 최종 예산/안정/형평/누락/민원 지표, 다음 캠페인 목표가 함께 남습니다.\n\n" +
                "이 화면은 엔딩 수집과 업적 외에도 반복 플레이 결과를 비교할 수 있게 해 주는 장기 기록판입니다.";
            if (careerRecordDetailText != null)
            {
                careerRecordDetailText.text = "선택 회차 상세\n완료 기록이 생기면 고압력 대표 사례와 조사 메모가 여기에 표시됩니다.";
            }
            UpdateCareerRecordCaseLinkButtons(null);
            UpdateCareerRecordNextObjectiveButton(null);
            UpdateCareerRecordActionHint(null);
            UpdateCareerRecordMandateFilterButtons();
            return;
        }

        List<CareerRecord> visibleRecords = FilterCareerRecordsByMandate(database.records, careerRecordMandateFilterId);
        string filterLabel = CareerRecordMandateFilterLabel(careerRecordMandateFilterId);
        if (visibleRecords.Count == 0)
        {
            careerRecordStatusText.text = $"기록 0회 · 필터: {filterLabel} · 전체 기록 {database.records.Count}회";
            careerRecordBodyText.text =
                $"최근 캠페인 기록 · 기준 필터: {filterLabel}\n" +
                BuildCareerRecordMandateTrendLine(database.records) +
                "\n\n선택한 운영 기준의 캠페인 기록이 없습니다.\n" +
                "헤더의 전체/균형/지원/긴축 필터로 다른 기준의 반복 플레이 이력을 확인할 수 있습니다.";
            if (careerRecordDetailText != null)
            {
                careerRecordDetailText.text = $"선택 회차 상세\n{filterLabel} 기준 기록이 생기면 대표 사례와 조사 메모가 여기에 표시됩니다.";
            }
            UpdateCareerRecordCaseLinkButtons(null);
            UpdateCareerRecordNextObjectiveButton(null);
            UpdateCareerRecordActionHint(null);
            UpdateCareerRecordMandateFilterButtons();
            return;
        }

        CareerRecord focusedRecord = FindCareerRecordByIdentity(visibleRecords, focusedCareerRecordSessionId, focusedCareerRecordStartedAt);
        CareerRecord selectedRecord = focusedRecord ?? visibleRecords[0];
        careerRecordStatusText.text = BuildCareerRecordStatusText(visibleRecords) + $" · 필터: {filterLabel}";
        careerRecordBodyText.text = BuildCareerRecordBodyText(visibleRecords, focusedRecord, focusedCareerRecordSourceLabel, filterLabel, careerRecordStoreCandidateCompactMode);
        if (careerRecordDetailText != null)
        {
            careerRecordDetailText.text = careerRecordStoreCandidateCompactMode
                ? BuildCareerRecordStoreCandidateDetailText(selectedRecord, focusedRecord != null, database.records)
                : BuildCareerRecordDetailText(selectedRecord, focusedRecord != null, database.records);
        }
        UpdateCareerRecordCaseLinkButtons(selectedRecord);
        UpdateCareerRecordNextObjectiveButton(selectedRecord);
        UpdateCareerRecordActionHint(selectedRecord);
        UpdateCareerRecordMandateFilterButtons();
    }

    private CareerRecord CurrentCareerRecordDetailRecord()
    {
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        if (database.records.Count == 0)
        {
            return null;
        }

        List<CareerRecord> visibleRecords = FilterCareerRecordsByMandate(database.records, careerRecordMandateFilterId);
        if (visibleRecords.Count == 0)
        {
            return null;
        }

        return FindCareerRecordByIdentity(visibleRecords, focusedCareerRecordSessionId, focusedCareerRecordStartedAt) ?? visibleRecords[0];
    }

    private void UpdateCareerRecordCaseLinkButtons(CareerRecord record)
    {
        UpdateCareerRecordCaseLinkButton(
            careerRecordRepresentativeCaseButton,
            careerRecordRepresentativeCaseButtonText,
            !string.IsNullOrWhiteSpace(record?.representativeCaseId),
            string.IsNullOrWhiteSpace(record?.representativeCaseId) ? "대표 없음" : "대표 사례");
        UpdateCareerRecordCaseLinkButton(
            careerRecordInvestigationMemoButton,
            careerRecordInvestigationMemoButtonText,
            !string.IsNullOrWhiteSpace(record?.investigationMemoCaseId),
            string.IsNullOrWhiteSpace(record?.investigationMemoCaseId) ? "조사 없음" : "조사 사례");
        UpdateCareerRecordCaseLinkButton(
            careerRecordAppealRemedyCaseButton,
            careerRecordAppealRemedyCaseButtonText,
            !string.IsNullOrWhiteSpace(record?.appealRemedyObjectiveCaseId),
            string.IsNullOrWhiteSpace(record?.appealRemedyObjectiveCaseId)
                ? "보정 없음"
                : (!string.IsNullOrWhiteSpace(record?.appealRemedyObjectiveTriageLabel) ? "추천 큐" : "보정 사례"));
    }

    private void UpdateCareerRecordNextObjectiveButton(CareerRecord record)
    {
        bool active = record != null && !string.IsNullOrWhiteSpace(record.nextCampaignChallenge);
        if (careerRecordNextObjectiveButton != null)
        {
            careerRecordNextObjectiveButton.interactable = active;
            Image image = careerRecordNextObjectiveButton.GetComponent<Image>();
            if (image != null)
            {
                image.color = active ? new Color32(116, 82, 50, 238) : new Color32(58, 58, 58, 156);
            }
        }

        if (careerRecordNextObjectiveButtonText != null)
        {
            careerRecordNextObjectiveButtonText.text = active ? CareerRecordNextObjectiveButtonLabel(record) : "목표 없음";
            careerRecordNextObjectiveButtonText.fontSize = active && careerRecordNextObjectiveButtonText.text.Length > 5 ? 13 : 14;
        }
    }

    private void UpdateCareerRecordActionHint(CareerRecord record)
    {
        if (careerRecordActionHintText == null)
        {
            return;
        }

        if (record == null)
        {
            careerRecordActionHintText.text = "액션 안내: 완료 기록에서 대표 사례, 조사 메모, 보정 사례, 다음 목표를 열 수 있습니다.";
            return;
        }

        string representative = string.IsNullOrWhiteSpace(record.representativeCaseId)
            ? "대표 없음"
            : "대표 " + Shorten(record.representativeCaseId, 12);
        string investigation = string.IsNullOrWhiteSpace(record.investigationMemoCaseId)
            ? "조사 없음"
            : "조사 " + Shorten(record.investigationMemoCaseId, 12);
        string remedy = string.IsNullOrWhiteSpace(record.appealRemedyObjectiveCaseId)
            ? "보정 없음"
            : (!string.IsNullOrWhiteSpace(record.appealRemedyObjectiveTriageLabel)
                ? "보정 추천 " + Shorten(record.appealRemedyObjectiveCaseId, 12)
                : "보정 " + Shorten(record.appealRemedyObjectiveCaseId, 12));
        string coaching = string.IsNullOrWhiteSpace(record.decisionAuditCoachingAppealCaseId)
            ? ""
            : " · 복기 " + Shorten(record.decisionAuditCoachingAppealCaseId, 8) + " 기록 복귀";
        string next = "목표 없음";
        if (!string.IsNullOrWhiteSpace(record.nextCampaignChallenge))
        {
            string nextLabel = CareerRecordNextObjectiveButtonLabel(record);
            next = nextLabel == "목표 재시작" ? "다음 목표" : "다음 목표 " + nextLabel;
        }

        careerRecordActionHintText.text = $"액션 안내: {representative} · {investigation} · {remedy} · {next}{coaching}";
    }

    private static string CareerRecordNextObjectiveButtonLabel(CareerRecord record)
    {
        if (record == null || string.IsNullOrWhiteSpace(record.nextCampaignChallenge))
        {
            return "목표 없음";
        }

        if (record.nextCampaignChallenge.Contains("성장 후속"))
        {
            return "후속 심사";
        }

        if (record.nextCampaignChallenge.Contains("성장 보정"))
        {
            return "보정 심사";
        }

        if (record.nextCampaignChallenge.Contains("성장 목표"))
        {
            return "성장 심사";
        }

        if (record.nextCampaignChallenge.Contains("이의제기") &&
            record.nextCampaignChallenge.Contains("보정"))
        {
            return "보정 심사";
        }

        return "목표 재시작";
    }

    private void UpdateCareerRecordMandateFilterButtons()
    {
        if (careerRecordMandateFilterButtons == null)
        {
            return;
        }

        string[] filterIds =
        {
            "",
            CampaignMandateId(CampaignMandate.Standard),
            CampaignMandateId(CampaignMandate.SupportExpanded),
            CampaignMandateId(CampaignMandate.AusterityAudit),
            CareerRecordGrowthFilterId,
            CareerRecordGrowthFollowUpFilterId,
            CareerRecordAppealRemedyFilterId,
            CareerRecordAppealTriageFilterId,
            CareerRecordDecisionPracticeFilterId
        };
        CareerRecordDatabase database = LoadCareerRecordDatabase();

        for (int i = 0; i < careerRecordMandateFilterButtons.Length && i < filterIds.Length; i++)
        {
            Button button = careerRecordMandateFilterButtons[i];
            if (button == null)
            {
                continue;
            }

            bool active = string.Equals(careerRecordMandateFilterId ?? "", filterIds[i], StringComparison.Ordinal);
            Image image = button.GetComponent<Image>();
            if (image != null)
            {
                image.color = active ? new Color32(96, 129, 67, 238) : new Color32(48, 60, 58, 226);
            }

            if (careerRecordMandateFilterButtonTexts != null &&
                i < careerRecordMandateFilterButtonTexts.Length &&
                careerRecordMandateFilterButtonTexts[i] != null)
            {
                careerRecordMandateFilterButtonTexts[i].text =
                    CareerRecordMandateFilterButtonText(filterIds[i], CountCareerRecordsForFilter(database.records, filterIds[i]));
                careerRecordMandateFilterButtonTexts[i].fontSize = 12;
                careerRecordMandateFilterButtonTexts[i].lineSpacing = 0.9f;
            }
        }
    }

    private static void UpdateCareerRecordCaseLinkButton(Button button, Text label, bool active, string text)
    {
        if (button != null)
        {
            button.interactable = active;
            Image image = button.GetComponent<Image>();
            if (image != null)
            {
                image.color = active ? new Color32(72, 94, 96, 238) : new Color32(58, 58, 58, 156);
            }
        }

        if (label != null)
        {
            label.text = text;
            label.fontSize = text.Length > 4 ? 14 : 15;
        }
    }

    private static List<CareerRecord> FilterCareerRecordsByMandate(List<CareerRecord> records, string mandateId)
    {
        List<CareerRecord> filtered = new();
        if (records == null)
        {
            return filtered;
        }

        if (string.IsNullOrWhiteSpace(mandateId))
        {
            filtered.AddRange(records);
            return filtered;
        }

        if (string.Equals(mandateId, CareerRecordGrowthFilterId, StringComparison.Ordinal))
        {
            for (int i = 0; i < records.Count; i++)
            {
                CareerRecord record = records[i];
                if (record != null && (record.startedFromGrowthObjective || !string.IsNullOrWhiteSpace(record.growthObjectiveTitle)))
                {
                    filtered.Add(record);
                }
            }

            return filtered;
        }

        if (string.Equals(mandateId, CareerRecordGrowthFollowUpFilterId, StringComparison.Ordinal))
        {
            for (int i = 0; i < records.Count; i++)
            {
                CareerRecord record = records[i];
                if (record != null && (record.startedFromGrowthFollowUpObjective || !string.IsNullOrWhiteSpace(record.growthFollowUpTitle)))
                {
                    filtered.Add(record);
                }
            }

            return filtered;
        }

        if (string.Equals(mandateId, CareerRecordAppealRemedyFilterId, StringComparison.Ordinal))
        {
            for (int i = 0; i < records.Count; i++)
            {
                CareerRecord record = records[i];
                if (record != null && record.appealRemedyObjectiveCompleted)
                {
                    filtered.Add(record);
                }
            }

            return filtered;
        }

        if (string.Equals(mandateId, CareerRecordAppealTriageFilterId, StringComparison.Ordinal))
        {
            for (int i = 0; i < records.Count; i++)
            {
                CareerRecord record = records[i];
                if (record != null &&
                    record.appealRemedyObjectiveCompleted &&
                    !string.IsNullOrWhiteSpace(record.appealRemedyObjectiveTriageLabel))
                {
                    filtered.Add(record);
                }
            }

            return filtered;
        }

        if (string.Equals(mandateId, CareerRecordDecisionPracticeFilterId, StringComparison.Ordinal))
        {
            for (int i = 0; i < records.Count; i++)
            {
                CareerRecord record = records[i];
                if (record != null && record.decisionPracticeObjectiveCompleted)
                {
                    filtered.Add(record);
                }
            }

            return filtered;
        }

        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (string.Equals(record.campaignMandateId, mandateId, StringComparison.Ordinal))
            {
                filtered.Add(record);
            }
        }

        return filtered;
    }

    private static int CountCareerRecordsForFilter(List<CareerRecord> records, string mandateId)
    {
        return FilterCareerRecordsByMandate(records, mandateId).Count;
    }

