    private static string BuildCareerRecordStatusText(List<CareerRecord> records)
    {
        int bestScore = -1;
        string bestGrade = "";
        int scoreTotal = 0;
        int standardCount = 0;
        int supportCount = 0;
        int auditCount = 0;
        int replayObjectiveCount = CountReplayObjectiveRecords(records);
        int decisionPracticeObjectiveCount = CountDecisionPracticeObjectiveRecords(records);

        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record.campaignScore > bestScore)
            {
                bestScore = record.campaignScore;
                bestGrade = record.campaignGrade;
            }

            scoreTotal += record.campaignScore;
            if (record.campaignMandateId == "support_expanded")
            {
                supportCount++;
            }
            else if (record.campaignMandateId == "austerity_audit")
            {
                auditCount++;
            }
            else
            {
                standardCount++;
            }
        }

        float averageScore = records.Count > 0 ? scoreTotal / (float)records.Count : 0f;
        return
            $"기록 {records.Count}회 · 최고 등급 {bestGrade}({bestScore}점) · 평균 {averageScore:0.0}점 · " +
            $"균형 {standardCount} / 지원 확대 {supportCount} / 긴축 감사 {auditCount} · 반복 목표 {replayObjectiveCount}회 · 비교 연습 {decisionPracticeObjectiveCount}회";
    }

    private static string BuildCareerRecordBodyText(List<CareerRecord> records, CareerRecord focusedRecord = null, string focusLabel = "", string filterLabel = "", bool storeCandidateCompact = false)
    {
        if (storeCandidateCompact && records != null && records.Count > 0)
        {
            return BuildCareerRecordStoreCandidateBodyText(records, focusedRecord ?? records[0], focusedRecord != null, focusLabel, filterLabel);
        }

        StringBuilder builder = new();
        builder.AppendLine(string.IsNullOrWhiteSpace(filterLabel)
            ? "최근 캠페인 기록 · 보기: 요약 / 최근 회차 / 선택 상세"
            : $"최근 캠페인 기록 · 보기: 요약 / 최근 회차 / 선택 상세 · 기준 필터: {filterLabel}");
        builder.AppendLine(Shorten(BuildCareerRecordTrendPanelLine(records), 86));
        builder.AppendLine(Shorten(BuildCareerRecordMandateTrendLine(records), 94));
        builder.AppendLine(Shorten(BuildCareerRecordGrowthComparisonLine(records, focusedRecord ?? records[0]), 94));
        builder.AppendLine(BuildCareerRecordCompactRepresentativeRetrospectiveLine(focusedRecord ?? records[0], records));
        builder.AppendLine(Shorten(BuildCareerRecordBriefingRetrospectiveLine(focusedRecord ?? records[0]), 92) + " · " + Shorten(BuildCareerRecordGrowthObjectiveSummaryLine(records), 84));
        builder.AppendLine(Shorten(BuildCareerRecordAppealReviewSummaryLine(records), 72) + " · " + Shorten(BuildCareerRecordAppealRemedyObjectiveSummaryLine(records), 72));
        builder.AppendLine(Shorten(BuildCareerRecordDecisionPracticeObjectiveSummaryLine(records), 72) + " · " + Shorten(BuildCareerRecordDecisionAuditCoachingLine(focusedRecord ?? records[0]), 70) + " · 검증 질문");
        builder.AppendLine();
        builder.AppendLine("최근 회차");
        builder.AppendLine("완료일          기준     등급  챌린지  권장   지표          다음 목표");

        int limit = Mathf.Min(records.Count, 3);
        for (int i = 0; i < limit; i++)
        {
            CareerRecord record = records[i];
            string focusMarker = IsSameCareerRecord(record, focusedRecord) ? "▶ " : "  ";
            builder.AppendLine(
                $"{focusMarker}{Shorten(record.completedAt, 13),-13}  " +
                $"{Shorten(record.campaignMandateName, 4),-4}  " +
                $"{record.campaignGrade}{record.campaignScore,3}  " +
                $"{(record.campaignChallengeSucceeded ? "성공" : "미달"),-4}  " +
                $"{record.matchedRecommendedCount}/{record.logCount}({record.recommendedMatchRatePercent:0}%)  " +
                $"{record.finalStability}/{record.finalEquity}/{record.finalMissedRisk}/{record.finalComplaints}  " +
                $"{Shorten(record.nextCampaignMandateName + " " + record.nextCampaignChallenge, 28)}");
        }

        CareerRecord latest = focusedRecord ?? records[0];
        builder.AppendLine();
        if (focusedRecord != null)
        {
            builder.AppendLine($"관련 엔딩 기록 포커스: {focusLabel} · {Shorten(latest.completedAt, 16)}");
        }
        builder.AppendLine(
            (focusedRecord != null ? "선택 회차 세부" : "마지막 회차 세부") +
            $": 아래 상세 패널 · 엔딩 {latest.endingTitle} · 챌린지 {Shorten(latest.campaignChallengeTitle, 22)} · 조사 후속 {latest.investigationFollowUpCount}건 · 내 판단 기준 {FallbackText(latest.closestAgentPersonaName, "기록 없음")}");
        if (!string.IsNullOrWhiteSpace(filterLabel) && !string.IsNullOrWhiteSpace(latest.growthObjectiveTitle))
        {
            builder.AppendLine($"성장 목표: {Shorten(latest.growthObjectiveChallenge, 58)} · 성장 판정 {(latest.growthObjectiveSucceeded ? "성공" : "미달")}");
        }
        if (!string.IsNullOrWhiteSpace(filterLabel) && !string.IsNullOrWhiteSpace(latest.growthFollowUpTitle))
        {
            builder.AppendLine($"성장 후속 목표: {Shorten(latest.growthFollowUpChallenge, 58)} · 성장 후속 근거 {Shorten(latest.growthFollowUpReason, 42)}");
        }
        if (!string.IsNullOrWhiteSpace(filterLabel) && latest.appealRemedyObjectiveCompleted)
        {
            builder.AppendLine($"이의제기 보정 목표 완료: {latest.appealRemedyObjectiveCaseId} · 보정 목표 완료 {latest.appealRemedyObjectiveBadge}");
        }
        string triageResultLine = BuildCareerRecordAppealRemedyTriageResultLine(latest);
        if (!string.IsNullOrWhiteSpace(filterLabel) && !string.IsNullOrWhiteSpace(triageResultLine))
        {
            builder.AppendLine(Shorten(triageResultLine, 86));
        }

        return builder.ToString();
    }

    private static string BuildCareerRecordStoreCandidateBodyText(List<CareerRecord> records, CareerRecord selectedRecord, bool focused, string focusLabel, string filterLabel)
    {
        StringBuilder builder = new();
        builder.AppendLine(string.IsNullOrWhiteSpace(filterLabel)
            ? "기록 요약 · 캠페인 기록 목표 재시작"
            : $"기록 요약 · {filterLabel} 기록 목표 재시작");
        builder.AppendLine(BuildCareerRecordTrendPanelLine(records));
        builder.AppendLine(BuildCareerRecordGrowthComparisonLine(records, selectedRecord));
        builder.AppendLine(BuildCareerRecordCompactRepresentativeRetrospectiveLine(selectedRecord, records));
        builder.AppendLine(Shorten(BuildCareerRecordBriefingRetrospectiveLine(selectedRecord), 116));
        builder.AppendLine(BuildCareerRecordGrowthObjectiveSummaryLine(records));
        builder.AppendLine(BuildCareerRecordDecisionAuditCoachingLine(selectedRecord));
        builder.AppendLine();
        builder.AppendLine("핵심 완료 회차");
        builder.AppendLine("완료일              기준       등급  결과  권장   다음 목표");
        builder.AppendLine("──────────────────────────────────────────────");

        int limit = Mathf.Min(records.Count, 4);
        for (int i = 0; i < limit; i++)
        {
            CareerRecord record = records[i];
            string focusMarker = IsSameCareerRecord(record, selectedRecord) ? "▶ " : "  ";
            builder.AppendLine(
                $"{focusMarker}{Shorten(record.completedAt, 16),-16}  " +
                $"{Shorten(record.campaignMandateName, 6),-6}  " +
                $"{record.campaignGrade}{record.campaignScore,3}  " +
                $"{(record.campaignChallengeSucceeded ? "성공" : "미달"),-4}  " +
                $"{record.matchedRecommendedCount}/{record.logCount}  " +
                $"{Shorten(record.nextCampaignMandateName + " " + record.nextCampaignChallenge, 34)}");
        }

        builder.AppendLine();
        if (focused && !string.IsNullOrWhiteSpace(focusLabel))
        {
            builder.AppendLine($"포커스: {focusLabel} · {selectedRecord.completedAt}");
        }
        builder.AppendLine($"다음 목표: {Shorten(selectedRecord.nextCampaignMandateName + " " + selectedRecord.nextCampaignChallenge, 82)}");
        if (!string.IsNullOrWhiteSpace(selectedRecord.nextCampaignReason))
        {
            builder.AppendLine($"추천 근거: {Shorten(selectedRecord.nextCampaignReason, 88)}");
        }
        if (!string.IsNullOrWhiteSpace(selectedRecord.growthFollowUpChallenge))
        {
            builder.AppendLine($"성장 후속: {Shorten(selectedRecord.growthFollowUpChallenge, 88)}");
        }
        string decisionAuditCoachingLine = BuildCareerRecordDecisionAuditCoachingLine(selectedRecord);
        if (!string.IsNullOrWhiteSpace(decisionAuditCoachingLine))
        {
            builder.AppendLine(Shorten(decisionAuditCoachingLine, 116));
        }

        return builder.ToString();
    }

    private static string BuildCareerRecordTrendPanelLine(List<CareerRecord> records)
    {
        if (records == null || records.Count == 0)
        {
            return "장기 추세 패널: 완료 기록 없음";
        }

        int bestScore = -1;
        string bestGrade = "";
        int scoreTotal = 0;
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null)
            {
                continue;
            }

            scoreTotal += record.campaignScore;
            if (record.campaignScore > bestScore)
            {
                bestScore = record.campaignScore;
                bestGrade = record.campaignGrade;
            }
        }

        float averageScore = records.Count > 0 ? scoreTotal / (float)records.Count : 0f;
        int replayObjectiveCount = CountReplayObjectiveRecords(records);
        string replayText = replayObjectiveCount >= 2
            ? $"반복 {replayObjectiveCount}회 · {AdvancedReplayChallengeTier(replayObjectiveCount)} · {AdvancedReplayChallengeDecoration(replayObjectiveCount)}"
            : $"반복 {replayObjectiveCount}회";
        int appealRemedyObjectiveCount = CountAppealRemedyObjectiveRecords(records);
        int decisionPracticeObjectiveCount = CountDecisionPracticeObjectiveRecords(records);
        return $"장기 추세 패널: {BuildCumulativeCareerTendencyGraphLine(records)} · 평균 {averageScore:0.0}점 · 최고 {bestGrade}{bestScore}점 · {replayText} · 보정 목표 {appealRemedyObjectiveCount}회 · 비교 연습 {decisionPracticeObjectiveCount}회";
    }

    private static string BuildCareerRecordMandateTrendLine(List<CareerRecord> records)
    {
        if (records == null || records.Count == 0)
        {
            return "기준별 추세: 기록 없음";
        }

        return
            "기준별 추세: " +
            BuildMandateTrendSegment(records, CampaignMandate.Standard, "균형") + " / " +
            BuildMandateTrendSegment(records, CampaignMandate.SupportExpanded, "지원") + " / " +
            BuildMandateTrendSegment(records, CampaignMandate.AusterityAudit, "긴축");
    }

    private static string BuildCareerRecordGrowthObjectiveSummaryLine(List<CareerRecord> records)
    {
        if (records == null || records.Count == 0)
        {
            return "성장 목표 요약: 기록 없음";
        }

        int growthCount = 0;
        int growthSuccessCount = 0;
        int growthMissCount = 0;
        int followUpCount = 0;
        CareerRecord latestGrowthRecord = null;
        CareerRecord latestFollowUpRecord = null;

        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null)
            {
                continue;
            }

            bool hasGrowthObjective = record.startedFromGrowthObjective || !string.IsNullOrWhiteSpace(record.growthObjectiveTitle);
            if (hasGrowthObjective)
            {
                growthCount++;
                if (record.growthObjectiveSucceeded)
                {
                    growthSuccessCount++;
                }
                else
                {
                    growthMissCount++;
                }

                latestGrowthRecord ??= record;
            }

            bool hasGrowthFollowUp = record.startedFromGrowthFollowUpObjective || !string.IsNullOrWhiteSpace(record.growthFollowUpTitle);
            if (hasGrowthFollowUp)
            {
                followUpCount++;
                latestFollowUpRecord ??= record;
            }
        }

        if (growthCount == 0 && followUpCount == 0)
        {
            return "성장 목표 요약: 성장 목표 기록 없음 · 성장 심사 완료 후 성공/미달/후속 흐름을 누적합니다.";
        }

        string recentGrowthState = latestGrowthRecord == null
            ? "최근 판정 없음"
            : "최근 " + (latestGrowthRecord.growthObjectiveSucceeded ? "성공" : "미달") +
                (string.IsNullOrWhiteSpace(latestGrowthRecord.growthObjectiveProgress)
                    ? ""
                    : " · " + Shorten(latestGrowthRecord.growthObjectiveProgress, 38));
        string recentFollowUp = latestFollowUpRecord == null || string.IsNullOrWhiteSpace(latestFollowUpRecord.growthFollowUpChallenge)
            ? "후속 대기"
            : "최근 후속 " + Shorten(latestFollowUpRecord.growthFollowUpChallenge, 34);

        return
            $"성장 목표 요약: 목표 {growthCount}회 · 성공 {growthSuccessCount} / 미달 {growthMissCount} · " +
            $"후속 {followUpCount}회 · {recentGrowthState} · {recentFollowUp}";
    }

    private static string BuildCareerRecordAppealReviewSummaryLine(List<CareerRecord> records)
    {
        if (records == null || records.Count == 0)
        {
            return "이의제기 누적: 기록 없음";
        }

        int appealCount = 0;
        int maxScore = 0;
        CareerRecord highestRecord = null;
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null || record.appealReviewCount <= 0)
            {
                continue;
            }

            appealCount += record.appealReviewCount;
            if (record.appealReviewMaxScore > maxScore)
            {
                maxScore = record.appealReviewMaxScore;
                highestRecord = record;
            }
        }

        if (appealCount <= 0 || highestRecord == null)
        {
            return "이의제기 누적: 보정 검토 기록 없음 · 고위험 불일치 판단이 생기면 항소 점수와 보정 조치를 저장합니다.";
        }

        return
            $"이의제기 누적: {appealCount}건 · 최고 {highestRecord.appealReviewStatus} {maxScore}점 · " +
            $"{highestRecord.appealReviewCaseId} · {Shorten(highestRecord.appealReviewRemedy, 46)}";
    }

    private static string BuildCareerRecordAppealRemedyObjectiveSummaryLine(List<CareerRecord> records)
    {
        if (records == null || records.Count == 0)
        {
            return "보정 목표 요약: 기록 없음";
        }

        int remedyCount = 0;
        int successCount = 0;
        CareerRecord latestRemedyRecord = null;
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null || !record.appealRemedyObjectiveCompleted)
            {
                continue;
            }

            remedyCount++;
            if (record.appealRemedyObjectiveSucceeded)
            {
                successCount++;
            }

            latestRemedyRecord ??= record;
        }

        if (remedyCount == 0 || latestRemedyRecord == null)
        {
            return "보정 목표 요약: 완료 기록 없음 · 이의제기 필터 큐에서 보정 목표를 시작하면 성공률과 다음 과제를 누적합니다.";
        }

        int successRate = Mathf.RoundToInt(successCount * 100f / remedyCount);
        string recentState = latestRemedyRecord.appealRemedyObjectiveSucceeded ? "성공" : "미달";
        string nextChallenge = IsAppealRemedyObjective(new NextCampaignObjective(
            CampaignMandateFromId(latestRemedyRecord.nextCampaignMandateId),
            latestRemedyRecord.nextCampaignChallenge,
            latestRemedyRecord.nextCampaignReason))
                ? latestRemedyRecord.nextCampaignChallenge
                : latestRemedyRecord.appealRemedyObjectiveChallenge;

        return
            $"보정 목표 요약: 완료 {remedyCount}회 · 성공률 {successRate}%({successCount}/{remedyCount}) · " +
            $"최근 {recentState} · {latestRemedyRecord.appealRemedyObjectiveCaseId} · 다음 {Shorten(nextChallenge, 38)}";
    }

    private static string BuildCareerRecordDecisionPracticeObjectiveSummaryLine(List<CareerRecord> records)
    {
        if (records == null || records.Count == 0)
        {
            return "판단 비교 연습 요약: 기록 없음";
        }

        int practiceCount = 0;
        float matchTotal = 0f;
        CareerRecord latestPracticeRecord = null;
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null || !record.decisionPracticeObjectiveCompleted)
            {
                continue;
            }

            practiceCount++;
            matchTotal += record.recommendedMatchRatePercent;
            latestPracticeRecord ??= record;
        }

        if (practiceCount == 0 || latestPracticeRecord == null)
        {
            return "판단 비교 연습 요약: 완료 기록 없음 · 사례 자료실 비교 연습으로 권장 판단 기준 회차를 누적합니다.";
        }

        float averageMatch = matchTotal / practiceCount;
        return
            $"판단 비교 연습 요약: 완료 {practiceCount}회 · 평균 권장 일치 {averageMatch:0}% · " +
            $"{DecisionPracticeRewardTier(practiceCount)} · {DecisionPracticeRewardDecoration(practiceCount)} · " +
            $"최근 {latestPracticeRecord.decisionPracticeCaseId} · {Shorten(latestPracticeRecord.decisionPracticeChallenge, 42)}";
    }

    private static string BuildCareerRecordDecisionAuditCoachingLine(CareerRecord record)
    {
        if (record == null || string.IsNullOrWhiteSpace(record.decisionAuditCoachingSummaryLine))
        {
            return "";
        }

        string counts =
            $"불일치 {record.decisionAuditCoachingMismatchCount}건 · " +
            $"고위험 지연 {record.decisionAuditCoachingUrgentDelayCount}건 · " +
            $"고비용 지원 {record.decisionAuditCoachingHighCostSupportCount}건";
        string appeal = string.IsNullOrWhiteSpace(record.decisionAuditCoachingAppealCaseId)
            ? ""
            : $" · 보정 사례 {record.decisionAuditCoachingAppealCaseId}";

        return
            $"판단 복기: {FallbackText(record.decisionAuditCoachingPattern, "기록 없음")} · " +
            $"추천 운영 {FallbackText(record.decisionAuditCoachingRecommendedMandateName, "없음")} · {counts} · " +
            $"실행 규칙 {Shorten(FallbackText(record.decisionAuditCoachingExecutionRule, "기록 없음"), 54)} · " +
            $"검증 질문 {Shorten(FallbackText(record.decisionAuditCoachingVerificationQuestion, "기록 없음"), 54)}{appeal}";
    }

    private static string BuildCareerRecordDecisionAuditCoachingRoundTripHint(CareerRecord record)
    {
        if (record == null || string.IsNullOrWhiteSpace(record.decisionAuditCoachingSummaryLine))
        {
            return "";
        }

        string caseId = string.IsNullOrWhiteSpace(record.decisionAuditCoachingAppealCaseId)
            ? FallbackText(record.representativeCaseId, "대표 사례")
            : record.decisionAuditCoachingAppealCaseId;
        return $"기록 복귀 안내: 복기 사례 {caseId}에서 추천 운영과 검증 질문을 확인한 뒤 기록으로 돌아갑니다.";
    }

    private static string BuildCareerRecordDecisionAuditCoachingFirstUseHint(CareerRecord record)
    {
        if (record == null || string.IsNullOrWhiteSpace(record.decisionAuditCoachingSummaryLine))
        {
            return "";
        }

        string caseId = string.IsNullOrWhiteSpace(record.decisionAuditCoachingAppealCaseId)
            ? FallbackText(record.representativeCaseId, "대표 사례")
            : record.decisionAuditCoachingAppealCaseId;
        return $"처음 열 때: {caseId}에서 압박 패턴을 확인한 뒤 기록 복귀로 추천 운영과 검증 질문을 다시 점검합니다.";
    }

    private static string BuildCareerRecordGrowthComparisonLine(List<CareerRecord> records, CareerRecord selectedRecord)
    {
        if (records == null || records.Count == 0 || selectedRecord == null)
        {
            return "성장 비교: 기록 없음";
        }

        CareerRecord previousRecord = FindPreviousCareerRecord(records, selectedRecord);
        CareerRecord bestPriorRecord = FindBestPriorCareerRecord(records, selectedRecord);
        if (previousRecord == null && bestPriorRecord == null)
        {
            return "성장 비교: 이전 기록 없음 · 다음 완료 회차부터 직전/이전 최고 대비 점수, 권장 일치, 위험 지표를 비교합니다.";
        }

        string previousSegment = previousRecord == null
            ? "직전 기록 없음"
            : "직전 " + Shorten(previousRecord.completedAt, 10) +
                " 대비 점수 " + SignedNumber(selectedRecord.campaignScore - previousRecord.campaignScore) + "점" +
                ", 권장 " + SignedNumber(Mathf.RoundToInt(selectedRecord.recommendedMatchRatePercent - previousRecord.recommendedMatchRatePercent)) + "p" +
                ", 예산 " + SignedNumber(selectedRecord.finalBudget - previousRecord.finalBudget) + "만" +
                ", 위험 " + SignedNumber(CareerRecordRiskScore(selectedRecord) - CareerRecordRiskScore(previousRecord)) + "p";
        string bestSegment = bestPriorRecord == null
            ? "이전 최고 없음"
            : "이전 최고 " + bestPriorRecord.campaignGrade + bestPriorRecord.campaignScore + "점 대비 " +
                SignedNumber(selectedRecord.campaignScore - bestPriorRecord.campaignScore) + "점";
        string focusSegment = BuildCareerRecordGrowthFocus(selectedRecord, previousRecord ?? bestPriorRecord);
        return $"성장 비교: {previousSegment} · {bestSegment} · {focusSegment}";
    }

    private static string BuildCareerRecordRepresentativeRetrospectiveLine(CareerRecord selectedRecord, List<CareerRecord> records)
    {
        if (selectedRecord == null || string.IsNullOrWhiteSpace(selectedRecord.representativeCaseId))
        {
            return "동일 사례 회고: 대표 사례 기록 없음";
        }

        CareerRecord previousCaseRecord = FindPreviousRepresentativeCaseRecord(records, selectedRecord);
        string currentDecision = CareerRecordRepresentativeDecisionText(selectedRecord);
        string objectiveOutcome = BuildCareerRecordObjectiveOutcome(selectedRecord);
        string graph = string.IsNullOrWhiteSpace(selectedRecord.representativeCaseBeforeAfterGraph)
            ? ""
            : " · " + Shorten(selectedRecord.representativeCaseBeforeAfterGraph, 58);

        if (previousCaseRecord == null)
        {
            return
                $"동일 사례 회고: {selectedRecord.representativeCaseId} · 현재 {currentDecision} · " +
                $"과거 판단 없음 · 목표 재도전 결과 {objectiveOutcome}{graph}";
        }

        string previousDecision = CareerRecordRepresentativeDecisionText(previousCaseRecord);
        int scoreDelta = selectedRecord.campaignScore - previousCaseRecord.campaignScore;
        int riskDelta = CareerRecordRiskScore(selectedRecord) - CareerRecordRiskScore(previousCaseRecord);
        int matchDelta = Mathf.RoundToInt(selectedRecord.recommendedMatchRatePercent - previousCaseRecord.recommendedMatchRatePercent);
        string changed = string.Equals(currentDecision, previousDecision, StringComparison.Ordinal)
            ? "판단 유지"
            : $"판단 변화 {previousDecision} -> {currentDecision}";

        return
            $"동일 사례 회고: {selectedRecord.representativeCaseId} · {changed} · " +
            $"이전 {previousCaseRecord.campaignGrade}{previousCaseRecord.campaignScore}점 대비 {SignedNumber(scoreDelta)}점, 권장 {SignedNumber(matchDelta)}p, 위험 {SignedNumber(riskDelta)}p · " +
            $"목표 재도전 결과 {objectiveOutcome}{graph}";
    }

    private static string BuildCareerRecordCompactRepresentativeRetrospectiveLine(CareerRecord selectedRecord, List<CareerRecord> records)
    {
        if (selectedRecord == null || string.IsNullOrWhiteSpace(selectedRecord.representativeCaseId))
        {
            return "동일 사례 회고: 대표 사례 기록 없음";
        }

        CareerRecord previousCaseRecord = FindPreviousRepresentativeCaseRecord(records, selectedRecord);
        string currentDecision = CareerRecordRepresentativeDecisionText(selectedRecord);
        string objectiveOutcome = BuildCareerRecordObjectiveOutcome(selectedRecord);
        if (previousCaseRecord == null)
        {
            return
                $"동일 사례 회고: {selectedRecord.representativeCaseId} · 현재 {Shorten(currentDecision, 34)} · " +
                $"첫 비교 · 목표 재도전 결과 {Shorten(objectiveOutcome, 44)}";
        }

        string previousDecision = CareerRecordRepresentativeDecisionText(previousCaseRecord);
        int scoreDelta = selectedRecord.campaignScore - previousCaseRecord.campaignScore;
        int riskDelta = CareerRecordRiskScore(selectedRecord) - CareerRecordRiskScore(previousCaseRecord);
        int matchDelta = Mathf.RoundToInt(selectedRecord.recommendedMatchRatePercent - previousCaseRecord.recommendedMatchRatePercent);
        string changed = string.Equals(currentDecision, previousDecision, StringComparison.Ordinal)
            ? "판단 유지"
            : "판단 변화";

        return
            $"동일 사례 회고: {selectedRecord.representativeCaseId} · {changed} · " +
            $"점수 {SignedNumber(scoreDelta)} / 권장 {SignedNumber(matchDelta)}p / 위험 {SignedNumber(riskDelta)}p · " +
            $"목표 재도전 결과 {Shorten(objectiveOutcome, 42)}";
    }

    private static string BuildCareerRecordBriefingRetrospectiveLine(CareerRecord record)
    {
        if (record == null)
        {
            return "브리핑 회고: 완료 기록 없음";
        }

        CampaignMandate mandate = CampaignMandateFromId(record.campaignMandateId);
        string risk = BuildMenuCampaignBriefingRiskLine(mandate);
        string reward = BuildMenuCampaignBriefingRewardLine(mandate);
        string result = BuildCareerRecordBriefingResultLine(record, mandate);
        return $"브리핑 회고: 예고 위험 {Shorten(risk, 34)} · 예고 보상 {Shorten(reward, 34)} · 실제 결과 {result}";
    }

    private static string BuildCareerRecordBriefingResultLine(CareerRecord record, CampaignMandate mandate)
    {
        string challenge = record.campaignChallengeSucceeded ? "챌린지 성공" : "챌린지 미달";
        int riskScore = record.finalMissedRisk + record.finalComplaints;
        return mandate switch
        {
            CampaignMandate.SupportExpanded =>
                $"{challenge} · 형평 {record.finalEquity} · 안정 {record.finalStability} · 위험 {riskScore} · 예산 {record.finalBudget}만",
            CampaignMandate.AusterityAudit =>
                $"{challenge} · 예산 {record.finalBudget}만 · 지원 {record.supportCount} · 위험 {riskScore} · 민원 {record.finalComplaints}",
            _ =>
                $"{challenge} · 권장 {record.recommendedMatchRatePercent:0}% · 점수 {record.campaignScore} · 예산 {record.finalBudget}만 · 위험 {riskScore}"
        };
    }

    private static CareerRecord FindPreviousRepresentativeCaseRecord(List<CareerRecord> records, CareerRecord selectedRecord)
    {
        if (records == null || selectedRecord == null || string.IsNullOrWhiteSpace(selectedRecord.representativeCaseId))
        {
            return null;
        }

        int selectedIndex = FindCareerRecordListIndex(records, selectedRecord);
        int startIndex = selectedIndex < 0 ? 0 : selectedIndex + 1;
        for (int i = startIndex; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null || IsSameCareerRecord(record, selectedRecord))
            {
                continue;
            }

            if (string.Equals(record.representativeCaseId, selectedRecord.representativeCaseId, StringComparison.OrdinalIgnoreCase))
            {
                return record;
            }
        }

        return null;
    }

    private static string CareerRecordRepresentativeDecisionText(CareerRecord record)
    {
        if (record == null)
        {
            return "판단 없음";
        }

        string decision = FallbackText(record.representativeCaseDecision, "판단 없음");
        string recommended = FallbackText(record.representativeCaseRecommendedDecision, "권장 없음");
        string match = record.representativeCaseMatchedRecommended ? "일치" : "불일치";
        return $"{decision}/{recommended} {match}";
    }

    private static string BuildCareerRecordObjectiveOutcome(CareerRecord record)
    {
        if (record == null)
        {
            return "기록 없음";
        }

        if (record.appealRemedyObjectiveCompleted)
        {
            return (record.appealRemedyObjectiveSucceeded ? "보정 성공" : "보정 미달") +
                " · " + Shorten(FallbackText(record.appealRemedyObjectiveProgress, record.appealRemedyObjectiveChallenge), 44);
        }

        if (record.decisionPracticeObjectiveCompleted)
        {
            return "비교 연습 완료 · " + Shorten(FallbackText(record.decisionPracticeChallenge, record.decisionPracticeReason), 44);
        }

        if (record.startedFromGrowthFollowUpObjective || !string.IsNullOrWhiteSpace(record.growthFollowUpTitle))
        {
            return "성장 후속 완료 · " + Shorten(FallbackText(record.growthFollowUpChallenge, record.growthFollowUpReason), 44);
        }

        if (record.startedFromGrowthObjective || !string.IsNullOrWhiteSpace(record.growthObjectiveTitle))
        {
            return (record.growthObjectiveSucceeded ? "성장 성공" : "성장 미달") +
                " · " + Shorten(FallbackText(record.growthObjectiveProgress, record.growthObjectiveChallenge), 44);
        }

        if (record.startedFromCaseObjective || !string.IsNullOrWhiteSpace(record.caseObjectiveSourceId))
        {
            return "사례 목표 완료 · " + Shorten(FallbackText(record.caseObjectiveChallenge, record.caseObjectiveSourceId), 44);
        }

        if (record.startedFromAchievementObjective || !string.IsNullOrWhiteSpace(record.achievementObjectiveTitle))
        {
            return "성과 목표 완료 · " + Shorten(FallbackText(record.achievementObjectiveTitle, record.achievementObjectiveChallenge), 44);
        }

        return (record.campaignChallengeSucceeded ? "챌린지 성공" : "챌린지 미달") +
            " · " + Shorten(FallbackText(record.campaignChallengeProgress, record.campaignChallengeTitle), 44);
    }

    private static CareerRecord FindPreviousCareerRecord(List<CareerRecord> records, CareerRecord selectedRecord)
    {
        int selectedIndex = FindCareerRecordListIndex(records, selectedRecord);
        if (selectedIndex < 0)
        {
            selectedIndex = -1;
        }

        for (int i = selectedIndex + 1; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record != null && !IsSameCareerRecord(record, selectedRecord))
            {
                return record;
            }
        }

        return null;
    }

    private static CareerRecord FindBestPriorCareerRecord(List<CareerRecord> records, CareerRecord selectedRecord)
    {
        int selectedIndex = FindCareerRecordListIndex(records, selectedRecord);
        int startIndex = selectedIndex < 0 ? 0 : selectedIndex + 1;
        CareerRecord bestRecord = null;
        for (int i = startIndex; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null || IsSameCareerRecord(record, selectedRecord))
            {
                continue;
            }

            if (bestRecord == null || record.campaignScore > bestRecord.campaignScore)
            {
                bestRecord = record;
            }
        }

        return bestRecord;
    }

    private static int FindCareerRecordListIndex(List<CareerRecord> records, CareerRecord selectedRecord)
    {
        if (records == null || selectedRecord == null)
        {
            return -1;
        }

        for (int i = 0; i < records.Count; i++)
        {
            if (IsSameCareerRecord(records[i], selectedRecord))
            {
                return i;
            }
        }

        return -1;
    }

    private static int CareerRecordRiskScore(CareerRecord record)
    {
        return record == null ? 0 : record.finalMissedRisk + record.finalComplaints;
    }

    private static string BuildCareerRecordGrowthFocus(CareerRecord selectedRecord, CareerRecord comparisonRecord)
    {
        if (selectedRecord == null || comparisonRecord == null)
        {
            return "비교 초점: 다음 기록 대기";
        }

        int scoreDelta = selectedRecord.campaignScore - comparisonRecord.campaignScore;
        int riskDelta = CareerRecordRiskScore(selectedRecord) - CareerRecordRiskScore(comparisonRecord);
        int budgetDelta = selectedRecord.finalBudget - comparisonRecord.finalBudget;
        int matchDelta = Mathf.RoundToInt(selectedRecord.recommendedMatchRatePercent - comparisonRecord.recommendedMatchRatePercent);
        if (scoreDelta > 0 && matchDelta >= 0)
        {
            return "비교 초점: 판단 품질 상승";
        }
        if (riskDelta < 0)
        {
            return "비교 초점: 위험 관리 개선";
        }
        if (budgetDelta > 0 && scoreDelta >= 0)
        {
            return "비교 초점: 예산 여력 개선";
        }
        if (matchDelta < 0)
        {
            return "비교 초점: 권장 판단 일치율 회복 필요";
        }

        return "비교 초점: 다음 회차에서 점수/위험 동시 개선";
    }

    private static string BuildMandateTrendSegment(List<CareerRecord> records, CampaignMandate mandate, string label)
    {
        string mandateId = CampaignMandateId(mandate);
        int count = 0;
        int scoreTotal = 0;
        float matchTotal = 0f;
        int matchCount = 0;
        int replayCount = 0;
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null || !string.Equals(record.campaignMandateId, mandateId, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }

            count++;
            scoreTotal += record.campaignScore;
            if (record.recommendedMatchRatePercent > 0f)
            {
                matchTotal += record.recommendedMatchRatePercent;
                matchCount++;
            }
            if (IsReplayObjectiveRecord(record))
            {
                replayCount++;
            }
        }

        if (count <= 0)
        {
            return $"{label} 0회";
        }

        float averageScore = scoreTotal / (float)count;
        float averageMatch = matchCount > 0 ? matchTotal / matchCount : 0f;
        return $"{label} {count}회 평균 {averageScore:0}점 권장 {averageMatch:0}% 반복 {replayCount}회";
    }

    private static string BuildCareerRecordDetailText(CareerRecord record, bool focused, List<CareerRecord> records)
    {
        if (record == null)
