    private static string WrapCareerRecordDetailText(string text)
    {
        return WrapTextByDisplayWidth(text, CareerRecordDetailWrapWidth);
    }

    private static string WrapTextByDisplayWidth(string text, float maxWidth)
    {
        if (string.IsNullOrEmpty(text))
        {
            return "";
        }

        string[] lines = text.Replace("\r\n", "\n").Split('\n');
        StringBuilder builder = new();
        for (int i = 0; i < lines.Length; i++)
        {
            AppendWrappedDisplayLine(builder, lines[i], maxWidth);
            if (i < lines.Length - 1)
            {
                builder.AppendLine();
            }
        }

        return builder.ToString();
    }

    private static void AppendWrappedDisplayLine(StringBuilder builder, string line, float maxWidth)
    {
        if (string.IsNullOrWhiteSpace(line) || DisplayWidth(line) <= maxWidth)
        {
            builder.Append(line);
            return;
        }

        string remaining = line.TrimEnd();
        string continuationIndent = remaining.StartsWith("- ", StringComparison.Ordinal) ? "  " : "";
        bool first = true;
        while (!string.IsNullOrWhiteSpace(remaining) && DisplayWidth(remaining) > maxWidth)
        {
            int splitIndex = FindDisplayWrapIndex(remaining, maxWidth);
            string part = remaining.Substring(0, splitIndex).TrimEnd();
            if (!first)
            {
                part = continuationIndent + part.TrimStart();
            }
            builder.AppendLine(part);
            remaining = remaining.Substring(splitIndex).TrimStart();
            first = false;
        }

        if (!string.IsNullOrWhiteSpace(remaining))
        {
            if (!first)
            {
                builder.Append(continuationIndent);
            }
            builder.Append(remaining);
        }
    }

    private static int FindDisplayWrapIndex(string line, float maxWidth)
    {
        float width = 0f;
        int fallback = Mathf.Min(line.Length, 1);
        int preferred = -1;
        for (int i = 0; i < line.Length; i++)
        {
            width += CharacterDisplayWidth(line[i]);
            if (width > maxWidth)
            {
                break;
            }

            fallback = i + 1;
            if (IsPreferredWrapCharacter(line[i]))
            {
                preferred = i + 1;
            }
        }

        return Mathf.Clamp(preferred > 0 ? preferred : fallback, 1, line.Length);
    }

    private static bool IsPreferredWrapCharacter(char value)
    {
        return char.IsWhiteSpace(value) ||
            value == '·' ||
            value == '/' ||
            value == ':' ||
            value == ',' ||
            value == '，' ||
            value == '。' ||
            value == '점';
    }

    private static float MaxDisplayLineWidth(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return 0f;
        }

        float max = 0f;
        string[] lines = text.Replace("\r\n", "\n").Split('\n');
        for (int i = 0; i < lines.Length; i++)
        {
            max = Mathf.Max(max, DisplayWidth(lines[i]));
        }

        return max;
    }

    private static string FirstLineContaining(string text, string token)
    {
        if (string.IsNullOrEmpty(text) || string.IsNullOrEmpty(token))
        {
            return "";
        }

        string[] lines = text.Replace("\r\n", "\n").Split('\n');
        for (int i = 0; i < lines.Length; i++)
        {
            if (lines[i].Contains(token))
            {
                return lines[i];
            }
        }

        return "";
    }

    private static float DisplayWidth(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return 0f;
        }

        float width = 0f;
        for (int i = 0; i < text.Length; i++)
        {
            width += CharacterDisplayWidth(text[i]);
        }

        return width;
    }

    private static float CharacterDisplayWidth(char value)
    {
        if (char.IsWhiteSpace(value))
        {
            return 0.6f;
        }

        return value <= 0x007f ? 1f : 1.65f;
    }

    private static string BuildDecisionPracticeRewardDetailLines(CareerRecord record, List<CareerRecord> records)
    {
        int practiceCount = CountDecisionPracticeObjectiveRecordsThrough(records, record);
        StringBuilder builder = new();
        builder.AppendLine($"비교 보상 단계: 현재 {practiceCount}회 · {DecisionPracticeRewardTier(practiceCount)} · {DecisionPracticeRewardDecoration(practiceCount)}");
        int[] thresholds = { 2, 4, 6 };
        for (int i = 0; i < thresholds.Length; i++)
        {
            int threshold = thresholds[i];
            string state = practiceCount >= threshold
                ? "해금"
                : Mathf.Max(0, threshold - practiceCount) + "회 남음";
            builder.AppendLine($"비교 보상 {threshold}회: {DecisionPracticeRewardDecoration(threshold)} · {state}");
        }

        return builder.ToString();
    }

    private static int CountDecisionPracticeObjectiveRecordsThrough(List<CareerRecord> records, CareerRecord selectedRecord)
    {
        if (records == null || selectedRecord == null)
        {
            return 0;
        }

        int count = 0;
        for (int i = records.Count - 1; i >= 0; i--)
        {
            CareerRecord record = records[i];
            if (record == null)
            {
                continue;
            }

            if (record.decisionPracticeObjectiveCompleted)
            {
                count++;
            }

            if (IsSameCareerRecord(record, selectedRecord))
            {
                return count;
            }
        }

        return selectedRecord.decisionPracticeObjectiveCompleted
            ? CountDecisionPracticeObjectiveRecords(records)
            : 0;
    }

