    {
        if (record == null || !record.appealRemedyObjectiveCompleted)
        {
            return "보정 액션 플랜: 이의제기 필터 큐에서 보정 목표를 완료하면 재도전 기준이 표시됩니다.";
        }

        string result = record.appealRemedyObjectiveSucceeded ? "성공 유지" : "재도전 필요";
        string progress = FallbackText(record.appealRemedyObjectiveProgress, record.appealRemedyObjectiveChallenge);
        string note = FallbackText(record.appealRemedyObjectiveResultNote, "보정 목표 판정 기록 없음");
        string next = IsAppealRemedyObjective(new NextCampaignObjective(
            CampaignMandateFromId(record.nextCampaignMandateId),
            record.nextCampaignChallenge,
            record.nextCampaignReason))
                ? record.nextCampaignChallenge
                : FallbackText(record.appealRemedyObjectiveChallenge, "보정 목표 대기");

        return
            $"보정 액션 플랜: {result} · {record.appealRemedyObjectiveCaseId} · " +
            $"{Shorten(progress, 56)} · 다음 {Shorten(next, 46)} · {Shorten(note, 48)}";
    }

