    private void ShowAchievementToast(AchievementDefinition achievement)
    {
        if (achievementToastRoot == null || achievementToastPanel == null || achievementToastTitleText == null || achievementToastBodyText == null)
        {
            return;
        }

        achievementToastTitleText.text = "성과 해금";
        achievementToastBodyText.text = $"{achievement.title}\n성과 기록에서 다음 목표와 기록 보상 확인";
        achievementToastRoot.gameObject.SetActive(true);
        achievementToastRoot.SetAsLastSibling();
        if (achievementToastRoutine != null)
        {
            StopCoroutine(achievementToastRoutine);
        }

        achievementToastRoutine = StartCoroutine(AnimateAchievementToast());
        PlaySfx(toastUnlockClip ?? saveClip ?? analysisClip, 0.72f);
    }

