    private IEnumerator AnimateAchievementToast()
    {
        const float fadeInSeconds = 0.22f;
        const float holdSeconds = 2.55f;
        const float fadeOutSeconds = 0.36f;
        float totalSeconds = fadeInSeconds + holdSeconds + fadeOutSeconds;
        float elapsed = 0f;
        while (elapsed < totalSeconds)
        {
            elapsed += Time.unscaledDeltaTime;
            float alpha;
            if (elapsed < fadeInSeconds)
            {
                alpha = Mathf.Clamp01(elapsed / fadeInSeconds);
            }
            else if (elapsed < fadeInSeconds + holdSeconds)
            {
                alpha = 1f;
            }
            else
            {
                alpha = 1f - Mathf.Clamp01((elapsed - fadeInSeconds - holdSeconds) / fadeOutSeconds);
            }

            SetAchievementToastAlpha(alpha);
            yield return null;
        }

        HideAchievementToast();
    }

    private void HideAchievementToast()
    {
        if (achievementToastRoutine != null)
        {
            StopCoroutine(achievementToastRoutine);
            achievementToastRoutine = null;
        }

        SetAchievementToastAlpha(0f);
        if (achievementToastRoot != null)
        {
            achievementToastRoot.gameObject.SetActive(false);
        }
    }

    private void SetAchievementToastAlpha(float alpha)
    {
        SetGraphicAlpha(achievementToastPanel, Mathf.Clamp01(alpha) * 0.93f);
        SetGraphicAlpha(achievementToastStrip, Mathf.Clamp01(alpha) * 0.92f);
        SetGraphicAlpha(achievementToastTitleText, Mathf.Clamp01(alpha));
        SetGraphicAlpha(achievementToastBodyText, Mathf.Clamp01(alpha));
    }

    private static void SetGraphicAlpha(Graphic graphic, float alpha)
    {
        if (graphic == null)
        {
            return;
        }

        Color color = graphic.color;
        color.a = alpha;
        graphic.color = color;
    }

    private void EvaluateReportAchievements(int matchedRecommendedCount, GrowthObjectiveResult growthResult)
    {
        if (logs.Count >= cases.Count && cases.Count > 0)
        {
            UnlockAchievement("campaign_complete");
        }

        if (logs.Count > 0 && matchedRecommendedCount >= Mathf.CeilToInt(logs.Count * 0.85f))
        {
            UnlockAchievement("recommended_path");
        }

        if (missedRisk <= 25)
        {
            UnlockAchievement("risk_shield");
        }

        if (equity >= 90)
        {
            UnlockAchievement("equity_guardian");
        }

        if (budget >= -1000)
        {
            UnlockAchievement("budget_explained");
        }

        if (CountCompletedMandates() >= 2)
        {
            UnlockAchievement("mandate_replay");
        }

        if (currentCampaignStartedFromCaseObjective)
        {
            UnlockAchievement("case_objective_replay");
        }

        if (currentCampaignStartedFromCaseObjective &&
            currentCampaignCaseObjectiveChallenge.Contains("이의제기") &&
            currentCampaignCaseObjectiveChallenge.Contains("보정"))
        {
            UnlockAchievement("appeal_remedy_objective");
        }

        if (currentCampaignStartedFromDecisionPracticeObjective)
        {
            UnlockAchievement("decision_practice_objective");
        }

        if (currentCampaignInvestigationFollowUpCount > 0)
        {
            UnlockAchievement("investigation_follow_up");
        }

        if (growthResult.active && growthResult.succeeded)
        {
            UnlockAchievement("growth_objective_success");
        }

        if (currentCampaignStartedFromGrowthFollowUpObjective)
        {
            UnlockAchievement("growth_follow_up_complete");
        }
    }

