    private static void SeedAchievementNextGoalForAppealRemedyTriageSmoke()
    {
        AchievementDefinition[] achievements = BuildAchievementCatalog();
        for (int i = 0; i < achievements.Length; i++)
        {
            string id = achievements[i].id;
            if (id == "appeal_remedy_objective")
            {
                PlayerPrefs.DeleteKey(AchievementUnlockedPrefsPrefix + id);
                PlayerPrefs.DeleteKey(AchievementUnlockedAtPrefsPrefix + id);
                break;
            }

            PlayerPrefs.SetInt(AchievementUnlockedPrefsPrefix + id, 1);
            PlayerPrefs.SetString(AchievementUnlockedAtPrefsPrefix + id, DateTime.Now.ToString("s"));
        }

        PlayerPrefs.Save();
    }

    private static void SeedAchievementNextGoalForSpecificSmoke(string lockedAchievementId)
    {
        AchievementDefinition[] achievements = BuildAchievementCatalog();
        bool reachedTarget = false;
        for (int i = 0; i < achievements.Length; i++)
        {
            string id = achievements[i].id;
            if (string.Equals(id, lockedAchievementId, StringComparison.Ordinal))
            {
                PlayerPrefs.DeleteKey(AchievementUnlockedPrefsPrefix + id);
                PlayerPrefs.DeleteKey(AchievementUnlockedAtPrefsPrefix + id);
                reachedTarget = true;
                continue;
            }

            if (!reachedTarget)
            {
                PlayerPrefs.SetInt(AchievementUnlockedPrefsPrefix + id, 1);
                PlayerPrefs.SetString(AchievementUnlockedAtPrefsPrefix + id, DateTime.Now.ToString("s"));
            }
            else
            {
                PlayerPrefs.DeleteKey(AchievementUnlockedPrefsPrefix + id);
                PlayerPrefs.DeleteKey(AchievementUnlockedAtPrefsPrefix + id);
            }
        }

        PlayerPrefs.Save();
    }

    private static bool IsAchievementUnlocked(string achievementId)
    {
        return PlayerPrefs.GetInt(AchievementUnlockedPrefsPrefix + achievementId, 0) == 1;
    }

    private static string AchievementUnlockedAt(string achievementId)
    {
        return PlayerPrefs.GetString(AchievementUnlockedAtPrefsPrefix + achievementId, "");
    }

    private void UnlockAchievement(string achievementId)
    {
        if (IsAchievementUnlocked(achievementId))
        {
            return;
        }

        PlayerPrefs.SetInt(AchievementUnlockedPrefsPrefix + achievementId, 1);
        PlayerPrefs.SetString(AchievementUnlockedAtPrefsPrefix + achievementId, DateTime.Now.ToString("s"));
        PlayerPrefs.Save();
        Debug.Log("CARE_REVIEW_ACHIEVEMENT_UNLOCKED id=" + achievementId);
        if (!Application.isBatchMode && TryGetAchievementDefinition(achievementId, out AchievementDefinition achievement))
        {
            ShowAchievementToast(achievement);
        }
    }

    private static void RestoreAchievementPref(string achievementId, bool unlocked, string unlockedAt)
    {
        if (unlocked)
        {
            PlayerPrefs.SetInt(AchievementUnlockedPrefsPrefix + achievementId, 1);
            PlayerPrefs.SetString(AchievementUnlockedAtPrefsPrefix + achievementId, unlockedAt ?? "");
        }
        else
        {
            PlayerPrefs.DeleteKey(AchievementUnlockedPrefsPrefix + achievementId);
            PlayerPrefs.DeleteKey(AchievementUnlockedAtPrefsPrefix + achievementId);
        }
    }

    private static bool TryGetAchievementDefinition(string achievementId, out AchievementDefinition achievement)
    {
        AchievementDefinition[] achievements = BuildAchievementCatalog();
        for (int i = 0; i < achievements.Length; i++)
        {
            if (achievements[i].id == achievementId)
            {
                achievement = achievements[i];
                return true;
            }
        }

        achievement = default;
        return false;
    }

    private static int UnlockedAchievementCount()
    {
        return UnlockedAchievementCount(BuildAchievementCatalog());
    }

    private static int UnlockedAchievementCount(AchievementDefinition[] achievements)
    {
        int count = 0;
        for (int i = 0; i < achievements.Length; i++)
        {
            if (IsAchievementUnlocked(achievements[i].id))
            {
                count++;
            }
        }

        return count;
    }

    private static int CountCompletedMandates()
    {
        int count = 0;
        for (int i = 0; i < CampaignMandateCatalog.Length; i++)
        {
            if (!string.IsNullOrEmpty(PlayerPrefs.GetString(LastEndingForMandateKey(CampaignMandateCatalog[i]), "")))
            {
                count++;
            }
        }

        return count;
    }

    private static int CountDiscoveredEndings(EndingOutcome[] endings)
    {
        int count = 0;
        foreach (EndingOutcome ending in endings)
        {
            if (IsEndingDiscovered(ending.id))
            {
                count++;
            }
        }

        return count;
    }

    private static int CountDiscoveredEndingsForMandate(CampaignMandate mandate, EndingOutcome[] endings)
    {
        int count = 0;
        foreach (EndingOutcome ending in endings)
        {
            if (IsEndingDiscoveredForMandate(mandate, ending.id))
            {
                count++;
            }
        }

        return count;
    }

    private static bool IsEndingDiscovered(string endingId)
    {
        return PlayerPrefs.GetInt(EndingSeenPrefsPrefix + endingId, 0) == 1;
    }

    private static bool IsEndingDiscoveredForMandate(CampaignMandate mandate, string endingId)
    {
        return PlayerPrefs.GetInt(EndingSeenForMandateKey(mandate, endingId), 0) == 1;
    }

    private void RegisterEndingDiscovered(EndingOutcome ending)
    {
        PlayerPrefs.SetInt(EndingSeenPrefsPrefix + ending.id, 1);
        PlayerPrefs.SetInt(EndingSeenForMandateKey(campaignMandate, ending.id), 1);
        PlayerPrefs.SetString(LastEndingPrefsKey, ending.id);
        PlayerPrefs.SetString(LastEndingForMandateKey(campaignMandate), ending.id);
        PlayerPrefs.Save();
    }

