    private void RegisterCareerRecord(EndingOutcome ending, CampaignGradeResult grade, int matchedRecommendedCount, int supportCount, int investigationCount, int holdCount, int rejectCount, NextCampaignObjective nextObjective, GrowthObjectiveResult growthResult, AppealRemedyObjectiveResult appealRemedyResult, CareerRecordDatabase preparedDatabase = null, string preparedSessionId = "")
    {
        if (logs.Count < cases.Count || cases.Count == 0)
        {
            return;
        }

        string sessionId = string.IsNullOrEmpty(preparedSessionId) ? EnsureSessionId() : preparedSessionId;
        CampaignChallengeResult challenge = BuildCampaignChallengeResult();
        CareerRecordDatabase database = preparedDatabase ?? LoadCareerRecordDatabase();
        RemoveCareerRecordForCurrentCampaign(database, sessionId);
        if (!growthResult.active && currentCampaignStartedFromGrowthObjective)
        {
            growthResult = BuildGrowthObjectiveResult(database, matchedRecommendedCount);
        }

        bool currentIsReplayObjective = currentCampaignStartedFromCaseObjective || currentCampaignStartedFromAchievementObjective;
        int replayObjectiveCompletionCount = CountReplayObjectiveRecords(database.records) + (currentIsReplayObjective ? 1 : 0);
        bool advancedReplayChallengeUnlocked = replayObjectiveCompletionCount >= 2;
        bool appealRemedyObjectiveCompleted = currentCampaignStartedFromCaseObjective &&
            currentCampaignCaseObjectiveChallenge.Contains("이의제기") &&
            currentCampaignCaseObjectiveChallenge.Contains("보정");
        bool decisionPracticeObjectiveCompleted = currentCampaignStartedFromDecisionPracticeObjective;
        AppealReviewCampaignSummary appealSummary = BuildAppealReviewCampaignSummary();
        DecisionAuditCoachingExport decisionAuditCoaching = BuildCurrentDecisionAuditCoachingExport();
        DecisionLog representativeLog = CareerRepresentativeLog();
        CareerRecord record = new()
        {
            sessionId = sessionId,
            campaignStartedAt = string.IsNullOrEmpty(campaignStartedAt) ? DateTime.Now.ToString("s") : campaignStartedAt,
            completedAt = DateTime.Now.ToString("s"),
            buildVersion = BuildVersionLabel,
            campaignMandateId = CampaignMandateId(campaignMandate),
            campaignMandateName = CampaignMandateLabel(campaignMandate),
            caseCount = cases.Count,
            logCount = logs.Count,
            endingId = ending.id,
            endingTitle = ending.title,
            campaignScore = grade.score,
            campaignGrade = grade.grade,
            campaignBadge = grade.badge,
            finalBudget = budget,
            finalStability = stability,
            finalEquity = equity,
            finalMissedRisk = missedRisk,
            finalComplaints = complaints,
            supportCount = supportCount,
            investigationCount = investigationCount,
            holdCount = holdCount,
            rejectCount = rejectCount,
            matchedRecommendedCount = matchedRecommendedCount,
            recommendedMatchRatePercent = logs.Count > 0 ? matchedRecommendedCount * 100f / logs.Count : 0f,
            campaignChallengeId = challenge.id,
            campaignChallengeTitle = challenge.title,
            campaignChallengeObjective = challenge.objective,
            campaignChallengeProgress = challenge.progress,
            campaignChallengeSucceeded = challenge.succeeded,
            campaignChallengeScore = challenge.score,
            nextCampaignMandateId = CampaignMandateId(nextObjective.mandate),
            nextCampaignMandateName = CampaignMandateLabel(nextObjective.mandate),
            nextCampaignChallenge = nextObjective.challenge,
            nextCampaignReason = nextObjective.reason,
            caseObjectiveSourceId = currentCampaignStartedFromCaseObjective ? currentCampaignCaseObjectiveId : "",
            caseObjectiveChallenge = currentCampaignStartedFromCaseObjective ? currentCampaignCaseObjectiveChallenge : "",
            startedFromCaseObjective = currentCampaignStartedFromCaseObjective,
            decisionPracticeObjectiveCompleted = decisionPracticeObjectiveCompleted,
            decisionPracticeObjectiveBadge = decisionPracticeObjectiveCompleted ? "판단 비교 연습 완료" : "",
            decisionPracticeCaseId = decisionPracticeObjectiveCompleted ? currentCampaignCaseObjectiveId : "",
            decisionPracticeChallenge = decisionPracticeObjectiveCompleted ? currentCampaignCaseObjectiveChallenge : "",
            decisionPracticeReason = decisionPracticeObjectiveCompleted ? currentCampaignCaseObjectiveReason : "",
            appealRemedyObjectiveCompleted = appealRemedyObjectiveCompleted,
            appealRemedyObjectiveBadge = appealRemedyObjectiveCompleted ? "이의제기 보정 목표 완료" : "",
            appealRemedyObjectiveCaseId = appealRemedyObjectiveCompleted ? currentCampaignCaseObjectiveId : "",
            appealRemedyObjectiveChallenge = appealRemedyObjectiveCompleted ? currentCampaignCaseObjectiveChallenge : "",
            appealRemedyObjectiveSucceeded = appealRemedyResult.active && appealRemedyResult.succeeded,
            appealRemedyObjectiveProgress = appealRemedyResult.active ? appealRemedyResult.progress : "",
            appealRemedyObjectiveResultNote = appealRemedyResult.active ? appealRemedyResult.note : "",
            appealRemedyObjectiveTriageLabel = appealRemedyObjectiveCompleted ? CurrentAppealRemedyObjectiveTriageLabel() : "",
            appealRemedyObjectiveTriageSummary = appealRemedyObjectiveCompleted ? CurrentAppealRemedyObjectiveTriageSummary() : "",
            startedFromAchievementObjective = currentCampaignStartedFromAchievementObjective,
            achievementObjectiveTitle = currentCampaignStartedFromAchievementObjective ? currentCampaignAchievementObjectiveTitle : "",
            achievementObjectiveChallenge = currentCampaignStartedFromAchievementObjective ? currentCampaignAchievementObjectiveChallenge : "",
            startedFromGrowthObjective = currentCampaignStartedFromGrowthObjective,
            growthObjectiveTitle = currentCampaignStartedFromGrowthObjective ? currentCampaignGrowthObjectiveTitle : "",
            growthObjectiveChallenge = currentCampaignStartedFromGrowthObjective ? currentCampaignGrowthObjectiveChallenge : "",
            growthObjectiveReason = currentCampaignStartedFromGrowthObjective ? currentCampaignGrowthObjectiveReason : "",
            growthObjectiveSucceeded = growthResult.active && growthResult.succeeded,
            growthObjectiveProgress = growthResult.active ? growthResult.progress : "",
            growthObjectiveResultNote = growthResult.active ? growthResult.note : "",
            startedFromGrowthFollowUpObjective = currentCampaignStartedFromGrowthFollowUpObjective,
            growthFollowUpTitle = currentCampaignStartedFromGrowthFollowUpObjective ? currentCampaignGrowthFollowUpTitle : "",
            growthFollowUpChallenge = currentCampaignStartedFromGrowthFollowUpObjective ? currentCampaignGrowthFollowUpChallenge : "",
            growthFollowUpReason = currentCampaignStartedFromGrowthFollowUpObjective ? currentCampaignGrowthFollowUpReason : "",
            investigationFollowUpCount = currentCampaignInvestigationFollowUpCount,
