            representativeCaseNextStep = representativeLog != null ? DecisionReviewNextStep(representativeLog) : "",
            representativeCaseDecision = representativeLog != null ? representativeLog.decision : "",
            representativeCaseRecommendedDecision = representativeLog != null ? representativeLog.recommendedDecision : "",
            representativeCaseMatchedRecommended = representativeLog != null && representativeLog.matchedRecommended,
            representativeCasePressureScore = representativeLog != null ? DecisionAuditQueuePriorityScore(representativeLog) : 0,
            representativeCaseBeforeAfterGraph = representativeLog != null ? DecisionAuditBeforeAfterGraphText(representativeLog) : "",
            investigationMemoCaseId = CareerInvestigationMemoCaseId(),
            investigationMemo = CareerInvestigationMemoText(),
            investigationMemoTimeline = CareerInvestigationMemoTimelineText(),
            careerDetailSummary = CareerDetailSummary(ending, grade),
            closestAgentPersonaId = "",
            closestAgentPersonaName = "",
            closestAgentMatchCount = 0,
            closestAgentComparableCount = 0,
            closestAgentMatchRatePercent = 0f,
            closestAgentProfileNote = "",
            decisionAuditCoachingPattern = decisionAuditCoaching.pattern,
            decisionAuditCoachingMismatchCount = decisionAuditCoaching.mismatchCount,
            decisionAuditCoachingUrgentDelayCount = decisionAuditCoaching.urgentDelayCount,
            decisionAuditCoachingHighCostSupportCount = decisionAuditCoaching.highCostSupportCount,
            decisionAuditCoachingRecommendedMandateId = decisionAuditCoaching.recommendedMandateId,
            decisionAuditCoachingRecommendedMandateName = decisionAuditCoaching.recommendedMandateName,
            decisionAuditCoachingExecutionRule = decisionAuditCoaching.executionRule,
            decisionAuditCoachingVerificationQuestion = decisionAuditCoaching.verificationQuestion,
            decisionAuditCoachingAppealCaseId = decisionAuditCoaching.appealCaseId,
            decisionAuditCoachingSummaryLine = decisionAuditCoaching.summaryLine
        };

        database.records.Insert(0, record);
        while (database.records.Count > CareerRecordLimit)
        {
            database.records.RemoveAt(database.records.Count - 1);
        }

        SaveCareerRecordDatabase(database);
    }

    private void RegisterAgentCareerProfile(List<AgentRunSummary> summaries)
    {
        if (summaries == null || summaries.Count == 0 || logs.Count == 0)
        {
            return;
        }

        if (!TryGetClosestAgentSummary(summaries, out AgentRunSummary closest) || closest.playerComparableCount <= 0)
        {
            return;
        }

        string sessionId = EnsureSessionId();
        CareerRecordDatabase database = LoadCareerRecordDatabase();
        int recordIndex = FindCareerRecordIndex(database.records, sessionId, campaignStartedAt);
        if (recordIndex < 0 && database.records.Count > 0)
        {
            recordIndex = 0;
        }
        if (recordIndex < 0)
        {
            return;
        }

        CareerRecord record = database.records[recordIndex];
        float matchRate = closest.playerMatchedCount * 100f / Mathf.Max(1, closest.playerComparableCount);
        record.closestAgentPersonaId = closest.personaId;
        record.closestAgentPersonaName = closest.personaName;
        record.closestAgentMatchCount = closest.playerMatchedCount;
        record.closestAgentComparableCount = closest.playerComparableCount;
        record.closestAgentMatchRatePercent = matchRate;
        record.closestAgentProfileNote = BuildAgentCareerProfileNote(closest, matchRate);
        SaveCareerRecordDatabase(database);
    }

    private DecisionLog CareerRepresentativeLog()
    {
        DecisionLog selected = null;
        int bestScore = int.MinValue;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            int score = DecisionAuditPressureScore(log);
            if (!log.matchedRecommended)
            {
                score += 35;
            }
            if (!string.IsNullOrWhiteSpace(log.investigationFinding))
            {
                score += 24;
            }

            if (selected == null || score > bestScore)
            {
                selected = log;
                bestScore = score;
            }
        }

        return selected;
    }

    private DecisionLog CareerInvestigationMemoLog()
    {
        DecisionLog selected = null;
        int bestScore = int.MinValue;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (string.IsNullOrWhiteSpace(log.investigationFinding))
            {
                continue;
            }

            int score = DecisionAuditPressureScore(log);
            if (log.decision == "추가조사")
            {
                score += 30;
            }
            if (!log.matchedRecommended)
            {
                score += 12;
            }

            if (selected == null || score > bestScore)
            {
                selected = log;
                bestScore = score;
            }
        }

        return selected;
    }

