    private string CareerInvestigationMemoTimelineText()
    {
        DecisionLog log = CareerInvestigationMemoLog();
        if (log == null)
        {
            return "";
        }

        InvestigationFollowUpImpact impact = BuildInvestigationFollowUpImpact(log.day);
        string followUpLine = impact.count > 0
            ? $"D{log.day + 1} 후속 반영: 해금 메모 {impact.count}건({impact.caseBrief}) · 예산 {SignedNumber(impact.budgetDelta)}만원, 안정 {SignedNumber(impact.stabilityDelta)}, 형평 {SignedNumber(impact.equityDelta)}, 누락 {SignedNumber(impact.missedRiskDelta)}, 민원 {SignedNumber(impact.complaintsDelta)}"
            : $"D{log.day + 1} 후속 반영: 같은 날 해금 메모가 없어 별도 보정 없음";

        return
            $"D{log.day} #{log.decisionIndex:00} 조사 해금: {Shorten(log.investigationFinding, 96)}\n" +
            $"{followUpLine}\n" +
            $"최종 지표: 예산 {budget}만원 · 안정 {stability} · 형평 {equity} · 누락 {missedRisk} · 민원 {complaints}";
    }

    private static string CareerRecordCaseTimelineText(CareerRecord record, string caseId)
    {
        if (record == null || string.IsNullOrWhiteSpace(caseId))
        {
            return "";
        }

        if (string.Equals(record.investigationMemoCaseId, caseId, StringComparison.OrdinalIgnoreCase) &&
            !string.IsNullOrWhiteSpace(record.investigationMemoTimeline))
        {
            return record.investigationMemoTimeline;
        }

        if (string.Equals(record.appealRemedyObjectiveCaseId, caseId, StringComparison.OrdinalIgnoreCase) &&
            record.appealRemedyObjectiveCompleted)
        {
            string status = FallbackText(record.appealReviewStatus, "이의제기 보정");
            string remedy = FallbackText(record.appealReviewRemedy, "보정 목표 심사 완료");
            string challenge = FallbackText(record.appealRemedyObjectiveChallenge, record.appealRemedyObjectiveBadge);
            string result = !string.IsNullOrWhiteSpace(record.appealRemedyObjectiveProgress)
                ? $"보정 판정: {(record.appealRemedyObjectiveSucceeded ? "성공" : "미달")} · {record.appealRemedyObjectiveProgress}\n"
                : "";
            return
                $"이의제기 보정: {status} · 최고 {record.appealReviewMaxScore}점 · {Shorten(remedy, 94)}\n" +
                $"보정 목표 완료: {challenge}\n" +
                result +
                $"최종 지표: 예산 {record.finalBudget}만원 · 안정 {record.finalStability} · 형평 {record.finalEquity} · 누락 {record.finalMissedRisk} · 민원 {record.finalComplaints}";
        }

        return "";
    }

