    private string BuildNextCampaignPromptShort()
    {
        if (hasPendingNextCampaignObjective)
        {
            return CampaignMandateLabel(pendingNextCampaignObjective.mandate) + " " + pendingNextCampaignObjective.challenge;
        }

        return BuildLongTermProgressionPromptText();
