    private static bool TryGetClosestAgentSummary(List<AgentRunSummary> summaries, out AgentRunSummary closest)
    {
        closest = null;
        if (summaries == null || summaries.Count == 0)
        {
            return false;
        }

        for (int i = 0; i < summaries.Count; i++)
        {
            AgentRunSummary candidate = summaries[i];
            if (candidate.playerComparableCount <= 0)
            {
                continue;
            }

            if (closest == null ||
                candidate.playerMatchedCount > closest.playerMatchedCount ||
                (candidate.playerMatchedCount == closest.playerMatchedCount && candidate.matchedCount > closest.matchedCount) ||
                (candidate.playerMatchedCount == closest.playerMatchedCount && candidate.matchedCount == closest.matchedCount && string.Compare(candidate.personaName, closest.personaName, StringComparison.Ordinal) < 0))
            {
                closest = candidate;
            }
        }

        return closest != null;
    }

    private static string BuildAgentCareerProfileNote(AgentRunSummary closest, float matchRate)
    {
        string tendency;
        if (closest.investigateCount >= closest.supportCount && closest.investigateCount >= closest.holdOrRejectCount)
        {
            tendency = "조사와 근거 보강을 우선하는 운영";
        }
        else if (closest.supportCount >= closest.holdOrRejectCount)
        {
            tendency = "지원 결정을 빠르게 내리는 운영";
        }
        else
        {
            tendency = "예산과 절차 위험을 보수적으로 보는 운영";
        }

        return $"{closest.personaName}과 {matchRate:0}% 일치. 다음 회차에는 {tendency}에서 벗어난 사례를 의식적으로 비교할 수 있습니다.";
    }

    private static int FindCareerRecordIndex(List<CareerRecord> records, string sessionId, string startedAt)
    {
        bool hasSessionId = !string.IsNullOrEmpty(sessionId);
        bool hasStartedAt = !string.IsNullOrEmpty(startedAt);
        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (hasSessionId && record.sessionId == sessionId)
            {
                return i;
            }

            if (hasStartedAt &&
                record.campaignStartedAt == startedAt &&
                (!hasSessionId || string.IsNullOrEmpty(record.sessionId)))
            {
                return i;
            }
        }

        return -1;
    }

    private void RemoveCareerRecordForCurrentCampaign(CareerRecordDatabase database, string sessionId)
    {
        if (database == null)
        {
            return;
        }

        if (database.records == null)
        {
            database.records = new List<CareerRecord>();
            return;
        }

        int existingIndex = FindCareerRecordIndex(database.records, sessionId, string.IsNullOrEmpty(campaignStartedAt) ? "" : campaignStartedAt);
        if (existingIndex >= 0)
        {
            database.records.RemoveAt(existingIndex);
        }
    }

    private static CareerRecordDatabase LoadCareerRecordDatabase()
    {
        string json = PlayerPrefs.GetString(CareerRecordPrefsKey, "");
        if (string.IsNullOrWhiteSpace(json))
        {
            return new CareerRecordDatabase();
        }

        try
        {
            CareerRecordDatabase database = JsonUtility.FromJson<CareerRecordDatabase>(json);
            return database != null && database.records != null
                ? database
                : new CareerRecordDatabase();
        }
        catch (Exception exception)
        {
            Debug.LogWarning("Failed to load campaign career records. " + exception.Message);
            return new CareerRecordDatabase();
        }
    }

    private static void SaveCareerRecordDatabase(CareerRecordDatabase database)
    {
        if (database.records == null)
        {
            database.records = new List<CareerRecord>();
        }

        PlayerPrefs.SetString(CareerRecordPrefsKey, JsonUtility.ToJson(database));
        PlayerPrefs.Save();
    }

