    {
        return EndingSeenByMandatePrefsPrefix + CampaignMandateId(mandate) + "_" + endingId;
    }

    private static string LastEndingForMandateKey(CampaignMandate mandate)
    {
        return LastEndingByMandatePrefsPrefix + CampaignMandateId(mandate);
    }

    private static string CompactPath(string path, int maxLength)
    {
        string normalized = path.Replace("\\", "/");
        if (normalized.Length <= maxLength)
        {
            return normalized;
        }

        string[] pathMarkers =
        {
            "/Care Review Office/Care Review Office/",
            "/Care Review Office/",
            "/SNU Final Project Prototype/"
        };

        foreach (string pathMarker in pathMarkers)
        {
            int markerIndex = normalized.LastIndexOf(pathMarker, StringComparison.Ordinal);
            if (markerIndex >= 0)
            {
                string shortened = "..." + normalized.Substring(markerIndex);
                if (shortened.Length <= maxLength)
                {
                    return shortened;
                }
            }
        }

        return "..." + normalized.Substring(normalized.Length - maxLength + 3);
    }

