    private void SaveSessionIfEnabled(bool reportShown)
    {
        if (autoSaveEnabled)
        {
            SaveSession(reportShown);
        }
    }

    private void SaveSession(bool reportShown)
    {
        try
        {
            Directory.CreateDirectory(Application.persistentDataPath);
            SaveData data = new()
            {
                version = SaveDataVersion,
                savedAt = DateTime.Now.ToString("s"),
                saveSlot = activeSaveSlot,
                currentSessionId = EnsureSessionId(),
                campaignStartedAt = string.IsNullOrEmpty(campaignStartedAt) ? DateTime.Now.ToString("s") : campaignStartedAt,
                totalPlaySeconds = CurrentCampaignElapsedSeconds(),
                campaignMandate = (int)this.campaignMandate,
                selectedDecisionRationaleIndex = this.selectedDecisionRationaleIndex,
                appealRemedyGraphTriageCandidateIndex = Mathf.Max(0, this.appealRemedyGraphTriageCandidateIndex),
                currentIndex = Mathf.Clamp(currentIndex, 0, cases.Count),
                budget = budget,
                stability = stability,
                equity = equity,
                missedRisk = missedRisk,
                complaints = complaints,
                investigations = investigations,
                awaitingNext = awaitingNext,
                reportShown = reportShown,
                dayTransitionShown = dayTransitionRoot != null && dayTransitionRoot.gameObject.activeSelf,
                logs = new List<DecisionLog>(logs),
                incidentLogs = new List<IncidentLog>(incidentLogs)
            };
            WriteSaveFileWithBackup(
                SavePath,
                SaveBackupPathForSlot(activeSaveSlot),
                SaveTempPathForSlot(activeSaveSlot),
                JsonUtility.ToJson(data, true));
        }
        catch (Exception exception)
        {
            Debug.LogWarning("Failed to save campaign session. " + exception.Message);
        }
    }

    private bool LoadSession()
    {
        if (!File.Exists(SavePath) && !File.Exists(SaveBackupPathForSlot(activeSaveSlot)))
        {
            return false;
        }

        if (!TryLoadSaveDataWithBackup(
            SavePath,
            SaveBackupPathForSlot(activeSaveSlot),
            out SaveData data,
            out bool recoveredFromBackup,
            out string loadError))
        {
            Debug.LogWarning("Failed to load campaign session. " + loadError);
            return false;
        }

        if (recoveredFromBackup)
        {
            Debug.LogWarning("Recovered campaign session from backup save file.");
        }

        try
        {
            campaignMandate = ClampCampaignMandate(data.campaignMandate);
            selectedDecisionRationaleIndex = ClampDecisionRationaleIndex(data.selectedDecisionRationaleIndex);
            appealRemedyGraphTriageCandidateIndex = Mathf.Max(0, data.appealRemedyGraphTriageCandidateIndex);
            PersistAppealRemedyGraphTriageCandidateIndex();
            currentSessionId = string.IsNullOrEmpty(data.currentSessionId) ? GenerateSessionId() : data.currentSessionId;
            campaignStartedAt = string.IsNullOrEmpty(data.campaignStartedAt) ? data.savedAt : data.campaignStartedAt;
            if (string.IsNullOrEmpty(campaignStartedAt))
            {
                campaignStartedAt = DateTime.Now.ToString("s");
            }
            accumulatedPlaySeconds = Mathf.Max(0, data.totalPlaySeconds);
            campaignRuntimeStartRealtime = Time.realtimeSinceStartup;
            currentIndex = Mathf.Clamp(data.currentIndex, 0, cases.Count);
            budget = data.budget;
            stability = data.stability;
            equity = data.equity;
            missedRisk = data.missedRisk;
            complaints = data.complaints;
            investigations = data.investigations;
            logs.Clear();
            if (data.logs != null)
            {
                logs.AddRange(data.logs);
            }
            incidentLogs.Clear();
            if (data.incidentLogs != null)
            {
                incidentLogs.AddRange(data.incidentLogs);
            }

        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        achievementRoot.gameObject.SetActive(false);
        careerRecordRoot.gameObject.SetActive(false);
        tutorialRoot.gameObject.SetActive(false);
        creditsRoot.gameObject.SetActive(false);

            if (data.dayTransitionShown && currentIndex < cases.Count)
            {
                reviewRoot.gameObject.SetActive(false);
                reportRoot.gameObject.SetActive(false);
                ShowDayTransition(currentIndex);
                return true;
            }

            bool reportShown = data.reportShown || currentIndex >= cases.Count || logs.Count >= cases.Count;
            if (reportShown)
            {
                reviewRoot.gameObject.SetActive(false);
                dayTransitionRoot.gameObject.SetActive(false);
                ShowReport();
                return true;
            }

            dayTransitionRoot.gameObject.SetActive(false);
            reportRoot.gameObject.SetActive(false);
            reviewRoot.gameObject.SetActive(true);
            ShowCase(currentIndex);
            RestoreAwaitingDecisionState(data.awaitingNext);
            UpdateMetrics();
            return true;
        }
        catch (Exception exception)
        {
            Debug.LogWarning("Failed to load campaign session. " + exception.Message);
            return false;
        }
    }

    private static void WriteSaveFileWithBackup(string savePath, string backupPath, string tempPath, string json)
    {
        string directory = Path.GetDirectoryName(savePath);
        if (!string.IsNullOrEmpty(directory))
        {
            Directory.CreateDirectory(directory);
        }

        DeleteFileIfExists(tempPath);
        if (File.Exists(savePath))
        {
            File.Copy(savePath, backupPath, true);
        }

        File.WriteAllText(tempPath, json, Encoding.UTF8);
        DeleteFileIfExists(savePath);
        File.Move(tempPath, savePath);
    }

    private static bool TryLoadSaveDataWithBackup(string savePath, string backupPath, out SaveData data, out bool recoveredFromBackup, out string error)
    {
        recoveredFromBackup = false;
        if (TryReadSaveDataFile(savePath, out data, out error))
        {
            return true;
        }

        string primaryError = error;
        if (!TryReadSaveDataFile(backupPath, out data, out error))
        {
            error = string.IsNullOrEmpty(primaryError)
                ? error
                : primaryError + "; backup: " + error;
            return false;
        }

        try
        {
            File.Copy(backupPath, savePath, true);
            recoveredFromBackup = true;
            error = "";
            return true;
        }
        catch (Exception exception)
        {
            recoveredFromBackup = true;
            error = "backup loaded but primary restore failed: " + exception.Message;
            return true;
        }
    }

    private static bool TryReadSaveDataFile(string path, out SaveData data, out string error)
    {
        data = null;
        error = "";
        if (string.IsNullOrEmpty(path) || !File.Exists(path))
        {
            error = "save file missing";
            return false;
        }

        try
        {
            data = JsonUtility.FromJson<SaveData>(File.ReadAllText(path, Encoding.UTF8));
            return ValidateSaveData(data, out error);
        }
        catch (Exception exception)
        {
            error = exception.Message;
            return false;
        }
    }

    private static bool ValidateSaveData(SaveData data, out string error)
    {
        if (data == null)
        {
            error = "save data is empty";
            return false;
        }

        if (data.version <= 0)
        {
            data.version = 1;
        }

        if (data.version > SaveDataVersion)
        {
            error = "save data version is newer than this build";
            return false;
        }

        if (string.IsNullOrEmpty(data.savedAt))
        {
            error = "save timestamp is missing";
            return false;
        }

        error = "";
        return true;
    }

    private static void DeleteFileIfExists(string path)
    {
        if (!string.IsNullOrEmpty(path) && File.Exists(path))
        {
            File.Delete(path);
        }
    }

    private void RestoreAwaitingDecisionState(bool savedAwaitingNext)
    {
        if (!savedAwaitingNext || logs.Count == 0)
        {
            return;
        }

        DecisionLog lastLog = logs[logs.Count - 1];
        ResetDecisionImpactVisuals();
        awaitingNext = true;
        nextButton.gameObject.SetActive(true);
        feedbackStampImage.sprite = StampForDecisionLabel(lastLog.decision);
        feedbackStampImage.color = new Color(1, 1, 1, 0.92f);
        feedbackText.text =
            lastLog.matchedRecommended
                ? $"{lastLog.decision}: 저장된 판단입니다. 다음 사례로 넘어가세요."
                : $"{lastLog.decision}: 권장 판단은 {lastLog.recommendedDecision}입니다. 저장된 판단을 이어갑니다.";
        ShowMetricDeltaFeedback(
            lastLog.budgetAfter - lastLog.budgetBefore,
            lastLog.stabilityAfter - lastLog.stabilityBefore,
            lastLog.equityAfter - lastLog.equityBefore,
            lastLog.missedRiskAfter - lastLog.missedRiskBefore,
            lastLog.complaintsAfter - lastLog.complaintsBefore,
            lastLog.consequenceTitle);
    }

    private Sprite StampForDecisionLabel(string decision)
    {
        return decision switch
        {
            "승인" => GridSprite(documentsStampsSheet, 4, 4, 2, 3),
            "조건부 승인" => GridSprite(documentsStampsSheet, 4, 4, 1, 2),
            "추가조사" => GridSprite(documentsStampsSheet, 4, 4, 2, 2),
            "거절" => GridSprite(documentsStampsSheet, 4, 4, 1, 3),
            _ => GridSprite(documentsStampsSheet, 4, 4, 3, 3)
        };
    }

