    private static int EvidenceLabelFontSize(string label)
    {
        if (string.IsNullOrEmpty(label))
        {
            return 11;
        }

        return label.Length >= 4 ? 14 : 15;
    }

    private static string EvidenceCaptionText(string label)
    {
        return label == "소득 증명" ? "소득증명" : label;
    }

    private static void ApplyEvidenceLabelText(Text label, string text)
    {
        if (label == null)
        {
            return;
        }

        label.text = EvidenceCaptionText(text);
        label.fontSize = EvidenceLabelFontSize(text);
        label.resizeTextMaxSize = label.fontSize;
        label.resizeTextMinSize = Mathf.Min(12, label.fontSize);
    }

    private void UpdateDocumentStrip(CareCase careCase, int caseIndex)
    {
        if (documentStripImages == null || documentStripLabels == null)
        {
            return;
        }

        int[] evidenceIndices = EvidenceIndicesForCase(careCase, caseIndex);
        for (int i = 0; i < documentStripImages.Length && i < evidenceIndices.Length; i++)
        {
            int evidenceIndex = Mathf.Clamp(evidenceIndices[i], 0, EvidenceCardLabels.Length - 1);
            documentStripImages[i].sprite = EvidenceSprite(evidenceIndex);
            ApplyEvidenceLabelText(documentStripLabels[i], EvidenceCardLabels[evidenceIndex]);
        }
    }

    private int[] EvidenceIndicesForCase(CareCase careCase, int caseIndex)
    {
        int[] evidence = { 0, 1, 2, 3 };
        string type = careCase.type ?? "";
        string documents = careCase.documents ?? "";
        string signal = careCase.signal ?? "";
        string summary = careCase.summary ?? "";
        string combined = type + "\n" + documents + "\n" + signal + "\n" + summary;

        evidence[0] = 0;
        evidence[1] = 1;

        bool hasHousingSignal =
            combined.Contains("주거") ||
            combined.Contains("월세") ||
            combined.Contains("임대") ||
            combined.Contains("임시거주") ||
            combined.Contains("거주지") ||
            combined.Contains("전입") ||
            combined.Contains("체납") ||
            combined.Contains("쉼터") ||
            combined.Contains("화재");

        if (combined.Contains("근무") || combined.Contains("야간"))
        {
            evidence[2] = 4;
        }
        else if (combined.Contains("의료") || combined.Contains("낙상") || combined.Contains("치료") || combined.Contains("약 "))
        {
            evidence[2] = 3;
        }
        else if (hasHousingSignal)
        {
            evidence[2] = 5;
        }
        else if (combined.Contains("학교") || combined.Contains("결석") || combined.Contains("특수교육") || combined.Contains("상담"))
        {
            evidence[2] = 2;
        }
        else if (combined.Contains("보육") || combined.Contains("대기"))
        {
            evidence[2] = 7;
        }
        else if (combined.Contains("주거") || combined.Contains("월세") || combined.Contains("임대"))
        {
            evidence[2] = 5;
        }
        else
        {
            evidence[2] = (caseIndex % 3) switch
            {
                0 => 6,
                1 => 9,
                _ => 11
            };
        }

        if (careCase.documentStrength < 45 || combined.Contains("누락") || combined.Contains("미제출"))
        {
            evidence[3] = 10;
        }
        else if (hasHousingSignal && careCase.documentStrength < 65)
        {
            evidence[3] = 5;
        }
        else if (careCase.urgency >= 82)
        {
            evidence[3] = 8;
        }
        else if (careCase.equityNeed >= 82)
        {
            evidence[3] = 7;
        }
        else if (combined.Contains("전화") || combined.Contains("면담") || combined.Contains("통화"))
        {
            evidence[3] = 9;
        }
        else if (careCase.documentStrength >= 70)
        {
            evidence[3] = 11;
        }
        else
        {
            evidence[3] = 6;
        }

        return evidence;
    }

