    private void ShowCase(int index)
    {
        PlayBgm(ReviewBgmKey);
        dayTransitionRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        awaitingNext = false;
        nextButton.gameObject.SetActive(false);
        ResetDecisionImpactVisuals();
        feedbackStampImage.color = new Color(1, 1, 1, 0f);
        CareCase c = cases[index];
        portraitImage.sprite = PortraitSprite(c.portraitIndex >= 0 ? c.portraitIndex : index);
        UpdateDocumentStrip(c, index);
        caseHeaderText.text = $"{c.id}\n{c.name}";
        progressText.text = $"{c.day}일차 · {index + 1} / {cases.Count}번째 신청서";
        UpdateCaseSnapshot(c);
        caseBodyText.text =
            $"유형: {c.type}\n\n" +
            $"요청: {c.request}\n\n" +
            $"{c.summary}\n\n" +
            $"위험 신호: {c.signal}";
        documentsText.text = c.documents;
        regulationText.text = BuildRegulationText();
        feedbackText.text = "신청서와 소득증명을 대조한 뒤 도장을 찍으세요.";
        UpdateDecisionRationaleButton();
        ClearMetricDeltaFeedback();
        UpdateDecisionPreviewStrip(c);
        UpdateMetrics();
        if (policyHandbookRoot != null && policyHandbookRoot.gameObject.activeSelf)
        {
            UpdatePolicyHandbookContent();
        }
        if (followUpInboxRoot != null && followUpInboxRoot.gameObject.activeSelf)
        {
            UpdateFollowUpInboxContent();
        }
        MaybeShowFirstCaseGuide();
        PlaySfx(paperSlideClip, 0.28f);
        SelectFirstInteractableButton(CurrentInteractiveRoot());
    }

    private void BuildDecisionPreviewStrip()
    {
        decisionPreviewTexts = new Text[PolicyDecisionOrder.Length];
        Vector2[] positions =
        {
            new Vector2(-420, -394),
            new Vector2(-210, -394),
            new Vector2(0, -394),
            new Vector2(210, -394),
            new Vector2(420, -394)
        };

        for (int i = 0; i < decisionPreviewTexts.Length && i < positions.Length; i++)
        {
            decisionPreviewTexts[i] = CreateTextBox(
                reviewRoot,
                "Decision Preview " + PolicyDecisionOrder[i],
                positions[i],
                new Vector2(154, 32),
                new Color32(26, 30, 28, 64),
                1,
                "",
                9,
                TextAnchor.MiddleCenter,
                new Color32(246, 232, 202, 118),
                FontStyle.Bold);
        }
    }

    private void UpdateDecisionPreviewStrip(CareCase careCase)
    {
        if (decisionPreviewTexts == null || careCase == null)
        {
            return;
        }

        for (int i = 0; i < decisionPreviewTexts.Length && i < PolicyDecisionOrder.Length; i++)
        {
            Text previewText = decisionPreviewTexts[i];
            if (previewText == null)
            {
                continue;
            }

            DecisionKind kind = PolicyDecisionOrder[i];
            DecisionPreview preview = BuildDecisionPreview(careCase, kind, campaignMandate, budget, stability, equity, missedRisk, complaints);
            string recommendationTag = DecisionPreviewRecommendationTag(preview.decisionLabel, careCase.recommendedDecision);
            int riskDelta = preview.missedRiskDelta + preview.complaintsDelta;
            previewText.text = BuildDecisionPreviewText(preview, recommendationTag, riskDelta);

            Image backer = previewText.transform.parent != null
                ? previewText.transform.parent.GetComponent<Image>()
                : null;
            if (backer != null)
            {
                backer.color = DecisionPreviewBackerColor(kind, recommendationTag);
            }
            ConfigureDecisionPreviewPresentation(previewText, recommendationTag);
        }
    }

    private void ConfigureDecisionPreviewPresentation(Text previewText, string recommendationTag)
    {
        if (previewText == null)
        {
            return;
        }

        if (recommendationTag == "권장")
        {
            previewText.fontSize = AdjustedFontSize(8);
            previewText.color = new Color32(246, 232, 202, 255);
            previewText.lineSpacing = 0.95f;
            return;
        }

        if (recommendationTag == "대체")
        {
            previewText.fontSize = AdjustedFontSize(7);
            previewText.color = new Color32(238, 219, 184, 150);
            previewText.lineSpacing = 0.92f;
            return;
        }

        previewText.fontSize = AdjustedFontSize(6);
        previewText.color = new Color32(220, 204, 172, 72);
        previewText.lineSpacing = 0.88f;
    }

    private static string BuildDecisionPreviewText(DecisionPreview preview, string recommendationTag, int riskDelta)
    {
        string recommendedPrefix = string.IsNullOrEmpty(recommendationTag) ? "" : recommendationTag + " · ";
        return
            $"{recommendedPrefix}{preview.decisionLabel}\n" +
            $"예산 {SignedNumber(preview.budgetDelta)}만 · 위험 {SignedNumber(riskDelta)}";
    }

    private static string DecisionPreviewRecommendationTag(string decision, string recommendedDecision)
    {
        if (decision == recommendedDecision)
        {
            return "권장";
        }

        return MatchesRecommended(decision, recommendedDecision) ? "대체" : "";
    }

    private static Color32 DecisionPreviewBackerColor(DecisionKind kind, string recommendationTag)
    {
        if (recommendationTag == "권장")
        {
            return new Color32(78, 96, 58, 170);
        }
        if (recommendationTag == "대체")
        {
            return new Color32(83, 72, 46, 108);
        }

        return kind switch
        {
            DecisionKind.Approve => new Color32(37, 55, 42, 58),
            DecisionKind.Conditional => new Color32(58, 56, 38, 58),
            DecisionKind.Investigate => new Color32(35, 44, 56, 58),
            DecisionKind.Reject => new Color32(62, 38, 34, 58),
            _ => new Color32(38, 40, 38, 52)
        };
    }

    private void UpdateCaseSnapshot(CareCase careCase)
    {
        if (caseSnapshotText == null)
        {
            return;
        }

        string incomeLabel = careCase.incomeEligible ? "소득 적합" : "소득 예외";
        string missingLabel = string.IsNullOrWhiteSpace(careCase.missingDocuments)
            ? "누락 없음"
            : Shorten(careCase.missingDocuments, 22);
        caseSnapshotText.text =
            $"먼저 볼 것: 긴급 {careCase.urgency} · 형평 {careCase.equityNeed} · 서류 {careCase.documentStrength}\n" +
            $"{incomeLabel} · 보강: {missingLabel}\n" +
            $"사례 플래그: {BuildCaseOperationalFlag(careCase)}";

        if (caseSnapshotBacker != null)
        {
            caseSnapshotBacker.color = CaseSnapshotColor(careCase);
        }
    }

    private static Color32 CaseSnapshotColor(CareCase careCase)
    {
        int pressure = Mathf.Max(careCase.urgency, careCase.equityNeed, 100 - careCase.documentStrength);
        if (pressure >= 92)
        {
            return new Color32(105, 43, 38, 212);
        }

        if (pressure >= 82)
        {
            return new Color32(99, 73, 39, 204);
        }

        return new Color32(31, 42, 40, 192);
    }

    private string BuildRegulationText()
    {
        int day = currentIndex >= 0 && currentIndex < cases.Count ? cases[currentIndex].day : 1;
        return
            $"운영 기준: {CampaignMandateLabel(campaignMandate)} · {CampaignMandateBrief(campaignMandate)}\n" +
            BuildCurrentDayOperationsFocus(day) +
            BuildGrowthObjectiveReviewProgressText() +
            BuildAppealRemedyObjectiveReviewProgressText() +
            BuildDecisionAuditCoachingReviewProgressText();
    }

    private bool CurrentCampaignIsAppealRemedyObjective()
    {
        return currentCampaignStartedFromCaseObjective &&
            currentCampaignCaseObjectiveChallenge.Contains("이의제기") &&
            currentCampaignCaseObjectiveChallenge.Contains("보정");
    }

    private string BuildAppealRemedyObjectiveReviewProgressText()
    {
        if (!CurrentCampaignIsAppealRemedyObjective())
        {
            return "";
        }

        int matchedCount = 0;
        int highRiskDelayCount = 0;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (log.matchedRecommended)
            {
                matchedCount++;
            }
            if (log.urgency >= 82 &&
                (log.decision.Contains("거절") || log.decision.Contains("보류")))
            {
                highRiskDelayCount++;
            }
        }

        float matchRate = logs.Count > 0 ? matchedCount * 100f / logs.Count : 0f;
        int riskScore = missedRisk + complaints;
        string reasonLine = !string.IsNullOrWhiteSpace(currentCampaignCaseObjectiveReason)
            ? $"\n근거 {Shorten(currentCampaignCaseObjectiveReason, 48)}"
            : "";
        return
            "\n\n이의제기 보정 진행\n" +
            $"{currentCampaignCaseObjectiveId} · {Shorten(currentCampaignCaseObjectiveChallenge, 38)}\n" +
            $"처리 {logs.Count}/{cases.Count} · 권장 {matchRate:0}% · 고위험 지연 {highRiskDelayCount} · 위험 {riskScore}" +
            reasonLine;
    }

    private string BuildGrowthObjectiveReviewProgressText()
    {
        if (!currentCampaignStartedFromGrowthObjective && !currentCampaignStartedFromGrowthFollowUpObjective)
        {
            return "";
        }

        int matchedCount = 0;
        for (int i = 0; i < logs.Count; i++)
        {
            if (logs[i].matchedRecommended)
            {
                matchedCount++;
            }
        }

        float matchRate = logs.Count > 0 ? matchedCount * 100f / logs.Count : 0f;
        int riskScore = missedRisk + complaints;
        string title = currentCampaignStartedFromGrowthObjective ? "성장 목표 진행" : "성장 후속 진행";
        string challenge = currentCampaignStartedFromGrowthObjective
            ? currentCampaignGrowthObjectiveChallenge
            : currentCampaignGrowthFollowUpChallenge;
        return
            $"\n\n{title}\n" +
            $"{Shorten(challenge, 42)}\n" +
            $"처리 {logs.Count}/{cases.Count} · 권장 {matchRate:0}% · 위험 {riskScore} · 예산 {budget}만";
    }

    private string BuildDecisionAuditCoachingReviewProgressText()
    {
        if (!currentCampaignStartedFromDecisionAuditCoachingObjective)
        {
            return "";
        }

        int highCostSupportCount = 0;
        int highRiskDelayCount = 0;
        int mismatchCount = 0;
        int appealRemedyCount = 0;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
            {
                highCostSupportCount++;
            }
            if (IsDelayDecision(log.decision) && log.urgency >= 78)
            {
                highRiskDelayCount++;
            }
            if (!log.matchedRecommended)
            {
                mismatchCount++;
            }
            if (log.urgency >= 80 && log.matchedRecommended)
            {
                appealRemedyCount++;
            }
        }

        string focusMetric = BuildDecisionAuditCoachingFocusProgressLine(
            currentCampaignDecisionAuditCoachingChallenge,
            highCostSupportCount,
            highRiskDelayCount,
            mismatchCount,
            appealRemedyCount);
        string reasonLine = !string.IsNullOrWhiteSpace(currentCampaignDecisionAuditCoachingReason)
            ? $"\n근거 {Shorten(currentCampaignDecisionAuditCoachingReason, 50)}"
            : "";

        return
            "\n\n판단 복기 진행\n" +
            $"{currentCampaignDecisionAuditCoachingPattern} · {Shorten(currentCampaignDecisionAuditCoachingChallenge, 40)}\n" +
            $"처리 {logs.Count}/{cases.Count} · {focusMetric}" +
            reasonLine;
    }

    private static string BuildDecisionAuditCoachingFocusProgressLine(string challenge, int highCostSupportCount, int highRiskDelayCount, int mismatchCount, int appealRemedyCount)
    {
        if (challenge.Contains("고비용 지원"))
        {
            return $"고비용 지원 {highCostSupportCount}/3 · 고위험 지연 {highRiskDelayCount} · 불일치 {mismatchCount}";
        }
        if (challenge.Contains("고위험 지연"))
        {
            return $"고위험 지연 {highRiskDelayCount}/3 · 고비용 지원 {highCostSupportCount} · 불일치 {mismatchCount}";
        }
        if (challenge.Contains("권장 불일치"))
        {
            return $"권장 불일치 {mismatchCount}/5 · 고위험 지연 {highRiskDelayCount} · 고비용 지원 {highCostSupportCount}";
        }
        if (challenge.Contains("이의제기 보정"))
        {
            return $"보정 재심사 {appealRemedyCount}/1 · 고위험 지연 {highRiskDelayCount} · 불일치 {mismatchCount}";
        }

        return $"불일치 {mismatchCount} · 고위험 지연 {highRiskDelayCount} · 고비용 지원 {highCostSupportCount}";
    }

    private string BuildCurrentDayOperationsFocus(int day)
    {
        int dayCaseCount = 0;
        int highRiskCount = 0;
        int documentWeakCount = 0;
        int incomeExceptionCount = 0;
        int highCostCount = 0;
        int investigationRecommendedCount = 0;
        int totalPressure = 0;

        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            if (careCase.day != day)
            {
                continue;
            }

            dayCaseCount++;
            int pressure = CasePressureScore(careCase);
            totalPressure += pressure;
            if (careCase.urgency >= 82 || pressure >= 78)
            {
                highRiskCount++;
            }
            if (careCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(careCase.missingDocuments))
            {
                documentWeakCount++;
            }
            if (!careCase.incomeEligible)
            {
                incomeExceptionCount++;
            }
            if (GetDecisionCost(DecisionKind.Approve, careCase) >= 300)
            {
                highCostCount++;
            }
            if (careCase.recommendedDecision == "추가조사")
            {
                investigationRecommendedCount++;
            }
        }

        int averagePressure = dayCaseCount > 0 ? Mathf.RoundToInt(totalPressure / (float)dayCaseCount) : 0;
        return
            $"오늘 운영 초점 · 오늘 접수 {dayCaseCount} · 평균 압박 {averagePressure}/100\n" +
            $"고위험 {highRiskCount} · 서류 {documentWeakCount} · 비용 {highCostCount} · {BuildCurrentDayProgressLine(day)}\n" +
            "판단 순서: " + BuildNextDayFocusLine(highRiskCount, documentWeakCount, incomeExceptionCount, highCostCount, investigationRecommendedCount, averagePressure);
    }

    private string BuildCurrentDayProgressLine(int day)
    {
        int dayCaseCount = 0;
        int processedCount = 0;
        int remainingHighRiskCount = 0;
        int unlockedInvestigationFindingCount = 0;

        List<string> processedCaseIds = new();
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (log.day != day)
            {
                continue;
            }

            processedCount++;
            processedCaseIds.Add(log.caseId);
            if (!string.IsNullOrWhiteSpace(log.investigationFinding))
            {
                unlockedInvestigationFindingCount++;
            }
        }

        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            if (careCase.day != day)
            {
                continue;
            }

            dayCaseCount++;
            if (processedCaseIds.Contains(careCase.id))
            {
                continue;
            }

            int pressure = CasePressureScore(careCase);
            if (careCase.urgency >= 82 || pressure >= 78)
            {
                remainingHighRiskCount++;
            }
        }

        int remainingCount = Mathf.Max(0, dayCaseCount - processedCount);
        return $"오늘 진행 {processedCount}/{dayCaseCount} · 남은 {remainingCount} · 남은 고위험 {remainingHighRiskCount} · 조사 메모 {unlockedInvestigationFindingCount}";
    }

    private static string BuildCaseOperationalFlag(CareCase careCase)
    {
        int pressure = CasePressureScore(careCase);
        if (careCase.urgency >= 86 || pressure >= 82)
        {
            return "고위험 우선";
        }
        if (careCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(careCase.missingDocuments))
        {
            return "서류보강";
        }
        if (!careCase.incomeEligible)
        {
            return "소득예외";
        }
        if (GetDecisionCost(DecisionKind.Approve, careCase, CampaignMandate.Standard) >= 300)
        {
            return "고비용";
        }
        if (careCase.recommendedDecision == "추가조사")
        {
            return "조사권장";
        }

        return "표준 검토";
    }

    private void AdvanceToNextCase()
    {
        int previousIndex = currentIndex;
        currentIndex++;
        if (currentIndex >= cases.Count)
        {
            if (previousIndex >= 0 && previousIndex < cases.Count)
            {
                ApplyDayTransitionEffects(cases[previousIndex].day, false);
            }
            PlaySfx(reportClip, 0.95f);
            ShowReport();
            return;
        }

        if (ShouldShowDayTransition(previousIndex, currentIndex))
        {
            ApplyDayTransitionEffects(cases[previousIndex].day);
            ShowDayTransition(currentIndex);
            SaveSessionIfEnabled(false);
            return;
        }

        PlaySfx(pageTurnClip, 0.65f);
        ShowCase(currentIndex);
        SaveSessionIfEnabled(false);
    }

    private bool ShouldShowDayTransition(int previousIndex, int nextIndex)
    {
        return previousIndex >= 0 &&
            previousIndex < cases.Count &&
            nextIndex >= 0 &&
            nextIndex < cases.Count &&
            cases[previousIndex].day != cases[nextIndex].day;
    }

    private void ShowDayTransition(int nextCaseIndex)
    {
        PlayBgm(PolicyBgmKey);
        int nextDay = cases[nextCaseIndex].day;
        int dayStart = 0;
        int dayCount = 0;
        for (int i = 0; i < cases.Count; i++)
        {
            if (cases[i].day == nextDay)
            {
                if (dayCount == 0)
                {
                    dayStart = i;
                }
                dayCount++;
            }
        }

        menuRoot.gameObject.SetActive(false);
        settingsRoot.gameObject.SetActive(false);
        creditsRoot.gameObject.SetActive(false);
        achievementRoot.gameObject.SetActive(false);
        careerRecordRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        dayTransitionRoot.gameObject.SetActive(true);

        int completedDay = nextDay - 1;
        IncidentLog mainIncident = LatestIncidentForDay(completedDay);
        ConfigureDayTransitionIncidentVisual(mainIncident);
        dayTransitionIncidentImage.sprite = IncidentSprite(mainIncident != null ? mainIncident.type : "budget_audit");
        dayTransitionIncidentImage.color = mainIncident != null ? Color.white : new Color(1f, 1f, 1f, 0.58f);
        dayTransitionIncidentTitleText.text = mainIncident != null ? $"{mainIncident.title} · {IncidentSeverityLabel(mainIncident)}" : "특별 사건 없음";
        dayTransitionIncidentImpactText.text = mainIncident != null
            ? IncidentImpactLine(mainIncident) + "\n" + IncidentBrief(mainIncident)
            : "전날 지표 변화와 예산 재배정만 반영됩니다.";
        PlayIncidentSfx(mainIncident);
        StartDayTransitionIncidentReveal(mainIncident);

        dayTransitionTitleText.text = $"{nextDay}일차 브리핑";
        dayTransitionBodyText.text =
            $"전날 심사 종료\n" +
            $"처리한 신청서: {dayStart}건 / 현재 지표: 예산 {budget}만원, 안정 {stability}, 형평 {equity}, 누락 {missedRisk}, 민원 {complaints}\n\n" +
            BuildTransitionEffectText(completedDay) +
            "\n\n" +
            BuildNextDayOperationsBriefing(nextDay) +
            "\n\n" +
            $"{nextDay}일차에는 {dayCount}건의 새 신청서가 접수되었습니다. 전날 판단의 결과가 예산 압박과 민원 위험으로 이어진 상태에서, 소득 기준 예외와 안전 위험을 다시 비교해야 합니다.\n\n" +
            "캠페인 구조에서는 날짜가 넘어갈수록 같은 승인 기준도 다른 압력을 받게 됩니다.";
        SelectFirstInteractableButton(dayTransitionRoot);
    }

    private void ApplyDayTransitionEffects(int completedDay, bool addNextDayReallocation = true)
    {
        int budgetDelta = 0;
        int stabilityDelta = 0;
        int equityDelta = 0;
        int missedRiskDelta = 0;
        int complaintsDelta = 0;

        foreach (DecisionLog log in logs)
        {
            if (log.day != completedDay)
            {
                continue;
            }

            budgetDelta += log.consequenceBudgetDelta;
            stabilityDelta += log.consequenceStabilityDelta;
            equityDelta += log.consequenceEquityDelta;
            missedRiskDelta += log.consequenceMissedRiskDelta;
            complaintsDelta += log.consequenceComplaintsDelta;
        }

        budget += budgetDelta;
        stability = Mathf.Clamp(stability + stabilityDelta, 0, 100);
        equity = Mathf.Clamp(equity + equityDelta, 0, 100);
        missedRisk = Mathf.Clamp(missedRisk + missedRiskDelta, 0, 100);
        complaints = Mathf.Clamp(complaints + complaintsDelta, 0, 100);

        InvestigationFollowUpImpact investigationImpact = BuildInvestigationFollowUpImpact(completedDay);
        if (investigationImpact.count > 0)
        {
            budget += investigationImpact.budgetDelta;
            stability = Mathf.Clamp(stability + investigationImpact.stabilityDelta, 0, 100);
            equity = Mathf.Clamp(equity + investigationImpact.equityDelta, 0, 100);
            missedRisk = Mathf.Clamp(missedRisk + investigationImpact.missedRiskDelta, 0, 100);
            complaints = Mathf.Clamp(complaints + investigationImpact.complaintsDelta, 0, 100);
            currentCampaignInvestigationFollowUpCount += investigationImpact.count;
        }

        TriggerSpecialIncidents(completedDay);
        if (addNextDayReallocation)
        {
            budget += CalculateDailyBudgetReallocation(completedDay + 1);
        }
    }

    private string BuildTransitionEffectText(int completedDay)
    {
        SumDayConsequenceDeltas(
            completedDay,
            out int budgetDelta,
            out int stabilityDelta,
            out int equityDelta,
            out int missedRiskDelta,
            out int complaintsDelta);
        List<string> highlights = new();

        foreach (DecisionLog log in logs)
        {
            if (log.day != completedDay)
            {
                continue;
            }

            if (highlights.Count < 3 && !string.IsNullOrEmpty(log.consequenceTitle))
            {
                highlights.Add($"{Shorten(log.caseName, 6)}: {log.consequenceTitle}");
            }
        }

        string highlightText = highlights.Count > 0 ? string.Join(" / ", highlights) : "특이 후폭풍 없음";
        int nextDayAllocation = CalculateDailyBudgetReallocation(completedDay + 1);
        return
            $"전날 후폭풍: 예산 {SignedNumber(budgetDelta)}만원, 안정 {SignedNumber(stabilityDelta)}, 형평 {SignedNumber(equityDelta)}, 누락 {SignedNumber(missedRiskDelta)}, 민원 {SignedNumber(complaintsDelta)}\n" +
            BuildInvestigationFollowUpText(completedDay) + "\n" +
            $"다음 날 기본 예산 재배정: {SignedNumber(nextDayAllocation)}만원\n" +
            $"주요 이슈: {highlightText}\n" +
            BuildIncidentSummary(completedDay);
    }

    private void SumDayConsequenceDeltas(
        int completedDay,
        out int budgetDelta,
        out int stabilityDelta,
        out int equityDelta,
        out int missedRiskDelta,
        out int complaintsDelta)
    {
        budgetDelta = 0;
        stabilityDelta = 0;
        equityDelta = 0;
        missedRiskDelta = 0;
        complaintsDelta = 0;

        foreach (DecisionLog log in logs)
        {
            if (log.day != completedDay)
            {
                continue;
            }

            budgetDelta += log.consequenceBudgetDelta;
            stabilityDelta += log.consequenceStabilityDelta;
            equityDelta += log.consequenceEquityDelta;
            missedRiskDelta += log.consequenceMissedRiskDelta;
            complaintsDelta += log.consequenceComplaintsDelta;
        }
    }

    private InvestigationFollowUpImpact BuildInvestigationFollowUpImpact(int completedDay)
    {
        int count = 0;
        List<string> caseIds = new();
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (log.day != completedDay || string.IsNullOrWhiteSpace(log.investigationFinding))
            {
                continue;
            }

            count++;
            if (caseIds.Count < 3)
            {
                caseIds.Add(log.caseId);
            }
        }

        if (count == 0)
        {
            return new InvestigationFollowUpImpact(0, 0, 0, 0, 0, 0, "");
        }

        int budgetDelta = -Mathf.Min(80, count * 20);
        int stabilityDelta = Mathf.Min(5, count * 2);
        int equityDelta = Mathf.Min(3, count);
        int missedRiskDelta = -Mathf.Min(12, count * 4);
        int complaintsDelta = -Mathf.Min(5, count * 2);
        return new InvestigationFollowUpImpact(
            count,
            budgetDelta,
            stabilityDelta,
            equityDelta,
            missedRiskDelta,
            complaintsDelta,
            string.Join("/", caseIds));
    }

    private string BuildInvestigationFollowUpText(int completedDay)
    {
        InvestigationFollowUpImpact impact = BuildInvestigationFollowUpImpact(completedDay);
        if (impact.count <= 0)
        {
            return "조사 후속: 해금 메모 없음";
        }

        return
            $"조사 후속: 해금 메모 {impact.count}건 반영({impact.caseBrief}) · " +
            $"예산 {SignedNumber(impact.budgetDelta)}만원, 안정 {SignedNumber(impact.stabilityDelta)}, 형평 {SignedNumber(impact.equityDelta)}, 누락 {SignedNumber(impact.missedRiskDelta)}, 민원 {SignedNumber(impact.complaintsDelta)}";
    }

    private string BuildNextDayOperationsBriefing(int nextDay)
    {
        int nextCaseCount = 0;
        int highRiskCount = 0;
        int documentWeakCount = 0;
        int incomeExceptionCount = 0;
        int highCostCount = 0;
        int investigationRecommendedCount = 0;
        int totalPressure = 0;

        for (int i = 0; i < cases.Count; i++)
        {
            CareCase careCase = cases[i];
            if (careCase.day != nextDay)
            {
                continue;
            }

            nextCaseCount++;
            int pressure = CasePressureScore(careCase);
            totalPressure += pressure;
            if (careCase.urgency >= 82 || pressure >= 78)
            {
                highRiskCount++;
            }
            if (careCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(careCase.missingDocuments))
            {
                documentWeakCount++;
            }
            if (!careCase.incomeEligible)
            {
                incomeExceptionCount++;
            }
            if (GetDecisionCost(DecisionKind.Approve, careCase) >= 300)
            {
                highCostCount++;
            }
            if (careCase.recommendedDecision == "추가조사")
            {
                investigationRecommendedCount++;
            }
        }

        int averagePressure = nextCaseCount > 0 ? Mathf.RoundToInt(totalPressure / (float)nextCaseCount) : 0;
        string incidentForecast = BuildIncidentForecastLine();
        string focus = BuildNextDayFocusLine(highRiskCount, documentWeakCount, incomeExceptionCount, highCostCount, investigationRecommendedCount, averagePressure);
        return
            "다음 날 운영 브리핑\n" +
            $"다음 접수: {nextCaseCount}건 · 평균 압박 {averagePressure}/100 · 고위험 {highRiskCount} · 서류보강 {documentWeakCount} · 소득예외 {incomeExceptionCount} · 고비용 {highCostCount} · 조사권장 {investigationRecommendedCount}\n" +
            $"위험 예보: {incidentForecast}\n" +
            $"운영 초점: {focus}";
    }

    private string BuildIncidentForecastLine()
    {
        List<string> forecasts = new();
        if (budget <= -1300)
        {
            forecasts.Add("예산 감사 임계 접근");
        }
        else if (budget <= -800)
        {
            forecasts.Add("예산 압박 상승");
        }

        if (complaints >= 50)
        {
            forecasts.Add("민원 폭증 가능");
        }
        else if (complaints >= 36)
        {
            forecasts.Add("민원 공동 대응 주의");
        }

        if (missedRisk >= 22)
        {
            forecasts.Add("긴급 안전점검 가능");
        }
        else if (missedRisk >= 14)
        {
            forecasts.Add("누락 위험 누적");
        }

        if (equity <= 35)
        {
            forecasts.Add("형평성 이의제기 가능");
        }
        if (stability <= 40)
        {
            forecasts.Add("심사 인력 과부하 가능");
        }
        if (complaints >= 38 && missedRisk >= 14)
        {
            forecasts.Add("사례 적체 경보 주의");
        }

        return forecasts.Count > 0 ? string.Join(" / ", forecasts) : "특별 사건 임계값은 아직 안정권";
    }

    private static string BuildNextDayFocusLine(int highRiskCount, int documentWeakCount, int incomeExceptionCount, int highCostCount, int investigationRecommendedCount, int averagePressure)
    {
        if (highRiskCount >= 4 || averagePressure >= 78)
        {
            return "고위험부터 조건부/조사 비교";
        }
        if (documentWeakCount >= 4)
        {
            return "서류보강은 대체 증빙 우선";
        }
        if (highCostCount >= 3)
        {
            return "고비용은 조건부/예산 설명";
        }
        if (incomeExceptionCount >= 3)
        {
            return "소득 예외는 형평 근거 우선";
        }
        if (investigationRecommendedCount >= 2)
        {
            return "조사권장은 빠른 종결";
        }

        return "권장 일치와 위험 동시 관리";
    }

    private int CalculateDailyBudgetReallocation(int nextDay)
    {
        return CalculateDailyBudgetReallocation(nextDay, campaignMandate);
    }

    private static int CalculateDailyBudgetReallocation(int nextDay, CampaignMandate mandate)
    {
        if (nextDay <= 1)
        {
            return 0;
        }

        float multiplier = mandate switch
        {
            CampaignMandate.SupportExpanded => 1.14f,
            CampaignMandate.AusterityAudit => 0.85f,
            _ => 1.0f
        };
        return Mathf.RoundToInt(DailyBudgetReallocation * multiplier);
    }

    private void TriggerSpecialIncidents(int completedDay)
    {
        if (budget <= -1500 && !HasIncident(completedDay, "budget_audit"))
        {
            AddIncident(CreateIncidentLog(completedDay, "budget_audit"));
        }

        if (complaints >= 55 && !HasIncident(completedDay, "complaint_surge"))
        {
            AddIncident(CreateIncidentLog(completedDay, "complaint_surge"));
        }

        if (missedRisk >= 25 && !HasIncident(completedDay, "safety_check"))
        {
            AddIncident(CreateIncidentLog(completedDay, "safety_check"));
        }

        if (equity <= 30 && !HasIncident(completedDay, "equity_objection"))
        {
            AddIncident(CreateIncidentLog(completedDay, "equity_objection"));
        }

        if (stability <= 35 && !HasIncident(completedDay, "staff_burnout"))
        {
            AddIncident(CreateIncidentLog(completedDay, "staff_burnout"));
        }

        if (complaints >= 42 && missedRisk >= 16 && !HasIncident(completedDay, "review_backlog"))
        {
            AddIncident(CreateIncidentLog(completedDay, "review_backlog"));
        }
    }

    private IncidentLog CreateIncidentLog(int completedDay, string incidentType)
    {
        IncidentDelta delta = IncidentDeltaFor(incidentType);
        int pressureTier = IncidentPressureTier(incidentType);
        return new IncidentLog(
            completedDay,
            incidentType,
            IncidentVariantTitle(incidentType, completedDay, campaignMandate, pressureTier),
            IncidentVariantText(incidentType, completedDay, campaignMandate, pressureTier),
            delta.budget,
            delta.stability,
            delta.equity,
            delta.missedRisk,
            delta.complaints);
    }

    private static IncidentDelta IncidentDeltaFor(string incidentType)
    {
        return incidentType switch
        {
            "budget_audit" => new IncidentDelta(-80, -1, -2, 0, 3),
            "complaint_surge" => new IncidentDelta(-60, -1, 1, 0, 3),
            "safety_check" => new IncidentDelta(-90, 2, 2, -8, 2),
            "equity_objection" => new IncidentDelta(-40, -1, -4, 1, 3),
            "staff_burnout" => new IncidentDelta(-50, -5, 0, 1, 2),
            "review_backlog" => new IncidentDelta(-70, -2, -1, 3, 2),
            _ => new IncidentDelta(0, 0, 0, 0, 0)
        };
    }

    private int IncidentPressureTier(string incidentType)
    {
        return incidentType switch
        {
            "budget_audit" => budget <= -2600 ? 3 : (budget <= -1900 ? 2 : 1),
            "complaint_surge" => complaints >= 82 ? 3 : (complaints >= 68 ? 2 : 1),
            "safety_check" => missedRisk >= 58 ? 3 : (missedRisk >= 38 ? 2 : 1),
            "equity_objection" => equity <= 18 ? 3 : (equity <= 24 ? 2 : 1),
            "staff_burnout" => stability <= 18 ? 3 : (stability <= 26 ? 2 : 1),
            "review_backlog" => complaints >= 68 || missedRisk >= 35 ? 3 : 2,
            _ => 1
        };
    }

    private static string IncidentVariantTitle(string incidentType, int completedDay, CampaignMandate mandate, int pressureTier)
    {
        bool finalDay = completedDay >= 5;
        bool lateCampaign = completedDay >= 4;
        return incidentType switch
        {
            "budget_audit" when finalDay => "최종 집행 감사 예고",
