            "review_backlog" when pressureTier >= 3 => $"{dayContext}추가조사와 민원 응대가 겹치며 대기열을 다시 배분해야 합니다.",
            "review_backlog" => $"{dayContext}보류·추가조사 사례가 쌓여 다음 심사의 처리 순서를 재정렬해야 합니다.",
            _ => $"{dayContext}전날 판단이 다음 심사 조건을 바꿉니다."
