    private void AddIncident(IncidentLog incident)
    {
        incidentLogs.Add(incident);
        budget += incident.budgetDelta;
        stability = Mathf.Clamp(stability + incident.stabilityDelta, 0, 100);
        equity = Mathf.Clamp(equity + incident.equityDelta, 0, 100);
        missedRisk = Mathf.Clamp(missedRisk + incident.missedRiskDelta, 0, 100);
        complaints = Mathf.Clamp(complaints + incident.complaintsDelta, 0, 100);
    }

    private bool HasIncident(int day, string incidentType)
    {
        foreach (IncidentLog incident in incidentLogs)
        {
            if (incident.day == day && incident.type == incidentType)
            {
                return true;
            }
        }

        return false;
    }

    private IncidentLog LatestIncidentForDay(int day)
    {
        IncidentLog latest = null;
        foreach (IncidentLog incident in incidentLogs)
        {
            if (incident.day == day)
            {
                latest = incident;
            }
        }

        return latest;
    }

    private static string IncidentImpactLine(IncidentLog incident)
    {
        return $"예산 {SignedNumber(incident.budgetDelta)}만원 · 안정 {SignedNumber(incident.stabilityDelta)} · 형평 {SignedNumber(incident.equityDelta)} · 누락 {SignedNumber(incident.missedRiskDelta)} · 민원 {SignedNumber(incident.complaintsDelta)}";
    }

    private void ConfigureDayTransitionIncidentVisual(IncidentLog incident)
    {
        Color accent = IncidentAccentColor(incident != null ? incident.type : "");
        float washAlpha = incident != null ? 0.20f : 0.08f;
        if (dayTransitionIncidentWashImage != null)
        {
            dayTransitionIncidentWashImage.color = new Color(accent.r, accent.g, accent.b, washAlpha);
        }

        if (dayTransitionIncidentBarImage != null)
        {
            dayTransitionIncidentBarImage.color = incident != null
                ? new Color(accent.r, accent.g, accent.b, 0.86f)
                : new Color(0.42f, 0.40f, 0.34f, 0.48f);
        }

        if (dayTransitionIncidentFrameOutline != null)
        {
            int severity = incident != null ? IncidentSeverity(incident) : 0;
            dayTransitionIncidentFrameOutline.effectColor = incident != null
                ? new Color(accent.r, accent.g, accent.b, 0.78f)
                : new Color(0.45f, 0.42f, 0.35f, 0.45f);
            dayTransitionIncidentFrameOutline.effectDistance = new Vector2(2.5f + severity * 0.85f, -2.5f - severity * 0.85f);
        }

        if (dayTransitionIncidentTitleText != null)
        {
            dayTransitionIncidentTitleText.color = incident != null
                ? new Color32(255, 241, 202, 255)
                : new Color32(225, 216, 190, 255);
        }
    }

    private void StartDayTransitionIncidentReveal(IncidentLog incident)
    {
        if (Application.isBatchMode || dayTransitionIncidentImage == null)
        {
            return;
        }

        if (dayTransitionIncidentRoutine != null)
        {
            StopCoroutine(dayTransitionIncidentRoutine);
        }

        dayTransitionIncidentRoutine = StartCoroutine(AnimateDayTransitionIncident(incident));
    }

    private void StopDayTransitionIncidentReveal()
    {
        if (dayTransitionIncidentRoutine != null)
        {
            StopCoroutine(dayTransitionIncidentRoutine);
            dayTransitionIncidentRoutine = null;
        }

        if (dayTransitionIncidentImage != null)
        {
            dayTransitionIncidentImage.rectTransform.anchoredPosition = new Vector2(-370, 58);
            dayTransitionIncidentImage.rectTransform.localScale = Vector3.one;
        }

        if (dayTransitionIncidentTitleText != null)
        {
            dayTransitionIncidentTitleText.rectTransform.anchoredPosition = new Vector2(-370, -232);
        }

        if (dayTransitionIncidentImpactText != null)
        {
            dayTransitionIncidentImpactText.rectTransform.anchoredPosition = new Vector2(-370, -282);
        }

        if (dayTransitionIncidentBarImage != null)
        {
            dayTransitionIncidentBarImage.rectTransform.anchoredPosition = new Vector2(-370, 304);
        }
    }

    private IEnumerator AnimateDayTransitionIncident(IncidentLog incident)
    {
        RectTransform card = dayTransitionIncidentImage.rectTransform;
        RectTransform title = dayTransitionIncidentTitleText != null ? dayTransitionIncidentTitleText.rectTransform : null;
        RectTransform impact = dayTransitionIncidentImpactText != null ? dayTransitionIncidentImpactText.rectTransform : null;
        RectTransform bar = dayTransitionIncidentBarImage != null ? dayTransitionIncidentBarImage.rectTransform : null;
        Vector2 cardBase = new Vector2(-370, 58);
        Vector2 titleBase = new Vector2(-370, -232);
        Vector2 impactBase = new Vector2(-370, -282);
        Vector2 barBase = new Vector2(-370, 304);
        Color accent = IncidentAccentColor(incident != null ? incident.type : "");
        int severity = incident != null ? IncidentSeverity(incident) : 0;
        float duration = incident != null ? 0.92f : 0.42f;
        float elapsed = 0f;

        while (elapsed < duration)
        {
            float t = Mathf.Clamp01(elapsed / duration);
            float settle = 1f - Mathf.Pow(1f - t, 3f);
            float pulse = Mathf.Sin(t * Mathf.PI * 2.1f) * (1f - t) * severity;
            float lift = Mathf.Lerp(28f + severity * 5f, 0f, settle);

            card.anchoredPosition = cardBase + new Vector2(pulse * 6f, lift);
            card.localScale = Vector3.one * (1.06f + 0.035f * severity * (1f - settle));
            if (title != null)
            {
                title.anchoredPosition = titleBase + new Vector2(pulse * 3f, lift * 0.20f);
            }
            if (impact != null)
            {
                impact.anchoredPosition = impactBase + new Vector2(pulse * 2f, lift * 0.12f);
            }
            if (bar != null)
            {
                bar.anchoredPosition = barBase + new Vector2(0f, Mathf.Sin(t * Mathf.PI * 3f) * 2.5f * severity);
                dayTransitionIncidentBarImage.color = new Color(accent.r, accent.g, accent.b, Mathf.Lerp(0.95f, 0.68f, t * 0.6f));
            }

            elapsed += Time.unscaledDeltaTime;
            yield return null;
        }

        card.anchoredPosition = cardBase;
        card.localScale = Vector3.one;
        if (title != null)
        {
            title.anchoredPosition = titleBase;
        }
        if (impact != null)
        {
            impact.anchoredPosition = impactBase;
        }
        if (bar != null)
        {
            bar.anchoredPosition = barBase;
        }

        ConfigureDayTransitionIncidentVisual(incident);
        dayTransitionIncidentRoutine = null;
    }

    private static Color IncidentAccentColor(string incidentType)
    {
        return incidentType switch
        {
            "budget_audit" => new Color32(190, 126, 54, 255),
            "complaint_surge" => new Color32(157, 92, 117, 255),
            "safety_check" => new Color32(184, 66, 52, 255),
            "equity_objection" => new Color32(80, 111, 145, 255),
            "staff_burnout" => new Color32(169, 132, 82, 255),
            "review_backlog" => new Color32(116, 128, 148, 255),
            _ => new Color32(126, 116, 92, 255)
        };
    }

    private static int IncidentSeverity(IncidentLog incident)
    {
        if (incident == null)
        {
            return 0;
        }

        int score =
            Mathf.Abs(incident.budgetDelta) / 30 +
            Mathf.Abs(incident.stabilityDelta) * 2 +
            Mathf.Abs(incident.equityDelta) * 2 +
            Mathf.Abs(incident.missedRiskDelta) * 2 +
            Mathf.Abs(incident.complaintsDelta);

        if (score >= 14 || incident.type == "safety_check" || incident.type == "review_backlog")
        {
            return 3;
        }

        return score >= 8 ? 2 : 1;
    }

    private static string IncidentSeverityLabel(IncidentLog incident)
    {
        return IncidentSeverity(incident) switch
        {
            3 => "긴급",
            2 => "주의",
            _ => "관찰"
        };
    }

