    {
        if (!string.IsNullOrWhiteSpace(incident.text))
        {
            return Shorten(incident.text, 54);
        }

        return incident.type switch
        {
            "budget_audit" => "예산 집행 근거를 다시 제출해야 합니다.",
            "complaint_surge" => "민원 응대가 다음 심사 압박으로 이어집니다.",
            "safety_check" => "위험 신호 누락 여부를 즉시 재점검합니다.",
            "equity_objection" => "같은 조건의 신청자 간 형평성을 따집니다.",
            "staff_burnout" => "심사 인력의 처리 안정도가 흔들립니다.",
            "review_backlog" => "보류·조사 사례의 대기열을 재배분합니다.",
            _ => "전날 판단이 다음 심사 조건을 바꿉니다."
        };
    }

    private string BuildIncidentSummary(int completedDay)
    {
        List<string> summaries = new();
        foreach (IncidentLog incident in incidentLogs)
        {
            if (incident.day == completedDay)
            {
                summaries.Add($"{incident.title}(예산 {SignedNumber(incident.budgetDelta)}만원, 민원 {SignedNumber(incident.complaintsDelta)})");
            }
        }

        return summaries.Count > 0
            ? "특별 사건: " + string.Join(" / ", summaries)
            : "특별 사건: 없음";
    }

    private void ContinueAfterDayTransition()
    {
        StopDayTransitionIncidentReveal();
        dayTransitionRoot.gameObject.SetActive(false);
        reportRoot.gameObject.SetActive(false);
        reviewRoot.gameObject.SetActive(true);
        PlaySfx(pageTurnClip, 0.65f);
        ShowCase(currentIndex);
        SaveSessionIfEnabled(false);
    }

    private void Decide(DecisionKind kind)
    {
        if (awaitingNext)
        {
            return;
        }

        DismissFirstCaseGuide();

        CareCase c = cases[currentIndex];
        int budgetBefore = budget;
        int stabilityBefore = stability;
        int equityBefore = equity;
        int missedRiskBefore = missedRisk;
        int complaintsBefore = complaints;
        DecisionPreview actualPreview = BuildDecisionPreview(
            c,
            kind,
            campaignMandate,
            budgetBefore,
            stabilityBefore,
            equityBefore,
            missedRiskBefore,
            complaintsBefore);
        DecisionPreview recommendedPreview = BuildDecisionPreview(
            c,
            DecisionKindFromLabel(c.recommendedDecision),
            campaignMandate,
            budgetBefore,
            stabilityBefore,
            equityBefore,
            missedRiskBefore,
            complaintsBefore);

        budget = actualPreview.budgetAfter;
        stability = actualPreview.stabilityAfter;
        equity = actualPreview.equityAfter;
        missedRisk = actualPreview.missedRiskAfter;
        complaints = actualPreview.complaintsAfter;
        if (kind == DecisionKind.Investigate)
        {
            investigations++;
        }

        string verdict = actualPreview.decisionLabel;
        bool matched = MatchesRecommended(verdict, c.recommendedDecision);
        Consequence consequence = actualPreview.consequence;
        int decisionIndex = logs.Count + 1;
        string investigationFinding = BuildInvestigationFinding(c, kind, actualPreview, matched);
        string rationaleId = CurrentDecisionRationaleId();
        string rationaleName = CurrentDecisionRationaleName();
        string rationaleDescription = CurrentDecisionRationaleDescription();
        logs.Add(new DecisionLog(
            c.id,
            c.name,
            c.type,
            decisionIndex,
            DateTime.Now.ToString("s"),
            CurrentCampaignElapsedSeconds(),
            c.day,
            c.incomeEligible,
            c.missingDocuments,
            c.endingTag,
            c.followUp,
            investigationFinding,
            rationaleId,
            rationaleName,
            rationaleDescription,
            verdict,
            c.recommendedDecision,
            actualPreview.spentBudget,
            matched,
            c.urgency,
            c.documentStrength,
            c.equityNeed,
            budgetBefore,
            budget,
            stabilityBefore,
            stability,
            equityBefore,
            equity,
            missedRiskBefore,
            missedRisk,
            complaintsBefore,
            complaints,
            consequence.type,
            consequence.title,
            consequence.text,
            consequence.budgetDelta,
            consequence.stabilityDelta,
            consequence.equityDelta,
            consequence.missedRiskDelta,
            consequence.complaintsDelta));

        feedbackStampImage.sprite = StampForDecisionLabel(verdict);
        feedbackStampImage.color = new Color(1, 1, 1, 0.92f);
        feedbackText.text =
            matched
                ? $"{verdict} 확정 · 근거: {rationaleName}\n권장 일치 · 다음 사례로 넘어가세요."
                : $"{verdict} 확정 · 권장 판단은 {c.recommendedDecision}\n근거: {rationaleName} · 심사 기록 저장";
        if (!string.IsNullOrWhiteSpace(investigationFinding))
        {
            feedbackText.text += $"\n조사 메모 해금: {Shorten(investigationFinding, 58)}";
        }
        ShowMetricDeltaFeedback(
            actualPreview.budgetDelta,
            actualPreview.stabilityDelta,
            actualPreview.equityDelta,
            actualPreview.missedRiskDelta,
            actualPreview.complaintsDelta,
            consequence.title,
            BuildRecommendedComparisonLine(actualPreview, recommendedPreview, matched));
        StartDecisionImpact(kind, matched);
        PlayDecisionSfx(kind);
        PlaySfx(decisionFeedbackClip, 0.42f);

        awaitingNext = true;
        nextButton.gameObject.SetActive(true);
        UpdateMetrics();
        if (regulationText != null)
        {
            regulationText.text = BuildRegulationText();
        }
        if (policyHandbookRoot != null && policyHandbookRoot.gameObject.activeSelf)
        {
            UpdatePolicyHandbookContent();
        }
        SaveSessionIfEnabled(false);
    }

    private static string BuildInvestigationFinding(CareCase careCase, DecisionKind kind, DecisionPreview preview, bool matchedRecommended)
    {
        if (kind != DecisionKind.Investigate)
        {
            return "";
        }

        string source;
        if (careCase.urgency >= 85)
        {
            source = "오늘 밤 돌봄 공백 가능성이 확인되어 24시간 안 안전 확인이 필요";
        }
        else if (!careCase.incomeEligible)
        {
            source = "소득 기준 예외 사유가 임시 지출 또는 부양 변동으로 분리되어 심의 가능";
        }
        else if (careCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(careCase.missingDocuments))
        {
            source = "누락 서류가 발급 지연으로 확인되어 대체 증빙 확보 가능";
        }
        else if (careCase.equityNeed >= 80)
        {
            source = "동일 유형 대기자와 비교해 취약 부담이 높아 조건부 우선순위 상향 필요";
        }
        else if (careCase.cost >= 300)
        {
            source = "고비용 요청은 분할 지원 견적과 기관 연계안을 함께 받아야 함";
        }
        else
        {
            source = "신청 내용과 연락 기록이 대체로 일치해 조건부 판단 근거 확보";
        }

        string nextStep;
        if (careCase.urgency >= 85)
        {
            nextStep = "조건부 긴급지원 또는 즉시 안전 점검";
        }
        else if (careCase.documentStrength < 60 || !string.IsNullOrWhiteSpace(careCase.missingDocuments))
        {
            nextStep = "대체 서류 확보 후 조건부 승인 재검토";
        }
        else if (!careCase.incomeEligible)
        {
            nextStep = "예외 심의 메모 첨부 후 제한 지원 검토";
        }
        else if (matchedRecommended)
        {
            nextStep = "현재 조사 판단을 유지하고 다음 상담에서 지원 폭 결정";
        }
        else
        {
            nextStep = "권장 판단과 차이를 기록하고 다음 회차에서 지원/보류 재비교";
        }

        string riskLine = preview.missedRiskDelta > 1
            ? $"지연 위험 {SignedNumber(preview.missedRiskDelta)}"
            : "지연 위험 낮음";
        return $"{source}. 다음 판단: {nextStep}. {riskLine}.";
    }

    private static DecisionPreview BuildDecisionPreview(
        CareCase careCase,
        DecisionKind kind,
        CampaignMandate mandate,
        int budgetBefore,
        int stabilityBefore,
        int equityBefore,
        int missedRiskBefore,
        int complaintsBefore)
    {
        int spentBudget = 0;
        int stabilityDelta = 0;
        int equityDelta = 0;
        int missedRiskDelta = 0;
        int complaintsDelta = 0;
        string decisionLabel = DecisionLabel(kind);

        switch (kind)
        {
            case DecisionKind.Approve:
                spentBudget = careCase.cost;
                stabilityDelta = Mathf.RoundToInt(careCase.urgency * 0.20f);
                equityDelta = Mathf.RoundToInt(careCase.equityNeed * 0.12f);
                missedRiskDelta = -Mathf.RoundToInt(careCase.urgency * 0.18f);
                complaintsDelta = careCase.documentStrength < 60 ? 2 : 0;
                break;
            case DecisionKind.Conditional:
                spentBudget = Mathf.RoundToInt(careCase.cost * 0.58f);
                stabilityDelta = Mathf.RoundToInt(careCase.urgency * 0.12f);
                equityDelta = Mathf.RoundToInt(careCase.equityNeed * 0.10f);
                missedRiskDelta = -Mathf.RoundToInt(careCase.urgency * 0.10f);
                complaintsDelta = 1;
                break;
            case DecisionKind.Hold:
                stabilityDelta = -Mathf.RoundToInt(careCase.urgency * 0.06f);
                equityDelta = -2;
                missedRiskDelta = Mathf.RoundToInt(careCase.urgency * 0.10f);
                complaintsDelta = 3;
                break;
            case DecisionKind.Investigate:
                stabilityDelta = careCase.urgency > 78 ? -2 : 0;
                equityDelta = 3;
                missedRiskDelta = careCase.urgency > 80 ? 5 : 1;
                complaintsDelta = 1;
                break;
            default:
                stabilityDelta = -Mathf.RoundToInt(careCase.urgency * 0.15f);
                equityDelta = -Mathf.RoundToInt(careCase.equityNeed * 0.09f);
                missedRiskDelta = Mathf.RoundToInt(careCase.urgency * 0.18f);
                complaintsDelta = careCase.urgency > 75 ? 5 : 2;
                break;
        }

        spentBudget = AdjustDecisionCostForMandate(mandate, spentBudget);
        missedRiskDelta = AdjustMissedRiskDeltaForMandate(mandate, missedRiskDelta);
        complaintsDelta = AdjustComplaintDeltaForMandate(mandate, complaintsDelta);

        int budgetAfter = budgetBefore - spentBudget;
        int stabilityAfter = Mathf.Clamp(stabilityBefore + stabilityDelta, 0, 100);
        int equityAfter = Mathf.Clamp(equityBefore + equityDelta, 0, 100);
        int missedRiskAfter = Mathf.Clamp(missedRiskBefore + missedRiskDelta, 0, 100);
        int complaintsAfter = Mathf.Clamp(complaintsBefore + complaintsDelta, 0, 100);
        bool matched = MatchesRecommended(decisionLabel, careCase.recommendedDecision);
        Consequence consequence = AdjustConsequenceForMandate(mandate, BuildConsequence(careCase, decisionLabel, matched, budgetAfter));

        return new DecisionPreview(
            decisionLabel,
            spentBudget,
            budgetAfter - budgetBefore,
            stabilityAfter - stabilityBefore,
            equityAfter - equityBefore,
            missedRiskAfter - missedRiskBefore,
            complaintsAfter - complaintsBefore,
            budgetAfter,
            stabilityAfter,
            equityAfter,
            missedRiskAfter,
            complaintsAfter,
            consequence);
    }

    private static bool MatchesRecommended(string decision, string recommendedDecision)
    {
        return decision == recommendedDecision || (recommendedDecision == "조건부 승인" && decision == "승인");
    }

    private static string BuildRecommendedComparisonLine(DecisionPreview actual, DecisionPreview recommended, bool matched)
    {
        if (matched)
        {
            return "권장 비교: 권장 판단과 일치";
        }

        int budgetGap = actual.budgetDelta - recommended.budgetDelta;
        int stabilityGap = actual.stabilityDelta - recommended.stabilityDelta;
        int riskGap = (actual.missedRiskDelta + actual.complaintsDelta) - (recommended.missedRiskDelta + recommended.complaintsDelta);
        return $"권장 대비: 예산 {SignedNumber(budgetGap)}만원 · 안정 {SignedNumber(stabilityGap)} · 위험 {SignedNumber(riskGap)}";
    }

    private static Consequence BuildConsequence(CareCase careCase, string verdict, bool matchedRecommended, int budgetAfter)
    {
        if (verdict == "승인")
        {
            if (!careCase.incomeEligible)
            {
                return new Consequence(
                    "exception_review",
                    "예외 승인 검토",
                    "소득 기준 예외 승인이 다음 날 내부 검토와 민원 문의를 동시에 불렀다.",
                    -20,
                    1,
                    2,
                    0,
                    2);
            }

            if (careCase.documentStrength < 60)
            {
                return new Consequence(
                    "audit_request",
                    "서류 감사 요청",
                    "서류가 약한 승인 사례가 감사 요청으로 이어져 담당자 시간이 묶였다.",
                    -30,
                    1,
                    -1,
                    0,
                    2);
            }

            return new Consequence(
                "stability_gain",
                "안정도 회복",
                "즉시 지원이 가족의 일정을 안정시켜 다음 날 상담 부담을 조금 줄였다.",
                budgetAfter < 0 ? -10 : 0,
                2,
                1,
                0,
                0);
        }

        if (verdict == "조건부 승인")
        {
            if (careCase.urgency >= 85)
            {
                return new Consequence(
                    "condition_monitoring",
                    "조건 이행 점검",
                    "조건부 지원은 위기를 늦췄지만 확인 업무가 다음 날까지 이어졌다.",
                    -15,
                    1,
                    1,
                    2,
                    1);
            }

            return new Consequence(
                "paperwork_followup",
                "서류 보완 업무",
                "조건 이행 확인을 위해 추가 서류 요청과 전화 확인이 필요해졌다.",
                    -10,
                    0,
                    1,
                    1,
                1);
        }

        if (verdict == "추가조사")
        {
            if (careCase.urgency >= 85)
            {
                return new Consequence(
                    "delay_risk",
                    "조사 지연 위험",
                    "고위험 사례가 조사 대기로 넘어가며 다음 날 안전 점검 부담이 커졌다.",
                    -10,
                    -2,
                    1,
                    5,
                    2);
            }

            return new Consequence(
                "clarity_gain",
                "판단 근거 보강",
                "추가조사가 판단 근거를 보강해 형평성 설명은 쉬워졌다.",
                -5,
                0,
                2,
                1,
                0);
        }

        if (careCase.urgency >= 75)
        {
            return new Consequence(
                "escalation",
                "위기 악화 신고",
                "긴급도가 높은 사례가 보류 또는 거절되며 다음 날 재신청과 민원 위험이 커졌다.",
            0,
            -4,
            -2,
            6,
            3);
        }

        return new Consequence(
            "budget_relief",
            "예산 방어",
            "긴급도가 낮은 사례를 보수적으로 처리해 예산 압박은 잠시 완화되었다.",
            20,
            0,
            -1,
            1,
            0);
    }

