    private void StartDecisionImpact(DecisionKind kind, bool matchedRecommended)
    {
        if (!gameObject.activeInHierarchy || feedbackStampImage == null)
        {
            return;
        }

        if (decisionImpactRoutine != null)
        {
            StopCoroutine(decisionImpactRoutine);
        }

        decisionImpactRoutine = StartCoroutine(AnimateDecisionImpact(kind, matchedRecommended));
    }

    private IEnumerator AnimateDecisionImpact(DecisionKind kind, bool matchedRecommended)
    {
        RectTransform stampRect = feedbackStampImage.rectTransform;
        Vector2 basePosition = new Vector2(0, -336);
        Color flashColor = DecisionImpactColor(kind, matchedRecommended);
        float duration = 0.62f;
        float elapsed = 0f;

        while (elapsed < duration)
        {
            float t = elapsed / duration;
            float settle = 1f - Mathf.Pow(1f - Mathf.Clamp01(t), 3f);
            float bounce = Mathf.Sin(Mathf.Clamp01(t) * Mathf.PI * 2.4f) * (1f - Mathf.Clamp01(t));
            float alpha = Mathf.Lerp(0.34f, 0f, Mathf.Clamp01(t * 1.35f));

            stampRect.anchoredPosition = basePosition + new Vector2(bounce * 10f, Mathf.Lerp(42f, 0f, settle));
            stampRect.localScale = Vector3.one * Mathf.Max(0.92f, 1.42f - settle * 0.42f + bounce * 0.10f);
            stampRect.localRotation = Quaternion.Euler(0f, 0f, Mathf.Lerp(DecisionImpactRotation(kind), 0f, settle));
            feedbackStampImage.color = new Color(1f, 1f, 1f, Mathf.Lerp(0.45f, 0.94f, settle));

            if (decisionImpactFlashImage != null)
            {
                decisionImpactFlashImage.color = new Color(flashColor.r, flashColor.g, flashColor.b, alpha);
            }

            elapsed += Time.unscaledDeltaTime;
            yield return null;
        }

        stampRect.anchoredPosition = basePosition;
        stampRect.localScale = Vector3.one;
        stampRect.localRotation = Quaternion.identity;
        feedbackStampImage.color = new Color(1f, 1f, 1f, 0.92f);
        if (decisionImpactFlashImage != null)
        {
            decisionImpactFlashImage.color = new Color(flashColor.r, flashColor.g, flashColor.b, 0f);
        }
        decisionImpactRoutine = null;
    }

    private void ResetDecisionImpactVisuals()
    {
        if (decisionImpactRoutine != null)
        {
            StopCoroutine(decisionImpactRoutine);
            decisionImpactRoutine = null;
        }

        if (feedbackStampImage != null)
        {
            RectTransform stampRect = feedbackStampImage.rectTransform;
            stampRect.anchoredPosition = new Vector2(0, -336);
            stampRect.localScale = Vector3.one;
            stampRect.localRotation = Quaternion.identity;
        }

        if (decisionImpactFlashImage != null)
        {
            Color color = decisionImpactFlashImage.color;
            decisionImpactFlashImage.color = new Color(color.r, color.g, color.b, 0f);
        }
    }

    private static Color DecisionImpactColor(DecisionKind kind, bool matchedRecommended)
    {
        if (!matchedRecommended)
        {
            return new Color32(148, 66, 48, 255);
        }

        return kind switch
        {
            DecisionKind.Approve => new Color32(98, 132, 72, 255),
            DecisionKind.Conditional => new Color32(136, 124, 65, 255),
            DecisionKind.Investigate => new Color32(77, 96, 116, 255),
            DecisionKind.Reject => new Color32(144, 63, 50, 255),
            _ => new Color32(95, 98, 94, 255)
        };
    }

    private static float DecisionImpactRotation(DecisionKind kind)
    {
        return kind switch
        {
            DecisionKind.Approve => -7f,
            DecisionKind.Conditional => 5f,
            DecisionKind.Investigate => -4f,
            DecisionKind.Reject => 8f,
            _ => 3f
        };
    }

