                matched++;
            }
            if (log.decision.Contains("승인"))
            {
                approvals++;
            }
            if (log.decision == "거절")
            {
                rejections++;
            }
            if (log.decision == "추가조사")
            {
                investigationDecisions++;
            }
            if (log.decision == "보류")
            {
                holds++;
            }
        }

        string profile = "균형형 심사자";
        if (approvals >= 4 && missedRisk <= 20)
        {
            profile = "위험 신호 우선형";
        }
        else if (rejections + holds >= 3)
        {
            profile = "규정·예산 보수형";
        }
        else if (investigations >= 2)
        {
            profile = "추가 검증 선호형";
        }

