        GrowthObjectiveResult growthResult = BuildGrowthObjectiveResult(reportCareerDatabase, matched);
        AppealRemedyObjectiveResult appealRemedyResult = BuildAppealRemedyObjectiveResult(matched);
        nextObjective = BuildGrowthFollowUpNextCampaignObjective(nextObjective, growthResult);
        nextObjective = BuildAppealRemedyFollowUpNextCampaignObjective(nextObjective, appealRemedyResult);
        pendingNextCampaignObjective = nextObjective;
        hasPendingNextCampaignObjective = true;
        UpdateRecommendedCampaignButton();
        UpdateReportAppealRemedyCaseButton();
        StringBuilder lines = new();
        StringBuilder followUps = new();
        int skippedLogCount = Mathf.Max(0, logs.Count - ReportPreviewLineLimit);
        int previewStartIndex = Mathf.Max(0, logs.Count - ReportPreviewLineLimit);
        for (int i = previewStartIndex; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            string mark = log.matchedRecommended ? "O" : "X";
            string income = log.incomeEligible ? "적합" : "예외";
            lines.AppendLine($"{i + 1}. {Shorten(log.caseName, 5)} {ShortDecision(log.decision)}/{ShortDecision(log.recommendedDecision)} {mark} · {income} · 예산 {log.budgetAfter}");
            followUps.AppendLine($"{i + 1}. {Shorten(log.consequenceTitle, 8)} · {Shorten(log.followUp, 16)}");
