    private string BuildReportAppealRemedyCaseTimelineText(string caseId)
    {
        DecisionLog bestAppeal = HighestAppealReviewLogForCase(caseId, out int appealScore);
        string status = bestAppeal != null ? AppealReviewStatus(bestAppeal) : "보정 목표 완료";
        string remedy = bestAppeal != null ? AppealReviewRemedy(bestAppeal) : "이의제기 보정 목표 회차 완료";
        AppealRemedyObjectiveResult result = BuildAppealRemedyObjectiveResult(CountMatchedRecommendedLogs());
        string resultLine = result.active
            ? $"보정 판정: {AppealRemedyObjectiveStateLabel(result)} · {result.progress}\n"
            : "";
        return
            $"최종 리포트 보정: {status} · 최고 {appealScore}점 · {remedy}\n" +
            $"보정 목표 완료: {currentCampaignCaseObjectiveChallenge}\n" +
            resultLine +
            $"회차 결과: 예산 {budget}만 · 안정 {stability} · 형평 {equity} · 누락 {missedRisk} · 민원 {complaints}";
    }

    private string BuildDecisionRationaleInsight()
    {
        List<DecisionRationaleSummaryExport> summaries = BuildDecisionRationaleSummaries();
        if (summaries.Count == 0 || logs.Count == 0)
        {
            return "판단 근거 분포: 아직 기록된 판단이 없습니다.";
        }

        DecisionRationaleSummaryExport top = TopDecisionRationaleSummary(summaries);
        StringBuilder builder = new();
        builder.AppendLine("판단 근거 분포");
        for (int i = 0; i < summaries.Count; i++)
        {
            DecisionRationaleSummaryExport summary = summaries[i];
            builder.Append($"{summary.shortLabel} {summary.count}건");
            if (i < summaries.Count - 1)
            {
                builder.Append(" · ");
            }
        }

        builder.AppendLine();
        builder.AppendLine($"최다 근거: {top.label} · 지원 {top.supportCount}건 · 추가조사 {top.investigationCount}건 · 권장 일치 {top.matchRatePercent:0}%");
        builder.Append($"해석: {top.description}");
        return builder.ToString();
    }

    private void UpdateReportGaugePanel()
    {
        if (reportGaugeLabels == null || reportGaugeFills == null || reportGaugeLabels.Length < 5 || reportGaugeFills.Length < 5)
        {
            return;
        }

        int startingBudget = Mathf.Max(1, StartingBudgetForMandate(campaignMandate));
        SetReportGauge(0, $"예산 {budget}만", Mathf.Clamp01((budget + 1600f) / (startingBudget + 1600f)));
        SetReportGauge(1, $"안정 {stability}", stability / 100f);
        SetReportGauge(2, $"형평 {equity}", equity / 100f);
        SetReportGauge(3, $"누락 {missedRisk}", missedRisk / 100f);
        SetReportGauge(4, $"민원 {complaints}", complaints / 100f);
    }

    private void SetReportGauge(int index, string label, float ratio)
    {
        const float fullWidth = 116f;
        const float gaugeY = 170f;
        float x = 70f + index * 135f;
        float width = Mathf.Clamp01(ratio) * fullWidth;

        reportGaugeLabels[index].text = label;
        RectTransform fillRect = reportGaugeFills[index].rectTransform;
        fillRect.sizeDelta = new Vector2(Mathf.Max(1f, width), 12f);
        fillRect.anchoredPosition = new Vector2(x - ((fullWidth - width) * 0.5f), gaugeY);
        reportGaugeFills[index].color = ReportGaugeColor(index);
    }

    private static Color32 ReportGaugeColor(int index)
    {
        return index switch
        {
            0 => new Color32(194, 139, 70, 230),
            1 => new Color32(91, 142, 89, 230),
            2 => new Color32(82, 132, 149, 230),
            3 => new Color32(170, 78, 55, 230),
            4 => new Color32(151, 70, 94, 230),
            _ => new Color32(210, 190, 128, 230)
        };
    }

    private int CountMatchedRecommendedLogs()
    {
        int matched = 0;
        for (int i = 0; i < logs.Count; i++)
        {
            if (logs[i].matchedRecommended)
            {
                matched++;
            }
        }

        return matched;
    }

    private CampaignGradeResult BuildCampaignGrade(int matchedRecommendedCount)
    {
        return BuildCampaignGradeFromMetrics(campaignMandate, logs.Count, matchedRecommendedCount, budget, stability, equity, missedRisk, complaints);
    }

    private static CampaignGradeResult BuildCampaignGradeFromMetrics(
        CampaignMandate mandate,
        int logCount,
        int matchedRecommendedCount,
        int finalBudget,
        int finalStability,
        int finalEquity,
        int finalMissedRisk,
        int finalComplaints)
    {
        float matchRate = logCount > 0 ? matchedRecommendedCount / (float)logCount : 0f;
        int startingBudget = Mathf.Max(1, StartingBudgetForMandate(mandate));
        int matchScore = Mathf.RoundToInt(matchRate * 30f);
        int safetyScore = Mathf.RoundToInt(Mathf.Clamp01((100f - finalMissedRisk) / 100f) * 20f);
        int complaintScore = Mathf.RoundToInt(Mathf.Clamp01((100f - finalComplaints) / 100f) * 15f);
        int stabilityScore = Mathf.RoundToInt(Mathf.Clamp01(finalStability / 100f) * 15f);
        int equityScore = Mathf.RoundToInt(Mathf.Clamp01(finalEquity / 100f) * 10f);
        int budgetScore = Mathf.RoundToInt(Mathf.Clamp01((finalBudget + 1000f) / (startingBudget + 1000f)) * 10f);
        int score = Mathf.Clamp(matchScore + safetyScore + complaintScore + stabilityScore + equityScore + budgetScore, 0, 100);
        string grade = score >= 90 ? "S" :
            score >= 80 ? "A" :
            score >= 70 ? "B" :
            score >= 60 ? "C" :
            score >= 50 ? "D" : "E";
        string badge = CampaignGradeBadge(score, matchRate, finalBudget, finalMissedRisk, finalComplaints, finalEquity);
        string reason = CampaignGradeReason(matchScore, safetyScore, complaintScore, stabilityScore, equityScore, budgetScore);
        return new CampaignGradeResult(score, grade, badge, reason, matchScore, safetyScore, complaintScore, stabilityScore, equityScore, budgetScore);
    }

