    private CampaignChallengeResult BuildCampaignChallengeResult()
    {
        int matched = 0;
        int urgentMismatchCount = 0;
        int delayedRiskCount = 0;
        int highCostSupportCount = 0;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (log.matchedRecommended)
            {
                matched++;
            }

            if (!log.matchedRecommended && log.urgency >= 80)
            {
                urgentMismatchCount++;
            }

            if (IsDelayDecision(log.decision) && log.urgency >= 78)
            {
                delayedRiskCount++;
            }

            if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
            {
                highCostSupportCount++;
            }
        }

        float matchRate = logs.Count > 0 ? matched * 100f / logs.Count : 0f;
        string id = CampaignChallengeId(campaignMandate);
        string title = CampaignChallengeTitle(campaignMandate);
        string objective = CampaignChallengeObjective(campaignMandate);

        if (campaignMandate == CampaignMandate.SupportExpanded)
        {
            bool succeeded = logs.Count >= cases.Count && delayedRiskCount <= 3 && missedRisk <= 30;
            int score = Mathf.Clamp(Mathf.RoundToInt((3 - delayedRiskCount) * 12f + (30 - missedRisk) * 1.8f + 70f), 0, 100);
            string progress = $"고위험 지연 {delayedRiskCount}건 · 누락 위험 {missedRisk}/100";
            return new CampaignChallengeResult(id, title, objective, progress, succeeded, score);
        }

        if (campaignMandate == CampaignMandate.AusterityAudit)
        {
            bool succeeded = logs.Count >= cases.Count && highCostSupportCount <= 3 && budget >= -500;
            int score = Mathf.Clamp(Mathf.RoundToInt((3 - highCostSupportCount) * 10f + ((budget + 500f) / 20f) + 70f), 0, 100);
            string progress = $"고비용 지원 {highCostSupportCount}건 · 최종 예산 {budget}만원";
            return new CampaignChallengeResult(id, title, objective, progress, succeeded, score);
        }

        bool standardSucceeded = logs.Count >= cases.Count && matchRate >= 75f && urgentMismatchCount <= 3;
        int standardScore = Mathf.Clamp(Mathf.RoundToInt(matchRate * 0.82f + (3 - urgentMismatchCount) * 6f + 12f), 0, 100);
        string standardProgress = $"권장 일치 {matchRate:0.0}% · 고위험 불일치 {urgentMismatchCount}건";
        return new CampaignChallengeResult(id, title, objective, standardProgress, standardSucceeded, standardScore);
    }

