    private GrowthObjectiveResult BuildGrowthObjectiveResult(CareerRecordDatabase priorDatabase, int matchedRecommendedCount)
    {
        if (!currentCampaignStartedFromGrowthObjective)
        {
            return GrowthObjectiveResult.Inactive;
        }

        CareerRecord baseline = FindGrowthObjectiveBaselineRecord(priorDatabase);
        float matchRate = logs.Count > 0 ? matchedRecommendedCount * 100f / logs.Count : 0f;
        int currentRisk = missedRisk + complaints;
        string title = string.IsNullOrWhiteSpace(currentCampaignGrowthObjectiveTitle)
            ? "최근 성장 목표"
            : currentCampaignGrowthObjectiveTitle;
        string challenge = string.IsNullOrWhiteSpace(currentCampaignGrowthObjectiveChallenge)
            ? "성장 목표"
            : currentCampaignGrowthObjectiveChallenge;
        bool complete = logs.Count >= cases.Count && cases.Count > 0;

        if (baseline == null)
        {
            bool fallbackSucceeded = complete && matchRate >= 70f && currentRisk <= 80 && budget >= -1200;
            string fallbackProgress = $"기준 기록 없음 · 권장 {matchRate:0}% · 위험 {currentRisk} · 예산 {budget}만";
            string fallbackNote = fallbackSucceeded
                ? "기준 기록 없이도 기본 성장 기준을 충족했습니다."
                : "기준 기록이 없어 기본 성장 기준으로 판정했습니다.";
            return new GrowthObjectiveResult(true, fallbackSucceeded, title, challenge, fallbackProgress, fallbackNote);
        }

        if (challenge.Contains("권장 판단"))
        {
            int targetPercent = ExtractFirstIntegerAfter(challenge, "일치율", 60);
            bool succeeded = complete && matchRate >= targetPercent;
            string progress = $"권장 {matchRate:0}%/{targetPercent}% · 직전 {baseline.recommendedMatchRatePercent:0}%";
            string note = succeeded
                ? "권장 판단 일치율 회복 목표를 달성했습니다."
                : "권장 판단 일치율이 목표치에 미달했습니다.";
            return new GrowthObjectiveResult(true, succeeded, title, challenge, progress, note);
        }

        if (challenge.Contains("위험 지표"))
        {
            int targetRiskDrop = ExtractFirstIntegerAfter(challenge, "위험 지표", 8);
            int baselineRisk = CareerRecordRiskScore(baseline);
            int riskDrop = baselineRisk - currentRisk;
            bool succeeded = complete && riskDrop >= targetRiskDrop;
            string progress = $"위험 {currentRisk} · 직전 {baselineRisk} · 개선 {SignedNumber(riskDrop)}p/{targetRiskDrop}p";
            string note = succeeded
                ? "직전 회차 대비 위험 지표를 목표 이상 낮췄습니다."
                : "위험 지표 개선 폭이 목표치에 미달했습니다.";
            return new GrowthObjectiveResult(true, succeeded, title, challenge, progress, note);
        }

        if (challenge.Contains("예산 손실"))
        {
            int targetBudgetGain = ExtractFirstIntegerAfter(challenge, "예산 손실", 120);
            int budgetGain = budget - baseline.finalBudget;
            bool succeeded = complete && budgetGain >= targetBudgetGain;
            string progress = $"예산 {budget}만 · 직전 {baseline.finalBudget}만 · 개선 {SignedNumber(budgetGain)}만/{targetBudgetGain}만";
            string note = succeeded
                ? "직전 회차 대비 예산 손실을 목표 이상 줄였습니다."
                : "예산 회복 폭이 목표치에 미달했습니다.";
            return new GrowthObjectiveResult(true, succeeded, title, challenge, progress, note);
        }

        int maintainMatchTarget = Mathf.Max(60, Mathf.RoundToInt(baseline.recommendedMatchRatePercent) - 2);
        int maintainRiskLimit = CareerRecordRiskScore(baseline) + 8;
        bool maintainSucceeded = complete && matchRate >= maintainMatchTarget && currentRisk <= maintainRiskLimit;
        string maintainProgress = $"권장 {matchRate:0}%/{maintainMatchTarget}% · 위험 {currentRisk}/{maintainRiskLimit} · 지원/조사 {CountSupportOrInvestigationLogs()}건";
        string maintainNote = maintainSucceeded
            ? "판단 품질을 유지하면서 고위험 대응 폭을 지켰습니다."
            : "판단 품질 또는 위험 관리가 유지 목표에 미달했습니다.";
        return new GrowthObjectiveResult(true, maintainSucceeded, title, challenge, maintainProgress, maintainNote);
    }

    private int CountSupportOrInvestigationLogs()
    {
        int count = 0;
        for (int i = 0; i < logs.Count; i++)
        {
            if (IsSupportDecision(logs[i].decision) || logs[i].decision == "추가조사")
            {
                count++;
            }
        }

        return count;
    }

    private int CountHighRiskDelayLogs()
    {
        int count = 0;
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (IsDelayDecision(log.decision) && log.urgency >= 78)
            {
                count++;
            }
        }

        return count;
    }

    private static CareerRecord FindGrowthObjectiveBaselineRecord(CareerRecordDatabase priorDatabase)
    {
        if (priorDatabase == null || priorDatabase.records == null)
        {
            return null;
        }

        for (int i = 0; i < priorDatabase.records.Count; i++)
        {
            CareerRecord record = priorDatabase.records[i];
            if (record != null && record.logCount > 0)
            {
                return record;
            }
        }

        return null;
    }

    private static int ExtractFirstIntegerAfter(string source, string marker, int fallback)
    {
        if (string.IsNullOrWhiteSpace(source))
        {
            return fallback;
        }

        int startIndex = 0;
        if (!string.IsNullOrEmpty(marker))
        {
            int markerIndex = source.IndexOf(marker, StringComparison.Ordinal);
            if (markerIndex >= 0)
            {
                startIndex = markerIndex + marker.Length;
            }
        }

        StringBuilder digits = new();
        for (int i = startIndex; i < source.Length; i++)
        {
            char c = source[i];
            if (char.IsDigit(c))
            {
                digits.Append(c);
            }
            else if (digits.Length > 0)
            {
                break;
            }
        }

        return int.TryParse(digits.ToString(), out int value) ? value : fallback;
    }

