        string note = succeeded
            ? "이의제기 보정 목표가 권장 판단 회복과 고위험 지연 억제 기준을 충족했습니다."
            : "이의제기 보정 목표가 권장 판단, 고위험 지연, 누락 위험 중 일부 기준에 미달했습니다.";
        return new AppealRemedyObjectiveResult(true, succeeded, challenge, progress, note);
    }

