    private static NextCampaignObjective BuildAppealRemedyFollowUpNextCampaignObjective(NextCampaignObjective originalObjective, AppealRemedyObjectiveResult result)
    {
        if (!result.active)
        {
            return originalObjective;
        }

        if (!result.succeeded)
        {
            return new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                "이의제기 보정 재도전: 고위험 지연 3건 이하, 누락 위험 30 이하",
                $"보정 목표 미달: {result.progress} · 지원 확대 기준으로 고위험 지연을 줄이세요");
        }

        return new NextCampaignObjective(
            CampaignMandate.Standard,
            "이의제기 보정 후속: 권장 75% 유지, 고위험 지연 3건 이하",
            $"보정 목표 성공: {result.progress} · 표준 기준에서 보정 품질을 유지하세요");
    }

    private NextCampaignObjective BuildGrowthFollowUpNextCampaignObjective(NextCampaignObjective originalObjective, GrowthObjectiveResult result)
    {
        if (!result.active)
        {
            return originalObjective;
        }

        if (!result.succeeded)
        {
            if (result.challenge.Contains("위험 지표"))
            {
                return new NextCampaignObjective(
                    CampaignMandate.AusterityAudit,
                    "성장 보정: 고위험 지연 3건 이하, 위험 지표 재도전",
                    $"성장 목표 미달: {result.progress} · 위험 신호부터 다시 줄이기");
            }

            if (result.challenge.Contains("예산 손실"))
            {
                return new NextCampaignObjective(
                    CampaignMandate.AusterityAudit,
                    "성장 보정: 예산 -500만 이상, 고비용 지원 3건 이하",
                    $"성장 목표 미달: {result.progress} · 예산 회복 우선");
            }

            if (result.challenge.Contains("권장 판단"))
            {
                return new NextCampaignObjective(
                    CampaignMandate.Standard,
                    "성장 보정: 권장 판단 일치율 75% 재도전",
                    $"성장 목표 미달: {result.progress} · 판단 근거 재정렬");
            }

            return new NextCampaignObjective(
                CampaignMandate.Standard,
                "성장 보정: 판단 품질과 위험 관리 동시 재검증",
                $"성장 목표 미달: {result.progress}");
        }

        if (result.challenge.Contains("위험 지표"))
        {
            return new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                "성장 후속: 위험 안정 유지하며 고위험 지원/조사 균형",
                $"성장 목표 성공: {result.progress} · 다음은 지원 폭 확장");
        }

        if (result.challenge.Contains("예산 손실"))
        {
            return new NextCampaignObjective(
                CampaignMandate.Standard,
                "성장 후속: 예산 회복 유지하며 권장 75% 이상",
                $"성장 목표 성공: {result.progress} · 다음은 판단 품질 회복");
        }

        if (result.challenge.Contains("권장 판단"))
        {
            return new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                "성장 후속: 권장 80% 유지하며 고위험 대응 폭 확장",
                $"성장 목표 성공: {result.progress} · 다음은 지원 확대 기준 검증");
        }

        return new NextCampaignObjective(
            campaignMandate == CampaignMandate.AusterityAudit ? CampaignMandate.Standard : CampaignMandate.AusterityAudit,
            "성장 후속: 다른 운영 기준에서 상승세 재검증",
            $"성장 목표 성공: {result.progress}");
    }

