            _ => CampaignMandate.Standard
        };
    }

    private static string CampaignGradeBadge(int score, float matchRate, int finalBudget, int finalMissedRisk, int finalComplaints, int finalEquity)
    {
        if (score >= 90 && finalBudget >= 0 && finalMissedRisk <= 25)
        {
            return "안정 운영";
        }

        if (matchRate >= 0.85f)
        {
            return "근거 중심";
        }

        if (finalBudget < -800)
        {
            return "예산 과열";
        }

        if (finalMissedRisk >= 45)
        {
            return "위험 누락";
        }

        if (finalComplaints >= 85)
        {
            return "민원 압박";
        }

        if (finalEquity >= 90)
        {
            return "형평 우선";
        }

        return "균형 보완";
    }

    private static string CampaignGradeReason(int matchScore, int safetyScore, int complaintScore, int stabilityScore, int equityScore, int budgetScore)
    {
        int lowest = Mathf.Min(matchScore, safetyScore, complaintScore, stabilityScore, equityScore, budgetScore);
        if (lowest == budgetScore)
        {
            return "예산 관리가 다음 회차의 핵심 보강 지점입니다.";
        }

        if (lowest == safetyScore)
        {
            return "누락 위험을 낮추는 판단이 더 필요합니다.";
        }

        if (lowest == complaintScore)
        {
            return "민원 위험과 설명 책임을 줄여야 합니다.";
        }

        if (lowest == matchScore)
        {
            return "권장 판단과 어긋난 사례를 다시 검토해야 합니다.";
        }

        if (lowest == stabilityScore)
        {
            return "가족 안정도 회복 폭이 부족했습니다.";
        }

        return "형평성 기준을 더 분명히 적용해야 합니다.";
    }

    private void UpdatePlayerDecisionMapPanel()
    {
        reportCaseLogText.text =
            "가족 유형 판단 지도\n" +
            "초록: 지원율 · 주황: 권장 일치율";

        List<FamilyDecisionSummary> summaries = BuildFamilyDecisionSummaries();
        for (int i = 0; i < playerFamilyRowTexts.Length; i++)
        {
            float rowY = 32f - i * 39f;
            if (i >= summaries.Count)
            {
                playerFamilyRowTexts[i].text = "";
                SetPlayerFamilyBar(playerFamilySupportFills[i], 236f, rowY + 8f, 0f);
                SetPlayerFamilyBar(playerFamilyMatchFills[i], 236f, rowY - 9f, 0f);
                continue;
            }

            FamilyDecisionSummary summary = summaries[i];
            playerFamilyRowTexts[i].text =
                $"{Shorten(summary.familyType, 9)}\n" +
                $"{summary.count}건 · 지 {summary.supportCount} · 조 {summary.investigateCount} · 일 {summary.matchedCount}";
            SetPlayerFamilyBar(playerFamilySupportFills[i], 236f, rowY + 8f, summary.supportCount / (float)Mathf.Max(1, summary.count));
            SetPlayerFamilyBar(playerFamilyMatchFills[i], 236f, rowY - 9f, summary.matchedCount / (float)Mathf.Max(1, summary.count));
        }

        reportFollowUpText.text = BuildPressureQueueText();
    }

    private List<FamilyDecisionSummary> BuildFamilyDecisionSummaries()
    {
        Dictionary<string, FamilyDecisionSummary> summaryByType = new();
        foreach (DecisionLog log in logs)
        {
            string familyType = DecisionAnalysisGroup(log);
            if (!summaryByType.TryGetValue(familyType, out FamilyDecisionSummary summary))
            {
                summary = new FamilyDecisionSummary(familyType);
                summaryByType.Add(familyType, summary);
            }

            summary.count++;
            if (IsSupportDecision(log.decision))
            {
                summary.supportCount++;
            }
            else if (log.decision == "추가조사")
            {
                summary.investigateCount++;
            }
            else
            {
                summary.holdOrRejectCount++;
            }

            if (log.matchedRecommended)
            {
                summary.matchedCount++;
            }
        }

        List<FamilyDecisionSummary> summaries = new(summaryByType.Values);
        summaries.Sort((a, b) =>
        {
            int countCompare = b.count.CompareTo(a.count);
            if (countCompare != 0)
            {
                return countCompare;
            }

            int pressureCompare = b.PressureScore.CompareTo(a.PressureScore);
            if (pressureCompare != 0)
            {
                return pressureCompare;
            }

            return string.Compare(a.familyType, b.familyType, StringComparison.Ordinal);
        });
        return summaries;
    }

    private static string DecisionAnalysisGroup(DecisionLog log)
    {
        string source = $"{log.familyType} {log.endingTag} {log.followUp}";
        if (ContainsAny(source, "다문화", "중도입국", "체류", "통번역", "청각장애", "의사소통"))
        {
            return "접근성·언어 장벽";
        }

        if (ContainsAny(source, "가정폭력", "학교폭력", "학대", "보호관찰", "안전", "고립"))
        {
            return "안전·보호 위험";
        }

        if (ContainsAny(source, "장애", "특수교육", "경계선", "치료", "의료", "암", "의료기기"))
        {
            return "장애·의료 돌봄";
        }

        if (ContainsAny(source, "조손", "조부모", "노부모", "치매", "친족", "수감"))
        {
            return "조손·친족 돌봄";
        }

        if (ContainsAny(source, "한부모", "영아", "산후", "청소년 부모", "보호자 소진"))
        {
            return "한부모·보호자 소진";
        }

        if (ContainsAny(source, "맞벌이", "플랫폼", "야간", "휴직", "자영업", "노동"))
        {
            return "노동·시간 돌봄";
        }

        if (ContainsAny(source, "주거", "전입", "화재", "부채", "소득", "고소득", "저위험"))
        {
            return "주거·경제 압박";
        }

        return string.IsNullOrWhiteSpace(log.familyType) ? "기타 돌봄 공백" : Shorten(log.familyType, 10);
    }

    private static bool ContainsAny(string source, params string[] needles)
    {
        foreach (string needle in needles)
        {
            if (source.IndexOf(needle, StringComparison.Ordinal) >= 0)
            {
                return true;
            }
        }

        return false;
    }

    private string BuildPressureQueueText()
    {
        int urgentMismatchCount = 0;
        int highCostSupportCount = 0;
        int delayedRiskCount = 0;

        foreach (DecisionLog log in logs)
        {
            bool urgentMismatch = !log.matchedRecommended && log.urgency >= 80;
            bool highCostSupport = IsSupportDecision(log.decision) && log.spentBudget >= 140;
            bool delayedRisk = IsDelayDecision(log.decision) && log.urgency >= 78;

            if (urgentMismatch)
            {
                urgentMismatchCount++;
            }
            if (highCostSupport)
            {
                highCostSupportCount++;
            }
            if (delayedRisk)
            {
                delayedRiskCount++;
            }
        }

        List<DecisionLog> highlightedLogs = BuildRankedDecisionReviewLogs(5);
        StringBuilder builder = new();
        builder.AppendLine($"재검토 큐: 불일치 {urgentMismatchCount} · 고비용 {highCostSupportCount} · 지연 {delayedRiskCount}");
        if (highlightedLogs.Count == 0)
        {
            builder.AppendLine("압박 사례 없음");
        }
        else
        {
            int shown = 0;
            foreach (DecisionLog log in highlightedLogs)
            {
                builder.AppendLine($"{log.caseId} {ShortDecision(log.decision)}/{ShortDecision(log.recommendedDecision)} · {Shorten(DecisionReviewReason(log), 24)}");
                shown++;
                if (shown >= 2)
                {
                    break;
                }
            }
        }

        return builder.ToString();
    }

    private List<DecisionLog> BuildRankedDecisionReviewLogs(int limit)
    {
        List<DecisionLog> rankedLogs = new(logs);
        rankedLogs.Sort((left, right) => DecisionAuditPressureScore(right).CompareTo(DecisionAuditPressureScore(left)));

        List<DecisionLog> reviewLogs = new();
        foreach (DecisionLog log in rankedLogs)
        {
            if (DecisionAuditPressureScore(log) <= 0 && reviewLogs.Count > 0)
            {
                break;
            }

            reviewLogs.Add(log);
            if (reviewLogs.Count >= limit)
            {
                break;
            }
        }

        return reviewLogs;
    }

    private static void SetPlayerFamilyBar(Image fill, float centerX, float centerY, float ratio)
    {
        const float fullWidth = 108f;
        float width = Mathf.Clamp01(ratio) * fullWidth;
        RectTransform fillRect = fill.rectTransform;
        fillRect.sizeDelta = new Vector2(Mathf.Max(1f, width), 9f);
        fillRect.anchoredPosition = new Vector2(centerX - ((fullWidth - width) * 0.5f), centerY);
    }

