    private void AdjustPlaytestSurveyRating(int index, int delta)
    {
        if (index < 0 || index >= playtestSurveyRatings.Length)
        {
            return;
        }

        playtestSurveyRatings[index] = Mathf.Clamp(playtestSurveyRatings[index] + delta, 1, 5);
        UpdatePlaytestSurveyContent();
    }

    private void SetPlaytestSurveyRating(int index, int value)
    {
        if (index < 0 || index >= playtestSurveyRatings.Length)
        {
            return;
        }

        playtestSurveyRatings[index] = Mathf.Clamp(value, 1, 5);
        UpdatePlaytestSurveyContent();
    }

    private void TogglePlaytestSurveyFlag(int index)
    {
        if (index < 0 || index >= playtestSurveyFlags.Length)
        {
            return;
        }

        playtestSurveyFlags[index] = !playtestSurveyFlags[index];
        UpdatePlaytestSurveyContent();
    }

    private void SetPlaytestSurveyFlag(int index, bool value)
    {
        if (index < 0 || index >= playtestSurveyFlags.Length)
        {
            return;
        }

        playtestSurveyFlags[index] = value;
        UpdatePlaytestSurveyContent();
    }

