            {
                if (playtestSurveyRatingTexts[i] != null)
                {
                    playtestSurveyRatingTexts[i].text = $"{playtestSurveyRatings[i]}/5\n{RatingDescriptor(playtestSurveyRatings[i])}";
                }
            }
        }

        if (playtestSurveyFlagTexts != null)
        {
            for (int i = 0; i < playtestSurveyFlagTexts.Length && i < playtestSurveyFlags.Length; i++)
            {
                if (playtestSurveyFlagTexts[i] != null)
                {
                    playtestSurveyFlagTexts[i].text = (playtestSurveyFlags[i] ? "[x] " : "[ ] ") + PlaytestSurveyFlagLabels[i];
                }
