    private PlaytestSurveyExport SavePlaytestSurveyFiles()
    {
        string sessionId = EnsureSessionId();
        string sessionDirectoryPath = SessionDirectory(sessionId);
        Directory.CreateDirectory(sessionDirectoryPath);

        PlaytestSurveyExport survey = BuildPlaytestSurveyExport();
        string jsonPath = Path.Combine(sessionDirectoryPath, "care_review_in_game_feedback.json");
        string markdownPath = Path.Combine(sessionDirectoryPath, "care_review_in_game_feedback.md");
        survey.sessionDirectoryPath = SessionRelativeDirectory(sessionId);
        survey.surveyJsonPath = SessionRelativePath(sessionId, jsonPath);
        survey.surveyMarkdownPath = SessionRelativePath(sessionId, markdownPath);

        File.WriteAllText(jsonPath, JsonUtility.ToJson(survey, true), Encoding.UTF8);
        File.WriteAllText(markdownPath, BuildPlaytestSurveyMarkdown(survey), Encoding.UTF8);
        WriteLatestPlaytestPacketCopies(jsonPath, markdownPath);

        string readinessLine = BuildPlaytestCollectionReadinessLine(BuildPlaytestCollectionReadiness());
        string notice =
            "인게임 설문 저장 완료\n" +
            $"세션 ID: {sessionId}\n" +
            readinessLine + "\n" +
            $"파일: {Path.GetFileName(jsonPath)} · {Path.GetFileName(markdownPath)}";
        UpdatePlaytestSurveyContent(notice);
        if (reportLogPathText != null)
        {
            reportLogPathText.text = notice + "\n플레이 로그와 환경 진단을 함께 회수하세요.";
        }

        Debug.Log("CARE_REVIEW_PLAYTEST_SURVEY path=" + jsonPath + " markdown=" + markdownPath + " completed=True");
        return survey;
    }

    private PlaytestCollectionReadiness BuildPlaytestCollectionReadiness()
    {
        string sessionId = EnsureSessionId();
        string[] surveyFiles =
        {
            "care_review_in_game_feedback.json",
            "care_review_in_game_feedback.md"
        };
        string[] packetFiles =
        {
            "care_review_play_log.json",
            "care_review_play_log.csv",
            "care_review_incident_log.csv",
            "care_review_playtest_feedback.md",
            "care_review_playtest_summary.json",
            "care_review_analytics_dashboard.html"
        };
        string[] diagnosticFiles =
        {
            "care_review_system_diagnostic.json",
            "care_review_system_diagnostic.md"
        };

        bool hasSurveyFiles = HasAllSessionFiles(sessionId, surveyFiles);
        bool hasPlaytestPacketFiles = HasAllSessionFiles(sessionId, packetFiles);
        bool hasDiagnosticFiles = HasAllSessionFiles(sessionId, diagnosticFiles);
        bool filesHaveNoLocalAbsolutePath = ExistingSessionFilesHaveNoLocalAbsolutePath(sessionId, surveyFiles) &&
            ExistingSessionFilesHaveNoLocalAbsolutePath(sessionId, packetFiles) &&
            ExistingSessionFilesHaveNoLocalAbsolutePath(sessionId, diagnosticFiles);
        bool hasMinimumDecisionCount = logs.Count >= MinimumPlaytestDecisionCount;
        bool hasCompleteDecisionCount = cases.Count > 0 && logs.Count >= cases.Count;
        bool readyForCollection = hasMinimumDecisionCount &&
            hasSurveyFiles &&
            hasPlaytestPacketFiles &&
            hasDiagnosticFiles &&
            filesHaveNoLocalAbsolutePath;

        return new PlaytestCollectionReadiness
        {
            generatedAt = DateTime.Now.ToString("s"),
            sessionId = sessionId,
            buildVersion = BuildVersionLabel,
            sessionDirectoryPath = SessionRelativeDirectory(sessionId),
            logCount = logs.Count,
            caseCount = cases.Count,
            minimumDecisionCount = MinimumPlaytestDecisionCount,
            hasMinimumDecisionCount = hasMinimumDecisionCount,
            hasCompleteDecisionCount = hasCompleteDecisionCount,
            hasSurveyFiles = hasSurveyFiles,
            hasPlaytestPacketFiles = hasPlaytestPacketFiles,
            hasDiagnosticFiles = hasDiagnosticFiles,
            filesHaveNoLocalAbsolutePath = filesHaveNoLocalAbsolutePath,
            readyForCollection = readyForCollection,
            statusLabel = readyForCollection ? "회수 완료" : "회수 준비 필요"
        };
    }

    private string BuildPlaytestCollectionReadinessLine(PlaytestCollectionReadiness readiness)
    {
        string decisionLabel = readiness.hasMinimumDecisionCount
            ? $"판단 {readiness.logCount}/{readiness.caseCount}"
            : $"판단 부족 {readiness.logCount}/{readiness.minimumDecisionCount}";
        string logLabel = readiness.hasPlaytestPacketFiles ? "로그 OK" : "로그 저장 필요";
        string surveyLabel = readiness.hasSurveyFiles ? "설문 OK" : "설문 저장 필요";
        string diagnosticLabel = readiness.hasDiagnosticFiles ? "환경 OK" : "환경 진단 필요";
        string privacyLabel = readiness.filesHaveNoLocalAbsolutePath ? "경로 OK" : "경로 확인 필요";
        return $"회수 준비: {readiness.statusLabel} · {decisionLabel} · {logLabel} · {surveyLabel} · {diagnosticLabel} · {privacyLabel}";
    }

    private bool HasAllSessionFiles(string sessionId, params string[] fileNames)
    {
        string sessionDirectoryPath = SessionDirectory(sessionId);
        for (int i = 0; i < fileNames.Length; i++)
        {
            if (!File.Exists(Path.Combine(sessionDirectoryPath, fileNames[i])))
            {
                return false;
            }
        }

        return true;
    }

    private bool ExistingSessionFilesHaveNoLocalAbsolutePath(string sessionId, params string[] fileNames)
    {
        string sessionDirectoryPath = SessionDirectory(sessionId);
        for (int i = 0; i < fileNames.Length; i++)
        {
            string path = Path.Combine(sessionDirectoryPath, fileNames[i]);
            if (!File.Exists(path))
            {
                continue;
            }

            if (ContainsLocalAbsolutePath(File.ReadAllText(path, Encoding.UTF8)))
            {
                return false;
            }
        }

        return true;
    }

    private PlaytestSurveyExport BuildPlaytestSurveyExport()
    {
        EndingOutcome ending = BuildEndingOutcome();
        CampaignGradeResult grade = BuildCampaignGrade(CountMatchedRecommendedLogs());
        return new PlaytestSurveyExport
        {
            generatedAt = DateTime.Now.ToString("s"),
            sessionId = EnsureSessionId(),
            buildVersion = BuildVersionLabel,
            campaignMandateId = CampaignMandateId(campaignMandate),
            campaignMandateName = CampaignMandateLabel(campaignMandate),
            caseCount = cases.Count,
            logCount = logs.Count,
            endingId = ending.id,
            endingTitle = ending.title,
            campaignScore = grade.score,
            campaignGrade = grade.grade,
            campaignBadge = grade.badge,
            finalBudget = budget,
            finalStability = stability,
            finalEquity = equity,
            finalMissedRisk = missedRisk,
            finalComplaints = complaints,
            difficultyRating = playtestSurveyRatings[0],
            decisionClarityRating = playtestSurveyRatings[1],
            resultFairnessRating = playtestSurveyRatings[2],
            uiReadabilityRating = playtestSurveyRatings[3],
            priceValueRating = playtestSurveyRatings[4],
            replayRewardValueRating = playtestSurveyRatings[5],
            difficultyTooHigh = playtestSurveyFlags[0],
            uiNeedsWork = playtestSurveyFlags[1],
            caseExplanationNeeded = playtestSurveyFlags[2],
            replayIntent = playtestSurveyFlags[3]
        };
    }

