        builder.AppendLine($"- UI 보강 필요: {BoolLabel(survey.uiNeedsWork)}");
        builder.AppendLine($"- 사례 설명 부족: {BoolLabel(survey.caseExplanationNeeded)}");
        builder.AppendLine($"- 다시 플레이 의향: {BoolLabel(survey.replayIntent)}");
        builder.AppendLine();
        builder.AppendLine("## 함께 회수할 파일");
        builder.AppendLine();
        builder.AppendLine("- `care_review_play_log.json`");
        builder.AppendLine("- `care_review_play_log.csv`");
        builder.AppendLine("- `care_review_incident_log.csv`");
        builder.AppendLine("- `care_review_playtest_summary.json`");
        builder.AppendLine("- `care_review_analytics_dashboard.html`");
        return builder.ToString();
    }

    private static string RatingDescriptor(int value)
    {
        return value switch
        {
            1 => "매우 낮음",
            2 => "낮음",
            4 => "높음",
            5 => "매우 높음",
            _ => "보통"
        };
    }
#endif

    private static string BoolLabel(bool value)
    {
        return value ? "예" : "아니오";
    }

    private void UpdateDecisionAuditDashboard()
    {
        if (decisionAuditSummaryText == null || decisionAuditRowTexts == null)
        {
            return;
        }

        List<DecisionDayAuditSummary> daySummaries = BuildDecisionDayAuditSummaries();
        int matched = 0;
        int urgentDelayCount = 0;
        int highCostSupportCount = 0;
        int mismatchCount = 0;
        int totalSpent = 0;
        int totalRiskDelta = 0;

        foreach (DecisionLog log in logs)
        {
            if (log.matchedRecommended)
            {
                matched++;
            }
            else
            {
                mismatchCount++;
            }

            if (IsDelayDecision(log.decision) && log.urgency >= 78)
            {
                urgentDelayCount++;
            }
            if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
            {
                highCostSupportCount++;
            }

            totalSpent += log.spentBudget;
            totalRiskDelta += Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore) + Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
        }

        decisionAuditSummaryText.text =
            "판단 복기\n" +
            $"운영 기준: {CampaignMandateLabel(campaignMandate)} · 판단 {logs.Count}/{cases.Count}건 · 권장 일치 {matched}/{Mathf.Max(1, logs.Count)}\n" +
            $"집행 {totalSpent}만원 · 위험 +{totalRiskDelta}p · 고위험 지연 {urgentDelayCount} · 고비용 지원 {highCostSupportCount} · 불일치 {mismatchCount}\n" +
            "일차별 지출, 위험 증가, 권장 일치율을 비교해 다음 회차 규칙을 정합니다.";

        for (int i = 0; i < decisionAuditRowTexts.Length; i++)
        {
            if (i >= daySummaries.Count)
            {
                decisionAuditRowTexts[i].text = "";
                SetDecisionAuditBar(decisionAuditSpendFills[i], 342f, 138f - i * 54f, 0f);
                SetDecisionAuditBar(decisionAuditRiskFills[i], 492f, 138f - i * 54f, 0f);
                SetDecisionAuditBar(decisionAuditMatchFills[i], 642f, 138f - i * 54f, 0f);
                continue;
            }

            DecisionDayAuditSummary day = daySummaries[i];
            float rowY = 138f - i * 54f;
            decisionAuditRowTexts[i].text =
                $"{day.day}일차 · {day.count}건\n" +
                $"지원 {day.supportCount} · 조사 {day.investigationCount} · 지연 {day.delayCount}";
            SetDecisionAuditBar(decisionAuditSpendFills[i], 342f, rowY, day.spentBudget / 1500f);
            SetDecisionAuditBar(decisionAuditRiskFills[i], 492f, rowY, day.riskDelta / 80f);
            SetDecisionAuditBar(decisionAuditMatchFills[i], 642f, rowY, day.matchedCount / (float)Mathf.Max(1, day.count));
        }

        if (decisionAuditQueueText != null)
        {
            decisionAuditQueueText.text = BuildDecisionAuditPressureQueueText();
        }
        if (decisionAuditCoachingText != null)
        {
            decisionAuditCoachingText.text = BuildDecisionAuditCoachingText(urgentDelayCount, highCostSupportCount, mismatchCount);
        }
    }

    private List<DecisionDayAuditSummary> BuildDecisionDayAuditSummaries()
    {
        Dictionary<int, DecisionDayAuditSummary> summariesByDay = new();
        foreach (DecisionLog log in logs)
        {
            if (!summariesByDay.TryGetValue(log.day, out DecisionDayAuditSummary summary))
            {
                summary = new DecisionDayAuditSummary(log.day);
                summariesByDay.Add(log.day, summary);
            }

            summary.count++;
            summary.spentBudget += log.spentBudget;
            summary.riskDelta += Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore) + Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
            if (IsSupportDecision(log.decision))
            {
                summary.supportCount++;
            }
            if (log.decision == "추가조사")
            {
                summary.investigationCount++;
            }
            if (IsDelayDecision(log.decision))
            {
                summary.delayCount++;
            }
            if (log.matchedRecommended)
            {
                summary.matchedCount++;
            }
        }

        List<DecisionDayAuditSummary> summaries = new(summariesByDay.Values);
        summaries.Sort((left, right) => left.day.CompareTo(right.day));
        return summaries;
    }

    private string BuildDecisionAuditPressureQueueText()
    {
        List<DecisionLog> rankedLogs = new(logs);
        rankedLogs.Sort((left, right) => DecisionAuditQueuePriorityScore(right).CompareTo(DecisionAuditQueuePriorityScore(left)));
        AppealReviewCampaignSummary appealSummary = BuildAppealReviewCampaignSummary();

        StringBuilder builder = new();
        builder.AppendLine("고압력 결정 · 대표 복기 사례");
        builder.AppendLine("불일치, 고위험 지연, 고비용 지원, 이의제기 점수를 합산한 상위 3건입니다.");
        if (appealSummary.count > 0)
        {
            builder.AppendLine($"이의제기 우선순위 {appealSummary.count}건 · 최고 {appealSummary.status} {appealSummary.maxScore}점 · {appealSummary.caseId} · 보정 {Shorten(appealSummary.remedy, 36)}");
            DecisionLog appealLog = HighestAppealReviewLogForCase(appealSummary.caseId, out _);
            if (appealLog != null)
            {
                builder.AppendLine($"{appealSummary.caseId} 보정 전/후 그래프 · {DecisionAuditBeforeAfterGraphText(appealLog)}");
            }
        }
        else
        {
            builder.AppendLine("이의제기 우선순위 0건 · 현재 보정 검토 큐 없음");
        }
        int added = 0;
        foreach (DecisionLog log in rankedLogs)
        {
            int score = DecisionAuditQueuePriorityScore(log);
            if (score <= 0 && added > 0)
            {
                break;
            }

            string flags = DecisionAuditFlags(log);
            int appealScore = AppealReviewScore(log);
            string appealSegment = appealScore >= 35
                ? $" · 보정 {AppealReviewStatus(log)} {appealScore}점"
                : "";
            string beforeAfterSegment = appealScore >= 35
                ? $" · {DecisionAuditBeforeAfterGraphText(log)}"
                : "";
            builder.AppendLine($"{log.caseId} · 우선 {score} · {ShortDecision(log.decision)}/{ShortDecision(log.recommendedDecision)} · {Shorten(flags, 18)}{Shorten(appealSegment + beforeAfterSegment, 24)}");
            added++;
            if (added >= 3)
            {
                break;
            }
        }

        if (added == 0)
        {
            builder.AppendLine("특정 고압력 결정이 없습니다. 심사 기록에서 세부 흐름을 확인하면 됩니다.");
        }

        return builder.ToString();
    }

    private string BuildDecisionAuditCoachingText(int urgentDelayCount, int highCostSupportCount, int mismatchCount)
    {
        DecisionAuditCoachingExport coaching = BuildDecisionAuditCoachingExport(urgentDelayCount, highCostSupportCount, mismatchCount);
        string appealLine = coaching.appealQueueCount > 0
            ? $"보정 큐: {coaching.appealQueueCount}건 · {coaching.appealCaseId} · {coaching.appealStatus} {coaching.appealScore}점"
            : "보정 큐: 현재 고점 사례 없음";

        return
            "다음 회차 복기\n" +
            $"핵심 패턴: {coaching.pattern} · 불일치 {coaching.mismatchCount} · 지연 {coaching.urgentDelayCount} · 고비용 {coaching.highCostSupportCount}\n" +
            $"추천 운영: {coaching.recommendedMandateName} · 실행 규칙: {Shorten(coaching.executionRule, 30)}\n" +
            $"검증 질문: {Shorten(coaching.verificationQuestion, 34)} · {Shorten(appealLine, 24)}\n" +
            $"다음 목표: {BuildDecisionAuditCoachingObjectiveChallenge(coaching)} · 버튼 라벨: {RecommendedCampaignButtonLabel(BuildDecisionAuditCoachingNextCampaignObjective(coaching))} · 권장 일치율";
    }

    private DecisionAuditCoachingExport BuildCurrentDecisionAuditCoachingExport()
    {
        int urgentDelayCount = 0;
        int highCostSupportCount = 0;
        int mismatchCount = 0;

        foreach (DecisionLog log in logs)
        {
            if (!log.matchedRecommended)
            {
                mismatchCount++;
            }

            if (IsDelayDecision(log.decision) && log.urgency >= 78)
            {
                urgentDelayCount++;
            }

            if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
            {
                highCostSupportCount++;
            }
        }

        return BuildDecisionAuditCoachingExport(urgentDelayCount, highCostSupportCount, mismatchCount);
    }

    private DecisionAuditCoachingExport BuildDecisionAuditCoachingExport(int urgentDelayCount, int highCostSupportCount, int mismatchCount)
    {
        AppealReviewCampaignSummary appealSummary = BuildAppealReviewCampaignSummary();
        string pattern;
        CampaignMandate recommendedMandate;
        string rule;

        if (urgentDelayCount >= Mathf.Max(2, highCostSupportCount))
        {
            pattern = "고위험 지연";
            recommendedMandate = CampaignMandate.SupportExpanded;
            rule = "긴급도 78+ 사례는 보류/거절 전에 조건부 지원 또는 추가조사를 먼저 검토";
        }
        else if (highCostSupportCount >= 2)
        {
            pattern = "고비용 지원";
            recommendedMandate = CampaignMandate.AusterityAudit;
            rule = "140만 원 이상 지원은 서류 강도와 대체 지원안을 같이 확인";
        }
        else if (mismatchCount >= Mathf.Max(2, logs.Count / 4))
        {
            pattern = "권장 불일치";
            recommendedMandate = CampaignMandate.Standard;
            rule = "권장 판단과 다른 결정을 내릴 때 위험/형평/예산 근거를 한 줄로 남김";
        }
        else if (appealSummary.count > 0)
        {
            pattern = "이의제기 보정";
            recommendedMandate = CampaignMandate.SupportExpanded;
            rule = "이의제기 점수 35+ 사례를 사례 자료실에서 보정 목표로 재심사";
        }
        else
        {
            pattern = "안정권";
            recommendedMandate = campaignMandate;
            rule = "현재 운영 기준을 유지하고 고압력 대표 사례 1건만 복기";
        }

        string verificationQuestion = "다음 판단 복기에서 위험 증가와 권장 일치율이 함께 개선됐는지 확인";
        return new DecisionAuditCoachingExport
        {
            pattern = pattern,
            mismatchCount = mismatchCount,
            urgentDelayCount = urgentDelayCount,
            highCostSupportCount = highCostSupportCount,
            recommendedMandateId = CampaignMandateId(recommendedMandate),
            recommendedMandateName = CampaignMandateLabel(recommendedMandate),
            executionRule = rule,
            appealQueueCount = appealSummary.count,
            appealCaseId = appealSummary.count > 0 ? appealSummary.caseId : "",
            appealStatus = appealSummary.count > 0 ? appealSummary.status : "",
            appealScore = appealSummary.count > 0 ? appealSummary.maxScore : 0,
            verificationQuestion = verificationQuestion,
            summaryLine = $"{pattern} · 추천 운영 {CampaignMandateLabel(recommendedMandate)} · {verificationQuestion}"
        };
    }

    private static NextCampaignObjective BuildDecisionAuditCoachingNextCampaignObjective(DecisionAuditCoachingExport coaching)
    {
        CampaignMandate mandate = CampaignMandateFromId(coaching.recommendedMandateId);
        return new NextCampaignObjective(
            mandate,
            BuildDecisionAuditCoachingObjectiveChallenge(coaching),
            BuildDecisionAuditCoachingObjectiveReason(coaching));
    }

    private static string BuildDecisionAuditCoachingObjectiveChallenge(DecisionAuditCoachingExport coaching)
    {
        if (coaching == null || string.IsNullOrWhiteSpace(coaching.pattern))
        {
            return "복기 목표: 고압력 대표 사례 1건 복기";
        }

        return coaching.pattern switch
        {
            "고위험 지연" => "복기 목표: 고위험 지연 3건 이하",
            "고비용 지원" => "복기 목표: 고비용 지원 3건 이하",
            "권장 불일치" => "복기 목표: 권장 불일치 5건 이하",
            "이의제기 보정" => "복기 목표: 이의제기 보정 사례 1건 재심사",
            _ => "복기 목표: 고압력 대표 사례 1건 복기"
        };
    }

    private static string BuildDecisionAuditCoachingObjectiveReason(DecisionAuditCoachingExport coaching)
    {
        if (coaching == null)
        {
            return "판단 복기 · 대표 사례 복기";
        }

        string appealSegment = coaching.appealQueueCount > 0 && !string.IsNullOrWhiteSpace(coaching.appealCaseId)
            ? $" · 보정 큐 {coaching.appealCaseId}"
            : "";
        return $"판단 복기 · 핵심 패턴 {coaching.pattern} · 추천 운영 {coaching.recommendedMandateName}{appealSegment}";
    }

    private static string DecisionAuditBeforeAfterGraphText(DecisionLog log)
    {
        int riskBefore = log.missedRiskBefore + log.complaintsBefore;
        int riskAfter = log.missedRiskAfter + log.complaintsAfter;
        return
            "보정 전/후 그래프 " +
            $"예산 {SignedNumber(log.budgetAfter - log.budgetBefore)} {MetricSpark(log.budgetBefore, log.budgetAfter, -4000, 16000)} · " +
            $"위험 {SignedNumber(riskAfter - riskBefore)} {MetricSpark(riskBefore, riskAfter, 0, 200)} · " +
            $"안정 {SignedNumber(log.stabilityAfter - log.stabilityBefore)} {MetricSpark(log.stabilityBefore, log.stabilityAfter, 0, 100)}";
    }

    private static string MetricSpark(int before, int after, int minValue, int maxValue)
    {
        const string levels = "▁▂▃▄▅▆▇█";
        return $"{MetricSparkLevel(before, minValue, maxValue, levels)}->{MetricSparkLevel(after, minValue, maxValue, levels)}";
    }

    private static char MetricSparkLevel(int value, int minValue, int maxValue, string levels)
    {
        float range = Mathf.Max(1, maxValue - minValue);
        int index = Mathf.Clamp(Mathf.RoundToInt(Mathf.Clamp01((value - minValue) / range) * (levels.Length - 1)), 0, levels.Length - 1);
        return levels[index];
    }

    private static int DecisionAuditQueuePriorityScore(DecisionLog log)
    {
        return DecisionAuditPressureScore(log) + AppealReviewScore(log) / 2;
    }

    private static int DecisionAuditPressureScore(DecisionLog log)
    {
        int score = 0;
        if (!log.matchedRecommended)
        {
            score += 35;
        }
        if (IsDelayDecision(log.decision) && log.urgency >= 78)
        {
            score += 30;
        }
        if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
        {
            score += 22;
        }
        score += Mathf.Max(0, log.urgency - 70) / 2;
        score += Mathf.Max(0, log.spentBudget - 120) / 6;
        score += Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore);
        score += Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
        return score;
    }

    private static string DecisionAuditFlags(DecisionLog log)
    {
        List<string> flags = new();
        if (!log.matchedRecommended)
        {
            flags.Add("권장 불일치");
        }
        if (IsDelayDecision(log.decision) && log.urgency >= 78)
        {
            flags.Add("고위험 지연");
        }
        if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
        {
            flags.Add("고비용 지원");
        }
        int riskDelta = Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore) + Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
        if (riskDelta > 0)
        {
            flags.Add("위험 +" + riskDelta);
        }
        int appealScore = AppealReviewScore(log);
        if (appealScore >= 35)
        {
            flags.Add("이의제기 " + appealScore);
        }

        return flags.Count == 0 ? "정상 범위" : string.Join(", ", flags);
    }

    private static string DecisionReviewReason(DecisionLog log)
    {
        List<string> reasons = new();
        if (!log.matchedRecommended)
        {
            reasons.Add("권장 판단과 다르게 처리");
        }
        if (IsDelayDecision(log.decision) && log.urgency >= 78)
        {
            reasons.Add("고위험 사례를 지연");
        }
        if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
        {
            reasons.Add("예산 부담이 큰 지원");
        }
        if (!log.incomeEligible && IsSupportDecision(log.decision))
        {
            reasons.Add("소득 예외 지원");
        }
        if (!string.IsNullOrWhiteSpace(log.missingDocuments) && IsSupportDecision(log.decision))
        {
            reasons.Add("보강 서류 남은 상태 지원");
        }

        int riskDelta = Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore) + Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
        if (riskDelta > 0)
        {
            reasons.Add("후속 위험 +" + riskDelta);
        }
        if (AppealReviewScore(log) >= 35)
        {
            reasons.Add("이의제기 검토 필요");
        }

        return reasons.Count == 0 ? "판단 근거 비교용 대표 사례" : string.Join(", ", reasons);
    }

    private static string DecisionReviewNextStep(DecisionLog log)
    {
        if (IsDelayDecision(log.decision) && log.urgency >= 78)
        {
            return "위험 신호 우선 근거로 추가조사/조건부 승인을 비교";
        }
        if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
        {
            return "예산 방어 근거로 조건부 승인이나 추가조사를 비교";
        }
        if (!log.matchedRecommended)
        {
            return $"권장 판단 '{log.recommendedDecision}' 적용 시 예산·위험 차이를 비교";
        }
        if (!string.IsNullOrWhiteSpace(log.missingDocuments) || log.documentStrength < 60)
        {
            return "서류 완성도 근거로 보류와 추가조사의 차이를 비교";
        }
        if (!log.incomeEligible)
        {
            return "소득 예외 기준을 적용했을 때 형평 지표 변화를 비교";
        }

        return "같은 가족 유형에서 선택 근거와 후속 지표를 비교";
    }

    private static string DecisionReviewArchiveFilter(DecisionLog log)
    {
        if (IsDelayDecision(log.decision) && log.urgency >= 78)
        {
            return "고위험";
        }
        if (!string.IsNullOrWhiteSpace(log.missingDocuments) || log.documentStrength < 60)
        {
            return "서류보강";
        }
        if (!log.incomeEligible)
        {
            return "소득예외";
        }
        if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
        {
            return "고비용";
        }
        if (log.decision == "추가조사" || log.recommendedDecision == "추가조사")
        {
            return "추가조사";
        }

        return "전체";
    }

    private static void SetDecisionAuditBar(Image fill, float centerX, float centerY, float ratio)
    {
        const float fullWidth = 98f;
        float width = Mathf.Clamp01(ratio) * fullWidth;
        RectTransform fillRect = fill.rectTransform;
        fillRect.sizeDelta = new Vector2(Mathf.Max(1f, width), 11f);
        fillRect.anchoredPosition = new Vector2(centerX - ((fullWidth - width) * 0.5f), centerY);
    }

    private static bool IsSupportDecision(string decision)
    {
        return decision == "승인" || decision == "조건부 승인";
    }

    private static bool IsDelayDecision(string decision)
    {
        return decision == "보류" || decision == "거절" || decision == "추가조사";
    }

    private string BuildIncidentReportLine()
    {
        if (incidentLogs.Count == 0)
        {
            return "특별 사건: 없음";
        }

        List<string> summaries = new();
        foreach (IncidentLog incident in incidentLogs)
        {
            if (summaries.Count >= 3)
            {
                break;
            }

            summaries.Add($"{incident.day}일차 {incident.title}");
        }

        return "특별 사건: " + string.Join(" / ", summaries);
    }

    private EndingOutcome BuildEndingOutcome()
    {
        if (stability >= 80 && equity >= 70 && missedRisk < 30 && complaints < 75 && budget > -1000)
        {
            return TrustRebuiltEnding();
        }

        if (budget < -1200 || complaints >= 90)
        {
            return PaperworkNightEnding();
        }

        if (missedRisk >= 55 || stability <= 35 || equity <= 35)
        {
            return WaitingRoomEnding();
        }

        return LitWindowsEnding();
    }

    private static EndingOutcome[] BuildEndingCatalog()
    {
        return new[]
        {
            TrustRebuiltEnding(),
            PaperworkNightEnding(),
            WaitingRoomEnding(),
            LitWindowsEnding()
        };
    }

    private static EndingOutcome TrustRebuiltEnding()
    {
        return new EndingOutcome(
            "trust_rebuilt",
            "신뢰 회복",
