    private string BuildEndingCardText(EndingOutcome ending)
    {
        return
            $"최종 엔딩 · {ending.title}\n" +
            $"{Shorten(ending.summary, 72)}\n" +
            $"후속: {CompactEndingEpilogueLine(ending)}\n" +
            $"다음: {Shorten(ending.nextStep, 70)}";
    }

    private string CompactEndingEpilogueLine(EndingOutcome ending)
    {
        if (currentCampaignInvestigationFollowUpCount > 0)
        {
            return $"조사 후속 기록 {currentCampaignInvestigationFollowUpCount}건 · {Shorten(ending.epilogue, 56)}";
        }

        return Shorten(ending.epilogue, 78);
    }

    private string BuildEndingEpilogue(EndingOutcome ending)
    {
        if (currentCampaignInvestigationFollowUpCount <= 0)
        {
            return ending.epilogue;
        }

        return ending.epilogue + "\n\n" +
            $"조사 후속 기록: 이번 회차에서 해금된 조사 메모 {currentCampaignInvestigationFollowUpCount}건이 다음 날 안전점검과 민원 완화로 이어졌습니다. " +
            "센터는 추가조사를 단순 지연이 아니라 다음 심사의 근거 자료로 남기는 절차를 만들었습니다.";
    }

    private string BuildReportInsight(string profile, int matched, EndingOutcome ending, CampaignGradeResult grade)
    {
        List<string> insights = new();
        insights.Add($"최종 엔딩: {ending.title}");
        insights.Add($"운영 등급: {grade.grade}({grade.score}점) · {grade.badge} · {grade.reason}");
        insights.Add("엔딩 해석: " + Shorten(ending.lesson, 72));
        insights.Add(BuildIncidentReportLine());
        if (budget < 0)
        {
            insights.Add("예산을 초과했습니다. 상용 버전에서는 다음 날 예산 압박 이벤트나 민원 증가로 이어질 수 있습니다.");
        }
        else if (budget < 250)
        {
            insights.Add("잔여 예산이 낮습니다. 고위험 사례를 승인한 이유와 보류한 사례의 기준을 함께 설명해야 합니다.");
        }
        else
        {
            insights.Add("예산 여지는 남아 있습니다. 남은 재원을 어떤 가족 유형에 배분했는지 비교하기 좋습니다.");
        }

        if (missedRisk >= 25)
        {
            insights.Add("누락 위험이 높아 사후 안전 점검이나 추가조사 카드가 필요합니다.");
        }
        else if (complaints >= 20)
        {
            insights.Add("민원 위험이 높습니다. 서류 기준과 예외 승인 기준을 리포트에서 분리해 보여주는 편이 좋습니다.");
        }
        else if (matched >= Mathf.CeilToInt(logs.Count * 0.75f))
        {
            insights.Add($"{profile} 성향이 권장 판단과 대체로 맞았습니다. 발표에서는 일치하지 않은 사례를 중심으로 설명하면 됩니다.");
        }
        else
        {
            insights.Add($"{profile} 성향이 권장 판단과 차이를 보였습니다. 차이가 난 사례를 판단 비교 결과와 다시 볼 수 있습니다.");
        }

        return string.Join("\n", insights);
    }

    private static string ShortReportObjectiveInsightLine(string text, int maxLength)
    {
        if (string.IsNullOrWhiteSpace(text))
        {
            return "";
        }

        return "\n" + Shorten(text.Replace("\n", " · "), maxLength);
    }

    private NextCampaignObjective BuildNextCampaignObjective(int matched, int supportDecisions, int holdDecisions, int rejectDecisions)
    {
        int highCostSupportCount = 0;
        int delayedRiskCount = 0;
        int urgentMismatchCount = 0;
        int mismatchCount = 0;
        foreach (DecisionLog log in logs)
        {
            if (IsSupportDecision(log.decision) && log.spentBudget >= 140)
            {
                highCostSupportCount++;
            }

            if (IsDelayDecision(log.decision) && log.urgency >= 78)
            {
                delayedRiskCount++;
            }

            if (!log.matchedRecommended && log.urgency >= 80)
            {
                urgentMismatchCount++;
            }

            if (!log.matchedRecommended)
            {
                mismatchCount++;
            }
        }

        float matchRate = logs.Count > 0 ? matched * 100f / logs.Count : 0f;
        if (TryBuildAchievementNextCampaignObjective(matchRate, out NextCampaignObjective achievementObjective))
        {
            return achievementObjective;
        }

        DecisionAuditCoachingExport coaching = BuildDecisionAuditCoachingExport(delayedRiskCount, highCostSupportCount, mismatchCount);
        if (coaching != null && !string.Equals(coaching.pattern, "안정권", StringComparison.Ordinal))
        {
            return BuildDecisionAuditCoachingNextCampaignObjective(coaching);
        }

        if (budget < -800 || highCostSupportCount >= 5)
        {
            return new NextCampaignObjective(
                CampaignMandate.AusterityAudit,
                "고비용 지원 3건 이하, 예산 -500만 이상",
                $"예산 {budget}만 · 고비용 지원 {highCostSupportCount}건");
        }

        if (missedRisk >= 45 || delayedRiskCount >= 5)
        {
            return new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                "고위험 지연 절반 줄이기",
                $"누락 {missedRisk}/100 · 고위험 지연 {delayedRiskCount}건");
        }

        if (complaints >= 85 || urgentMismatchCount >= 4)
        {
            return new NextCampaignObjective(
                CampaignMandate.Standard,
                "권장 불일치 5건 이하",
                $"민원 {complaints}/100 · 고위험 불일치 {urgentMismatchCount}건");
        }

        if (matchRate >= 85f && budget >= 0 && missedRisk <= 25)
        {
            CampaignMandate nextMandate = campaignMandate == CampaignMandate.AusterityAudit
                ? CampaignMandate.SupportExpanded
                : CampaignMandate.AusterityAudit;
            string challenge = nextMandate == CampaignMandate.AusterityAudit
                ? "권장 일치 80% 이상, 예산 흑자 유지"
                : "지원 확대에서도 누락 위험 30 이하";
            return new NextCampaignObjective(
                nextMandate,
                challenge,
                $"일치율 {matchRate:0}% · 예산 {budget}만 · 누락 {missedRisk}");
        }

        if (investigations <= 2 && matchRate < 75f)
        {
            return new NextCampaignObjective(
                CampaignMandate.Standard,
                "추가조사 4건 이상, 일치율 75% 회복",
                $"추가조사 {investigations}건 · 일치율 {matchRate:0}%");
        }

        CampaignMandate fallbackMandate = campaignMandate == CampaignMandate.Standard
            ? CampaignMandate.SupportExpanded
            : CampaignMandate.Standard;
        return new NextCampaignObjective(
            fallbackMandate,
            "다른 운영 기준에서 같은 사례 다시 판단",
            $"지원 {supportDecisions}건 · 보류/거절 {holdDecisions + rejectDecisions}건 · 일치율 {matchRate:0}%");
    }

    private bool TryBuildAchievementNextCampaignObjective(float matchRate, out NextCampaignObjective objective)
    {
        if (!IsAchievementUnlocked("budget_explained") && budget < -1000)
        {
            objective = new NextCampaignObjective(
                CampaignMandate.AusterityAudit,
                "성과 목표: 예산 초과 -1000만 미만",
                $"미해금 성과: 예산 설명 완료 · 현재 예산 {budget}만");
            return true;
        }

        if (!IsAchievementUnlocked("risk_shield") && missedRisk > 25)
        {
            objective = new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                "성과 목표: 최종 누락 위험 25 이하",
                $"미해금 성과: 누락 위험 방어 · 현재 누락 {missedRisk}/100");
            return true;
        }

        if (!IsAchievementUnlocked("equity_guardian") && equity < 90)
        {
            objective = new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                "성과 목표: 형평성 90 이상",
                $"미해금 성과: 형평성 우선 · 현재 형평 {equity}/100");
            return true;
        }

        if (!IsAchievementUnlocked("recommended_path") && matchRate < 85f)
        {
            objective = new NextCampaignObjective(
                CampaignMandate.Standard,
                "성과 목표: 권장 판단 85% 이상",
                $"미해금 성과: 근거 중심 심사 · 현재 일치율 {matchRate:0}%");
            return true;
        }

        if (!IsAchievementUnlocked("investigation_follow_up") && currentCampaignInvestigationFollowUpCount <= 0)
        {
            objective = new NextCampaignObjective(
                CampaignMandate.Standard,
                "성과 목표: 조사 메모 후속 1건 이상",
                "미해금 성과: 조사 후속 처리 · 추가조사 권장 사례를 놓치지 않기");
            return true;
        }

        if (!IsAchievementUnlocked("mandate_replay") && CountCompletedMandates() < 2)
        {
            CampaignMandate nextMandate = campaignMandate == CampaignMandate.AusterityAudit
                ? CampaignMandate.SupportExpanded
                : CampaignMandate.AusterityAudit;
            objective = new NextCampaignObjective(
                nextMandate,
                "성과 목표: 다른 운영 기준으로 캠페인 완료",
                $"미해금 성과: 운영 기준 실험 · 현재 완료 기준 {CountCompletedMandates()}/{CampaignMandateCatalog.Length}");
            return true;
        }

        objective = default;
        return false;
    }

    private static bool IsAchievementObjective(NextCampaignObjective objective)
    {
        return !string.IsNullOrWhiteSpace(objective.reason) &&
            objective.reason.Contains("미해금 성과");
    }

    private static string AchievementObjectiveTitle(NextCampaignObjective objective)
    {
        if (!IsAchievementObjective(objective))
        {
            return "";
        }

        string marker = "미해금 성과:";
        int markerIndex = objective.reason.IndexOf(marker, StringComparison.Ordinal);
        if (markerIndex < 0)
        {
            return "장기 성과 목표";
        }

        string title = objective.reason.Substring(markerIndex + marker.Length).Trim();
        int separatorIndex = title.IndexOf('·');
        if (separatorIndex >= 0)
        {
            title = title.Substring(0, separatorIndex).Trim();
        }

        return string.IsNullOrWhiteSpace(title) ? "장기 성과 목표" : title;
    }

    private static string BuildLongTermProgressionPromptLine()
    {
        return "장기 추천: " + BuildLongTermProgressionPromptText();
    }

    private static string BuildAdvancedReplayChallengeReportLine()
    {
        int replayObjectiveCount = CountReplayObjectiveRecords(LoadCareerRecordDatabase().records);
        if (replayObjectiveCount < 2)
        {
            return $"상위 챌린지: 반복 목표 {replayObjectiveCount}/2 · 사례 목표/성과 목표 회차를 더 완료";
        }

        return $"상위 챌린지: {AdvancedReplayChallengeBadge(replayObjectiveCount)} · {AdvancedReplayChallengeProgress(replayObjectiveCount)}";
    }

    private static string BuildAdvancedReplayChallengeMenuCardLine()
    {
        int replayObjectiveCount = CountReplayObjectiveRecords(LoadCareerRecordDatabase().records);
        if (replayObjectiveCount <= 0)
        {
            return "반복 장식: 목표 심사 완료 후 챌린지 카드 해금";
        }

        string next = replayObjectiveCount >= 6
            ? "최고 단계"
            : $"다음 {Mathf.Max(2, replayObjectiveCount >= 4 ? 6 : 4)}회";
        return $"반복 장식: {AdvancedReplayChallengeTier(replayObjectiveCount)} · {AdvancedReplayChallengeDecoration(replayObjectiveCount)} · {replayObjectiveCount}회/{next}";
    }

    private static string BuildLongTermProgressionPromptText()
    {
        List<CareerRecord> records = LoadCareerRecordDatabase().records;
        int replayObjectiveCount = CountReplayObjectiveRecords(records);
        int appealRemedyObjectiveCount = CountAppealRemedyObjectiveRecords(records);
        if (replayObjectiveCount >= 2)
        {
            string appealSegment = appealRemedyObjectiveCount > 0 ? $" · 보정 목표 {appealRemedyObjectiveCount}회" : "";
            return $"{AdvancedReplayChallengeBadge(replayObjectiveCount)} 해금 - 고난도 챌린지 {AdvancedReplayChallengeProgress(replayObjectiveCount)}{appealSegment}.";
        }

        if (appealRemedyObjectiveCount > 0)
        {
            return $"이의제기 보정 목표 {appealRemedyObjectiveCount}회 완료 - 사례 자료실 이의제기 큐에서 다음 보정 목표를 이어가세요.";
        }

        if (!IsAchievementUnlocked("campaign_complete"))
        {
            return "첫 5일 캠페인을 완료해 성과 기록을 여세요.";
        }

        if (!IsAchievementUnlocked("budget_explained"))
        {
            return "예산 설명 완료 - 긴축 감사에서 예산 초과를 -1000만 미만으로 줄이기.";
        }

        if (!IsAchievementUnlocked("risk_shield"))
        {
            return "누락 위험 방어 - 고위험 지연을 줄여 최종 누락 위험 25 이하 달성.";
        }

        if (!IsAchievementUnlocked("equity_guardian"))
        {
            return "형평성 우선 - 지원 확대 기준에서 형평성 90 이상 달성.";
        }

        if (!IsAchievementUnlocked("recommended_path"))
        {
            return "근거 중심 심사 - 권장 판단 85% 이상 일치.";
        }

        if (!IsAchievementUnlocked("investigation_follow_up"))
        {
            return "조사 후속 처리 - 추가조사 메모를 다음 날 위험 완화로 연결.";
        }

        if (!IsAchievementUnlocked("mandate_replay"))
        {
            return $"운영 기준 실험 - 다른 운영 기준으로 완료해 기준별 기록 {CountCompletedMandates()}/{CampaignMandateCatalog.Length} 확장.";
        }

        if (!IsAchievementUnlocked("case_objective_replay"))
        {
            return "사례 재심사 목표 - V 사례 자료실에서 목표 심사로 새 회차 시작.";
        }

        return "반복 목표 2회차 이상 누적 후 상위 배지와 고난도 챌린지를 노리세요.";
    }

    private static bool IsReplayObjectiveRecord(CareerRecord record)
    {
        if (record == null)
        {
            return false;
        }

        return record.startedFromCaseObjective || record.startedFromAchievementObjective;
    }

    private static int CountReplayObjectiveRecords(List<CareerRecord> records)
    {
        int count = 0;
        if (records == null)
        {
            return count;
        }

        for (int i = 0; i < records.Count; i++)
        {
            if (IsReplayObjectiveRecord(records[i]))
            {
                count++;
            }
        }

        return count;
    }

    private static int CountAppealRemedyObjectiveRecords(List<CareerRecord> records)
    {
        int count = 0;
        if (records == null)
        {
            return count;
        }

        for (int i = 0; i < records.Count; i++)
        {
            if (records[i] != null && records[i].appealRemedyObjectiveCompleted)
            {
                count++;
            }
        }

        return count;
    }

    private static int CountAppealRemedyTriageCareerRecords(List<CareerRecord> records, out int successCount)
    {
        int count = 0;
        successCount = 0;
        if (records == null)
        {
            return count;
        }

        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null ||
                !record.appealRemedyObjectiveCompleted ||
                string.IsNullOrWhiteSpace(record.appealRemedyObjectiveTriageLabel))
            {
                continue;
            }

            count++;
            if (record.appealRemedyObjectiveSucceeded)
            {
                successCount++;
            }
        }

        return count;
    }

    private static bool TryFindLatestAppealRemedyTriageCareerRecord(List<CareerRecord> records, out CareerRecord linkedRecord)
    {
        linkedRecord = null;
        if (records == null || records.Count == 0)
        {
            return false;
        }

        for (int i = 0; i < records.Count; i++)
        {
            CareerRecord record = records[i];
            if (record == null ||
                !record.appealRemedyObjectiveCompleted ||
                string.IsNullOrWhiteSpace(record.appealRemedyObjectiveTriageLabel))
            {
                continue;
            }

            if (linkedRecord == null ||
                string.Compare(record.completedAt, linkedRecord.completedAt, StringComparison.Ordinal) > 0)
            {
                linkedRecord = record;
            }
        }

        return linkedRecord != null;
    }

    private static int CountDecisionPracticeObjectiveRecords(List<CareerRecord> records)
    {
        int count = 0;
        if (records == null)
        {
            return count;
        }

        for (int i = 0; i < records.Count; i++)
        {
            if (records[i] != null && records[i].decisionPracticeObjectiveCompleted)
            {
                count++;
            }
        }

        return count;
    }

    private static string AdvancedReplayChallengeBadge(int replayObjectiveCount)
    {
        if (replayObjectiveCount >= 6)
        {
            return "상위 배지: 반복 목표 설계자";
        }

        return replayObjectiveCount >= 4
            ? "상위 배지: 반복 목표 감독관"
            : "상위 배지: 반복 목표 전문가";
    }

    private static string AdvancedReplayChallengeProgress(int replayObjectiveCount)
    {
        if (replayObjectiveCount >= 6)
        {
            return $"반복 목표 {replayObjectiveCount}회 완료 · 최고 단계 장식 활성";
        }

        int nextTarget = replayObjectiveCount >= 4 ? 6 : 4;
        return $"반복 목표 {replayObjectiveCount}회 완료 · 다음 상위 단계 {nextTarget}회";
    }

    private static string AdvancedReplayChallengeTier(int replayObjectiveCount)
    {
        if (replayObjectiveCount >= 6)
        {
            return "상위 단계 3";
        }
        if (replayObjectiveCount >= 4)
        {
            return "상위 단계 2";
        }
        if (replayObjectiveCount >= 2)
        {
            return "상위 단계 1";
        }

        return "상위 단계 준비";
    }

    private static string AdvancedReplayChallengeDecoration(int replayObjectiveCount)
    {
        if (replayObjectiveCount >= 6)
        {
            return "금색 엔딩 장식";
        }
        if (replayObjectiveCount >= 4)
        {
            return "은색 챌린지 카드";
        }
        if (replayObjectiveCount >= 2)
        {
            return "동색 반복 목표 인장";
        }

        return "장식 잠김";
    }

    private static string SignedNumber(int value)
    {
        return value >= 0 ? "+" + value : value.ToString();
    }

    private static string ShortDecision(string decision)
    {
        return decision switch
        {
            "승인" => "승",
            "조건부 승인" => "조건",
            "추가조사" => "조사",
            "보류" => "보류",
            "거절" => "거절",
            _ => decision
        };
    }

#if !CARE_REVIEW_QA_TOOLS
    private static DecisionKind DecisionKindFromLabel(string decision)
    {
        return decision switch
        {
            "승인" => DecisionKind.Approve,
            "조건부 승인" => DecisionKind.Conditional,
            "추가조사" => DecisionKind.Investigate,
            "거절" => DecisionKind.Reject,
            _ => DecisionKind.Hold
        };
    }
