        string diagnosticMarkdownPath = Path.Combine(sessionDirectoryPath, "care_review_system_diagnostic.md");
        SystemDiagnosticExport diagnostic = BuildSystemDiagnosticExport(sessionId, BuildEmptyPerformanceSample("playtest_readiness"), diagnosticJsonPath, diagnosticMarkdownPath);
        File.WriteAllText(diagnosticJsonPath, JsonUtility.ToJson(diagnostic, true), Encoding.UTF8);
        File.WriteAllText(diagnosticMarkdownPath, BuildSystemDiagnosticMarkdown(diagnostic), Encoding.UTF8);
        WriteLatestPlaytestPacketCopies(diagnosticJsonPath, diagnosticMarkdownPath);
        return diagnostic;
    }

    private SystemDiagnosticExport BuildSystemDiagnosticExport(string sessionId, PerformanceScreenSample sample, string jsonPath, string markdownPath)
    {
        Resolution currentResolution = Screen.currentResolution;
        return new SystemDiagnosticExport
        {
            generatedAt = DateTime.Now.ToString("s"),
            sessionId = sessionId,
            buildVersion = BuildVersionLabel,
            operatingSystem = SystemInfo.operatingSystem,
            processorType = SystemInfo.processorType,
            processorCount = SystemInfo.processorCount,
            systemMemorySizeMb = SystemInfo.systemMemorySize,
            graphicsDeviceName = SystemInfo.graphicsDeviceName,
            graphicsDeviceVendor = SystemInfo.graphicsDeviceVendor,
            graphicsDeviceType = SystemInfo.graphicsDeviceType.ToString(),
            graphicsMemorySizeMb = SystemInfo.graphicsMemorySize,
            graphicsShaderLevel = SystemInfo.graphicsShaderLevel,
            graphicsMultiThreaded = SystemInfo.graphicsMultiThreaded,
            displayResolution = $"{currentResolution.width}x{currentResolution.height}@{currentResolution.refreshRateRatio.value:0.##}Hz",
            screenWidth = Screen.width,
            screenHeight = Screen.height,
            fullscreen = fullscreenEnabled,
            resolutionLabel = ResolutionLabel(),
            lowSpecMode = lowSpecMode,
            targetFrameRate = Application.targetFrameRate,
            frameRateLabel = FrameRateLabel(),
            largeTextMode = largeTextMode,
            highContrastMode = highContrastMode,
            sampleScreen = sample.screen,
            sampleFrameCount = sample.frameCount,
            averageFrameMs = sample.averageFrameMs,
            p95FrameMs = sample.p95FrameMs,
            maxFrameMs = sample.maxFrameMs,
            passesFrameBudget = sample.passesFrameBudget,
            managedMemoryBytes = sample.managedMemoryBytes,
            diagnosticJsonPath = SessionRelativePath(sessionId, jsonPath),
            diagnosticMarkdownPath = SessionRelativePath(sessionId, markdownPath)
        };
    }

    private static string BuildSystemDiagnosticMarkdown(SystemDiagnosticExport diagnostic)
    {
        StringBuilder builder = new();
        builder.AppendLine("# 돌봄지원 심사소 환경 진단");
        builder.AppendLine();
        builder.AppendLine($"- 생성 시각: {diagnostic.generatedAt}");
        builder.AppendLine($"- 세션 ID: {diagnostic.sessionId}");
        builder.AppendLine($"- 빌드: {diagnostic.buildVersion}");
        builder.AppendLine();
        builder.AppendLine("## 시스템");
        builder.AppendLine();
        builder.AppendLine($"- OS: {diagnostic.operatingSystem}");
        builder.AppendLine($"- CPU: {diagnostic.processorType} ({diagnostic.processorCount} threads)");
        builder.AppendLine($"- RAM: {diagnostic.systemMemorySizeMb} MB");
        builder.AppendLine($"- 그래픽: {diagnostic.graphicsDeviceName} / {diagnostic.graphicsDeviceVendor}");
        builder.AppendLine($"- 그래픽 타입: {diagnostic.graphicsDeviceType}, VRAM {diagnostic.graphicsMemorySizeMb} MB, shader {diagnostic.graphicsShaderLevel}");
        builder.AppendLine();
        builder.AppendLine("## 게임 설정");
        builder.AppendLine();
        builder.AppendLine($"- 화면: {diagnostic.screenWidth}x{diagnostic.screenHeight}, 설정 {diagnostic.resolutionLabel}, 전체화면 {BoolLabel(diagnostic.fullscreen)}");
        builder.AppendLine($"- 성능: {(diagnostic.lowSpecMode ? "저사양 모드" : "표준")}, FPS {diagnostic.frameRateLabel}, target {diagnostic.targetFrameRate}");
        builder.AppendLine($"- 접근성: 큰 글자 {BoolLabel(diagnostic.largeTextMode)}, 고대비 {BoolLabel(diagnostic.highContrastMode)}");
        builder.AppendLine();
        builder.AppendLine("## 프레임 샘플");
        builder.AppendLine();
        builder.AppendLine($"- 화면: {diagnostic.sampleScreen}");
        builder.AppendLine($"- 샘플: {diagnostic.sampleFrameCount} frames");
        builder.AppendLine($"- 평균: {diagnostic.averageFrameMs:0.00}ms");
        builder.AppendLine($"- p95: {diagnostic.p95FrameMs:0.00}ms");
        builder.AppendLine($"- 최대: {diagnostic.maxFrameMs:0.00}ms");
        builder.AppendLine($"- 50ms 기준: {(diagnostic.passesFrameBudget ? "통과" : "확인 필요")}");
        builder.AppendLine();
        builder.AppendLine("## 회수 파일");
        builder.AppendLine();
        builder.AppendLine($"- JSON: {diagnostic.diagnosticJsonPath}");
        builder.AppendLine($"- Markdown: {diagnostic.diagnosticMarkdownPath}");
        return builder.ToString();
    }

    private PlaytestAggregateExport ExportPlaytestSessionAggregate()
    {
        List<PlaytestAggregateSessionRow> rows = LoadPlaytestAggregateRows();
        rows.Sort((left, right) => string.Compare(left.generatedAt, right.generatedAt, StringComparison.Ordinal));

        int totalCaseLogs = 0;
        int totalPlaySeconds = 0;
        int totalBudget = 0;
        int totalStability = 0;
        int totalEquity = 0;
        int totalMissedRisk = 0;
        int totalComplaints = 0;
        int totalCampaignScore = 0;
        int totalChallengeScore = 0;
        int challengeSuccessCount = 0;
        int surveySessionCount = 0;
        int totalDifficultyRating = 0;
        int totalDecisionClarityRating = 0;
        int totalResultFairnessRating = 0;
        int totalUiReadabilityRating = 0;
        int totalPriceValueRating = 0;
        int totalReplayRewardValueRating = 0;
        int replayIntentCount = 0;
        int lowPriceValueCount = 0;
        int lowReplayRewardValueCount = 0;
        int lowDecisionClarityCount = 0;
        int uiNeedsWorkCount = 0;
        int commercialChecklistPriceValuePositiveCount = 0;
        int commercialChecklistReplayRewardPositiveCount = 0;
        int commercialChecklistReplayIntentPositiveCount = 0;
        int commercialChecklistFollowUpCount = 0;
        float totalMatchRate = 0f;
        int completedCampaigns = 0;
        int appealRemedyGraphCaseCount = 0;
        int decisionAuditCoachingSessionCount = 0;
        int decisionAuditCoachingMismatchCount = 0;
        int decisionAuditCoachingUrgentDelayCount = 0;
        int decisionAuditCoachingHighCostSupportCount = 0;
        int decisionAuditCoachingAppealQueueSessionCount = 0;
        List<PlaytestAggregateCount> mandateCounts = new();
        List<PlaytestAggregateCount> endingCounts = new();
        List<PlaytestAggregateCount> focusCounts = new();
        List<PlaytestAggregateCount> decisionAuditCoachingPatternCounts = new();
        List<PlaytestAggregateCount> decisionAuditCoachingMandateCounts = new();

        foreach (PlaytestAggregateSessionRow row in rows)
        {
            totalCaseLogs += row.logCount;
            totalPlaySeconds += row.totalPlaySeconds;
            totalBudget += row.finalBudget;
            totalStability += row.finalStability;
            totalEquity += row.finalEquity;
            totalMissedRisk += row.finalMissedRisk;
            totalComplaints += row.finalComplaints;
            totalCampaignScore += row.campaignScore;
            totalChallengeScore += row.campaignChallengeScore;
            totalMatchRate += row.recommendedMatchRatePercent;
            if (row.campaignChallengeSucceeded)
            {
                challengeSuccessCount++;
            }
            if (row.logCount >= row.caseCount && row.caseCount > 0)
            {
                completedCampaigns++;
            }
            appealRemedyGraphCaseCount += row.decisionAuditAppealRemedyCaseCount;
            if (row.hasSurveyRatings)
            {
                surveySessionCount++;
                totalDifficultyRating += row.difficultyRating;
                totalDecisionClarityRating += row.decisionClarityRating;
                totalResultFairnessRating += row.resultFairnessRating;
                totalUiReadabilityRating += row.uiReadabilityRating;
                totalPriceValueRating += row.priceValueRating;
                totalReplayRewardValueRating += row.replayRewardValueRating;
                if (row.priceValueRating >= 4)
                {
                    commercialChecklistPriceValuePositiveCount++;
                }
                if (row.replayRewardValueRating >= 4)
                {
                    commercialChecklistReplayRewardPositiveCount++;
                }
                if (row.replayIntent)
                {
                    replayIntentCount++;
                    commercialChecklistReplayIntentPositiveCount++;
                }
                if (row.priceValueRating > 0 && row.priceValueRating <= 2)
                {
                    lowPriceValueCount++;
                }
                if (row.replayRewardValueRating > 0 && row.replayRewardValueRating <= 2)
                {
                    lowReplayRewardValueCount++;
                }
                if (row.decisionClarityRating > 0 && row.decisionClarityRating <= 2)
                {
                    lowDecisionClarityCount++;
                }
                if (row.uiNeedsWork)
                {
                    uiNeedsWorkCount++;
                }
                if ((row.priceValueRating > 0 && row.priceValueRating <= 2) ||
                    (row.replayRewardValueRating > 0 && row.replayRewardValueRating <= 2) ||
                    row.uiNeedsWork ||
                    !row.replayIntent)
                {
                    commercialChecklistFollowUpCount++;
                }
            }

            IncrementAggregateCount(mandateCounts, row.campaignMandateId, row.campaignMandateName);
            IncrementAggregateCount(endingCounts, row.endingId, row.endingTitle);
            IncrementAggregateCount(focusCounts, row.balanceRiskFocus, row.balanceRiskFocus);
            if (!string.IsNullOrEmpty(row.decisionAuditCoachingPattern))
            {
                decisionAuditCoachingSessionCount++;
                decisionAuditCoachingMismatchCount += row.decisionAuditCoachingMismatchCount;
                decisionAuditCoachingUrgentDelayCount += row.decisionAuditCoachingUrgentDelayCount;
                decisionAuditCoachingHighCostSupportCount += row.decisionAuditCoachingHighCostSupportCount;
                if (!string.IsNullOrEmpty(row.decisionAuditCoachingAppealCaseId))
                {
                    decisionAuditCoachingAppealQueueSessionCount++;
                }

                IncrementAggregateCount(
                    decisionAuditCoachingPatternCounts,
                    row.decisionAuditCoachingPattern,
                    row.decisionAuditCoachingPattern);
                IncrementAggregateCount(
                    decisionAuditCoachingMandateCounts,
                    row.decisionAuditCoachingRecommendedMandateId,
                    row.decisionAuditCoachingRecommendedMandateName);
            }
        }

        int sessionCount = rows.Count;
        PlaytestAggregateExport aggregate = new()
        {
            generatedAt = DateTime.Now.ToString("s"),
            sessionCount = sessionCount,
            completedCampaigns = completedCampaigns,
            totalCaseLogs = totalCaseLogs,
            averagePlaySeconds = sessionCount > 0 ? totalPlaySeconds / sessionCount : 0,
            averagePlayTime = FormatDuration(sessionCount > 0 ? totalPlaySeconds / sessionCount : 0),
            averageCampaignScore = sessionCount > 0 ? totalCampaignScore / (float)sessionCount : 0f,
            averageChallengeScore = sessionCount > 0 ? totalChallengeScore / (float)sessionCount : 0f,
            challengeSuccessCount = challengeSuccessCount,
            averageRecommendedMatchRatePercent = sessionCount > 0 ? totalMatchRate / sessionCount : 0f,
            averageFinalBudget = sessionCount > 0 ? totalBudget / (float)sessionCount : 0f,
            averageFinalStability = sessionCount > 0 ? totalStability / (float)sessionCount : 0f,
            averageFinalEquity = sessionCount > 0 ? totalEquity / (float)sessionCount : 0f,
            averageFinalMissedRisk = sessionCount > 0 ? totalMissedRisk / (float)sessionCount : 0f,
            averageFinalComplaints = sessionCount > 0 ? totalComplaints / (float)sessionCount : 0f,
            surveySessionCount = surveySessionCount,
            averageDifficultyRating = surveySessionCount > 0 ? totalDifficultyRating / (float)surveySessionCount : 0f,
            averageDecisionClarityRating = surveySessionCount > 0 ? totalDecisionClarityRating / (float)surveySessionCount : 0f,
            averageResultFairnessRating = surveySessionCount > 0 ? totalResultFairnessRating / (float)surveySessionCount : 0f,
            averageUiReadabilityRating = surveySessionCount > 0 ? totalUiReadabilityRating / (float)surveySessionCount : 0f,
            averagePriceValueRating = surveySessionCount > 0 ? totalPriceValueRating / (float)surveySessionCount : 0f,
            averageReplayRewardValueRating = surveySessionCount > 0 ? totalReplayRewardValueRating / (float)surveySessionCount : 0f,
            replayIntentCount = replayIntentCount,
            lowPriceValueCount = lowPriceValueCount,
            lowReplayRewardValueCount = lowReplayRewardValueCount,
            lowDecisionClarityCount = lowDecisionClarityCount,
            uiNeedsWorkCount = uiNeedsWorkCount,
            commercialChecklistSurveyCount = surveySessionCount,
            commercialChecklistPriceValuePositiveCount = commercialChecklistPriceValuePositiveCount,
            commercialChecklistReplayRewardPositiveCount = commercialChecklistReplayRewardPositiveCount,
            commercialChecklistReplayIntentPositiveCount = commercialChecklistReplayIntentPositiveCount,
            commercialChecklistFollowUpCount = commercialChecklistFollowUpCount,
            commercialChecklistAggregateSummaryReady = surveySessionCount > 0,
            appealRemedyGraphCaseCount = appealRemedyGraphCaseCount,
            appealRemedyGraphTriage = BuildAggregateAppealRemedyGraphTriage(rows),
            decisionAuditCoachingSessionCount = decisionAuditCoachingSessionCount,
            decisionAuditCoachingMismatchCount = decisionAuditCoachingMismatchCount,
            decisionAuditCoachingUrgentDelayCount = decisionAuditCoachingUrgentDelayCount,
            decisionAuditCoachingHighCostSupportCount = decisionAuditCoachingHighCostSupportCount,
            decisionAuditCoachingAppealQueueSessionCount = decisionAuditCoachingAppealQueueSessionCount,
            decisionAuditCoachingPatternCounts = decisionAuditCoachingPatternCounts,
            decisionAuditCoachingMandateCounts = decisionAuditCoachingMandateCounts,
            sessions = rows,
            mandateCounts = mandateCounts,
            endingCounts = endingCounts,
            focusCounts = focusCounts
        };

        Directory.CreateDirectory(LogDirectory);
        string csvPath = Path.Combine(LogDirectory, "care_review_playtest_sessions_index.csv");
        string jsonPath = Path.Combine(LogDirectory, "care_review_playtest_aggregate.json");
        string markdownPath = Path.Combine(LogDirectory, "care_review_playtest_aggregate.md");
        File.WriteAllText(csvPath, BuildPlaytestAggregateCsv(rows), Encoding.UTF8);
        File.WriteAllText(jsonPath, JsonUtility.ToJson(aggregate, true), Encoding.UTF8);
        File.WriteAllText(markdownPath, BuildPlaytestAggregateMarkdown(aggregate), Encoding.UTF8);
        Debug.Log("CARE_REVIEW_PLAYTEST_AGGREGATE path=" + jsonPath + " sessions=" + sessionCount);
        return aggregate;
    }

    private List<PlaytestAggregateSessionRow> LoadPlaytestAggregateRows()
    {
        List<PlaytestAggregateSessionRow> rows = new();
        HashSet<string> seenSessionIds = new();
        string sessionArchiveRoot = Path.Combine(LogDirectory, "playtest_sessions");
        if (!Directory.Exists(sessionArchiveRoot))
        {
            return rows;
        }

        string[] summaryPaths = Directory.GetFiles(sessionArchiveRoot, "care_review_playtest_summary.json", SearchOption.AllDirectories);
        Array.Sort(summaryPaths, StringComparer.OrdinalIgnoreCase);
        foreach (string summaryPath in summaryPaths)
        {
            try
            {
                PlaytestPacketExport packet = JsonUtility.FromJson<PlaytestPacketExport>(File.ReadAllText(summaryPath, Encoding.UTF8));
                if (packet == null || string.IsNullOrEmpty(packet.sessionId) || seenSessionIds.Contains(packet.sessionId))
                {
                    continue;
                }

                seenSessionIds.Add(packet.sessionId);
                string fallbackSessionDirectory = SessionRelativeDirectory(packet.sessionId);
                string feedbackMarkdownPath = string.IsNullOrEmpty(packet.feedbackMarkdownPath) || ContainsLocalAbsolutePath(packet.feedbackMarkdownPath)
                    ? fallbackSessionDirectory + "/care_review_playtest_feedback.md"
                    : NormalizeShareablePath(packet.feedbackMarkdownPath);
                string analyticsDashboardPath = string.IsNullOrEmpty(packet.analyticsDashboardPath) || ContainsLocalAbsolutePath(packet.analyticsDashboardPath)
                    ? fallbackSessionDirectory + "/care_review_analytics_dashboard.html"
                    : NormalizeShareablePath(packet.analyticsDashboardPath);
                CampaignGradeResult grade = packet.campaignScore > 0 && !string.IsNullOrEmpty(packet.campaignGrade)
                    ? new CampaignGradeResult(packet.campaignScore, packet.campaignGrade, packet.campaignBadge, packet.campaignGradeReason, 0, 0, 0, 0, 0, 0)
                    : BuildCampaignGradeFromPacket(packet);
                PlaytestSurveyExport survey = LoadPlaytestSurveyForAggregate(summaryPath);
                bool hasSurveyRatings = survey != null && survey.priceValueRating > 0;
                int replayRewardValueRating = hasSurveyRatings
                    ? (survey.replayRewardValueRating > 0 ? survey.replayRewardValueRating : survey.priceValueRating)
                    : 0;
                List<PlaytestAggregateAppealRemedyCase> appealRemedyCases = BuildPlaytestAggregateAppealRemedyCases(packet);
                PlaytestAggregateAppealRemedyCase topAppealRemedyCase = appealRemedyCases.Count > 0 ? appealRemedyCases[0] : null;
                DecisionAuditCoachingExport coaching = packet.decisionAuditCoaching;

                rows.Add(new PlaytestAggregateSessionRow
                {
                    sessionId = packet.sessionId,
                    generatedAt = packet.generatedAt,
                    campaignStartedAt = packet.campaignStartedAt,
                    totalPlaySeconds = packet.totalPlaySeconds,
                    totalPlayTime = packet.totalPlayTime,
                    campaignMandateId = packet.campaignMandateId,
                    campaignMandateName = packet.campaignMandateName,
                    caseCount = packet.caseCount,
                    logCount = packet.logCount,
                    incidentCount = packet.incidentCount,
                    endingId = packet.endingId,
                    endingTitle = packet.endingTitle,
                    campaignScore = grade.score,
                    campaignGrade = grade.grade,
                    campaignBadge = grade.badge,
                    finalBudget = packet.finalBudget,
                    finalStability = packet.finalStability,
                    finalEquity = packet.finalEquity,
                    finalMissedRisk = packet.finalMissedRisk,
                    finalComplaints = packet.finalComplaints,
                    supportCount = packet.supportCount,
                    conditionalCount = packet.conditionalCount,
                    investigationCount = packet.investigationCount,
                    holdCount = packet.holdCount,
                    rejectCount = packet.rejectCount,
                    matchedRecommendedCount = packet.matchedRecommendedCount,
                    recommendedMatchRatePercent = packet.recommendedMatchRatePercent,
                    balanceRiskFocus = packet.balanceRiskFocus,
                    campaignChallengeId = packet.campaignChallengeId,
                    campaignChallengeTitle = packet.campaignChallengeTitle,
                    campaignChallengeObjective = packet.campaignChallengeObjective,
                    campaignChallengeProgress = packet.campaignChallengeProgress,
                    campaignChallengeSucceeded = packet.campaignChallengeSucceeded,
                    campaignChallengeScore = packet.campaignChallengeScore,
                    topDecisionRationaleId = packet.topDecisionRationaleId,
                    topDecisionRationaleName = packet.topDecisionRationaleName,
                    topDecisionRationaleCount = packet.topDecisionRationaleCount,
                    nextCampaignMandateId = packet.nextCampaignMandateId,
                    nextCampaignMandateName = packet.nextCampaignMandateName,
                    nextCampaignChallenge = NormalizeReviewTerms(packet.nextCampaignChallenge),
                    nextCampaignReason = NormalizeReviewTerms(packet.nextCampaignReason),
                    hasSurveyRatings = hasSurveyRatings,
                    difficultyRating = hasSurveyRatings ? survey.difficultyRating : 0,
                    decisionClarityRating = hasSurveyRatings ? survey.decisionClarityRating : 0,
                    resultFairnessRating = hasSurveyRatings ? survey.resultFairnessRating : 0,
                    uiReadabilityRating = hasSurveyRatings ? survey.uiReadabilityRating : 0,
                    priceValueRating = hasSurveyRatings ? survey.priceValueRating : 0,
                    replayRewardValueRating = replayRewardValueRating,
                    difficultyTooHigh = hasSurveyRatings && survey.difficultyTooHigh,
                    uiNeedsWork = hasSurveyRatings && survey.uiNeedsWork,
                    caseExplanationNeeded = hasSurveyRatings && survey.caseExplanationNeeded,
                    replayIntent = hasSurveyRatings && survey.replayIntent,
                    decisionAuditAppealRemedyCaseCount = appealRemedyCases.Count,
                    decisionAuditTopAppealCaseId = topAppealRemedyCase != null ? topAppealRemedyCase.caseId : "",
                    decisionAuditTopAppealArchiveFilter = topAppealRemedyCase != null ? topAppealRemedyCase.archiveFilter : "",
                    decisionAuditTopAppealBeforeAfterGraph = topAppealRemedyCase != null ? topAppealRemedyCase.beforeAfterGraph : "",
                    decisionAuditCoachingPattern = coaching != null ? coaching.pattern : "",
                    decisionAuditCoachingMismatchCount = coaching != null ? coaching.mismatchCount : 0,
                    decisionAuditCoachingUrgentDelayCount = coaching != null ? coaching.urgentDelayCount : 0,
                    decisionAuditCoachingHighCostSupportCount = coaching != null ? coaching.highCostSupportCount : 0,
                    decisionAuditCoachingRecommendedMandateId = coaching != null ? coaching.recommendedMandateId : "",
                    decisionAuditCoachingRecommendedMandateName = coaching != null ? coaching.recommendedMandateName : "",
                    decisionAuditCoachingExecutionRule = coaching != null ? NormalizeReviewTerms(coaching.executionRule) : "",
                    decisionAuditCoachingAppealQueueCount = coaching != null ? coaching.appealQueueCount : 0,
                    decisionAuditCoachingAppealCaseId = coaching != null ? coaching.appealCaseId : "",
                    decisionAuditCoachingVerificationQuestion = coaching != null ? NormalizeReviewTerms(coaching.verificationQuestion) : "",
                    appealRemedyCases = appealRemedyCases,
                    sessionDirectoryPath = string.IsNullOrEmpty(packet.sessionDirectoryPath) || ContainsLocalAbsolutePath(packet.sessionDirectoryPath)
                        ? fallbackSessionDirectory
                        : NormalizeShareablePath(packet.sessionDirectoryPath),
                    feedbackMarkdownPath = feedbackMarkdownPath,
                    analyticsDashboardPath = analyticsDashboardPath
                });
            }
            catch (Exception exception)
            {
                Debug.LogWarning("Failed to load playtest session summary. " + summaryPath + " " + exception.Message);
            }
        }

        return rows;
    }

    private static string NormalizeReviewTerms(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return "";
        }

        return text
            .Replace("판단 복기 코칭", "판단 복기")
            .Replace("결정 감사 코칭", "판단 복기")
            .Replace("다음 회차 코칭", "다음 회차 복기")
            .Replace("코칭 목표", "복기 목표")
            .Replace("코칭 패턴", "복기 패턴")
            .Replace("코칭 W-207", "복기 W-207");
    }

    private static List<PlaytestAggregateAppealRemedyCase> BuildPlaytestAggregateAppealRemedyCases(PlaytestPacketExport packet)
    {
        List<PlaytestAggregateAppealRemedyCase> cases = new();
        if (packet == null || packet.decisionAuditCases == null)
        {
            return cases;
        }

        for (int i = 0; i < packet.decisionAuditCases.Count; i++)
        {
            DecisionAuditPressureCaseExport pressureCase = packet.decisionAuditCases[i];
            if (!IsPlaytestAggregateAppealRemedyGraphCase(pressureCase))
            {
                continue;
            }

            string archiveFilter = string.IsNullOrWhiteSpace(pressureCase.archiveFilter)
                ? "보정 그래프"
                : pressureCase.archiveFilter;
            cases.Add(new PlaytestAggregateAppealRemedyCase
            {
                caseId = pressureCase.caseId,
                familyType = pressureCase.familyType,
                archiveFilter = archiveFilter,
                decision = pressureCase.decision,
                recommendedDecision = pressureCase.recommendedDecision,
                queuePriorityScore = pressureCase.queuePriorityScore,
                appealReviewScore = pressureCase.appealReviewScore,
                beforeAfterGraph = pressureCase.beforeAfterGraph,
                triageKey = PlaytestAggregateAppealRemedyTriageKey(archiveFilter, pressureCase.familyType),
                triageLabel = PlaytestAggregateAppealRemedyTriageLabel(archiveFilter, pressureCase.familyType)
            });
        }

        cases.Sort((left, right) => right.queuePriorityScore.CompareTo(left.queuePriorityScore));
        return cases;
    }

    private static bool IsPlaytestAggregateAppealRemedyGraphCase(DecisionAuditPressureCaseExport pressureCase)
    {
        if (pressureCase == null || string.IsNullOrWhiteSpace(pressureCase.beforeAfterGraph) || !pressureCase.beforeAfterGraph.Contains("보정 전/후"))
        {
            return false;
        }

        return pressureCase.appealReviewScore >= 35 ||
            !string.IsNullOrWhiteSpace(pressureCase.appealReviewStatus) ||
            !string.IsNullOrWhiteSpace(pressureCase.appealReviewRemedy) ||
            (!string.IsNullOrWhiteSpace(pressureCase.archiveFilter) && pressureCase.archiveFilter.Contains("이의제기"));
    }

    private static string PlaytestAggregateAppealRemedyTriageKey(string archiveFilter, string familyType)
    {
        string raw = !string.IsNullOrWhiteSpace(archiveFilter) ? archiveFilter : familyType;
        raw = string.IsNullOrWhiteSpace(raw) ? "appeal_remedy_graph" : raw.Trim().ToLowerInvariant();
        StringBuilder key = new();
        for (int i = 0; i < raw.Length; i++)
        {
            char character = raw[i];
            if (char.IsLetterOrDigit(character))
            {
                key.Append(character);
            }
            else if (character == ' ' || character == '-' || character == '_' || character == '/' || character == '\\')
            {
                if (key.Length == 0 || key[key.Length - 1] != '_')
                {
                    key.Append('_');
                }
            }
        }

        string result = key.ToString().Trim('_');
        return string.IsNullOrWhiteSpace(result) ? "appeal_remedy_graph" : result;
    }

    private static string PlaytestAggregateAppealRemedyTriageLabel(string archiveFilter, string familyType)
    {
        if (!string.IsNullOrWhiteSpace(archiveFilter))
        {
            return archiveFilter;
        }

        return string.IsNullOrWhiteSpace(familyType) ? "보정 그래프 사례" : familyType;
    }

    private static List<AppealRemedyGraphTriageItem> BuildAggregateAppealRemedyGraphTriage(List<PlaytestAggregateSessionRow> rows)
    {
        List<AppealRemedyGraphTriageItem> triage = new();
        if (rows == null)
        {
            return triage;
        }

        foreach (PlaytestAggregateSessionRow row in rows)
        {
            if (row == null || row.appealRemedyCases == null)
            {
                continue;
            }

            HashSet<string> sessionKeys = new();
            for (int i = 0; i < row.appealRemedyCases.Count; i++)
            {
                PlaytestAggregateAppealRemedyCase appealCase = row.appealRemedyCases[i];
                if (appealCase == null)
                {
                    continue;
                }

                AppealRemedyGraphTriageItem item = FindAppealRemedyGraphTriageItem(triage, appealCase.triageKey);
                if (item == null)
                {
                    item = new AppealRemedyGraphTriageItem
                    {
                        id = appealCase.triageKey,
                        label = appealCase.triageLabel,
                        ownerScreen = "사례 자료실 / 결정 감사 / 플레이테스트 패킷",
                        recommendation = "반복 등장 시 보정 목표 문구와 사례 자료실 비교표를 우선 점검"
                    };
                    triage.Add(item);
                }

                item.caseCount++;
                if (sessionKeys.Add(appealCase.triageKey))
                {
                    item.sessionCount++;
                }

                if (appealCase.queuePriorityScore >= item.highestQueuePriorityScore)
                {
                    item.highestQueuePriorityScore = appealCase.queuePriorityScore;
                    item.topSessionId = row.sessionId;
                    item.topCaseId = appealCase.caseId;
                    item.topFamilyType = appealCase.familyType;
                    item.topBeforeAfterGraph = appealCase.beforeAfterGraph;
                    item.topDecisionComparison = $"{appealCase.decision}/{appealCase.recommendedDecision}";
                }
            }
        }

        triage.Sort((left, right) =>
        {
            int countCompare = right.caseCount.CompareTo(left.caseCount);
            if (countCompare != 0)
            {
                return countCompare;
            }

            return right.highestQueuePriorityScore.CompareTo(left.highestQueuePriorityScore);
        });
        return triage;
    }

    private static AppealRemedyGraphTriageItem FindAppealRemedyGraphTriageItem(List<AppealRemedyGraphTriageItem> triage, string id)
    {
        for (int i = 0; i < triage.Count; i++)
        {
            if (triage[i].id == id)
            {
                return triage[i];
            }
        }

        return null;
    }

    private static PlaytestSurveyExport LoadPlaytestSurveyForAggregate(string summaryPath)
    {
        string sessionDirectory = Path.GetDirectoryName(summaryPath);
        if (string.IsNullOrEmpty(sessionDirectory))
        {
            return null;
        }

        string surveyPath = Path.Combine(sessionDirectory, "care_review_in_game_feedback.json");
        if (!File.Exists(surveyPath))
        {
            return null;
        }

        try
        {
            return JsonUtility.FromJson<PlaytestSurveyExport>(File.ReadAllText(surveyPath, Encoding.UTF8));
        }
        catch (Exception exception)
        {
            Debug.LogWarning("Failed to load playtest survey for aggregate. " + surveyPath + " " + exception.Message);
            return null;
        }
    }

