        builder.AppendLine($"평균 권장 판단 일치율: {aggregate.averageRecommendedMatchRatePercent:0.0}%");
        builder.AppendLine($"평균 최종 지표: 예산 {aggregate.averageFinalBudget:0.0}만원, 안정 {aggregate.averageFinalStability:0.0}, 형평 {aggregate.averageFinalEquity:0.0}, 누락 {aggregate.averageFinalMissedRisk:0.0}, 민원 {aggregate.averageFinalComplaints:0.0}");
        builder.AppendLine();
        builder.AppendLine("## 설문/가격 가치감");
        builder.AppendLine();
        if (aggregate.surveySessionCount > 0)
        {
            builder.AppendLine($"- 설문 회수 세션: {aggregate.surveySessionCount}/{aggregate.sessionCount}");
            builder.AppendLine($"- 평균 난이도 적절성: {aggregate.averageDifficultyRating:0.0}/5");
