        {
            builder.AppendLine($"- 체크 패널 기준: 성과 기록 / 캠페인 기록 / 상점 후보 / 다시 할 이유");
            builder.AppendLine($"- 성과 기록: 반복 보상/장기 기록 가치감 4점 이상 {aggregate.commercialChecklistReplayRewardPositiveCount}/{aggregate.commercialChecklistSurveyCount}세션 · 평균 {aggregate.averageReplayRewardValueRating:0.0}/5");
            builder.AppendLine($"- 캠페인 기록: 장기 추세와 다음 목표가 다시 플레이할 이유로 보였는지 재플레이 의향 {aggregate.commercialChecklistReplayIntentPositiveCount}/{aggregate.commercialChecklistSurveyCount}세션으로 확인");
            builder.AppendLine($"- 상점 후보: 10달러 가치감 4점 이상 {aggregate.commercialChecklistPriceValuePositiveCount}/{aggregate.commercialChecklistSurveyCount}세션 · 평균 {aggregate.averagePriceValueRating:0.0}/5");
            builder.AppendLine($"- 다시 할 이유: 재플레이 의향 {aggregate.replayIntentCount}/{aggregate.surveySessionCount}세션, 후속 보강 필요 {aggregate.commercialChecklistFollowUpCount}세션");
            builder.AppendLine("- 회수 판정 힌트: 낮은 반복 가치감, 낮은 10달러 가치감, UI 보강 필요, 재플레이 의향 없음이 있으면 `PLAYTEST_COMMERCIAL_TRIAGE_ACTIONS.csv`의 반복 보상/장기 기록 가치감 행과 함께 본다.");
        }
        else
        {
            builder.AppendLine("- 상용화 보강 체크 응답은 아직 없다. 최종 리포트의 `상용화 보강 체크` 패널을 보고 설문을 저장한 세션을 회수해야 한다.");
        }
        builder.AppendLine();
        builder.AppendLine("## 운영 기준 분포");
        AppendAggregateCountMarkdown(builder, aggregate.mandateCounts);
        builder.AppendLine();
        builder.AppendLine("## 엔딩 분포");
        AppendAggregateCountMarkdown(builder, aggregate.endingCounts);
        builder.AppendLine();
        builder.AppendLine("## 우선 확인 지점");
        AppendAggregateCountMarkdown(builder, aggregate.focusCounts);
        builder.AppendLine();
        builder.AppendLine("## 이의제기/보정 그래프 유형 분류");
        builder.AppendLine();
        if (aggregate.appealRemedyGraphTriage != null && aggregate.appealRemedyGraphTriage.Count > 0)
        {
            builder.AppendLine($"총 보정 그래프 후보: {aggregate.appealRemedyGraphCaseCount}건");
            foreach (AppealRemedyGraphTriageItem item in aggregate.appealRemedyGraphTriage)
            {
                builder.AppendLine($"- {item.label}: {item.caseCount}건/{item.sessionCount}세션 · 대표 {item.topCaseId} · 우선 {item.highestQueuePriorityScore} · {item.topBeforeAfterGraph} · 담당 {item.ownerScreen} · {item.recommendation}");
            }
        }
        else
        {
            builder.AppendLine("- 보정 전/후 그래프가 있는 이의제기 후보가 아직 없다.");
        }
        builder.AppendLine();
        builder.AppendLine("## 판단 복기 패턴 분포");
        builder.AppendLine();
        if (aggregate.decisionAuditCoachingSessionCount > 0)
        {
            builder.AppendLine($"- 복기 생성 세션: {aggregate.decisionAuditCoachingSessionCount}/{aggregate.sessionCount}");
            builder.AppendLine($"- 누적 불일치: {aggregate.decisionAuditCoachingMismatchCount}건 · 고위험 지연 {aggregate.decisionAuditCoachingUrgentDelayCount}건 · 고비용 지원 {aggregate.decisionAuditCoachingHighCostSupportCount}건");
            builder.AppendLine($"- 검증 사례 연결: {aggregate.decisionAuditCoachingAppealQueueSessionCount}/{aggregate.decisionAuditCoachingSessionCount}세션");
            builder.AppendLine("- 패턴 분포:");
            AppendAggregateCountMarkdown(builder, aggregate.decisionAuditCoachingPatternCounts);
            builder.AppendLine("- 추천 운영 분포:");
            AppendAggregateCountMarkdown(builder, aggregate.decisionAuditCoachingMandateCounts);
        }
        else
        {
            builder.AppendLine("- 판단 복기를 포함한 세션이 아직 없다.");
        }
        builder.AppendLine();
        builder.AppendLine("## 세션 목록");
        builder.AppendLine();
        foreach (PlaytestAggregateSessionRow row in aggregate.sessions)
        {
            string nextCampaign = string.IsNullOrWhiteSpace(row.nextCampaignChallenge)
                ? "다음 목표 미기록"
                : $"다음 목표 {row.nextCampaignMandateName} · {row.nextCampaignChallenge}";
            string rationale = string.IsNullOrWhiteSpace(row.topDecisionRationaleName)
                ? "판단 근거 미기록"
                : $"최다 근거 {row.topDecisionRationaleName} {row.topDecisionRationaleCount}건";
            string challenge = string.IsNullOrWhiteSpace(row.campaignChallengeTitle)
                ? "챌린지 미기록"
                : $"챌린지 {row.campaignChallengeTitle} {(row.campaignChallengeSucceeded ? "성공" : "미달")}({row.campaignChallengeScore}점)";
            string survey = row.hasSurveyRatings
                ? $"설문 가치감 {row.priceValueRating}/5 · 반복 가치 {row.replayRewardValueRating}/5 · 재플레이 {BoolLabel(row.replayIntent)}"
                : "설문 미회수";
            string coaching = string.IsNullOrWhiteSpace(row.decisionAuditCoachingPattern)
                ? "복기 미기록"
                : $"복기 {row.decisionAuditCoachingPattern} · 추천 운영 {row.decisionAuditCoachingRecommendedMandateName} · 검증 사례 {(string.IsNullOrWhiteSpace(row.decisionAuditCoachingAppealCaseId) ? "없음" : row.decisionAuditCoachingAppealCaseId)}";
            builder.AppendLine($"- {row.sessionId}: {row.campaignMandateName}, {row.endingTitle}, 등급 {row.campaignGrade}({row.campaignScore}점), {challenge}, {row.logCount}/{row.caseCount}건, 권장 일치 {row.recommendedMatchRatePercent:0.0}%, {row.balanceRiskFocus}, {rationale}, {nextCampaign}, {survey}, {coaching}");
        }

        builder.AppendLine();
        builder.AppendLine("## 회수 기준");
        builder.AppendLine();
        builder.AppendLine("실제 테스터 회차는 로그 폴더의 `playtest_sessions/<sessionId>` 폴더 단위로 회수한다. 루트의 고정 파일명은 최신 사본이므로 여러 명의 테스트를 모을 때 원본으로 쓰지 않는다.");
        return builder.ToString();
    }

    private static void AppendAggregateCountMarkdown(StringBuilder builder, List<PlaytestAggregateCount> counts)
    {
        if (counts == null || counts.Count == 0)
        {
            builder.AppendLine("- 없음");
            return;
        }

        for (int i = 0; i < counts.Count; i++)
        {
            builder.AppendLine($"- {counts[i].label}: {counts[i].count}");
        }
    }

    private static void IncrementAggregateCount(List<PlaytestAggregateCount> counts, string id, string label)
    {
        id = string.IsNullOrEmpty(id) ? "unknown" : id;
        label = string.IsNullOrEmpty(label) ? id : label;
        for (int i = 0; i < counts.Count; i++)
        {
            if (counts[i].id == id)
            {
                counts[i].count++;
                return;
            }
        }

        counts.Add(new PlaytestAggregateCount { id = id, label = label, count = 1 });
    }

    private static string DecisionRationaleSummaryLine(List<DecisionRationaleSummaryExport> summaries)
    {
        if (summaries == null || summaries.Count == 0)
        {
            return "기록 없음";
        }

        StringBuilder builder = new();
        for (int i = 0; i < summaries.Count; i++)
        {
            if (i > 0)
            {
                builder.Append(" · ");
            }

            string label = string.IsNullOrWhiteSpace(summaries[i].shortLabel) ? summaries[i].label : summaries[i].shortLabel;
            builder.Append(label).Append(' ').Append(summaries[i].count).Append("건");
        }

        return builder.ToString();
    }

    private PlaytestPacketExport BuildPlaytestPacketExport(EndingOutcome ending, string playLogJsonPath, string playLogCsvPath, string incidentCsvPath)
    {
        int supportCount = 0;
        int conditionalCount = 0;
        int investigationCount = 0;
        int holdCount = 0;
        int rejectCount = 0;
        int matchedCount = 0;
        int urgentMismatchCount = 0;
        int urgentDelayCount = 0;
        int highCostSupportCount = 0;
        int mismatchCount = 0;

        foreach (DecisionLog log in logs)
        {
            if (log.decision == "승인")
            {
                supportCount++;
            }
            else if (log.decision == "조건부 승인")
            {
                conditionalCount++;
            }
            else if (log.decision == "추가조사")
            {
                investigationCount++;
            }
            else if (log.decision == "보류")
            {
                holdCount++;
            }
            else if (log.decision == "거절")
            {
                rejectCount++;
            }

            if (log.matchedRecommended)
            {
                matchedCount++;
            }
            else
            {
                mismatchCount++;
            }

            if (!log.matchedRecommended && log.urgency >= 80)
            {
                urgentMismatchCount++;
            }

            if (IsDelayDecision(log.decision) && log.urgency >= 78)
            {
                urgentDelayCount++;
            }

            if ((log.decision == "승인" || log.decision == "조건부 승인") && log.spentBudget >= 140)
            {
                highCostSupportCount++;
            }
        }

        float matchRate = logs.Count > 0 ? matchedCount * 100f / logs.Count : 0f;
        CampaignGradeResult grade = BuildCampaignGrade(matchedCount);
        string riskFocus =
            budget < -1000 ? "예산 압박" :
            missedRisk >= 45 ? "누락 위험" :
            complaints >= 85 ? "민원 압박" :
            urgentMismatchCount >= 4 ? "고위험 불일치" :
            "균형 확인";
        NextCampaignObjective nextObjective = BuildNextCampaignObjective(
            matchedCount,
            supportCount + conditionalCount,
            holdCount,
            rejectCount);
        CampaignChallengeResult challenge = BuildCampaignChallengeResult();
        List<DecisionRationaleSummaryExport> rationaleSummaries = BuildDecisionRationaleSummaries();
        DecisionRationaleSummaryExport topRationale = TopDecisionRationaleSummary(rationaleSummaries);

        string sessionId = EnsureSessionId();
        return new PlaytestPacketExport
        {
            generatedAt = DateTime.Now.ToString("s"),
            sessionId = sessionId,
            buildVersion = BuildVersionLabel,
            campaignStartedAt = campaignStartedAt,
            totalPlaySeconds = CurrentCampaignElapsedSeconds(),
            totalPlayTime = FormatDuration(CurrentCampaignElapsedSeconds()),
            campaignMandateId = CampaignMandateId(campaignMandate),
            campaignMandateName = CampaignMandateLabel(campaignMandate),
            caseCount = cases.Count,
            logCount = logs.Count,
            incidentCount = incidentLogs.Count,
            endingId = ending.id,
            endingTitle = ending.title,
            campaignScore = grade.score,
            campaignGrade = grade.grade,
            campaignBadge = grade.badge,
            campaignGradeReason = grade.reason,
            finalBudget = budget,
            finalStability = stability,
            finalEquity = equity,
            finalMissedRisk = missedRisk,
            finalComplaints = complaints,
            supportCount = supportCount,
            conditionalCount = conditionalCount,
            investigationCount = investigationCount,
            holdCount = holdCount,
            rejectCount = rejectCount,
            matchedRecommendedCount = matchedCount,
            recommendedMatchRatePercent = matchRate,
            urgentMismatchCount = urgentMismatchCount,
            highCostSupportCount = highCostSupportCount,
            averageDecisionSeconds = -1,
            balanceRiskFocus = riskFocus,
            campaignChallengeId = challenge.id,
            campaignChallengeTitle = challenge.title,
            campaignChallengeObjective = challenge.objective,
            campaignChallengeProgress = challenge.progress,
            campaignChallengeSucceeded = challenge.succeeded,
            campaignChallengeScore = challenge.score,
            nextCampaignMandateId = CampaignMandateId(nextObjective.mandate),
            nextCampaignMandateName = CampaignMandateLabel(nextObjective.mandate),
            nextCampaignChallenge = nextObjective.challenge,
            nextCampaignReason = nextObjective.reason,
            topDecisionRationaleId = topRationale.id,
            topDecisionRationaleName = topRationale.label,
            topDecisionRationaleCount = topRationale.count,
            decisionRationaleSummaries = rationaleSummaries,
            decisionAuditDays = BuildDecisionAuditDayExports(),
            decisionAuditCases = BuildDecisionAuditPressureCaseExports(5),
            decisionAuditCoaching = BuildDecisionAuditCoachingExport(urgentDelayCount, highCostSupportCount, mismatchCount),
            playLogJsonPath = SessionRelativePath(sessionId, playLogJsonPath),
            playLogCsvPath = SessionRelativePath(sessionId, playLogCsvPath),
            incidentCsvPath = SessionRelativePath(sessionId, incidentCsvPath)
        };
    }

    private List<DecisionAuditDayExport> BuildDecisionAuditDayExports()
    {
        List<DecisionAuditDayExport> exports = new();
        foreach (DecisionDayAuditSummary summary in BuildDecisionDayAuditSummaries())
        {
            exports.Add(new DecisionAuditDayExport
            {
                day = summary.day,
                count = summary.count,
                supportCount = summary.supportCount,
                investigationCount = summary.investigationCount,
                delayCount = summary.delayCount,
                spentBudget = summary.spentBudget,
                riskDelta = summary.riskDelta,
                matchedCount = summary.matchedCount,
                matchRatePercent = summary.count > 0 ? summary.matchedCount * 100f / summary.count : 0f
            });
        }

        return exports;
    }

    private List<DecisionAuditPressureCaseExport> BuildDecisionAuditPressureCaseExports(int limit)
    {
        List<DecisionLog> rankedLogs = new(logs);
        rankedLogs.Sort((left, right) => DecisionAuditQueuePriorityScore(right).CompareTo(DecisionAuditQueuePriorityScore(left)));

        List<DecisionAuditPressureCaseExport> exports = new();
        foreach (DecisionLog log in rankedLogs)
        {
            int riskDelta = Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore) + Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
            int riskBefore = log.missedRiskBefore + log.complaintsBefore;
            int riskAfter = log.missedRiskAfter + log.complaintsAfter;
            exports.Add(new DecisionAuditPressureCaseExport
            {
                caseId = log.caseId,
                familyType = log.familyType,
                decision = log.decision,
                recommendedDecision = log.recommendedDecision,
                score = DecisionAuditPressureScore(log),
                queuePriorityScore = DecisionAuditQueuePriorityScore(log),
                flags = DecisionAuditFlags(log),
                reviewReason = DecisionReviewReason(log),
                nextReviewPrompt = DecisionReviewNextStep(log),
                archiveFilter = DecisionReviewArchiveFilter(log),
                appealReviewScore = AppealReviewScore(log),
                appealReviewStatus = AppealReviewStatus(log),
                appealReviewRemedy = AppealReviewRemedy(log),
                beforeAfterGraph = DecisionAuditBeforeAfterGraphText(log),
                budgetBefore = log.budgetBefore,
                budgetAfter = log.budgetAfter,
                riskBefore = riskBefore,
                riskAfter = riskAfter,
                stabilityBefore = log.stabilityBefore,
                stabilityAfter = log.stabilityAfter,
                urgency = log.urgency,
                spentBudget = log.spentBudget,
                riskDelta = riskDelta
            });

            if (exports.Count >= limit)
            {
                break;
            }
        }

        return exports;
    }

