    private static void AppendDecisionReviewQueueMarkdown(StringBuilder builder, PlaytestPacketExport packet)
    {
        builder.AppendLine("## 자동 재검토 큐");
        builder.AppendLine();
        builder.AppendLine("아래 사례는 테스터에게 먼저 이유를 물어볼 후보입니다. 게임 안 사례 자료실의 필터 큐와 연결해 다시 확인합니다.");
        builder.AppendLine();
        if (packet.decisionAuditCases == null || packet.decisionAuditCases.Count == 0)
        {
            builder.AppendLine("- 특정 재검토 사례가 없습니다.");
            return;
        }

        int index = 1;
        foreach (DecisionAuditPressureCaseExport pressureCase in packet.decisionAuditCases)
        {
            builder.AppendLine($"{index}. `{pressureCase.caseId}` · 자료실 필터 `{pressureCase.archiveFilter}` · {pressureCase.decision}/{pressureCase.recommendedDecision}");
            builder.AppendLine($"   - 재검토 이유: {pressureCase.reviewReason}");
            builder.AppendLine($"   - 다음 회차 실험: {pressureCase.nextReviewPrompt}");
            builder.AppendLine($"   - 보정 전/후 그래프: {pressureCase.beforeAfterGraph}");
            index++;
        }
    }

    private static void AppendDecisionAuditCoachingMarkdown(StringBuilder builder, PlaytestPacketExport packet)
    {
        builder.AppendLine("## 판단 복기 다음 회차");
        builder.AppendLine();
        if (packet.decisionAuditCoaching == null)
        {
            builder.AppendLine("- 다음 회차 복기를 만들 기록이 없습니다.");
            return;
        }

        DecisionAuditCoachingExport coaching = packet.decisionAuditCoaching;
        builder.AppendLine($"- 핵심 패턴: {coaching.pattern} · 불일치 {coaching.mismatchCount}건 · 고위험 지연 {coaching.urgentDelayCount}건 · 고비용 지원 {coaching.highCostSupportCount}건");
        builder.AppendLine($"- 추천 운영: {coaching.recommendedMandateName} ({coaching.recommendedMandateId})");
        builder.AppendLine($"- 실행 규칙: {coaching.executionRule}");
        if (coaching.appealQueueCount > 0)
        {
            builder.AppendLine($"- 보정 큐: {coaching.appealQueueCount}건 · {coaching.appealCaseId} · {coaching.appealStatus} {coaching.appealScore}점");
        }
        else
        {
            builder.AppendLine("- 보정 큐: 현재 고점 사례 없음");
        }
        builder.AppendLine($"- 검증 질문: {coaching.verificationQuestion}");
    }

