        html.AppendLine("</section>");
        html.AppendLine("</main></body></html>");
        return html.ToString();
    }

    private static void AppendMetricCard(StringBuilder html, string label, string value, string note)
    {
        html.AppendLine("<div class=\"metric\">" +
            $"<span>{HtmlEscape(label)}</span><strong>{HtmlEscape(value)}</strong><span class=\"muted\">{HtmlEscape(note)}</span>" +
            "</div>");
    }

    private static void AppendBar(StringBuilder html, string label, int value, int total, string colorClass)
    {
        float ratio = total > 0 ? Mathf.Clamp01(value / (float)total) : 0f;
        html.AppendLine($"<p>{HtmlEscape(label)} · {value}/{Mathf.Max(1, total)}</p>");
        html.AppendLine($"<div class=\"bar\"><div class=\"fill {HtmlEscape(colorClass)}\" style=\"width:{ratio * 100f:0.#}%\"></div></div>");
    }

