    private void RunAgentSimulation()
    {
        PlayBgm(PolicyBgmKey);
        UnlockAchievement("agent_lab");
        reportDashboardRoot.gameObject.SetActive(false);
        reportTextBoxObject.SetActive(false);
        if (decisionAuditRoot != null)
        {
            decisionAuditRoot.gameObject.SetActive(false);
        }
#if CARE_REVIEW_QA_TOOLS
        if (playtestSurveyRoot != null)
        {
            playtestSurveyRoot.gameObject.SetActive(false);
        }
#endif
        if (agentDashboardRoot != null)
        {
            agentDashboardRoot.gameObject.SetActive(true);
        }
        PlaySfx(analysisClip, 0.85f);

        List<AgentPersona> personas = BuildAgentPersonas();
        Dictionary<string, string> playerDecisionsByCase = BuildPlayerDecisionMap();
        List<AgentDecisionLog> agentLogs = new();
        List<AgentRunSummary> runSummaries = new();
        StringBuilder summary = new();
        summary.AppendLine("판단 비교");
        summary.AppendLine();
        summary.AppendLine($"운영 기준: {CampaignMandateLabel(campaignMandate)} · {CampaignMandateBrief(campaignMandate)}");
        summary.AppendLine($"현재 {cases.Count}개 사례를 서로 다른 판단 성향으로 다시 비교한 결과입니다.");
        summary.AppendLine("내 판단이 어떤 기준과 가까웠는지 보고, 다음 회차의 운영 기준을 고릅니다.");
        summary.AppendLine();

        foreach (AgentPersona persona in personas)
        {
            int simulatedBudget = StartingBudgetForMandate(campaignMandate);
            int supportCount = 0;
            int investigateCount = 0;
            int holdOrRejectCount = 0;
            int matchedCount = 0;
            int playerComparableCount = 0;
            int playerMatchedCount = 0;
            int followUpBudgetDelta = 0;
            int followUpComplaintsDelta = 0;
            int followUpMissedRiskDelta = 0;

            foreach (CareCase careCase in cases)
            {
                int budgetBefore = simulatedBudget;
                DecisionKind decision = ChooseAgentDecision(persona, careCase, simulatedBudget, StartingBudgetForMandate(campaignMandate));
                string decisionLabel = DecisionLabel(decision);
                int cost = GetDecisionCost(decision, careCase);
                simulatedBudget -= cost;

                bool matched = decisionLabel == careCase.recommendedDecision ||
                    (careCase.recommendedDecision == "조건부 승인" && decisionLabel == "승인");
                Consequence consequence = AdjustConsequenceForMandate(campaignMandate, BuildConsequence(careCase, decisionLabel, matched, simulatedBudget));
                followUpBudgetDelta += consequence.budgetDelta;
                followUpComplaintsDelta += consequence.complaintsDelta;
                followUpMissedRiskDelta += consequence.missedRiskDelta;

                if (decision == DecisionKind.Approve || decision == DecisionKind.Conditional)
                {
                    supportCount++;
                }
                else if (decision == DecisionKind.Investigate)
                {
                    investigateCount++;
                }
                else
                {
                    holdOrRejectCount++;
                }

                if (matched)
                {
                    matchedCount++;
                }

                bool matchedPlayerDecision = false;
                if (playerDecisionsByCase.TryGetValue(careCase.id, out string playerDecision))
                {
                    playerComparableCount++;
                    matchedPlayerDecision = string.Equals(playerDecision, decisionLabel, StringComparison.OrdinalIgnoreCase);
                    if (matchedPlayerDecision)
                    {
                        playerMatchedCount++;
                    }
                }

                string decisionReason = BuildAgentDecisionReason(persona, careCase, decisionLabel, budgetBefore, simulatedBudget, StartingBudgetForMandate(campaignMandate));
                agentLogs.Add(new AgentDecisionLog(
                    persona.id,
                    persona.name,
                    careCase.id,
                    careCase.type,
                    careCase.urgency,
                    careCase.documentStrength,
                    careCase.equityNeed,
                    budgetBefore,
                    simulatedBudget,
                    decisionLabel,
                    careCase.recommendedDecision,
                    matched,
                    matchedPlayerDecision,
                    decisionReason,
                    consequence.type,
                    consequence.title,
                    consequence.budgetDelta,
                    consequence.missedRiskDelta,
                    consequence.complaintsDelta));
            }

            summary.AppendLine($"{persona.name}: 지원 {supportCount}건, 추가조사 {investigateCount}건, 보류/거절 {holdOrRejectCount}건, 권장 일치 {matchedCount}/{cases.Count}, 잔여 예산 {simulatedBudget}만원, 후폭풍 예산 {SignedNumber(followUpBudgetDelta)}만원, 누락 {SignedNumber(followUpMissedRiskDelta)}, 민원 {SignedNumber(followUpComplaintsDelta)}");
            runSummaries.Add(new AgentRunSummary(
                persona.id,
                persona.name,
                supportCount,
                investigateCount,
                holdOrRejectCount,
                matchedCount,
                playerMatchedCount,
                playerComparableCount,
                simulatedBudget,
                followUpBudgetDelta,
                followUpMissedRiskDelta,
                followUpComplaintsDelta));
        }

        latestAgentDecisionLogs.Clear();
        latestAgentDecisionLogs.AddRange(agentLogs);

        string disagreementBrief = BuildAgentDisagreementBrief(agentLogs, 5);
        latestAgentDisagreementCaseId = TopAgentDisagreementCaseId(agentLogs);
        string playerSimilarityBrief = BuildAgentPlayerSimilarityBrief(runSummaries);
        RegisterAgentCareerProfile(runSummaries);
        UpdateLatestAgentReplayObjective(runSummaries);

        summary.AppendLine();
        summary.AppendLine(playerSimilarityBrief);
        summary.AppendLine();
        summary.AppendLine(disagreementBrief);
        summary.AppendLine();
        summary.AppendLine("비교 결과가 갱신되었습니다. 사례 자료실에서 대표 비교 사례를 다시 열 수 있습니다.");
        reportText.text = summary.ToString();
        UpdateAgentDashboard(runSummaries, agentLogs);
    }

    private void UpdateAgentDashboard(List<AgentRunSummary> summaries, List<AgentDecisionLog> agentLogs)
    {
        if (agentDashboardRoot == null || agentDashboardSummaryText == null || agentRowTexts == null)
        {
            reportTextBoxObject.SetActive(true);
            return;
        }

        agentDashboardSummaryText.text =
            "판단 비교\n" +
            $"운영 기준: {CampaignMandateLabel(campaignMandate)} · {CampaignMandateBrief(campaignMandate)}\n" +
            $"{cases.Count}개 사례를 {summaries.Count}개 기준 성향과 비교했습니다. 막대는 전체 사례 대비 지원/추가조사/권장 일치 비율입니다.";

        int caseCount = Mathf.Max(1, cases.Count);
        for (int i = 0; i < agentRowTexts.Length; i++)
        {
            if (i >= summaries.Count)
            {
                agentRowTexts[i].text = "";
                SetAgentBar(agentSupportFills[i], AgentDashboardSupportX(i), AgentDashboardRowY(i), 0f);
                SetAgentBar(agentInvestigationFills[i], AgentDashboardInvestigationX(i), AgentDashboardRowY(i), 0f);
                SetAgentBar(agentMatchFills[i], AgentDashboardMatchX(i), AgentDashboardRowY(i), 0f);
                continue;
            }

            AgentRunSummary run = summaries[i];
            agentRowTexts[i].text =
                $"{run.personaName}\n" +
                $"내 판단 {run.playerMatchedCount}/{Mathf.Max(1, run.playerComparableCount)} · 잔여 {run.finalBudget}만";

            float y = AgentDashboardRowY(i);
            SetAgentBar(agentSupportFills[i], AgentDashboardSupportX(i), y, run.supportCount / (float)caseCount);
            SetAgentBar(agentInvestigationFills[i], AgentDashboardInvestigationX(i), y, run.investigateCount / (float)caseCount);
            SetAgentBar(agentMatchFills[i], AgentDashboardMatchX(i), y, run.matchedCount / (float)caseCount);
        }

        if (agentDashboardDisagreementText != null)
        {
            agentDashboardDisagreementText.text = BuildAgentPlayerSimilarityBrief(summaries) + "\n" + BuildAgentDisagreementBrief(agentLogs, 2);
        }

        if (agentDashboardPathText != null)
        {
            string profileLine = TryGetClosestAgentSummary(summaries, out AgentRunSummary closest) && closest.playerComparableCount > 0
                ? $"가까운 기준: {closest.personaName} {closest.playerMatchedCount}/{closest.playerComparableCount}"
                : "가까운 기준: 심사 기록 부족";
            string objectiveLine = latestAgentReplayObjectiveReady
                ? $"다음 회차 추천: {CampaignMandateLabel(latestAgentReplayObjective.mandate)} · {Shorten(latestAgentReplayObjective.challenge, 32)}"
                : "다음 회차 추천: 심사 기록 부족";
            agentDashboardPathText.text =
                $"{profileLine}\n" +
                objectiveLine;
        }
    }

    private void UpdateLatestAgentReplayObjective(List<AgentRunSummary> summaries)
    {
        latestAgentReplayObjectiveReady = false;
        latestAgentReplayPersonaName = "";
        if (!TryGetClosestAgentSummary(summaries, out AgentRunSummary closest) || closest.playerComparableCount <= 0)
        {
            return;
        }

        latestAgentReplayObjective = BuildAgentReplayObjective(closest);
        latestAgentReplayPersonaName = closest.personaName;
        latestAgentReplayObjectiveReady = true;
    }

    private static NextCampaignObjective BuildAgentReplayObjective(AgentRunSummary closest)
    {
        float caseCount = Mathf.Max(1, closest.supportCount + closest.investigateCount + closest.holdOrRejectCount);
        float supportRate = closest.supportCount / caseCount;
        float investigationRate = closest.investigateCount / caseCount;
        float delayRate = closest.holdOrRejectCount / caseCount;
        float matchRate = closest.playerMatchedCount * 100f / Mathf.Max(1, closest.playerComparableCount);

        if (delayRate >= supportRate && delayRate >= investigationRate)
        {
            return new NextCampaignObjective(
                CampaignMandate.SupportExpanded,
                "성향 반전: 고위험 지연 3건 이하, 조건부/승인 판단을 의식적으로 늘리기",
                $"{closest.personaName}과 {matchRate:0}% 일치해 지연 성향이 강합니다. 다음 회차는 지원 확대 기준으로 고위험 지연을 줄입니다.");
        }

        if (supportRate >= delayRate && supportRate >= investigationRate)
        {
            return new NextCampaignObjective(
                CampaignMandate.AusterityAudit,
                "성향 반전: 고비용 즉시 승인 4건 이하, 조건부와 추가조사로 비용 설명 확보",
                $"{closest.personaName}과 {matchRate:0}% 일치해 지원 성향이 강합니다. 다음 회차는 긴축 감사 기준으로 고비용 승인을 검증합니다.");
        }

        return new NextCampaignObjective(
            CampaignMandate.Standard,
            "성향 반전: 추가조사 5건 이하, 조사 메모 해금 뒤 조건부 승인까지 연결",
            $"{closest.personaName}과 {matchRate:0}% 일치해 조사 성향이 강합니다. 다음 회차는 균형 심사 기준으로 조사 후 결정을 빠르게 닫습니다.");
    }

    private Dictionary<string, string> BuildPlayerDecisionMap()
    {
        Dictionary<string, string> decisionsByCase = new(StringComparer.OrdinalIgnoreCase);
        for (int i = 0; i < logs.Count; i++)
        {
            DecisionLog log = logs[i];
            if (log == null ||
                string.IsNullOrWhiteSpace(log.caseId) ||
                string.IsNullOrWhiteSpace(log.decision))
            {
                continue;
            }

            decisionsByCase[log.caseId] = log.decision;
        }

        return decisionsByCase;
    }

    private static string BuildAgentPlayerSimilarityBrief(List<AgentRunSummary> summaries)
    {
        if (summaries == null || summaries.Count == 0)
        {
            return "내 판단과 가까운 기준\n비교할 기준 성향이 없습니다.";
        }

        int comparableCount = 0;
        for (int i = 0; i < summaries.Count; i++)
        {
            comparableCount = Mathf.Max(comparableCount, summaries[i].playerComparableCount);
        }

        if (comparableCount <= 0)
        {
            return "내 판단과 가까운 기준\n아직 비교할 심사 기록이 부족합니다.";
        }

        List<AgentRunSummary> sorted = new(summaries);
        sorted.Sort((left, right) =>
        {
            int compare = right.playerMatchedCount.CompareTo(left.playerMatchedCount);
            if (compare != 0)
            {
                return compare;
            }

            compare = right.matchedCount.CompareTo(left.matchedCount);
            if (compare != 0)
            {
                return compare;
            }

            return string.Compare(left.personaName, right.personaName, StringComparison.Ordinal);
        });

        StringBuilder builder = new();
        builder.Append("내 판단과 가까운 기준: ");
        int count = Mathf.Min(3, sorted.Count);
        for (int i = 0; i < count; i++)
        {
            AgentRunSummary summary = sorted[i];
            if (i > 0)
            {
                builder.Append(" / ");
            }

            float rate = summary.playerComparableCount > 0 ? summary.playerMatchedCount * 100f / summary.playerComparableCount : 0f;
            builder.Append(summary.personaName);
            builder.Append(" ");
            builder.Append(summary.playerMatchedCount);
            builder.Append("/");
            builder.Append(summary.playerComparableCount);
            builder.Append(" ");
            builder.Append(rate.ToString("0"));
            builder.Append("%");
        }

        return builder.ToString();
    }

    private static string BuildAgentDecisionReason(AgentPersona persona, CareCase careCase, string decisionLabel, int budgetBefore, int budgetAfter, int startingBudget)
    {
        if (persona == null || careCase == null)
        {
            return "판단 기준 정보가 부족해 사유를 생성하지 못했습니다.";
        }

        string mainSignal = DominantAgentSignal(persona, careCase, budgetBefore, startingBudget);
        string budgetState = budgetAfter < 0
            ? "초과 위험"
            : budgetBefore < careCase.cost
                ? "즉시 집행 부족"
                : "집행 가능";
        string documentSignal = careCase.documentStrength < 50
            ? "서류 취약"
            : careCase.documentStrength >= 75
                ? "서류 양호"
                : "서류 보통";

        return decisionLabel switch
        {
            "승인" => $"{persona.name}은 {mainSignal}을 가장 크게 보고 예산 상태({budgetState})에서도 즉시 지원 이익이 크다고 판단했습니다.",
            "조건부 승인" => $"{persona.name}은 {mainSignal}을 인정하되 서류 상태({documentSignal})에 조건을 붙여 지원과 통제를 함께 선택했습니다.",
            "추가조사" => $"{persona.name}은 서류 상태({documentSignal})와 {mainSignal} 사이의 충돌을 확인해 현장 확인 후 판단하는 쪽을 골랐습니다.",
            "보류" => $"{persona.name}은 예산 상태({budgetState})와 서류 상태({documentSignal}) 때문에 지금 결정하면 후폭풍이 크다고 봤습니다.",
            "거절" => $"{persona.name}은 예산 상태({budgetState})에서 지원 근거보다 운영 부담이 크다고 판단했습니다.",
            _ => $"{persona.name}은 {mainSignal}, 서류 상태({documentSignal}), 예산 상태({budgetState})를 종합해 {decisionLabel}을 선택했습니다."
        };
    }

    private static string DominantAgentSignal(AgentPersona persona, CareCase careCase, int budgetBefore, int startingBudget)
    {
        float urgencyScore = careCase.urgency * persona.urgencyWeight;
        float equityScore = careCase.equityNeed * persona.equityWeight;
        float documentScore = (100 - careCase.documentStrength) * persona.documentDoubtWeight;
        float budgetPressure = Mathf.Clamp01((startingBudget - budgetBefore) / Mathf.Max(1f, startingBudget));
        float budgetScore = ((careCase.cost / 10f) + budgetPressure * 45f) * persona.budgetWeight;

        if (urgencyScore >= equityScore && urgencyScore >= documentScore && urgencyScore >= budgetScore)
        {
            return "긴급 위험";
        }

        if (equityScore >= urgencyScore && equityScore >= documentScore && equityScore >= budgetScore)
        {
            return "형평성 필요";
        }

        if (documentScore >= urgencyScore && documentScore >= equityScore && documentScore >= budgetScore)
        {
            return "증빙 불확실성";
        }

        return "예산 압박";
    }

    private static string BuildAgentDisagreementBrief(List<AgentDecisionLog> agentLogs, int maxRows)
    {
        List<AgentDisagreementSummary> sorted = BuildAgentDisagreementSummaries(agentLogs);
        if (sorted.Count == 0)
        {
            return "비교 사례 큐\n비교할 판단 기록이 아직 없습니다.";
        }

        StringBuilder builder = new();
        builder.AppendLine("비교 사례 큐");
        int rows = Mathf.Min(Mathf.Max(1, maxRows), sorted.Count);
        for (int i = 0; i < rows; i++)
        {
            AgentDisagreementSummary summary = sorted[i];
            builder.AppendLine($"{summary.caseId} {summary.familyType} · 분기 {summary.DecisionVariety} · 불일치 {summary.mismatchCount}/{summary.totalCount} · {BuildDecisionCountBrief(summary.decisionCounts)}");
        }

        return builder.ToString().TrimEnd();
    }

    private static string TopAgentDisagreementCaseId(List<AgentDecisionLog> agentLogs)
    {
        List<AgentDisagreementSummary> sorted = BuildAgentDisagreementSummaries(agentLogs);
        return sorted.Count > 0 ? sorted[0].caseId : "";
    }

    private static List<AgentDisagreementSummary> BuildAgentDisagreementSummaries(List<AgentDecisionLog> agentLogs)
    {
        List<AgentDisagreementSummary> sorted = new();
        if (agentLogs == null || agentLogs.Count == 0)
        {
            return sorted;
        }

        Dictionary<string, AgentDisagreementSummary> summaries = new(StringComparer.OrdinalIgnoreCase);
        for (int i = 0; i < agentLogs.Count; i++)
        {
            AgentDecisionLog log = agentLogs[i];
            if (string.IsNullOrWhiteSpace(log.caseId))
            {
                continue;
            }

            if (!summaries.TryGetValue(log.caseId, out AgentDisagreementSummary summary))
            {
                summary = new AgentDisagreementSummary(log.caseId, log.familyType, log.recommendedDecision, log.urgency, log.documentStrength, log.equityNeed);
                summaries.Add(log.caseId, summary);
            }

            summary.totalCount++;
            if (!log.matchedRecommended)
            {
                summary.mismatchCount++;
            }

            string decision = string.IsNullOrWhiteSpace(log.decision) ? "미정" : log.decision;
            if (!summary.decisionCounts.ContainsKey(decision))
            {
                summary.decisionCounts[decision] = 0;
            }
            summary.decisionCounts[decision]++;
        }

        sorted.AddRange(summaries.Values);
        sorted.Sort((left, right) =>
        {
            int compare = right.DecisionVariety.CompareTo(left.DecisionVariety);
            if (compare != 0)
            {
                return compare;
            }

            compare = right.mismatchCount.CompareTo(left.mismatchCount);
            if (compare != 0)
            {
                return compare;
            }

            return right.urgency.CompareTo(left.urgency);
        });
        return sorted;
    }

    private static string BuildDecisionCountBrief(Dictionary<string, int> decisionCounts)
    {
        if (decisionCounts == null || decisionCounts.Count == 0)
        {
            return "판단 없음";
        }

        List<KeyValuePair<string, int>> sorted = new(decisionCounts);
        sorted.Sort((left, right) =>
        {
            int compare = right.Value.CompareTo(left.Value);
            return compare != 0 ? compare : string.Compare(left.Key, right.Key, StringComparison.Ordinal);
        });

        StringBuilder builder = new();
        int count = Mathf.Min(3, sorted.Count);
        for (int i = 0; i < count; i++)
        {
            if (i > 0)
            {
                builder.Append("/");
            }
            builder.Append(ShortDecisionLabel(sorted[i].Key));
            builder.Append(sorted[i].Value);
        }
        return builder.ToString();
    }

    private static string ShortDecisionLabel(string decision)
    {
        return decision switch
        {
            "조건부 승인" => "조건",
            "추가조사" => "조사",
            _ => decision
        };
    }

    private static float AgentDashboardColumnCenterX(int index)
    {
        return index / AgentDashboardRowsPerColumn == 0 ? 172f : 500f;
    }

    private static float AgentDashboardRowY(int index)
    {
        return 138f - (index % AgentDashboardRowsPerColumn) * 56f;
    }

    private static float AgentDashboardSupportX(int index)
    {
        return AgentDashboardColumnCenterX(index) + 32f;
    }

    private static float AgentDashboardInvestigationX(int index)
    {
        return AgentDashboardColumnCenterX(index) + 100f;
    }

    private static float AgentDashboardMatchX(int index)
    {
        return AgentDashboardColumnCenterX(index) + 168f;
    }

    private static void SetAgentBar(Image fill, float centerX, float centerY, float ratio)
    {
        const float fullWidth = AgentDashboardBarWidth;
        float width = Mathf.Clamp01(ratio) * fullWidth;
        RectTransform fillRect = fill.rectTransform;
        fillRect.sizeDelta = new Vector2(Mathf.Max(1f, width), 12f);
        fillRect.anchoredPosition = new Vector2(centerX - ((fullWidth - width) * 0.5f), centerY);
    }

    private static List<AgentPersona> BuildAgentPersonas()
    {
        TextAsset personaAsset = Resources.Load<TextAsset>("Data/agent_personas");
        if (personaAsset != null)
        {
            try
            {
                AgentPersonaDatabase database = JsonUtility.FromJson<AgentPersonaDatabase>(personaAsset.text);
                if (database?.personas != null && database.personas.Count > 0)
                {
                    return database.personas;
                }
            }
            catch (Exception exception)
            {
                Debug.LogWarning("Failed to load agent personas. Falling back to embedded personas. " + exception.Message);
            }
        }

        return new List<AgentPersona>
        {
            new("budget_guard", "예산 방어형", 0.60f, 0.40f, 0.70f, 1.40f, 0.70f, 8f, -15f),
            new("risk_first", "위험 신호 우선형", 1.25f, 0.70f, 0.30f, 0.40f, 0.40f, 4f, 10f),
            new("document_strict", "서류 엄격형", 0.65f, 0.45f, 1.10f, 0.75f, 1.25f, 18f, -5f),
            new("equity_adjuster", "형평성 보정형", 0.80f, 1.20f, 0.40f, 0.55f, 0.55f, 10f, 5f),
            new("investigation_first", "추가조사 선호형", 0.70f, 0.70f, 0.55f, 0.60f, 1.00f, 25f, -10f),
            new("complaint_avoidant", "민원 회피형", 0.95f, 0.85f, 0.45f, 0.65f, 0.55f, 6f, 14f),
            new("child_safety_first", "아동 안전형", 1.45f, 0.75f, 0.35f, 0.35f, 0.45f, 2f, 16f),
            new("procedure_first", "절차 우선형", 0.70f, 0.55f, 1.35f, 0.85f, 1.45f, 22f, -8f),
            new("recovery_focused", "회복 가능성형", 1.05f, 1.05f, 0.50f, 0.50f, 0.50f, 8f, 12f),
            new("data_recommender", "권고 추종형", 1.00f, 0.95f, 0.85f, 0.70f, 0.65f, 12f, 2f)
        };
    }

    private static DecisionKind ChooseAgentDecision(AgentPersona persona, CareCase careCase, int remainingBudget, int startingBudget)
    {
        float budgetPressure = Mathf.Clamp01((startingBudget - remainingBudget) / Mathf.Max(1f, startingBudget));
        float unaffordablePenalty = remainingBudget < careCase.cost ? 25f : 0f;
        float supportScore =
            careCase.urgency * persona.urgencyWeight +
            careCase.equityNeed * persona.equityWeight +
            careCase.documentStrength * persona.documentWeight +
            persona.approvalBias -
            (careCase.cost / 10f) * persona.budgetWeight -
            budgetPressure * 45f * persona.budgetWeight;

        float cautionScore =
            (100 - careCase.documentStrength) * persona.documentDoubtWeight +
            budgetPressure * 35f * persona.budgetWeight +
            persona.investigationBias +
            unaffordablePenalty;

        if (remainingBudget <= 0 && persona.budgetWeight >= 0.80f)
        {
            return careCase.urgency >= 82 ? DecisionKind.Hold : DecisionKind.Reject;
        }

        if (careCase.documentStrength < 52 && cautionScore > supportScore * 0.72f)
        {
            return DecisionKind.Investigate;
        }

        if (supportScore >= 170f && remainingBudget >= careCase.cost * 0.70f)
        {
            return DecisionKind.Approve;
        }

        if (supportScore >= 130f && remainingBudget >= careCase.cost * 0.45f)
        {
            return DecisionKind.Conditional;
        }

        if (careCase.urgency >= 82 && persona.urgencyWeight >= persona.documentDoubtWeight && remainingBudget >= careCase.cost * 0.45f)
        {
            return DecisionKind.Conditional;
        }

        if (cautionScore >= 75f)
        {
            return DecisionKind.Investigate;
        }

        if (persona.budgetWeight > 1.10f && careCase.cost > remainingBudget * 0.35f)
        {
            return DecisionKind.Hold;
        }

        return careCase.urgency < 65 ? DecisionKind.Reject : DecisionKind.Hold;
    }

    private int GetDecisionCost(DecisionKind decision, CareCase careCase)
    {
        return GetDecisionCost(decision, careCase, campaignMandate);
    }

    private static int GetDecisionCost(DecisionKind decision, CareCase careCase, CampaignMandate mandate)
    {
        int baseCost = decision switch
        {
            DecisionKind.Approve => careCase.cost,
            DecisionKind.Conditional => Mathf.RoundToInt(careCase.cost * 0.58f),
            _ => 0
        };
        return AdjustDecisionCostForMandate(mandate, baseCost);
    }

    private static int AdjustDecisionCostForMandate(CampaignMandate mandate, int baseCost)
    {
        if (baseCost <= 0)
        {
            return 0;
        }

        float multiplier = mandate switch
        {
            CampaignMandate.SupportExpanded => 0.90f,
            CampaignMandate.AusterityAudit => 1.08f,
            _ => 1.0f
        };
        return Mathf.RoundToInt(baseCost * multiplier);
    }

    private static int AdjustBudgetConsequenceForMandate(CampaignMandate mandate, int delta)
    {
        if (delta >= 0)
        {
            return delta;
        }

        float multiplier = mandate switch
        {
            CampaignMandate.SupportExpanded => 0.86f,
            CampaignMandate.AusterityAudit => 1.14f,
            _ => 1.0f
        };
        return Mathf.RoundToInt(delta * multiplier);
    }

    private static int AdjustMissedRiskDeltaForMandate(CampaignMandate mandate, int delta)
    {
        if (delta == 0)
        {
            return 0;
        }

        float multiplier = mandate switch
        {
            CampaignMandate.SupportExpanded => delta > 0 ? 0.84f : 1.05f,
            CampaignMandate.AusterityAudit => delta > 0 ? 1.14f : 0.90f,
            _ => 1.0f
        };
        return Mathf.RoundToInt(delta * multiplier);
    }

    private static int AdjustComplaintDeltaForMandate(CampaignMandate mandate, int delta)
    {
        if (delta <= 0)
        {
            return delta;
        }

        float multiplier = mandate switch
        {
            CampaignMandate.SupportExpanded => 0.72f,
            CampaignMandate.AusterityAudit => 1.22f,
            _ => 1.0f
        };
        return Mathf.RoundToInt(delta * multiplier);
    }

    private static Consequence AdjustConsequenceForMandate(CampaignMandate mandate, Consequence consequence)
    {
        return new Consequence(
            consequence.type,
            consequence.title,
            consequence.text,
            AdjustBudgetConsequenceForMandate(mandate, consequence.budgetDelta),
            consequence.stabilityDelta,
            consequence.equityDelta,
            AdjustMissedRiskDeltaForMandate(mandate, consequence.missedRiskDelta),
            AdjustComplaintDeltaForMandate(mandate, consequence.complaintsDelta));
    }

