    private static int ClampDecisionRationaleIndex(int index)
    {
        int count = DecisionRationaleIds.Length;
        if (count <= 0)
        {
            return 0;
        }

        return ((index % count) + count) % count;
    }

    private static string DecisionRationaleId(int index)
    {
        return DecisionRationaleIds[ClampDecisionRationaleIndex(index)];
    }

    private static string DecisionRationaleLabel(int index)
    {
        return DecisionRationaleLabels[ClampDecisionRationaleIndex(index)];
    }

    private static string DecisionRationaleName(int index)
    {
