    }

    private static string DecisionRationaleLabelForLog(DecisionLog log)
    {
        if (log == null)
        {
            return DecisionRationaleName(0);
        }

        if (!string.IsNullOrWhiteSpace(log.decisionRationaleLabel))
        {
            return log.decisionRationaleLabel;
        }

        if (!string.IsNullOrWhiteSpace(log.decisionRationaleId))
        {
            for (int i = 0; i < DecisionRationaleIds.Length; i++)
            {
                if (string.Equals(log.decisionRationaleId, DecisionRationaleIds[i], StringComparison.OrdinalIgnoreCase))
                {
                    return DecisionRationaleName(i);
                }
            }
        }

        return DecisionRationaleName(0);
    }

    private static string DecisionRationaleIdForLog(DecisionLog log)
    {
        if (log == null || string.IsNullOrWhiteSpace(log.decisionRationaleId))
        {
            return DecisionRationaleId(0);
        }

        for (int i = 0; i < DecisionRationaleIds.Length; i++)
        {
            if (string.Equals(log.decisionRationaleId, DecisionRationaleIds[i], StringComparison.OrdinalIgnoreCase))
            {
                return DecisionRationaleIds[i];
            }
        }

        return DecisionRationaleId(0);
    }

    private static string DecisionRationaleDescriptionForLog(DecisionLog log)
    {
        if (log != null && !string.IsNullOrWhiteSpace(log.decisionRationaleDescription))
        {
            return log.decisionRationaleDescription;
        }

        string id = DecisionRationaleIdForLog(log);
        for (int i = 0; i < DecisionRationaleIds.Length; i++)
        {
            if (string.Equals(id, DecisionRationaleIds[i], StringComparison.OrdinalIgnoreCase))
            {
                return DecisionRationaleDescription(i);
            }
        }

        return DecisionRationaleDescription(0);
    }

    private List<DecisionRationaleSummaryExport> BuildDecisionRationaleSummaries()
    {
        Dictionary<string, DecisionRationaleSummaryExport> summaryById = new(StringComparer.OrdinalIgnoreCase);
        for (int i = 0; i < DecisionRationaleIds.Length; i++)
        {
            string id = DecisionRationaleId(i);
            summaryById[id] = new DecisionRationaleSummaryExport
            {
                id = id,
                shortLabel = DecisionRationaleLabel(i),
                label = DecisionRationaleName(i),
                description = DecisionRationaleDescription(i)
            };
        }

        foreach (DecisionLog log in logs)
        {
            string id = DecisionRationaleIdForLog(log);
            if (!summaryById.TryGetValue(id, out DecisionRationaleSummaryExport summary))
            {
                summary = new DecisionRationaleSummaryExport
                {
                    id = id,
                    shortLabel = DecisionRationaleLabel(0),
                    label = DecisionRationaleLabelForLog(log),
                    description = DecisionRationaleDescriptionForLog(log)
                };
                summaryById[id] = summary;
            }

            summary.count++;
            if (IsSupportDecision(log.decision))
            {
                summary.supportCount++;
            }
            else if (log.decision == "추가조사")
            {
                summary.investigationCount++;
            }
            else
            {
                summary.delayCount++;
            }

            if (log.matchedRecommended)
            {
                summary.matchedRecommendedCount++;
            }

            summary.spentBudget += log.spentBudget;
            summary.riskDelta += Mathf.Max(0, log.missedRiskAfter - log.missedRiskBefore) + Mathf.Max(0, log.complaintsAfter - log.complaintsBefore);
        }

        List<DecisionRationaleSummaryExport> summaries = new();
        for (int i = 0; i < DecisionRationaleIds.Length; i++)
        {
            DecisionRationaleSummaryExport summary = summaryById[DecisionRationaleId(i)];
            summary.supportRatePercent = summary.count > 0 ? summary.supportCount * 100f / summary.count : 0f;
            summary.matchRatePercent = summary.count > 0 ? summary.matchedRecommendedCount * 100f / summary.count : 0f;
            summaries.Add(summary);
        }

        return summaries;
    }

    private static DecisionRationaleSummaryExport TopDecisionRationaleSummary(List<DecisionRationaleSummaryExport> summaries)
    {
        if (summaries == null || summaries.Count == 0)
        {
            return new DecisionRationaleSummaryExport
            {
                id = DecisionRationaleId(0),
                shortLabel = DecisionRationaleLabel(0),
                label = DecisionRationaleName(0),
                description = DecisionRationaleDescription(0)
            };
        }

        DecisionRationaleSummaryExport selected = summaries[0];
        for (int i = 1; i < summaries.Count; i++)
        {
            DecisionRationaleSummaryExport candidate = summaries[i];
            if (candidate.count > selected.count ||
                (candidate.count == selected.count && candidate.riskDelta > selected.riskDelta))
            {
                selected = candidate;
            }
        }

        return selected;
    }

