    private static string Shorten(string value, int maxCharacters)
    {
        if (string.IsNullOrEmpty(value) || value.Length <= maxCharacters)
        {
            return value ?? "";
        }

        return value.Substring(0, Mathf.Max(0, maxCharacters - 3)) + "...";
    }

    private static string CombinedText(Text[] texts)
    {
        if (texts == null || texts.Length == 0)
        {
            return "";
        }

        StringBuilder builder = new();
        for (int i = 0; i < texts.Length; i++)
        {
            if (texts[i] != null && !string.IsNullOrEmpty(texts[i].text))
            {
                builder.AppendLine(texts[i].text);
            }
        }

        return builder.ToString();
    }

#if CARE_REVIEW_QA_TOOLS
    private static string EscapeCsv(string value)
    {
        if (string.IsNullOrEmpty(value))
        {
            return "";
        }

        bool needsQuotes = value.Contains(',') || value.Contains('"') || value.Contains('\n') || value.Contains('\r');
        string escaped = value.Replace("\"", "\"\"");
        return needsQuotes ? "\"" + escaped + "\"" : escaped;
    }

#endif

    private static string EscapeJson(string value)
    {
        if (string.IsNullOrEmpty(value))
        {
            return "";
        }

        return value
            .Replace("\\", "\\\\")
            .Replace("\"", "\\\"")
            .Replace("\r", "\\r")
            .Replace("\n", "\\n");
    }

