    private static void TryWriteProjectQaSmokeResult(string fileName, string content)
    {
        try
        {
            string root = Directory.GetCurrentDirectory();
            for (int i = 0; i < 6 && !string.IsNullOrWhiteSpace(root); i++)
            {
                if (File.Exists(Path.Combine(root, "ProjectSettings", "ProjectVersion.txt")))
                {
                    string qaDirectory = Path.Combine(root, "Builds", "QA", "v0.3.0");
                    string targetPath = Path.Combine(qaDirectory, fileName);
                    string targetDirectory = Path.GetDirectoryName(targetPath);
                    Directory.CreateDirectory(qaDirectory);
                    if (!string.IsNullOrEmpty(targetDirectory))
                    {
                        Directory.CreateDirectory(targetDirectory);
                    }

                    File.WriteAllText(targetPath, content, Encoding.UTF8);
                    return;
                }

                DirectoryInfo parent = Directory.GetParent(root);
                root = parent != null ? parent.FullName : "";
            }
        }
        catch (Exception exception)
        {
            Debug.LogWarning("QA smoke mirror failed: " + exception.Message);
        }
    }

    private static void TryMirrorProjectQaPlaytestPacketFile(string sourcePath)
    {
        try
        {
            if (string.IsNullOrWhiteSpace(sourcePath) || !File.Exists(sourcePath))
            {
                return;
            }

            TryWriteProjectQaSmokeResult(Path.Combine("playtest_packet", Path.GetFileName(sourcePath)), File.ReadAllText(sourcePath, Encoding.UTF8));
        }
        catch (Exception exception)
        {
            Debug.LogWarning("Playtest packet QA mirror failed: " + Path.GetFileName(sourcePath) + " " + exception.Message);
        }
    }

