    private bool PlaySfx(AudioClip clip, float volumeScale = 0.75f)
    {
        if (sfxSource == null || clip == null || volumeLevel <= 0)
        {
            return false;
        }

        sfxSource.PlayOneShot(clip, Mathf.Clamp01(volumeScale));
        return true;
    }

    private static AudioClip CreateToneClip(string name, float duration, Func<float, float> sampler)
    {
        int sampleCount = Mathf.Max(1, Mathf.RoundToInt(AudioSampleRate * duration));
        float[] data = new float[sampleCount];
        for (int i = 0; i < sampleCount; i++)
        {
            float t = i / (float)AudioSampleRate;
            float envelope = AudioEnvelope(i, sampleCount);
            data[i] = Mathf.Clamp(sampler(t) * envelope, -0.95f, 0.95f);
        }

        AudioClip clip = AudioClip.Create(name, sampleCount, 1, AudioSampleRate, false);
        clip.SetData(data, 0);
        return clip;
    }

    private static AudioClip CreateNoiseClip(string name, float duration, float amplitude, int seed)
    {
        int sampleCount = Mathf.Max(1, Mathf.RoundToInt(AudioSampleRate * duration));
        float[] data = new float[sampleCount];
        int state = seed;
        for (int i = 0; i < sampleCount; i++)
        {
            state = unchecked(state * 1103515245 + 12345);
            float noise = (((state >> 16) & 32767) / 16383.5f) - 1f;
            float t = i / (float)AudioSampleRate;
            float paperSweep = Mathf.Sin(2f * Mathf.PI * (900f - 620f * t) * t);
            data[i] = Mathf.Clamp((noise * 0.55f + paperSweep * 0.45f) * amplitude * AudioEnvelope(i, sampleCount), -0.95f, 0.95f);
        }

        AudioClip clip = AudioClip.Create(name, sampleCount, 1, AudioSampleRate, false);
        clip.SetData(data, 0);
        return clip;
    }

    private static AudioClip CreateAmbienceClip(string name)
    {
        int sampleCount = AudioSampleRate * 4;
        float[] data = new float[sampleCount];
        int state = 97;
        for (int i = 0; i < sampleCount; i++)
        {
            float t = i / (float)AudioSampleRate;
            state = unchecked(state * 1664525 + 1013904223);
            float noise = (((state >> 16) & 32767) / 16383.5f) - 1f;
            float hum = 0.030f * Mathf.Sin(2f * Mathf.PI * 60f * t) + 0.012f * Mathf.Sin(2f * Mathf.PI * 120f * t);
            float fluorescent = 0.010f * Mathf.Sin(2f * Mathf.PI * 247f * t) * (0.5f + 0.5f * Mathf.Sin(2f * Mathf.PI * 0.33f * t));
            data[i] = Mathf.Clamp(hum + fluorescent + noise * 0.010f, -0.20f, 0.20f);
        }

        AudioClip clip = AudioClip.Create(name, sampleCount, 1, AudioSampleRate, false);
        clip.SetData(data, 0);
        return clip;
    }

    private static float AudioEnvelope(int sampleIndex, int sampleCount)
    {
        float attack = Mathf.Clamp01(sampleIndex / Mathf.Max(1f, sampleCount * 0.08f));
        float release = Mathf.Clamp01((sampleCount - sampleIndex - 1) / Mathf.Max(1f, sampleCount * 0.18f));
        return Mathf.Min(attack, release);
    }

    private void Restart()
    {
        StartRecommendedCampaign();
    }

    private void StartRecommendedCampaign()
    {
        CampaignMandate nextMandate = hasPendingNextCampaignObjective
            ? pendingNextCampaignObjective.mandate
            : campaignMandate;
        bool startedFromAppealRemedyObjective = hasPendingNextCampaignObjective && IsAppealRemedyObjective(pendingNextCampaignObjective);
        bool startedFromDecisionPracticeObjective = hasPendingNextCampaignObjective && IsDecisionPracticeObjective(pendingNextCampaignObjective);
        bool startedFromCaseObjective = hasPendingNextCampaignObjective && (pendingCaseReplayObjectiveReady || startedFromAppealRemedyObjective);
        bool startedFromAchievementObjective = hasPendingNextCampaignObjective && IsAchievementObjective(pendingNextCampaignObjective);
        bool startedFromGrowthObjective = hasPendingNextCampaignObjective && IsGrowthObjective(pendingNextCampaignObjective);
        bool startedFromGrowthFollowUpObjective = hasPendingNextCampaignObjective && IsGrowthFollowUpObjective(pendingNextCampaignObjective);
        bool startedFromDecisionAuditCoachingObjective = hasPendingNextCampaignObjective && IsDecisionAuditCoachingObjective(pendingNextCampaignObjective);
        string caseObjectiveId = "";
        string caseObjectiveChallenge = "";
        string caseObjectiveReason = "";
        if (startedFromCaseObjective)
        {
            caseObjectiveId = pendingCaseReplayObjectiveReady
                ? pendingCaseReplayObjectiveCaseId
                : currentCampaignCaseObjectiveId;
            caseObjectiveChallenge = pendingCaseReplayObjectiveReady
                ? pendingCaseReplayObjectiveChallenge
                : pendingNextCampaignObjective.challenge;
            caseObjectiveReason = pendingNextCampaignObjective.reason;
        }
        string achievementObjectiveTitle = startedFromAchievementObjective ? AchievementObjectiveTitle(pendingNextCampaignObjective) : "";
        string achievementObjectiveChallenge = startedFromAchievementObjective ? pendingNextCampaignObjective.challenge : "";
        string growthObjectiveTitle = startedFromGrowthObjective ? "최근 성장 목표" : "";
        string growthObjectiveChallenge = startedFromGrowthObjective ? pendingNextCampaignObjective.challenge : "";
        string growthObjectiveReason = startedFromGrowthObjective ? pendingNextCampaignObjective.reason : "";
        string growthFollowUpTitle = startedFromGrowthFollowUpObjective
            ? (pendingNextCampaignObjective.challenge.Contains("성장 보정") ? "성장 보정 목표" : "성장 후속 목표")
            : "";
        string growthFollowUpChallenge = startedFromGrowthFollowUpObjective ? pendingNextCampaignObjective.challenge : "";
        string growthFollowUpReason = startedFromGrowthFollowUpObjective ? pendingNextCampaignObjective.reason : "";
        string decisionAuditCoachingPattern = startedFromDecisionAuditCoachingObjective ? DecisionAuditCoachingButtonPattern(pendingNextCampaignObjective) : "";
        string decisionAuditCoachingChallenge = startedFromDecisionAuditCoachingObjective ? pendingNextCampaignObjective.challenge : "";
        string decisionAuditCoachingReason = startedFromDecisionAuditCoachingObjective ? pendingNextCampaignObjective.reason : "";
        campaignMandate = nextMandate;
        PlayerPrefs.SetInt(CampaignMandatePrefsKey, (int)campaignMandate);
        PlayerPrefs.Save();
        pendingDeleteSlot = -1;
        ResetCampaignState();
        currentCampaignStartedFromCaseObjective = startedFromCaseObjective;
        currentCampaignCaseObjectiveId = caseObjectiveId;
        currentCampaignCaseObjectiveChallenge = caseObjectiveChallenge;
        currentCampaignCaseObjectiveReason = caseObjectiveReason;
        currentCampaignStartedFromDecisionPracticeObjective = startedFromDecisionPracticeObjective;
        currentCampaignStartedFromAchievementObjective = startedFromAchievementObjective;
        currentCampaignAchievementObjectiveTitle = achievementObjectiveTitle;
        currentCampaignAchievementObjectiveChallenge = achievementObjectiveChallenge;
        currentCampaignStartedFromGrowthObjective = startedFromGrowthObjective;
        currentCampaignGrowthObjectiveTitle = growthObjectiveTitle;
        currentCampaignGrowthObjectiveChallenge = growthObjectiveChallenge;
        currentCampaignGrowthObjectiveReason = growthObjectiveReason;
        currentCampaignStartedFromGrowthFollowUpObjective = startedFromGrowthFollowUpObjective;
        currentCampaignGrowthFollowUpTitle = growthFollowUpTitle;
        currentCampaignGrowthFollowUpChallenge = growthFollowUpChallenge;
        currentCampaignGrowthFollowUpReason = growthFollowUpReason;
        currentCampaignStartedFromDecisionAuditCoachingObjective = startedFromDecisionAuditCoachingObjective;
        currentCampaignDecisionAuditCoachingPattern = decisionAuditCoachingPattern;
        currentCampaignDecisionAuditCoachingChallenge = decisionAuditCoachingChallenge;
        currentCampaignDecisionAuditCoachingReason = decisionAuditCoachingReason;
        ResetFirstCaseGuide();
        ShowTutorial(true);
    }

    private void UpdateRecommendedCampaignButton()
    {
        if (recommendedCampaignButtonText == null)
        {
            return;
        }

        if (hasPendingNextCampaignObjective)
        {
            recommendedCampaignButtonText.text = RecommendedCampaignButtonLabel(pendingNextCampaignObjective);
            recommendedCampaignButtonText.fontSize = pendingNextCampaignObjective.challenge.Contains("성장") ||
                IsAppealRemedyObjective(pendingNextCampaignObjective) ||
                IsDecisionPracticeObjective(pendingNextCampaignObjective) ||
                IsDecisionAuditCoachingObjective(pendingNextCampaignObjective)
                    ? 14
                    : 15;
        }
        else
        {
            recommendedCampaignButtonText.text = "추천 심사";
            recommendedCampaignButtonText.fontSize = 20;
        }
    }

    private static string RecommendedCampaignButtonLabel(NextCampaignObjective objective)
    {
        if (objective.challenge.Contains("성장 후속"))
        {
            return $"성장 후속 시작: {CampaignMandateLabel(objective.mandate)}";
        }

        if (objective.challenge.Contains("성장 보정"))
        {
            return $"성장 보정 시작: {CampaignMandateLabel(objective.mandate)}";
        }

        if (IsAppealRemedyObjective(objective))
        {
            return $"보정 심사 시작: {CampaignMandateLabel(objective.mandate)}";
        }

        if (IsDecisionPracticeObjective(objective))
        {
            return $"비교 연습 시작: {CampaignMandateLabel(objective.mandate)}";
        }

        if (IsDecisionAuditCoachingObjective(objective))
        {
            return $"복기 {DecisionAuditCoachingButtonPattern(objective)} 시작: {CampaignMandateLabel(objective.mandate)}";
        }

        return $"추천 심사 시작: {CampaignMandateLabel(objective.mandate)}";
    }

    private static bool IsAppealRemedyObjective(NextCampaignObjective objective)
    {
        return objective.challenge.Contains("이의제기") && objective.challenge.Contains("보정");
    }

    private static bool IsDecisionPracticeObjective(NextCampaignObjective objective)
    {
        return objective.challenge.Contains("판단 비교 연습") || objective.reason.Contains("판단 비교표");
    }

    private static bool IsDecisionAuditCoachingObjective(NextCampaignObjective objective)
    {
        return objective.challenge.Contains("복기 목표") ||
            objective.reason.Contains("판단 복기");
    }

    private static string DecisionAuditCoachingButtonPattern(NextCampaignObjective objective)
    {
        if (objective.challenge.Contains("고비용 지원") || objective.reason.Contains("고비용 지원"))
        {
            return "고비용";
        }

        if (objective.challenge.Contains("고위험 지연") || objective.reason.Contains("고위험 지연"))
        {
            return "고위험";
        }

        if (objective.challenge.Contains("권장 불일치") || objective.reason.Contains("권장 불일치"))
        {
            return "기준선";
        }

        if (objective.challenge.Contains("이의제기") || objective.reason.Contains("이의제기"))
        {
            return "보정";
        }

        return "복기";
    }

