    private void StartSessionMetadata()
    {
        currentSessionId = GenerateSessionId();
        campaignStartedAt = DateTime.Now.ToString("yyyy-MM-ddTHH:mm:ss.fff");
        accumulatedPlaySeconds = 0;
        campaignRuntimeStartRealtime = Time.realtimeSinceStartup;
    }

    private string EnsureSessionId()
    {
        if (string.IsNullOrEmpty(currentSessionId))
        {
            StartSessionMetadata();
        }

        return currentSessionId;
    }

    private int CurrentCampaignElapsedSeconds()
    {
        if (campaignRuntimeStartRealtime <= 0f)
        {
            campaignRuntimeStartRealtime = Time.realtimeSinceStartup;
        }

        int currentRunSeconds = Mathf.Max(0, Mathf.RoundToInt(Time.realtimeSinceStartup - campaignRuntimeStartRealtime));
        return Mathf.Max(0, accumulatedPlaySeconds + currentRunSeconds);
    }

    private static string FormatDuration(int totalSeconds)
    {
        totalSeconds = Mathf.Max(0, totalSeconds);
        int minutes = totalSeconds / 60;
        int seconds = totalSeconds % 60;
        return $"{minutes:00}:{seconds:00}";
    }

    private static string GenerateSessionId()
    {
        return "CR-" + DateTime.UtcNow.ToString("yyyyMMddHHmmss") + "-" + Guid.NewGuid().ToString("N").Substring(0, 6).ToUpperInvariant();
    }

    private string SessionDirectory(string sessionId)
    {
        return Path.Combine(LogDirectory, "playtest_sessions", SafePathSegment(sessionId));
    }

    private static string SessionRelativeDirectory(string sessionId)
    {
        return "playtest_sessions/" + SafePathSegment(sessionId);
    }

    private static string SessionRelativePath(string sessionId, string filePath)
    {
        return SessionRelativeDirectory(sessionId) + "/" + Path.GetFileName(filePath);
    }

    private static string NormalizeShareablePath(string path)
    {
        return string.IsNullOrEmpty(path) ? "" : path.Replace("\\", "/");
    }

    private static bool ContainsLocalAbsolutePath(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return false;
        }

        return ContainsOrdinalIgnoreCase(text, "C:/Users") ||
            ContainsOrdinalIgnoreCase(text, "C:\\Users") ||
            ContainsOrdinalIgnoreCase(text, "C:\\\\Users") ||
            ContainsOrdinalIgnoreCase(text, "/AppData/") ||
            ContainsOrdinalIgnoreCase(text, "\\AppData\\") ||
            ContainsOrdinalIgnoreCase(text, "\\\\AppData\\\\") ||
            ContainsOrdinalIgnoreCase(text, "LocalLow");
    }

    private static bool ContainsOrdinalIgnoreCase(string text, string pattern)
    {
        return text.IndexOf(pattern, StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private static string SafePathSegment(string value)
    {
        if (string.IsNullOrEmpty(value))
        {
            return "session";
        }

        char[] invalidChars = Path.GetInvalidFileNameChars();
        StringBuilder builder = new(value.Length);
        foreach (char c in value)
        {
            bool invalid = false;
            for (int i = 0; i < invalidChars.Length; i++)
            {
                if (c == invalidChars[i])
                {
                    invalid = true;
                    break;
                }
            }

            builder.Append(invalid ? '_' : c);
        }

        return builder.ToString();
    }

    private Sprite PortraitSprite(int index)
    {
        int portraitColumns = PortraitSheetColumns();
        int portraitRows = PortraitSheetRows(portraitColumns);
        int portraitCount = portraitColumns * portraitRows;
        int safeIndex = ((index % portraitCount) + portraitCount) % portraitCount;
        if (portraitCache.TryGetValue(safeIndex, out Sprite sprite))
        {
            return sprite;
        }

        int col = safeIndex % portraitColumns;
        int row = safeIndex / portraitColumns;
        int x = Mathf.RoundToInt(familyPortraitsSheet.width * col / (float)portraitColumns);
        int nextX = Mathf.RoundToInt(familyPortraitsSheet.width * (col + 1) / (float)portraitColumns);
        int cellHeight = Mathf.RoundToInt(familyPortraitsSheet.height / (float)portraitRows);
        int y = familyPortraitsSheet.height - ((row + 1) * cellHeight);
        if (row == portraitRows - 1)
        {
            y = 0;
            cellHeight = familyPortraitsSheet.height - Mathf.RoundToInt(familyPortraitsSheet.height * row / (float)portraitRows);
        }

        Rect rect = new Rect(x, y, nextX - x, cellHeight);
        sprite = Sprite.Create(familyPortraitsSheet, rect, new Vector2(0.5f, 0.5f), 100f);
        portraitCache[safeIndex] = sprite;
        return sprite;
    }

    private int PortraitSheetColumns()
    {
        if (familyPortraitsSheet == null)
        {
            return 1;
        }

        return familyPortraitsSheet.width >= familyPortraitsSheet.height * 2 ? 5 : 4;
    }

    private int PortraitSheetRows(int columns)
    {
        if (familyPortraitsSheet == null || columns <= 0)
        {
            return 1;
        }

        return columns >= 5 ? 1 : 2;
    }

    private Sprite EvidenceSprite(int visualIndex)
    {
        if (evidenceCardsSheet == null)
        {
            int fallbackColumn = Mathf.Clamp(visualIndex, 0, 3);
            return GridSprite(documentsStampsSheet, 4, 4, fallbackColumn, 0);
        }

        int col = visualIndex % 4;
        int row = visualIndex / 4;
        return GridSprite(evidenceCardsSheet, 4, 3, col, row);
    }

    private Sprite GridSprite(Texture2D texture, int columns, int rows, int visualColumn, int visualRow)
    {
        string key = texture.name + ":" + columns + ":" + rows + ":" + visualColumn + ":" + visualRow;
        if (gridSpriteCache.TryGetValue(key, out Sprite sprite))
        {
            return sprite;
        }

        int cellWidth = texture.width / columns;
        int cellHeight = texture.height / rows;
        int x = visualColumn * cellWidth;
        int y = texture.height - ((visualRow + 1) * cellHeight);
        sprite = Sprite.Create(texture, new Rect(x, y, cellWidth, cellHeight), new Vector2(0.5f, 0.5f), 100f);
        gridSpriteCache[key] = sprite;
        return sprite;
    }

    private Sprite GeneratedUiSprite(string resourceName, bool sliced)
    {
        string key = resourceName + ":" + sliced;
        if (generatedUiSpriteCache.TryGetValue(key, out Sprite sprite))
        {
            return sprite;
        }

        Texture2D texture = Resources.Load<Texture2D>("Art/" + resourceName);
        if (texture == null)
        {
            return null;
        }

        Vector4 border = sliced ? GeneratedUiBorder(texture, resourceName) : Vector4.zero;
        sprite = Sprite.Create(
            texture,
            new Rect(0, 0, texture.width, texture.height),
            new Vector2(0.5f, 0.5f),
            100f,
            0,
            SpriteMeshType.FullRect,
            border);
        generatedUiSpriteCache[key] = sprite;
        return sprite;
    }

    private static Vector4 GeneratedUiBorder(Texture2D texture, string resourceName)
    {
        float horizontal = Mathf.Clamp(texture.width * 0.13f, 18f, 48f);
        float vertical = Mathf.Clamp(texture.height * 0.24f, 14f, 46f);
        if (resourceName.Contains("hotkey") || resourceName.Contains("focus"))
        {
            horizontal = Mathf.Clamp(texture.width * 0.18f, 18f, 42f);
            vertical = Mathf.Clamp(texture.height * 0.18f, 14f, 38f);
        }

        horizontal = Mathf.Min(horizontal, texture.width * 0.42f);
        vertical = Mathf.Min(vertical, texture.height * 0.42f);
        return new Vector4(horizontal, vertical, horizontal, vertical);
    }

    private Sprite EndingSprite(int visualIndex)
    {
        int col = visualIndex % 2;
        int row = visualIndex / 2;
        return GridSprite(endingVignettesSheet, 2, 2, col, row);
    }

    private Sprite IncidentSprite(string incidentType)
    {
        if (incidentCardsSheet == null)
        {
            return EndingSprite(0);
        }

        int columns = incidentCardsSheet.width >= incidentCardsSheet.height * 3 / 2 ? 3 : 2;
        int rows = 2;
        int col = 0;
        int row = 0;
        switch (incidentType)
        {
            case "complaint_surge":
                col = 1;
                row = 0;
                break;
            case "safety_check":
                col = 0;
                row = 1;
                break;
            case "equity_objection":
                col = 1;
                row = 1;
                break;
            case "staff_burnout":
                col = 2;
                row = 0;
                break;
            case "review_backlog":
                col = 2;
                row = 1;
                break;
        }

        if (col >= columns)
        {
            col = 0;
            row = 0;
        }

        return GridSprite(incidentCardsSheet, columns, rows, col, row);
    }

    private RectTransform CreateRoot(string name)
    {
        GameObject go = new(name, typeof(RectTransform));
        go.transform.SetParent(canvas.transform, false);
        RectTransform rt = go.GetComponent<RectTransform>();
        rt.anchorMin = Vector2.zero;
        rt.anchorMax = Vector2.one;
        rt.offsetMin = Vector2.zero;
        rt.offsetMax = Vector2.zero;
        return rt;
    }

    private RectTransform CreateChildRoot(Transform parent, string name)
    {
        GameObject go = new(name, typeof(RectTransform));
        go.transform.SetParent(parent, false);
        RectTransform rt = go.GetComponent<RectTransform>();
        rt.anchorMin = Vector2.zero;
        rt.anchorMax = Vector2.one;
        rt.offsetMin = Vector2.zero;
        rt.offsetMax = Vector2.zero;
        return rt;
    }

    private Image CreatePanel(string name, Transform parent, Vector2 position, Vector2 size, Color color)
    {
        Image image = CreateImage(name, parent, null, position, size, color);
        image.raycastTarget = false;
        AddGeneratedPanelChrome(name, image.transform, size, color);
        return image;
    }

    private void AddGeneratedPanelChrome(string name, Transform parent, Vector2 size, Color color)
    {
        string assetName = GeneratedPanelAssetName(name, size);
        if (string.IsNullOrEmpty(assetName))
        {
            return;
        }

        Sprite sprite = GeneratedUiSprite(assetName, true);
        if (sprite == null)
        {
            return;
        }

        Image chrome = CreateImage("Generated UI Chrome", parent, sprite, Vector2.zero, size, GeneratedPanelTint(name, color));
        chrome.type = Image.Type.Sliced;
        chrome.raycastTarget = false;
    }

    private static string GeneratedPanelAssetName(string name, Vector2 size)
    {
        if (name.Contains("Dim") ||
            name.Contains("Tint") ||
            name.Contains("Fill") ||
            name.Contains("Track") ||
            name.Contains("Shadow") ||
            name.Contains("Wash") ||
            name.Contains("Gauge") ||
            name.Contains("Severity Frame"))
        {
            return null;
        }

        if (name.Contains("Paper") && size.x >= 520f && size.y >= 360f)
        {
            return "ui_panel_paper_generated";
        }

        if (name.Contains("Action Rail") ||
            name.Contains("Tool Rail") ||
            name.Contains("Button Rail") ||
            name.Contains("Command Rail") ||
            name.Contains("Objective Shelf") ||
            name.Contains("Support Rail") ||
            name.Contains("Decision Stamp Tray") ||
            name.Contains("Action Dock"))
        {
            return "ui_action_rail_generated";
        }

        if (name.Contains("Header") || name.Contains("Strip"))
        {
            return "ui_button_analysis_generated";
        }

        if (name.Contains("Card") && size.x >= 300f && size.y >= 100f)
        {
            return "ui_panel_modal_generated";
        }

        return null;
    }

    private static Color GeneratedPanelTint(string name, Color baseColor)
    {
        if (name.StartsWith("Menu ", StringComparison.Ordinal))
        {
            float menuAlpha = Mathf.Clamp01(baseColor.a + 0.06f);
            if (name.Contains("Objective Shelf"))
            {
                menuAlpha = Mathf.Clamp01(baseColor.a + 0.04f);
            }
            return new Color(1f, 1f, 1f, menuAlpha);
        }

        if (name.StartsWith("Review ", StringComparison.Ordinal) ||
            name.Contains("Decision Stamp Tray"))
        {
            return new Color(1f, 1f, 1f, Mathf.Clamp01(baseColor.a + 0.06f));
        }

        float alpha = Mathf.Clamp01(Mathf.Max(0.56f, baseColor.a + 0.14f));
        if (name.Contains("Paper"))
        {
            alpha = Mathf.Clamp01(Mathf.Max(0.78f, baseColor.a + 0.08f));
        }
        else if (name.Contains("Header") || name.Contains("Strip"))
        {
            alpha = Mathf.Clamp01(Mathf.Max(0.68f, baseColor.a + 0.10f));
        }

        return new Color(1f, 1f, 1f, alpha);
    }

    private RawImage CreateRawImage(string name, Transform parent, Texture texture, Vector2 position, Vector2 size, bool stretch, Color color)
    {
        GameObject go = new(name, typeof(RectTransform), typeof(RawImage));
        go.transform.SetParent(parent, false);
        RectTransform rt = go.GetComponent<RectTransform>();
        if (stretch)
        {
            rt.anchorMin = Vector2.zero;
            rt.anchorMax = Vector2.one;
            rt.offsetMin = Vector2.zero;
            rt.offsetMax = Vector2.zero;
        }
        else
        {
            SetRect(rt, position, size);
        }
        RawImage raw = go.GetComponent<RawImage>();
        raw.texture = texture;
        raw.color = color;
        raw.raycastTarget = false;
        return raw;
    }

    private Image CreateImage(string name, Transform parent, Sprite sprite, Vector2 position, Vector2 size, Color color)
    {
        GameObject go = new(name, typeof(RectTransform), typeof(Image));
        go.transform.SetParent(parent, false);
        RectTransform rt = go.GetComponent<RectTransform>();
        SetRect(rt, position, size);
        Image image = go.GetComponent<Image>();
        image.sprite = sprite;
        image.color = color;
        image.raycastTarget = false;
        return image;
    }

    private Text CreateText(Transform parent, string name, string text, int size, TextAnchor anchor, Color color, FontStyle style)
    {
        GameObject go = new(name, typeof(RectTransform), typeof(Text));
        go.transform.SetParent(parent, false);
        Text uiText = go.GetComponent<Text>();
        uiText.font = koreanFont;
        uiText.text = text;
        uiText.fontStyle = DisplayFontStyle(style);
        uiText.alignment = anchor;
        uiText.alignByGeometry = true;
        uiText.color = color;
        uiText.horizontalOverflow = HorizontalWrapMode.Wrap;
        uiText.verticalOverflow = VerticalWrapMode.Truncate;
        uiText.lineSpacing = 1.08f;
        RegisterText(uiText, size);
        return uiText;
    }

    private Text CreateTextBox(Transform parent, string name, Vector2 position, Vector2 size, Color32 backerColor, int padding, string text, int fontSize, TextAnchor anchor, Color textColor, FontStyle style)
    {
        GameObject box = new(name, typeof(RectTransform), typeof(Image), typeof(RectMask2D));
        box.transform.SetParent(parent, false);
        RectTransform boxRect = box.GetComponent<RectTransform>();
        SetRect(boxRect, position, size);

        Image backer = box.GetComponent<Image>();
        backer.color = backerColor;
        backer.raycastTarget = false;
        AddGeneratedTextBoxChrome(box.transform, size, backerColor);

        GameObject textObject = new(name + " Text", typeof(RectTransform), typeof(Text));
        textObject.transform.SetParent(box.transform, false);
        RectTransform textRect = textObject.GetComponent<RectTransform>();
        textRect.anchorMin = Vector2.zero;
        textRect.anchorMax = Vector2.one;
        int contentPadding = padding + TextBoxSafeInset;
        textRect.offsetMin = new Vector2(contentPadding, contentPadding);
        textRect.offsetMax = new Vector2(-contentPadding, -contentPadding);

        Text uiText = textObject.GetComponent<Text>();
        uiText.font = koreanFont;
        uiText.text = text;
        uiText.fontStyle = DisplayFontStyle(style);
        uiText.alignment = anchor;
        uiText.alignByGeometry = true;
        uiText.color = textColor;
        uiText.horizontalOverflow = HorizontalWrapMode.Wrap;
        uiText.verticalOverflow = VerticalWrapMode.Truncate;
        uiText.lineSpacing = 1.02f;
        uiText.raycastTarget = false;
        RegisterText(uiText, fontSize);
        return uiText;
    }

    private FontStyle DisplayFontStyle(FontStyle requestedStyle)
    {
        if (requestedStyle == FontStyle.Bold && koreanFont != null && koreanFont.name.IndexOf("Paperlogy", StringComparison.OrdinalIgnoreCase) >= 0)
        {
            return FontStyle.Normal;
        }

        return requestedStyle;
    }

    private const int TextBoxSafeInset = 3;

    private void AddGeneratedTextBoxChrome(Transform parent, Vector2 size, Color32 backerColor)
    {
        Sprite sprite = GeneratedUiSprite(GeneratedTextBoxAssetName(backerColor), true);
        if (sprite == null)
        {
            return;
        }

        Image chrome = CreateImage("Generated Text Box Chrome", parent, sprite, Vector2.zero, size, GeneratedTextBoxTint(backerColor));
        chrome.type = Image.Type.Sliced;
        chrome.raycastTarget = false;
    }

    private static string GeneratedTextBoxAssetName(Color32 backerColor)
    {
        float luminance = RelativeLuminance(backerColor);
        if (luminance > 0.55f)
        {
            return "ui_panel_paper_generated";
        }

        return backerColor.a >= 170 ? "ui_panel_modal_generated" : "ui_button_analysis_generated";
    }

    private static Color GeneratedTextBoxTint(Color32 backerColor)
    {
        float luminance = RelativeLuminance(backerColor);
        if (luminance > 0.55f)
        {
            return new Color(1f, 1f, 1f, Mathf.Clamp01(backerColor.a / 255f + 0.18f));
        }

        return new Color(1f, 1f, 1f, Mathf.Clamp01(backerColor.a / 255f + 0.10f));
    }

    private void RegisterText(Text text, int baseFontSize)
    {
        trackedTexts.Add(new TrackedText(text, baseFontSize));
        text.fontSize = AdjustedFontSize(baseFontSize);
    }

    private int AdjustedFontSize(int baseFontSize)
    {
        int readabilityBoost = 2;
        return baseFontSize + readabilityBoost + (largeTextMode ? 2 : 0);
    }

    private void ApplyTextScale()
    {
        foreach (TrackedText trackedText in trackedTexts)
        {
            if (trackedText.text != null)
            {
                trackedText.text.fontSize = AdjustedFontSize(trackedText.baseFontSize);
                trackedText.text.color = highContrastMode ? HighContrastTextColor(trackedText.baseColor) : trackedText.baseColor;
                if (trackedText.accessibilityOutline != null)
                {
                    trackedText.accessibilityOutline.enabled = highContrastMode;
                    trackedText.accessibilityOutline.effectColor = HighContrastOutlineColor(trackedText.text.color);
                    trackedText.accessibilityOutline.effectDistance = highContrastMode ? new Vector2(1.5f, -1.5f) : Vector2.zero;
                }
            }
        }
    }

    private static Color HighContrastTextColor(Color baseColor)
    {
        return RelativeLuminance(baseColor) < 0.45f
            ? new Color32(18, 14, 10, 255)
            : new Color32(255, 248, 224, 255);
    }

    private static Color HighContrastOutlineColor(Color textColor)
    {
        return RelativeLuminance(textColor) < 0.45f
            ? new Color32(255, 248, 224, 230)
            : new Color32(12, 10, 8, 235);
    }

    private static float RelativeLuminance(Color color)
    {
        return 0.2126f * color.r + 0.7152f * color.g + 0.0722f * color.b;
    }

    private void CreateDecisionButton(string label, DecisionKind decision, Sprite stampSprite, Vector2 position, Color32 tint)
    {
        GameObject go = new("Decision " + label, typeof(RectTransform), typeof(Image), typeof(Button));
        go.transform.SetParent(reviewRoot, false);
        RectTransform rt = go.GetComponent<RectTransform>();
        SetRect(rt, position, new Vector2(172, 82));
        Image image = go.GetComponent<Image>();
        image.color = new Color32(30, 23, 18, 146);
        image.raycastTarget = true;

        Button button = go.GetComponent<Button>();
        ConfigureControllerFocusableButton(button, image, tint);
        button.onClick.AddListener(() => Decide(decision));

        CreateImage("Stamp Pad Tint", go.transform, null, new Vector2(0, -2), new Vector2(150, 60), new Color32(tint.r, tint.g, tint.b, 62));
        CreateImage("Stamp Pad Top Edge", go.transform, null, new Vector2(0, 31), new Vector2(142, 2), new Color32(246, 220, 168, 36));
        CreateImage("Stamp Pad Bottom Edge", go.transform, null, new Vector2(0, -35), new Vector2(142, 2), new Color32(0, 0, 0, 56));

        Image stampImage = CreateImage("Decision Stamp Face", go.transform, stampSprite, new Vector2(0, 7), new Vector2(72, 72), new Color32(255, 255, 255, 232));
        stampImage.preserveAspect = true;
        stampImage.raycastTarget = false;

        int hotkey = DecisionHotkey(decision);
        Sprite hotkeyBadgeSprite = GeneratedUiSprite("ui_hotkey_badge_generated", true);
        Image hotkeyBacker = CreateImage("Hotkey Badge", go.transform, hotkeyBadgeSprite, new Vector2(-64, 28), new Vector2(26, 20), hotkeyBadgeSprite != null ? new Color32(255, 255, 255, 164) : new Color32(19, 23, 22, 156));
        hotkeyBacker.type = hotkeyBacker.sprite != null ? Image.Type.Sliced : Image.Type.Simple;
        hotkeyBacker.raycastTarget = false;
        Text hotkeyText = CreateText(go.transform, "Hotkey", hotkey.ToString(), 11, TextAnchor.MiddleCenter, new Color32(250, 232, 180, 232), FontStyle.Bold);
        SetRect(hotkeyText.rectTransform, new Vector2(-64, 28), new Vector2(22, 16));
        AddShadow(hotkeyText, new Color32(16, 12, 10, 180), new Vector2(1, -1));

        Text accessibleLabel = CreateText(go.transform, "Label", label, 1, TextAnchor.MiddleCenter, new Color32(255, 255, 255, 0), FontStyle.Normal);
        SetRect(accessibleLabel.rectTransform, new Vector2(0, -29), new Vector2(112, 18));
    }

    private static int DecisionHotkey(DecisionKind decision)
    {
        for (int i = 0; i < PolicyDecisionOrder.Length; i++)
        {
            if (PolicyDecisionOrder[i] == decision)
            {
                return i + 1;
            }
        }

        return 0;
    }

    private Button CreateTextButton(Transform parent, string label, Vector2 position, Vector2 size, Color32 color, Action onClick)
    {
        GameObject go = new(label, typeof(RectTransform), typeof(Image), typeof(Button));
        go.transform.SetParent(parent, false);
        SetRect(go.GetComponent<RectTransform>(), position, size);
        string displayLabel = DisplayButtonLabel(label);
        TextButtonRole role = ResolveTextButtonRole(label, displayLabel);
        GameObject roleMarker = new("Button Role " + role);
        roleMarker.transform.SetParent(go.transform, false);

        Image image = go.GetComponent<Image>();
        Sprite generatedButtonSprite = GeneratedButtonSprite(role);
        bool usesGeneratedSprite = generatedButtonSprite != null;
        if (usesGeneratedSprite)
        {
            image.sprite = generatedButtonSprite;
            image.type = Image.Type.Sliced;
            image.color = GeneratedButtonTint(color);
        }
        else
        {
            image.color = ButtonBaseColor(color, role);
        }
        image.raycastTarget = true;
        AddButtonChrome(go.transform, size, color, role, usesGeneratedSprite);
        Button button = go.GetComponent<Button>();
        ConfigureControllerFocusableButton(button, image, usesGeneratedSprite ? GeneratedButtonSelectedTint(role) : ButtonSelectedColor(color, role));
        button.onClick.AddListener(() =>
        {
            PlaySfx(buttonClickClip, 0.55f);
            onClick();
        });

        Text text = CreateText(go.transform, "Label", displayLabel, ButtonFontSize(displayLabel, size), TextAnchor.MiddleCenter, new Color32(245, 235, 214, 255), FontStyle.Bold);
        SetRect(text.rectTransform, Vector2.zero, ButtonLabelSize(displayLabel, size));
        AddShadow(text, new Color32(22, 18, 16, 210), new Vector2(1, -1));
        return button;
    }

    private void AddButtonChrome(Transform parent, Vector2 size, Color32 baseColor, TextButtonRole role, bool usesGeneratedSprite)
    {
        if (usesGeneratedSprite)
        {
            GameObject generatedMarker = new("Button Generated UI");
            generatedMarker.transform.SetParent(parent, false);

            if (role == TextButtonRole.Primary || role == TextButtonRole.Analysis || role == TextButtonRole.Danger)
            {
                Color32 accentColor = role == TextButtonRole.Primary
                    ? new Color32(238, 201, 105, 156)
                    : ScaleAlpha(LightenColor(baseColor, role == TextButtonRole.Danger ? 0.08f : 0.16f), 0.72f);
                float accentWidth = role == TextButtonRole.Primary ? 3.5f : 3f;
                Image leftAccent = CreateImage("Button Accent", parent, null, new Vector2(-size.x * 0.5f + 4.5f, 0), new Vector2(accentWidth, Mathf.Max(18f, size.y - 18f)), accentColor);
                leftAccent.raycastTarget = false;
            }

            Shadow generatedShadow = parent.gameObject.AddComponent<Shadow>();
            generatedShadow.effectColor = new Color32(0, 0, 0, role == TextButtonRole.Primary ? (byte)82 : (byte)46);
            generatedShadow.effectDistance = role == TextButtonRole.Primary ? new Vector2(1.4f, -1.4f) : new Vector2(0.8f, -0.8f);
            return;
        }

        if (role == TextButtonRole.Utility)
        {
            Image utilityLine = CreateImage("Button Utility Line", parent, null, new Vector2(0, size.y * 0.5f - 3f), new Vector2(size.x - 14f, 1.5f), ScaleAlpha(LightenColor(baseColor, 0.08f), 0.72f));
            utilityLine.raycastTarget = false;
            Shadow utilityShadow = parent.gameObject.AddComponent<Shadow>();
            utilityShadow.effectColor = new Color32(0, 0, 0, 32);
            utilityShadow.effectDistance = new Vector2(0.7f, -0.7f);
            return;
        }

        float edgeThickness = role == TextButtonRole.Primary || role == TextButtonRole.Danger ? 2.5f : 2f;
        Image topEdge = CreateImage("Button Top Edge", parent, null, new Vector2(0, size.y * 0.5f - 4f), new Vector2(size.x - 10f, edgeThickness), ScaleAlpha(LightenColor(baseColor, 0.12f), 0.72f));
        topEdge.raycastTarget = false;
        Image bottomEdge = CreateImage("Button Bottom Edge", parent, null, new Vector2(0, -size.y * 0.5f + 3f), new Vector2(size.x - 10f, edgeThickness + 0.5f), ScaleAlpha(DarkenColor(baseColor, 0.20f), 0.68f));
        bottomEdge.raycastTarget = false;

        if (role == TextButtonRole.Primary || role == TextButtonRole.Analysis || role == TextButtonRole.Danger)
        {
            Color32 accentColor = role == TextButtonRole.Primary
                ? new Color32(238, 201, 105, (byte)Mathf.Min(baseColor.a, 164))
                : ScaleAlpha(LightenColor(baseColor, role == TextButtonRole.Danger ? 0.10f : 0.18f), 0.72f);
            Image leftAccent = CreateImage("Button Accent", parent, null, new Vector2(-size.x * 0.5f + 4f, 0), new Vector2(role == TextButtonRole.Primary ? 4f : 3f, Mathf.Max(18f, size.y - 16f)), accentColor);
            leftAccent.raycastTarget = false;
        }

        Shadow buttonShadow = parent.gameObject.AddComponent<Shadow>();
        buttonShadow.effectColor = new Color32(0, 0, 0, role == TextButtonRole.Primary ? (byte)82 : (byte)52);
        buttonShadow.effectDistance = role == TextButtonRole.Primary ? new Vector2(1.6f, -1.6f) : new Vector2(0.9f, -0.9f);
    }

    private Sprite GeneratedButtonSprite(TextButtonRole role)
    {
        string assetName = role switch
        {
            TextButtonRole.Primary => "ui_button_primary_generated",
            TextButtonRole.Secondary => "ui_button_secondary_generated",
            TextButtonRole.Utility => "ui_button_utility_generated",
            TextButtonRole.Analysis => "ui_button_analysis_generated",
            TextButtonRole.Danger => "ui_button_danger_generated",
            _ => null
        };

        return string.IsNullOrEmpty(assetName) ? null : GeneratedUiSprite(assetName, true);
    }

    private static Color GeneratedButtonTint(Color32 baseColor)
    {
        return new Color(1f, 1f, 1f, Mathf.Clamp01(baseColor.a / 255f * 0.88f));
    }

    private static Color32 GeneratedButtonSelectedTint(TextButtonRole role)
    {
        return role switch
        {
            TextButtonRole.Primary => new Color32(255, 236, 176, 255),
            TextButtonRole.Danger => new Color32(255, 204, 188, 255),
            TextButtonRole.Analysis => new Color32(220, 234, 242, 255),
            TextButtonRole.Utility => new Color32(226, 214, 194, 255),
            _ => new Color32(232, 224, 210, 255)
        };
    }

    private static string DisplayButtonLabel(string label)
    {
        return label switch
        {
            "안내 이전" => "이전",
            "안내 다음" => "다음",
            "첫 사례 다음" => "다음",
            "첫 사례 닫기" => "닫기",
            _ => label
        };
    }

    private static TextButtonRole ResolveTextButtonRole(string internalLabel, string displayLabel)
    {
        if (internalLabel == "안내 다음" ||
            internalLabel == "첫 사례 다음" ||
            displayLabel.Contains("새 캠페인") ||
            displayLabel.Contains("다음 사례") ||
            displayLabel.Contains("다음 날") ||
            displayLabel.Contains("확인하고 시작") ||
            displayLabel.Contains("추천 심사"))
        {
            return TextButtonRole.Primary;
        }

        if (displayLabel.Contains("삭제") ||
            displayLabel.Contains("종료") ||
            displayLabel.Contains("데이터 삭제"))
        {
            return TextButtonRole.Danger;
        }

        if (displayLabel.Contains("분석") ||
            displayLabel.Contains("감사") ||
            displayLabel.Contains("설문") ||
            displayLabel.Contains("성과 기록") ||
            displayLabel.Contains("엔딩 기록") ||
            displayLabel.Contains("캠페인 기록"))
        {
            return TextButtonRole.Analysis;
        }

        if (displayLabel.Length <= 2 ||
            displayLabel.Contains("메뉴") ||
            displayLabel.Contains("연락함") ||
            displayLabel.Contains("근거") ||
            displayLabel.Contains("기준표") ||
            displayLabel.Contains("도움말") ||
            displayLabel == "저장" ||
            displayLabel.Contains("설정") ||
            displayLabel.Contains("고지") ||
            displayLabel.Contains("슬롯") ||
            displayLabel.Contains("필터") ||
            displayLabel.Contains("기준 전환"))
        {
            return TextButtonRole.Utility;
        }

        return TextButtonRole.Secondary;
    }

    private static int ButtonFontSize(string label, Vector2 size)
    {
        if (size.y <= 38f)
        {
            return label.Length >= 6 ? 14 : 16;
        }
        if (size.x >= 250f && label.Length >= 12)
        {
            return 15;
        }
        if (size.x <= 130f)
        {
            return label.Length >= 5 ? 16 : 18;
        }
        if (label.Contains("\n"))
        {
            return 17;
        }
        if (label.Length >= 7)
        {
            return 18;
        }

        return 21;
    }

    private static Vector2 ButtonLabelSize(string label, Vector2 size)
    {
        float horizontalInset = label.Length >= 12 ? 30f : 24f;
        return new Vector2(Mathf.Max(20f, size.x - horizontalInset), Mathf.Max(20f, size.y - 14f));
    }

    private static int CountButtonLabelsContaining(RectTransform root, params string[] terms)
    {
        if (root == null || terms == null || terms.Length == 0)
        {
            return 0;
        }

        int count = 0;
        Button[] buttons = root.GetComponentsInChildren<Button>(true);
        foreach (Button button in buttons)
        {
            if (button == null || !button.gameObject.activeInHierarchy)
            {
                continue;
            }

            Text label = button.GetComponentInChildren<Text>(true);
            string text = label != null ? label.text : "";
            for (int i = 0; i < terms.Length; i++)
            {
                if (!string.IsNullOrEmpty(terms[i]) && text.Contains(terms[i]))
                {
                    count++;
                    break;
                }
            }
        }

        return count;
    }

    private static int CountActiveTextsContaining(RectTransform root, params string[] terms)
    {
        if (root == null || terms == null || terms.Length == 0)
        {
            return 0;
        }

        int count = 0;
        Text[] texts = root.GetComponentsInChildren<Text>(true);
        foreach (Text text in texts)
        {
            if (text == null || !text.gameObject.activeInHierarchy)
            {
                continue;
            }

            string value = text.text ?? "";
            for (int i = 0; i < terms.Length; i++)
            {
                if (!string.IsNullOrEmpty(terms[i]) && value.Contains(terms[i]))
                {
                    count++;
                    break;
                }
            }
        }

        return count;
    }

    private static string FirstActiveTextContaining(RectTransform root, params string[] terms)
    {
        if (root == null || terms == null || terms.Length == 0)
        {
            return "";
        }

        Text[] texts = root.GetComponentsInChildren<Text>(true);
        foreach (Text text in texts)
        {
            if (text == null || !text.gameObject.activeInHierarchy)
            {
                continue;
            }

            string value = text.text ?? "";
            for (int i = 0; i < terms.Length; i++)
            {
                if (!string.IsNullOrEmpty(terms[i]) && value.Contains(terms[i]))
                {
                    return value;
                }
            }
        }

        return "";
    }

    private static string FirstNonEmpty(params string[] values)
    {
        if (values == null)
        {
            return "";
        }

        for (int i = 0; i < values.Length; i++)
        {
            if (!string.IsNullOrWhiteSpace(values[i]))
            {
                return values[i];
            }
        }

        return "";
    }

    private static Color32 ButtonBaseColor(Color32 color, TextButtonRole role)
    {
        return role switch
        {
            TextButtonRole.Primary => LightenColor(color, 0.04f),
            TextButtonRole.Secondary => new Color32(color.r, color.g, color.b, (byte)Mathf.Min(color.a, 224)),
            TextButtonRole.Utility => new Color32((byte)Mathf.RoundToInt(color.r * 0.72f), (byte)Mathf.RoundToInt(color.g * 0.72f), (byte)Mathf.RoundToInt(color.b * 0.72f), (byte)Mathf.Min(color.a, 210)),
            TextButtonRole.Analysis => new Color32(color.r, color.g, color.b, (byte)Mathf.Min(color.a, 226)),
            TextButtonRole.Danger => new Color32(color.r, color.g, color.b, (byte)Mathf.Min(color.a, 226)),
            _ => color
        };
    }

    private static Color32 ButtonSelectedColor(Color32 color, TextButtonRole role)
    {
        return role == TextButtonRole.Primary
            ? LightenColor(color, 0.34f)
            : LightenColor(color, 0.20f);
    }

    private static Color32 LightenColor(Color32 color, float amount)
    {
        amount = Mathf.Clamp01(amount);
        return new Color32(
            (byte)Mathf.Clamp(Mathf.RoundToInt(color.r + (255 - color.r) * amount), 0, 255),
            (byte)Mathf.Clamp(Mathf.RoundToInt(color.g + (255 - color.g) * amount), 0, 255),
            (byte)Mathf.Clamp(Mathf.RoundToInt(color.b + (255 - color.b) * amount), 0, 255),
            color.a);
    }

    private static Color32 DarkenColor(Color32 color, float amount)
    {
        amount = Mathf.Clamp01(amount);
        return new Color32(
            (byte)Mathf.Clamp(Mathf.RoundToInt(color.r * (1f - amount)), 0, 255),
            (byte)Mathf.Clamp(Mathf.RoundToInt(color.g * (1f - amount)), 0, 255),
            (byte)Mathf.Clamp(Mathf.RoundToInt(color.b * (1f - amount)), 0, 255),
            color.a);
    }

    private static Color32 ScaleAlpha(Color32 color, float factor)
    {
        return new Color32(
            color.r,
            color.g,
            color.b,
            (byte)Mathf.Clamp(Mathf.RoundToInt(color.a * Mathf.Max(0f, factor)), 0, 255));
    }

    private static void ConfigureControllerFocusableButton(Button button, Image image, Color32 selectedTint)
    {
        button.targetGraphic = image;
        button.transition = Selectable.Transition.ColorTint;
        Navigation navigation = button.navigation;
        navigation.mode = Navigation.Mode.Automatic;
        button.navigation = navigation;

        ColorBlock colors = button.colors;
        colors.normalColor = new Color32(255, 255, 255, 255);
        colors.highlightedColor = selectedTint;
        colors.selectedColor = selectedTint;
        colors.pressedColor = new Color32(230, 214, 188, 255);
        colors.disabledColor = new Color32(118, 112, 104, 112);
        colors.colorMultiplier = 1f;
        colors.fadeDuration = 0.08f;
        button.colors = colors;

        Outline focusOutline = button.gameObject.AddComponent<Outline>();
        focusOutline.enabled = false;
        focusOutline.effectColor = new Color32(255, 218, 112, 0);
        focusOutline.effectDistance = new Vector2(3f, -3f);
        button.gameObject.AddComponent<ControllerFocusHighlight>().Configure(focusOutline);
    }

    private static void ConfigureExplicitNavigation(Button button, Selectable left, Selectable right, Selectable up, Selectable down)
    {
        if (button == null)
        {
            return;
        }

        Navigation navigation = button.navigation;
        navigation.mode = Navigation.Mode.Explicit;
        navigation.selectOnLeft = left;
        navigation.selectOnRight = right;
        navigation.selectOnUp = up;
        navigation.selectOnDown = down;
        button.navigation = navigation;
    }

    private void EnsureControllerFocus()
    {
        RectTransform root = CurrentInteractiveRoot();
        if (root == null || ActiveRootContainsSelection(root))
        {
            return;
        }

        SelectFirstInteractableButton(root);
    }

    private RectTransform CurrentInteractiveRoot()
    {
        if (IsInteractiveRootActive(firstRunNoticeRoot)) return firstRunNoticeRoot;
        if (IsInteractiveRootActive(firstCaseGuideRoot)) return firstCaseGuideRoot;
        if (IsInteractiveRootActive(tutorialRoot)) return tutorialRoot;
#if CARE_REVIEW_QA_TOOLS
        if (IsInteractiveRootActive(playtestSurveyRoot)) return playtestSurveyRoot;
#endif
        if (IsInteractiveRootActive(decisionAuditRoot)) return decisionAuditRoot;
        if (IsInteractiveRootActive(decisionHistoryRoot)) return decisionHistoryRoot;
        if (IsInteractiveRootActive(followUpInboxRoot)) return followUpInboxRoot;
        if (IsInteractiveRootActive(policyHandbookRoot)) return policyHandbookRoot;
        if (IsInteractiveRootActive(settingsRoot)) return settingsRoot;
        if (IsInteractiveRootActive(dayTransitionRoot)) return dayTransitionRoot;
        if (IsInteractiveRootActive(reportRoot)) return reportRoot;
        if (IsInteractiveRootActive(endingGalleryRoot)) return endingGalleryRoot;
        if (IsInteractiveRootActive(achievementRoot)) return achievementRoot;
        if (IsInteractiveRootActive(careerRecordRoot)) return careerRecordRoot;
        if (IsInteractiveRootActive(caseArchiveRoot)) return caseArchiveRoot;
        if (IsInteractiveRootActive(creditsRoot)) return creditsRoot;
        if (IsInteractiveRootActive(reviewRoot)) return reviewRoot;
        if (IsInteractiveRootActive(menuRoot)) return menuRoot;
        return null;
    }

    private static bool IsInteractiveRootActive(RectTransform root)
    {
        return root != null && root.gameObject.activeInHierarchy;
    }

    private static bool SelectFirstInteractableButton(RectTransform root)
    {
        EventSystem current = EventSystem.current;
        if (root == null || current == null || !root.gameObject.activeInHierarchy)
        {
            return false;
        }

        Button[] buttons = root.GetComponentsInChildren<Button>(true);
        for (int i = 0; i < buttons.Length; i++)
        {
            Button button = buttons[i];
            if (button != null && button.interactable && button.gameObject.activeInHierarchy)
            {
                current.SetSelectedGameObject(button.gameObject);
                return true;
            }
        }

        return false;
    }

    private static bool ActiveRootContainsSelection(RectTransform root)
    {
        EventSystem current = EventSystem.current;
        GameObject selected = current != null ? current.currentSelectedGameObject : null;
        if (root == null || selected == null || !root.gameObject.activeInHierarchy || !selected.activeInHierarchy)
        {
            return false;
        }

        Button button = selected.GetComponent<Button>();
        return button != null && button.interactable && selected.transform.IsChildOf(root);
    }

    private static bool CurrentSelectionHasFocusHighlight()
    {
        EventSystem current = EventSystem.current;
        GameObject selected = current != null ? current.currentSelectedGameObject : null;
        if (selected == null)
        {
            return false;
        }

        ControllerFocusHighlight highlight = selected.GetComponent<ControllerFocusHighlight>();
        return highlight != null && highlight.HasOutline;
    }

    private void AddShadow(Text text, Color color, Vector2 distance)
    {
        Shadow shadow = text.gameObject.AddComponent<Shadow>();
        shadow.effectColor = color;
        shadow.effectDistance = distance;
    }

    private static void SetRect(RectTransform rt, Vector2 position, Vector2 size)
    {
        rt.anchorMin = new Vector2(0.5f, 0.5f);
        rt.anchorMax = new Vector2(0.5f, 0.5f);
        rt.pivot = new Vector2(0.5f, 0.5f);
        rt.anchoredPosition = position;
        rt.sizeDelta = size;
    }

    private static void EnsureEventSystem()
    {
        if (FindAnyObjectByType<EventSystem>() != null)
        {
            return;
        }
        GameObject eventSystem = new("EventSystem", typeof(EventSystem), typeof(StandaloneInputModule));
        eventSystem.transform.SetAsLastSibling();
    }

    private sealed class ControllerFocusHighlight : MonoBehaviour, ISelectHandler, IDeselectHandler
    {
        private Outline focusOutline;

        public bool HasOutline => focusOutline != null;

        public void Configure(Outline outline)
        {
            focusOutline = outline;
            if (focusOutline != null)
            {
                focusOutline.enabled = false;
                focusOutline.effectColor = new Color32(255, 218, 112, 0);
            }
        }

        public void OnSelect(BaseEventData eventData)
        {
            if (focusOutline == null)
            {
                return;
            }

            focusOutline.enabled = true;
            focusOutline.effectColor = new Color32(255, 218, 112, 235);
        }

        public void OnDeselect(BaseEventData eventData)
        {
            if (focusOutline == null)
            {
                return;
            }

            focusOutline.effectColor = new Color32(255, 218, 112, 0);
            focusOutline.enabled = false;
        }
    }

