    private sealed class TrackedText
    {
        public readonly Text text;
        public readonly int baseFontSize;
        public readonly Color baseColor;
        public readonly Outline accessibilityOutline;

        public TrackedText(Text text, int baseFontSize)
        {
            this.text = text;
            this.baseFontSize = baseFontSize;
            baseColor = text.color;
            accessibilityOutline = text.gameObject.AddComponent<Outline>();
            accessibilityOutline.enabled = false;
            accessibilityOutline.effectDistance = Vector2.zero;
        }
    }

